INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-04b5eef4e8e7', 'theoutnet', 'ton-46376663163017967', 'Striped Cotton And Linen Blend Pique Polo Shirt', 'Alex Mill', 'clothing', 'men', 'Polo en algodón y lino con rayas sutiles, fresco y pulido para un armario discreto.', 'https://www.theoutnet.com/variants/images/46376663163017967/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163017967/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163017967/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163017967/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163017967/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163017967/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/alex-mill/tops/polo-shirts/striped-cotton-and-linen-blend-pique-polo-shirt/46376663163017967', 115, 177.99, 'Llévalo con reloj de acero cepillado, perfume cítrico y mocasines beige o sneakers blancas.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-646a31a1c4c9', 'mp-8d5bb353d59a']::text[], 'Polo ligero y fresco con espadrilles de ante y Seiko azul: un conjunto relajado, pulido y muy veraniego. El Neroli Portofino aporta cítricos limpios y notas aromáticas, ideal para almuerzos junto al mar o fines de semana con discreta elegancia.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4f382c4cb4f5', 'theoutnet', 'ton-46376663163094471', 'Linen Polo Shirt', 'Sandro', 'clothing', 'men', 'Polo de lino sobrio, ligero y refinado para días cálidos con naturalidad.', 'https://www.theoutnet.com/variants/images/46376663163094471/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163094471/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094471/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094471/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094471/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094471/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/sandro/tops/polo-shirts/linen-polo-shirt/46376663163094471', 118, 180.99, 'Combínalo con reloj minimalista, perfume limpio y pantalón marfil con loafers de gamuza.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-69ef4764b1ae', 'mp-d74238edf829', 'mp-0de6cc427e14']::text[], 'El lino del polo se equilibra con espadrilles de canvas y el Seiko plateado, creando una lectura fresca y sobria. Acqua di Gio Parfum añade un carácter marino, luminoso y refinado, perfecto para oficina relajada o escapadas de verano.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-cab8b3ae8035', 'theoutnet', 'ton-46376663163098985', 'Lyocell And Linen Blend Shirt', 'Dunhill', 'clothing', 'men', 'Camisa en lyocell y lino con caída elegante, pensada para una presencia relajada.', 'https://www.theoutnet.com/variants/images/46376663163098985/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163098985/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098985/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098985/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098985/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098985/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/dunhill/tops/casual-shirts/lyocell-and-linen-blend-shirt/46376663163098985', 119, 181.99, 'Acompáñala con reloj fino, perfume amaderado suave y pantalón gris con derbies marrones.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-7795ae7c1d60', 'mp-28b674995133', 'mp-33eb4986cc4c']::text[], 'La camisa de lyocell y lino pide mocasines limpios y un reloj de esfera clara para mantener el tono ejecutivo sin rigidez. Eau Sauvage Parfum suma frescura cítrica y elegante, ideal para oficina y reuniones de día.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-357d594d46a8', 'theoutnet', 'ton-46376663163013127', 'Striped Linen And Cotton Blend Shirt', 'Boglioli', 'clothing', 'men', 'Camisa rayada de lino y algodón, clásica y ligera con una silueta impecable.', 'https://www.theoutnet.com/variants/images/46376663163013127/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163013127/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163013127/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163013127/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163013127/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163013127/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/boglioli/tops/casual-shirts/striped-linen-and-cotton-blend-shirt/46376663163013127', 120, 182.99, 'Úsala con reloj sobrio, perfume fresco y pantalón azul tinta con mocasines de cuero.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-42bc749064f5', 'mp-28b674995133', 'mp-2dc2d5978672']::text[], 'Las rayas suaves funcionan muy bien con loafers de ante y un Citizen de aire clásico. Eau Sauvage aporta una frescura seca y pulida, perfecta para oficina en clima cálido o un viernes smart casual con discreta sofisticación.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5b8b2a197a98', 'jomashop', 'Y-A2T9K', 'Hugo Boss Men''s Bottled Parfum 6.76 oz', 'Hugo Boss', 'perfume', 'men', 'Aroma envolvente y pulcro, con carácter moderno para una firma personal elegante.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-bottled-parfum-676-oz-fragrances-3616303173104.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-bottled-parfum-676-oz-fragrances-3616303173104.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-bottled-parfum-676-oz-fragrances-3616303173104_7.jpg', 'https://www.harmoniq.se/image/128786/3616303173104.jpg']::text[], 'https://www.jomashop.com/hugo-boss-mens-bottled-parfum-6-76-oz-fragrances-3616303173104.html', 121.11, 183.99, 'Combínalo con reloj oscuro, traje azul medianoche y zapatos de piel; suma abrigo o blazer limpio.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-c680203f6394', 'mp-6d00b4d9aef1', 'mp-357d594d46a8']::text[], 'El perfil intenso de Bottled Parfum se refuerza con mocasines de ante y el Tissot PRX digital para un look nocturno sobrio. La camisa ligera equilibra el conjunto; ideal para cenas y reuniones after office con presencia contenida.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0c135b99cc61', 'jomashop', 'Z-BWRQT', 'Jean Paul Gaultier Ladies Scandal Absolu Parfum 2.7 oz', 'Jean Paul Gaultier', 'perfume', 'women', 'Oriental intenso con firma de piel cálida y presencia nocturna para destacar con discreción.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-ladies-scandal-absolu-parfum-27-oz-fragrances-8435415080422.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-ladies-scandal-absolu-parfum-27-oz-fragrances-8435415080422.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-ladies-scandal-absolu-parfum-27-oz-fragrances-8435415080422_7.jpg', 'https://www.kunchals.in/cdn/shop/files/8435415080422.webp?v=1735816885', 'https://lacasadelperfume.cl/wp-content/uploads/2025/03/8435415080422-3.jpg', 'https://rougeb2car.vtexassets.com/arquivos/ids/216383/8435415080422_2.jpg?v=638558090947970000', 'https://i5.walmartimages.com/seo/Jean-Paul-Gaultier-Ladies-Scandal-Absolu-Parfum-2-7-oz-Fragrances-8435415080422_fba116c9-2005-4fa5-b7d1-ff0744f02ab6.317182dd865ec8a8d8a3b34f6c0060ce.jpeg']::text[], 'https://www.jomashop.com/jean-paul-gaultier-ladies-scandal-absolu-edp-spray-2-7-oz-fragrances-8435415080422.html', 121.11, 183.99, 'Combínalo con reloj acero pulido, blazer negro y zapatos de cuero borgoña; perfume ambarado, acabado limpio.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-33c53e7b9d78', 'mp-f9f99f3e6118', 'mp-cebec8d3d39d']::text[], 'El perfume, intenso y seductor, combina con el vestido midi y los pumps cristalinos para una noche elegante. El reloj de acero aporta brillo contenido, mientras la silueta mantiene un lujo sofisticado y femenino sin exceso.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-765cebf90a4e', 'jomashop', 'COS-LMXMTS67', 'Jean Paul Gaultier Men''s Le Maxi Male EDT Spray 6.7 oz', 'Jean Paul Gaultier', 'perfume', 'men', 'Fragancia intensa y provocadora, ideal para una entrada segura y memorable.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-le-maxi-male-edt-spray-67-oz-fragrances-3423470475852.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-le-maxi-male-edt-spray-67-oz-fragrances-3423470475852.jpg', 'https://m.media-amazon.com/images/I/51RCRxeAjCL._SL1000_.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-le-maxi-male-edt-spray-67-oz-fragrances-3423470475852_7.jpg']::text[], 'https://www.jomashop.com/jean-paul-gaultier-mens-le-maxi-male-edt-spray-6-7-oz-fragrances-3423470475852-lmxmts67.html', 121.11, 183.99, 'Llévalo con reloj audaz, camisa negra y chaqueta estructurada; completa con botas o derby brillantes.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-a057942bba4c']::text[], 'La camisa satinada, los loafers de terciopelo y el Seiko dorado construyen un look nocturno glamuroso pero refinado. El perfume, dulce-especiado y cálido, encaja perfecto para cena o coctel con actitud elegante y moderna.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-91312228cf67', 'jomashop', 'Y-148541', 'Jean Paul Gaultier Men''s Le Male Le Parfum EDP Spray 4.2 oz', 'Jean Paul Gaultier', 'perfume', 'men', 'Parfum profundo y seductor, con acabado sofisticado para noches bien vestidas.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-le-male-le-parfum-edp-spray-4-2-oz-fragrances-8435415032315.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-le-male-le-parfum-edp-spray-4-2-oz-fragrances-8435415032315.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-le-male-le-parfum-edp-spray-42-oz-fragrances-8435415032315_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-le-male-le-parfum-edp-spray-42-oz-fragrances-8435415032315_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-le-male-le-parfum-edp-spray-42-oz-fragrances-8435415032315_vthumb_1.jpg', 'https://vitaltone.co.uk/wp-content/uploads/2023/07/8435415032315_4-1-scaled.jpg', 'https://www.superbuys.com.au/assets/full/8435415032315.jpg?20220719235614', 'https://cdn2.jomashop.com/media/catalog/product/cache/b3e31d40bbb1abcc90b26106659d5d3f/j/e/jean-paul-gaultier-mens-le-male-le-parfum-edp-spray-42-oz-fragrances-8435415032315_1.jpg?width=800&height=800']::text[], 'https://www.jomashop.com/jean-paul-gaultier-mens-le-male-le-parfum-edp-spray-4-2-oz-fragrances-8435415032315.html', 121.11, 183.99, 'Combínalo con reloj de caja pulida, traje oscuro y zapatos negros; añade abrigo largo.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-3f1bb37bec2f', 'mp-474b2526c36a', 'mp-68b8b7f85f35']::text[], 'La camisa satinada floral y los velvets elevan Le Male Le Parfum hacia una noche formal con aire editorial. El reloj dorado suma lujo, mientras el perfume aporta vainilla, especias y profundidad ambarada, ideal para cena o evento.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-40dd2be6dd83', 'jomashop', 'Z-FA98C', 'Yves Saint Laurent Men''s Myslf Le Parfum 3.3 oz', 'Yves Saint Laurent', 'perfume', 'men', 'Amaderado y moderno, con una firma masculina pulida y segura.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-mens-myslf-le-parfum-3-3-oz-fragrances-3614274114645_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-mens-myslf-le-parfum-3-3-oz-fragrances-3614274114645_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-mens-myslf-le-parfum-3-3-oz-fragrances-3614274114645_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-mens-myslf-le-parfum-3-3-oz-fragrances-3614274114645_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/y/v/yves-saint-laurent-mens-myslf-le-parfum-33-oz-fragrances-3614274114645_3.jpg?width=546&height=546', 'https://mediafiles.maxaroma.com/9cd29e92-4b8f-436f-ad1f-8e368b30dc1d/https://www.maxaroma.com/productimages/large/UP3614274114645.jpg?ver=1740691322']::text[], 'https://www.jomashop.com/yves-saint-laurent-mens-myslf-le-parfum-3-3-oz-fragrances-3614274114645.html', 120.64, 183.99, 'Llévalo con reloj de acero, camisa negra o azul noche, blazer estructurado y zapatos derby; tonos carbón.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-76e86cc39c9a', 'mp-9e04bde41b3e', 'mp-23af6e30e1cc']::text[], 'El perfume gourmand y envolvente se acompaña de pantalón de lana, loafers finos y un Presage azul para un conjunto elegante. Perfecto para noche o invierno, con un carácter sobrio, pulido y claramente de lujo silencioso.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6d00b4d9aef1', 'jomashop', 'TIST1374631105000', 'Tissot PRX Quartz Digital Black Dial Men''s Watch', 'Tissot', 'watch', 'men', 'PRX digital en negro, precisa y sobria, con estética técnica y elegante.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-digital-black-dial-mens-watch-t1374631105000.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-digital-black-dial-mens-watch-t1374631105000.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-digital-black-dial-mens-watch-t1374631105000_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-digital-black-dial-mens-watch-t1374631105000_3.jpg', 'https://cdn11.bigcommerce.com/s-28d61/images/stencil/1280x1280/products/14595/140798/tissot-watches-tissot-prx-digital-40mm-quartz-ss-black-mens-watch-t137.463.11.050.00__14221.1745942331.jpg?c=2']::text[], 'https://www.jomashop.com/tissot-tissot-prx-black-dial-unisex-watch-t1374631105000.html', 122.55, 185.99, 'Úsalo con camisa blanca, pantalón gris y derbies negros; perfume fresco amaderado, reloj de acero.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-d3392a7bbb8e', 'mp-9c175b220b04', 'mp-a1a9c18f6ebe']::text[], 'El PRX digital negro pide una camisa nítida, loafers estructurados y un perfume vetiver para un registro ejecutivo contemporáneo. Conecta especialmente en oficina y jornadas urbanas, donde la precisión visual y olfativa importan más que el gesto ostentoso.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-51927a8880f3', 'jomashop', 'TIST1372631103000', 'Tissot PRX Digital Quartz Silver Dial Watch', 'Tissot', 'watch', 'unisex', 'PRX digital en plata, limpia y moderna, para un pulso refinado de diario.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-silver-dial-mens-watch-t1372631103000_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-silver-dial-mens-watch-t1372631103000_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-silver-dial-mens-watch-t1372631103000_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-silver-dial-mens-watch-t1372631103000_4.jpg', 'https://i5.walmartimages.com/seo/Tissot-PRX-Digital-Quartz-Silver-Dial-Men-s-Watch-T1372631103000_1eef2085-9f5f-4dfd-b386-4058ff5f8733.1ed0baa5692b3265f0b56a4f85b1a6ff.jpeg', 'https://i5.walmartimages.com/seo/Tissot-PRX-Digital-Quartz-Silver-Dial-Men-s-Watch-T1372631103000_5ec9b8e3-0de4-4e7b-a930-90fa9194faee.640a9db123ee79b42ebe2a7a75df0d4b.jpeg', 'https://assets.tissotwatches.com/transform/Extend/97cfb56b-3c1d-4ff3-addd-2c536035bcf7/T137_263_11_030_00']::text[], 'https://www.jomashop.com/tissot-prx-digital-quartz-silver-dial-mens-watch-t1372631103000.html', 122.55, 185.99, 'Acompáñalo con traje azul marino, camisa celeste y mocasines marrón; perfume limpio, acero cepillado.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-cab8b3ae8035', 'mp-c680203f6394', 'mp-4520d6ec87f1']::text[], 'Para oficina, elige la camisa de lino-lyocell, los loafers en ante y un vetiver elegante. El PRX digital suma precisión moderna; el conjunto se ve sobrio, pulido y muy Lima, ideal para reuniones y días largos.', 'oficina', ARRAY['mp-e80799294eb5', 'mp-4f1a6a5f486b', 'mp-5d7de0b2cfb9']::text[], 'Para oficina, esta camisa impecable, los flats con carácter y Libre en tono floral-amaderado crean una imagen actual y segura. El reloj refuerza el aire limpio y profesional, perfecto para un día de trabajo con elegancia.', 'oficina') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7e328d33cd02', 'jomashop', 'TIST1372631105000', 'Tissot PRX Digital Quartz Black Dial Men''s Watch', 'Tissot', 'watch', 'men', 'PRX digital negro, contundente y discreta, con aire ejecutivo y contemporáneo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-black-dial-mens-watch-t1372631105000.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-black-dial-mens-watch-t1372631105000.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-black-dial-mens-watch-t1372631105000_2_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-black-dial-mens-watch-t1372631105000_3.jpg', 'https://i5.walmartimages.com/seo/Tissot-PRX-Digital-Quartz-Black-Dial-Men-s-Watch-T1372631105000_d21ea8b2-08d3-42e6-8336-9df06eaa8ffd.24686a03017080f39a0f3f842f37375f.jpeg']::text[], 'https://www.jomashop.com/tissot-prx-digital-quartz-black-dial-mens-watch-t1372631105000.html', 122.55, 185.99, 'Combínalo con abrigo camel, pantalón carbón y oxford negros; perfume seco, metal oscuro.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-cab8b3ae8035', 'mp-9c175b220b04', 'mp-9b75c4948e46']::text[], 'La esfera negra se ve impecable con camisa de lino y mocasines de ante; todo transmite sobriedad moderna. El vetiver aporta limpieza seca y elegante, ideal para oficina y reuniones donde conviene proyectar calma y criterio.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d8261d7f8fcf', 'jomashop', 'TIST1374631103000', 'Tissot PRX Digital Quartz Silver Dial Men''s Watch', 'Tissot', 'watch', 'men', 'PRX digital plata, versátil y precisa, con brillo contenido para el trabajo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-silver-dial-mens-watch-t1374631103000.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-silver-dial-mens-watch-t1374631103000.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-silver-dial-mens-watch-t1374631103000_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-silver-dial-mens-watch-t1374631103000_3.jpg', 'https://cdn11.bigcommerce.com/s-28d61/products/14594/images/140761/tissot-watches-tissot-prx-digital-40mm-qtz-ss-silver-dial-mens-watch-t137.463.11.030.00__39322.1695868873.1280.1280.jpg?c=2']::text[], 'https://www.jomashop.com/tissot-prx-digital-quartz-silver-dial-mens-watch-t1374631103000.html', 122.55, 185.99, 'Lúcelo con saco gris, polo blanco y loafers café; perfume cítrico amaderado, acero brillante.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-357d594d46a8', 'mp-ae99e2aca74c', 'mp-7795ae7c1d60']::text[], 'El PRX plateado armoniza con rayas finas, mocasines de cuero y un perfume amaderado elegante. El resultado es limpio y profesional, perfecto para oficina o almuerzos de trabajo, con una presencia discreta y bien medida.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-cdb9c6279865', 'jomashop', 'Z-9B9H2', 'Giorgio Armani Ladies My Way Nectar EDP Spray 3.0 oz', 'Giorgio Armani', 'perfume', 'women', 'Perfume luminoso y femenino, fresco con un perfil delicado y contemporáneo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-my-way-nectar-edp-spray-3-0-oz-fragrances-3614273947763.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-my-way-nectar-edp-spray-3-0-oz-fragrances-3614273947763.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-my-way-nectar-edp-spray-30-oz-fragrances-3614273947763_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-my-way-nectar-edp-spray-30-oz-fragrances-3614273947763_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-my-way-nectar-edp-spray-30-oz-fragrances-3614273947763_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-my-way-nectar-edp-spray-30-oz-fragrances-3614273947763_7.jpg', 'https://farmaciasdelpueblo.vtexassets.com/arquivos/ids/209711/3614273947763-2.png?v=638850825320830000', 'https://f.fcdn.app/imgs/04fbe2/universobinario.com/ubinuy/5d6b/original/catalogo/3614273947763-001_1/2000-2000/perfume-giorgio-armani-my-way-nectar-edp-90-ml-001.jpg']::text[], 'https://www.jomashop.com/armani-ladies-my-way-nectar-edp-spray-3-0-oz-fragrances-3614273947763.html', 123.49, 185.99, 'Acompáñalo con reloj dorado fino, vestido fluido claro y sandalias nude o ballet flats.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-56139b744bbc', 'mp-f9f99f3e6118', 'mp-c92d231b1d76']::text[], 'El pantalón de lana y los pumps enmarcan My Way Nectar con una elegancia femenina y pulida, ideal para cena o evento diurno. Su aroma floral-frutal resulta luminoso, suave y sofisticado.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c1343ccc13f4', 'jomashop', 'Z-2ALYD', 'Gucci Winter''s Spring 100ml Eau De Parfum 3.3 Oz', 'Gucci', 'perfume', 'unisex', 'Fragancia cálida y refinada, con presencia serena para días fríos.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-winters-spring-100ml-eau-de-parfum-33-oz-3614227767782.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-winters-spring-100ml-eau-de-parfum-33-oz-3614227767782.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-winters-spring-100ml-eau-de-parfum-33-oz-3614227767782_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-winters-spring-100ml-eau-de-parfum-33-oz-3614227767782_7.jpg']::text[], 'https://www.jomashop.com/gucci-winters-spring-100ml-eau-de-parfum-3-3-oz-3614227767782.html', 123.49, 185.99, 'Combínala con reloj de oro discreto, lana camel y botines oscuros; añade abrigo estructurado.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-22a9a0aaf882', 'mp-b2dbfc6f7e6e', 'mp-23af6e30e1cc']::text[], 'Para invierno, combina el polo de merino, los oxford texturizados y un Presage azul clásico. El perfume acompaña con calidez especiada y refinada; ideal para cenas y reuniones donde buscas presencia discreta.', 'invierno', ARRAY['mp-381d102f4ffc', 'mp-d0246a15c10d', 'mp-f4871962fdc0']::text[], 'Para invierno, el sweater de cashmere, los pumps limpios y el reloj nacarado logran una silueta serena y sofisticada. El perfume aporta una estela elegante, ambarada y envolvente, ideal para noches frías y eventos formales.', 'invierno') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a79276c5048b', 'jomashop', 'Z-QBACZ', 'Prada Ladies Paradoxe Intense EDP Spray 3.0 oz', 'Prada', 'perfume', 'women', 'Aroma intenso y sofisticado, con una estela moderna y segura.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-ladies-paradoxe-intense-edp-spray-3-0-oz-fragrances-3614273961707.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-ladies-paradoxe-intense-edp-spray-3-0-oz-fragrances-3614273961707.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-ladies-paradoxe-intense-edp-spray-30-oz-fragrances-3614273961707_7.jpg', 'https://perfumeriasclapes.es/wp-content/uploads/2023/09/3614273961707_1.jpg']::text[], 'https://www.jomashop.com/prada-ladies-paradoxe-intense-edp-spray-3-0-oz-fragrances-3614273961707.html', 123.49, 185.99, 'Úsalo con reloj pulido, vestido negro o satén y tacones finos; suma abrigo negro.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-56139b744bbc', 'mp-2a81e6864b82', 'mp-cebec8d3d39d']::text[], 'Un conjunto pulido y femenino para cena o evento nocturno: pantalón de lana limpia, pumps de línea clásica y un reloj discreto. Paradoxe Intense aporta un aura cálida, floral y envolvente, perfecta para invierno y looks sofisticados.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-605a39d82c0f', 'jomashop', 'Z-RJYXN', 'Prada Men''s Luna Rossa Carbon EDP Spray 3.4 oz', 'Prada', 'perfume', 'men', 'Fragancia fresca y urbana, con energía limpia para el día a día.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-mens-luna-rossa-carbon-edp-spray-3-4-oz-fragrances-3614274490237.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-mens-luna-rossa-carbon-edp-spray-3-4-oz-fragrances-3614274490237.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-mens-luna-rossa-carbon-edp-spray-3-4-oz-fragrances-3614274490237_2.jpg', 'https://fredrikoglouisa.no/wp-content/uploads/2026/01/3614274490237.jpg', 'https://www.magasin.no/dw/image/v2/BFCS_PRD/on/demandware.static/-/Sites-mdn-master-catalog/default/dw4fa1d066/large2/15/3614274490237_2.jpg?sw=600&sh=720&sm=fit&sfrm=jpg']::text[], 'https://www.jomashop.com/prada-mens-luna-rossa-carbon-edp-spray-3-4-oz-fragrances-3614274490237.html', 123.49, 185.99, 'Combínala con reloj deportivo sobrio, polo gris y zapatillas blancas; añade chaqueta ligera.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-4f382c4cb4f5', 'mp-e886cd56a6d2', 'mp-1e5953f00a58']::text[], 'Luna Rossa Carbon encaja con polo de lino, sneakers técnicas y un Promaster robusto para un casual activo. El perfume se siente aromático, limpio y moderno; ideal para fines de semana, traslados urbanos o una salida deportiva sofisticada.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description