INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c29150dab3af', 'jomashop', 'COS-BLDES34-Q', 'Black Orchid by Tom Ford Unisex Eau De Parfum Spray 3.4 Oz (100 Ml) (U)', 'Tom Ford', 'perfume', 'unisex', 'Oscuro, intenso y magnético, con una firma olfativa sofisticada y audaz.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/b/l/black-orchid-by-tom-ford-unisex-eau-de-parfum-spray-3-4-oz-100-ml-u-888066000079.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/b/l/black-orchid-by-tom-ford-unisex-eau-de-parfum-spray-3-4-oz-100-ml-u-888066000079.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/b/l/black-orchid-by-tom-ford-unisex-eau-de-parfum-spray-3-4-oz-100-ml-u-888066000079_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/b/l/black-orchid-by-tom-ford-unisex-eau-de-parfum-spray-3-4-oz-100-ml-u-888066000079_3.jpg', 'https://res.cloudinary.com/dp9dnliwc/image/upload/c_mfit,h_1200,w_1200/f_auto/q_auto/wmmedia/watch_images/large/888066000079_1528316834.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fc2ff48f80400416c47c36b80c0a3202/b/l/black-orchid-by-tom-ford-unisex-eau-de-parfum-spray-34-oz-100-ml-u-888066000079_3.jpg?width=546&height=546', 'https://www.alseerandsafeer.com/image/cache/catalog/brands/tom-ford/products/888066000079_2-550x550h.jpg.webp', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/b/l/black-orchid-by-tom-ford-unisex-eau-de-parfum-spray-34-oz-100-ml-u-888066000079_2.jpg?width=546&height=546']::text[], 'https://www.jomashop.com/tom-ford-bldes34-q.html', 123.45, 185.99, 'Combínalo con reloj negro pulido, abrigo largo o traje oscuro y zapatos de cuero; añade tonos terciopelo.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-23af6e30e1cc']::text[], 'Para noche, la camisa satinada, los loafers de terciopelo y el Presage azul crean un perfil oscuro y refinado. Black Orchid añade un acorde ambarado, terroso y seductor; perfecto para cena o cóctel.', 'noche', ARRAY['mp-f597bbe6ab0b', 'mp-f9f99f3e6118', 'mp-f4871962fdc0']::text[], 'Para noche, la mini de georgette, los pumps cristalinos y el reloj nácar forman un look sensorial y elegante. Black Orchid deja una firma floral-amaderada, profunda y misteriosa; ideal para cena o evento nocturno.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-50407391ddd8', 'jomashop', 'Z-FH9HE', 'Valentino Men''s Uomo Born In Roma Intense EDP Spray 3.4 oz', 'Valentino', 'perfume', 'men', 'Vainilla, especias y madera en una estela masculina cálida y decidida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-mens-uomo-born-in-roma-intense-edp-spray-3-4-oz-fragrances-3614273790826.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-mens-uomo-born-in-roma-intense-edp-spray-3-4-oz-fragrances-3614273790826.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-mens-uomo-born-in-roma-intense-edp-spray-34-oz-fragrances-3614273790826_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/v/a/valentino-mens-uomo-born-in-roma-intense-edp-spray-34-oz-fragrances-3614273790826_1.jpg?width=546&height=546', 'https://compraperfumesoriginales.com/product-images/valentino-uomo-born-in-roma-intense-3614273790826-4349.png', 'https://abclive1.s3.amazonaws.com/31a7f8a4-c7f7-4d3a-81a6-26f396972754/productimage/P-3614273790826___3___XL.jpg']::text[], 'https://www.jomashop.com/valentino-mens-uomo-born-in-roma-intense-edp-spray-3-4-oz-fragrances-3614273790826.html', 123.49, 185.99, 'Úsalo con reloj de cuero negro, blazer azul tinta y botas café; perfume ambarado, textura mate.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-474b2526c36a', 'mp-68b8b7f85f35']::text[], 'La camisa satinada aporta brillo contenido, las loafers de terciopelo elevan el porte y el reloj dorado remata con discreción. Ideal para una cena o evento nocturno, con una estela intensa, especiada y seductora acorde al perfume.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-62787e09ac2c', 'jomashop', 'Y-85962', 'Xerjoff Men''s Casamorati Regio EDP Spray 3.4 oz', 'Xerjoff', 'perfume', 'men', 'Acorde refinado y luminoso, con herencia clásica y carácter distinguido.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-mens-casamorati-regio-edp-spray-34-oz-fragrances-8033488153601.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-mens-casamorati-regio-edp-spray-34-oz-fragrances-8033488153601.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-mens-casamorati-regio-edp-spray-34-oz-fragrances-8033488153601_2.jpg', 'https://www.prijs-parfum.nl/images/Xerjoff/Xerjoff-Regio-Edp-100ml-Spray-8033488153601.jpg']::text[], 'https://www.jomashop.com/xerjoff-casamorati-mens-1888-regio-edp-spray-3-4-oz-fragrances-8033488153601.html', 123.49, 185.99, 'Combínalo con reloj dorado discreto, saco beige y mocasines marrón; perfume cítrico floral, sastrería suave.', 'https://images.stockcake.com/public/e/f/1/ef1cb030-ed89-4a00-af5d-cf1485e9e655_large/elegant-men-s-fashion-stockcake.jpg', ARRAY['mp-59bca7fb130c', 'mp-9e04bde41b3e', 'mp-23af6e30e1cc']::text[], 'La popelina bordada suma pulcritud, las loafers de Santoni mantienen una elegancia serena y el Seiko Presage aporta refinamiento. El conjunto funciona muy bien para oficina distinguida o almuerzo formal, acompañado por un perfume noble, ambarado y pulido.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-63b6616930d2', 'jomashop', 'Z-3D6PC', 'Yves Saint Laurent Ladies Libre L’Eau Nue EDP Spray 3.0 oz', 'Yves Saint Laurent', 'perfume', 'women', 'Esencia luminosa y etérea, fresca sobre la piel con una elegancia natural.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-leau-nue-edp-spray-30-oz-fragrances-3614274241006.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-leau-nue-edp-spray-30-oz-fragrances-3614274241006.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-leau-nue-edp-spray-30-oz-fragrances-3614274241006_7.jpg', 'https://www.parfum-outlet.ch/media/13/07/30/1743695237/Yves Saint Laurent Libre L Eau Nue 90 ml Parfum de Peau 3614274241006.png', 'https://cdn.notinoimg.com/detail_main_hq/yves-saint-laurent/3614274241006_02-o/libre-leau-nue___250113.jpg', 'https://www.sephora.com.mx/on/demandware.static/-/Sites-masterCatalog_Sephora/es_MX/dw4fd61429/images/hi-res/boletos/Rocío Martínez/YVEST LAURENT/3614274241006_3.jpg', 'https://media.glam4u.gr/storage/glam4u/infocube_image_cache/jpg/1200x630x100/i3commerce/images/3/6/3614274241006.jpg?v=2025062003']::text[], 'https://www.jomashop.com/yves-saint-laurent-ladies-libre-l-eau-nue-edp-spray-3-0-oz-fragrances-3614274241006.html', 123.49, 185.99, 'Acompáñalo con reloj delicado, lino blanco y sandalias suaves; ideal para tonos crema.', 'https://www.styleatacertainage.com/wp-content/uploads/2025/06/Quince-Linen-Picks.png', ARRAY['mp-56139b744bbc', 'mp-771e0dce9f5f', 'mp-cebec8d3d39d']::text[], 'Un conjunto luminoso y pulido para oficina o almuerzo elegante: pantalón de lana, ballet flats y reloj fino. Libre L’Eau Nue encaja por su frescura suave, limpia y floral, con una estela discreta y refinada.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3f65ae3ddf19', 'theoutnet', 'ton-1647597307735043', 'Hibbert Printed Pique Shirt', 'Orlebar Brown', 'clothing', 'men', 'Camisa estampada con aire vacacional, relajada pero cuidada en cada detalle.', 'https://www.theoutnet.com/variants/images/1647597307735043/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597307735043/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597307735043/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597307735043/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597307735043/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597307735043/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/hibbert-printed-pique-shirt/1647597307735043', 123, 185.99, 'Llévala con reloj de acero, perfume marino y bermuda beige con mocasines o alpargatas.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-69ef4764b1ae', 'mp-646a31a1c4c9', 'mp-8d5bb353d59a']::text[], 'La camisa gráfica pide espadrilles y un reloj azul para un aire relajado pero cuidado. Perfecto para verano, brunch o escapada costera; el perfume de neroli aporta frescura cítrica y marina, muy limpia y sofisticada.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-780634c515c3', 'jomashop', 'Z-DLAUR', 'Gucci Ladies Flora Gorgeous Jasmine EDP Spray 3.4 oz (100 ml)', 'Gucci', 'perfume', 'women', 'Jazmín luminoso y femenino, fresco como una mañana clara y pulida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-ladies-flora-gorgeous-jasmine-edp-spray-3-4-oz-100-ml-3616303048181.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-ladies-flora-gorgeous-jasmine-edp-spray-3-4-oz-100-ml-3616303048181.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-ladies-flora-gorgeous-jasmine-edp-spray-34-oz-100-ml-3616303048181_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-ladies-flora-gorgeous-jasmine-edp-spray-34-oz-100-ml-3616303048181_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-ladies-flora-gorgeous-jasmine-edp-spray-34-oz-100-ml-3616303048181_7.jpg']::text[], 'https://www.jomashop.com/gucci-ladies-flora-gorgeous-jasmine-edp-spray-3-4-oz-fragrances-3616303048181.html', 123.54, 186.99, 'Combínalo con reloj fino, vestido satinado claro y sandalias metálicas; suma bolso estructurado.', 'https://www.styleatacertainage.com/wp-content/uploads/2025/06/Quince-Linen-Picks.png', ARRAY['mp-37dd49d175c3', 'mp-771e0dce9f5f', 'mp-b92296fdc3b1']::text[], 'La falda midi y las flats equilibran el aire femenino de Flora Gorgeous Jasmine con un tono relajado, ideal para brunch o tarde casual. El perfume suma un jazmín luminoso, delicado y alegre, sin perder elegancia.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d3392a7bbb8e', 'theoutnet', 'ton-46376663163018483', 'Striped Cotton Poplin Shirt', 'Alex Mill', 'clothing', 'men', 'Camisa de popelina rayada, nítida y versátil con presencia impecable.', 'https://www.theoutnet.com/variants/images/46376663163018483/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163018483/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163018483/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163018483/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163018483/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163018483/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/alex-mill/tops/casual-shirts/striped-cotton-poplin-shirt/46376663163018483', 124, 186.99, 'Úsala con reloj clásico, perfume limpio y pantalón azul marino con loafers de cuero.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-7795ae7c1d60', 'mp-397d0f68578a', 'mp-2dc2d5978672']::text[], 'La raya clásica se apoya en loafers pulidos y un reloj sobrio para un look de oficina impecable. La fragancia cítrica-aromática suma limpieza y presencia, ideal para jornadas largas, reuniones y un estilo silenciosamente elegante.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c935380c8999', 'jomashop', 'Y-173266', 'Gucci Men''s Moonlight Serenade EDP Spray 5 oz', 'Gucci', 'perfume', 'men', 'Perfume envolvente y silencioso, con un brillo nocturno muy sofisticado.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-mens-moonlight-serenade-edp-spray-5-oz-fragrances-3614227575981_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-mens-moonlight-serenade-edp-spray-5-oz-fragrances-3614227575981_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-mens-moonlight-serenade-edp-spray-5-oz-fragrances-3614227575981_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-mens-moonlight-serenade-edp-spray-5-oz-fragrances-3614227575981_3.jpg', 'https://www.parfuem365.de/media/image/b5/68/a5/3614227575981_1.jpg', 'https://www.alluringauras.com/wp-content/uploads/2024/07/3614227575981-1-800x800.webp']::text[], 'https://www.jomashop.com/gucci-mens-moonlight-serenade-edp-spray-5-oz-fragrances-3614227575981.html', 124.99, 187.99, 'Combínalo con reloj negro, saco de terciopelo y camisa oscura; completa con derby pulidos.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-474b2526c36a', 'mp-c109304a8cd3']::text[], 'La camisa satinada, las loafers de terciopelo y el reloj azul intenso construyen una imagen nocturna y sofisticada. Va perfecto para cóctel o cena formal; el perfume aporta un acorde dulce, luminoso y envolvente.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-730616e97e03', 'jomashop', 'Z-VHD8G', 'Hugo Boss Men''s The Collection Noble Wood EDP Spray 3.4 oz', 'Hugo Boss', 'perfume', 'men', 'Madera noble y seca, refinada para proyectar autoridad sin estridencia.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-the-collection-noble-wood-edp-spray-34-oz-fragrances-3614229387681.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-the-collection-noble-wood-edp-spray-34-oz-fragrances-3614229387681.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-the-collection-noble-wood-edp-spray-34-oz-fragrances-3614229387681_7.jpg', 'https://www.maxaroma.com/productimages/large/UP3614229387681_1.jpg?ver=1738171097', 'https://www.myperfumeshop.ae/cdn/shop/files/Elemento-1-3614229387681.jpg?v=1744733553&width=1080', 'https://fredrikoglouisa.no/wp-content/uploads/2022/10/3614229387681_1.jpg', 'https://fredrikoglouisa.no/wp-content/uploads/2022/10/3614229387681_2.jpg']::text[], 'https://www.jomashop.com/hugo-boss-mens-the-collection-noble-wood-edp-spray-3-4-oz-fragrances-3614229387681.html', 124.98, 187.99, 'Acompáñalo con reloj de acero, abrigo azul marino y zapatos de cordones en café oscuro.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-bdcc5c48a475', 'mp-9b75c4948e46', 'mp-d8261d7f8fcf']::text[], 'El sweater de lana y las loafers de ante equilibran el carácter amaderado del perfume, creando una elegancia cálida. Funciona muy bien en invierno y oficina, con un reloj digital sobrio para una lectura contemporánea y precisa.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c60a1e1dc903', 'jomashop', 'Z-VVWWP', 'Hugo Boss Men''s The Scent Elixir EDP Spray 3.4 oz', 'Hugo Boss', 'perfume', 'men', 'Elixir intenso y especiado, con magnetismo elegante para destacar sin esfuerzo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-the-scent-elixir-edp-spray-34-oz-fragrances-3616305169204.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-the-scent-elixir-edp-spray-34-oz-fragrances-3616305169204.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-the-scent-elixir-edp-spray-34-oz-fragrances-3616305169204_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-the-scent-elixir-edp-spray-34-oz-fragrances-3616305169204_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/h/u/hugo-boss-mens-the-scent-elixir-edp-spray-34-oz-tester-fragrances-t3616305169204_1.jpg', 'https://www.harmoniq.se/image/150592/3616305169204_7.jpg']::text[], 'https://www.jomashop.com/hugo-boss-mens-the-scent-elixir-edp-spray-3-4-oz-fragrances-3616305169204.html', 124.98, 187.99, 'Úsalo con reloj de caja sólida, traje negro y mocasines brillantes; añade camisa de seda oscura.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-f3cd717d3b87', 'mp-68b8b7f85f35']::text[], 'La camisa satinada y las loafers ornamentadas intensifican el perfil seductor del perfume, mientras el reloj dorado añade brillo controlado. Ideal para una noche formal o cita, con una estela especiada, dulce y muy masculina.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-af8d626e9475', 'jomashop', 'Y-148656', 'Jean Paul Gaultier Men''s Scandal Pour Homme EDT Spray 6.8 oz', 'Jean Paul Gaultier', 'perfume', 'men', 'Amaderado dulce con energía carismática, pensado para dejar huella sin esfuerzo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-pour-homme-edt-spray-68-oz-fragrances-8435415055956.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-pour-homme-edt-spray-68-oz-fragrances-8435415055956.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-pour-homme-edt-spray-68-oz-fragrances-8435415055956_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-pour-homme-edt-spray-68-oz-fragrances-8435415055956_3.jpg', 'https://www.prijs-parfum.nl/images/Overige/Jean-Paul-Gaultier-Scandal-Pour-Homme-Eau-de-Toilette-Refill-200-ml-8435415055956.jpg']::text[], 'https://www.jomashop.com/jean-paul-gaultier-mens-scandal-pour-homme-edt-spray-6-8-oz-fragrances-8435415055956.html', 124.98, 187.99, 'Llévalo con reloj acero negro, chaqueta de cuero y zapatos Chelsea; perfume especiado, silueta ajustada.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-f3cd717d3b87', 'mp-68b8b7f85f35']::text[], 'La camisa satinada, las loafers decoradas y el reloj dorado refuerzan el carácter provocador del perfume. Pensado para noche y ocasión especial, el conjunto equilibra sensualidad y elegancia con una presencia moderna y segura.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3324cbea3f8c', 'jomashop', 'Y-A29JJ', 'Jean Paul Gaultier - Le Beau Le Parfum Eau De Parfum Intense Spray 125ml / 4.2oz', 'Jean Paul Gaultier', 'perfume', 'unisex', 'Aroma cálido y luminoso, con sensualidad limpia para noches de verano.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-le-beau-le-parfum-eau-de-parfum-intense-spray-125ml-4-2oz-8435415062190.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-le-beau-le-parfum-eau-de-parfum-intense-spray-125ml-4-2oz-8435415062190.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-le-beau-le-parfum-eau-de-parfum-intense-spray-125ml-42oz-8435415062190.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-le-beau-le-parfum-eau-de-parfum-intense-spray-125ml-42oz-8435415062190_2.jpg', 'https://cdn.notinoimg.com/detail_main_hq/jean-paul-gaultier/8435415062190_02-o/le-beau-le-parfum-intense___221017.jpg', 'https://www.dealdoktor.de/app/uploads/2024/02/jean-paul-gaultier-le-beau-le-parfum-eau-de-parfum-125-ml-8435415062190-pack.webp']::text[], 'https://www.jomashop.com/jean-paul-gaultier-le-beau-le-parfum-eau-de-parfum-intense-spray-125ml-4-2oz-8435415062190.html', 124.99, 187.99, 'Combínalo con reloj metálico, camisa abierta y pantalón claro; completa con sandalias o mocasines.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-6f035be15849', 'mp-b9b2b677d2ef', 'mp-c109304a8cd3']::text[], 'Para verano, la camisa floral en lino, las espadrilles y el reloj de buceo equilibran frescura y lujo relajado. Le Beau Le Parfum aporta coco, ámbar y dulzor limpio; ideal para atardeceres junto al mar.', 'verano', ARRAY['mp-33c53e7b9d78', 'mp-f9f99f3e6118', 'mp-21f8ec52e6da']::text[], 'Para verano, el vestido midi, los pumps cristalinos y el reloj rosado crean un conjunto femenino y luminoso. Le Beau Le Parfum suma un carácter cremoso, cálido y seductor; perfecto para una cena de verano.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-96f746f61319', 'jomashop', 'Y-A2CZC', 'Paco Rabanne Men''s One Million Elixir Parfum Intense Spray 6.8 oz', 'Paco Rabanne', 'perfume', 'men', 'Parfum intenso y gourmand, pensado para una presencia segura y marcada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-one-million-elixir-parfum-intense-spray-68-oz-fragrances-3349668600298.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-one-million-elixir-parfum-intense-spray-68-oz-fragrances-3349668600298.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-one-million-elixir-parfum-intense-spray-68-oz-fragrances-3349668600298_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-one-million-elixir-parfum-intense-spray-6-8-oz-fragrances-3349668600298_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-one-million-elixir-parfum-intense-spray-6-8-oz-fragrances-3349668600298_2.jpg', 'https://compraperfumesoriginales.com/product-images/1-million-elixir-3349668600298-7058.png', 'https://compraperfumesoriginales.com/product-images/1-million-elixir-3349668600298.png']::text[], 'https://www.jomashop.com/paco-rabanne-mens-one-million-elixir-parfum-intense-spray-6-8-oz-fragrances-3349668600298.html', 124.99, 187.99, 'Llévalo con reloj llamativo pero sobrio, abrigo oscuro y zapatos negros; suma traje entallado.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-bdcc5c48a475', 'mp-474b2526c36a', 'mp-98496652d515']::text[], 'La lana oscura, el terciopelo en los loafers y el reloj dorado construyen un look invernal de impacto. Ideal para noche formal; el perfume acompaña con dulzor licoroso, especias y una estela intensa, opulenta y cálida.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d1442b11b2af', 'jomashop', 'Y-126697', 'Tom Ford - Costa Azzurra Eau De Parfum Spray (Gold) 100ml/3.4oz', 'Tom Ford', 'perfume', 'unisex', 'Brisa mediterránea con matiz luminoso, ideal para un perfil fresco y pulido.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-costa-azzurra-eau-de-parfum-spray-gold-100ml34oz-888066117470.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-costa-azzurra-eau-de-parfum-spray-gold-100ml34oz-888066117470.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-costa-azzurra-eau-de-parfum-spray-gold-100ml34oz-888066117470_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-costa-azzurra-eau-de-parfum-spray-gold-100ml34oz-888066117470_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-costa-azzurra-eau-de-parfum-spray-gold-100ml3-4oz-888066117470_3.jpg', 'https://www.faces.sa/on/demandware.static/-/Sites-faces-master-catalog/default/dwabb83ada/product/888066117470_/888066117470_.jpg', 'https://parfum.bg/image/cache/catalog/images/parfum/2022/09.22/63888066117470-700x700h.jpg']::text[], 'https://www.jomashop.com/tom-ford-costa-azzurra-eau-de-parfum-spray-gold-100ml-3-4oz-888066117470.html', 125.39, 187.99, 'Llévalo con reloj de acero claro, lino beige, mocasines y perfume cítrico; usa azul cielo o blanco.', 'https://morningkoffee.com/wp-content/uploads/2025/05/Comfy-summer-outfit-Tote-bag-@bonheur-.linenclothing-linenoutfit-summerstyles-bonheurbag-birkenstocks-pinstripes-linenshirt-linenpants-totebag-canvasbag-casualoutfit-summerlooks.jpg', ARRAY['mp-5f5d93891dbb', 'mp-3c75f66f94e0', 'mp-aaadd7c31bbe']::text[], 'Para verano, el polo lino-algodón, los loafers en terciopelo y el reloj de buceo dan un aire mediterráneo y refinado. Costa Azzurra es salino, cítrico y amaderado; ideal para almuerzos junto al mar.', 'verano', ARRAY['mp-eccea3334d40', 'mp-ca5e6334e29b', 'mp-f4871962fdc0']::text[], 'Para verano, el vestido floral wrap, las sandalias pulidas y el reloj nacarado forman un look fresco y sofisticado. Costa Azzurra aporta notas marinas y cítricas, con fondo amaderado; perfecto para brunch o escapada costeña.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5e366e01c3aa', 'jomashop', 'Y-A2QPA', 'Versace Men''s Eros Parfum Spray 6.76 oz', 'Versace', 'perfume', 'men', 'Cítrico y ambarado, con pulso enérgico y una salida magnética.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-mens-eros-parfum-spray-6-76-oz-fragrances-8011003877904.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-mens-eros-parfum-spray-6-76-oz-fragrances-8011003877904.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-mens-eros-parfum-spray-676-oz-fragrances-8011003877904_7.jpg', 'https://compraperfumesoriginales.com/product-images/eros-classic-8011003877904-1232.png']::text[], 'https://www.jomashop.com/versace-mens-eros-parfum-spray-6-76-oz-fragrances-8011003877904.html', 124.98, 187.99, 'Acompáñalo con reloj deportivo limpio, polo oscuro y zapatillas blancas; perfume fresco, capas ligeras.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-a9c08c82f70a', 'mp-6abb16f437af', 'mp-06e2a90e79c5']::text[], 'El swim short y las sneakers técnicas potencian el perfil enérgico del perfume, mientras el reloj diver completa la estética activa. Ideal para salida nocturna informal o verano urbano; la fragancia es dulce, fresca y adictiva.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8262b36fa874', 'jomashop', 'Y-A3L9Q', 'Yves Saint Laurent Ladies Black Opium Le Parfum EDP Spray 3.04 oz', 'Yves Saint Laurent', 'perfume', 'women', 'Vainilla profunda y ámbar luminoso en una estela elegante y envolvente.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-black-opium-le-parfum-edp-spray-304-oz-fragrances-3614273863360_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-black-opium-le-parfum-edp-spray-304-oz-fragrances-3614273863360_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-black-opium-le-parfum-edp-spray-304-oz-fragrances-3614273863360_2.jpg', 'https://cdn.notinoimg.com/detail_main_hq/yves-saint-laurent/3614273863360_02-o/black-opium-le-parfum___230124.jpg', 'https://perfumeriasclapes.es/wp-content/uploads/2024/01/3614273863360-OK2.jpg']::text[], 'https://www.jomashop.com/yves-saint-laurent-ladies-black-opium-le-parfum-edp-spray-3-04-oz-fragrances-3614273863360.html', 124.99, 187.99, 'Llévalo con reloj joya discreto, vestido negro y tacones satinados; perfume gourmand, líneas depuradas.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-56139b744bbc', 'mp-d0246a15c10d', 'mp-c92d231b1d76']::text[], 'Pantalón de lana, pumps refinados y reloj con brillo delicado elevan Black Opium Le Parfum. Funciona muy bien en invierno o una salida nocturna: café intenso, vainilla oscura y sensualidad elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c410fa946bc6', 'theoutnet', 'ton-46376663163093303', 'Checked Cotton Shirt', 'Thom Browne', 'clothing', 'men', 'Camisa a cuadros discretos, precisa y contemporánea con una elegancia contenida.', 'https://www.theoutnet.com/variants/images/46376663163093303/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163093303/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093303/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093303/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093303/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093303/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/tops/casual-shirts/checked-cotton-shirt/46376663163093303', 125, 187.99, 'Combínala con reloj de cuero, perfume amaderado y pantalón gris con derbies o loafers.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-7795ae7c1d60', 'mp-397d0f68578a', 'mp-33eb4986cc4c']::text[], 'La camisa a cuadros se vuelve más refinada con loafers lisos y un reloj de líneas discretas. Para oficina o jornada smart casual, el perfume añade un fondo limpio, vetiver y cítrico, elegante sin imponerse.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_n