INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6becc442eecf', 'jomashop', 'Y-A3UAP', 'Giorgio Armani Ladies My Way Parfum Spray 3.04 oz', 'Giorgio Armani', 'perfume', 'women', 'Parfum radiante y envolvente, con un brillo femenino de presencia serena.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-my-way-le-parfum-edp-spray-304-oz-fragrances-3614273927352.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-my-way-le-parfum-edp-spray-304-oz-fragrances-3614273927352.jpg', 'https://i5.walmartimages.com/seo/Giorgio-Armani-Ladies-My-Way-Parfum-Spray-3-04-oz-Fragrances-3614273927352_b8772e8f-5330-4b8e-8145-414751861bdc.302adfd40eefce50a55258be1ba3b1e6.jpeg', 'https://perfumeriasclapes.es/wp-content/uploads/2023/03/3614273927352-ok.jpg']::text[], 'https://www.jomashop.com/giorgio-armani-ladies-my-way-le-parfum-edp-spray-3-04-oz-fragrances-3614273927352.html', 126.34, 188.99, 'Acompáñalo con reloj delicado, vestido fluido y tacones nude; suma joyas mínimas.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-56139b744bbc', 'mp-f9f99f3e6118', 'mp-cebec8d3d39d']::text[], 'El pantalón de lana, los pumps y el reloj plateado acompañan la faceta refinada de My Way Parfum. Un conjunto femenino y luminoso para oficina formal o cena, con toque floral limpio y envolvente.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c4085bacd0b7', 'theoutnet', 'ton-46376663163074595', 'Twisted Embroidered Cotton Jersey t Shirt', 'Versace', 'clothing', 'women', 'Camiseta Versace con bordado twist, gráfica y sofisticada para elevar lo cotidiano.', 'https://www.theoutnet.com/variants/images/46376663163074595/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163074595/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074595/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074595/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074595/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074595/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/tops/t-shirts/twisted-embroidered-cotton-jersey-t-shirt/46376663163074595', 126, 188.99, 'Úsala con reloj acero, jeans índigo rectos y mocasines negros; perfume limpio, contraste sobrio.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-2208bf601ddb', 'mp-c798e1926e9d', 'mp-572ed2ab2e82']::text[], 'La silueta pulida del pantalón, los loafers y el PRX aportan formalidad sin rigidez. La camiseta funciona en verano con aire moderno y discreto, ideal para oficina creativa o almuerzo ejecutivo.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCL