INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-59bca7fb130c', 'theoutnet', 'ton-46376663163110092', 'Embroidered Cotton Poplin Shirt', 'Jacquemus', 'clothing', 'men', 'Camisa bordada de algodón, fresca y distintiva con un encanto relajado.', 'https://www.theoutnet.com/variants/images/46376663163110092/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163110092/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163110092/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163110092/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163110092/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163110092/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jacquemus/tops/casual-shirts/embroidered-cotton-poplin-shirt/46376663163110092', 126, 188.99, 'Úsala con reloj fino, perfume cítrico y pantalón blanco o denim crudo con sandalias.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-69ef4764b1ae', 'mp-49eca1e6c7f4', 'mp-0de6cc427e14']::text[], 'El bordado da textura artesanal, las espadrilles suavizan la silueta y el reloj automático mantiene el aire pulcro. Ideal para verano y escapada relajada; el perfume aporta neroli y notas marinas, frescas y luminosas.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXC