INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-646a31a1c4c9', 'jomashop', 'SE-SNKK27', 'Seiko 5 Blue Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Seiko 5 azul automático, clásico y confiable con un toque de color.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-blue-automatic-men_s-watch-snkk27_5.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-blue-automatic-men_s-watch-snkk27_5.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-blue-automatic-men_s-watch-snkk27_2_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-blue-automatic-men_s-watch-snkk27_3_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-blue-automatic-men_s-watch-snkk27_4_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/s/e/seiko-5-automatic-blue-dial-mens-watch-snkk27k1_1.jpg?width=546&height=546']::text[], 'https://www.jomashop.com/seiko-watch-snkk27.html', 127.3, 189.99, 'Combínalo con camisa oxford celeste, denim oscuro y loafers marrón; perfume acuático amaderado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-b1497c588a00', 'mp-e4ca126bdb77', 'mp-605a39d82c0f']::text[], 'La camisa de lino refuerza el tono relajado del reloj azul, y las sneakers blancas pulen el conjunto sin rigidez. Excelente para fines de semana o clima cálido; el perfume suma cítricos y ámbar limpio, muy versátil.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-49eca1e6c7f4', 'jomashop', 'SE-SNKK71', 'Seiko 5 Automatic Black Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Seiko 5 negro automático, sobrio y versátil, con presencia limpia y cotidiana.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-men_s-watch-snkk71.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-men_s-watch-snkk71.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-men_s-watch-snkk71_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-men_s-watch-snkk71_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-men_s-watch-snkk71_4.jpg']::text[], 'https://www.jomashop.com/seiko-watch-snkk71.html', 127.3, 189.99, 'Llévalo con suéter gris, pantalón chino carbón y derby negros; perfume seco, acabados mate.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-d3392a7bbb8e', 'mp-e886cd56a6d2', 'mp-2dc2d5978672']::text[], 'La camisa de popelina, las sneakers de cuero y el Eau Sauvage crean un conjunto sobrio y pulido para el día. Funciona muy bien en Lima, con un aire fresco, limpio y discretamente refinado.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-304f7a41cfbb', 'jomashop', 'SE-SNK357', 'Seiko 5 Automatic Midnight Logo Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Seiko 5 de esfera midnight, discreto y moderno con espíritu urbano.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-midnight-logo-dial-mens-watch-snk357.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-midnight-logo-dial-mens-watch-snk357.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-midnight-logo-dial-mens-watch-snk357_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-midnight-logo-dial-mens-watch-snk357_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fc2ff48f80400416c47c36b80c0a3202/s/e/seiko-5-automatic-midnight-logo-dial-mens-watch-snk357_1.jpg?width=546&height=546']::text[], 'https://www.jomashop.com/seiko-5-automatic-snk357.html', 127.3, 189.99, 'Úsalo con camiseta blanca, sobrecamisa azul y zapatillas negras; perfume fresco amaderado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-357d594d46a8', 'mp-1b60c92c78b6', 'mp-605a39d82c0f']::text[], 'La camisa de lino, las sneakers bicolor y Luna Rossa Carbon aportan frescura y equilibrio al reloj oscuro. Ideal para un look de fin de semana con carácter limpio, moderno y muy versátil.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCL