INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c92d231b1d76', 'jomashop', 'CZFE1140-86L', 'Citizen Silhouette Crystal Eco-Drive Blue Dial Stainless Steel Ladies Watch', 'Citizen', 'watch', 'women', 'Citizen con cristales y esfera azul, delicado brillo para un gesto femenino.', 'https://citizenwatch.widen.net/content/ddwfpir0o3/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/ddwfpir0o3/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-crystal-eco-drive-blue-dial-stainless-steel-ladies-watch-fe1140-86l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-crystal-eco-drive-blue-dial-stainless-steel-ladies-watch-fe1140-86l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-crystal-eco-drive-blue-dial-stainless-steel-ladies-watch-fe1140-86l_3.jpg', 'https://elegantwatchesfl.com/wp-content/uploads/2021/02/FE1140-86L.jpg', 'https://senmix.com/pictures/product/01/40/large/silhouette-crystal-eco-drive-blue-dial-stainless-steel-womens-watch-fe1140-86l.jpg']::text[], 'https://www.jomashop.com/citizen-watch-fe1140-86l.html', 127.3, 189.99, 'Combínalo con blazer crema, blusa seda y pumps nude; perfume floral limpio, joyería mínima.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-37dd49d175c3', 'mp-771e0dce9f5f', 'mp-780634c515c3']::text[], 'La falda de cuadros, las bailarinas y Flora Gorgeous Jasmine logran un look femenino y versátil. Perfecto para día casual o almuerzo; el perfume es floral, luminoso y delicadamente sofisticado.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-33eb4986cc4c', 'jomashop', 'Y-70276', 'Dior Men''s Eau Sauvage Parfum 3.4 oz', 'Dior', 'perfume', 'men', 'Clásico aromático y pulcro, elegante para un porte masculino atemporal.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-mens-eau-sauvage-parfum-3-4-oz-fragrances-3348901069830.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-mens-eau-sauvage-parfum-3-4-oz-fragrances-3348901069830.jpg', 'https://m.media-amazon.com/images/I/71p+m-BbAIL._SL1500_.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-mens-eau-sauvage-parfum-34-oz-fragrances-3348901069830_7.jpg']::text[], 'https://www.jomashop.com/christian-dior-mens-eau-sauvage-edp-spray-3-4-oz-fragrances-3348901069830.html', 128.24, 190.99, 'Combínalo con reloj de acero, camisa blanca y traje azul; completa con oxford negros.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4f703db7d409', 'mp-7795ae7c1d60', 'mp-6d00b4d9aef1']::text[], 'La camisa de lyocell, los loafers de cuero y el PRX digital sostienen una elegancia contenida para oficina o cena. Eau Sauvage Parfum suma un aroma cítrico-aromático, pulcro y distinguido.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2b2683ef3cce', 'jomashop', 'Y-A5LP3', 'Gucci Men''s Guilty Absolu de Parfum Parfum 2.03 oz', 'Gucci', 'perfume', 'men', 'Ámbar oscuro y presencia intensa para una firma masculina con carácter nocturno.', 'https://media.gucci.com/style/DarkGray_Center_0_0_1200x1200/1750840203/829671_99999_0099_001_100_0000_Light-gucci-guilty-absolu-de-parfum-pour-homme-60ml.jpg', ARRAY['https://media.gucci.com/style/DarkGray_Center_0_0_1200x1200/1750840203/829671_99999_0099_001_100_0000_Light-gucci-guilty-absolu-de-parfum-pour-homme-60ml.jpg', 'https://media.gucci.com/style/DarkGray_Center_0_0_1200x1200/1750840205/829671_99999_0099_002_100_0000_Light-gucci-guilty-absolu-de-parfum-pour-homme-60ml.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-mens-guilty-absolu-de-perfume-parfum-203-oz-fragrances-3616305931160.jpg', 'https://cdn.notinoimg.com/detail_main_hq/gucci/3616305931160_02-o/guilty-absolu-de-parfum___250730.jpg', 'https://assets.goldenscent.com/catalog/product/cache/1/small_image/750x750/9df78eab33525d08d6e5fb8d27136e95/3/6/3616305931160_-_gucci_-_gucci_guilty_pour_homme_absolu_de_parfum_60_ml_-_60_ml_-_fd.png', 'https://confiseriedubonheur.net/Stalk3r_hGeDKFxAmyy7H5pn/wp-content/uploads/2025/12/visu_gucci_3616305931160_c2.webp', 'https://cdn.notinoimg.com/detail_main_hq/gucci/3616305931160_07_/guilty-absolu-de-parfum___250724.jpg']::text[], 'https://www.jomashop.com/gucci-mens-guilty-absolu-de-perfume-parfum-2-03-oz-fragrances-3616305931160.html', 128.24, 190.99, 'Combínalo con reloj de acero negro, camisa azul noche y zapatos derby café oscuro.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-68b8b7f85f35']::text[], 'La camisa satinada, los loafers de terciopelo y el reloj dorado elevan el carácter nocturno del perfume. Concierta para cena o cóctel, con una estela intensa, sensual y muy elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ffa13b2c7329', 'jomashop', 'Z-Y4Y9S', 'Gucci Unisex Love At Your Darkest EDP 3.4 oz', 'Gucci', 'perfume', 'unisex', 'Una estela envolvente y profunda, pensada para destacar con discreción sofisticada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-love-at-your-darkest-edp-34-oz-fragrances-3614228839709.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-love-at-your-darkest-edp-34-oz-fragrances-3614228839709.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-love-at-your-darkest-edp-34-oz-fragrances-3614228839709_7.jpg', 'https://cdn.beymen.com/mnresize/596/830/productimages/dbjjyrcw.kcm_IMG_03_3614228839709.jpg']::text[], 'https://www.jomashop.com/gucci-unisex-love-at-your-darkest-edp-3-4-oz-fragrances-3614228839709.html', 128.24, 190.99, 'Llévalo con reloj minimalista, blazer negro mate y mocasines de cuero espresso.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-c410fa946bc6', 'mp-3c75f66f94e0', 'mp-7e328d33cd02']::text[], 'Para noche, la camisa de cuadro fino, los loafers de terciopelo y el PRX negro sostienen una imagen discreta y potente. Love At Your Darkest huele oscuro, especiado y ambarado; ideal para una cena íntima.', 'noche', ARRAY['mp-6ef5af9ad162', 'mp-d0246a15c10d', 'mp-3d070978e5a8']::text[], 'Para noche, la falda satinada, los pumps y el reloj nácar crean un conjunto sobrio y magnético. Love At Your Darkest deja una estela oscura, especiada y resinosa; perfecto para una cena elegante o cóctel.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6195e4aa6adf', 'jomashop', 'Z-3VFHT', 'Maison Margiela Unisex Replica Flying EDP Spray 3.4 oz', 'Maison Margiela', 'perfume', 'unisex', 'Aire limpio y sensación etérea, como una prenda ligera en movimiento.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-flying-edp-spray-34-oz-fragrances-3614271563408.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-flying-edp-spray-34-oz-fragrances-3614271563408.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-flying-edp-spray-34-oz-fragrances-3614271563408_2.jpg', 'https://www.maxaroma.com/productimages/large/UP3614271563408.jpg?ver=1734123073', 'https://www.maisonmargiela-fragrances.eu/dw/image/v2/BDCR_PRD/on/demandware.static/-/Sites-margiela-master-catalog/default/dw11f71d86/images/products/MM152/MaisonMargiela-REPLICA-EDT-3614271563408-ProductPage_Desktop_01.jpg', 'https://fredrikoglouisa.no/wp-content/uploads/2025/06/3614271563408_1.jpg']::text[], 'https://www.jomashop.com/maison-margiela-unisex-replica-flying-edp-spray-3-4-oz-fragrances-3614271563408.html', 128.24, 190.99, 'Llévalo con reloj de cuero claro, lino beige y mocasines suaves; perfume fresco, tonos arena.', 'https://lifewithjazz.com/wp-content/uploads/2022/04/5-Smart-Casual-Outfits-Last-picture.jpg', ARRAY['mp-357d594d46a8', 'mp-e4ca126bdb77', 'mp-e043070ecde2']::text[], 'Para casual, la camisa de lino rayado, las sneakers Off-White y el Seiko automático logran un look relajado pero curado. Flying aporta limpieza etérea, cítrica y suave; ideal para fines de semana y viajes.', 'casual', ARRAY['mp-f828dda76d0c', 'mp-771e0dce9f5f', 'mp-3c42564cbf4d']::text[], 'Para casual, la camisa de cuadros, las ballerinas y el reloj dos tonos equilibran comodidad y distinción. Flying se percibe ligero, limpio y airy; perfecto para un día libre con sobriedad chic.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c688e79ee2b0', 'jomashop', 'Z-RWP8G', 'Tom Ford Unisex Oud Minerale 2023 EDP Spray 3.4 oz', 'Tom Ford', 'perfume', 'unisex', 'Mineral y profundo, con un aire nocturno refinado y poco común.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-oud-minerale-2023-edp-spray-3-4-oz-fragrances-888066144254.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-oud-minerale-2023-edp-spray-3-4-oz-fragrances-888066144254.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-oud-minerale-2023-edp-spray-34-oz-fragrances-888066144254_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-oud-minerale-2023-edp-spray-34-oz-fragrances-888066144254_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-oud-minerale-2023-edp-spray-34-oz-fragrances-888066144254_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/b3e31d40bbb1abcc90b26106659d5d3f/t/o/tom-ford-unisex-oud-minerale-2023-edp-spray-34-oz-fragrances-888066144254.jpg?width=800&height=800', 'https://cdn.paris-avenues.com/image/cache/catalog/Product2/888066144254-2-1000x1000.png', 'https://cdn.paris-avenues.com/image/cache/catalog/Product2/888066144254-600x315w.png']::text[], 'https://www.jomashop.com/tom-ford-unisex-oud-minerale-2023-edp-spray-3-4-oz-fragrances-888066144254.html', 128.25, 190.99, 'Combínalo con reloj negro, abrigo de lana, camisa oscura y botas; elige tonos grafito y arena.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-76e86cc39c9a', 'mp-3c75f66f94e0', 'mp-23af6e30e1cc']::text[], 'Para una noche discreta y sofisticada, combina el pantalón de lana con loafers de terciopelo y un reloj Presage azul: líneas limpias, brillo sutil y presencia impecable. Oud Minerale aporta un halo mineral, salino y oscuro, muy refinado.', 'noche', ARRAY['mp-8b1d23d08a7c', 'mp-d0246a15c10d', 'mp-f4871962fdc0']::text[], 'Para una noche elegante, este conjunto equilibra volumen fluido, pumps pulidos y un reloj nácar: femenino sin exceso. Oud Minerale suma una estela mineral, fresca y envolvente, perfecta para un look sobrio y moderno.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5d7de0b2cfb9', 'jomashop', 'Z-L9NKL', 'Yves Saint Laurent Ladies Libre L''Absolu Platine Parfum Spray 3.0 oz', 'Yves Saint Laurent', 'perfume', 'women', 'Más intenso y cremoso, con una estela sofisticada de carácter contemporáneo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-labsolu-platine-parfum-spray-30-oz-fragrances-3614273924030.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-labsolu-platine-parfum-spray-30-oz-fragrances-3614273924030.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-labsolu-platine-parfum-spray-30-oz-fragrances-3614273924030_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-labsolu-platine-parfum-spray-30-oz-fragrances-3614273924030_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-labsolu-platine-parfum-spray-30-oz-fragrances-3614273924030_7.jpg', 'https://cdn.notinoimg.com/detail_main_hq/yves-saint-laurent/3614273924030_03-o/libre-labsolu-platine___230905.jpg', 'https://cdn.notinoimg.com/social/yves-saint-laurent/3614273924030_01-o/yves-saint-laurent-libre-labsolu-platine-parfum-pour-femme___230905.jpg', 'https://cdn.notinoimg.com/detail_main_hq/yves-saint-laurent/3614273924030_08/yves-saint-laurent-libre-labsolu-platine-parfum-fur-damen___230821.jpg']::text[], 'https://www.jomashop.com/yves-saint-laurent-ladies-libre-labsolu-platine-parfum-spray-3-0-oz-fragrances-3614273924030.html', 128.24, 190.99, 'Úsalo con reloj dorado fino, vestido negro o sastre marfil y tacones; perfume floral blanco opcional.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-56139b744bbc', 'mp-2a81e6864b82', 'mp-cebec8d3d39d']::text[], 'La madera floral de Libre L''Absolu Platine pide líneas limpias y refinadas. Los pantalones estructurados, los pumps y el reloj en acero crean una silueta impecable para una cena o evento de invierno.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5f5d93891dbb', 'theoutnet', 'ton-46376663163061244', 'Simon Cotton And Linen Blend Polo Shirt', 'Officine Générale', 'clothing', 'men', 'Polo de lino y algodón, limpio y ligero, ideal para un porte relajado y pulido.', 'https://www.theoutnet.com/variants/images/46376663163061244/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163061244/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061244/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061244/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061244/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061244/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/officine-generale/tops/polo-shirts/simon-cotton-and-linen-blend-polo-shirt/46376663163061244', 129, 191.99, 'Úsalo con reloj de acero, perfume cítrico suave, pantalón crudo y loafers de ante beige.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-646a31a1c4c9', 'mp-8d5bb353d59a']::text[], 'El polo de lino pide espadrilles, un Seiko azul y un perfume cítrico para un verano elegante. El conjunto es fresco, marítimo y discreto, perfecto para almuerzo, paseo o escapada costera.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, 