INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6ff65be7069d', 'jomashop', 'COS-MDGTS34', 'Miss Dior Blooming Bouquet / Christian Dior EDT Spray 3.4 oz (100 ml) (w)', 'Dior', 'perfume', 'unisex', 'Rosa luminoso y femenino, con una suavidad fresca que acompaña el día.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/i/miss-dior-blooming-bouquet-christian-dior-edt-spray-34-oz-100-ml-w-3348900871991.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/i/miss-dior-blooming-bouquet-christian-dior-edt-spray-34-oz-100-ml-w-3348900871991.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/i/miss-dior-blooming-bouquet-christian-dior-edt-spray-3-4-oz-100-ml-w-3348900871991_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/i/miss-dior-blooming-bouquet-christian-dior-edt-spray-3-4-oz-100-ml-w-3348900871991_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/i/miss-dior-blooming-bouquet-christian-dior-edt-spray-3-4-oz-100-ml-w-3348900871991_3.jpg', 'https://compraperfumesoriginales.com/product-images/miss-dior-blooming-bouquet-3348900871991-3173.png', 'https://assets.solesense.com/en/images/products/500/miss-dior-blooming-bouquet-christian-dior-edt-spray-3-4-oz-100-ml-white-3348900871991oz_1.jpg', 'https://compraperfumesoriginales.com/product-images/miss-dior-blooming-bouquet-3348900871991.png']::text[], 'https://www.jomashop.com/miss-dior-blooming-bouquet-christian-dior-edt-spray-3-4-oz-100-ml-w-3348900871991.html', 129.99, 192.99, 'Acompáñalo con reloj delicado, vestido marfil y sandalias nude; perfume floral limpio.', 'https://morningkoffee.com/wp-content/uploads/2025/05/Comfy-summer-outfit-Tote-bag-@bonheur-.linenclothing-linenoutfit-summerstyles-bonheurbag-birkenstocks-pinstripes-linenshirt-linenpants-totebag-canvasbag-casualoutfit-summerlooks.jpg', ARRAY['mp-207fc3fa1532', 'mp-b9b2b677d2ef', 'mp-68b8b7f85f35']::text[], 'Para verano, apuesta por el polo de lino, espadrilles y un PRX dorado: fresco, limpio y con un punto distinguido. Blooming Bouquet acompaña con un perfil floral suave y luminoso, ideal para el día o una cena al aire libre.', 'verano', ARRAY['mp-eccea3334d40', 'mp-ca5e6334e29b', 'mp-b92296fdc3b1']::text[], 'Para verano, el vestido floral, las sandalias de cuero y el reloj azul crean una feminidad ligera y elegante. Blooming Bouquet aporta rosas y peonía delicadas, un perfume fresco y romántico para el día o una comida especial.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
