lan deportivo.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-37fd1af3f852', 'jomashop', 'Z-4FWCZ', 'Giorgio Armani Men''s Armani Code Parfum Spray 4.2 oz', 'Giorgio Armani', 'perfume', 'men', 'Cálido, moderno y definido; un aroma de noche con gesto ejecutivo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-armani-code-parfum-spray-4-2-oz-fragrances-3614273604932.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-armani-code-parfum-spray-4-2-oz-fragrances-3614273604932.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-armani-code-parfum-spray-42-oz-fragrances-3614273604932_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-armani-code-parfum-spray-42-oz-fragrances-3614273604932_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-armani-code-parfum-spray-42-oz-fragrances-3614273604932_7.jpg', 'https://www.maxiparfum.hu/images/products/3614273604932-giorgio-armani-armani-code-parfum-125-ml-2-550x550.png']::text[], 'https://www.jomashop.com/giorgio-armani-mens-armani-code-parfum-edp-spray-4-2-oz-fragrances-3614273604932.html', 129.99, 192.99, 'Combínalo con reloj clásico, traje azul marino y zapatos negros de piel pulida.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-4f703db7d409', 'mp-3c75f66f94e0', 'mp-993ce0e172fa']::text[], 'La camisa de lyocell, los loafers de terciopelo y el Seiko negro construyen una presencia sobria para oficina o noche. Armani Code Parfum aporta una faceta ambarada, elegante y seductora.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
