nder=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b5f3689e32d6', 'jomashop', 'Z-RGETY', 'Prada Infusion De Rose for Ladies by Prada Eau De Parfum Spray 3.4 oz (100 ml)', 'Prada', 'perfume', 'women', 'Rosa tenue y limpio, con refinamiento sereno y una feminidad muy pulida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-infusion-de-rose-for-ladies-by-prada-eau-de-parfum-spray-34-oz-100-ml-8435137754601.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-infusion-de-rose-for-ladies-by-prada-eau-de-parfum-spray-34-oz-100-ml-8435137754601.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-infusion-de-rose-for-ladies-by-prada-eau-de-parfum-spray-34-oz-100-ml-8435137754601_2.jpg', 'https://www.parfuem365.de/media/image/f7/a4/8e/8435137754601.jpg', 'https://www.maxaroma.com/productimages/large/UP8435137754601.jpg?ver=1601576595', 'https://img.pzrmcdn.com/mnresize/1180/1182/asset/8435137754601/images/pradainfusionderoseedp100mlkadnparfm-1.jpg', 'https://www.occhiali-profumi.com/media/catalog/product/cache/cf4220b8fda3ebb5571dad8beab3fcd2/8/4/8435137754601.jpg']::text[], 'https://www.jomashop.com/prada-infusion-de-rose-for-ladies-by-prada-eau-de-parfum-spray-3-4-oz-8435137754601.html', 129.99, 192.99, 'Úsalo con reloj fino, blazer marfil y tacones beige; perfume floral suave, silueta ordenada.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-56139b744bbc', 'mp-f9f99f3e6118', 'mp-c92d231b1d76']::text[], 'Infusion de Rose es delicado y pulcro; los pantalones rectos, los pumps y el reloj cristalino afinan el conjunto. Ideal para oficina o almuerzo elegante, con una feminidad serena y actual.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-57625857aaaa', 'jomashop', 'Y-90315', 'Yves Saint Laurent Ladies Libre Intense EDP Spray 3 oz', 'Yves Saint Laurent', 'perfume', 'women', 'Lavanda intensa y vainilla cremosa en una firma femenina poderosa y pulida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-intense-edp-spray-3-oz-fragrances-3614273069557.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-intense-edp-spray-3-oz-fragrances-3614273069557.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-intense-edp-spray-3-oz-fragrances-3614273069557_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-intense-edp-spray-3-oz-fragrances-3614273069557_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/y/v/yves-saint-laurent-ladies-libre-intense-edp-spray-3-oz-fragrances-3614273069557_2_1.jpg?width=546&height=546', 'https://i5.walmartimages.com/seo/Yves-Saint-Laurent-Ladies-Libre-Intense-EDP-Spray-3-oz-Fragrances-3614273069557_bfa2aedc-da90-4cfa-8f56-2bbca8c895aa.34ca5dbf5b68fed11ff42bfe9c3820d4.jpeg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/y/v/yves-saint-laurent-ladies-libre-intense-edp-spray-30-oz-tester-fragrances-t3614273069557.jpg?width=546&height=546', 'https://kassioperfumaria.vteximg.com.br/arquivos/ids/233963-1000-1000/3614273069557-0.png?v=638325671486530000']::text[], 'https://www.jomashop.com/yves-saint-laurent-ladies-libre-intense-edp-spray-3-oz-fragrances-3614273069557.html', 129.99, 192.99, 'Combínalo con reloj dorado discreto, vestido negro largo y sandalias finas; perfume ámbar floral, caída elegante.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-8b1d23d08a7c', 'mp-2a81e6864b82', 'mp-7997636e757e']::text[], 'Libre Intense, cálido y floral-ambarado, pide contraste sofisticado. Los pantalones con brillo, los pumps y el reloj negro dorado forman un conjunto contundente para invierno y noches formales.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-45666e31d0a0', 'jomashop', 'Z-GPNRK', 'Yves Saint Laurent Ladies Black Opium Over Red EDP Spray 3.0 oz', 'Yves Saint Laurent', 'perfume', 'women', 'Fruta oscura y café en una versión más intensa, seductora y moderna.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-black-opium-over-red-edp-spray-30-oz-fragrances-3614274076202.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-black-opium-over-red-edp-spray-30-oz-fragrances-3614274076202.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-black-opium-over-red-edp-spray-30-oz-fragrances-3614274076202_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-black-opium-over-red-edp-spray-30-oz-fragrances-3614274076202_7.jpg', 'https://compraperfumesoriginales.com/product-images/opium-black-over-red-3614274076202-7283.png', 'https://www.kozmo.rs/image/cache/wp/gj/Parfum Company/PC-076202/Yves Saint Laurent Black Opium Over Red Edp 90ml - 3614274076202 - Kozmo (2).-640x640.webp']::text[], 'https://www.jomashop.com/yves-saint-laurent-ladies-black-opium-over-red-edp-spray-3-0-oz-fragrances-3614274076202.html', 129.99, 192.99, 'Llévalo con reloj acero pulido, top negro y falda satinada; perfume gourmand, accesorios mínimos.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-6ef5af9ad162', 'mp-95ac9c8c22b8', 'mp-7997636e757e']::text[], 'Black Opium Over Red, intenso y gourmand, acompaña el satén, los pumps afilados y el reloj oscuro. Un look de noche invernal, sensual y elegante, con carácter sin perder pulcritud.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-06ff9dcd5d2f', 'theoutnet', 'ton-1647597334788388', 'Cropped Zebra Print Twill Shirt', 'Balmain', 'clothing', 'women', 'Camisa recortada con zebra print, audaz y pulida, para destacar con sofisticación contemporánea.', 'https://www.theoutnet.com/variants/images/1647597334788388/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597334788388/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597334788388/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597334788388/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597334788388/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597334788388/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/tops/long-sleeved-tops/cropped-zebra-print-twill-shirt/1647597334788388', 130, 192.99, 'Combínala con reloj negro minimalista, perfume amaderado y pantalón sastre beige con mocasines negros.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-2208bf601ddb', 'mp-c798e1926e9d', 'mp-db86cdd766da']::text[], 'La camisa zebra se ordena con loafers, reloj de madreperla y Creed Spring Flower, floral y luminoso. El resultado es profesional y distinto, perfecto para oficina con código elegante y seguro.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-207fc3fa1532', 'theoutnet', 'ton-46376663163112928', 'Sebastian Linen Jersey Polo Shirt', 'Orlebar Brown', 'clothing', 'men', 'Polo de lino, liviano y sobrio, para una elegancia natural junto al mar.', 'https://www.theoutnet.com/variants/images/46376663163112928/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163112928/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163112928/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163112928/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163112928/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163112928/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/polo-shirts/sebastian-linen-jersey-polo-shirt/46376663163112928', 130, 192.99, 'Combínalo con reloj de acero cepillado, perfume acuático y bermudas piedra con mocasines.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-32f83814872c', 'mp-8d5bb353d59a', 'mp-397d0f68578a']::text[], 'El polo de lino, las espadrilles y Neroli Portofino forman un verano impecable y relajado. La fragancia aporta cítricos luminosos y un toque mediterráneo, perfecto para el día junto al mar.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b1497c588a00', 'theoutnet', 'ton-46376663163112927', 'Maitan Linen Shirt', 'Orlebar Brown', 'clothing', 'men', 'Camisa de lino con caída limpia, perfecta para un estilo relajado y refinado.', 'https://www.theoutnet.com/variants/images/46376663163112927/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163112927/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163112927/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163112927/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163112927/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163112927/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/maitan-linen-shirt/46376663163112927', 130, 192.99, 'Úsala con reloj sencillo, pantalón blanco roto y zapatillas de cuero minimalistas.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-32f83814872c', 'mp-6a32aace5e0a', 'mp-397d0f68578a']::text[], 'La camisa de lino, el polo complementario y las espadrilles crean un look fresco y sobrio para clima cálido. Neroli Sauvage añade cítricos nítidos y un fondo limpio, ideal para vacaciones.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3d070978e5a8', 'jomashop', 'CZAW1236-03A', 'Citizen Eco-Drive Silver Dial Black Leather Men''s Watch', 'Citizen', 'watch', 'women', 'Reloj Citizen de esfera plata y cuero negro, limpio y versátil para el día impecable.', 'https://citizenwatch.widen.net/content/nzfh8zolpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/nzfh8zolpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-silver-dial-black-leather-men_s-watch-aw1236-03a.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-silver-dial-black-leather-men_s-watch-aw1236-03a_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-silver-dial-black-leather-men_s-watch-aw1236-03a_3.jpg', 'https://i5.walmartimages.com/seo/Citizen-Eco-Drive-Silver-Dial-Black-Leather-Men-s-Watch-AW1236-03A_45890251-3bff-4a56-9705-eb98e50427c1.2f55eb1ae6056fefd38a0255dd738bf9.jpeg?odnHeight=573&odnWidth=573&odnBg=FFFFFF', 'https://s.turbifycdn.com/aah/4-watches/men-s-citizen-eco-drive-black-leather-strap-dress-watch-aw1236-03a-36.jpg']::text[], 'https://www.jomashop.com/citizen-watch-aw1236-03a.html', 130.63, 193.99, 'Llévalo con perfume cítrico sobrio, camisa blanca, blazer gris y zapatos derby negros.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-37dd49d175c3', 'mp-771e0dce9f5f', 'mp-0c59ff75cce4']::text[], 'El reloj de cuero negro gana presencia junto a la falda midi, las ballerinas y un perfume cremoso-floral. Propuesta femenina y versátil para oficina casual o almuerzo de fin de semana.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-fdac946676d9', 'jomashop', 'Z-MGKFP', 'Maison Margiela Unisex Replica Afternoon Delight EDT Spray 3.4 oz', 'Maison Margiela', 'perfume', 'unisex', 'Dulce y etéreo, con un toque íntimo que deja una impresión distinta.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-afternoon-delight-edt-spray-3-4-oz-fragrances-3614274226454.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-afternoon-delight-edt-spray-3-4-oz-fragrances-3614274226454.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-afternoon-delight-edt-spray-3-4-oz-fragrances-3614274226454_2.jpg', 'https://www.maisonmargiela-fragrances.eu/dw/image/v2/BDCR_PRD/on/demandware.static/-/Sites-margiela-master-catalog/default/dw8e35185e/images/products/MM150/MaisonMargiela-REPLICA-EDT-3614274226454-100ML-ProductPage_2000x2000_01.jpg', 'https://cdn.notinoimg.com/detail_main_hq/maison-margiela/3614274226454_03/replica-afternoon-delight___241108.jpg', 'https://cdn.notinoimg.com/detail_main_hq/maison-margiela/3614274226454_02-o/replica-afternoon-delight___241112.jpg', 'https://mediafiles.maxaroma.com/9cd29e92-4b8f-436f-ad1f-8e368b30dc1d/https://www.maxaroma.com/productimages/large/UP3614274226454_1.jpg?ver=1754667405']::text[], 'https://www.jomashop.com/maison-margiela-unisex-replica-afternoon-delight-edt-spray-3-4-oz-fragrances-3614274226454.html', 131.42, 193.99, 'Combínalo con reloj discreto, tejido negro y botines o mocasines en piel lisa.', 'https://lifewithjazz.com/wp-content/uploads/2022/04/5-Smart-Casual-Outfits-Last-picture.jpg', ARRAY['mp-5f5d93891dbb', 'mp-371303f8ebbb', 'mp-5744d9813fec']::text[], 'Para un verano casual, el polo de lino, las espadrilles y el reloj Promaster forman un conjunto relajado pero pulido. Afternoon Delight sugiere un acorde gourmand, cálido y cremoso, ideal para una salida nocturna sin rigidez.', 'casual', ARRAY['mp-eccea3334d40', 'mp-b89a0d057c25', 'mp-3c42564cbf4d']::text[], 'Para una noche casual de verano, el vestido floral, las flip flops joya y el reloj plateado logran un aire desenfadado y chic. Afternoon Delight deja un rastro suave, gourmand y envolvente, ideal para una cita relajada.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-64542fde01c1', 'jomashop', 'SE-SYMD90', 'Seiko 5 Automatic White Dial Two-tone Ladies Watch', 'Seiko', 'watch', 'women', 'Seiko femenino de dos tonos, clásico y luminoso, con presencia refinada para cada jornada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-two-tone-ladies-watch-symd90.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-two-tone-ladies-watch-symd90.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-two-tone-ladies-watch-symd90_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-two-tone-ladies-watch-symd90_3.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Automatic-White-Dial-Two-tone-Ladies-Watch-SYMD90_329b86db-55f7-4c65-afca-0471ee831ef1.1598c377ecb66102df1acdf90be1cfe5.jpeg']::text[], 'https://www.jomashop.com/seiko-watch-symd90.html', 132.05, 194.99, 'Úsalo con perfume floral suave, blusa marfil, falda midi y tacones nude.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-56139b744bbc', 'mp-f9f99f3e6118', 'mp-5d7de0b2cfb9']::text[], 'El reloj two-tone es clásico y luminoso; los pantalones rectos y los pumps sostienen una imagen profesional. Si sumas Libre L''Absolu Platine, el resultado es elegante, limpio y sofisticado.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-397d0f68578a', 'jomashop', 'SE-SNK621', 'Seiko 5 Automatic Grey Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Seiko clásico de esfera gris, versátil y sereno para el uso diario.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-grey-dial-mens-watch-snk621.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-grey-dial-mens-watch-snk621.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-grey-dial-mens-watch-snk621_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-grey-dial-mens-watch-snk621_3.jpg', 'https://s3-ap-southeast-1.amazonaws.com/xshipimage/Seiko/SNK621K1/SNK621K1.jpg', 'https://watchesofamerica.com/cdn/shop/files/seiko-5-automatic-grey-dial-mens-watch-snk621-570.jpg?v=1777666041&width=900']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snk621.html', 132.05, 194.99, 'Llévalo con camisa oxford azul, pantalón gris y derbies de cuero marrón medio.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-cab8b3ae8035', 'mp-7795ae7c1d60', 'mp-33eb4986cc4c']::text[], 'La camisa de lyocell, los loafers y Eau Sauvage Parfum dan al reloj gris una elegancia contenida. Ideal para oficina o días de ciudad, con una firma limpia, clásica y muy precisa.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-203058f4e322', 'jomashop', 'COS-JADTS33N-A', 'Jadore / Christian Dior EDT Spray 3.3 oz (100 ml) (w)', 'Dior', 'perfume', 'unisex', 'J’adore despliega flores luminosas y feminidad pulida en una estela clásica y delicada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/a/jadore-christian-dior-edt-spray-33-oz-100-ml-w-3348901296632_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/a/jadore-christian-dior-edt-spray-33-oz-100-ml-w-3348901296632_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/a/jadore-christian-dior-edt-spray-33-oz-100-ml-w-3348901296632_2.jpg', 'https://compraperfumesoriginales.com/product-images/jadore-3348901296632.png', 'https://compraperfumesoriginales.com/product-images/jadore-3348901296632-2097.png', 'https://fesshopcr.com/wp-content/uploads/2025/01/3348901296632.jpg']::text[], 'https://www.jomashop.com/christian-dior-perfume-jadts33n-a.html', 131.99, 194.99, 'Acompáñalo con reloj dorado fino, vestido seda marfil y sandalias crema de líneas limpias.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-b1497c588a00', 'mp-ac85563341af', 'mp-aaadd7c31bbe']::text[], 'Para verano y ocasiones elegantes, la camisa de lino, los loafers de ante y el reloj Promaster equilibran frescura y refinamiento. J’adore aporta un carácter floral luminoso y limpio, inesperado pero muy pulcro en un hombre seguro.', 'verano', ARRAY['mp-eccea3334d40', 'mp-4f1a6a5f486b', 'mp-b92296fdc3b1']::text[], 'Para verano, el vestido midi floral, los flats de cuero y el reloj azul crean una silueta serena y sofisticada. J’adore acompaña con flores blancas y brillo limpio, ideal para almuerzo elegante o evento diurno.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-eb2f7438d615', 'jomashop', 'Z-6QW99', 'Valentino Men''s Uomo Born in Roma Extradose Parfum 3.4 oz', 'Valentino', 'perfume', 'men', 'Uomo Born in Roma Extradose intensifica la firma italiana con carácter moderno y sensual.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-mens-uomo-born-in-roma-extradose-parfum-3-4-oz-fragrances-3614274350739_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-mens-uomo-born-in-roma-extradose-parfum-3-4-oz-fragrances-3614274350739_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-mens-uomo-born-in-roma-extradose-parfum-34-oz-fragrances-3614274350739_2.jpg', 'https://escentual.com/cdn/shop/files/3614274350739_1.png?v=1736266076', 'https://cdn.notinoimg.com/detail_main_mq/valentino/3614274350739_02-o/born-in-roma-extradose-uomo___250108.jpg', 'https://cdn.jarrolds.co.uk/products-temp/valentino/2025/3614274350739_2{w=1000,h=1000}.jpg', 'https://cdn.notinoimg.com/detail_main_hq/valentino/3614274350739_04/born-in-roma-extradose-uomo___250115.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/9d6243d99187096e972f05545e39058c/v/a/valentino-mens-uomo-born-in-roma-extradose-parfum-34-oz-fragrances-3614274350739.jpg']::text[], 'https://www.jomashop.com/valentino-mens-uomo-born-in-roma-extradose-parfum-3-4-oz-fragrances-3614274350739.html', 132, 194.99, 'Combínalo con reloj acero oscuro, camisa negra, chaqueta estructurada y botas de cuero.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-68b8b7f85f35']::text[], 'Seda satinada, pantalón de sastrería y mocasines de terciopelo crean una presencia nocturna sobria y moderna. Uomo Born in Roma Extradose suma profundidad ambarada y sensual, perfecta para cena o cóctel.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a244c05efe4e', 'jomashop', 'Z-KC2G9', 'Xerjoff Ladies Casamorati Gran Ballo EDP 3.4 oz', 'Xerjoff', 'perfume', 'women', 'Casamorati Gran Ballo evoca romance dorado y presencia teatral con un aire delicado.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-gran-ballo-edp-3-4-oz-fragrances-8033488153281.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-gran-ballo-edp-3-4-oz-fragrances-8033488153281.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-gran-ballo-edp-34-oz-fragrances-8033488153281_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-gran-ballo-edp-34-oz-fragrances-8033488153281_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-gran-ballo-edp-34-oz-fragrances-8033488153281_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-gran-ballo-edp-34-oz-fragrances-8033488153281_7.jpg', 'https://cdn.notinoimg.com/detail_main_hq/xerjoff/8033488153281_02-o/xerjoff-casamorati-1888-gran-ballo-eau-de-parfum-for-women_.jpg', 'https://cdn.paris-avenues.com/image/cache/catalog/Product2/8033488153281-Xerjoff-Casamorati-Gran-Ballo-EDP-100-Ml-2-1000x1000.jpg']::text[], 'https://www.jomashop.com/xerjoff-ladies-casamorati-1888-gran-ballo-edp-3-4-oz-fragrances-8033488153281.html', 132.04, 194.99, 'Llévalo con reloj joya, vestido satén rosa empolvado y tacones finos color nude.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-37dd49d175c3', 'mp-771e0dce9f5f', 'mp-c92d231b1d76']::text[], 'La falda midi estructurada y las ballet flats equilibran su faceta floral y festiva con gracia. Perfecto para un almuerzo elegante o una salida de tarde, con reloj delicado como acento femenino.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2ecaf353c55e', 'jomashop', 'Z-ELZH6', 'Givenchy Men''s Gentleman Society Sport EDP Spray 3.4 oz', 'Givenchy', 'perfume', 'men', 'Acento fresco y dinámico para un porte masculino más activo y actual.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/givenchy-mens-gentleman-society-sport-edp-spray-34-oz-fragrances-3274872502598.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/givenchy-mens-gentleman-society-sport-edp-spray-34-oz-fragrances-3274872502598.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/b3e31d40bbb1abcc90b26106659d5d3f/g/i/givenchy-mens-gentleman-society-sport-edp-spray-34-oz-fragrances-3274872502598_2.jpg?width=800&height=800', 'https://cdn.notinoimg.com/detail_main_hq/givenchy/3274872502598_06/gentleman-society-sport___260204.jpg']::text[], 'https://www.jomashop.com/givenchy-mens-gentleman-society-sport-edp-spray-3-4-oz-fragrances-3274872502598.html', 132.53, 195.99, 'Combínalo con reloj deportivo sobrio, polo blanco y sneakers de cuero gris claro.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-e518f29b87d4', 'mp-88537ad017be']::text[], 'Camiseta limpia, sneakers técnicos y reloj de espíritu outdoor: una lectura deportiva bien resuelta para ciudad o viaje. Gentleman Society Sport aporta frescura aromática y energía mineral, sin perder pulso elegante.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9c175b220b04', 'jomashop', 'Z-GY6R5', 'Hugo Boss Men''s The Collection Elegant Vetiver EDP Spray 3.4 oz', 'Hugo Boss', 'perfume', 'men', 'Vetiver elegante y seco, pensado para una presencia pulida y reservada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-the-collection-elegant-vetiver-edp-spray-34-oz-fragrances-3614229387742.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-the-collection-elegant-vetiver-edp-spray-34-oz-fragrances-3614229387742.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-the-collection-elegant-vetiver-edp-spray-34-oz-fragrances-3614229387742_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/h/u/hugo-boss-mens-the-collection-elegant-vetiver-edp-spray-34-oz-fragrances-3614229387742_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/o/p/open-box-hugo-boss-mens-the-collection-elegant-vetiver-edp-spray-34-oz-fragrances-3614229387742.jpg', 'https://fredrikoglouisa.no/wp-content/uploads/2022/10/3614229387742_1.jpg', 'https://facescr.vtexassets.com/arquivos/ids/190628/3614229387742_3.jpg?v=638725655631070000']::text[], 'https://www.jomashop.com/hugo-boss-mens-the-collection-elegant-vetiver-edp-spray-3-4-oz-fragrances-3614229387742.html', 132.84, 195.99, 'Úsalo con reloj de acero, saco azul tinta y zapatos negros o burdeos oscuro.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-d3392a7bbb8e', 'mp-c680203f6394', 'mp-397d0f68578a']::text[], 'Camisa de rayas, loafers sobrios y un Seiko discreto construyen un look profesional, pulcro y silenciosamente lujoso. Vetiver refuerza la seriedad con un carácter verde, seco y elegante, ideal para oficina.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-136bf9c3e1ec', 'jomashop', 'Z-XRA3H', 'Jean Paul Gaultier Men''s Scandal Pour Homme Intense EDP Spray 3.4 oz', 'Jean Paul Gaultier', 'perfume', 'men', 'Scandal Pour Homme Intense combina profundidad dulce y fuerza elegante para noches decisivas.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-pour-homme-intense-edp-spray-34-oz-fragrances-8435415102728.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-pour-homme-intense-edp-spray-34-oz-fragrances-8435415102728.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-pour-homme-intense-edp-spray-34-oz-fragrances-8435415102728_7.jpg', 'https://cdn.notinoimg.com/detail_main_hq/jean-paul-gaultier/8435415102728_02-o/scandal-pour-homme-intense___250304.jpg', 'https://cdn.notinoimg.com/detail_main_hq/jean-paul-gaultier/8435415102728_03/scandal-pour-homme-intense___250225.jpg', 'https://cdn.notinoimg.com/social/jean-paul-gaultier/8435415102728_01-o/scandal-pour-homme-intense___250304.jpg', 'https://cdn.notinoimg.com/detail_main_hq/jean-paul-gaultier/8435415102728_05/scandal-pour-homme-intense___250225.jpg']::text[], 'https://www.jomashop.com/jean-paul-gaultier-mens-scandal-pour-homme-edt-spray-3-4-oz-fragrances-8435415102728.html', 132.84, 195.99, 'Úsalo con reloj negro, abrigo camel, camisa de seda oscura y botines pulidos.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-f3cd717d3b87', 'mp-98496652d515']::text[], 'Satinado negro, mocasines ornamentales y oro discreto elevan el conjunto hacia una noche de invierno muy sofisticada. Scandal Pour Homme Intense aporta miel, ámbar y madera: cálido, seductor y rotundo.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-768dc0a820c7', 'jomashop', 'Z-48J9Y', 'Maison Margiela Unisex Replica Dancing On The Moon EDP Spray 3.4 oz', 'Maison Margiela', 'perfume', 'unisex', 'Un acorde onírico y cálido, ideal para momentos de noche con distinción.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-dancing-on-the-moon-edp-spray-34-oz-fragrances-3614271429872.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-dancing-on-the-moon-edp-spray-34-oz-fragrances-3614271429872.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-dancing-on-the-moon-edp-spray-34-oz-fragrances-3614271429872_7.jpg', 'https://cdn.notinoimg.com/detail_main_hq/maison-margiela/3614271429872_02-o/replica-dancing-on-the-moon___240704.jpg', 'https://cdn.notinoimg.com/detail_main_lq/maison-margiela/3614271429872_04/maison-margiela-replica-dancing-on-the-moon-eau-de-parfum-unisex___240704.jpg', 'https://www.maisonmargiela-fragrances.eu/dw/image/v2/BDCR_PRD/on/demandware.static/-/Sites-margiela-master-catalog/default/dw6ae33430/images/products/MM153/mm_replica_edp_dancing_on_the_moon_ingredients_compo_100ml_3614271429872_rvb_1x1.jpg?sw=1152&sh=1152&sm=cut&sfrm=jpg&q=70', 'https://cdn.notinoimg.com/detail_main_hq/maison-margiela/3614271429872_03/maison-margiela-replica-dancing-on-the-moon-eau-de-parfum-unisex___240704.jpg']::text[], 'https://www.jomashop.com/maison-margiela-unisex-replica-dancing-on-the-moon-edp-spray-3-4-oz-fragrances-3614271429872.html', 132.99, 195.99, 'Combínalo con reloj oscuro, vestido fluido negro y sandalias finas en piel satinada.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-c109304a8cd3']::text[], 'Para una noche elegante, la camisa satinada, los loafers de terciopelo y el reloj azul añaden contraste y lujo contenido. Dancing On The Moon se siente luminoso, elegante y ligeramente nocturno, perfecto para una cena especial.', 'noche', ARRAY['mp-33c53e7b9d78', 'mp-d0246a15c10d', 'mp-64542fde01c1']::text[], 'Para noche elegante, el vestido de punto, los pumps clásicos y el reloj nácar dibujan una silueta pulida y sensual. Dancing On The Moon aporta un aura suave, luminosa y moderna, ideal para una cena o cóctel.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ca4d6e9f65ab', 'jomashop', 'COS-VLVES34-Q', 'Velvet Orchid by Tom Ford EDP Spray 3.4 oz (100 ml) (w)', 'Tom Ford', 'perfume', 'unisex', 'Florido aterciopelado, sofisticado y envolvente con brillo nocturno.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/velvet-orchid-by-tom-ford-edp-spray-3-4-oz-100-ml-w-888066023955.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/velvet-orchid-by-tom-ford-edp-spray-3-4-oz-100-ml-w-888066023955.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/velvet-orchid-by-tom-ford-edp-spray-34-oz-100-ml-w-888066023955_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/velvet-orchid-by-tom-ford-edp-spray-34-oz-100-ml-w-888066023955_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/velvet-orchid-by-tom-ford-edp-spray-34-oz-100-ml-w-888066023955_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/v/e/velvet-orchid-tom-ford-edp-spray-34-oz-w-888066023955.jpg?width=546&height=546', 'https://www.nk.se/globalassets/888066023955.jpg?ref=25A8FCDDC5&format=jpg&quality=85', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/v/e/velvet-orchid-by-tom-ford-edp-spray-34-oz-100-ml-w-888066023955_1.jpg?width=546&height=546']::text[], 'https://www.jomashop.com/tom-ford-perfume-vlves34-q.html', 132.95, 195.99, 'Acompáñalo con reloj fino, vestido satinado o sastrería fluida y sandalias nude; oro suave y crema.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-76e86cc39c9a', 'mp-ac85563341af', 'mp-23af6e30e1cc']::text[], 'Para una noche sobria y elegante, el pantalón de lana, los loafers de ante y el Presage azul construyen una presencia muy Maison Privée. Velvet Orchid añade un fondo floral oscuro, cremoso y envolvente, de gran clase.', 'noche', ARRAY['mp-f4871962fdc0', 'mp-f597bbe6ab0b', 'mp-8b8b764da74e']::text[], 'Para una noche de lujo silencioso, el sweater de cashmere, los flats de cuero y el reloj nácar equilibran abrigo y elegancia. Velvet Orchid aporta un perfil floral ambarado, suave y profundo, ideal para destacar sin estridencias.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-cb004bfbf1f3', 'jomashop', 'Z-VE56R', 'Valentino Ladies Donna Born In Roma Intense EDP 3.4 oz', 'Valentino', 'perfume', 'women', 'Donna Born in Roma Intense ofrece intensidad femenina y elegancia urbana con fondo envolvente.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-donna-born-in-roma-intense-edp-3-4-oz-fragrances-3614273790840.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-donna-born-in-roma-intense-edp-3-4-oz-fragrances-3614273790840.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-donna-born-in-roma-intense-edp-34-oz-fragrances-3614273790840_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-donna-born-in-roma-intense-edp-34-oz-fragrances-3614273790840_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-donna-born-in-roma-intense-edp-34-oz-fragrances-3614273790840_7.jpg', 'https://abclive1.s3.amazonaws.com/31a7f8a4-c7f7-4d3a-81a6-26f396972754/productimage/P-3614273790840___L.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-donna-born-in-roma-intense-edp-34-oz-fragrances-3614273790840.jpg', 'https://abclive1.s3.amazonaws.com/31a7f8a4-c7f7-4d3a-81a6-26f396972754/productimage/P-3614273790840___1___XL.jpg']::text[], 'https://www.jomashop.com/valentino-ladies-donna-born-in-roma-intense-edp-3-4-oz-fragrances-3614273790840.html', 132.99, 195.99, 'Combínalo con reloj dorado discreto, vestido negro, blazer entallado y sandalias de cuero.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-56139b744bbc', 'mp-f9f99f3e6118', 'mp-cebec8d3d39d']::text[], 'Pantalón de lana, pumps de cristal y reloj discreto crean un look invernal y elegante. La fragancia es intensa, dulce y seductora, perfecta para cenas y ocasiones especiales.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-aa3aa1e2b5dd', 'jomashop', 'SE-SNKE61', 'Seiko 5 Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Seiko 5 azul automático, sobrio y confiable, con un toque deportivo refinado.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snke61.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snke61.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snke61_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snke61_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snke61_4.jpg', 'https://res.cloudinary.com/dp9dnliwc/image/upload/c_pad,h_900,w_900/f_auto/q_auto/wmmedia/watch_images/large/snke61k1_1659380918.jpg', 'https://www.ioomobile.com/assets/images/seiko-snke61k1-men-watch-04.jpg']::text[], 'https://www.jomashop.com/seiko-5-watch-snke61.html', 134, 196.99, 'Combínalo con perfume fresco, polo blanco, pantalón chino gris y zapatillas de cuero.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-d3392a7bbb8e', 'mp-7795ae7c1d60', 'mp-ae99e2aca74c']::text[], 'Camisa de popelina, loafers y un perfume amaderado equilibran el azul del dial con un registro limpio y versátil. Ideal para oficina relajada o fin de semana urbano con elegancia contenida.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e043070ecde2', 'jomashop', 'SE-SNKK25', 'Seiko 5 Automatic White Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Seiko 5 de esfera blanca y acero, pulido y atemporal, ideal para vestir con calma.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-stainless-steel-white-dial-men_s-watch-snkk25.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-stainless-steel-white-dial-men_s-watch-snkk25.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-stainless-steel-white-dial-men_s-watch-snkk25_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-stainless-steel-white-dial-men_s-watch-snkk25_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-stainless-steel-white-dial-men_s-watch-snkk25_4.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Automatic-White-Dial-Stainless-Steel-Men-s-Watch-SNKK25_a541164f-46c1-4c3b-9a63-150783400bb7.5f77720f281854384c043062b5279e86.jpeg', 'https://hnau.imgix.net/media/catalog/product/s/n/snkk25k1-1_1.jpg']::text[], 'https://www.jomashop.com/seiko-5-mens-watch-snkk25.html', 134, 196.99, 'Úsalo con perfume limpio, camisa celeste, sastre gris y zapatos oxford café.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-d3392a7bbb8e', 'mp-7795ae7c1d60', 'mp-2dc2d5978672']::text[], 'Popelina rayada, loafers de cuero y un clásico cítrico crean una imagen sobria y confiable, sin rigidez. Eau Sauvage aporta frescura aromática y atemporal, ideal para oficina y diario.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7b3c22e58e52', 'jomashop', 'Z-VKV3G', 'Jean Paul Gaultier Men''s Scandal Le Parfum EDP Spray 5.0 oz', 'Jean Paul Gaultier', 'perfume', 'men', 'Scandal Le Parfum potencia una sensualidad cálida y moderna con presencia rotunda.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-le-parfum-edp-spray-50-oz-fragrances-8435415065214.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-le-parfum-edp-spray-50-oz-fragrances-8435415065214.jpg', 'https://resources.sanborns.com.mx/imagenes-sanborns-ii/1200/8435415065214_2.jpg?scale=500&qlty=75', 'https://cdn.cosmetics.vn/nuoc-hoa/v/jean-paul-gaultier-scandal-le-parfum-pour-homme-eau-de-perfume-edp-spray-150ml-8435415065214-1.jpg']::text[], 'https://www.jomashop.com/jean-paul-gaultier-mens-scandal-le-parfum-edp-spray-5-0-oz-fragrances-8435415065214.html', 133.99, 196.99, 'Combínalo con reloj negro brillante, blazer de terciopelo, camisa oscura y botas elegantes.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-5e2e71d7480e', 'mp-68b8b7f85f35']::text[], 'Satinado, brogues con presencia y acentos dorados forman un look de noche contundente y pulido. Scandal Le Parfum añade dulzor profundo, ámbar y calidez especiada, perfecto para invierno.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-981a93fef36b', 'jomashop', 'Z-PPPPR', 'Jean Paul Gaultier Men''s Scandal Absolu Parfum 3.4 oz', 'Jean Paul Gaultier', 'perfume', 'men', 'Scandal Absolu proyecta intensidad profunda y sofisticación, con una estela nocturna muy marcada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-absolu-parfum-3-4-oz-fragrances-8435415080385.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-absolu-parfum-3-4-oz-fragrances-8435415080385.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-absolu-parfum-34-oz-fragrances-8435415080385_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-absolu-parfum-34-oz-fragrances-8435415080385_7.jpg', 'https://bestbrandsperfume.com/wp-content/uploads/2025/12/Jean-Paul-Gaultier-Scandal-Absolu-Pour-Homme-Mens-Parfum-Concentre-Spray-3.4-oz-8435415080385-164-Retail-100ml-Sealed-.webp', 'https://cdn.notinoimg.com/detail_main_hq/jean-paul-gaultier/8435415080385_06_/scandal-pour-homme-absolu___250410.jpg']::text[], 'https://www.jomashop.com/jean-paul-gaultier-mens-scandal-absolu-parfum-3-4-oz-fragrances-8435415080385.html', 133.68, 196.99, 'Llévalo con reloj de acero negro, abrigo largo, cuello alto y zapatos de gamuza.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-474b2526c36a', 'mp-98496652d515']::text[], 'La seda brillante, el velvet y el oro crean una estética opulenta, muy propia de noche e invierno. Scandal Absolu intensifica el conjunto con notas gourmand, ambaradas y densas, de gran estela.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
