DED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-17575cface64', 'jomashop', 'Z-BHJEV', 'Giorgio Armani Men''s Armani Code EDT Spray 6.7 oz', 'Giorgio Armani', 'perfume', 'men', 'Clásico moderno con firma sensual, preciso para una imagen sofisticada y segura.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-armani-code-edt-spray-67-oz-fragrances-8431240392181.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-armani-code-edt-spray-67-oz-fragrances-8431240392181.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-armani-code-edt-spray-67-oz-fragrances-8431240392181_7.jpg', 'https://i5.walmartimages.com/seo/Giorgio-Armani-Men-s-Armani-Code-EDT-Spray-6-7-oz-Fragrances-8431240392181_5a5f0b2b-0820-4a1d-bc18-699a5ac5773d.af547614bd53b5d6103d3cd7b2b5a371.jpeg']::text[], 'https://www.jomashop.com/giorgio-armani-mens-armani-code-edt-spray-6-7-oz-fragrances-8431240392181.html', 134.99, 197.99, 'Llévalo con reloj automático, traje gris carbón y mocasines negros de suela fina.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-99cf05ce2452', 'mp-ccd7e4d707b6', 'mp-a87722f18d77']::text[], 'Camisa blanca limpia, brogues clásicos y un Seiko de líneas discretas sostienen un código ejecutivo sin estridencias. Armani Code suma un toque ambarado y moderno, ideal para oficina y cena.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCL