INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ae99e2aca74c', 'jomashop', 'Z-CAN4E', 'Givenchy Men''s Gentleman Reserve Privee EDP 6.7 oz', 'Givenchy', 'perfume', 'men', 'Gentleman Reserve Privée une iris y madera en una elegancia sobria, masculina y precisa.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/givenchy-mens-gentleman-reserve-privee-edp-67-oz-fragrances-3274872461642.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/givenchy-mens-gentleman-reserve-privee-edp-67-oz-fragrances-3274872461642.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/givenchy-mens-gentleman-reserve-privee-edp-67-oz-fragrances-3274872461642_2.jpg', 'https://a.allegroimg.com/s720/117ac9/41c5e9e9430f99ad7aed0c67c127/GIVENCHY-GENTLEMAN-RESERVE-PRIVEE-EDP-100ML-ORYGINAL']::text[], 'https://www.jomashop.com/givenchy-mens-gentleman-reserve-privee-edp-6-7-oz-fragrances-3274872461642.html', 134.99, 197.99, 'Combínalo con reloj acero pulido, traje azul tinta, camisa blanca y derby negros.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4f703db7d409', 'mp-c680203f6394', 'mp-a87722f18d77']::text[], 'La camisa de twill, los loafers de ante y el reloj sobrio refuerzan una elegancia contenida y contemporánea. Reserve Privee aporta ron, iris y madera suave: refinado para oficina y noche.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2869630c1217', 'jomashop', 'Z-2VRJL', 'Maison Margiela Unisex Soul of The Forest EDP Spray 3.4 oz', 'Maison Margiela', 'perfume', 'unisex', 'Soul of the Forest captura un bosque húmedo y oscuro, profundo y sereno.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-soul-of-the-forest-edp-spray-3-4-oz-fragrances-3614271429902.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-soul-of-the-forest-edp-spray-3-4-oz-fragrances-3614271429902.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-soul-of-the-forest-edp-spray-34-oz-fragrances-3614271429902_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-soul-of-the-forest-edp-spray-34-oz-fragrances-3614271429902_7.jpg', 'https://i5.walmartimages.com/seo/Maison-Margiela-Unisex-Soul-of-The-Forest-EDP-Spray-3-4-oz-Fragrances-3614271429902_e5baf4ee-a533-4517-955b-8ea9bcf2c668.ee5b8303aecbad025f92e82cbf7a5606.jpeg', 'https://samawa.ae/cdn/shop/files/3614271429902_1.jpg?v=1736157671', 'https://www.alseerandsafeer.com/image/cache/catalog/brands/maison-margiela/products/3614271429902_1-550x550h.jpg.webp', 'https://cdn.notinoimg.com/detail_main_hq/maison-margiela/3614271429902_02-o/maison-margiela-replica-soul-of-the-forest-eau-de-parfum-unisex___240704.jpg']::text[], 'https://www.jomashop.com/martin-margiela-unisex-soul-of-the-forest-edp-spray-3-4-oz-fragrances-3614271429902.html', 134.89, 197.99, 'Llévalo con reloj verde oscuro o negro, abrigo lana, punto grueso y botas de cuero.', 'https://www.pennypincherfashion.com/wp-content/uploads/2018/12/Layered-Winter-Outfits-2.png', ARRAY['mp-bdcc5c48a475', 'mp-55daa2a79111', 'mp-68b8b7f85f35']::text[], 'Para invierno, el sweater rayado, la bomber con borrego y los loafers Thom Browne crean una textura rica y masculina. Soul of The Forest acompaña con un carácter amaderado, terroso y contemplativo, perfecto para tardes frías.', 'invierno', ARRAY['mp-cf73e236b136', 'mp-2ca59b3d8894', 'mp-f4871962fdc0']::text[], 'Para invierno, el vestido de punto, las botas de caña alta y el reloj nácar logran un look cálido y refinado. Soul of The Forest suma maderas y musgo, un perfume profundo y sereno para días fríos.', 'invierno') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d3b04c599098', 'jomashop', 'COS-PIDES34B', 'Prada Infusion Diris / Prada EDP Spray 3.4 oz (100 ml) (w)', 'Prada', 'perfume', 'unisex', 'Prada Infusion d’Iris ofrece limpieza refinada y una suavidad blanca de aire parisino.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-infusion-diris-prada-edp-spray-34-oz-100-ml-w-8435137743155.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-infusion-diris-prada-edp-spray-34-oz-100-ml-w-8435137743155.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-infusion-diris-prada-edp-spray-34-oz-100-ml-w-8435137743155_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-infusion-diris-prada-edp-spray-34-oz-100-ml-w-8435137743155_7.jpg', 'https://perfumeriasclapes.es/wp-content/uploads/2022/03/8435137743155-ok1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/p/r/prada-infusion-diris-prada-edp-spray-3-4-oz-100-ml-w-8435137743155_2.jpg?width=546&height=546', 'https://abclive1.s3.amazonaws.com/31a7f8a4-c7f7-4d3a-81a6-26f396972754/productimage/8435137743155___1___XL.jpg', 'https://tfcff1.vteximg.com.br/arquivos/ids/157638-1000-1000/8435137743155_1.png?v=637762936993000000']::text[], 'https://www.jomashop.com/prada-perfume-pides34b.html', 134.99, 197.99, 'Combínalo con reloj de acero fino, blusa blanca, pantalón sastre y mocasines nude.', 'https://i.pinimg.com/736x/35/8d/a6/358da61f35d03c9a72d7796edeb64275--formal-outfits-work-outfits.jpg', ARRAY['mp-4f703db7d409', 'mp-a1a9c18f6ebe', 'mp-a7fbae0e4ca7']::text[], 'Para oficina o almuerzo ejecutivo en Lima: la camisa limpia, los loafers pulidos y el PRX champagne proyectan discreción y precisión. Prada Infusion Diris aporta un iris suave, empolvado y elegante, ideal para un porte sobrio y refinado.', 'lujo-silencioso', ARRAY['mp-792737be6247', 'mp-08cb860e5a5a', 'mp-c798e1926e9d']::text[], 'Para oficina o reuniones formales: el pantalón estructurado, los pumps y el PRX en madre perla crean una línea pulcra y femenina. Prada Infusion Diris suma un iris limpio, delicado y sereno, perfecto para un lujo discreto.', 'oficina') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-42dd8d4c10ba', 'jomashop', 'Z-ULRH5', 'Tom Ford Ombre Leather Eau de Parfum Spray 3.4 oz', 'Tom Ford', 'perfume', 'women', 'Cuero suave y oscuro, con una estela refinada y moderna.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-ombre-leather-eau-de-parfum-spray-3-4-oz-888066075145_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-ombre-leather-eau-de-parfum-spray-3-4-oz-888066075145_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-ombre-leather-eau-de-parfum-spray-34-oz-888066075145_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-ombre-leather-eau-de-parfum-spray-34-oz-888066075145_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-ombre-leather-eau-de-parfum-spray-34-oz-888066075145_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/t/o/tom-ford-ombre-leather-eau-de-parfum-spray-34-oz-888066075145_1.jpg?width=546&height=546', 'https://www.topsandbottomsusa.com/cdn/shop/files/tom-ford-mens-tom-ford-ombre-leather-edp-spray-3-4-oz-888066075145_2.jpg?v=1698269881&width=1200', 'https://www.prijs-parfum.nl/images/Tom-Ford/Tom-Ford-Ombre-Leather-100ml-EDP-Spray-888066075145.jpg']::text[], 'https://www.jomashop.com/tom-ford-ombre-leather-eau-de-parfum-spray-888066075145.html', 136, 198.99, 'Llévalo con reloj negro o acero, camisa negra y botas Chelsea; añade lana, carbón y café.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-8b1d23d08a7c', 'mp-95ac9c8c22b8', 'mp-3d070978e5a8']::text[], 'Los pantalones de lana con brillo, pumps de cuero y un reloj sobrio equilibran el cuero oscuro del perfume. Ideal para noche de invierno; aroma intenso, sensual y seco, con carácter elegante y envolvente.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-38da4925ae6b', 'theoutnet', 'ton-46376663163098221', 'Travis Printed Woven Shirt', 'Orlebar Brown', 'clothing', 'men', 'Camisa estampada con aire ligero, pensada para vestir con frescura y estilo.', 'https://www.theoutnet.com/variants/images/46376663163098221/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163098221/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098221/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098221/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098221/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098221/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/travis-printed-woven-shirt/46376663163098221', 136, 198.99, 'Combínala con reloj de acero, perfume cítrico y pantalón beige con mocasines blancos.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-162803429493', 'mp-0de6cc427e14', 'mp-5744d9813fec']::text[], 'La camisa estampada pide sandalias limpias y un perfume marino para un verano relajado pero bien vestido. Acqua di Gio Parfum suma frescura mineral, limpia y luminosa, ideal para el día.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3e4f57e6ec66', 'theoutnet', 'ton-46376663163061257', 'Simon Cotton And Linen Blend Polo Shirt', 'Officine Générale', 'clothing', 'men', 'Polo de lino y algodón, sobrio y fresco, con una línea impecable.', 'https://www.theoutnet.com/variants/images/46376663163061257/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163061257/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061257/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061257/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061257/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061257/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/officine-generale/tops/polo-shirts/simon-cotton-and-linen-blend-polo-shirt/46376663163061257', 136, 198.99, 'Úsalo con reloj discreto, pantalón arena y loafers de ante en tono tabaco.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-d74238edf829', 'mp-8d5bb353d59a']::text[], 'Las espadrilles de ante y la Seiko de esfera clara equilibran el polo con refinamiento relajado. Ideal para Lima en verano, con un perfil fresco y sobrio; el Neroli Portofino aporta cítricos, neroli y almizcle limpio.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a87722f18d77', 'jomashop', 'SE-SNK623', 'Seiko 5 Black Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Seiko 5 negro en acero, sobrio y funcional, con presencia limpia de uso diario.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snk623.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snk623.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snk623_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snk623_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snk623_4.jpg', 'https://media.karousell.com/media/photos/products/2023/4/20/seiko_5_snk623_mens_automatic__1681964395_36fd089d_progressive', 'https://media.karousell.com/media/photos/products/2023/4/20/seiko_5_snk623_mens_automatic__1681964395_f97ade4e', 'https://media.karousell.com/media/photos/products/2023/4/14/time_cruze_seiko_5_snk623_auto_1681468599_ec3752b1_progressive']::text[], 'https://www.jomashop.com/seiko-watch-snk623.html', 137.09, 199.99, 'Úsalo con perfume amaderado ligero, camisa oxford, chino carbón y zapatos derby.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-cab8b3ae8035', 'mp-7795ae7c1d60', 'mp-2dc2d5978672']::text[], 'Camisa de lino, loafers pulidos y la Seiko negra crean un registro discreto y profesional. Funciona muy bien en oficina o reunión diurna; Eau Sauvage suma cítricos, hierbas y un fondo elegante, clásico.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d74238edf829', 'jomashop', 'SE-SNK601', 'Seiko 5 Automatic Silver Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Seiko 5 plateado y automático, clásico y equilibrado, pensado para vestir con discreción.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-silver-dial-men_s-watch-snk601.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-silver-dial-men_s-watch-snk601.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-silver-dial-men_s-watch-snk601_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-silver-dial-men_s-watch-snk601_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-silver-dial-men_s-watch-snk601_4.jpg', 'https://www.jomashop.com/media/catalog/product/s/e/seiko-5-automatic-silver-dial-men_s-watch-snk601.jpg', 'https://i5.walmartimages.com/seo/Seiko-Men-s-5-Automatic-Silver-Dial-Watch-SNK601_465d32b4-4814-4f9b-9508-d201db99400d.79737744905429ac2b1c28acad8d0b7d.jpeg?odnHeight=640&odnWidth=640&odnBg=FFFFFF']::text[], 'https://www.jomashop.com/seiko-5-watch-snk601.html', 136.5, 199.99, 'Combínalo con perfume fresco, blazer azul, camisa blanca y zapatos brogue marrones.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-d3392a7bbb8e', 'mp-42bc749064f5', 'mp-9c175b220b04']::text[], 'La camisa de rayas, los loafers de ante y la esfera plateada forman un conjunto limpio y versátil. Para oficina o after office, Elegant Vetiver aporta vetiver seco, maderas y una estela contenida.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7997636e757e', 'jomashop', 'SE-SYMK22', 'Seiko 5 Automatic Black Dial Gold-tone Ladies Watch', 'Seiko', 'watch', 'women', 'Seiko femenino negro y dorado, con brillo contenido y espíritu elegante de diario.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-gold-tone-ladies-watch-symk22.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-gold-tone-ladies-watch-symk22.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-gold-tone-ladies-watch-symk22_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-gold-tone-ladies-watch-symk22_3.jpg']::text[], 'https://www.jomashop.com/seiko-watch-symk22.html', 136.8, 199.99, 'Llévalo con perfume floral limpio, vestido midi negro y tacones nude o loafers.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-56139b744bbc', 'mp-2208bf601ddb', 'mp-ccf304630040']::text[], 'Pantalón estructurado, loafers clásicos y el reloj dorado logran una lectura femenina y profesional. Perfecto para oficina; el perfume suma vainilla oscura, frambuesa y profundidad floral, con un halo elegante.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-993ce0e172fa', 'jomashop', 'SE-SNKK17J1', 'Seiko 5 Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Seiko negro de presencia contenida, versátil y fácil de llevar a diario.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-black-dial-mens-watch-snkk17j1_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-black-dial-mens-watch-snkk17j1_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-black-dial-mens-watch-snkk17j1_2_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-black-dial-mens-watch-snkk17j1_3_1.jpg', 'https://i5.walmartimages.com/seo/Seiko-Men-s-5-Automatic-SNKK17J1-Black-Dial-Stainless-Steel-Watch_f4c7cf52-bd89-49f0-8047-6a8b055ed60a.776c797c7f1cb6724770cdf5ae5db47f.jpeg']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snkk17j1.html', 136.8, 199.99, 'Combínalo con camisa blanca, pantalón marino y zapatos negros de cuero liso.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-357d594d46a8', 'mp-9c175b220b04', 'mp-7795ae7c1d60']::text[], 'Las rayas de lino, el pantalón de twill y el reloj negro construyen un look sobrio y seguro. Perfecto para oficina o ciudad; Elegant Vetiver refuerza con vetiver, maderas y un aire pulcro.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-11a7339e06e4', 'jomashop', 'SE-SNKE51J1', 'Seiko 5 Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Azul profundo y mecánica clásica para un estilo sobrio con carácter.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-blue-dial-mens-watch-snke51j1_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-blue-dial-mens-watch-snke51j1_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-blue-dial-mens-watch-snke51j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-blue-dial-mens-watch-snke51j1_3.jpg', 'https://i5.walmartimages.com/seo/Seiko-Seiko-5-Automatic-Blue-Dial-Men-s-Watch-SNKE51J1_5d3df34c-1617-42b7-95e1-4f8b5b9c4b52.8c88a30c36d1e4d36ae8d568166c44f4.jpeg?odnHeight=573&odnWidth=573&odnBg=FFFFFF', 'https://wp.jomla.ae/wp-content/uploads/2024/01/Seiko-Mens-Series-5-Automatic-Blue-Dial-Stainless-Steel-Watch-Snke51j1GSSNKE51J1.jpg']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snke51j1.html', 136.8, 199.99, 'Llévalo con blazer gris, camisa celeste y derbies marrón oscuro o azul marino.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-160483d92533', 'mp-42bc749064f5', 'mp-2dc2d5978672']::text[], 'El polo velour, los loafers de ante y el azul del dial logran un casual refinado. Muy adecuado para día o cena informal; Acqua di Gio Parfum aporta frescura marina, incienso suave y fondo amaderado.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-28b674995133', 'jomashop', 'CZAW1232-04A', 'Citizen Men''s Straps Eco-Drive Ivory White Dial Watch', 'Citizen', 'watch', 'men', 'Citizen de esfera marfil y correa oscura, cálido y sereno, con carácter clásico.', 'https://citizenwatch.widen.net/content/bffzmktggl/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/bffzmktggl/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-men_s-straps-eco-drive-ivory-white-dial-watch-aw1232-04a_5.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-men_s-straps-eco-drive-ivory-white-dial-watch-aw1232-04a_2_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-men_s-straps-eco-drive-ivory-white-dial-watch-aw1232-04a_3_3.jpg', 'https://cdn.vuanhwatch.com/media/products/21364/dong-ho-nam-citizen-men-s-straps-eco-drive-ivory-white-dial-watch-aw1232-04a-phoi-mau-vang-trang-63a924795452a-26122022113505.jpg', 'https://cdn.vuahanghieu.com/unsafe/0x900/left/top/smart/filters:quality(90)/https://admin.vuahanghieu.com/upload/product/2022/12/dong-ho-nam-citizen-men-s-straps-eco-drive-ivory-white-dial-watch-aw1232-04a-phoi-mau-vang-trang-63a924795eede-26122022113505.jpg']::text[], 'https://www.jomashop.com/citizen-watch-aw1232-04a.html', 136.8, 199.99, 'Combínalo con perfume de té o cítrico, camisa crema, blazer café y loafers.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-7795ae7c1d60', 'mp-d3392a7bbb8e', 'mp-2dc2d5978672']::text[], 'La camisa popelina, los loafers de cuero y el dial marfil transmiten orden y elegancia serena. Ideal para oficina o almuerzo de trabajo; Armani Code suma cítricos, iris y haba tonka con discreción.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ccf304630040', 'jomashop', 'Y-138585', 'Giorgio Armani Ladies Si Intense EDP Spray 3.4 oz', 'Giorgio Armani', 'perfume', 'women', 'Una intensidad femenina y envolvente, ideal para vestir la noche con seguridad.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-si-intense-edp-spray-3-4-oz-fragrances-3614273313162.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-si-intense-edp-spray-3-4-oz-fragrances-3614273313162.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-si-intense-edp-spray-34-oz-fragrances-3614273313162_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-si-intense-edp-spray-3-4-oz-fragrances-3614273313162_3.jpg', 'https://farmaciasanisidro.mx/wp-content/uploads/2023/08/3614273313162.webp', 'https://compraperfumesoriginales.com/product-images/si-intense-3614273313162-3884.png', 'https://compraperfumesoriginales.com/product-images/si-intense-3614273313162-4177.png', 'https://www.perfumecenter.com.mx/cdn/shop/files/3614273313162.jpg?v=1714981709']::text[], 'https://www.jomashop.com/giorgio-armani-ladies-si-edp-spray-3-4-oz-fragrances-3614273313162.html', 136.99, 199.99, 'Combínalo con reloj fino, vestido negro satinado y tacones nude o vino.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-6ef5af9ad162', 'mp-2a81e6864b82', 'mp-c92d231b1d76']::text[], 'La falda satinada, las pumps de gamuza y el reloj azul elevan el perfume a un registro nocturno. Perfecto para invierno; la fragancia es intensa, frutal-ámbar, sensual y muy elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-30c94b9f4b59', 'jomashop', 'Y-131561', 'Jean Paul Gaultier Ladies La Belle EDP Spray 3.4 oz', 'Jean Paul Gaultier', 'perfume', 'women', 'Dulce y luminosa, con una sensualidad marcada para salidas especiales.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-ladies-la-belle-edp-spray-3-4-oz-fragrances-8435415017244.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-ladies-la-belle-edp-spray-3-4-oz-fragrances-8435415017244.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-ladies-la-belle-edp-spray-34-oz-fragrances-8435415017244_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-ladies-la-belle-edp-spray-34-oz-fragrances-8435415017244_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-ladies-la-belle-edp-spray-34-oz-fragrances-8435415017244_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-ladies-la-belle-edp-spray-34-oz-fragrances-8435415017244_5.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-ladies-la-belle-edp-spray-34-oz-fragrances-8435415017244_7.jpg', 'https://www.prijs-parfum.nl/images/Jean-Paul-Gaultier/Jean-Paul-GaultierJPG-La-Belle-edp-100-ml-8435415017244.jpg']::text[], 'https://www.jomashop.com/jean-paul-gaultier-ladies-la-belle-edp-spray-3-4-oz-fragrances-8435415017244.html', 136.71, 199.99, 'Úsalo con reloj dorado discreto, conjunto negro y sandalias de tiras en tonos miel.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-37dd49d175c3', 'mp-771e0dce9f5f', 'mp-b92296fdc3b1']::text[], 'La falda de lana, las ballerinas y el reloj azul dan un equilibrio refinado y femenino. Ideal para oficina o almuerzo elegante; el perfume es jugoso, vainillado y luminoso, con encanto sofisticado.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
