ED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8498b52f4f24', 'jomashop', 'Z-K7FFD', 'Yves Saint Laurent Ladies Elle EDP Spray 2.7 oz', 'Yves Saint Laurent', 'perfume', 'women', 'Elegancia francesa con aire limpio, versátil para el día y la ciudad.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-elle-edp-spray-27-oz-fragrances-3614274222982.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-elle-edp-spray-27-oz-fragrances-3614274222982.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-elle-edp-spray-27-oz-fragrances-3614274222982_2.jpg', 'https://media.alina-cosmetics.com/prod/thumbnail/20/e4/5d/1729246649/3614274222982_1_800x800.webp', 'https://cdn.notinoimg.com/detail_main_hq/yves-saint-laurent/3614274222982_02-o/elle___250901.jpg']::text[], 'https://www.jomashop.com/yves-saint-laurent-ladies-elle-edp-spray-2-7-oz-fragrances-3614274222982.html', 137.13, 199.99, 'Llévalo con reloj delgado, blazer beige y pantalón recto con mocasines camel.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-56139b744bbc', 'mp-f9f99f3e6118', 'mp-cebec8d3d39d']::text[], 'Pantalón de lana impecable, pumps refinados y reloj de acero pulen un conjunto femenino y sobrio. Ideal para oficina o cena formal; Elle EDP aporta un aura floral y limpia, elegante sin exceso.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f065ddd579e4', 'theoutnet', 'ton-46376663163061144', 'Eren Floral Print Lyocell Shirt', 'Officine Générale', 'clothing', 'men', 'Estampa floral ligera sobre lyocell, fresca y sofisticada para días cálidos.', 'https://www.theoutnet.com/variants/images/46376663163061144/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163061144/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061144/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061144/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061144/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061144/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/officine-generale/tops/casual-shirts/eren-floral-print-lyocell-shirt/46376663163061144', 137, 199.99, 'Combínala con reloj de acero, perfume verde suave y pantalón marfil con loafers.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-371303f8ebbb', 'mp-11a7339e06e4', 'mp-65d98c5ac518']::text[], 'La camisa floral pide espadrilles relajadas, reloj azul y una fragancia luminosa. Perfecto para verano y escapadas; Cedrat de Diamante aporta cítricos brillantes, notas aromáticas y un fondo limpio.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-31c48c024c31', 'jomashop', 'COS-FAHMTS68', 'Fahrenheit by Christian Dior EDT Spray 6.8 oz (m)', 'Dior', 'perfume', 'unisex', 'Fahrenheit mezcla cuero y violeta en una estela magnética, clásica y audaz.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/f/a/fahrenheit-by-christian-dior-edt-spray-6-8-oz-m-3348900147324.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/f/a/fahrenheit-by-christian-dior-edt-spray-6-8-oz-m-3348900147324.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/f/a/fahrenheit-by-christian-dior-edt-spray-68-oz-m-3348900147324_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/f/a/fahrenheit-by-christian-dior-edt-spray-68-oz-m-3348900147324_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/f/a/fahrenheit-by-christian-dior-edt-spray-68-oz-m-3348900147324_7.jpg', 'https://mediafiles.maxaroma.com/9cd29e92-4b8f-436f-ad1f-8e368b30dc1d/https://www.maxaroma.com/productimages/large/UP3348900147324_1.jpg?ver=1765556965', 'https://compraperfumesoriginales.com/product-images/fahrenheit-3348900147324-8631.png']::text[], 'https://www.jomashop.com/chdior-fahmts68.html', 137.74, 200.99, 'Llévalo con reloj negro, chaqueta de cuero, jeans oscuros y botas Chelsea.', 'https://www.pennypincherfashion.com/wp-content/uploads/2018/12/Layered-Winter-Outfits-2.png', ARRAY['mp-bdcc5c48a475', 'mp-3c75f66f94e0', 'mp-661a4722b214']::text[], 'Para una noche de invierno, el sweater de lana, los loafers de terciopelo y el Presage azul equilibran calidez y carácter. Fahrenheit aporta cuero, violeta y notas ahumadas, con presencia sofisticada sin perder elegancia.', 'noche', ARRAY['mp-33c53e7b9d78', 'mp-f9f99f3e6118', 'mp-21f8ec52e6da']::text[], 'Para una noche de invierno, el vestido de punto, los pumps con brillo y el reloj rosado dibujan una silueta elegante. Fahrenheit aporta cuero, violeta y un fondo cálido, intenso y sofisticado.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8ead31ed14fc', 'jomashop', 'COS-TONMES34', 'Tom Ford Noir by Tom Ford EDP Spray 3.4 oz', 'Tom Ford', 'perfume', 'unisex', 'Oscuro y especiado, con una elegancia intensa y envolvente para la noche.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-noir-by-tom-ford-edp-spray-3-4-oz-888066015509.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-noir-by-tom-ford-edp-spray-3-4-oz-888066015509.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-noir-by-tom-ford-edp-spray-34-oz-888066015509_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-noir-by-tom-ford-edp-spray-34-oz-888066015509_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-noir-by-tom-ford-edp-spray-34-oz-888066015509_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-noir-by-tom-ford-edp-spray-34-oz-888066015509_7.jpg']::text[], 'https://www.jomashop.com/tom-ford-tonmes34.html', 137.74, 200.99, 'Combínalo con reloj negro o dorado, traje oscuro y zapatos de cuero; añade terciopelo o seda mate.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-76e86cc39c9a', 'mp-3c75f66f94e0', 'mp-68b8b7f85f35']::text[], 'Para una cena nocturna, el pantalón de lana, los loafers de terciopelo y el reloj dorado crean un conjunto sobrio y preciso. Tom Ford Noir suma iris, ámbar y especias suaves, con profundidad y magnetismo.', 'noche', ARRAY['mp-6ef5af9ad162', 'mp-d0246a15c10d', 'mp-3c42564cbf4d']::text[], 'Para una cena o cóctel nocturno, la falda satinada, los pumps y el reloj bicolor logran un lujo contenido y femenino. Tom Ford Noir aporta ámbar, vainilla y un matiz especiado, elegante y envolvente.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9397a3c3f1ee', 'jomashop', 'COS-TNEMES34-Q', 'Tom Ford Noir Extreme / Tom Ford EDP Spray 3.4 oz (100 ml) (m)', 'Tom Ford', 'perfume', 'unisex', 'Especiado y ambarado, con una elegancia cálida y envolvente.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-noir-extreme-tom-ford-edp-spray-3-4-oz-100-ml-m-888066035392.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-noir-extreme-tom-ford-edp-spray-3-4-oz-100-ml-m-888066035392.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-noir-extreme-tom-ford-edp-spray-34-oz-100-ml-m-888066035392_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-noir-extreme-tom-ford-edp-spray-34-oz-100-ml-m-888066035392_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-noir-extreme-tom-ford-edp-spray-34-oz-100-ml-m-888066035392_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/t/o/tom-ford-noir-extreme-tom-ford-edp-spray-34-oz-100-ml-m-888066035392.jpg?width=546&height=546', 'https://www.sephora.com.mx/on/demandware.static/-/Sites-masterCatalog_Sephora/es_MX/dwa61e9ba7/images/hi-res/boletos/Karla Nieto/TOM FORD/888066035392_2.jpg', 'https://cdn.beymen.com/productimages/fbudevpv.rbr_IMG_01_888066035392.jpg']::text[], 'https://www.jomashop.com/tom-ford-perfume-tnemes34-q.html', 137.75, 200.99, 'Combínalo con reloj de acero oscuro, abrigo negro y botas Chelsea; tonos tabaco, azul noche y crema.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-22a9a0aaf882', 'mp-ac85563341af', 'mp-23af6e30e1cc']::text[], 'Para una noche elegante, el sweater de merino, los loafers en gamuza y el reloj azul equilibran textura y refinamiento. Noir Extreme aporta cardamomo, vainilla y ámbar, con un aire cálido, moderno y seductor.', 'noche', ARRAY['mp-f597bbe6ab0b', 'mp-8b8b764da74e', 'mp-f4871962fdc0']::text[], 'Para una noche especial, la falda de seda, las sandalias y el reloj nácar crean un conjunto sofisticado y luminoso. Noir Extreme añade cardamomo, vainilla y ámbar, con sensualidad cálida y pulida.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-031ae1ff8635', 'jomashop', 'Y-128132', 'Tom Ford - Black Orchid Parfum Spray 100ml/3.4oz', 'Tom Ford', 'perfume', 'unisex', 'Oscuro, floral y profundo, con una sensualidad pulida y sofisticada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-black-orchid-parfum-spray-100ml3-4oz-888066112727.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-black-orchid-parfum-spray-100ml3-4oz-888066112727.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-black-orchid-parfum-spray-100ml34oz-888066112727_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-black-orchid-parfum-spray-100ml34oz-888066112727_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-black-orchid-parfum-spray-100ml34oz-888066112727_7.jpg', 'https://www.alseerandsafeer.com/image/cache/catalog/brands/tom-ford/products/888066112727_2-550x550h.jpg.webp', 'https://www.beautytheshop.com/imgs/productos_cosmetica/resized/300x300/0888066112727_1.webp', 'https://sasobg.com/wp-content/uploads/2023/05/55888066112727-800x800-1.jpg']::text[], 'https://www.jomashop.com/tom-ford-black-orchid-parfum-spray-100ml-3-4oz-888066112727.html', 137.7, 200.99, 'Llévalo con reloj negro, vestido de seda o traje oscuro y zapatos pulidos; añade borgoña y satén.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-76e86cc39c9a', 'mp-3c75f66f94e0', 'mp-49e760656023']::text[], 'Para una cena formal, el pantalón de lana, los loafers de terciopelo y el reloj negro-dorado aportan lujo silencioso. Black Orchid perfume suma trufa, flores oscuras y patchouli, con profundidad elegante y misteriosa.', 'noche', ARRAY['mp-6ef5af9ad162', 'mp-95ac9c8c22b8', 'mp-f4871962fdc0']::text[], 'Para una noche formal, la falda satinada, los pumps y el reloj nácar equilibran brillo y sofisticación. Black Orchid aporta trufa, flores oscuras y patchouli, con un carácter intenso, elegante y misterioso.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1b8e7ba760be', 'jomashop', 'Z-RUG2A', 'Valentino Ladies Donna Born In Roma Purple Melancholia EDP Spray 3.4 oz', 'Valentino', 'perfume', 'women', 'Violeta profundo con carácter seductor, pensado para una presencia memorable.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-donna-born-in-roma-purple-melancholia-edp-spray-34-oz-fragrances-3614274626858.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-donna-born-in-roma-purple-melancholia-edp-spray-34-oz-fragrances-3614274626858.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-donna-born-in-roma-purple-melancholia-edp-spray-34-oz-fragrances-3614274626858_2.jpg', 'https://media-2025.alina-cosmetics.com/prod/media/82/4e/22/1768478359/3614274626858_2.png?ts=1768478359', 'https://cdn.notinoimg.com/detail_main_hq/valentino/3614274626858_02-o/born-in-roma-purple-melancholia-donna___251216.jpg', 'https://media-2025.alina-cosmetics.com/prod/media/28/b9/a2/1768478360/3614274626858_1.png?ts=1768478360']::text[], 'https://www.jomashop.com/valentino-ladies-donna-born-in-roma-purple-melancholia-edp-spray-3-4-oz-fragrances-3614274626858.html', 137.74, 200.99, 'Acompáñalo con reloj joya, vestido negro o ciruela y tacones en gamuza.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-56139b744bbc', 'mp-f9f99f3e6118', 'mp-91b2a0d90108']::text[], 'Pantalón estructurado, pumps delicados y reloj con brillo equilibran la melancolía floral del perfume. Ideal para oficina o una cena sobria; el conjunto se siente femenino, actual y muy pulido.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-67f6e2760997', 'theoutnet', 'ton-46376663163158656', 'Oversized Logo Appliqued Cotton Jersey t Shirt', 'Fear of God Essentials', 'clothing', 'men', 'Camiseta de algodón con logo aplicado y volumen relajado, precisa para un armario urbano discreto.', 'https://www.theoutnet.com/variants/images/46376663163158656/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158656/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158656/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158656/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158656/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158656/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/fear-of-god-essentials/tops/t-shirts/oversized-logo-appliqued-cotton-jersey-t-shirt/46376663163158656', 138, 200.99, 'Úsala con reloj de acero cepillado, perfume amaderado y pantalón recto en gris piedra con sneakers blancas.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-e4ca126bdb77', 'mp-993ce0e172fa', 'mp-605a39d82c0f']::text[], 'Las sneakers de piel, la Seiko oscura y el perfil limpio del perfume hacen un casual de lujo silencioso. Luna Rossa Carbon añade lavanda metálica, cítricos y ambroxan, fresco y moderno.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_