INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-bc9abdade371', 'jomashop', 'SE-SNKK67', 'Seiko 5 Automatic Grey Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera gris y acero para una presencia limpia, versátil y serena en el día a día.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-grey-dial-link-bracelet-mens-watch-snkk67.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-grey-dial-link-bracelet-mens-watch-snkk67.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-grey-dial-link-bracelet-mens-watch-snkk67_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-grey-dial-link-bracelet-mens-watch-snkk67_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-grey-dial-link-bracelet-mens-watch-snkk67_4.jpg', 'https://i5.walmartimages.com/seo/Seiko-Men-s-5-Automatic-Grey-Dial-Stainless-Steel-Watch-SNKK67_0faa2968-2d97-44ce-a702-62a5ac32c217.d9e08b75bf3f2208c533bc491523bac3.jpeg', 'https://cdn2.jomashop.com/media/catalog/product/cache/b3e31d40bbb1abcc90b26106659d5d3f/o/p/open-box-seiko-5-automatic-grey-dial-stainless-steel-mens-watch-snkk67_2.jpg?width=800&height=800']::text[], 'https://www.jomashop.com/seiko-5-mens-watch-snkk67.html', 139, 201.99, 'Con traje azul marino, zapatos negros y perfume Prada L''Homme; suma pulso sobrio y moderno.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-99cf05ce2452', 'mp-5d0569476f27', 'mp-1fee958584dc']::text[], 'La camisa popelina, los loafers de ante y la Seiko gris crean una base pulcra y contemporánea. Para oficina, MYSLF aporta cítricos, flor blanca y maderas ambaradas, sobrio pero actual.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9d0a5b94af11', 'jomashop', 'SE-SNKK09', 'Seiko 5 Silver Stainless Steel Automatic Men''s Watch', 'Seiko', 'watch', 'men', 'Acero pulido y esfera plata para un estilo clásico, discreto y fácil de llevar.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-silver-stainless-steel-automatic-men_s-watch-snkk09.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-silver-stainless-steel-automatic-men_s-watch-snkk09.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-silver-stainless-steel-automatic-men_s-watch-snkk09_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-silver-stainless-steel-automatic-men_s-watch-snkk09_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-silver-stainless-steel-automatic-men_s-watch-snkk09_4.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Silver-Stainless-Steel-Automatic-Men-s-Watch-SNKK09_53cb21f3-71fa-46a4-b6a4-ca474a81186c.69834585988208d35f8b3011d29186c8.jpeg', 'https://media.karousell.com/media/photos/products/2020/4/14/seiko_5_snkk09_automatic_stain_1586838098_a9bb7936_progressive.jpg', 'https://timeaccess-store.com/cdn/shop/files/SNKK09K1fs.jpg?v=1734094570&width=1080']::text[], 'https://www.jomashop.com/seiko-watch-snkk09.html', 139, 201.99, 'Llévalo con camisa blanca, mocasines marrón oscuro y perfume Acqua di Gio Parfum para equilibrio fresco.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-de6cf0652c90', 'mp-60a8cf75a8f6', 'mp-0de6cc427e14']::text[], 'La camisa de lino, los derbies de ante y el reloj acero/negro equilibran formalidad ligera. Excelente para oficina en clima cálido; Acqua di Gio Parfum suma frescura marina, incienso y maderas.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9c1b5d405588', 'jomashop', 'SE-SNKL23', 'Seiko 5 Black Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'La esfera negra aporta carácter limpio y una elegancia funcional que no pasa de moda.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snkl23.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snkl23.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snkl23_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snkl23_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snkl23_10.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snkl23_4.jpg', 'https://cdn.shopify.com/s/files/1/0535/2882/1952/products/SNKL23_1800x1800.jpg?v=1646330310', 'https://media.karousell.com/media/photos/products/2023/6/5/seiko_5_snkl23_mens_automatic__1685939779_d7a70f17_progressive']::text[], 'https://www.jomashop.com/seiko-watch-snkl23.html', 139, 201.99, 'Combínalo con blazer gris, pantalón azul tinta, derbies negros y perfume Prada L''Homme.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-cab8b3ae8035', 'mp-7795ae7c1d60', 'mp-33eb4986cc4c']::text[], 'La camisa de lino, los loafers de cuero y la esfera negra crean un look limpio y reservado. Ideal para oficina o cena informal; Eau Sauvage Parfum aporta cítricos, vetiver y madera seca.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c136c14b019b', 'jomashop', 'SE-SNKL77', 'Seiko 5 Automatic Silver Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Dial plateado y acero inoxidable en una silueta atemporal, pulcra y bien proporcionada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-silver-dial-stainless-steel-mens-watch-snkl77.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-silver-dial-stainless-steel-mens-watch-snkl77.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-silver-dial-stainless-steel-mens-watch-snkl77_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-silver-dial-stainless-steel-mens-watch-snkl77_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-silver-dial-stainless-steel-mens-watch-snkl77_4.jpg', 'https://i5.walmartimages.com/seo/Seiko-Men-s-5-Silver-Dial-Stainless-Steel-Watch-SNKL77_b5e1bdf1-f21b-4cc1-9c2c-c4a7a2a0cd9f.84ee6bce7019a3d301eabcc9ea9a1c9e.jpeg', 'https://secured.watchsurplus.com/wp-content/uploads/SNKL77-1.webp', 'https://media.karousell.com/media/photos/products/2020/4/14/seiko_5_snkl77_automatic_stain_1586838264_0468eb43_progressive.jpg']::text[], 'https://www.jomashop.com/seiko-watch-snkl77.html', 139, 201.99, 'Úsalo con camisa celeste, pantalón de lana gris y perfume Acqua di Gio Parfum.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-d3392a7bbb8e', 'mp-7795ae7c1d60', 'mp-2dc2d5978672']::text[], 'Camisa de rayas, loafers de cuero y Eau Sauvage crean un conjunto pulido y discreto para oficina o reuniones. El acero del reloj acompaña el tono clásico, limpio y atemporal del look.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-726c443c3534', 'jomashop', 'SE-SNKK11', 'Seiko 5 Automatic Stainless Steel Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Azul profundo y acero para un aire fresco, dinámico y fácil de combinar.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-stainless-steel-blue-dial-men_s-watch-snkk11.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-stainless-steel-blue-dial-men_s-watch-snkk11.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-stainless-steel-blue-dial-men_s-watch-snkk11_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-stainless-steel-blue-dial-men_s-watch-snkk11_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-stainless-steel-blue-dial-men_s-watch-snkk11_4.jpg', 'https://www.ioomobile.com/assets/images/SEIKO-5-SNKK11K1-Automatic-Men-Watch-01.jpg', 'https://media.karousell.com/media/photos/products/2023/5/2/seiko_5_snkk11_mens_automatic__1683035359_aae9ce3b', 'https://media.karousell.com/media/photos/products/2023/5/2/seiko_5_snkk11_mens_automatic__1683035359_806cbfaa_progressive']::text[], 'https://www.jomashop.com/seiko-5-mens-watch-snkk11.html', 139, 201.99, 'Queda bien con polo blanco, jeans oscuros, zapatillas minimalistas y perfume Acqua di Gio Parfum.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-68a041916a67', 'mp-e518f29b87d4', 'mp-605a39d82c0f']::text[], 'Camiseta esencial, sneakers ligeros y Luna Rossa Carbon forman un look urbano y activo, ideal para fin de semana o viaje. El perfume aporta frescura aromática con matiz moderno y energético.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-cebec8d3d39d', 'jomashop', 'CZFE1082-05A', 'Citizen Eco-Drive Corso Silver Dial Ladies Watch', 'Citizen', 'watch', 'women', 'Diseño limpio y esfera plata para un porte femenino, discreto y luminoso.', 'https://citizenwatch.widen.net/content/59vqcoudyf/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/59vqcoudyf/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-corso-silver-dial-ladies-watch-fe1082-05a--.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-corso-silver-dial-ladies-watch-fe1082-05a--_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-corso-silver-dial-ladies-watch-fe1082-05a--_3.jpg', 'https://www.lowryjewellers.com/images/citizen-ladies-eco-drive-watch-fe1082-05a-p4536-4611_image.jpg']::text[], 'https://www.jomashop.com/citizen-watch-fe1082-05a.html', 139.2, 201.99, 'Combínalo con blusa marfil, pantalón sastre beige, tacones nude y perfume Libre.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-af985f5371c7', 'mp-771e0dce9f5f', 'mp-4893b6d641b9']::text[], 'El pantalón de lana, las bailarinas y el perfume de perfil suave elevan el look cotidiano. Virgin Violet suma un matiz floral-violeta, delicado y moderno, ideal para día y media estación.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8aee15c7a2fc', 'theoutnet', 'ton-46376663163098116', 'Percy Linen Shirt', 'Orlebar Brown', 'clothing', 'men', 'Camisa de lino ligera, limpia y fresca, pensada para días luminosos con elegancia sin esfuerzo.', 'https://www.theoutnet.com/variants/images/46376663163098116/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163098116/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098116/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098116/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098116/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098116/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/percy-linen-shirt/46376663163098116', 139, 201.99, 'Combínala con reloj fino de cuero, perfume cítrico y chinos arena con mocasines de gamuza beige.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-32f83814872c', 'mp-a87722f18d77', 'mp-8d5bb353d59a']::text[], 'Espadrilles, Seiko de esfera negra y Neroli Portofino elevan la camisa de lino con naturalidad. Es un conjunto veraniego, relajado y refinado; el perfume suena cítrico, limpio y mediterráneo.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9dfc7292a642', 'theoutnet', 'ton-46376663163018059', 'Som Linen And Cotton Blend Shirt', 'Alex Mill', 'clothing', 'men', 'Camisa de lino y algodón con caída natural, sobria y versátil para un estilo pulido.', 'https://www.theoutnet.com/variants/images/46376663163018059/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163018059/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163018059/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163018059/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163018059/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163018059/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/alex-mill/tops/casual-shirts/som-linen-and-cotton-blend-shirt/46376663163018059', 139, 201.99, 'Llévala con reloj minimalista, perfume limpio y pantalón blanco roto con loafers marrón claro.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-32f83814872c', 'mp-d74238edf829', 'mp-cf2b71c1d9e8']::text[], 'Las espadrilles, el Seiko de esfera plateada y Mefisto refuerzan el aire fresco y silencioso de la camisa. Perfecto para verano en Lima: elegante, ligero y con perfume cítrico-aromático.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, 