INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-aa752fde5755', 'jomashop', 'COS-DIIMES34-A', 'Dior Men''s Dior Homme Intense EDP Spray 3.4 oz', 'Dior', 'perfume', 'men', 'Iris y cuero suave crean una firma intensa, refinada y profundamente masculina.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-homme-intense-christian-dior-edp-spray-3-4-oz-m-3348900838185_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-homme-intense-christian-dior-edp-spray-3-4-oz-m-3348900838185_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-homme-intense-christian-dior-edp-spray-34-oz-m-3348900838185_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-homme-intense-christian-dior-edp-spray-34-oz-m-3348900838185_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-homme-intense-christian-dior-edp-spray-34-oz-m-3348900838185_7.jpg', 'https://www.alseerandsafeer.com/image/cache/catalog/brands/dior/products/3348900838185_2-550x550h.jpg.webp', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/c/h/christian-dior-mens-dior-homme-intense-edp-spray-34-oz-tester-fragrances-t3348900838185.jpg?width=546&height=546', 'https://fuschia.com.py/userfiles/images/productos/600/3348900838185-2.jpg']::text[], 'https://www.jomashop.com/chdior-diimes34-a.html', 139.99, 202.99, 'Acompáñalo con abrigo gris, camisa negra, botas Chelsea y reloj de acero pulido.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-f468012c6135', 'mp-3c75f66f94e0', 'mp-1f0254abf485']::text[], 'Bomber de shearling, velvet loafers y Seastar 1000 construyen una noche invernal sofisticada. Dior Homme Intense aporta iris, cacao y maderas: oscuro, envolvente y muy elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c94e03ea5af0', 'jomashop', 'Y-64896', 'Velvet Ginestra by Dolce and Gabbana for Women - 5 oz EDP Spray', 'Dolce & Gabbana', 'perfume', 'women', 'Acorde floral cálido y aterciopelado, con presencia refinada y matiz femenino.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/velvet-ginestra-by-dolce-and-gabbana-for-women-5-oz-edp-spray-730870159835.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/velvet-ginestra-by-dolce-and-gabbana-for-women-5-oz-edp-spray-730870159835.jpg', 'https://i5.walmartimages.com/seo/Dolce-Gabbana-Velvet-Ginestra-EDP-Spray-for-Women_6f1c6e3f-f088-4475-91c1-d67898ad1f5a.dbeab32325728af5634346fdc150e72d.jpeg', 'https://www.perfumenz.co.nz/cdn/shop/products/dolce-velvet-ginestra-150ml_1200x1200.png?v=1657762486', 'https://www.bigw.com.au/medias/sys_master/images/images/h6d/hc4/101992542273566.jpg']::text[], 'https://www.jomashop.com/velvet-ginestra-by-dolce-and-gabbana-for-women-5-oz-edp-spray-730870159835.html', 139.99, 202.99, 'Acompáñalo con vestido negro fluido, reloj joya en oro y sandalias satinadas en nude.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-37dd49d175c3', 'mp-771e0dce9f5f', 'mp-cebec8d3d39d']::text[], 'La falda midi, las bailarinas y el reloj plateado suavizan la riqueza del perfume con feminidad serena. Ideal para día elegante o media estación; el aroma es floral, luminoso y refinado.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0c59ff75cce4', 'jomashop', 'Y-65710', 'Velvet Pure by Dolce and Gabbana for Women - 5 oz EDP Spray', 'Dolce & Gabbana', 'perfume', 'women', 'Perfume envolvente y profundo, de textura suave y carácter sensual para destacar con discreción.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/velvet-pure-by-dolce-and-gabbana-for-women-5-oz-edp-spray-730870197202.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/velvet-pure-by-dolce-and-gabbana-for-women-5-oz-edp-spray-730870197202.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/velvet-pure-by-dolce-and-gabbana-for-women-5-oz-edp-spray-730870197202_7.jpg', 'https://cdn.paris-avenues.com/image/cache/catalog/Product2/730870197202-Dolce-and-Gabbana-Velvet-Pure-EDP-150-Ml-2-1000x1000.png']::text[], 'https://www.jomashop.com/velvet-pure-by-dolce-and-gabbana-for-women-5-oz-edp-spray-730870197202.html', 139.99, 202.99, 'Lúcelo con reloj delgado dorado, vestido satinado marfil y tacones negros de líneas limpias.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-56139b744bbc', 'mp-771e0dce9f5f', 'mp-c92d231b1d76']::text[], 'Pantalón de lana estructurado, bailarinas clásicas y reloj sobrio: un conjunto pulido y femenino para oficina o cena. El perfume aporta un aura floral envolvente, refinada y discreta, ideal para clima templado de Lima.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0de6cc427e14', 'jomashop', 'Z-SPVRU', 'Giorgio Armani Men''s Acqua di Gio Parfum 3.4 oz', 'Giorgio Armani', 'perfume', 'men', 'Acordes marinos y cítricos evocan frescura limpia con una elegancia relajada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-parfum-3-4-oz-fragrances-3614273954167_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-parfum-3-4-oz-fragrances-3614273954167_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-parfum-34-oz-fragrances-3614273954167_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-parfum-34-oz-fragrances-3614273954167_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-parfum-34-oz-fragrances-3614273954167_7.jpg', 'https://cdn.notinoimg.com/detail_main_hq/armani/3614273954167_05/acqua-di-gio-parfum___240325.jpg']::text[], 'https://www.jomashop.com/giorgio-armani-mens-acqua-di-gio-parfum-3-4-oz-fragrances-3614273954167.html', 139.99, 202.99, 'Úsalo con lino blanco, pantalón azul claro, loafers y reloj deportivo en acero.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-8aee15c7a2fc', 'mp-32f83814872c', 'mp-5744d9813fec']::text[], 'Camisa de lino, espadrilles y reloj de buceo componen un look fresco y sobrio para verano. Acqua di Gio Parfum suma un carácter marino, limpio y elegante, perfecto para días cálidos.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0e418dfcc37a', 'jomashop', 'Z-JY3VJ', 'Maison Margiela Unisex Replica Ideal One EDP Spray 3.4 oz', 'Maison Margiela', 'perfume', 'unisex', 'Fragancia unisex de aura íntima y contemporánea, delicada, moderna y sofisticada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-ideal-one-edp-spray-34-oz-fragrances-3614274329414.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-ideal-one-edp-spray-34-oz-fragrances-3614274329414.jpg', 'https://cdn.notinoimg.com/detail_main_lq/maison-margiela/3614274329414_02-o/replica-ideal-one___250709.jpg', 'https://cdn.notinoimg.com/detail_main_lq/maison-margiela/3614274329414_04/replica-ideal-one___250704.jpg']::text[], 'https://www.jomashop.com/maison-margiela-unisex-replica-ideal-one-edp-spray-3-4-oz-fragrances-3614274329414.html', 139.99, 202.99, 'Combínalo con reloj minimalista, blazer crema y pantalón negro sastre con mocasines pulidos.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-8aee15c7a2fc', 'mp-ac85563341af', 'mp-23af6e30e1cc']::text[], 'Para un look de viaje elegante o brunch refinado: la camisa de lino, los loafers y el reloj azul dan frescura y control. Ideal One acompaña con un perfil limpio, suave y envolvente, muy discreto.', 'lujo-silencioso', ARRAY['mp-381d102f4ffc', 'mp-4f1a6a5f486b', 'mp-3c42564cbf4d']::text[], 'Para oficina creativa o almuerzo sofisticado: el sweater de cashmere, las ballet flats y el reloj two-tone componen una elegancia serena. Ideal One se siente limpio, almizclado y pulcro, con un aura íntima y refinada.', 'lujo-silencioso') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5ead5c34cd69', 'jomashop', 'Y-73782', 'Paco Rabanne Men''s 1 Million Lucky EDT Spray 6.8 oz', 'Paco Rabanne', 'perfume', 'men', 'Dulce y amaderado, con un brillo moderno que suma presencia sin esfuerzo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-1-million-lucky-edt-spray-68-oz-fragrances-3349668566211.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-1-million-lucky-edt-spray-68-oz-fragrances-3349668566211.jpg', 'https://www.superbuys.com.au/assets/full/3349668566211.jpg?20210309032748', 'https://perfumesaqua.com/wp-content/uploads/2021/06/3349668566211.jpg', 'https://www.sephora.com.mx/on/demandware.static/-/Sites-masterCatalog_Sephora/es_MX/dwf9a7e37d/images/hi-res/hombre-paco-rabanne-paco-rabanne-one-million-lucky-eau-de-toilette-200ml3349668566211D.jpg']::text[], 'https://www.jomashop.com/paco-rabanne-mens-1-million-edt-spray-6-8-oz-fragrances-3349668566211.html', 139.99, 202.99, 'Combínalo con chaqueta de cuero, jeans índigo, botas negras y reloj de acero.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-67f6e2760997', 'mp-1b60c92c78b6', 'mp-aa7a78509b09']::text[], 'Camiseta oversized, sneakers deportivas y reloj negro dan un aire nocturno casual con actitud. 1 Million Lucky añade dulzor amaderado y avellanado, ideal para salidas informales con presencia.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d26ee4dee7e5', 'theoutnet', 'ton-46376663163154688', 'Cropped Cotton Corduroy Wide Leg Pants', 'Ralph Lauren', 'clothing', 'women', 'El corduroy aporta textura cálida y una silueta actual de aire relajado.', 'https://www.theoutnet.com/variants/images/46376663163154688/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163154688/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154688/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154688/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154688/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154688/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154688/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/polo-ralph-lauren/pants/wide-leg-pants/cropped-cotton-corduroy-wide-leg-pants/46376663163154688', 141, 203.99, 'Llévalo con camisa de popelina, mocasines cacao y reloj de acero para balance pulcro.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-f9f99f3e6118', 'mp-c798e1926e9d', 'mp-6c9d45aa5bb4']::text[], 'El corte amplio en corduroy se vuelve elegante con pumps de suela fina, reloj de nácar y un perfume floral-amaderado. Funciona muy bien para oficina en verano, con presencia pulida sin rigidez.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-aa7a78509b09', 'jomashop', 'CZBM8475-00F', 'Citizen Eco-Drive Black Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Esfera negra y perfil robusto para un estilo funcional, limpio y urbano.', 'https://citizenwatch.widen.net/content/ip1t49sqzy/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/ip1t49sqzy/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/rvirira7ok/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/jh8y2hxjva/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-black-dial-black-ip-stainless-steel-men_s-watch-bm8475-00f_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-black-dial-black-ip-stainless-steel-men_s-watch-bm8475-00f_2_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-black-dial-black-ip-stainless-steel-men_s-watch-bm8475-00f_3_1.jpg']::text[], 'https://www.jomashop.com/citizen-watch-bm8475-00f.html', 141.55, 204.99, 'Combínalo con polo gris, joggers rectos, zapatillas negras y perfume Acqua di Gio Parfum.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-68a041916a67', 'mp-e518f29b87d4', 'mp-605a39d82c0f']::text[], 'La camiseta de logo, las Pegasus y Luna Rossa Carbon refuerzan su carácter activo y urbano. Conjunto cómodo para fin de semana; el perfume es fresco, ambarado y ligeramente aromático.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-38c8045950e9', 'jomashop', 'TIST1374633302000', 'Tissot Prx Quartz Digital Gold Dial Unisex Watch', 'Tissot', 'watch', 'unisex', 'Oro y digital se encuentran en una pieza sutilmente icónica y contemporánea.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-digital-gold-dial-unisex-watch-t1374633302000.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-digital-gold-dial-unisex-watch-t1374633302000.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-digital-gold-dial-unisex-watch-t1374633302000_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-digital-gold-dial-unisex-watch-t1374633302000_3.jpg', 'https://data.guzzigioielli.it/imgprodotto/orologio-tissot-prx-digital-quartz-t1374633302000_61648_zoom.jpg', 'https://cdn.shopify.com/s/files/1/0721/9897/9877/files/t1374633302000-5_3fdc0b99-8672-4542-9ca7-2cc8baccda0e_1200x.jpg?v=1704230336']::text[], 'https://www.jomashop.com/tissot-tissot-prx-gold-tone-dial-unisex-watch-t1374633302000.html', 141.55, 204.99, 'Úsalo con camisa negra, pantalón sastre crema y perfume Dior Homme Intense.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-9dfc7292a642', 'mp-a1a9c18f6ebe', 'mp-eb2f7438d615']::text[], 'Para oficina o un cóctel diurno, la camisa de lino, los penny loafers y el PRX dorado equilibran modernidad y sobriedad. Born in Roma Extradose aporta vainilla, vetiver y un toque ambarado, limpio y seguro.', 'oficina', ARRAY['mp-381d102f4ffc', 'mp-d0246a15c10d', 'mp-cb004bfbf1f3']::text[], 'Para oficina o cena temprana, el sweater de cashmere, los pumps y el PRX dorado crean una presencia pulida. Donna Born in Roma Intense añade vainilla, jazmín y resinas cálidas, elegante y envolvente.', 'elegante') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7e3459da5ce3', 'jomashop', 'COS-SVGMES34', 'Sauvage / Christian Dior EDP Spray 3.4 oz (100 ml) (m)', 'Dior', 'perfume', 'unisex', 'Frescura incisiva con carácter magnético, ideal para una impresión segura y actual.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/a/sauvage-christian-dior-edp-spray-34-oz-100-ml-m-3348901368247.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/a/sauvage-christian-dior-edp-spray-34-oz-100-ml-m-3348901368247.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/a/sauvage-christian-dior-edp-spray-34-oz-100-ml-m-3348901368247_7.jpg', 'https://www.perfumeprice.net/Images/3348901368247_02.jpg?resizeid=4&resizeh=1500&resizew=1500', 'https://compraperfumesoriginales.com/product-images/sauvage-classic-3348901368247-8557.png', 'https://www.perfumeprice.net/Images/3348901368247_01.jpg?resizeid=4&resizeh=1500&resizew=1500', 'https://bp.ua/image/cache/catalog/bp-images/14365/christian-dior-sauvage-2018-parfyumirovannaya-voda-100-ml-new-3348901368247-253681-2-3892x2595.jpg', 'https://compraperfumesoriginales.com/product-images/sauvage-classic-3348901368247-3022.png']::text[], 'https://www.jomashop.com/christian-dior-fragrances-svgmes34-3-4oz.html', 142.45, 204.99, 'Acompáñalo con reloj robusto de acero, polo oscuro y zapatillas blancas impecables con denim crudo.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-c109304a8cd3']::text[], 'Para una noche informal con carácter, combina la camisa satén, unas loafers de terciopelo y el Seiko de aire náutico. Sauvage aporta frescura especiada y magnética, perfecta para destacar sin excesos.', 'noche', ARRAY['mp-33c53e7b9d78', 'mp-8b8b764da74e', 'mp-6f0d137af367']::text[], 'Para ti, el vestido de punto, las sandalias con relieve y el Citizen crean una silueta pulida y actual. Sauvage suma un aura fresca, amaderada y vibrante, ideal para una noche segura y sofisticada.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f17b834331fa', 'jomashop', 'Y-100261', 'Si Passione by Giorgio Armani for Women - 5 oz EDP Spray', 'Giorgio Armani', 'perfume', 'women', 'Fragancia luminosa y voluptuosa, con energía femenina y final seductor.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/i/si-passione-by-giorgio-armani-for-women-5-oz-edp-spray-3614272556379.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/i/si-passione-by-giorgio-armani-for-women-5-oz-edp-spray-3614272556379.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/i/si-passione-by-giorgio-armani-for-women-5-oz-edp-spray-3614272556379_7.jpg', 'https://www.sephora.com.mx/on/demandware.static/-/Sites-masterCatalog_Sephora/es_MX/dwee833e38/images/hi-res/eau-de-parfum-armani-giorgio-armani-si-passione-eau-de-parfum-100ml3614272556379A.png']::text[], 'https://www.jomashop.com/si-passione-by-giorgio-armani-for-women-5-oz-edp-spray-3614272556379.html', 142.49, 204.99, 'Combínala con reloj fino, vestido rojo profundo y sandalias negras de tiras minimalistas.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-56139b744bbc', 'mp-f9f99f3e6118', 'mp-cebec8d3d39d']::text[], 'El pantalón de lana, las pumps de ante y el reloj de acero elevan esta fragancia vibrante y femenina. Perfecto para cena o reunión importante; el conjunto transmite elegancia segura y actual.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4893b6d641b9', 'jomashop', 'Z-6SEAC', 'Gucci The Virgin Violet - Eau de Parfum for Men and Women 3.4 oz (100ml)', 'Gucci', 'perfume', 'women', 'Violeta aterciopelada y moderna, con un perfil artístico de elegancia discreta.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-the-virgin-violet-eau-de-parfum-for-men-and-women-100ml-3614227767836.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-the-virgin-violet-eau-de-parfum-for-men-and-women-100ml-3614227767836.jpg', 'https://cdn.storims.com/api/v2/image/resize?path=https://storage.googleapis.com/storims_cdn/storims/uploads/4bae0c3d256bd66b9e029c1101e368fa.jpeg&format=jpeg', 'https://cdn.storims.com/api/v2/image/resize?path=https://storage.googleapis.com/storims_cdn/storims/uploads/16f85db2b43d6a9c814a85f665e275eb.jpeg&format=jpeg']::text[], 'https://www.jomashop.com/gucci-the-virgin-violet-eau-de-parfum-for-men-and-women-100ml-3614227767836.html', 142.49, 204.99, 'Llévalo con reloj de esfera limpia, camisa negra y pantalón de lana gris con botines Chelsea.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-37dd49d175c3', 'mp-771e0dce9f5f', 'mp-b92296fdc3b1']::text[], 'La falda de cuadros suaviza el carácter artístico del perfume, mientras las flats y el reloj azul mantienen el look limpio. Funciona para un almuerzo o salida casual con un aire elegante y fresco.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7e69a8c87386', 'jomashop', 'Z-DPE2F', 'Prada Unisex Mirages Miracle of the Rose EDP Spray 3.4 oz', 'Prada', 'perfume', 'unisex', 'Rosa moderna y envolvente, con delicadeza sofisticada y un aire sereno.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-unisex-mirages-miracle-of-the-rose-edp-spray-34-oz-fragrances-3614274113464.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-unisex-mirages-miracle-of-the-rose-edp-spray-34-oz-fragrances-3614274113464.jpg', 'https://www.harmoniq.se/image/188478/3614274113464_1.jpg', 'https://www.harmoniq.se/image/188479/3614274113464.jpg']::text[], 'https://www.jomashop.com/prada-unisex-mirages-miracle-of-the-rose-edp-spray-3-4-oz-fragrances-3614274113464.html', 142.49, 204.99, 'Úsalo con reloj delicado, abrigo beige y vestido midi marfil con zapatos de punta fina.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-9dfc7292a642', 'mp-a1a9c18f6ebe', 'mp-23af6e30e1cc']::text[], 'Para un estilo sereno y exquisito, la camisa de lino, los loafers y el Seiko Presage equilibran textura y discreción. Miracle of the Rose añade un velo floral suave, elegante y moderno, ideal para cena o evento íntimo.', 'lujo-silencioso', ARRAY['mp-af985f5371c7', 'mp-f9f99f3e6118', 'mp-3c42564cbf4d']::text[], 'Para ti, el pantalón de lana, los pumps joya y el reloj Citizen construyen una elegancia contenida. Miracle of the Rose aporta un matiz floral refinado, perfecto para una cena o una noche de invierno.', 'lujo-silencioso') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-fdb9bb5ae600', 'jomashop', 'Z-UUBQU', 'Valentino Men''s Uomo Born In Roma EDT Spray 5.0 oz', 'Valentino', 'perfume', 'men', 'Vainilla, tabaco suave y especias construyen una elegancia cálida y actual.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-mens-uomo-born-in-roma-edt-spray-50-oz-fragrances-3614273582612.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-mens-uomo-born-in-roma-edt-spray-50-oz-fragrances-3614273582612.jpg', 'https://mediafiles.maxaroma.com/9cd29e92-4b8f-436f-ad1f-8e368b30dc1d/https://www.maxaroma.com/productimages/large/UP3614273582612_2.jpg?ver=1775664910', 'https://cdn2.jomashop.com/media/catalog/product/v/a/valentino-mens-uomo-born-in-roma-edt-spray-50-oz-tester-fragrances-t3614273582612.jpg']::text[], 'https://www.jomashop.com/valentino-mens-uomo-born-in-roma-edt-spray-5-0-oz-fragrances-3614273582612.html', 142.49, 204.99, 'Combínalo con blazer azul noche, camisa blanca, zapatos negros y reloj de acero.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-68b8b7f85f35']::text[], 'La camisa satinada, los loafers de terciopelo y el PRX digital dorado acompañan la estela cálida y seductora del perfume. Perfecto para una cena o noche formal, con acento sofisticado.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6c9d45aa5bb4', 'jomashop', 'Z-3MPJQ', 'Valentino Ladies Born in Roma the Gold Donna EDP Spray 3.4 oz', 'Valentino', 'perfume', 'women', 'Flores luminosas y ámbar dorado para una feminidad intensa y sofisticada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-born-in-roma-the-gold-donna-edp-spray-34-oz-fragrances-3614274217148.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-born-in-roma-the-gold-donna-edp-spray-34-oz-fragrances-3614274217148.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-born-in-roma-the-gold-donna-edp-spray-34-oz-fragrances-3614274217148_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-ladies-born-in-roma-the-gold-donna-edp-spray-34-oz-fragrances-3614274217148_7.jpg', 'https://cdn.notinoimg.com/detail_main_hq/valentino/3614274217148_02-o/born-in-roma-the-gold-donna___250411.jpg', 'https://lume-perfumes.co.il/wp-content/uploads/2025/08/vlt_frag_bir-franchise_rendez-vous-24_dmi_donna_100ml_3614274217148_front-scaled-1.webp']::text[], 'https://www.jomashop.com/valentino-ladies-born-in-roma-the-gold-donna-edp-spray-3-4-oz-fragrances-3614274217148.html', 142.49, 204.99, 'Llévalo con vestido negro, sandalias doradas y reloj fino; añade labios borgoña.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-56139b744bbc', 'mp-f9f99f3e6118', 'mp-91b2a0d90108']::text[], 'Pantalón sastre, pumps de ante y reloj dorado acompañan el perfume con brillo sutil. Ideal para noche o evento especial; la fragancia se percibe cálida, elegante y femenina, sin exceso.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-bbe172b1b28a', 'jomashop', 'Z-9CQB4', 'Xerjoff Unisex Casamorati 1888 EDP 3.4 oz', 'Xerjoff', 'perfume', 'unisex', 'Especias y resinas envuelven una composición clásica, rica y muy distinguida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-casamorati-1888-edp-3-4-oz-fragrances-8033488153267.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-casamorati-1888-edp-3-4-oz-fragrances-8033488153267.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-casamorati-1888-edp-34-oz-fragrances-8033488153267_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/x/e/xerjoff-unisex-casamorati-1888-edp-34-oz-fragrances-8033488153267_1.jpg?width=546&height=546', 'https://www.gpmcallen.com/media/catalog/product/cache/df4d6ab77e3c9593d62f9004fba54da5/8/0/8033488153267_GoppFR6WlGmVlNaT.jpg', 'https://www.prijs-parfum.nl/images/Xerjoff/XERJOFF-Casamorati-1888-Eau-De-Parfum-100-ml-8033488153267.jpg']::text[], 'https://www.jomashop.com/xerjoff-unisex-casamorati-1888-edp-3-4-oz-fragrances-8033488153267.html', 142.49, 204.99, 'Acompáñalo con abrigo camel, cuello alto negro, botines de cuero y reloj dorado discreto.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-bdcc5c48a475', 'mp-3c75f66f94e0', 'mp-68b8b7f85f35']::text[], 'Para invierno, el sweater de lana, los loafers de terciopelo y el PRX dorado dan presencia cálida y pulida. Casamorati 1888 acompaña con un perfil especiado, opulento y clásico, perfecto para una velada elegante.', 'invierno', ARRAY['mp-381d102f4ffc', 'mp-2ca59b3d8894', 'mp-cebec8d3d39d']::text[], 'Para ti, el sweater de cashmere, las botas altas y el reloj madre perla crean un conjunto sofisticado y cálido. Casamorati 1888 aporta especias nobles, florales y ambaradas, ideal para invierno y ocasiones formales.', 'invierno') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0b51d5a76a1e', 'theoutnet', 'ton-46376663163100411', 'Hibbert Floral Print Pique Shirt', 'Orlebar Brown', 'clothing', 'men', 'Camisa floral en piqué, fresca y luminosa, perfecta para un estilo relajado con intención.', 'https://www.theoutnet.com/variants/images/46376663163100411/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163100411/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100411/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100411/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100411/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100411/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/hibbert-floral-print-pique-shirt/46376663163100411', 142, 204.99, 'Combínala con reloj de acero, perfume cítrico y bermudas azul marino con mocasines blancos.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-162803429493', 'mp-2ee580e3f520', 'mp-0de6cc427e14']::text[], 'Las sandalias, el Seiko plateado y Acqua di Gio Parfum acompañan la camisa floral con frescura y equilibrio. Ideal para almuerzo o paseo de verano: limpio, relajado y muy actual.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2ee580e3f520', 'jomashop', 'SE-SNKL15', 'Seiko 5 Automatic Silver Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Dial plata y líneas limpias para una presencia versátil, sobria y segura.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-silver-dial-mens-watch-snkl15.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-silver-dial-mens-watch-snkl15.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-silver-dial-mens-watch-snkl15_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-silver-dial-mens-watch-snkl15_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-silver-dial-mens-watch-snkl15_4.jpg', 'https://media.karousell.com/media/photos/products/2022/3/12/seiko_5_snkl15_automatic_steel_1647096200_24969c62_progressive.jpg']::text[], 'https://www.jomashop.com/seiko-5-mens-watch-snkl15.html', 142.5, 205.99, 'Combínalo con traje azul marino, camisa celeste, zapatos oxford y perfume Prada L''Homme.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-d3392a7bbb8e', 'mp-7795ae7c1d60', 'mp-2dc2d5978672']::text[], 'La camisa de rayas, los loafers y Eau Sauvage forman un conjunto clásico para oficina. El reloj de acero aporta discreción y orden, mientras el perfume deja una impresión fresca y distinguida.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3901beb56bb2', 'jomashop', 'SE-SNKL45J1', 'Seiko 5 Automatic Black Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Reloj automático clásico de líneas limpias, discreto y fácil de llevar a diario.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snkl45j1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snkl45j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snkl45j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snkl45j1_3.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Automatic-Black-Dial-Stainless-Steel-Men-s-Watch-SNKL45J1_7246197c-acd0-4676-ae61-6db9292b66ae.607bd986ab9fa52e4a037fffc8685562.jpeg', 'https://www.ioomobile.com/assets/images/seiko-5-snkl45j1-21-jewels-watch-01.jpg', 'https://www.raspberryminute.com/image/cache/catalog/Seiko/SNKL45J1/IMG_9150-1920x1920.JPG']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snkl45j1.html', 142.5, 205.99, 'Llévalo con camisa celeste, perfume amaderado suave y traje gris medio con zapatos negros.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-cab8b3ae8035', 'mp-9c175b220b04', 'mp-7795ae7c1d60']::text[], 'El negro del reloj pide una sastrería limpia y sobria. La camisa de lino suaviza el conjunto para oficina con clima templado, y los loafers de cuero elevan sin exceso. Vetiver elegante o discreto si buscas aroma profesional.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-303de456e445', 'jomashop', 'Z-KAA6L', 'Versace Atelier Fleur De Mate EDP Spray 3.4 oz', 'Versace', 'perfume', 'unisex', 'Mate aromático con brillo vegetal, refinado y poco predecible para un porte distinguido.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-atelier-fleur-de-mate-edp-spray-34-oz-fragrances-8011003863730.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-atelier-fleur-de-mate-edp-spray-34-oz-fragrances-8011003863730.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-atelier-fleur-de-mate-edp-spray-34-oz-fragrances-8011003863730_7.jpg', 'https://www.alluringauras.com/wp-content/uploads/2024/11/8011003863730-2.jpg', 'https://www.faces.sa/dw/image/v2/BJSM_PRD/on/demandware.static/-/Sites-faces-master-catalog/default/dw56de58cd/product/8011003863730_2/8011003863730_2.jpg?sw=800&sh=800']::text[], 'https://www.jomashop.com/versace-atelier-fleur-de-mate-edp-spray-3-4-oz-fragrances-8011003863730.html', 142.99, 205.99, 'Combínalo con reloj de oro cepillado, blazer oscuro y camisa blanca con pantalón negro.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-ef6b916a5f31', 'mp-f3cd717d3b87', 'mp-c109304a8cd3']::text[], 'Para una noche de impacto, la camisa satinada, los loafers adornados y el reloj de buceo equilibran lujo y modernidad. Fleur De Mate deja una estela verde, elegante y ligeramente ahumada, muy seductora.', 'noche', ARRAY['mp-6c3004326cc4', 'mp-6e02774d371b', 'mp-21f8ec52e6da']::text[], 'Para ti, el cardigan metálico, las sandalias de patent y el reloj con brillo cristalino logran un look nocturno impecable. Fleur De Mate suma una faceta verde y sofisticada, perfecta para cena o cóctel.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-661a4722b214', 'jomashop', 'CZBU4020-01L', 'Citizen CTO Eco-Drive Navy Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Azul marino profundo y eco-drive para una lectura clara con porte ejecutivo.', 'https://citizenwatch.widen.net/content/aslrdeif8c/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/aslrdeif8c/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/humhdtw4z9/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/qzhjkxnkdy/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/23uiq6jwgh/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-cto-ecodrive-navy-blue-dial-mens-watch-bu402001l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-cto-ecodrive-navy-blue-dial-mens-watch-bu402001l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-cto-ecodrive-navy-blue-dial-mens-watch-bu402001l_3.jpg']::text[], 'https://www.jomashop.com/citizen-watch-bu4020-01l.html', 144, 206.99, 'Úsalo con traje gris carbón, camisa blanca, cinturón negro y perfume Acqua di Gio Parfum.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-cab8b3ae8035', 'mp-ccd7e4d707b6', 'mp-fdb9bb5ae600']::text[], 'El azul marino funciona con tonos neutros y cortes limpios. La camisa de lino aporta frescura, los brogues ordenan el look y la fragancia añade un carácter amaderado-aromático, perfecto para oficina con elegancia contenida.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c98229ae5f30', 'jomashop', 'COS-LMMMTS34', 'Lhomme / Prada EDT Spray 3.4 oz (100 ml) (m)', 'Prada', 'perfume', 'men', 'Limpio, irisado y preciso; un clásico de piel blanca con sello contemporáneo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/l/h/lhomme-prada-edt-spray-3-4-oz-100-ml-m-8435137749607.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/l/h/lhomme-prada-edt-spray-3-4-oz-100-ml-m-8435137749607.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/l/h/lhomme-prada-edt-spray-34-oz-100-ml-m-8435137749607_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/l/h/lhomme-prada-edt-spray-34-oz-100-ml-m-8435137749607_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/l/h/lhomme-prada-edt-spray-34-oz-100-ml-m-8435137749607_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/931945d7c16f894606662cd152adf9d4/l/h/lhomme-prada-edt-spray-34-oz-100-ml-m-8435137749607.jpg?width=80&height=80']::text[], 'https://www.jomashop.com/prada-perfume-lmmmts34.html', 144.99, 207.99, 'Combínalo con camisa blanca impecable, pantalón gris y mocasines negros para un lujo silencioso.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-d9fcaa470913', 'mp-ccd7e4d707b6', 'mp-a7fbae0e4ca7']::text[], 'Prada L''Homme es limpio, iridiscente y muy profesional. El polo de punto y los brogues equilibran modernidad y rigor, mientras el PRX en champagne suma brillo discreto para oficina o reunión importante.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2b89f3f68943', 'jomashop', 'SE-SNKL23J1', 'Seiko 5 Black Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Negro profundo y acero para una estética esencial, firme y atemporal.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snkl23j1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snkl23j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snkl23j1_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-black-dial-stainless-steel-mens-watch-snkl23j1_2.jpg', 'https://cdn.vuahanghieu.com/unsafe/0x900/left/top/smart/filters:quality(90)/https://admin.vuahanghieu.com/upload/product/2024/02/dong-ho-nam-seiko-5-black-dial-stainless-steel-men-s-watch-snkl23j1-mau-den-bac-65bc6ec42ad1f-02022024112540.jpg']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snkl23j1.html', 146.3, 208.99, 'Combínalo con camisa Oxford azul, jeans oscuros, derbies negros y perfume Prada L''Homme.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-9dfc7292a642', 'mp-e886cd56a6d2', 'mp-605a39d82c0f']::text[], 'Un conjunto relajado pero pulido: camisa ligera, sneakers de piel y un reloj negro sobrio. Luna Rossa Carbon aporta frescura mineral y un fondo aromático limpio, ideal para fines de semana urbanos.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-68b8b7f85f35', 'jomashop', 'TIST1372633302000', 'Tissot PRX Digital Quartz Gold Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Oro digital con estética PRX para un gesto moderno, pulcro y distintivo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-gold-dial-mens-watch-t1372633302000.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-gold-dial-mens-watch-t1372633302000.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-gold-dial-mens-watch-t1372633302000_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-digital-quartz-gold-dial-mens-watch-t1372633302000_3.jpg', 'https://i5.walmartimages.com/seo/Tissot-PRX-Digital-Quartz-Gold-Dial-Men-s-Watch-T1372633302000_a0b6d41c-b2ca-45ff-9c71-9e0f7beff04a.18c8f7da7986577ec58276dc0ad4660f.jpeg', 'https://mzwatcheslk.com/cdn/shop/files/t1372633302000-1_1080x1080.webp?v=1694865864']::text[], 'https://www.jomashop.com/tissot-prx-digital-quartz-gold-dial-mens-watch-t1372633302000.html', 146.3, 208.99, 'Úsalo con blazer azul marino, camiseta blanca premium, pantalón recto y mocasines negros.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-40dd2be6dd83']::text[], 'El dorado del PRX pide líneas depuradas y materiales nobles. La camisa satinada, los loafers de terciopelo y el perfume almizclado-amaderado crean una estética nocturna, sobria y muy refinada.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6a1ce8b94f7e', 'jomashop', 'Z-4LGE2', 'Maison Margiela Unisex Replica Celestial Whispers EDP Spray 3.4 oz', 'Maison Margiela', 'perfume', 'unisex', 'Fragancia etérea y envolvente, con una transparencia sofisticada y actual.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-celestial-whispers-edp-spray-34-oz-fragrances-3614274347425.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-celestial-whispers-edp-spray-34-oz-fragrances-3614274347425.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/a/maison-margiela-unisex-replica-celestial-whispers-edp-spray-34-oz-fragrances-3614274347425_2.jpg', 'https://cdn.notinoimg.com/social/maison-margiela/3614274347425_01-o/replica-celestial-whispers___250704.jpg']::text[], 'https://www.jomashop.com/maison-margiela-unisex-replica-celestial-whispers-edp-spray-3-4-oz-fragrances-3614274347425.html', 145.99, 208.99, 'Acompáñalo con reloj minimalista, knit crema y pantalón sastre taupe con mocasines de cuero.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-f259885fccd2', 'mp-b2dbfc6f7e6e', 'mp-23af6e30e1cc']::text[], 'Para un lujo discreto, la camisa de popelina, los Oxford y el Presage azul construyen un conjunto limpio y distinguido. Celestial Whispers añade un acorde etéreo, suave y almizclado, ideal para noche elegante.', 'lujo-silencioso', ARRAY['mp-f597bbe6ab0b', 'mp-f9f99f3e6118', 'mp-f4871962fdc0']::text[], 'Para ti, la mini skirt de seda, los pumps cristalinos y el reloj madre perla crean una elegancia sutil y femenina. Celestial Whispers se percibe suave, aireado y almizclado, perfecto para cena o evento especial.', 'lujo-silencioso') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-dc208d31ea6f', 'theoutnet', 'ton-46376663163060202', 'Cotton And Linen Blend Polo Shirt', 'Missoni', 'clothing', 'men', 'Polo de mezcla ligera con textura sutil y colorido sofisticado, ideal para días cálidos.', 'https://www.theoutnet.com/variants/images/46376663163060202/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163060202/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163060202/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163060202/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163060202/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163060202/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/missoni/tops/polo-shirts/cotton-and-linen-blend-polo-shirt/46376663163060202', 146, 208.99, 'Combínalo con reloj de acero, perfume fresco y pantalón beige con loafers en gamuza.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-32f83814872c', 'mp-9c1b5d405588', 'mp-0de6cc427e14']::text[], 'Polo texturizado, espadrilles y Seiko clásico forman un lujo relajado para verano en Lima. Acqua di Giò aporta frescor marino-cítrico, limpio y luminoso, perfecto para almuerzo costero o paseo casual.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_ima