de noche, con una estela floral intensa y sofisticada.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3ca07bcbe159', 'jomashop', 'Z-AZX3B', 'Xerjoff Ladies Casamorati La Tosca 3.4 oz (100 ml)', 'Xerjoff', 'perfume', 'women', 'Un bouquet opulento y aterciopelado que deja una estela sofisticada y memorable.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-la-tosca-3-4-oz-100-ml-8033488154158.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-la-tosca-3-4-oz-100-ml-8033488154158.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-la-tosca-34-oz-100-ml-8033488154158_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-la-tosca-34-oz-100-ml-8033488154158_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/x/e/xerjoff-ladies-casamorati-la-tosca-34-oz-100-ml-8033488154158.jpg?width=546&height=546', 'https://www.parfuem365.de/media/image/g0/42/39/8033488154158_1.jpg', 'https://assets.goldenscent.com/catalog/product/8/0/8033488154158-02_1_.png', 'https://dikochi.com/cdn/shop/files/8033488154158_1_480ed544-63ce-463b-8326-f3c48f7bfbb4.png?v=1735980464']::text[], 'https://www.jomashop.com/xerjoff-ladies-casamorati-la-tosca-3-4-oz-fragrances-8033488154158.html', 147.24, 209.99, 'Llévalo con vestido seda marfil, sandalias finas y reloj delicado en oro rosa.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-37dd49d175c3', 'mp-4f1a6a5f486b', 'mp-b92296fdc3b1']::text[], 'La firma olfativa de La Tosca combina muy bien con falda midi, ballet flats y un reloj azul femenino. Ideal para primavera u oficina creativa, con un aire romántico, limpio y refinado.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
