INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-76c7afefcd12', 'theoutnet', 'ton-46376663163132715', 'Printed Cotton Jersey t Shirt', 'Off-White', 'clothing', 'men', 'Camiseta gráfica de algodón, contemporánea y relajada, con presencia urbana limpia.', 'https://www.theoutnet.com/variants/images/46376663163132715/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163132715/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163132715/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163132715/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163132715/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163132715/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/tops/t-shirts/printed-cotton-jersey-t-shirt/46376663163132715', 148, 210.99, 'Combínala con reloj de acero oscuro, perfume amaderado y jean recto negro con sneakers negras.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-e886cd56a6d2', 'mp-2b89f3f68943', 'mp-60727c51909d']::text[], 'El print del tee pide contraste limpio: sneakers en piel, un Seiko clásico y Sauvage para un perfil aromático fresco, especiado y versátil. Funciona muy bien en fin de semana o ciudad.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_