INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a743c0bebe72', 'jomashop', 'SE-SNK369', 'Seiko 5 Automatic White Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera blanca limpia y perfil clásico para un estilo sobrio de uso diario.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-men_s-automatic-watch-snk369.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-men_s-automatic-watch-snk369.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-men_s-automatic-watch-snk369_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-men_s-automatic-watch-snk369_3.jpg', 'https://i5.walmartimages.com/seo/Seiko-SNK369K1-Men-s-Series-5-White-Dial-Bracelet-Automatic-Watch_65957529-a949-4d28-9ece-ec62e4bff4cd.7b666717d77fac7e1e5bbd519d16a253.jpeg', 'https://watchzonebd.com/uploads/product/SNK369K1-1_65192b0353f6a.webp']::text[], 'https://www.jomashop.com/seiko-5-watch-snk369.html', 149, 211.99, 'Llévalo con reloj robusto de acero, perfume fresco amaderado, camisa celeste y mocasines marrón claro.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-cab8b3ae8035', 'mp-7795ae7c1d60', 'mp-9c175b220b04']::text[], 'El dial blanco es muy versátil con camisa de lino y loafers pulidos. El conjunto resulta sobrio, cómodo y elegante para oficina; el vetiver aporta una firma seca, limpia y masculina.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-42ef9cd82f29', 'theoutnet', 'ton-1647597307746433', 'Shanklin Linen Shirt', 'Orlebar Brown', 'clothing', 'men', 'Camisa de lino con caída nítida, fresca y versátil para un vestir impecable.', 'https://www.theoutnet.com/variants/images/1647597307746433/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597307746433/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597307746433/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597307746433/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597307746433/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597307746433/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/shanklin-linen-shirt/1647597307746433', 149, 211.99, 'Llévala con reloj delgado, perfume herbal y pantalón crudo con mocasines de ante.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-32f83814872c', 'mp-2b89f3f68943', 'mp-0de6cc427e14']::text[], 'Lino, espadrilles y Seiko negro equilibran frescura y discreción. La fragancia suma un toque marino y luminoso, ideal para un almuerzo de verano o escapada costera con lujo silencioso.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.