INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-864d2667cf0c', 'jomashop', 'Y-62086', 'Velvet Sublime by Dolce and Gabbana for Women - 5 oz EDP Spray', 'Dolce & Gabbana', 'perfume', 'women', 'Fragancia brillante y rica, con una faceta floral opulenta y pulida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/velvet-sublime-by-dolce-and-gabbana-for-women-5-oz-edp-spray-737052833811.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/velvet-sublime-by-dolce-and-gabbana-for-women-5-oz-edp-spray-737052833811.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/b3e31d40bbb1abcc90b26106659d5d3f/v/e/velvet-sublime-by-dolce-and-gabbana-for-women-5-oz-edp-spray-737052833811_7.jpg?width=800&height=800', 'https://m.media-amazon.com/images/I/61UkDYRD-yL._AC_SL1500_.jpg']::text[], 'https://www.jomashop.com/velvet-sublime-by-dolce-and-gabbana-for-women-5-oz-edp-spray-737052833811.html', 149.99, 212.99, 'Acompáñala con reloj joya, vestido satinado verde oscuro y sandalias doradas de líneas finas.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-56139b744bbc', 'mp-771e0dce9f5f', 'mp-21f8ec52e6da']::text[], 'Velvet Sublime se acompaña mejor de pantalón pulido, flats delicados y un reloj femenino sutil. Ideal para otoño o cena íntima: el conjunto transmite lujo suave y la fragancia aporta calidez floral-cremosa.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price