INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8cf3908f3eee', 'jomashop', 'Z-UWHCC', 'Gucci Ladies Gucci Flora Gorgeous Gardenia EDP Spray 5.0 oz', 'Gucci', 'perfume', 'women', 'Gardenia luminosa y femenina, con una salida fresca y un fondo pulido.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-ladies-gucci-flora-gorgeous-gardenia-edp-spray-50-oz-fragrances-3616304255243.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-ladies-gucci-flora-gorgeous-gardenia-edp-spray-50-oz-fragrances-3616304255243.jpg', 'https://www.perfumeprice.co.uk/media/iopt/catalog/product/cache/a1e6b8f4154e163a9e2499169c925833/3/6/3616304255243.webp', 'https://www.iraqdutyfree.com/upload/items/hd/646628001.jpg', 'https://bizweb.dktcdn.net/thumb/1024x1024/100/426/728/products/untitled-1-0042-flora-gorgeous-gardenia-eau-de-parfum-gucci-for-women-1-11aa72bd111c440ca7bbf8d3b00d6ef4-master-photoroo.png?v=1696521833643']::text[], 'https://www.jomashop.com/gucci-ladies-gucci-flora-gorgeous-gardenia-edp-spray-5-0-oz-fragrances-3616304255243.html', 149.63, 212.99, 'Combínalo con reloj delicado, vestido marfil y sandalias nude para un acabado limpio y luminoso.', 'https://www.styleatacertainage.com/wp-content/uploads/2025/06/Quince-Linen-Picks.png', ARRAY['mp-37dd49d175c3', 'mp-771e0dce9f5f', 'mp-b92296fdc3b1']::text[], 'Flora Gorgeous Gardenia pide una silueta femenina y equilibrada: falda midi, flats clásicos y un reloj azul delicado. Perfecto para primavera o evento diurno, con un carácter floral luminoso y refinado.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
