image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f259885fccd2', 'theoutnet', 'ton-46376663163097852', 'Travis Striped Cotton Poplin Shirt', 'Orlebar Brown', 'clothing', 'men', 'Camisa de popelina con rayas precisas, fresca y ordenada para un estilo relajado.', 'https://www.theoutnet.com/variants/images/46376663163097852/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163097852/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097852/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097852/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097852/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097852/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/travis-striped-cotton-poplin-shirt/46376663163097852', 151, 213.99, 'Úsala con reloj de acero, perfume limpio y pantalón beige con loafers marrón oscuro.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-3f54661aa9f5', 'mp-ec5394530cac', 'mp-6a32aace5e0a']::text[], 'Las rayas en popelina piden textura natural y acentos mediterráneos. Las espadrilles y el Seiko blanco alivian el look; Neroli Sauvage aporta cítricos limpios y hierbas, perfecto para verano casual.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c4e376ebb5ab', 'theoutnet', 'ton-46376663163158673', 'Logo Appliqued Cotton Jersey t Shirt', 'Fear of God Essentials', 'clothing', 'men', 'Camiseta con logo discreto y algodón suave, pensada para un uso fácil y actual.', 'https://www.theoutnet.com/variants/images/46376663163158673/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158673/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158673/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158673/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158673/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158673/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/fear-of-god-essentials/tops/t-shirts/logo-appliqued-cotton-jersey-t-shirt/46376663163158673', 151, 213.99, 'Combínala con reloj simple, perfume amaderado y jogger negro o jean recto con zapatillas blancas.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-e4ca126bdb77', 'mp-7fe5887981ce', 'mp-2dc2d5978672']::text[], 'El logo discreto funciona mejor con piezas sobrias y actuales. Sneakers de cuero, Seiko gris y Eau Sauvage componen un look casual refinado, con frescura cítrica y un fondo clásico muy pulido.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a82f63ef280c', 'jomashop', 'COS-JADES34', 'Jadore / Christian Dior EDP Spray 3.4 oz (w) (100 ml)', 'Dior', 'perfume', 'unisex', 'Un floral icónico, sensual y pulido, pensado para destacar con discreción.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/a/jadore-christian-dior-edp-spray-3-4-oz-w-100-ml-3348900417878.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/a/jadore-christian-dior-edp-spray-3-4-oz-w-100-ml-3348900417878.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/a/jadore-christian-dior-edp-spray-34-oz-w-100-ml-3348900417878_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/j/a/jadore-christian-dior-edp-spray-34-oz-w-100-ml-3348900417878.jpg?width=546&height=546', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/j/a/jadore-christian-dior-edp-spray-34-oz-w-3348900417878_2.jpg?width=546&height=546', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/j/a/jadore-christian-dior-edp-spray-34-oz-w-3348900417878_1.jpg?width=546&height=546', 'https://compraperfumesoriginales.com/product-images/jadore-3348900417878.png', 'https://compraperfumesoriginales.com/product-images/jadore-3348900417878-6483.png']::text[], 'https://www.jomashop.com/christian-dior-perfume-jades34.html', 151.99, 214.99, 'Úsalo con reloj dorado delgado, vestido negro fluido y sandalias de tiras; suma perfume avainillado ligero.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-68b8b7f85f35']::text[], 'Para una noche elegante, la camisa satinada, los loafers de terciopelo y el PRX dorado forman un conjunto sobrio y cálido. J’adore aporta un halo floral blanco, limpio y refinado, inesperadamente seductor.', 'noche', ARRAY['mp-f597bbe6ab0b', 'mp-f9f99f3e6118', 'mp-3c42564cbf4d']::text[], 'Para ti, la mini skirt de gasa, los pumps con cristal y el reloj two-tone equilibran glamour y delicadeza. J’adore acompaña con flores luminosas, cremosas y elegantes, ideal para una cena de noche.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ab882ca68431', 'jomashop', 'Z-B69FE', 'Xerjoff Ladies Casamorati Bouquet Ide EDP 3.4 oz', 'Xerjoff', 'perfume', 'women', 'Bouquet refinado con aire clásico, elegante y envolvente desde el primer instante.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-bouquet-ide-edp-3-4-oz-fragrances-8033488153588.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-bouquet-ide-edp-3-4-oz-fragrances-8033488153588.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-bouquet-ide-edp-34-oz-fragrances-8033488153588_7.jpg', 'https://www.prijs-parfum.nl/images/Xerjoff/Xerjoff-Casamorati-1888-Bouquet-Ideale-Eau-De-Parfum-Spray-100-Ml-For-Women-8033488153588.jpg']::text[], 'https://www.jomashop.com/xerjoff-ladies-casamorati-1888-bouquet-ide-edp-3-4-oz-fragrances-8033488153588.html', 151.99, 214.99, 'Combínalo con reloj joya, vestido de seda champagne y tacones altos; perfume floral blanco para completar.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-37dd49d175c3', 'mp-771e0dce9f5f', 'mp-21f8ec52e6da']::text[], 'La fragancia floral se acompaña de una falda de lana y ballerinas clásicas para una elegancia suave. El reloj con acentos rosados completa un conjunto femenino, perfecto para almuerzo o reunión de temporada.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b70fc97dccd4', 'theoutnet', 'ton-46376663163158615', 'Velvet Trimmed Stretch Silk Satin Pajama Shorts', 'Tom Ford', 'clothing', 'men', 'Short de pijama en seda con ribete aterciopelado, sofisticado y de gesto íntimo.', 'https://www.theoutnet.com/variants/images/46376663163158615/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158615/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158615/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158615/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158615/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158615/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/underwear-sleepwear/sleepwear/velvet-trimmed-stretch-silk-satin-pajama-shorts/46376663163158615', 152, 214.99, 'Llévalo con reloj fino, perfume cálido y bata oscura o camisa satinada con sandalias de cuero.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-474b2526c36a', 'mp-68b8b7f85f35', 'mp-7b3c22e58e52']::text[], 'Un conjunto de noche con aire de boudoir refinado: mocasines de terciopelo y un reloj dorado elevan el short. El Scandal Le Parfum aporta un toque cálido, gourmand y seductor, perfecto para una velada íntima y elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-62e2e4c0cd63', 'jomashop', 'Z-KK98B', 'Paco Rabanne Men''s Phantom Parfum Spray 5.0 oz', 'Paco Rabanne', 'perfume', 'men', 'Acabado futurista y envolvente con presencia moderna, ideal para destacar con discreción nocturna.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-phantom-parfum-spray-50-oz-fragrances-3349668614608.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-phantom-parfum-spray-50-oz-fragrances-3349668614608.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-phantom-parfum-spray-50-oz-fragrances-3349668614608_7.jpg', 'https://vitaltone.co.uk/wp-content/uploads/2023/09/3349668614608_2-scaled.jpg']::text[], 'https://www.jomashop.com/paco-rabanne-mens-phantom-parfum-spray-5-0-oz-fragrances-3349668614608.html', 152.77, 215.99, 'Úsalo con reloj de acero negro, polo azul marino y derby liso; perfuma con maderas suaves y ámbar.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-474b2526c36a', 'mp-49e760656023']::text[], 'La fragancia gana carácter con seda satinada, mocasines de terciopelo y un reloj negro-dorado. Ideal para una noche elegante; el perfume refuerza un perfil dulce, ambarado y moderno, con presencia sin perder sofisticación.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7fe5887981ce', 'jomashop', 'SE-SNXS75', 'Seiko 5 Automatic Grey Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Acero y esfera gris para una presencia limpia, sólida y fácil de llevar.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snxs75.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snxs75.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snxs75_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snxs75_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snxs75_4.jpg', 'https://res.cloudinary.com/passthewatch/image/upload/v1613421596/Seiko/SNXS75_jfinhm.jpg']::text[], 'https://www.jomashop.com/seiko-5-watch-snxs75.html', 154, 216.99, 'Llévalo con reloj de líneas rectas, perfume aromático discreto, traje gris y derbies negros.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-cab8b3ae8035', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'Grey dial muy pulido para oficina o smart casual: camisa de lino-ligero, loafers clásicos y Grey Vetiver, limpio, seco y elegante. El conjunto transmite discreción, orden y un lujo silencioso impecable para Lima.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ec5394530cac', 'jomashop', 'SE-SNKP15', 'Seiko 5 Automatic White Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Diseño limpio en acero y blanco, ideal para un estilo ordenado y versátil.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-stainless-steel-mens-watch-snkp15k1s.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-stainless-steel-mens-watch-snkp15k1s.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-stainless-steel-mens-watch-snkp15k1s_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-stainless-steel-mens-watch-snkp15k1s_3.jpg', 'https://cdn.shopify.com/s/files/1/0535/2882/1952/products/SNKP15_1800x1800.jpg?v=1655263198', 'https://cdn.shopify.com/s/files/1/0535/2882/1952/products/SNKP15_2_1800x1800.jpg?v=1655263198', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/s/e/seiko-seiko-5-automatic-white-dial-mens-watch-snkp15j1_1.jpg?width=546&height=546', 'https://i5.walmartimages.com/seo/Seiko-Seiko-5-Automatic-White-Dial-Men-s-Watch-SNKP15J1_b0dae3f8-9ff3-4728-be3c-b7ee7eaebc28.30d2a46e50ea9361987251c2e4d4ae77.jpeg']::text[], 'https://www.jomashop.com/seiko-5-watch-snkp15k1s.html', 154, 216.99, 'Acompáñalo con reloj fino, perfume cítrico elegante, camisa blanca y chinos beige con loafers.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-357d594d46a8', 'mp-7795ae7c1d60', 'mp-2dc2d5978672']::text[], 'El blanco del reloj conversa con una camisa fresca y loafers sobrios, creando un look versátil de oficina con pausa casual. Eau Sauvage suma cítricos nobles y herbales, ideal para días cálidos y bien vestidos.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3c12ff13af52', 'jomashop', 'SE-SNKK11J1', 'Seiko 5 Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Automático japonés de esfera azul, sobrio y versátil para llevar del trabajo al fin de semana.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-blue-dial-mens-watch-snkk11j1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-blue-dial-mens-watch-snkk11j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-blue-dial-mens-watch-snkk11j1_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-blue-dial-mens-watch-snkk11j1_2_1.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Automatic-Blue-Dial-Men-s-Watch-SNKK11J1_f40f124b-7a39-435c-89b1-b4c2a9beaffc.0233be6092d9920cd1e305f8d61e260a.jpeg?odnHeight=573&odnWidth=573&odnBg=FFFFFF']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snkk11j1.html', 154, 216.99, 'Combínalo con perfume limpio, camisa celeste y mocasines marrón; suma blazer gris o chino beige.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-d3392a7bbb8e', 'mp-42bc749064f5', 'mp-c98229ae5f30']::text[], 'Azul y tonos neutros en clave relajada: camisa a rayas, loafers de ante y L’Homme, limpio y almizclado. Funciona para oficina casual o fin de semana pulido, con una estética fresca y discreta.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b92296fdc3b1', 'jomashop', 'CZEW2290-54L', 'Citizen Corso Eco-Drive Blue Dial Ladies Watch', 'Citizen', 'watch', 'women', 'Azul sereno y cristales discretos para una elegancia femenina sin exceso.', 'https://citizenwatch.widen.net/content/7frhppxno6/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/7frhppxno6/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/l/a/ladies-corso-eco-drive-blue-dial-stainless-steel-ladies-watch-ew2290-54l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/l/a/ladies-corso-eco-drive-blue-dial-stainless-steel-ladies-watch-ew2290-54l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/l/a/ladies-corso-eco-drive-blue-dial-stainless-steel-ladies-watch-ew2290-54l_3.jpg', 'https://content.abt.com/image.php/big_EW229054L.jpg?image=/images/products/BDP_Images/big_EW229054L.jpg&canvas=1&min_w=750&min_h=550', 'https://s.turbifycdn.com/aah/yhst-92803816272180/citizen-ew2290-54l-corso-ladies-eco-drive-watch-42.jpg']::text[], 'https://www.jomashop.com/citizen-watch-ew2290-54l.html', 153.78, 216.99, 'Combínalo con reloj delgado plateado, perfume floral acuoso, blusa blanca y pantalón sastre azul marino.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-56139b744bbc', 'mp-771e0dce9f5f', 'mp-3ca07bcbe159']::text[], 'El azul del reloj se equilibra con pantalón de lana y bailarinas, logrando un casual pulido. La Tosca aporta flores verdes y almizcle suave, perfecta para primavera o tardes en la ciudad.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-98aa71f123ac', 'jomashop', 'COS-SVGMPS34', 'Dior Men''s Sauvage Parfum 3.4 oz', 'Dior', 'perfume', 'men', 'Seco, intenso y pulido; deja una estela masculina que se impone con elegancia.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/a/sauvage-christian-dior-parfum-spray-34-oz-100-ml-m-3348901486385.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/a/sauvage-christian-dior-parfum-spray-34-oz-100-ml-m-3348901486385.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/a/sauvage-christian-dior-parfum-spray-34-oz-100-ml-m-3348901486385_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/a/sauvage-christian-dior-parfum-spray-34-oz-100-ml-m-3348901486385_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/c/h/christian-dior-mens-sauvage-parfum-edp-spray-34-oz-tester-fragrances-t3348901486385.jpg?width=546&height=546', 'https://www.odoraperfume.com/media/1375/catalog/CHRISTIAN-DIOR-SAUVAGE-FOR-MEN-PARFUM-100ML-3348901486385.jpg', 'https://skinperfectcosmetics.com/cdn/shop/files/s-3348901486385__1.jpg?v=1710546659&width=600']::text[], 'https://www.jomashop.com/christian-dior-fragrances-svgmps34-3-4oz.html', 154.84, 217.99, 'Llévalo con reloj de acero, traje azul oscuro y zapatos negros; acompaña con tonos grafito y perfume ambarado.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-474b2526c36a', 'mp-a057942bba4c']::text[], 'Sauvage Parfum pide brillo contenido: camisa satinada, mocasines de terciopelo y reloj champagne. Perfecto para noche elegante; el perfume se percibe amaderado, especiado y sensual, con una estela limpia pero intensa.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c5f3d838309b', 'jomashop', 'Y-127360', 'Christian Dior Ladies J''Adore Infinissime EDP Spray 3.4 oz', 'Dior', 'perfume', 'women', 'Un floral luminoso y sofisticado que envuelve la piel con presencia femenina refinada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-ladies-jadore-infinissime-edp-spray-3-4-oz-fragrances-3348901521512.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-ladies-jadore-infinissime-edp-spray-3-4-oz-fragrances-3348901521512.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-ladies-jadore-infinissime-edp-spray-34-oz-fragrances-3348901521512_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-ladies-jadore-infinissime-edp-spray-34-oz-fragrances-3348901521512_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-ladies-jadore-infinissime-edp-spray-34-oz-fragrances-3348901521512_7.jpg', 'https://compraperfumesoriginales.com/product-images/jadore-infinissime-3348901521512-1312.png', 'https://www.perfumeprice.net/Images/3348901521512_01.jpg?resizeid=4&resizeh=1500&resizew=1500']::text[], 'https://www.jomashop.com/christian-dior-jadore-infinissime-eau-de-parfum-spray-100ml-3-4oz-3348901521512.html', 154.99, 217.99, 'Combínalo con reloj fino dorado, vestido marfil o negro y tacón nude; suma joyería discreta.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-6df6546277aa', 'mp-f9f99f3e6118', 'mp-21f8ec52e6da']::text[], 'J''Adore Infinissime brilla con pantalón slim y pumps de cristal, un conjunto sofisticado y femenino. El reloj rosa añade delicadeza; ideal para cena, cocktail o evento de noche.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8e63d543abef', 'jomashop', 'Z-4DGMG', 'Yves Saint Laurent Men''s MYSLF L’Absolu Parfum 3.3 oz', 'Yves Saint Laurent', 'perfume', 'men', 'Más profundo y pulido, ofrece un carácter limpio con final sofisticado y persistente.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-mens-myslf-labsolu-parfum-3-3-oz-fragrances-3614274329384.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-mens-myslf-labsolu-parfum-3-3-oz-fragrances-3614274329384.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-mens-myslf-labsolu-parfum-33-oz-fragrances-3614274329384_2.jpg', 'https://cdn2.jomashop.com/media/.thumbswysiwyg/category-banners/home_fragrances.jpg']::text[], 'https://www.jomashop.com/yves-saint-laurent-mens-myslf-l-absolu-parfum-3-4-oz-fragrances-3614274329384.html', 154.99, 217.99, 'Usa reloj minimalista, camisa blanca, blazer antracita y loafer negro; elige tonos sobrios y perfume ambarado.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4f703db7d409', 'mp-ccd7e4d707b6', 'mp-7fe5887981ce']::text[], 'MYSLF L’Absolu encaja con una camisa estructurada, brogues sobrios y un reloj de acero: moderno y ejecutivo. Ideal para oficina y cena posterior; su carácter es floral-amaderado, pulido y luminoso.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a2530700e8c7', 'theoutnet', 'ton-46376663163061285', 'Arsene Checked Linen Shirt', 'Officine Générale', 'clothing', 'men', 'Lino con cuadro sutil y caída relajada, perfecto para un estilo fresco y seguro.', 'https://www.theoutnet.com/variants/images/46376663163061285/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163061285/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061285/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061285/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061285/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061285/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/officine-generale/tops/casual-shirts/arsene-checked-linen-shirt/46376663163061285', 155, 217.99, 'Combínala con reloj de cuero tostado, pantalón arena y mocasines claros; añade perfume cítrico ligero.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-371303f8ebbb', 'mp-5744d9813fec', 'mp-0de6cc427e14']::text[], 'Lino veraniego y espadrilles crean una silueta relajada y refinada para Lima. El reloj de buceo añade frescura deportiva, mientras Acqua di Gio aporta un acorde acuático-cítrico, limpio y muy estival.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-21f8ec52e6da', 'jomashop', 'CZFE1140-86X', 'Citizen Silhouette Crystal Eco-Drive Pink Dial Diamond Ladies Watch', 'Citizen', 'watch', 'women', 'Rosa suave con brillo de diamantes para una elegancia delicada y actual.', 'https://citizenwatch.widen.net/content/uj6p8zfzqn/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/uj6p8zfzqn/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/4w4nqr0eum/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/gikp7yw5ek/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-crystal-eco-drive-pink-dial-diamond-stainless-steel-ladies-watch-fe1140-86x.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-crystal-eco-drive-pink-dial-diamond-stainless-steel-ladies-watch-fe1140-86x_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-crystal-eco-drive-pink-dial-diamond-stainless-steel-ladies-watch-fe1140-86x_3.jpg']::text[], 'https://www.jomashop.com/citizen-watch-fe1140-86x.html', 155.8, 218.99, 'Llévalo con reloj fino en acero, perfume floral limpio, blusa crema y falda lápiz o tacones nude.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-56139b744bbc', 'mp-771e0dce9f5f', 'mp-3ca07bcbe159']::text[], 'El reloj rosado pide líneas limpias y femeninas: pantalón de lana impecable, bailarinas clásicas y un perfume floral empolvado con aire sofisticado. Ideal para oficina o almuerzo elegante, especialmente en clima templado.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2dc2d5978672', 'jomashop', 'COS-EASMTS66', 'Eau Sauvage / Christian Dior EDT Spray 6.6 oz (m)', 'Dior', 'perfume', 'unisex', 'Cítrico clásico y preciso, con frescura limpia para un porte impecable.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/e/a/eau-sauvage-christian-dior-edt-spray-6-6-oz-m-3348900627482_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/e/a/eau-sauvage-christian-dior-edt-spray-6-6-oz-m-3348900627482_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/e/a/eau-sauvage-christian-dior-edt-spray-66-oz-m-3348900627482_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/e/a/eau-sauvage-christian-dior-edt-spray-66-oz-m-3348900627482_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/e/a/eau-sauvage-christian-dior-edt-spray-66-oz-m-3348900627482_7.jpg', 'https://compraperfumesoriginales.com/product-images/eau-sauvage-3348900627482.png', 'https://www.bjutip.com/image/cache/catalog/Perfumes/Men/3348900627482_4-800x800.jpg', 'https://www.totrack.it/wp-content/uploads/2023/11/3348900627482-000-557.jpg']::text[], 'https://www.jomashop.com/christian-dior-perfume-easmts66.html', 155.99, 218.99, 'Combínalo con reloj de acero, perfume herbal suave, camisa blanca y blazer azul con mocasines.', 'https://i.pinimg.com/736x/35/8d/a6/358da61f35d03c9a72d7796edeb64275--formal-outfits-work-outfits.jpg', ARRAY['mp-357d594d46a8', 'mp-7795ae7c1d60', 'mp-7fe5887981ce']::text[], 'Para oficina o smart casual, la camisa de lino, los loafers de cuero y el Seiko de acero son una fórmula impecable. Eau Sauvage aporta cítricos limpios, herbales y clásicos, muy pulidos.', 'oficina', ARRAY['mp-e80799294eb5', 'mp-771e0dce9f5f', 'mp-cbf5fd94f2da']::text[], 'Para ti, la camisa popelina, las bailarinas y el PRX de 35 mm crean un look profesional y refinado. Eau Sauvage suma frescura cítrica y limpia, ideal para oficina y días cálidos en Lima.', 'oficina') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-589013bfe12b', 'jomashop', 'Z-CETAK', 'Prada Unisex Un Chant D''amour EDP Spray 3.4 oz', 'Prada', 'perfume', 'unisex', 'Un acorde romántico y envolvente con aire de colección, delicado pero memorable.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-unisex-un-chant-damour-edp-spray-34-oz-fragrances-3614274113860.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-unisex-un-chant-damour-edp-spray-34-oz-fragrances-3614274113860.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-unisex-un-chant-damour-edp-spray-34-oz-fragrances-3614274113860_2.jpg', 'https://cdn.paris-avenues.com/image/cache/catalog/Product2/3614274113860-Prada-Un-Chante-D''Amour-EDP-100-Ml-600x315w.png']::text[], 'https://www.jomashop.com/prada-unisex-un-chant-damour-edp-spray-3-4-oz-fragrances-3614274113860.html', 156.74, 219.99, 'Llévalo con reloj slim plateado, vestido satinado marfil y sandalias negras; perfuma con notas florales suaves.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-49e760656023']::text[], 'Para una noche refinada, combina la camisa satinada con loafers de terciopelo y un reloj dorado: sobrio, sensual y pulido. El perfume aporta un halo floral-amaderado, íntimo y elegante.', 'noche', ARRAY['mp-33c53e7b9d78', 'mp-f9f99f3e6118', 'mp-3c42564cbf4d']::text[], 'Para una noche elegante, el vestido de punto, los pumps con brillo y el reloj bicolor equilibran feminidad y presencia. El perfume deja una estela floral suave, moderna y envolvente.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-67730c139083', 'jomashop', 'Z-FG9ZR', 'Xerjoff Unisex V Accento EDP Spray 3.4 Oz', 'Xerjoff', 'perfume', 'unisex', 'Fruta pulida y fondo sofisticado para una estela moderna y distinguida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-accento-edp-spray-3-4-oz-fragrances-8033488156206.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-accento-edp-spray-3-4-oz-fragrances-8033488156206.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-accento-edp-spray-34-oz-fragrances-8033488156206_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-accento-edp-spray-34-oz-fragrances-8033488156206_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-accento-edp-spray-34-oz-fragrances-8033488156206_7.jpg', 'https://i5.walmartimages.com/seo/Xerjoff-Unisex-V-Accento-EDP-Spray-3-4-Oz-Fragrances-8033488156206_3366218a-0ac5-4e2e-bb8f-b118ca432f5c.159d98b75f882839b6e771c129373417.jpeg', 'https://i5.walmartimages.com/seo/Xerjoff-Unisex-V-Accento-EDP-Spray-3-4-Oz-Fragrances-8033488156206_772f9535-b6aa-4998-b063-d68d846db0b7.9c1db1cbd2de6daab1fcded43e02c481.jpeg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/x/e/xerjoff-unisex-accento-edp-spray-34-oz-tester-fragrances-t8033488156206.jpg?width=546&height=546']::text[], 'https://www.jomashop.com/xerjoff-accento-100ml-3-4-oz-shiping-eau-de-parfum-8033488156206.html', 156.74, 219.99, 'Combínalo con reloj elegante, traje azul tinta o vestido satinado, zapatos negros y accesorios mínimos.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-23af6e30e1cc']::text[], 'Para una velada de lujo silencioso, la camisa satinada, los loafers de terciopelo y el reloj Presage crean un perfil refinado y seguro. El perfume suma una faceta elegante, cálida y pulida.', 'lujo-silencioso', ARRAY['mp-6ef5af9ad162', 'mp-f9f99f3e6118', 'mp-f4871962fdc0']::text[], 'Para una noche sofisticada, la falda satinada, los pumps cristalinos y el reloj nacarado logran una armonía discreta y lujosa. El perfume acompaña con un carácter cálido, ambarado y elegante.', 'lujo-silencioso') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d2572817bc32', 'jomashop', 'Y-A2SNK', 'Yves Saint Laurent Ladies Libre Le Parfum 3.04 oz', 'Yves Saint Laurent', 'perfume', 'women', 'Fragancia luminosa y envolvente con carácter moderno y presencia refinada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-le-parfum-3-04-oz-fragrances-3614273776127.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-le-parfum-3-04-oz-fragrances-3614273776127.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-le-parfum-304-oz-fragrances-3614273776127_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-le-parfum-304-oz-fragrances-3614273776127_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-ladies-libre-le-parfum-304-oz-fragrances-3614273776127_7.jpg']::text[], 'https://www.jomashop.com/yves-saint-laurent-ladies-libre-le-parfum-3-04-oz-fragrances-3614273776127.html', 156.74, 219.99, 'Llévalo con reloj dorado discreto, blazer marfil y tacones nude para un perfil pulido.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-6df6546277aa', 'mp-f9f99f3e6118', 'mp-3c42564cbf4d']::text[], 'Libre Le Parfum pide un look potente y femenino: pantalón slim, pumps pulidos y un reloj bicolor. Su carácter floral ámbar acompaña muy bien una cena o jornada de oficina con presencia, especialmente en otoño-invierno.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1fee958584dc', 'jomashop', 'Z-NWLJY', 'Yves Saint Laurent Men''s Myslf EDP 5 oz', 'Yves Saint Laurent', 'perfume', 'men', 'Firma limpia y contemporánea, de presencia pulida para el día a día urbano.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-mens-myslf-edp-5-oz-fragrances-3614274289527.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-mens-myslf-edp-5-oz-fragrances-3614274289527.jpg', 'https://cdn.notinoimg.com/detail_main_mq/yves-saint-laurent/3614274289527_02-o/myslf___250903.jpg', 'https://i5.walmartimages.com/asr/28d42f04-5f88-4d37-adaf-737374732f33.317ea134385ea257126d8fbb97b2f7b9.jpeg?odnHeight=1000&odnWidth=1000&odnBg=FFFFFF']::text[], 'https://www.jomashop.com/yves-saint-laurent-mens-myslf-edp-5-oz-fragrances-3614274289527.html', 156.74, 219.99, 'Combínalo con reloj de acero, camisa blanca y pantalón gris; remata con sneakers blancas o derby.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-de6cf0652c90', 'mp-42bc749064f5', 'mp-b4d53c0ac75a']::text[], 'MYSLF funciona muy bien con lino claro, loafers de ante y acero sobrio. Es una propuesta de oficina casual con aire contemporáneo; el perfume es limpio, amaderado-floral y ligeramente cremoso.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-fd9c4a2bd58d', 'theoutnet', 'ton-46376663162848557', 'Long Length Striped Seersucker Swim Shorts', 'Thom Browne', 'clothing', 'men', 'Bermuda ligera de rayas, relajada y pulida para días cálidos junto al mar.', 'https://www.theoutnet.com/variants/images/46376663162848557/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162848557/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162848557/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162848557/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162848557/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162848557/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/swimwear-beachwear/swim-shorts/long-length-striped-seersucker-swim-shorts/46376663162848557', 157, 219.99, 'Úsalo con reloj de caucho blanco, polo crudo y alpargatas; añade perfume cítrico acuático.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-69ef4764b1ae', 'mp-5744d9813fec', 'mp-0e1d44d63a68']::text[], 'Swim shorts con espadrilles y un reloj de buceo forman un look veraniego de resort impecable. Acqua di Gio Absolu suma frescura marina con matiz ambarado, ideal para playa, piscina o almuerzos junto al mar.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-aa9cd49c4ded', 'jomashop', 'Z-D2K6C', 'Prada Ladies Infusion De Figue EDP Spray 3.3 oz', 'Prada', 'perfume', 'women', 'Higo luminoso y verde, fresco y elegante, con textura olfativa serena.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-ladies-infusion-de-figue-edp-spray-33-oz-fragrances-3261473906678.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-ladies-infusion-de-figue-edp-spray-33-oz-fragrances-3261473906678.jpg', 'https://m.media-amazon.com/images/I/61TRgvej2KL._AC_SL1500_.jpg', 'https://dynamic.zacdn.com/RjGXlRvGAum44kuOle9rA2keDz4=/filters:quality(70):format(webp)/https://static-hk.zacdn.com/p/prada-1611-2062117-2.jpg', 'https://www.prada-beauty.com/on/demandware.static/-/Sites-prada-us-Library/default/dw8969545f/images/figue.jpg']::text[], 'https://www.jomashop.com/prada-ladies-les-infusions-de-figue-edp-spray-3-3-oz-fragrances-3261473906678.html', 157.7, 220.99, 'Combínalo con reloj plateado, lino beige y mocasines claros; perfuma con acordes verdes y limpios.', 'https://www.styleatacertainage.com/wp-content/uploads/2025/06/Quince-Linen-Picks.png', ARRAY['mp-56139b744bbc', 'mp-f9f99f3e6118', 'mp-3c42564cbf4d']::text[], 'Infusion de Figue acompaña un pantalón de lana pulido, pumps refinados y un reloj discreto. Su frescura verde-amaderada resulta perfecta para oficina o almuerzo elegante, con una sensación serena y limpia.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f950f566de48', 'jomashop', 'Z-RNHER', 'Prada Unisex Mirages Some Velvet Morning EDP Spray 3.4 oz', 'Prada', 'perfume', 'unisex', 'Un velo sensual y amaderado con aire artístico, pensado para una presencia distinta.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-unisex-mirages-some-velvet-morning-edp-spray-34-oz-fragrances-3614274113495.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-unisex-mirages-some-velvet-morning-edp-spray-34-oz-fragrances-3614274113495.jpg', 'https://www.harmoniq.se/image/188659/3614274113495.jpg', 'https://www.harmoniq.se/image/188658/3614274113495_2.jpg', 'https://www.harmoniq.se/thumb/188657/620x0/3614274113495_1.jpg']::text[], 'https://www.jomashop.com/prada-unisex-mirages-some-velvet-morning-edp-spray-3-4-oz-fragrances-3614274113495.html', 157.65, 220.99, 'Llévalo con reloj negro mate, abrigo oscuro y botas de cuero; suma perfume ambarado y tonos burdeos.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-c109304a8cd3']::text[], 'Para una noche elegante, la camisa satinada, los loafers y el reloj azul construyen un look limpio y distinguido. El perfume aporta un matiz cremoso y seductor, ideal para cena o cóctel.', 'noche', ARRAY['mp-33c53e7b9d78', 'mp-95ac9c8c22b8', 'mp-3c42564cbf4d']::text[], 'Para una noche elegante, el vestido de punto, los pumps y el reloj two-tone crean una silueta pulida y femenina. El perfume envuelve con un carácter suave, sensual y cálido.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-330e5126eba7', 'theoutnet', 'ton-46376663163120761', 'Felix Linen Jersey Polo Shirt', 'Orlebar Brown', 'clothing', 'men', 'Polo de jersey en lino, fresco y depurado, ideal para un lujo relajado.', 'https://www.theoutnet.com/variants/images/46376663163120761/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163120761/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163120761/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163120761/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163120761/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/polo-shirts/felix-linen-jersey-polo-shirt/46376663163120761', 158, 220.99, 'Combínalo con reloj de acero, chinos piedra y sneakers blancas; añade perfume cítrico y gafas sobrias.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-371303f8ebbb', 'mp-ec5394530cac', 'mp-0de6cc427e14']::text[], 'Polo de lino, espadrilles y un reloj blanco crean un verano limpio y relajado, ideal para Lima. Acqua di Gio aporta frescura acuática y cítrica, muy natural para días cálidos y salidas informales.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-bc1e47d9fe61', 'theoutnet', 'ton-46376663163023804', 'Lucio Cotton And Linen Blend Jersey t Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Camiseta de mezcla natural con caída suave, simple y refinada para todos los días.', 'https://www.theoutnet.com/variants/images/46376663163023804/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163023804/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023804/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023804/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023804/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023804/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/t-shirts/lucio-cotton-and-linen-blend-jersey-t-shirt/46376663163023804', 158, 220.99, 'Úsala con reloj minimalista, jeans crudos y mocasines o tenis blancas; perfume limpio y fresco.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-e305c6bba67b', 'mp-7fe5887981ce', 'mp-65d98c5ac518']::text[], 'La camiseta de lino y algodón pide sandalias sobrias y un reloj gris de pulso limpio. Cedrat de Diamante acompaña con cítricos brillantes y transparentes, perfecto para verano casual, almuerzos frente al mar o escapadas ligeras.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ee7b4aec829f', 'jomashop', 'SE-SNKP09', 'Seiko 5 Automatic White Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera blanca y caja limpia para un estilo japonés sobrio y versátil.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-stainless-steel-mens-watch-snkp09j1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-stainless-steel-mens-watch-snkp09j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-stainless-steel-mens-watch-snkp09j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-stainless-steel-mens-watch-snkp09j1_3.jpg', 'https://cdnstatic.creationwatches.com/products/product-images/m/SNKP09K1_MED.webp', 'https://watchzonebd.com/uploads/product/main171181224284065SNKP09K1.webp', 'https://watchzonebd.com/uploads/multiimage/SNKP09K1-8_66082e9292d0e.webp', 'https://webassets.ashford.com/images/web/seiko/SNKP09_FXA.jpg']::text[], 'https://www.jomashop.com/seiko-5-watch-snkp09j1.html', 159, 221.99, 'Acompáñalo con reloj de acero clásico, perfume amaderado ligero, camisa celeste y derbies marrón oscuro.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-cab8b3ae8035', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'Reloj blanco clásico para oficina y casual pulido: camisa de lino suave, loafers discretos y Grey Vetiver. El resultado es sereno y exacto, con una elegancia seca, limpia y muy silenciosa.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2c94095dbacb', 'jomashop', 'Z-X8CL2', 'Paco Rabanne Men''s 1 Million Golden Oud EDP Spray 3.4 oz', 'Paco Rabanne', 'perfume', 'men', 'Oud dorado y cálido, con carácter envolvente y presencia sofisticada de noche.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-1-million-golden-oud-edp-spray-34-oz-fragrances-3349668622009.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-1-million-golden-oud-edp-spray-34-oz-fragrances-3349668622009.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/a/paco-rabanne-mens-1-million-golden-oud-edp-spray-34-oz-fragrances-3349668622009_7.jpg', 'https://i5.walmartimages.com/seo/Paco-Rabanne-Men-s-1-Million-Golden-Oud-EDP-Spray-3-4-oz-Fragrances-3349668622009_bfa494da-d9a8-4f61-8ead-13a1cf6c7078.cf20a6f3f05a7184b2e411a5bc08115e.jpeg', 'https://www.mazaya.eg/media/catalog/product/3/3/3349668622009.jpg?store=en&image-type=image?format=jpeg']::text[], 'https://www.jomashop.com/paco-rabanne-mens-1-million-golden-oud-edp-spray-3-4-oz-fragrances-3349668622009.html', 159.42, 221.99, 'Combínalo con reloj de acero oscuro, traje azul tinta y zapato negro; suma paño grueso y tonos tabaco.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-f468012c6135', 'mp-d92a8189d8f4', 'mp-c109304a8cd3']::text[], 'Para una noche invernal, el bomber con shearling y las botas de ante elevan el carácter opulento del perfume. El reloj suma presencia clásica y sobria, equilibrando la estela cálida, especiada y ambarada del oud.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-65d98c5ac518', 'jomashop', 'Y-57901', 'Versace Unisex Cedrat De Diamante EDP Spray 3.4 oz', 'Versace', 'perfume', 'unisex', 'Cítrico claro y refinado, pensado para una frescura limpia con mucha presencia.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-unisex-cedrat-de-diamante-edp-spray-34-oz-fragrances-8011003848232.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-unisex-cedrat-de-diamante-edp-spray-34-oz-fragrances-8011003848232.jpg', 'https://www.alluringauras.com/wp-content/uploads/2024/07/8011003848232-2.jpg', 'https://papique.com/cdn/shop/files/8011003848232-1.jpg?v=1718370690&width=1500']::text[], 'https://www.jomashop.com/versace-unisex-cedrat-de-diamante-edp-spray-3-4-oz-fragrances-8011003848232.html', 158.83, 221.99, 'Llévalo con reloj plateado, camisa de lino blanca y pantalón arena; completa con loafers claros.', 'https://morningkoffee.com/wp-content/uploads/2025/05/Comfy-summer-outfit-Tote-bag-@bonheur-.linenclothing-linenoutfit-summerstyles-bonheurbag-birkenstocks-pinstripes-linenshirt-linenpants-totebag-canvasbag-casualoutfit-summerlooks.jpg', ARRAY['mp-e0f309401645', 'mp-371303f8ebbb', 'mp-df6073566e3f']::text[], 'Para verano, la camisa de lino, las espadrilles y el reloj de acero componen un look fresco y relajado. El perfume refuerza la impresión cítrica y luminosa, perfecta para día libre o paseo.', 'verano', ARRAY['mp-eccea3334d40', 'mp-a817148e69da', 'mp-3c42564cbf4d']::text[], 'Para verano, el vestido midi floral, las sneakers ligeras y el reloj two-tone equilibran comodidad y encanto. El perfume deja un frescor cítrico limpio, ideal para planes casuales de día.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-af985f5371c7', 'theoutnet', 'ton-46376663163069946', 'Evane Pleated Striped Wool And Cotton Blend Twill Tapered Pants', 'Ralph Lauren', 'clothing', 'women', 'Pantalón de lana y algodón con raya sutil para una sastrería relajada y fina.', 'https://www.theoutnet.com/variants/images/46376663163069946/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163069946/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163069946/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163069946/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163069946/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163069946/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163069946/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ralph-lauren-collection/pants/tapered-pants/evane-pleated-striped-wool-and-cotton-blend-twill-tapered-pants/46376663163069946', 159, 221.99, 'Combínalo con reloj clásico, perfume limpio amaderado, camisa blanca y loafers café o derbies negros.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-8e3bd4eb7fe9', 'mp-023029369bbc', 'mp-fa38caa36f41']::text[], 'Este pantalón pide una combinación seria y femenina: pumps pulidos, reloj sobrio y un perfume de cuero elegante. Conjunto ideal para oficina o reuniones, con una estética invernal muy refinada.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0e1d44d63a68', 'jomashop', 'COS-ACBMES42-A', 'Acqua Di Gio Absolu / Giorgio Armani EDP Spray 4.2 oz (125 ml) (m)', 'Giorgio Armani', 'perfume', 'unisex', 'Cítrico marino y vibrante, ideal para una presencia fresca y activa.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/a/c/acqua-di-gio-absolu-giorgio-armani-edp-spray-4-2-oz-125-ml-m-3614271992932.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/a/c/acqua-di-gio-absolu-giorgio-armani-edp-spray-4-2-oz-125-ml-m-3614271992932.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/a/c/acqua-di-gio-absolu-giorgio-armani-edp-spray-42-oz-125-ml-m-3614271992932_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/a/c/acqua-di-gio-absolu-giorgio-armani-edp-spray-42-oz-125-ml-m-3614271992932_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/o/p/open-box-acqua-di-gio-absolu-giorgio-armani-edp-spray-42-oz-125-ml-m-3614271992932.jpg?width=546&height=546', 'https://fraganciasfinas.com.mx/wp-content/uploads/2021/09/3614271992932-1.png', 'https://farmava.com.ar/images-ecommerce/3614271992932_3.jpeg']::text[], 'https://www.jomashop.com/giorgio-armani-perfume-acbmes42-a.html', 159.99, 222.99, 'Úsalo con reloj deportivo limpio, polo blanco, pantalón de lino azul claro y sneakers o mocasines beige.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-a9c08c82f70a', 'mp-e518f29b87d4', 'mp-aa7a78509b09']::text[], 'Para un look deportivo de verano, los swim shorts, las sneakers técnicas y el reloj negro mantienen energía y limpieza visual. El perfume acompaña con un frescor marino-cítrico, dinámico y moderno.', 'deportivo', ARRAY['mp-d26ee4dee7e5', 'mp-a817148e69da', 'mp-6f0d137af367']::text[], 'Para un día casual de verano, los pantalones de algodón, las sneakers y el reloj azul marino equilibran comodidad y estilo. El perfume suma un frescor acuático-cítrico, ligero y pulcro.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4520d6ec87f1', 'jomashop', 'COS-GRVMES34', 'Tom Ford Men''s Grey Vetiver EDP Spray 3.4 oz (100 ml)', 'Tom Ford', 'perfume', 'men', 'Vetiver limpio y sobrio, con presencia clásica que acompaña la elegancia diaria.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-mens-grey-vetiver-edp-spray-3-4-oz-100-ml-888066007795.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-mens-grey-vetiver-edp-spray-3-4-oz-100-ml-888066007795.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-mens-grey-vetiver-edp-spray-34-oz-100-ml-888066007795_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-mens-grey-vetiver-edp-spray-34-oz-100-ml-888066007795_7.jpg']::text[], 'https://www.jomashop.com/tom-ford-mens-grey-vetiver-edp-spray-3-4-oz-fragrances-888066007795-grvmes34.html', 159.99, 222.99, 'Llévalo con reloj de acero, camisa blanca y zapatos derby marrón oscuro; suma gris, beige y azul marino.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-cab8b3ae8035', 'mp-a1a9c18f6ebe', 'mp-7fe5887981ce']::text[], 'Perfecto para oficina con lujo discreto: camisa de lino y lino-cotón, loafers refinados y un reloj limpio. Grey Vetiver aporta un perfil seco, verde y elegante, muy apropiado para reuniones y jornadas formales.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e0f309401645', 'theoutnet', 'ton-46376663163093246', 'Checked Linen Shirt', 'Thom Browne', 'clothing', 'men', 'Cuadro clásico en lino, de corte relajado y elegancia fácil para el clima cálido.', 'https://www.theoutnet.com/variants/images/46376663163093246/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163093246/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093246/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093246/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093246/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093246/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/tops/casual-shirts/checked-linen-shirt/46376663163093246', 160, 222.99, 'Combínala con reloj de cuero cognac, pantalón beige y mocasines; añade perfume fresco herbáceo.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-371303f8ebbb', 'mp-0de6cc427e14', 'mp-5744d9813fec']::text[], 'Ideal para verano casual: la camisa de lino con espadrilles mantiene el look fresco y sofisticado. El perfume, opcional, suma un tono marino y luminoso que acompaña bien salidas diurnas o almuerzos frente al mar.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDE