INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b4d53c0ac75a', 'jomashop', 'SE-SNXS73', 'Seiko 5 Automatic Silver Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera plateada y acero pulido en un diseño clásico, versátil y discreto.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snxs73.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snxs73.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-mens-automatic-watch-snxs73_2.jpg', 'https://chronospride.com.au/wp-content/uploads/2021/02/SNXS73-5.png']::text[], 'https://www.jomashop.com/seiko-5-watch-snxs73.html', 160.55, 223.99, 'Combínalo con perfume fresco cítrico, camisa oxford azul y mocasines negros o sneakers blancos minimalistas.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-357d594d46a8', 'mp-7795ae7c1d60', 'mp-2dc2d5978672']::text[], 'Un combo de oficina sobria: la camisa de rayas, los loafers de piel y el reloj automático transmiten orden y buen gusto. Eau Sauvage añade una frescura cítrica y clásica, impecable para el día.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-df6073566e3f', 'jomashop', 'SE-SNKL41J1', 'Seiko 5 Automatic White Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Automático blanco, limpio y atemporal, una pieza discreta que acompaña cualquier jornada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-mens-watch-snkl41j1_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-mens-watch-snkl41j1_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-mens-watch-snkl41j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-mens-watch-snkl41j1_3.jpg', 'https://www.raspberryminute.com/image/cache/catalog/Seiko/SNKL41J1/IMG_9149-1920x1920.JPG', 'https://www.raspberryminute.com/image/cache/catalog/Seiko/SNKL41J1/IMG_9136-1920x1920.JPG', 'https://www.picclickimg.com/vTEAAOSwWGZkbvC3/Seiko-5-SNKL41J1-Automatic-Made-In-Japan-White.webp', 'https://www.zetamarket.com/wp-content/uploads/2020/02/SNKL41J1.jpg']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snkl41j1.html', 160.55, 223.99, 'Combínalo con perfume fresco, camisa blanca y blazer azul; usa zapatos café o sneakers sobrias.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-d3392a7bbb8e', 'mp-7795ae7c1d60', 'mp-2dc2d5978672']::text[], 'Con camisa oxford, loafers y un reloj limpio, el conjunto se ve pulido sin rigidez. Eau Sauvage aporta un halo cítrico y refinado, perfecto para oficina y uso cotidiano con elegancia silenciosa.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-cf2b71c1d9e8', 'jomashop', 'Z-2PJZD', 'Xerjoff Men''s Casamorati Mefisto EDP 3.4 oz', 'Xerjoff', 'perfume', 'men', 'Aromática luminosa con aire mediterráneo, refinada y naturalmente fresca.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-mens-casamorati-mefisto-edp-3-4-oz-fragrances-8033488153557.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-mens-casamorati-mefisto-edp-3-4-oz-fragrances-8033488153557.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-mens-casamorati-mefisto-edp-34-oz-fragrances-8033488153557_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-mens-casamorati-mefisto-edp-34-oz-fragrances-8033488153557_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/x/e/xerjoff-mens-casamorati-mefisto-edp-34-oz-tester-fragrances-t8033488153557.jpg?width=546&height=546', 'https://cdn.pazarama.com/mnresize/590/591/asset/8033488153557/images/xerjoffcasamorati1888mefistoerkekparfmedp100ml-2.jpeg', 'https://www.parfuem365.de/media/image/fd/09/df/8033488153557_1.jpg']::text[], 'https://www.jomashop.com/xerjoff-mens-casamorati-1888-mefisto-edp-3-4-oz-fragrances-8033488153557.html', 161.49, 223.99, 'Acompáñalo con reloj de acero, lino beige y loafers marrón claro; perfume limpio y camisa celeste.', 'https://images.stockcake.com/public/e/f/1/ef1cb030-ed89-4a00-af5d-cf1485e9e655_large/elegant-men-s-fashion-stockcake.jpg', ARRAY['mp-42ef9cd82f29', 'mp-ac85563341af', 'mp-68b8b7f85f35']::text[], 'Para verano elegante, la camisa de lino y los loafers suaves mantienen la línea ligera y exquisita. El perfume aporta una frescura cítrica y aromática, muy limpia, ideal para almuerzos o cenas al aire libre.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-cedc1b107150', 'jomashop', 'Y-85989', 'Xerjoff Men''s Casamorati Fiero EDP Spray 3.4 oz', 'Xerjoff', 'perfume', 'men', 'Salida vibrante y aromática, de carácter pulido y frescura luminosa.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-mens-casamorati-fiero-edp-spray-3-4-oz-fragrances-8033488153571.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-mens-casamorati-fiero-edp-spray-3-4-oz-fragrances-8033488153571.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-mens-casamorati-fiero-edp-spray-34-oz-fragrances-8033488153571_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-mens-casamorati-fiero-edp-spray-34-oz-fragrances-8033488153571_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-mens-casamorati-fiero-edp-spray-34-oz-fragrances-8033488153571_4.jpg']::text[], 'https://www.jomashop.com/xerjoff-casamorati-mens-1888-fiero-edp-spray-3-4-oz-fragrances-8033488153571.html', 161.49, 223.99, 'Úsalo con reloj azul, polo blanco y zapatillas de cuero blanco; tonos arena y gris claro.', 'https://images.stockcake.com/public/e/f/1/ef1cb030-ed89-4a00-af5d-cf1485e9e655_large/elegant-men-s-fashion-stockcake.jpg', ARRAY['mp-8aee15c7a2fc', 'mp-b9b2b677d2ef', 'mp-a057942bba4c']::text[], 'El lino, las sandalias tipo espadrille y el reloj dorado crean un look veraniego, pulcro y relajado. Fiero acompaña con frescura cítrica y herbal, perfecta para días cálidos y planes junto al mar.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-37dd49d175c3', 'theoutnet', 'ton-46376663163081106', 'Pleated Checked Wool Midi Skirt', 'Thom Browne', 'clothing', 'women', 'Fal da estructurada con cuadro sobrio, precisa y distinguida para un vestir contemporáneo.', 'https://www.theoutnet.com/variants/images/46376663163081106/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163081106/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163081106/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163081106/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163081106/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163081106/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/skirts/midi-skirts/pleated-checked-wool-midi-skirt/46376663163081106', 162, 224.99, 'Úsala con reloj delicado, blusa marfil y botines negros; perfuma con notas limpias y florales.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-64542fde01c1', 'mp-771e0dce9f5f', 'mp-ccf304630040']::text[], 'La falda de lana pide un remate pulido: flats, reloj sobrio y un perfume envolvente. Si lo usas en invierno u oficina, Si Intense suma calidez ambarada y femenina.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7def16c416be', 'jomashop', 'Z-RV95K', 'Jean Paul Gaultier Men''s Scandal Absolu Parfum 5.0 oz', 'Jean Paul Gaultier', 'perfume', 'men', 'Intenso y cremoso, con un contraste seductor y elegante.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-absolu-parfum-50-oz-fragrances-8435415080392.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-absolu-parfum-50-oz-fragrances-8435415080392.jpg', 'https://i5.walmartimages.com/seo/Jean-Paul-Gaultier-Scandal-Pour-Homme-Absolu-Parfum-Concentr-5-fl-oz_99edcbda-9e49-4957-9653-0575bdf26dde.7c3e1d0436c7318f34203fc17035e0cb.jpeg', 'https://www.thefragrancecounter.co.uk/user/products/large/jeanpaulgaultierscandalabsoluforhimfragranceswithnotes.jpg']::text[], 'https://www.jomashop.com/jean-paul-gaultier-mens-scandal-absolu-parfum-5-0-oz-fragrances-8435415080392.html', 162.74, 225.99, 'Combínalo con reloj de esfera oscura, blazer negro y zapatos de cuero pulido; tonos vino y grafito.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-f3cd717d3b87', 'mp-49e760656023']::text[], 'Para noche elegante, la camisa satinada, los loafers adornados y el reloj dorado elevan el dramatismo con control. El perfume suma intensidad dulce, especiada y seductora, ideal para cenas y eventos after dark.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCL