la estela cremosa y especiada del perfume. Es una propuesta de noche invernal, rica y envolvente, con presencia sin exceso.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e6839ece5ca7', 'theoutnet', 'ton-1647597323811079', 'Alfred Floral Print Woven Pants', 'Orlebar Brown', 'clothing', 'men', 'Pantalón floral ligero, expresivo y fresco, perfecto para un look vacacional cuidado.', 'https://www.theoutnet.com/variants/images/1647597323811079/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597323811079/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597323811079/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597323811079/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597323811079/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597323811079/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/pants/casual-pants/alfred-floral-print-woven-pants/1647597323811079', 163, 225.99, 'Combínalo con reloj de caucho, polo blanco y sandalias o espadrilles; usa perfume acuático y cítrico.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-162803429493', 'mp-b4d53c0ac75a', 'mp-0e1d44d63a68']::text[], 'Para verano casual, los pantalones estampados se suavizan con sandalias limpias y un reloj clásico. Acqua di Gio Absolu aporta un perfil acuático, aromático y fresco, perfecto para fines de semana y escapadas.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ad78b887d97f', 'jomashop', 'SE-SNKM83', 'Seiko 5 Automatic White Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera blanca y perfil limpio en un clásico automático muy fácil de llevar.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-white-dial-automatic-men_s-watch-snkm83k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-white-dial-automatic-men_s-watch-snkm83k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-white-dial-automatic-men_s-watch-snkm83k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-white-dial-automatic-men_s-watch-snkm83k1_3.jpg', 'https://chronospride.com.au/wp-content/uploads/2018/02/SNKM83K1-3.jpg', 'https://seikokw.com/wp-content/uploads/2026/04/seiko-5-white-dial-automatic-men_s-watch-snkm83k1.jpg']::text[], 'https://www.jomashop.com/seiko-5-watch-snkm83k1.html', 164, 226.99, 'Combínalo con perfume amaderado ligero, camisa celeste y zapatos derby o sneakers de cuero blanco.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-cab8b3ae8035', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'Muy correcto para oficina: camisa de lino-cotón, loafers y un reloj sencillo con presencia. Grey Vetiver añade una firma seca, verde y sobria, ideal para jornadas largas y reuniones discretas.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-11ad98d9569f', 'jomashop', 'Z-JUFDC', 'Versace Unisex Atelier Tabac Imperial EDP Spray 3.4 oz', 'Versace', 'perfume', 'unisex', 'Tabaco y resinas en una composición oscura, elegante y profundamente envolvente.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-unisex-atelier-tabac-imperial-edp-spray-34-oz-fragrances-8011003863747.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-unisex-atelier-tabac-imperial-edp-spray-34-oz-fragrances-8011003863747.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-unisex-atelier-tabac-imperial-edp-spray-34-oz-fragrances-8011003863747_7.jpg', 'https://compraperfumesoriginales.com/product-images/atelier-tabac-imperial-80110038637473955.png', 'https://compraperfumesoriginales.com/product-images/atelier-tabac-imperial-8011003863747-7475.png']::text[], 'https://www.jomashop.com/versace-unisex-tabac-imperial-edp-spray-3-4-oz-fragrances-8011003863747.html', 163.68, 226.99, 'Combínalo con reloj de acero negro, abrigo camel y camisa grafito; añade cuero liso y lana.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-f468012c6135', 'mp-d92a8189d8f4', 'mp-1f0254abf485']::text[], 'Para invierno y noche, el bomber con shearling, las botas de ante y el reloj Seastar crean un conjunto robusto y elegante. El perfume aporta humo, tabaco y calidez, ideal para cena o bar.', 'invierno', ARRAY['mp-6df6546277aa', 'mp-0cf3b002ce9d', 'mp-f4871962fdc0']::text[], 'Para invierno y noche, el pantalón slim, los ankle boots y el reloj nacarado equilibran fuerza y sofisticación. El perfume tiene un carácter ahumado, cálido y envolvente, perfecto para una salida nocturna.', 'invierno') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9ece639f26e7', 'jomashop', 'COS-MDGTS5', 'Miss Dior Blooming Bouquet / Christian Dior EDT Spray 5.0 oz (150 ml) (w)', 'Dior', 'perfume', 'unisex', 'Bouquet luminoso y delicado, ideal para una feminidad fresca y pulida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/i/miss-dior-blooming-bouquet-christian-dior-edt-spray-50-oz-150-ml-w-3348901283984.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/i/miss-dior-blooming-bouquet-christian-dior-edt-spray-50-oz-150-ml-w-3348901283984.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/m/i/miss-dior-blooming-bouquet-christian-dior-edt-spray-50-oz-150-ml-w-3348901283984_7.jpg', 'https://assets.solesense.com/en/images/products/500/miss-dior-blooming-bouquet-christian-dior-edt-spray-5-0-oz-150-ml-white-3348901283984oz_1.jpg', 'https://compraperfumesoriginales.com/product-images/miss-dior-blooming-bouquet-3348901283984.png', 'https://mediafiles.maxaroma.com/9cd29e92-4b8f-436f-ad1f-8e368b30dc1d/https://www.maxaroma.com/productimages/large/UP3348901283984_1.jpg?ver=1767028065', 'https://compraperfumesoriginales.com/product-images/miss-dior-blooming-bouquet-3348901283984-2503.png', 'https://cdn.paris-avenues.com/image/cache/catalog/Product2/Pa1/3348901283984-Dior-Miss-Blooming-Bouquet-Edt-150-Ml-1-600x315w.png']::text[], 'https://www.jomashop.com/christian-dior-fragrances-mdgts5.html', 164.99, 227.99, 'Llévalo con reloj fino rosado, vestido beige o blanco y sandalias nude; suma joyas mínimas.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-6f035be15849', 'mp-3c75f66f94e0', 'mp-572e6daacaab']::text[], 'Para verano, la camisa floral de lino, los loafers y el reloj dorado logran un aire elegante sin rigidez. El perfume aporta una frescura floral luminosa, ideal para almuerzo, evento diurno o terraza.', 'verano', ARRAY['mp-eccea3334d40', 'mp-ca5e6334e29b', 'mp-f4871962fdc0']::text[], 'Para verano, el vestido floral, las sandalias de cuero y el reloj de nácar crean un conjunto fresco y delicado. El perfume acompaña con un bouquet floral limpio y luminoso, muy chic.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
