n_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e5b8eeedce5f', 'jomashop', 'Y-70274', 'Christian Dior Men''s Homme Intense EDP Spray 5 oz', 'Dior', 'perfume', 'men', 'Dior Intense ofrece profundidad aterciopelada y una silueta elegante, sobria y muy actual.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-mens-homme-intense-edp-spray-5-oz-fragrances-3348901001120.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-mens-homme-intense-edp-spray-5-oz-fragrances-3348901001120.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-mens-homme-intense-edp-spray-5-oz-fragrances-3348901001120_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-mens-homme-intense-edp-spray-5-oz-fragrances-3348901001120_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/o/p/open-box-christian-dior-mens-homme-intense-edp-spray-5-oz-fragrances-3348901001120.jpg', 'https://cdn.evkur.com.tr/c/Product/3348901001120_e7q9lg.jpg']::text[], 'https://www.jomashop.com/christian-dior-ladies-homme-intense-edp-spray-5-oz-fragrances-3348901001120.html', 166.24, 228.99, 'Combínalo con reloj de acero, traje carbón y derby negro; suma perfume amaderado y corbata lisa.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4f703db7d409', 'mp-bc4ac599808b', 'mp-5e2e71d7480e']::text[], 'Para oficina nocturna o cena formal, la camisa sobria, los brogues y el reloj automático crean una imagen precisa y elegante. Homme Intense acompaña con iris, cacao y maderas, denso y refinado.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d57b7db0b092', 'jomashop', 'Y-A5DQG', 'Prada Ladies Paradoxe Radical Essence Parfum 3 oz', 'Prada', 'perfume', 'women', 'Aroma moderno y femenino con presencia suave y acabado refinado.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-ladies-paradoxe-radical-essence-parfum-3-oz-fragrances-3614274305401.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-ladies-paradoxe-radical-essence-parfum-3-oz-fragrances-3614274305401.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-ladies-paradoxe-radical-essence-parfum-3-oz-fragrances-3614274305401_2.jpg', 'https://www.sephora.com.mx/on/demandware.static/-/Sites-masterCatalog_Sephora/es_MX/dwa1abba79/images/hi-res/boletos/Frida/PRADA/3614274305401_2.jpg', 'https://image-optimizer-reg.production.sephora-asia.net/images/product_images/closeup_3_Product_3614274305401-Prada-Paradoxe-Radical-Essence-Parfu_ca079dd3b3e633e88227ecad268c94997f2769d7_1759917208.png', 'https://cdn.notinoimg.com/detail_main_mq/prada/3614274305401_04/paradoxe-radical-essence___250912.jpg', 'https://cdn.notinoimg.com/detail_main_hq/prada/3614274305401_02-o/paradoxe-radical-essence___250604.jpg']::text[], 'https://www.jomashop.com/prada-ladies-paradoxe-radical-essence-parfum-3-oz-fragrances-3614274305401.html', 166.24, 228.99, 'Llévalo con reloj de acero pulido, blusa marfil y tacones nude para un perfil limpio y elegante.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-56139b744bbc', 'mp-f9f99f3e6118', 'mp-b92296fdc3b1']::text[], 'Pantalón de lana, pumps y reloj azul construyen un conjunto limpio y femenino, ideal para oficina o cena. Paradoxe Radical Essence aporta un floral moderno, cremoso y luminoso.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-81d52947c289', 'jomashop', 'Z-DPH4F', 'Xerjoff Ladies Casamorati 1888 Dama Bianca EDP 3.4 oz (100 ml)', 'Xerjoff', 'perfume', 'women', 'Polvo irisado y delicado, con una feminidad luminosa y refinada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-1888-dama-bianca-edp-34-oz-100-ml-8033488151652.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-1888-dama-bianca-edp-34-oz-100-ml-8033488151652.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-1888-dama-bianca-edp-34-oz-100-ml-8033488151652_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-ladies-casamorati-1888-dama-bianca-edp-34-oz-100-ml-8033488151652_7.jpg', 'https://lacasadelperfume.cl/wp-content/uploads/2022/05/8033488151652.jpg']::text[], 'https://www.jomashop.com/xerjoff-ladies-casamorati-1888-dama-bianca-edp-3-4-oz-fragrances-8033488151652.html', 166.24, 228.99, 'Llévalo con reloj delgado, vestido crema y tacones nude; añade joyas discretas y lino suave.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-56139b744bbc', 'mp-771e0dce9f5f', 'mp-3c42564cbf4d']::text[], 'Pantalón de lana pulido, flats clásicos y reloj bicolor refinan Dama Bianca con discreción. Ideal para oficina o almuerzo elegante: el perfume aporta un halo empolvado, femenino y luminoso, muy limpio y sofisticado.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-60727c51909d', 'jomashop', 'COS-SVGMTS67', 'Sauvage / Christian Dior EDT Spray "new Fragrance" 6.7 oz (m)', 'Dior', 'perfume', 'unisex', 'Fresco, especiado y limpio, con una firma masculina muy reconocible.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/a/sauvage-christian-dior-edt-spray-new-fragrance-67-oz-m-3348901321129.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/a/sauvage-christian-dior-edt-spray-new-fragrance-67-oz-m-3348901321129.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/a/sauvage-christian-dior-edt-spray-new-fragrance-67-oz-m-3348901321129_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/a/sauvage-christian-dior-edt-spray-new-fragrance-67-oz-m-3348901321129_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/a/sauvage-christian-dior-edt-spray-new-fragrance-67-oz-m-3348901321129_7.jpg', 'https://compraperfumesoriginales.com/product-images/sauvage-classic-3348901321129-9577.png', 'https://cdn.vortexs.io/api/images/463ca42a-9a48-4c84-ab6b-889f608e29c8/1920/w/nuoc-hoa-christian-dior-sauvage-edt-200-ml-3348901321129.jpeg', 'https://dcdn-us.mitiendanube.com/stores/005/305/341/products/3348901321129-e5f6c77f91ec93f70317558828152629-640-0.png']::text[], 'https://www.jomashop.com/christian-dior-perfume-svgmts67.html', 168.14, 230.99, 'Usa reloj deportivo de acero, polo gris y sneakers blancos; completa con denim oscuro o chino beige.', 'https://lifewithjazz.com/wp-content/uploads/2022/04/5-Smart-Casual-Outfits-Last-picture.jpg', ARRAY['mp-c4e376ebb5ab', 'mp-a2717c731232', 'mp-3240465564d7']::text[], 'Para un look casual con carácter, combina el polo con zapatillas de cuero y un Seiko deportivo. Sauvage aporta frescura aromática, limpia y amaderada, ideal para el día en Lima o una salida relajada con estilo.', 'casual', ARRAY['mp-06ff9dcd5d2f', 'mp-a817148e69da', 'mp-0011f169d584']::text[], 'El crop shirt, las sneakers técnicas y el Tissot crean un conjunto moderno y relajado. Para ti, Sauvage suma un perfil fresco, especiado y limpio, perfecto para un día casual con presencia.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2c2fe7ad405a', 'theoutnet', 'ton-1647597298600014', 'Mayer Linen Jersey Polo Shirt', 'Orlebar Brown', 'clothing', 'men', 'Polo de lino-jersey ligero, pulido y natural para días cálidos.', 'https://www.theoutnet.com/variants/images/1647597298600014/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597298600014/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597298600014/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597298600014/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597298600014/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/polo-shirts/mayer-linen-jersey-polo-shirt/1647597298600014', 168, 230.99, 'Combínalo con reloj de esfera clara, fragancia cítrica y pantalón arena con mocasines de gamuza.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-371303f8ebbb', 'mp-5744d9813fec', 'mp-0de6cc427e14']::text[], 'Lino y textura natural para un look de fin de semana en Lima. Las espadrilles mantienen la línea relajada, el Citizen suma frescura náutica y Acqua di Gio aporta un perfil cítrico-marino limpio y discreto.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-aa4c56b42c33', 'jomashop', 'SE-SNKP11', 'Seiko Seiko 5 Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Reloj automático Seiko 5 de dial negro, sobrio y versátil.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-black-dial-mens-watch-snkp11.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-black-dial-mens-watch-snkp11.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-black-dial-mens-watch-snkp11_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-black-dial-mens-watch-snkp11_3.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Automatic-Black-Dial-Snkp11-Snkp11k1-Snkp11k-Men-s-Watch_54298a0e-979c-4c8d-8246-6a1af41f260d.633aabbbe18640a5a92287580f9222a2.jpeg?odnHeight=573&odnWidth=573&odnBg=FFFFFF', 'https://psbwatches.com/cdn/shop/files/MONTRE-SEIKO-5-SNKP11K1-NOIR_1.jpg?v=1718832064&width=1600']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snkp11j1.html', 169, 231.99, 'Úsalo con camisa blanca, perfume amaderado y zapatos derby negros para un look discreto y preciso.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-d3392a7bbb8e', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'La camisa de rayas y los loafers afilan el Seiko sin perder sobriedad. Grey Vetiver añade un carácter seco, elegante y profesional, ideal para oficina con un guiño contemporáneo.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
