con sobriedad, perfecto para trabajo o almuerzo refinado en temporada cálida.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-bc4ac599808b', 'jomashop', 'SE-SNKP21J1', 'Seiko 5 Automatic Black Arabic Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Seiko 5 automático con números árabes, clásico y fácil de llevar.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-arabic-dial-mens-watch-snkp21j1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-arabic-dial-mens-watch-snkp21j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-arabic-dial-mens-watch-snkp21j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-arabic-dial-mens-watch-snkp21j1_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-arabic-dial-mens-watch-snkp21j1_vthumb_1.jpg', 'https://www.citywatches.co.za/wp-content/uploads/2023/12/SNKP21J1.jpg', 'https://psbwatches.com/cdn/shop/files/SEIKO-5-ARABIC-DIAL-SNKP21J1_PRINCIPALE.jpg?v=1710712504&width=2048']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snkp21j1.html', 170.05, 232.99, 'Acompáñalo con polo azul marino, perfume fresco y loafers marrones para un estilo relajado y pulido.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-cab8b3ae8035', 'mp-6e78cd2c0e9e', 'mp-2dc2d5978672']::text[], 'La camisa en lino y los penny loafers equilibran el negro del reloj con elegancia limpia. Eau Sauvage suma frescura cítrica aromática, ideal para oficina y días templados.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO 