INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-064aad366e7c', 'jomashop', 'CZAW1158-05L', 'Citizen AR Blue Dial Blue Polyurethane Eco-Drive Men''s Watch', 'Citizen', 'watch', 'men', 'Azul intenso y construcción robusta para un pulso activo y moderno.', 'https://citizenwatch.widen.net/content/wyyenh9kla/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/wyyenh9kla/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/r3fbqelh0x/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/ul8hg5k0vr/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/23uiq6jwgh/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ar-blue-dial-mens-watch-aw1158-05l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ar-blue-dial-mens-watch-aw1158-05l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ar-blue-dial-mens-watch-aw1158-05l_3.jpg']::text[], 'https://www.jomashop.com/citizen-ar-watch-aw1158-05l.html', 170.05, 232.99, 'Combínalo con perfume acuático, polo técnico y sneakers; usa negro, azul marino y gris grafito.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-a9c08c82f70a', 'mp-e518f29b87d4', 'mp-605a39d82c0f']::text[], 'El azul del reloj conversa con swim shorts y sneakers para un conjunto activo y veraniego. Luna Rossa Carbon añade una energía limpia, mineral y moderna, perfecta para días de movimiento.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-bca30cdd6816', 'jomashop', 'Y-57893', 'Versace Unisex Eclat De Rose EDP Spray 3.4 oz', 'Versace', 'perfume', 'unisex', 'Rosa luminosa y femenina con un matiz elegante y actual.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-unisex-eclat-de-rose-edp-spray-34-oz-fragrances-8011003848218.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-unisex-eclat-de-rose-edp-spray-34-oz-fragrances-8011003848218.jpg', 'https://www.alluringauras.com/wp-content/uploads/2024/07/8011003848218-2.jpg', 'https://image-optimizer-reg.production.sephora-asia.net/eyJlZGl0cyI6eyJyZXNpemUiOnt9fX0=/images/product_images/zoom_1_Product_8011003848218-Versace-Eclat-De-Rose-Eau-De-Parfum-100ml_55947d4fe73593de81af75a10f9d132b729862e7_1690177554.png', 'https://fredrikoglouisa.no/wp-content/uploads/2025/03/8011003848218_3.jpg']::text[], 'https://www.jomashop.com/versace-unisex-eclat-de-rose-edp-spray-3-4-oz-fragrances-8011003848218.html', 169.74, 232.99, 'Combínalo con reloj dorado discreto, vestido satinado y sandalias crema para una presencia suave y refinada.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-a057942bba4c']::text[], 'Para una noche elegante, el satén, los loafers de terciopelo y el Seiko dorado elevan tu presencia. Eclat De Rose aporta un halo floral sofisticado, ideal para cena o evento nocturno.', 'noche', ARRAY['mp-33c53e7b9d78', 'mp-f9f99f3e6118', 'mp-21f8ec52e6da']::text[], 'El vestido de punto, los pumps joya y el Citizen rosa equilibran feminidad y brillo discreto. Eclat De Rose acompaña con una rosa suave y luminosa, perfecta para una cena o gala.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-00d24bd45f6d', 'jomashop', 'Y-57898', 'Versace Unisex Jasmin Au Soleil EDP Spray 3.4 oz', 'Versace', 'perfume', 'unisex', 'Jazmín solar, limpio y luminoso, con aire sofisticado de verano.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-unisex-jasmin-au-soleil-edp-spray-34-oz-fragrances-8011003848225.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-unisex-jasmin-au-soleil-edp-spray-34-oz-fragrances-8011003848225.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-unisex-jasmin-au-soleil-edp-spray-34-oz-fragrances-8011003848225_2.jpg', 'https://www.maxaroma.com/productimages/large/UP8011003848225.jpg?ver=1663776704', 'https://image-optimizer-reg.production.sephora-asia.net/eyJlZGl0cyI6eyJyZXNpemUiOnt9fX0=/images/product_images/zoom_1_Product_8011003848225-Versace-Jasmin-Au-Soleil-Eau-De-Parfum-100ml_c8ae87bda3c170d08a80700abd83637fdafe431f_1690177555.png']::text[], 'https://www.jomashop.com/versace-unisex-jasmin-au-soleil-edp-spray-3-4-oz-fragrances-8011003848225.html', 169.74, 232.99, 'Llévalo con reloj minimalista, lino blanco y sandalias camel para un look fresco y silenciosamente lujoso.', 'https://morningkoffee.com/wp-content/uploads/2025/05/Comfy-summer-outfit-Tote-bag-@bonheur-.linenclothing-linenoutfit-summerstyles-bonheurbag-birkenstocks-pinstripes-linenshirt-linenpants-totebag-canvasbag-casualoutfit-summerlooks.jpg', ARRAY['mp-2c2fe7ad405a', 'mp-3c75f66f94e0', 'mp-68b8b7f85f35']::text[], 'Para verano, el polo ligero, los loafers y el reloj dorado logran un lujo relajado. Jasmin Au Soleil aporta jazmín solar, cítrico y cálido, ideal para almuerzo al aire libre o viaje.', 'verano', ARRAY['mp-eccea3334d40', 'mp-ca5e6334e29b', 'mp-21f8ec52e6da']::text[], 'El vestido floral, las sandalias y el reloj con diamantes crean un verano refinado. Jasmin Au Soleil se siente luminoso, floral y delicado, perfecto para brunch, terraza o escapada soleada.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
