INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-37af76f7012d', 'jomashop', 'Z-RLXGQ', 'Gucci Unisex The Last Day Of Summer EDP 3.4 oz', 'Gucci', 'perfume', 'unisex', 'Fragancia luminosa y melancólica, evocando un verano sereno y natural.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-the-last-day-of-summer-edp-34-oz-fragrances-3614227767881.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-the-last-day-of-summer-edp-34-oz-fragrances-3614227767881.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-the-last-day-of-summer-edp-34-oz-fragrances-3614227767881_2.jpg', 'https://cdn.clothbase.com/uploads/c437f8aa-8d0a-4240-927e-2c6e979f079b/azrf7exposs4xg4q2sob.jpg']::text[], 'https://www.jomashop.com/gucci-unisex-the-last-day-of-summer-edp-3-4-oz-fragrances-3614227767881.html', 170.99, 233.99, 'Úsalo con reloj de cuero tostado, camisa beige y zapatillas blancas para una elegancia relajada.', 'https://morningkoffee.com/wp-content/uploads/2025/05/Comfy-summer-outfit-Tote-bag-@bonheur-.linenclothing-linenoutfit-summerstyles-bonheurbag-birkenstocks-pinstripes-linenshirt-linenpants-totebag-canvasbag-casualoutfit-summerlooks.jpg', ARRAY['mp-a4bda690ccc8', 'mp-371303f8ebbb', 'mp-5744d9813fec']::text[], 'La camisa a rayas, las espadrilles y el Promaster forman un look fresco y costero. The Last Day Of Summer tiene un perfil limpio y melancólico, perfecto para días cálidos y relajados.', 'verano', ARRAY['mp-3c7b7e01069a', 'mp-ca5e6334e29b', 'mp-cebec8d3d39d']::text[], 'La falda denim, las sandalias y el reloj plateado equilibran casualidad y pulcritud. The Last Day Of Summer aporta frescura suave y nostálgica, ideal para paseo, café o tarde de verano.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
