INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-385b10452c37', 'jomashop', 'Z-Y5NXM', 'Xerjoff Unisex V Erba Pura EDP Spray 3.4 oz (100 ml)', 'Xerjoff', 'perfume', 'unisex', 'Frutal y transparente, con brillo limpio y una sensación de lujo ligero.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-erba-pura-edp-spray-3-4-oz-100-ml-8033488156329.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-erba-pura-edp-spray-3-4-oz-100-ml-8033488156329.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-erba-pura-edp-spray-34-oz-100-ml-8033488156329_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-erba-pura-edp-spray-3-4-oz-100-ml-8033488156329_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-erba-pura-edp-spray-3-4-oz-100-ml-8033488156329_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/x/e/xerjoff-unisex-erba-pura-edp-spray-34-oz-tester-fragrances-t8033488156329.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/o/p/open-box-xerjoff-unisex-v-erba-pura-edp-spray-34-oz-100-ml-8033488156329_2.jpg?width=546&height=546']::text[], 'https://www.jomashop.com/xerjoff-unisex-erba-pura-edp-spray-3-4-oz-fragrances-8033488156329.html', 172.9, 235.99, 'Acompáñalo con reloj de acero, lino blanco y sandalias minimalistas; suma tonos marfil, beige y celeste.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-42ef9cd82f29', 'mp-a1a9c18f6ebe', 'mp-68b8b7f85f35']::text[], 'La camisa de lino, los loafers y el PRX digital construyen un lujo discreto y pulido. Erba Pura deja una estela frutal-ambarada, limpia y sofisticada, perfecta para almuerzo elegante o verano en la ciudad.', 'lujo-silencioso', ARRAY['mp-eccea3334d40', 'mp-4f1a6a5f486b', 'mp-f4871962fdc0']::text[], 'El vestido floral, las flats y el reloj nacarado crean un verano refinado y femenino. Erba Pura aporta brillo frutal, almizclado y envolvente, ideal para una cita diurna o cena junto al mar.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-36075fe9c90d', 'jomashop', 'Y-127563', 'Giorgio Armani - Prive Rose Milano Eau De Toilette Spray 100ml/3.4oz', 'Giorgio Armani', 'perfume', 'unisex', 'Rosa Milano delicado, floral y refinado, con carácter italiano.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-prive-rose-milano-eau-de-toilette-spray-100ml34oz-3614272650961.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-prive-rose-milano-eau-de-toilette-spray-100ml34oz-3614272650961.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-prive-rose-milano-eau-de-toilette-spray-100ml34oz-3614272650961_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-prive-rose-milano-eau-de-toilette-spray-100ml34oz-3614272650961_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-prive-rose-milano-eau-de-toilette-spray-100ml34oz-3614272650961_7.jpg', 'https://www.atticadps.gr/images/h2160/4/jpg/files/products/3614272650961/20.jpg', 'https://www.atticadps.gr/images/h2160/4/jpg/files/products/3614272650961/30.jpg', 'https://cms.brnstc.de/product_images/680x930_retina/cpro/media/images/product/22/5/3614272650961_3_1651579082786.jpg']::text[], 'https://www.jomashop.com/giorgio-armani-prive-rose-milano-eau-de-toilette-spray-100ml-3-4oz-3614272650961.html', 173.84, 236.99, 'Llévalo con reloj fino, blazer crema y zapatos de punta suave para un conjunto impecable.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-a057942bba4c']::text[], 'La camisa satinada, los loafers de terciopelo y el reloj dorado elevan tu imagen nocturna. Rose Milano aporta una rosa moderna, limpia y elegante, perfecta para cena, cóctel o una salida formal.', 'noche', ARRAY['mp-33c53e7b9d78', 'mp-f9f99f3e6118', 'mp-87c1eb6527f0']::text[], 'El vestido de punto, los pumps con cristal y el reloj brillante crean una silueta sofisticada. Rose Milano se percibe floral, fresca y refinada, ideal para gala, cena o noche especial.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3cd8a928e8c8', 'jomashop', 'CZBM7330-59L', 'Citizen Corso Eco-Drive Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Azul sobrio y líneas limpias en un reloj práctico, refinado y cotidiano.', 'https://citizenwatch.widen.net/content/psampppube/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/psampppube/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-corso-eco-drive-blue-dial-stainless-steel-men_s-watch-bm7330-59l_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-corso-eco-drive-blue-dial-stainless-steel-men_s-watch-bm7330-59l_2_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-corso-eco-drive-blue-dial-stainless-steel-men_s-watch-bm7330-59l_3_1.jpg', 'https://www.jomashop.com/media/catalog/product/c/i/citizen-corso-eco-drive-blue-dial-stainless-steel-men_s-watch-bm7330-59l_1.jpg', 'https://donghominhnhat.vn/imagesys/images/product/2021/04/dong-ho-CITIZEN-BM7330-59L-chinh-hang.webp']::text[], 'https://www.jomashop.com/citizen-watch-bm7330-59l.html', 174.8, 237.99, 'Combínalo con perfume cítrico, camisa azul claro y mocasines marrones; completa con blazer gris.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-357d594d46a8', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'La camisa de lino y los loafers equilibran el azul del reloj con sobriedad y ritmo urbano. Grey Vetiver suma frescura seca y refinada, ideal para oficina y after office.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c0df1d51328d', 'jomashop', 'Z-2J9F9', 'Dolce and Gabbana Unisex Velvet Tender Oud EDP 3.4 oz', 'Dolce & Gabbana', 'perfume', 'unisex', 'Oud aterciopelado con fondo cálido, profundo y muy sofisticado.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/o/dolce-and-gabbana-unisex-velvet-tender-oud-edp-34-oz-fragrances-8054754400113.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/o/dolce-and-gabbana-unisex-velvet-tender-oud-edp-34-oz-fragrances-8054754400113.jpg', 'https://rougeb2car.vtexassets.com/arquivos/ids/240189/8054754400113_2.jpg?v=638889873626200000', 'https://fredrikoglouisa.no/wp-content/uploads/2025/04/8054754400113_3.jpg']::text[], 'https://www.jomashop.com/dolce-and-gabbana-unisex-velvet-tender-oud-edp-3-4-oz-fragrances-8054754400113.html', 174.99, 237.99, 'Combínalo con reloj oscuro, traje azul medianoche y zapatos de cuero liso para máxima discreción.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-1e4d84f905c4', 'mp-5e2e71d7480e', 'mp-c109304a8cd3']::text[], 'La camisa de satén, los brogues metálicos y el reloj azul construyen un noche intensa y elegante. Velvet Tender Oud añade un oud aterciopelado, cálido y profundo, perfecto para evento formal o cena privada.', 'noche', ARRAY['mp-33c53e7b9d78', 'mp-95ac9c8c22b8', 'mp-87c1eb6527f0']::text[], 'El vestido de punto, los pumps de cuero y el reloj con brillo crean una presencia sofisticada. Velvet Tender Oud aporta un oud suave, envolvente y sensual, ideal para cóctel o cena nocturna.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, 