INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a1b047454372', 'theoutnet', 'ton-46376663163100013', 'Travis Floral Print Pique Shirt', 'Orlebar Brown', 'clothing', 'men', 'Camisa piqué floral, fresca y expresiva con espíritu vacacional.', 'https://www.theoutnet.com/variants/images/46376663163100013/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163100013/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100013/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100013/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100013/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100013/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/travis-floral-print-pique-shirt/46376663163100013', 175, 237.99, 'Úsala con reloj de acero, fragancia acuática y bermudas crudas con mocasines ligeros.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-371303f8ebbb', 'mp-5744d9813fec', 'mp-0de6cc427e14']::text[], 'La camisa floral pide espadrilles y un reloj azul para un equilibrio fresco y elegante. Acqua di Gio acompaña con una salida marina, ideal para escapada de fin de semana.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note,