INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ea2cb2e893b0', 'jomashop', 'Z-JWW3X', 'Jean Paul Gaultier Men''s Scandal Elixir Parfum 3.4 oz', 'Jean Paul Gaultier', 'perfume', 'men', 'Licoroso y especiado, con intensidad cálida y carácter escénico.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-elixir-parfum-34-oz-fragrances-8435415114028.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-elixir-parfum-34-oz-fragrances-8435415114028.jpg', 'https://cdn.notinoimg.com/social/jean-paul-gaultier/8435415114028_01-o/scandal-elixir___251218.jpg', 'https://cdn.notinoimg.com/detail_main_mq/jean-paul-gaultier/8435415114028_04/scandal-elixir___251218.jpg']::text[], 'https://www.jomashop.com/jean-paul-gaultier-mens-scandal-elixir-parfum-3-4-oz-fragrances-8435415114028.html', 177.19, 239.99, 'Combínalo con reloj de esfera oscura, traje negro o terciopelo y zapatos brillantes; tonos vino y grafito.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-a057942bba4c']::text[], 'La camisa satinada, los loafers de terciopelo y el reloj dorado elevan el look con dramatismo controlado. Scandal Elixir aporta dulzor especiado y cálido, perfecto para noche y ambiente sofisticado.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3c42564cbf4d', 'jomashop', 'CZEW1544-53A', 'Citizen Silhouette Eco-Drive White Dial Two-tone Ladies Watch', 'Citizen', 'watch', 'women', 'Dos tonos suaves y esfera clara en un diseño femenino, pulido y discreto.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-eco-drive-white-dial-two-tone-ladies-watch-ew1544-53a_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-eco-drive-white-dial-two-tone-ladies-watch-ew1544-53a_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-eco-drive-white-dial-two-tone-ladies-watch-ew1544-53a_2_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-eco-drive-white-dial-two-tone-ladies-watch-ew1544-53a_3_1.jpg', 'https://www.watchuseek.com/attachments/ew1544-53a-2-jpg.1564749/', 'https://i5.walmartimages.com/seo/Citizen-Silhouette-Eco-Drive-White-Dial-Two-tone-Ladies-Watch-EW1544-53A_6d632e64-a787-4699-8ce7-5ea5fb8207c8_1.8937b898cc7441288f180f34e7c5e675.jpeg', 'https://www.watchconcepts.com/citizen/ladies/ew1544-53am.jpg']::text[], 'https://www.jomashop.com/citizen-watch-ew1544-53a.html', 179, 241.99, 'Acompáñalo con perfume floral limpio, blusa crema y pantalón sastre; usa ballet flats o tacones nude.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-af985f5371c7', 'mp-771e0dce9f5f', 'mp-d2572817bc32']::text[], 'El pantalón sastre y las bailarinas mantienen una elegancia suave y atemporal. Libre Le Parfum suma un floral ambarado con presencia, ideal para oficina, cena o día especial.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-db2b986478c3', 'jomashop', 'CZAT2141-52L', 'Citizen Sapphire Collection Eco-Drive Chronograph Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Cronógrafo azul con presencia técnica y refinada, ideal para el día a día.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-sapphire-collection-blue-dial-men_s-watch-at2141-52l.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-sapphire-collection-blue-dial-men_s-watch-at2141-52l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-sapphire-collection-blue-dial-men_s-watch-at2141-52l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-sapphire-collection-blue-dial-men_s-watch-at2141-52l_3.jpg', 'https://chronospride.com.au/wp-content/uploads/2018/10/Citizen-AT2141-52L-5.jpg']::text[], 'https://www.jomashop.com/citizen-watch-at2141-52l.html', 178.5, 241.99, 'Combínalo con perfume fresco, camisa blanca y chaqueta azul marino; suma loafers o sneakers de cuero.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-cab8b3ae8035', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'El azul del dial conversa con la camisa de lino y los mocasines en cuero, logrando una elegancia sobria para oficina o almuerzos de trabajo. Grey Vetiver aporta frescura seca, muy pulida y refinada.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e60c84968449', 'jomashop', 'SE-SNXL72', 'Seiko 5 Automatic Champagne Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Champagne suave y acero clásico en un automático elegante y versátil.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-gold-tone-automatic-mens-watch-snxl72.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-gold-tone-automatic-mens-watch-snxl72.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-gold-tone-automatic-mens-watch-snxl72_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-gold-tone-automatic-mens-watch-snxl72_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-gold-tone-automatic-mens-watch-snxl72_4.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Automatic-Champagne-Dial-Men-s-Watch-SNXL72_93108811-f512-40bd-b23f-9aa51f2de379.b8cccd2df539bf2032caa559c85ee0ce.jpeg']::text[], 'https://www.jomashop.com/seiko-watch-snxl72.html', 179.55, 242.99, 'Combínalo con perfume amaderado fresco, camisa blanca y pantalón azul marino; usa loafers marrón oscuro.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-d3392a7bbb8e', 'mp-42bc749064f5', 'mp-2dc2d5978672']::text[], 'El champán del reloj se equilibra con la camisa a rayas y el pantalón twill, mientras los mocasines de ante suavizan el conjunto. Ideal para un casual inteligente; puede acompañarse con perfume fresco y limpio.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6e5b43773292', 'jomashop', 'CZCA0621-05L', 'Citizen Chandler Chronograph Eco-Drive Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Cronógrafo azul con aire ejecutivo, limpio y fácil de integrar.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-chandler-blue-dial-men_s-chronograph-leather-watch-ca0621-05l.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-chandler-blue-dial-men_s-chronograph-leather-watch-ca0621-05l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-chandler-blue-dial-men_s-chronograph-leather-watch-ca0621-05l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-chandler-blue-dial-men_s-chronograph-leather-watch-ca0621-05l_3.jpg', 'https://images.jamtangan.com/preset:sharp/resize:fit:462:492/dpr:1.5/width:462/height:492/resize:fit/plain/https://assets.jamtangan.com/images/product/citizen/CA0621-05L/1l.jpg']::text[], 'https://www.jomashop.com/citizen-watch-ca0621-05l.html', 179.55, 242.99, 'Acompáñalo con perfume cítrico, camisa celeste y blazer gris; añade pantalón chino y derby café.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-357d594d46a8', 'mp-7795ae7c1d60', 'mp-2dc2d5978672']::text[], 'La esfera azul armoniza con la camisa de lino rayado y el pantalón ligero, creando un look relajado pero cuidado. Perfecto para días templados; los mocasines mantienen el registro pulido sin perder naturalidad.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-fa38caa36f41', 'jomashop', 'Y-142477', 'Giorgio Armani Ladies Prive Cuir Zerzura Intense EDP Spray 3.4 oz', 'Giorgio Armani', 'perfume', 'women', 'Cuero intenso y sensual con una firma elegante y envolvente.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-prive-cuir-zerzura-intense-edp-spray-3-4-oz-fragrances-3614272905139.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-prive-cuir-zerzura-intense-edp-spray-3-4-oz-fragrances-3614272905139.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-prive-cuir-zerzura-intense-edp-spray-3-4-oz-fragrances-3614272905139_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-ladies-prive-cuir-zerzura-intense-edp-spray-3-4-oz-fragrances-3614272905139_3.jpg', 'https://www.myperfumeshop.co.nz/cdn/shop/files/ARMANI_PRIVE_CUIR_ZERZURA-_3614272905139_100_ingredients_v2.webp?v=1705424184&width=1200', 'https://www.colorcafe.com/wp-content/uploads/2023/12/3614272905139_3.jpg']::text[], 'https://www.jomashop.com/giorgio-armani-ladies-prive-cuir-zerzura-intense-edp-spray-3-4-oz-fragrances-3614272905139.html', 180.49, 242.99, 'Acompáñalo con reloj negro, vestido negro estructurado y stilettos para una presencia sofisticada.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-33c53e7b9d78', 'mp-95ac9c8c22b8', 'mp-f4871962fdc0']::text[], 'El perfume de cuero intenso pide un vestido negro con pumps finos y un reloj madreperla, para una noche elegante. La composición resulta sensual y sofisticada, con un carácter amaderado, envolvente y profundo.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-27e3dcae5bef', 'jomashop', 'Z-GSN24', 'Gucci Unisex The Alchemist''s Garden A Floral Verse EDP Spray 3.4 oz', 'Gucci', 'perfume', 'unisex', 'Floral artístico y etéreo, con aire de colección distinguida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-the-alchemists-garden-a-floral-verse-edp-spray-34-oz-fragrances-3616303474300.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-the-alchemists-garden-a-floral-verse-edp-spray-34-oz-fragrances-3616303474300.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-the-alchemists-garden-a-floral-verse-edp-spray-34-oz-fragrances-3616303474300_7.jpg', 'https://cdn.paris-avenues.com/image/cache/catalog/Product2/Pa1/3616303474300-Gucci-Alchemist''S-Garden-A-Floral-Verse-Edp-100-Ml-2-1000x1000.png']::text[], 'https://www.jomashop.com/gucci-unisex-the-alchemists-garden-a-floral-verse-edp-spray-3-4-oz-fragrances-3616303474300.html', 180.49, 242.99, 'Combínalo con reloj joya, satén marfil y sandalias doradas para un look delicado y exclusivo.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-68b8b7f85f35']::text[], 'Para una noche elegante, la camisa satinada, los loafers de terciopelo y el reloj dorado crean un conjunto refinado y sobrio. El perfume aporta un floral luminoso y envolvente, ideal para cenas o eventos con presencia discreta.', 'noche', ARRAY['mp-33c53e7b9d78', 'mp-f9f99f3e6118', 'mp-87c1eb6527f0']::text[], 'Para una noche elegante, el vestido de punto, los pumps con cristales y el reloj delicado equilibran brillo y sofisticación. El perfume suma un floral radiante y femenino, perfecto para cena, cóctel o celebración especial.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c6184453fc68', 'theoutnet', 'ton-46376663163073898', 'Short Length Printed Swim Shorts', 'Missoni', 'clothing', 'men', 'Short de baño estampado, ligero y llamativo para días de sol.', 'https://www.theoutnet.com/variants/images/46376663163073898/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163073898/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163073898/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163073898/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163073898/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163073898/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/missoni/swimwear-beachwear/swim-shorts/short-length-printed-swim-shorts/46376663163073898', 180, 242.99, 'Llévalo con reloj resistente al agua, polo blanco y sandalias de cuero en tono tabaco.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-371303f8ebbb', 'mp-5744d9813fec', 'mp-0de6cc427e14']::text[], 'Los shorts gráficos funcionan mejor con espadrilles y un reloj de aire náutico, ideal para playa o fin de semana en Lima. Acqua di Giò Parfum suma frescura marina, limpia y luminosa.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6b641e4a6597', 'theoutnet', 'ton-46376663163103800', 'Maitan Printed Lyocell Shirt', 'Orlebar Brown', 'clothing', 'men', 'Camisa lyocell estampada, suave al tacto y de caída fluida.', 'https://www.theoutnet.com/variants/images/46376663163103800/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163103800/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103800/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103800/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103800/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103800/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/maitan-printed-lyocell-shirt/46376663163103800', 180, 242.99, 'Combínala con reloj minimalista, perfume fresco y pantalón lino arena con mocasines sin calcetines.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-e305c6bba67b', 'mp-06e2a90e79c5', 'mp-65d98c5ac518']::text[], 'La camisa estampada gana equilibrio con sandalias de cuero y un reloj digital azul, perfecto para vacaciones o almuerzo costero. Cedrat de Diamante aporta cítricos vibrantes y una estela fresca, soleada.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.rec