INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-98496652d515', 'jomashop', 'SE-SNKK98', 'Seiko 5 All Gold-plated Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Acabado dorado sobrio con presencia clásica y pulso vintage para elevar cualquier conjunto.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-all-gold-plated-stainless-steel-men_s-watch-snkk98.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-all-gold-plated-stainless-steel-men_s-watch-snkk98.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-all-gold-plated-stainless-steel-men_s-watch-snkk98_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-all-gold-plated-stainless-steel-men_s-watch-snkk98_3.jpg', 'https://prestigetimepiececenter.com/cdn/shop/products/SNKK98K1-1.jpg?v=1629073967', 'https://www.jomashop.com/media/catalog/product/s/e/seiko-5-all-gold-plated-stainless-steel-men_s-watch-snkk98_3.jpg']::text[], 'https://www.jomashop.com/seiko-5-all-gold-plated-mens-watch-snkk98.html', 180.5, 243.99, 'Combínalo con camisa marfil, blazer azul marino, derbies negras y perfume amaderado limpio.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-f259885fccd2', 'mp-3c75f66f94e0', 'mp-40dd2be6dd83']::text[], 'El oro del reloj pide tonos sobrios y texturas nobles: camisa popelina, loafers de terciopelo y una fragancia moderna. Myslf Le Parfum aporta madera especiada y elegancia contemporánea, ideal para noche o recepción.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4da26784b5f8', 'theoutnet', 'ton-46376663163106261', 'Gelati Gingham Twill Shorts', 'Jacquemus', 'clothing', 'men', 'Short gingham de tacto limpio, alegre y fácil de estilizar.', 'https://www.theoutnet.com/variants/images/46376663163106261/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163106261/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163106261/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163106261/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163106261/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163106261/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jacquemus/shorts/casual-shorts/gelati-gingham-twill-shorts/46376663163106261', 182, 244.99, 'Úsalo con reloj plateado, camiseta blanca y zapatillas de lona para un look fresco y pulido.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-69ef4764b1ae', 'mp-3f497a8f0e15', 'mp-fdac946676d9']::text[], 'Los shorts gingham funcionan con espadrilles y un cronógrafo azul, para un look de escapada urbana o fin de semana. Replica Afternoon Delight añade un dulzor suave y luminoso, muy veraniego y relajado.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a057942bba4c', 'jomashop', 'SE-SNKE56', 'Seiko 5 Automatic Champagne Dial Yellow Gold-tone Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera champagne y baño dorado en una pieza clásica, discreta y refinada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-gold-dial-gold-tone-men_s-watch-snke56.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-gold-dial-gold-tone-men_s-watch-snke56.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-gold-dial-gold-tone-men_s-watch-snke56_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-gold-dial-gold-tone-men_s-watch-snke56_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/o/p/open-box-seiko-5-automatic-champagne-dial-yellow-goldtone-mens-watch-snke56_2.jpg?width=546&height=546']::text[], 'https://www.jomashop.com/seiko-5-mens-watch-snke56.html', 184.3, 246.99, 'Acompáñalo con camisa celeste, pantalón crudo, mocasines café y perfume amaderado suave.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-76e86cc39c9a', 'mp-55daa2a79111', 'mp-62787e09ac2c']::text[], 'El tono dorado del reloj se afina con pantalón de lana, loafers con grosgrain y un perfume cítrico-aromático. Regio aporta frescura clásica, ideal para cenas, reuniones formales o un elegante día de oficina.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, 