INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4b27526bd0db', 'jomashop', 'COS-JADES5', 'Jadore / Christian Dior EDP Spray 5.0 oz (w)', 'Dior', 'perfume', 'unisex', 'J''adore, floral icónico con presencia femenina y acabado luminoso.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/a/jadore-christian-dior-edp-spray-50-oz-w-3348901237116.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/a/jadore-christian-dior-edp-spray-50-oz-w-3348901237116.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/a/jadore-christian-dior-edp-spray-50-oz-w-3348901237116_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/j/a/jadore-christian-dior-edp-spray-50-oz-w-3348901237116_1.jpg?width=546&height=546', 'https://compraperfumesoriginales.com/product-images/jadore-3348901237116.png', 'https://compraperfumesoriginales.com/product-images/jadore-3348901237116-6184.png']::text[], 'https://www.jomashop.com/christian-dior-fragrances-jades5-5-0oz.html', 184.29, 246.99, 'Llévalo con reloj de oro claro, vestido marfil y tacones nude para una elegancia clásica.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-1e4d84f905c4', 'mp-474b2526c36a', 'mp-49e760656023']::text[], 'Para una noche elegante, la camisa satinada, los loafers de terciopelo y el reloj con oro envejecido construyen una presencia pulida. El perfume es un floral intenso y refinado, ideal para una cena formal o salida nocturna.', 'noche', ARRAY['mp-270a92a68fd4', 'mp-5794efa186cc', 'mp-87c1eb6527f0']::text[], 'Para una noche elegante, el vestido de punto, las mules texturizadas y el reloj con cristales logran un equilibrio sofisticado. El perfume aporta un floral opulento y seductor, perfecto para cena o gala.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-56139b744bbc', 'theoutnet', 'ton-1647597318428312', 'Alaina Twill Trimmed Grain de Poudre Wool Straight Leg Pants', 'Ralph Lauren', 'clothing', 'women', 'Pantalón de lana con línea recta y acabado pulido, pensado para una elegancia serena.', 'https://www.theoutnet.com/variants/images/1647597318428312/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597318428312/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597318428312/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597318428312/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597318428312/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597318428312/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ralph-lauren-collection/pants/straight-leg-pants/alaina-twill-trimmed-grain-de-poudre-wool-straight-leg-pants/1647597318428312', 184, 246.99, 'Llévalo con reloj de acero, blusa marfil, tacones negros y perfume floral discreto.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-f0129b3dfc05', 'mp-c798e1926e9d', 'mp-fa38caa36f41']::text[], 'El pantalón de lana exige líneas limpias: pumps clásicos, reloj en madreperla y un perfume de cuero elegante. Ideal para oficina o reuniones formales; la fragancia aporta un fondo intenso, pulido y distinguido.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-362cba4998a2', 'theoutnet', 'ton-46376663163097793', 'Striped Cotton And Linen Blend Jersey t Shirt', 'Orlebar Brown', 'clothing', 'men', 'Camiseta de algodón y lino, ligera y refinada en su sencillez.', 'https://www.theoutnet.com/variants/images/46376663163097793/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163097793/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097793/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097793/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097793/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/t-shirts/striped-cotton-and-linen-blend-jersey-t-shirt/46376663163097793', 185, 247.99, 'Combínala con reloj de acero, perfume cítrico y pantalón beige con mocasines blancos o crema.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-162803429493', 'mp-db2b986478c3', 'mp-37af76f7012d']::text[], 'La camiseta de lino rayada se lleva mejor con sandalias limpias y un reloj cronógrafo azul, perfecto para días cálidos. The Last Day Of Summer suma un aire cítrico-verde, fresco y vacacional.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d9fcaa470913', 'theoutnet', 'ton-46376663162956978', 'Horton Jacquard Knit Silk And Cotton Blend Polo Shirt', 'Orlebar Brown', 'clothing', 'men', 'Polo de seda y algodón con textura sutil y porte distinguido.', 'https://www.theoutnet.com/variants/images/46376663162956978/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162956978/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162956978/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162956978/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162956978/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162956978/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/polo-shirts/horton-jacquard-knit-silk-and-cotton-blend-polo-shirt/46376663162956978', 186, 248.99, 'Úsalo con reloj de brazalete fino, perfume amaderado y pantalón gris con loafers de ante.', 'https://images.stockcake.com/public/e/f/1/ef1cb030-ed89-4a00-af5d-cf1485e9e655_large/elegant-men-s-fashion-stockcake.jpg', ARRAY['mp-ccd7e4d707b6', 'mp-a057942bba4c', 'mp-ea2cb2e893b0']::text[], 'El polo de punto eleva un look smart casual con brogues, reloj champagne y un perfume especiado. Scandal Elixir aporta calor ambarado y presencia nocturna, sin romper la sobriedad del conjunto.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_no