INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-99cf05ce2452', 'theoutnet', 'ton-46376663163100145', 'Shanklin Cotton Poplin Shirt', 'Orlebar Brown', 'clothing', 'men', 'Camisa popelina nítida, sobria y precisa para vestir con aplomo.', 'https://www.theoutnet.com/variants/images/46376663163100145/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163100145/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100145/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100145/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100145/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100145/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/shanklin-cotton-poplin-shirt/46376663163100145', 186, 248.99, 'Acompáñala con reloj clásico, fragancia limpia y pantalón navy con derby negros o mocasines.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-7795ae7c1d60', 'mp-c375faf076fd', 'mp-4520d6ec87f1']::text[], 'Para la oficina, el polo de algodón funciona con loafers limpios y un reloj clásico de acero. El perfume suma un vetiver fresco y elegante, sobrio y profesional, ideal para días de trabajo con estilo relajado.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.rec