INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-06e2a90e79c5', 'jomashop', 'CZBN0231-01L', 'Citizen Promaster Dive Digital Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Reloj de buceo azul con energía náutica y resistencia para días dinámicos.', 'https://citizenwatch.widen.net/content/gmwy8btt9k/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/gmwy8btt9k/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/b8mmhjtr67/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/85ofc9wrvy/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iv1z6lnskv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-digital-blue-dial-mens-watch-bn023101l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-digital-blue-dial-mens-watch-bn023101l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-digital-blue-dial-mens-watch-bn023101l_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-dive-digital-blue-dial-mens-watch-bn0231-01l.html', 187.25, 249.99, 'Úsalo con polo blanco, bermudas caqui, sneakers náuticas y perfume acuático fresco.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-1957de84ee3b', 'mp-e518f29b87d4', 'mp-605a39d82c0f']::text[], 'Para un look deportivo y casual, el hoodie técnico, las sneakers ligeras y el reloj de buceo se sienten prácticos y modernos. El perfume añade un frescor aromático limpio, perfecto para un día activo o de fin de semana.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1e81c2039c6b', 'theoutnet', 'ton-1647597277196178', 'Striped Stretch Jacquard Leggings', 'Balmain', 'clothing', 'women', 'Legging de jacquard con rayas que afina la silueta y aporta dramatismo contemporáneo.', 'https://www.theoutnet.com/variants/images/1647597277196178/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597277196178/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597277196178/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597277196178/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597277196178/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597277196178/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/pants/leggings/striped-stretch-jacquard-leggings/1647597277196178', 187, 249.99, 'Combínalo con reloj metálico, blazer negro, botines de cuero y perfume ambarado elegante.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-95ac9c8c22b8', 'mp-b92296fdc3b1', 'mp-610cfd98812d']::text[], 'Para la oficina con salida de noche, las leggings estructuradas, los pumps clásicos y el reloj azul crean una silueta elegante y segura. El perfume aporta un acorde dulce y potente, ideal para una jornada que termina en cena.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, in