INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-610cfd98812d', 'jomashop', 'Z-SYGWJ', 'Jean Paul Gaultier Ladies Scandal Elixir Parfum 2.7 oz', 'Jean Paul Gaultier', 'perfume', 'women', 'Elixir sensual y envolvente, pensado para una firma nocturna.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-ladies-scandal-elixir-parfum-27-oz-fragrances-8435415113960.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-ladies-scandal-elixir-parfum-27-oz-fragrances-8435415113960.jpg', 'https://cdn.notinoimg.com/detail_main_lq/jean-paul-gaultier/8435415113960_02-o/scandal-elixir___251218.jpg', 'https://cdn.notinoimg.com/detail_main_hq/jean-paul-gaultier/8435415113960_03/scandal-elixir___251218.jpg']::text[], 'https://www.jomashop.com/jean-paul-gaultier-ladies-scandal-elixir-parfum-2-7-oz-fragrances-8435415113960.html', 188.06, 250.99, 'Combínalo con reloj dorado, vestido satinado oscuro y sandalias finas para un impacto elegante.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-33c53e7b9d78', 'mp-95ac9c8c22b8', 'mp-f4871962fdc0']::text[], 'Para una noche elegante, el vestido de punto, los pumps y el reloj nacarado equilibran sensualidad y clase. El perfume es dulce, ambarado y envolvente; perfecto para una cena, cóctel o evento especial.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_not