INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6ddcf5d64d8b', 'theoutnet', 'ton-46376663162955342', 'Horton Cotton Polo Shirt', 'Orlebar Brown', 'clothing', 'men', 'Polo de algodón limpio y atemporal, de líneas discretas.', 'https://www.theoutnet.com/variants/images/46376663162955342/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162955342/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162955342/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162955342/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162955342/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162955342/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/polo-shirts/horton-cotton-polo-shirt/46376663162955342', 188, 250.99, 'Llévalo con reloj de acero, perfume fresco y pantalón azul marino con mocasines de cuero.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-ccd7e4d707b6', 'mp-a057942bba4c', 'mp-cf2b71c1d9e8']::text[], 'Para un casual pulido, el polo, los brogues y el reloj dorado mantienen una línea elegante sin rigidez. El perfume aporta un carácter fresco y aromático, ideal para almuerzos, reuniones informales o fines de semana en la ciudad.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.r