INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f4871962fdc0', 'jomashop', 'CZEW1670-59D', 'Citizen Silhouette Eco-Drive Mother of Pearl Dial Ladies Watch', 'Citizen', 'watch', 'women', 'Esfera de nácar con brillo tenue y líneas femeninas para una elegancia discreta.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-eco-drive-mother-of-pearl-dial-stainless-steel-ladies-watch-ew1670-59d.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-eco-drive-mother-of-pearl-dial-stainless-steel-ladies-watch-ew1670-59d.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-eco-drive-mother-of-pearl-dial-stainless-steel-ladies-watch-ew1670-59d_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-eco-drive-mother-of-pearl-dial-stainless-steel-ladies-watch-ew1670-59d_3.jpg', 'https://i5.walmartimages.com/seo/CITIZEN-Women-s-EW1670-59D-Silver-Stainless-Steel-Eco-Drive-Fashion-Watch_68da53a6-f66e-4a15-ae5e-9366e1dd8086.814361a77b6b9853cf979affc1674e8f.jpeg', 'https://s.turbifycdn.com/aah/yhst-92803816272180/citizen-ew1670-59d-silhouette-ladies-quartz-watch-43.jpg']::text[], 'https://www.jomashop.com/citizen-watch-ew1670-59d.html', 189.05, 251.99, 'Llévalo con blusa crema, falda midi beige, mocasines y perfume floral limpio.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-af985f5371c7', 'mp-f9f99f3e6118', 'mp-42dd8d4c10ba']::text[], 'Para un lujo silencioso impecable, los pantalones de lana, los pumps de acabado refinado y el perfume de cuero suave construyen una elegancia serena. Ideal para oficina premium o cenas discretas con presencia impecable.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3f497a8f0e15', 'jomashop', 'CZCA0648-09L', 'Citizen Brycen Eco-Drive Chronograph Men''s Watch', 'Citizen', 'watch', 'men', 'Cronógrafo azul de espíritu deportivo, con presencia funcional y toque distinguido.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-brycen-eco-drive-chronograph-men_s-watch-ca0648-09l.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-brycen-eco-drive-chronograph-men_s-watch-ca0648-09l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-brycen-eco-drive-chronograph-men_s-watch-ca0648-09l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-brycen-eco-drive-chronograph-men_s-watch-ca0648-09l_3.jpg', 'https://dvdbarato.es/265848-thickbox_default/reloj-hombre-citizen-ecodrive-brycen-ca0648-09l-44mm-dial-azul-correa-de-cuero-taquimetro-100m.jpg', 'https://cdn.vuanhwatch.com/media/products/20012/dong-ho-citizen-brycen-eco-drive-chronograph-men-s-watch-ca0648-09l-606a97adc2f47-05042021115301.jpg']::text[], 'https://www.jomashop.com/citizen-brycen-watch-ca0648-09l.html', 189, 251.99, 'Combínalo con camisa Oxford, jeans índigo, zapatillas de cuero y perfume cítrico aromático.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-6abb16f437af', 'mp-60727c51909d']::text[], 'Para un look deportivo y casual, la camiseta de algodón, las sneakers ligeras y el cronógrafo azul se ven actuales y funcionales. El perfume aporta una frescura aromática intensa, perfecta para fines de semana o planes activos.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4852550c74a2', 'jomashop', 'Z-VJGR9', 'Dolce and Gabbana Unisex Velvet Black Patchouli EDP Spray 3.4 oz', 'Dolce & Gabbana', 'perfume', 'unisex', 'Patchouli oscuro y aterciopelado con una profundidad elegante.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/o/dolce-and-gabbana-unisex-velvet-black-patchouli-edp-spray-34-oz-fragrances-8054754400007.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/o/dolce-and-gabbana-unisex-velvet-black-patchouli-edp-spray-34-oz-fragrances-8054754400007.jpg', 'https://cdn.beymen.com/mnresize/596/830/productimages/kxrnmjz4.i1u_IMG_02_8054754400007.jpg', 'https://fredrikoglouisa.no/wp-content/uploads/2025/04/8054754400007_3.jpg']::text[], 'https://www.jomashop.com/dolce-and-gabbana-unisex-velvet-black-patchouli-edp-spray-3-4-oz-fragrances-8054754400007.html', 188.99, 251.99, 'Úsalo con reloj negro, blazer de lana y zapatos de cuero pulido para un lujo silencioso.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-98496652d515']::text[], 'Para una noche elegante, la camisa satinada, los loafers de terciopelo y el reloj dorado refuerzan el carácter cálido del perfume. Su perfil amaderado y oscuro acompaña muy bien cenas formales o salidas nocturnas.', 'noche', ARRAY['mp-33c53e7b9d78', 'mp-9fca20b50d99', 'mp-f4871962fdc0']::text[], 'Para una noche elegante, el vestido de punto, las sandalias de ante y el perfume crean un look profundo y sofisticado. El aroma es oscuro, ambarado y terroso, ideal para cena, teatro o un evento especial.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-337d48edab34', 'jomashop', 'Z-23GFP', 'Giorgio Armani Men''s Acqua di Gio Parfum 6.8 oz', 'Giorgio Armani', 'perfume', 'men', 'Frescura mediterránea con salida luminosa y fondo elegante para un uso diario versátil.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-parfum-68-oz-fragrances-3614273954150.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-parfum-68-oz-fragrances-3614273954150.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-parfum-68-oz-fragrances-3614273954150_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-parfum-68-oz-fragrances-3614273954150_3.jpg']::text[], 'https://www.jomashop.com/giorgio-armani-mens-acqua-di-gio-parfum-6-8-oz-fragrances-3614273954150.html', 189.99, 252.99, 'Llévalo con reloj de acero, lino blanco, loafers claros y una pulsera de cuero suave.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-5971df26ccfa', 'mp-371303f8ebbb', 'mp-06e2a90e79c5']::text[], 'Para verano, los pantalones de lino, las espadrillas y el reloj de buceo logran un conjunto fresco y pulido. El perfume es marino, cítrico y luminoso, perfecto para almuerzos al aire libre o escapadas costeras.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6866e44b5cc7', 'jomashop', 'Z-XYZVJ', 'Gucci Unisex A Midnight Stroll EDP 3.4 oz', 'Gucci', 'perfume', 'unisex', 'Misteriosa y amaderada, con presencia nocturna refinada para quienes buscan un aroma sobrio e inolvidable.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-a-midnight-stroll-edp-34-oz-fragrances-3616305909329.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-a-midnight-stroll-edp-34-oz-fragrances-3616305909329.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/b3e31d40bbb1abcc90b26106659d5d3f/g/u/gucci-unisex-a-midnight-stroll-edp-34-oz-fragrances-3616305909329_7.jpg?width=800&height=800', 'https://fragrance-cosmetics.com/cdn/shop/files/MIDNIGHT33-250818113000842.jpg?v=1762391472&width=990']::text[], 'https://www.jomashop.com/gucci-unisex-a-midnight-stroll-edp-3-4-oz-fragrances-3616305909329.html', 189.99, 252.99, 'Combine con reloj negro, camisa azul marino y mocasines de cuero liso para un perfil sobrio.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-4f703db7d409', 'mp-3c75f66f94e0', 'mp-b4c472331e21']::text[], 'Para una cena íntima o un evento nocturno, estas piezas equilibran sobriedad y presencia. La camisa limpia, los loafers de terciopelo y el Seiko dorado acompañan bien este perfume ambarado y oscuro, elegante sin esfuerzo.', 'lujo-silencioso', ARRAY['mp-6ef5af9ad162', 'mp-95ac9c8c22b8', 'mp-87c1eb6527f0']::text[], 'Para una salida de noche, el skirt satinado, los pumps y el reloj con brillo crean una silueta refinada y moderna. El perfume aporta un aura ambarada, profunda y seductora, ideal para destacar con discreción.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6df6546277aa', 'theoutnet', 'ton-46376663163119496', 'Crepe Slim Leg Pants', 'Alexander McQueen', 'clothing', 'women', 'Pantalón crepé de corte limpio con caída precisa y una sofisticación de línea editorial.', 'https://www.theoutnet.com/variants/images/46376663163119496/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163119496/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163119496/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163119496/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163119496/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163119496/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/mcq-alexander-mcqueen/pants/skinny-leg-pants/crepe-slim-leg-pants/46376663163119496', 190, 252.99, 'Combínalo con reloj delgado, blusa negra, stilettos nude y perfume chipre seco.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-95ac9c8c22b8', 'mp-21f8ec52e6da', 'mp-610cfd98812d']::text[], 'Para oficina o cena elegante, el pantalón impecable gana fuerza con el cardigan texturizado, pumps limpios y un reloj delicado. El conjunto se ve pulido; el perfume suma un carácter floral-ambarado, femenino y sofisticado.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note