INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a1d6b9ffa898', 'jomashop', 'Z-7PC6G', 'Valentino Unisex Club Couture EDP Spray 3.4 oz', 'Valentino', 'perfume', 'unisex', 'Carácter festivo y moderno con una estela pulida, pensado para destacar con elegancia.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-unisex-club-couture-edp-spray-34-oz-fragrances-3614274255218.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-unisex-club-couture-edp-spray-34-oz-fragrances-3614274255218.jpg', 'https://fimgs.net/mdimg/secundar/o.119223.jpg', 'https://fimgs.net/mdimg/secundar/o.119221.jpg', 'https://www.valentino-beauty.us/dw/image/v2/AAFM_PRD/on/demandware.static/-/Sites-valentino-master-catalog/default/dw7db4ff5e/AnatomyofDreams30ml/vlt_frag_collection_launch-24_dmi_still-life_club-couture_duo_3614274255218_3614274255249_1x1_RVB_300DP.jpg?sw=1440&sh=1440&sm=cut&sfrm=jpg&q=70']::text[], 'https://www.jomashop.com/valentino-unisex-club-couture-edp-spray-3-4-oz-fragrances-3614274255218.html', 192.99, 255.99, 'Combínelo con reloj metálico oscuro, blazer negro y zapatos de cuero pulido en borgoña.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-98496652d515']::text[], 'Para una noche elegante, la camisa satinada, los loafers de terciopelo y el reloj dorado crean un gesto sofisticado. El perfume acompaña con una presencia intensa y refinada, perfecta para destacar con discreción.', 'noche', ARRAY['mp-33c53e7b9d78', 'mp-95ac9c8c22b8', 'mp-87c1eb6527f0']::text[], 'Para una cena o cóctel nocturno, el vestido de punto, los pumps y el reloj con brillo logran una elegancia moderna. El perfume deja una estela cálida y envolvente, ideal para la noche.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b4c472331e21', 'jomashop', 'SE-SNXS79', 'Seiko 5 Automatic Black Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera negra y acero limpio en un diseño versátil, sobrio y fácil de llevar.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snxs79.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snxs79.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snxs79_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snxs79_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snxs79_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snxs79k1_vthumb_1.jpg', 'https://www.jomashop.com/media/catalog/product/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snxs79.jpg', 'https://cdnstatic.creationwatches.com/products/product-images/l/SNXS79K1_LRG.webp']::text[], 'https://www.jomashop.com/seiko-automatic-mens-watch-snxs79.html', 194, 256.99, 'Llévalo con camiseta blanca, chaqueta gris, jeans rectos y perfume cítrico amaderado.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-f259885fccd2', 'mp-e886cd56a6d2', 'mp-60727c51909d']::text[], 'Para un look diario impecable, la camisa ligera, las sneakers de cuero y el Seiko negro equilibran comodidad y pulso urbano. El perfume suma una frescura limpia y atemporal, perfecta para uso cotidiano.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-88537ad017be', 'jomashop', 'CZBN0151-17L', 'Citizen Eco-Drive Promaster Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Promaster azul con carácter náutico y funcionalidad precisa para ritmo diario o escapadas.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ecodrive-promaster-blue-dial-mens-watch-bn015117l.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ecodrive-promaster-blue-dial-mens-watch-bn015117l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ecodrive-promaster-blue-dial-mens-watch-bn015117l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ecodrive-promaster-blue-dial-mens-watch-bn015117l_3.jpg', 'https://www.watchpilot.com/cdn/shop/files/CITIZEN_BN0151-17L-1_800x800.jpg?v=1738771831', 'https://images.jamtangan.com/preset:sharp/resize:fit:462:492/dpr:1.5/width:462/height:492/resize:fit/plain/https://assets.jamtangan.com/images/product/citizen/BN0151-17L/1l.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-blue-dial-mens-watch-bn0151-17l.html', 193.8, 256.99, 'Combínalo con polo celeste, chino beige, sneakers blancas y perfume marino limpio.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-1957de84ee3b', 'mp-e518f29b87d4', 'mp-c3c82fdede97']::text[], 'Para un día activo o una escapada de verano, el hoodie técnico, las sneakers y este reloj de buceo funcionan con naturalidad. El perfume refuerza una estela fresca, poderosa y acuática, muy masculina.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c109304a8cd3', 'jomashop', 'CZNY0040-17L', 'Citizen Promaster Sea Automatic Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Reloj de buceo con presencia intensa y espíritu profesional para un estilo decidido.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-sea-automatic-blue-dial-mens-watch-ny004017l.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-sea-automatic-blue-dial-mens-watch-ny004017l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-sea-automatic-blue-dial-mens-watch-ny004017l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-sea-automatic-blue-dial-mens-watch-ny004017l_3.jpg', 'https://cdn.vuahanghieu.com/unsafe/0x0/left/top/smart/filters:quality(90)/https://admin.vuahanghieu.com/upload/news/content/2024/02/dong-ho-nam-citizen-promaster-sea-automatic-blue-dial-men-s-watch-ny0040-17l-mau-xanh-navy1-jpg-1707190274-06022024103114.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/o/p/open-box-citizen-promaster-sea-automatic-blue-dial-mens-watch-ny004017l_3.jpg?width=546&height=546', 'https://assets.jamtangan.com/images/product/citizen/NY0040-17L/1m.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-sea-automatic-blue-dial-mens-watch-ny0040-17l.html', 193.8, 256.99, 'Úsalo con jersey negro, pantalón técnico, botas oscuras y perfume especiado amaderado.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-5e366e01c3aa']::text[], 'Para una salida nocturna junto al mar, la camisa satinada, los loafers de terciopelo y el reloj de buceo crean contraste elegante. El perfume añade un carácter intenso, sensual y mediterráneo, ideal para la noche.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2116186a3093', 'theoutnet', 'ton-46376663163100042', 'Travis Printed Pique Shirt', 'Orlebar Brown', 'clothing', 'men', 'Tejido piqué y estampado expresivo para vestir con frescura y estilo junto al mar.', 'https://www.theoutnet.com/variants/images/46376663163100042/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163100042/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100042/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100042/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100042/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100042/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/travis-printed-pique-shirt/46376663163100042', 194, 256.99, 'Llévelo con reloj nácar o acero, shorts beige y mocasines claros para un aire relajado.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-371303f8ebbb', 'mp-88537ad017be', 'mp-0de6cc427e14']::text[], 'Para un día de verano en Lima: espadrilles de lino, reloj azul limpio y Acqua di Gio aportan frescura marina y elegancia relajada. El conjunto mantiene un lujo discreto, ideal para almuerzos frente al mar o escapadas urbanas.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6371b694236b', 'theoutnet', 'ton-46376663163113006', 'Phil Lyocell Linen And Cotton Blend Drawstring Shorts', 'Officine Générale', 'clothing', 'men', 'Corte ligero y textura suave para un descanso elegante con silueta depurada.', 'https://www.theoutnet.com/variants/images/46376663163113006/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163113006/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163113006/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163113006/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163113006/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163113006/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/officine-generale/shorts/casual-shorts/phil-lyocell-linen-and-cotton-blend-drawstring-shorts/46376663163113006', 194, 256.99, 'Combínelos con reloj de acero, camisa de lino blanca y sandalias o zapatillas en crema.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-32f83814872c', 'mp-b4c472331e21', 'mp-65d98c5ac518']::text[], 'Shorts impecables con espadrilles de gamuza, reloj sobrio y Cedrat de Diamante para un carácter cítrico y refinado. Perfecto para fines de semana, paseos o un brunch de verano con un aire pulido y sin esfuerzo.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=