INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7949c2b35fc6', 'jomashop', 'Z-ACPCB', 'Gucci The Alchemists Garden A Song For The Rose Eau De Parfum 3.4 oz', 'Gucci', 'perfume', 'unisex', 'Rosa de jardín con carácter artístico, delicada y sofisticada en su expresión.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-the-alchemists-garden-a-song-for-the-rose-eau-de-parfum-34-oz-3614227767980.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-the-alchemists-garden-a-song-for-the-rose-eau-de-parfum-34-oz-3614227767980.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-the-alchemists-garden-a-song-for-the-rose-eau-de-parfum-34-oz-3614227767980_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-the-alchemists-garden-a-song-for-the-rose-eau-de-parfum-34-oz-3614227767980_7.jpg', 'https://www.atticadps.gr/images/h1080/1/jpg/files/products/3614227767980/30.jpg', 'https://www.faces.ae/dw/image/v2/BJSM_PRD/on/demandware.static/-/Sites-faces-master-catalog/default/dwc01fe523/product/3614227767980_4/3614227767980_4.jpg?sw=800&sh=800', 'https://shopatshams.com.pk/cdn/shop/products/3614227767980_1024x1024.jpg?v=1701147944']::text[], 'https://www.jomashop.com/gucci-the-alchemists-garden-a-song-for-the-rose-eau-de-parfum-100ml-3614227767980.html', 194.74, 257.99, 'Acompáñelo con reloj fino, seda marfil y zapatos nude o loafers rosados muy suaves.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-4f703db7d409', 'mp-9e04bde41b3e', 'mp-23af6e30e1cc']::text[], 'Sastrería fluida, loafers pulidos y un reloj Presage crean una presencia serena y precisa. Acompaña la rosa del perfume con una salida fresca y un fondo sofisticado, perfecto para cena o evento nocturno elegante.', 'elegante', ARRAY['mp-d04ffafba9a6', 'mp-f9f99f3e6118', 'mp-217a0ab70ad2']::text[], 'El vestido midi, los pumps y un reloj madre perla forman un conjunto refinado y femenino. La rosa del perfume suma un velo floral limpio, ideal para cena, cóctel o una noche especial con elegancia contenida.', 'elegante') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-227dea13a49b', 'jomashop', 'Y-159745', 'Xerjoff Unisex 1861 Naxos EDP Spray 3.4 oz', 'Xerjoff', 'perfume', 'unisex', 'Oriental de miel y tabaco con profundidad cálida y estela refinada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-1861-naxos-edp-spray-3-4-oz-8033488155070.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-1861-naxos-edp-spray-3-4-oz-8033488155070.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-1861-naxos-edp-spray-34-oz-8033488155070_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-1861-naxos-edp-spray-34-oz-8033488155070_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-1861-naxos-edp-spray-34-oz-8033488155070_7.jpg', 'https://www.alluringauras.com/wp-content/uploads/2024/07/8033488155070-1.jpg', 'https://cdn.myikas.com/images/f0784d0b-4183-47e6-9fe0-9ab65cca0587/7eefbb5f-d440-4464-b9fe-590c073a7fd8/1080/0709001254-img-01-8033488155070.jpg']::text[], 'https://www.jomashop.com/xerjoff-unisex-1861-naxos-edp-spray-3-4-oz-fragrances-8033488155070.html', 195, 257.99, 'Acompáñalo con reloj clásico, blazer oscuro, camisa crema y zapatos de cuero pulido.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-572e6daacaab']::text[], 'La camisa satinada, loafers de terciopelo y el toque cálido de Naxos construyen un look nocturno, elegante y magnético. Perfecto para cena o bar sofisticado, con un perfil dulce-especiado y muy envolvente.', 'noche', ARRAY['mp-33c53e7b9d78', 'mp-8b8b764da74e', 'mp-87c1eb6527f0']::text[], 'El vestido de punto, sandalias de impacto y un reloj delicado equilibran sensualidad y pulcritud. Naxos aporta miel, tabaco suave y cítricos cálidos; ideal para cena, cóctel o una noche elegante.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-acd803b7103a', 'jomashop', 'Z-T28PP', 'Prada Unisex Mirages Soleil au Zenith EDP Spray 3.4 oz', 'Prada', 'perfume', 'unisex', 'Brillante y solar, evoca una frescura sofisticada con aire luminoso y moderno.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-unisex-mirages-soleil-au-zenith-edp-spray-34-oz-fragrances-3614274113488.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/p/r/prada-unisex-mirages-soleil-au-zenith-edp-spray-34-oz-fragrances-3614274113488.jpg', 'https://www.perfumewear.com/cdn/shop/products/PRADA_OLFACTORIES_ZENITH_CLOSE-UP1_800x.jpg?v=1676261757', 'https://www.atticadps.gr/images/h1080/2/jpg/files/products/3614274113488/4.jpg']::text[], 'https://www.jomashop.com/prada-unisex-soleil-au-zenith-edp-spray-3-4-oz-fragrances-3614274113488.html', 197.59, 260.99, 'Úselo con reloj de acero pulido, lino arena y mocasines blancos o camel.', 'https://morningkoffee.com/wp-content/uploads/2025/05/Comfy-summer-outfit-Tote-bag-@bonheur-.linenclothing-linenoutfit-summerstyles-bonheurbag-birkenstocks-pinstripes-linenshirt-linenpants-totebag-canvasbag-casualoutfit-summerlooks.jpg', ARRAY['mp-b5910205a035', 'mp-32f83814872c', 'mp-d6955ecf2eee']::text[], 'Camisa ligera, espadrilles refinadas y un reloj azul sobrio sostienen un verano de lujo silencioso. Soleil au Zenith refuerza la sensación con un brillo solar limpio, ideal para almuerzos, terrazas y viajes.', 'lujo-silencioso', ARRAY['mp-eb14c8e1c046', 'mp-771e0dce9f5f', 'mp-217a0ab70ad2']::text[], 'El tank tejido, ballet flats y un reloj nacarado crean una elegancia fresca y discreta. El perfume suma un acorde solar limpio, perfecto para días cálidos, almuerzos o escapadas con estética serena.', 'lujo-silencioso') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-572e6daacaab', 'jomashop', 'SE-SNK574', 'Seiko 5 Automatic Gold Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Oro discreto y esfera limpia en una pieza clásica con encanto vintage japonés.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-gold-dial-mens-watch-snk574j1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-gold-dial-mens-watch-snk574j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-gold-dial-mens-watch-snk574j1_2.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Automatic-Gold-Dial-Men-s-Watch-SNK574J1_e104d1f5-a18e-47b2-b2aa-7559fdf1034a.c6956d376557327533fed7b9ece0618f.jpeg', 'https://watchesqatar.com/cdn/shop/products/seiko-snk574j1_1_1024x.jpg?v=1669365693', 'https://cdn2.jomashop.com/media/catalog/product/o/p/open-box-seiko-5-automatic-gold-dial-mens-watch-snk574j1.jpg', 'https://www.skywatches.com.sg/cdn/shop/files/snk574j1-2.jpg?v=1685039597&width=550', 'https://www.skywatches.com.sg/cdn/shop/files/snk574j1-1.jpg?v=1685039569&width=550']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snk574j1.html', 198.55, 261.99, 'Combínalo con saco azul, camisa blanca, pantalón gris y perfume amaderado suave.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4f703db7d409', 'mp-a1a9c18f6ebe', 'mp-40dd2be6dd83']::text[], 'Una camisa de lyocell, penny loafers y vetiver moderno elevan el reloj dorado con discreción. Ideal para oficina o cena sobria: el look es limpio, clásico y muy bien medido en tonos cálidos.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f51733480d81', 'jomashop', 'CZNY0086-16L', 'Citizen Promaster Automatic Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Promaster azul de líneas robustas, pensado para un uso activo con estilo contenido.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-automatic-blue-dial-mens-watch-ny008616l.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-automatic-blue-dial-mens-watch-ny008616l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-automatic-blue-dial-mens-watch-ny008616l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-automatic-blue-dial-mens-watch-ny008616l_3.jpg', 'https://s.turbifycdn.com/aah/yhst-92803816272180/citizen-ny0086-16l-promaster-mens-automatic-watch-16.jpg', 'https://images.jamtangan.com/preset:sharp/resize:fit:462:492/dpr:1.5/width:462/height:492/resize:fit/plain/https://assets.jamtangan.com/images/product/citizen/NY0086-16L/DETAIL.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-automatic-blue-dial-mens-watch-ny0086-16l.html', 198.55, 261.99, 'Llévalo con camiseta técnica, pantalón beige, zapatillas marinas y perfume acuático fresco.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-1957de84ee3b', 'mp-e518f29b87d4', 'mp-605a39d82c0f']::text[], 'Hoodie técnico, sneakers ligeras y Luna Rossa Carbon crean un conjunto activo y actual. La fragancia es fresca, aromática y ligeramente amaderada; perfecta para entreno urbano, fin de semana o un look sporty casual.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d6955ecf2eee', 'jomashop', 'CZBM7334-58L', 'Citizen Corso Eco-Drive Blue Dial Two-tone Men''s Watch', 'Citizen', 'watch', 'men', 'Dos tonos y esfera azul en un reloj sobrio que acompaña jornadas pulidas.', 'https://citizenwatch.widen.net/content/gp6bbhod3w/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/gp6bbhod3w/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/bgriettjq9/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/u6ccas8eqz/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-corso-eco-drive-blue-dial-two-tone-stainless-steel-men_s-watch-bm7334-58l_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-corso-eco-drive-blue-dial-two-tone-stainless-steel-men_s-watch-bm7334-58l_2_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-corso-eco-drive-blue-dial-two-tone-stainless-steel-men_s-watch-bm7334-58l_3_1.jpg']::text[], 'https://www.jomashop.com/citizen-watch-bm7334-58l.html', 198.55, 261.99, 'Combínalo con traje gris claro, camisa celeste, oxford marrones y perfume cítrico amaderado.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-10e143d19f46', 'mp-c680203f6394', 'mp-4520d6ec87f1']::text[], 'Camisa de algodón, loafers de ante y Grey Vetiver acompañan con sobriedad el reloj bicolor. Un look de oficina impecable, con perfume seco, limpio y elegante; transmite profesionalismo sin rigidez.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-87c1eb6527f0', 'jomashop', 'CZEW2340-58A', 'Citizen Silhouette Crystal Eco-Drive Ladies Watch', 'Citizen', 'watch', 'women', 'Cristales sutiles y esfera clara en una pieza femenina, luminosa y refinada.', 'https://citizenwatch.widen.net/content/vzn0kw1uis/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/vzn0kw1uis/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/wh3hedbkby/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/7wenlo9qqc/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-crystal-ladies-watch-ew2340-58a.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-crystal-ladies-watch-ew2340-58a_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-silhouette-crystal-ladies-watch-ew2340-58a_3.jpg']::text[], 'https://www.jomashop.com/citizen-watch-ew2340-58a.html', 199.49, 261.99, 'Llévalo con vestido midi marfil, tacones nude, bolso estructurado y perfume floral limpio.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-37dd49d175c3', 'mp-771e0dce9f5f', 'mp-4c1e18349ce0']::text[], 'El brillo del reloj acompaña la falda midi, ballerinas y la faceta floral del perfume para un look casual refinado. Ideal para día, té o cita informal; femenino y luminoso.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1e7075d60425', 'jomashop', 'Y-A5LP2', 'Gucci Ladies Guilty Absolu de Parfum Parfum 2.03 oz', 'Gucci', 'perfume', 'women', 'Intensa y envolvente, con un aura sofisticada para noches de presencia segura.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-ladies-guilty-absolu-de-parfum-parfum-203-oz-fragrances-3616305931177.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-ladies-guilty-absolu-de-parfum-parfum-203-oz-fragrances-3616305931177.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-ladies-guilty-absolu-de-parfum-parfum-203-oz-fragrances-3616305931177_7.jpg', 'https://mazzolari.com/cdn/shop/files/3616305931177_2223c501-c015-4ed1-bd08-028ddf9db980.jpg?v=1765465394&width=1500', 'https://cdn.notinoimg.com/detail_main_mq/gucci/3616305931177_03-o/guilty-absolu-de-parfum___250825.jpg', 'https://cdn.notinoimg.com/social/gucci/3616305931177_01-o/guilty-absolu-de-parfum___250825.jpg']::text[], 'https://www.jomashop.com/gucci-ladies-guilty-absolu-de-perfume-parfum-2-03-oz-fragrances-3616305931177.html', 198.84, 261.99, 'Llévelo con reloj negro, vestido de terciopelo y tacones altos en tono vino o negro.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-33c53e7b9d78', 'mp-95ac9c8c22b8', 'mp-21f8ec52e6da']::text[], 'El vestido midi, pumps y un reloj con diamantes enmarcan una noche elegante y femenina. Guilty Absolu aporta intensidad floral y moderna, ideal para cena, cóctel o una ocasión especial.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-df895bef62df', 'theoutnet', 'ton-46376663163111962', 'Marne Fil Coupe Cotton Blend Shirt', 'Orlebar Brown', 'clothing', 'men', 'Textura fil coupé y perfil ligero para un vestir relajado con detalle sutil.', 'https://www.theoutnet.com/variants/images/46376663163111962/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163111962/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111962/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111962/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111962/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111962/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/marne-fil-coupe-cotton-blend-shirt/46376663163111962', 199, 261.99, 'Combínela con reloj de acero, pantalón crudo y mocasines de ante en tabaco.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-371303f8ebbb', 'mp-0de6cc427e14', 'mp-5744d9813fec']::text[], 'La camisa de algodón, espadrilles y Acqua di Gio dan un verano relajado pero pulido. El resultado es fresco, limpio y versátil, perfecto para almuerzos, viajes o un fin de semana junto al mar.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=