INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-420b79f56ab3', 'jomashop', 'CZAW1147-52L', 'Citizen WDR Eco-Drive Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Esfera azul y perfil limpio en un diseño versátil para rutina y trabajo.', 'https://citizenwatch.widen.net/content/lu7ptubmc1/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/lu7ptubmc1/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/knmgeix8kg/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/ke5u9jsi6v/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/23uiq6jwgh/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-wdr-eco-drive-blue-dial-men_s-watch-aw1147-52l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-wdr-eco-drive-blue-dial-men_s-watch-aw1147-52l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-wdr-eco-drive-blue-dial-men_s-watch-aw1147-52l_3.jpg']::text[], 'https://www.jomashop.com/citizen-wdr-watch-aw1147-52l.html', 199.5, 262.99, 'Combínalo con reloj de acero, camisa azul claro, pantalón gris y derby marrones.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-99cf05ce2452', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'Camisa popelina, mocasines pulidos y Grey Vetiver crean un conjunto sobrio y moderno para oficina. El azul del reloj aporta frescura sin romper la discreción; ideal para Lima, todo el año.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c3c82fdede97', 'jomashop', 'COS-SVGMES68', 'Dior Men''s Sauvage EDP Spray 6.8 oz', 'Dior', 'perfume', 'men', 'Aromático y incisivo, con una salida intensa que deja una impresión clara.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-mens-sauvage-edp-spray-6-8-oz-fragrances-3348901428545.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-mens-sauvage-edp-spray-6-8-oz-fragrances-3348901428545.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-mens-sauvage-edp-spray-68-oz-fragrances-3348901428545_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-mens-sauvage-edp-spray-68-oz-fragrances-3348901428545_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/i/dior-mens-sauvage-edp-spray-68-oz-fragrances-3348901428545_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/b3e31d40bbb1abcc90b26106659d5d3f/d/i/dior-mens-sauvage-edp-spray-68-oz-tester-fragrances-t3348901428545.jpg?width=800&height=800', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/s/a/sauvage-christian-dior-edp-spray-68-oz-200-ml-m-3348901428545_2_1.jpg?width=546&height=546', 'https://compraperfumesoriginales.com/product-images/sauvage-classic-3348901428545-2106.png']::text[], 'https://www.jomashop.com/christian-dior-fragrances-svgmes68-6-8oz.html', 199.99, 262.99, 'Acompáñelo con reloj robusto, camiseta gris, chaqueta oscura y botas o sneakers negras.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-015d339460d4', 'mp-e518f29b87d4', 'mp-c109304a8cd3']::text[], 'Pantalón técnico, sneakers limpios y un diver azul equilibran la faceta urbana de Sauvage con un aire nocturno. Funciona muy bien para salida informal o after office, con carácter fresco, especiado y magnético.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-572ed2ab2e82', 'jomashop', 'COS-CACIES33', 'Creed Acqua Originale Iris Tubereuse / Creed EDP Spray 3.3 oz (100 ml) (w)', 'Creed', 'perfume', 'unisex', 'Iris y tuberosa en una firma delicada, femenina y sofisticada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-acqua-originale-iris-tubereuse-creed-edp-spray-33-oz-100-ml-w-3508441001466.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-acqua-originale-iris-tubereuse-creed-edp-spray-33-oz-100-ml-w-3508441001466.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-acqua-originale-iris-tubereuse-creed-edp-spray-33-oz-100-ml-w-3508441001466_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-acqua-originale-iris-tubereuse-creed-edp-spray-33-oz-100-ml-w-3508441001466_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-acqua-originale-iris-tubereuse-creed-edp-spray-33-oz-100-ml-w-3508441001466_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/b3e31d40bbb1abcc90b26106659d5d3f/o/p/open-box-creed-acqua-originale-iris-tubereuse-creed-edp-spray-33-oz-100-ml-w-3508441001466.jpg?width=800&height=800', 'https://cdn.notinoimg.com/detail_main_hq/creed/3508441001466_02-o/acqua-originale-iris-tubereuse___210108.jpg', 'https://www.perfumeprice.net/Images/3508441001466_01.jpg?resizeid=4&resizeh=1500&resizew=1500']::text[], 'https://www.jomashop.com/creed-cacies33.html', 201.86, 286.99, 'Acompáñalo con reloj plateado, vestido satinado y sandalias en tonos perla o arena.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-4f703db7d409', 'mp-a1a9c18f6ebe', 'mp-572e6daacaab']::text[], 'Camisa de lyocell, loafers sobrios y Eau Sauvage Parfum construyen un lujo silencioso impecable. El acorde cítrico-aromático del perfume acompaña muy bien una cena fina, una reunión importante o la oficina.', 'lujo-silencioso', ARRAY['mp-d04ffafba9a6', 'mp-8b8b764da74e', 'mp-3c42564cbf4d']::text[], 'Para una cena íntima o un brunch sofisticado, este conjunto en tonos suaves realza la feminidad con discreción. El perfume aporta iris aterciopelado y tuberosa limpia, elegante y luminosa, ideal para un look pulido sin exceso.', 'lujo-silencioso') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2e495b310fd2', 'jomashop', 'Z-EWWMT', 'Jean Paul Gaultier Men''s Scandal Elixir Parfum 5 oz', 'Jean Paul Gaultier', 'perfume', 'men', 'Un perfume intenso y oscuro, pensado para dejar una estela memorable.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-elixir-parfum-5-oz-fragrances-8435415114011.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/j/e/jean-paul-gaultier-mens-scandal-elixir-parfum-5-oz-fragrances-8435415114011.jpg', 'https://cdn.notinoimg.com/detail_main_hq/jean-paul-gaultier/8435415114011_02-o/scandal-pour-homme-elixir___251218.jpg', 'https://media.cosmeticexpress.com/prod-public/media/b5/03/c9/1769769326/8435415114011_werbebild_150ml_4.jpg?ts=1769769326']::text[], 'https://www.jomashop.com/jean-paul-gaultier-mens-scandal-elixir-parfum-5-oz-fragrances-8435415114011.html', 201.25, 286.99, 'Combínalo con reloj negro, chaqueta estructurada y zapatos de cuero en tono carbón.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-572e6daacaab']::text[], 'La camisa satinada, los loafers de terciopelo y el diver azul elevan Scandal Elixir con teatralidad elegante. Conjunto perfecto para noche formal; el perfume se siente dulce, ambarado y seductor.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e4d93be29211', 'jomashop', 'SE-SNKK20J1', 'Seiko 5 Automatic Gold Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Reloj Seiko de esfera dorada, clásico y sobrio para el día a día.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-gold-dial-mens-watch-snkk20j1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-gold-dial-mens-watch-snkk20j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-gold-dial-mens-watch-snkk20j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-gold-dial-mens-watch-snkk20j1_3.jpg', 'https://wp.jomla.ae/wp-content/uploads/2024/01/Seiko-Mens-5-Automatic-Gold-Dial-Stainless-Steel-Watch-Snkk20j1GSSNKK20J1.jpg']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snkk20j1.html', 203.3, 288.99, 'Úsalo con traje azul marino, camisa blanca y zapatos café oscuro; añade perfume amaderado suave.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4f703db7d409', 'mp-c680203f6394', 'mp-4520d6ec87f1']::text[], 'La camisa de lyocell, mocasines de ante y Grey Vetiver acompañan el tono dorado del reloj con refinamiento contenido. Conjunto ideal para oficina y reuniones; limpio, elegante y sin excesos.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b446d04f063c', 'jomashop', 'SE-SNKK22J1', 'Seiko 5 Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera negra y perfil limpio para una elegancia discreta y funcional.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-black-dial-mens-watch-snkk22j1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-black-dial-mens-watch-snkk22j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-black-dial-mens-watch-snkk22j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-black-dial-mens-watch-snkk22j1_3.jpg']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snkk22j1.html', 203.3, 288.99, 'Combínalo con blazer gris, pantalón de lana y mocasines negros; perfume limpio y seco.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4f703db7d409', 'mp-7795ae7c1d60', 'mp-33eb4986cc4c']::text[], 'Camisa de lyocell, mocasines clásicos y Eau Sauvage Parfum construyen una presencia pulida y serena. El reloj negro aporta contraste discreto; perfecto para oficina y cenas tempranas, con frescura cítrica y maderas limpias.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7ac8c4440ab6', 'jomashop', 'SE-SNK063', 'Seiko 5 Automatic Black Arabic Dial Stainless Steel Men''s Watch', 'Seiko', 'watch', 'men', 'Diseño automático y esfera negra con números árabes, sobrio y fácil de llevar.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snk063j5.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snk063j5.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snk063j5_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snk063j5_3.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Automatic-Black-Arabic-Dial-Stainless-Steel-Men-s-Watch-SNK063J5_626a3765-4abd-4577-8662-92c058e3685d.204e122a82c9a62372b91d3ee83a7c8c.jpeg', 'https://cdn.vuahanghieu.com/unsafe/0x900/left/top/smart/filters:quality(90)/https://admin.vuahanghieu.com/upload/product/jomashop/seiko-5-automatic-black-dial-stainless-steel-mens-watch-snk063j5.jpg', 'https://timeaccess-store.com/cdn/shop/files/SNK063J5_g.webp?v=1726127385&width=1000', 'https://watches.ae/cdn/shop/products/seiko-snk063j5_1_900x_fbe54642-b365-4c89-8c0d-7468d9c78dc2.webp?v=1676967323&width=1080']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snk063j5.html', 204, 289.99, 'Combínelo con traje gris, camisa blanca y zapatos negros lisos para un conjunto preciso.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4f703db7d409', 'mp-c680203f6394', 'mp-9c175b220b04']::text[], 'Camisa de lyocell, loafers de ante y vetiver elegante armonizan con la estética sobria del reloj negro. Un look de oficina muy Maison Privée: limpio, fino y ligeramente contemporáneo.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-fe86d6135112', 'jomashop', 'SE-SNKK38', 'Seiko 5 Automatic Gold Dial Yellow Gold-tone Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera dorada y caja metálica, con un aire clásico y distinguido.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-gold-dial-yellow-goldtone-mens-watch-snkk38j1_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-gold-dial-yellow-goldtone-mens-watch-snkk38j1_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-gold-dial-yellow-goldtone-mens-watch-snkk38j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-gold-dial-yellow-goldtone-mens-watch-snkk38j1_3.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Automatic-Gold-Dial-Yellow-Gold-tone-Men-s-Watch-SNKK38J1_040fffd1-5c49-43cb-992c-2c3519ec2159.c9732470034dfab7f6c77be39a43b758.jpeg', 'https://i5.walmartimages.com/seo/Seiko-5-Automatic-Gold-Dial-Yellow-Gold-tone-Men-s-Watch-SNKK38J1_04f83ba7-663e-4eca-ad53-bbefad0d6c2d.3441580858c6cee1d6c4ca56f1c10aaf.jpeg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/o/p/open-box-seiko-5-automatic-gold-dial-yellow-goldtone-mens-watch-snkk38j1_3.jpg?width=546&height=546']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snkk38j1.html', 204.25, 289.99, 'Llévelo con blazer azul oscuro, camisa celeste y mocasines marrón chocolate para un equilibrio elegante.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4f703db7d409', 'mp-7795ae7c1d60', 'mp-ae99e2aca74c']::text[], 'La camisa suave, los mocasines de piel y Gentleman Reserve Privée acompañan el dorado del reloj con lujo contenido. Ideal para oficina o almuerzo ejecutivo; el perfume aporta cacao, iris y maderas.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
