=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-38cbaea03658', 'theoutnet', 'ton-46376663163096307', 'Printed Woven Shirt', 'Onia', 'clothing', 'men', 'Camisa estampada de caída suave, ideal para un vestir fresco con carácter relajado.', 'https://www.theoutnet.com/variants/images/46376663163096307/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096307/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096307/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096307/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096307/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096307/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/tops/casual-shirts/printed-woven-shirt/46376663163096307', 204, 289.99, 'Combínela con reloj de acero, bermudas beige y mocasines de ante o sandalias finas.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-162803429493', 'mp-3b366b7a7eb1', 'mp-8d5bb353d59a']::text[], 'Camisa estampada, sandalias de denim y Acqua di Gio Parfum forman un verano refinado y fresco. El conjunto es ideal para Lima costera; el perfume aporta notas marinas, cítricas y limpias.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.