INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9aba8e5f2da5', 'theoutnet', 'ton-46376663163096305', 'Broderie Anglaise Shirt', 'Onia', 'clothing', 'men', 'Broderie anglaise delicado, ligero y luminoso, pensado para un estilo fresco y refinado.', 'https://www.theoutnet.com/variants/images/46376663163096305/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096305/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096305/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096305/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096305/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096305/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/tops/casual-shirts/broderie-anglaise-shirt/46376663163096305', 204, 289.99, 'Llévela con reloj pequeño, pantalón blanco y sandalias de cuero en tonos arena.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-b9b2b677d2ef', 'mp-68b8b7f85f35', 'mp-24e01ce26ae0']::text[], 'La broderie, las espadrilles y el PRX dorado crean una lectura luminosa y elegante, perfecta para verano o una cena junto al mar. Dolce Amalfi añade un carácter frutal, cítrico y sofisticado.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4f703db7d409', 'theoutnet', 'ton-46376663163096309', 'Lyocell Twill Shirt', 'Onia', 'clothing', 'men', 'Lyocell twill de línea limpia para un vestir pulido, ligero y versátil.', 'https://www.theoutnet.com/variants/images/46376663163096309/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096309/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096309/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096309/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096309/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096309/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/tops/casual-shirts/lyocell-twill-shirt/46376663163096309', 205, 290.99, 'Acompáñela con reloj de acero, pantalón sastre beige y loafers marrón oscuro o negros.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-c680203f6394', 'mp-7ac8c4440ab6', 'mp-4520d6ec87f1']::text[], 'La camisa de lyocell se integra con el reloj negro y los mocasines de ante para un uniforme sobrio y contemporáneo. Grey Vetiver remata con frescura seca y madera limpia, ideal para oficina.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1a45a0c32ec9', 'jomashop', 'Z-DWJ47', 'Versace Atelier Encens Supreme EDP Spray 3.4 oz', 'Versace', 'perfume', 'unisex', 'Incienso profundo y elegante, con una firma resinosa de aire ceremonial.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-atelier-encens-supreme-edp-spray-34-oz-fragrances-8011003863778.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/e/versace-atelier-encens-supreme-edp-spray-34-oz-fragrances-8011003863778.jpg', 'https://cdn2.jomashop.com/media/catalog/product/o/p/open-box-versace-atelier-encens-supreme-edp-spray-34-oz-fragrances-8011003863778.jpg', 'https://compraperfumesoriginales.com/product-images/atelier-encens-supreme-8011003863778.png', 'https://image-optimizer-reg.production.sephora-asia.net/eyJlZGl0cyI6eyJyZXNpemUiOnt9fX0=/images/product_images/zoom_1_Product_8011003863778-Versace-Encens-Supreme-Eau-De-Parfum-100ml_9f1ea9dd57fb7d97642d092091e63dce29f507d5_1699272117.png', 'https://fredrikoglouisa.no/wp-content/uploads/2025/03/8011003863778_3.jpg']::text[], 'https://www.jomashop.com/versace-encens-supreme-edp-spray-3-4-oz-fragrances-8011003863778.html', 205.7, 291.99, 'Combínelo con reloj oscuro, camisa negra y abrigo de lana junto a botas de cuero.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-21ad3f055628']::text[], 'Para ti, una salida nocturna pide sastrería relajada y presencia contenida. La camisa satinada, los loafers de terciopelo y el reloj equilibran lujo y sobriedad; el perfume añade incienso profundo, seco y envolvente.', 'noche', ARRAY['mp-6ef5af9ad162', 'mp-f9f99f3e6118', 'mp-8e3bd4eb7fe9']::text[], 'Para una noche especial, este look combina brillo sutil y líneas limpias. La falda satinada, los pumps y el reloj crean una silueta elegante; el perfume aporta incienso cálido, oscuro y refinado, muy envolvente.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f9ea383669ef', 'theoutnet', 'ton-46376663163111975', 'Marne Fil Coupe Cotton Blend Shirt', 'Orlebar Brown', 'clothing', 'men', 'Textura fil coupé y caída ligera para un look relajado con detalle artesanal.', 'https://www.theoutnet.com/variants/images/46376663163111975/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163111975/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111975/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111975/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111975/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111975/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/marne-fil-coupe-cotton-blend-shirt/46376663163111975', 206, 291.99, 'Úsela con reloj de acero, pantalón crudo y mocasines claros o zapatillas minimalistas.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-371303f8ebbb', 'mp-21ad3f055628', 'mp-0de6cc427e14']::text[], 'La camisa texturizada, las espadrilles y el reloj blanco construyen un look ligero y muy veraniego. Acqua di Gio Parfum aporta una estela marina y elegante, ideal para fines de semana en costa.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-21cb86406dcc', 'theoutnet', 'ton-46376663163111973', 'Printed Cotton Terry Shirt', 'Orlebar Brown', 'clothing', 'men', 'Terry suave y estampado expresivo para un estilo vacacional cómodo y sofisticado.', 'https://www.theoutnet.com/variants/images/46376663163111973/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163111973/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111973/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111973/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111973/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111973/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/printed-cotton-terry-shirt/46376663163111973', 206, 291.99, 'Combínela con reloj plateado, shorts blancos y sandalias de cuero en tono coñac.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-162803429493', 'mp-ff7ebb450c85', 'mp-8d5bb353d59a']::text[], 'La camisa de terry, sandalias y reloj negro equilibran comodidad y estilo para días cálidos. Neroli Portofino suma brillo mediterráneo, cítrico y limpio; perfecto para verano y escapadas informales.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6ef5af9ad162', 'theoutnet', 'ton-1647597342618480', 'Quilted Satin Skirt', 'Maison Margiela', 'clothing', 'women', 'Falda satinada acolchada con caída fluida y presencia sofisticada.', 'https://www.theoutnet.com/variants/images/1647597342618480/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597342618480/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597342618480/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597342618480/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597342618480/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597342618480/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/mm6-maison-margiela/skirts/knee-length-skirts/quilted-satin-skirt/1647597342618480', 207, 293.99, 'Lúcela con reloj fino, blusa de seda negra y sandalias metálicas para un tono nocturno.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-95ac9c8c22b8', 'mp-da98d2ee7fd3', 'mp-db3e96bd55d9']::text[], 'Los pumps afinan la falda satinada con elegancia silenciosa, y el PRX nácar aporta brillo contenido. Love in White envuelve el conjunto con flores blancas limpias; ideal para noche y ocasión especial.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f9bea38717c0', 'theoutnet', 'ton-46376663163069457', 'Denim Midi Skirt', 'Ralph Lauren', 'clothing', 'women', 'Falda midi denim con aire clásico y facilidad para combinar.', 'https://www.theoutnet.com/variants/images/46376663163069457/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163069457/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163069457/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163069457/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163069457/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163069457/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/polo-ralph-lauren/skirts/midi-skirts/denim-midi-skirt/46376663163069457', 207, 293.99, 'Combínala con reloj de acero, camisa blanca y mocasines beige; perfume fresco y limpio.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-2208bf601ddb', 'mp-cbf5fd94f2da', 'mp-db3e96bd55d9']::text[], 'Los loafers Ferragamo y el PRX verde suave refuerzan el minimalismo refinado de la falda denim. Love in White aporta frescura floral limpia; perfecto para día, brunch o ciudad con discreción.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_