INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d8cab3532362', 'theoutnet', 'ton-46376663163100063', 'Hibbert Printed Lyocell Shirt', 'Orlebar Brown', 'clothing', 'men', 'Lyocell fluido y estampado gráfico para un vestir ligero con presencia discreta.', 'https://www.theoutnet.com/variants/images/46376663163100063/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163100063/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100063/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100063/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100063/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100063/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/hibbert-printed-lyocell-shirt/46376663163100063', 207, 293.99, 'Acompáñela con reloj de acero, pantalón arena y mocasines o alpargatas en beige.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-e305c6bba67b', 'mp-25c7b21954be', 'mp-6a32aace5e0a']::text[], 'La camisa estampada, las sandalias de cuero y el diver azul proponen un verano sofisticado y relajado. Neroli Sauvage aporta neroli luminoso y cítricos finos, ideal para almuerzos al aire libre.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-25c7b21954be', 'jomashop', 'CZBN0168-06L', 'Citizen Promaster Dive Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Reloj de buceo azul, robusto y listo para un estilo activo.', 'https://citizenwatch.widen.net/content/aqlyyqze95/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/aqlyyqze95/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/wpnbdke16w/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iv1z6lnskv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-blue-dial-mens-watch-bn016806l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-blue-dial-mens-watch-bn016806l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-blue-dial-mens-watch-bn016806l_3.jpg', 'https://cdnstatic.creationwatches.com/products/product-images/l/BN0168-06L_LRG.webp']::text[], 'https://www.jomashop.com/citizen-promaster-dive-blue-dial-mens-watch-bn0168-06l.html', 208.05, 294.99, 'Llévalo con polo blanco, chaqueta técnica y zapatillas azul marino; perfume cítrico discreto.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-e518f29b87d4', 'mp-605a39d82c0f', 'mp-a9c08c82f70a']::text[], 'Para un look de fin de semana o playa urbana: las sneakers mantienen el aire técnico del reloj, mientras Luna Rossa Carbon aporta frescura aromática moderna, limpia y ligeramente mineral, ideal para clima cálido.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-13b71b592183', 'jomashop', 'COS-CAQES25', 'Creed Acqua Fiorentina / Creed EDP Spray 2.5 oz (w)', 'Creed', 'perfume', 'unisex', 'Salida luminosa de pera, bergamota y rosas para una estela femenina y refinada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-acqua-fiorentina-creed-edp-spray-25-oz-w-3508441104631.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-acqua-fiorentina-creed-edp-spray-25-oz-w-3508441104631.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-acqua-fiorentina-creed-edp-spray-25-oz-w-3508441104631_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-acqua-fiorentina-creed-edp-spray-25-oz-w-3508441104631_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-acqua-fiorentina-creed-edp-spray-25-oz-w-3508441104631_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-acqua-fiorentina-creed-edp-spray-25-oz-w-3508441104631_7.jpg', 'https://luxefora.com/cdn/shop/files/3508441104631raw.jpg?v=1700525212&width=2000', 'https://cdn.beymen.com/productimages/hh4a2jnt.tzw_IMG_01_3508441104631.jpg']::text[], 'https://www.jomashop.com/creed-perfume-caqes25.html', 209.99, 296.99, 'Combínalo con reloj plateado, vestido crema y sandalias nude; perfume floral suave, sin dulzor pesado.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-6f035be15849', 'mp-b9b2b677d2ef', 'mp-68b8b7f85f35']::text[], 'Para ti, un verano elegante se resuelve con lino fresco, espadrilles y un reloj sobrio en tono dorado. El perfume acompaña con una estela cítrica-floral, luminosa y limpia, perfecta para almuerzos al aire libre o viajes.', 'verano', ARRAY['mp-eccea3334d40', 'mp-ca5e6334e29b', 'mp-c798e1926e9d']::text[], 'Para una tarde de verano o un almuerzo frente al mar, este vestido fluye con naturalidad y feminidad. Las sandalias y el reloj aportan brillo discreto; el perfume se siente fresco, floral y cristalino.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8b1d23d08a7c', 'theoutnet', 'ton-46376663163060428', 'Embellished Wool Blend Straight Leg Pants', 'Versace', 'clothing', 'women', 'Pantalón de lana con apliques sutiles y silueta impecable.', 'https://www.theoutnet.com/variants/images/46376663163060428/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163060428/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163060428/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163060428/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163060428/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163060428/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/pants/straight-leg-pants/embellished-wool-blend-straight-leg-pants/46376663163060428', 210, 296.99, 'Combínalo con reloj delgado, top negro y stilettos satinados; perfume cálido y elegante.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-95ac9c8c22b8', 'mp-c798e1926e9d', 'mp-58072ada40a0']::text[], 'Los pumps afilan la silueta y el reloj nácar aporta brillo refinado sin exceso, perfecto para una cena o gala. Tuscan Leather añade un carácter cálido, cuero y especiado, muy elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-bdcc5c48a475', 'theoutnet', 'ton-1647597344086858', 'Striped Wool Sweater', 'MR P.', 'clothing', 'men', 'Lana a rayas con textura sobria, ideal para un guardarropa pulido y atemporal.', 'https://www.theoutnet.com/variants/images/1647597344086858/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597344086858/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597344086858/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597344086858/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597344086858/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597344086858/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/mr-p/knitwear/crew-neck-sweaters/striped-wool-sweater/1647597344086858', 210, 296.99, 'Llévalo con reloj acero, pantalón gris grafito, perfume amaderado y mocasines negros de líneas limpias.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-c680203f6394', 'mp-21ad3f055628', 'mp-4520d6ec87f1']::text[], 'La combinación de loafers, reloj clásico y Grey Vetiver construye una presencia sobria y precisa para oficina en invierno. El perfume es seco, limpio y amaderado, con un lujo contenido muy Maison Privée.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-60c72978d5e8', 'jomashop', 'CZEW3144-51A', 'Citizen Eco-Drive Sport White Dial Two-tone Ladies Watch', 'Citizen', 'watch', 'women', 'Reloj dos tonos con madreperla, delicado y versátil para jornadas largas.', 'https://citizenwatch.widen.net/content/fhamz3rwqq/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/fhamz3rwqq/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-sport-white-dial-two-tone-ladies-watch-ew3144-51a.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-sport-white-dial-two-tone-ladies-watch-ew3144-51a_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-sport-white-dial-two-tone-ladies-watch-ew3144-51a_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-eco-drive-sport-white-dial-two-tone-ladies-watch-ew3144-51a_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fde19e4197824625333be074956e7640/o/p/open-box-citizen-ecodrive-sport-white-dial-twotone-ladies-watch-ew314451a_2.jpg?width=546&height=546']::text[], 'https://www.jomashop.com/citizen-watch-ew3144-51a.html', 210.19, 297.99, 'Úsalo con blazer crema, camisa celeste y tacones nude; perfume floral limpio y suave.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-af985f5371c7', 'mp-08cb860e5a5a', 'mp-d3b04c599098']::text[], 'Los pantalones de lana afinan el conjunto con un aire ejecutivo y femenino, ideal para oficina. Las loafers equilibran la estética y Prada Infusion d’Iris aporta un iris limpio, suave y elegante.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8ac2c54cd43d', 'theoutnet', 'ton-46376663162971050', 'Sequin Embellished Printed Low Rise Skinny Jeans', 'Ralph Lauren', 'clothing', 'women', 'Jean ceñido con brillo sutil para una silueta llamativa.', 'https://www.theoutnet.com/variants/images/46376663162971050/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162971050/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162971050/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162971050/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162971050/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162971050/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ralph-lauren-collection/jeans/skinny-leg-jeans/sequin-embellished-printed-low-rise-skinny-jeans/46376663162971050', 211, 298.99, 'Combínalo con reloj joya, top negro y botines de tacón; perfume dulce pero sobrio.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-023029369bbc', 'mp-8e3bd4eb7fe9', 'mp-fa38caa36f41']::text[], 'Para una salida nocturna, las sandalias estilizan el denim brillante y el PRX añade un punto joya contemporáneo. Cuir Zerzura Intense aporta cuero elegante con matiz especiado y sofisticado.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5d5078b27905', 'theoutnet', 'ton-46376663163096654', 'Howell Cotton Blend Terry Jacquard Shirt', 'Orlebar Brown', 'clothing', 'men', 'Piqué jaspeado de tacto suave, perfecto para días cálidos con elegancia relajada.', 'https://www.theoutnet.com/variants/images/46376663163096654/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096654/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096654/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096654/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096654/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096654/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/casual-shirts/howell-cotton-blend-terry-jacquard-shirt/46376663163096654', 211, 298.99, 'Con reloj nácar, bermudas marfil, perfume cítrico y loafers de ante beige para un aire náutico sobrio.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-21ad3f055628', 'mp-8d5bb353d59a']::text[], 'Las espadrilles y el Seiko blanco mantienen una elegancia casual muy veraniega, sin esfuerzo. Neroli Portofino suma un frescor cítrico-aromático limpio y solar, perfecto para Lima y escapadas costeras.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EX