INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6f035be15849', 'theoutnet', 'ton-46376663163023770', 'Roberto Floral Print Linen Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Lino con print floral discreto, fresco y distinguido para escapadas soleadas.', 'https://www.theoutnet.com/variants/images/46376663163023770/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163023770/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023770/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023770/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023770/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023770/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/casual-shirts/roberto-floral-print-linen-shirt/46376663163023770', 211, 298.99, 'Acompáñalo con reloj dorado fino, pantalón blanco, perfume verde limpio y alpargatas color arena.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-371303f8ebbb', 'mp-25c7b21954be', 'mp-f1ca527ff067']::text[], 'El lino floral pide espadrilles y un reloj de buceo azul para un contraste relajado y sofisticado. Acqua di Giò Parfum aporta frescura marina y refinada, ideal para un almuerzo de verano.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-24e01ce26ae0', 'jomashop', 'Y-85959', 'Xerjoff Casamorati Unisex Dolce Amalfi EDP Spray 3.4 oz (100 ml)', 'Xerjoff', 'perfume', 'unisex', 'Cítrico gourmand con espíritu mediterráneo y brillo refinado.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-casamorati-unisex-dolce-amalfi-edp-spray-34-oz-100-ml-8033488150112.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-casamorati-unisex-dolce-amalfi-edp-spray-34-oz-100-ml-8033488150112.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-casamorati-unisex-dolce-amalfi-edp-spray-34-oz-100-ml-8033488150112_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-casamorati-unisex-dolce-amalfi-edp-spray-34-oz-100-ml-8033488150112_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-casamorati-unisex-dolce-amalfi-edp-spray-34-oz-100-ml-8033488150112_7.jpg', 'https://www.nk.se/globalassets/8033488150112.jpg?ref=E512E68854&format=jpg&quality=85']::text[], 'https://www.jomashop.com/xerjoff-casamorati-unisex-1888-dolce-amalfi-edp-spray-3-4-oz-fragrances-8033488150112.html', 212.56, 299.99, 'Acompáñalo con reloj dorado claro, lino blanco y sandalias nude para un look fresco.', 'https://morningkoffee.com/wp-content/uploads/2025/05/Comfy-summer-outfit-Tote-bag-@bonheur-.linenclothing-linenoutfit-summerstyles-bonheurbag-birkenstocks-pinstripes-linenshirt-linenpants-totebag-canvasbag-casualoutfit-summerlooks.jpg', ARRAY['mp-3f1bb37bec2f', 'mp-b9b2b677d2ef', 'mp-572e6daacaab']::text[], 'Para ti, el conjunto sugiere vacaciones elegantes: camisa de seda estampada, espadrilles y un reloj dorado. El perfume, cítrico y almizclado, acompaña con aire mediterráneo, fresco y sofisticado, ideal para días cálidos.', 'verano', ARRAY['mp-a3b7700027eb', 'mp-608588842523', 'mp-1fa42b862d9c']::text[], 'Para una escapada de verano o una comida luminosa, el vestido floral aporta movimiento y gracia. Las sandalias elevan el conjunto y el reloj suma un acento moderno; el perfume es cítrico, dulce y luminoso.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
