yling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3b366b7a7eb1', 'jomashop', 'SE-SRPJ37K1', 'Seiko 5 Sports Automatic Green Camouflage Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Camo verde y energía sport en un Seiko de carácter relajado.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-green-camouflage-dial-mens-watch-srpj37k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-green-camouflage-dial-mens-watch-srpj37k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-green-camouflage-dial-mens-watch-srpj37k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-green-camouflage-dial-mens-watch-srpj37k1_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-green-camouflage-dial-mens-watch-srpj37k1_4.jpg', 'https://www.strapseeker.com/cdn/shop/products/seikoseiko-5-sports-srpj37-srpj37k-srpj37k1-camouflage-street-style-green-dial-watch-831996.jpg?v=1706551643&width=1200', 'https://watchesofamerica.com/cdn/shop/files/seiko-5-sports-automatic-green-camouflage-dial-mens-watch-srpj37k1-910.jpg?v=1776230068&width=900', 'https://www.timeplanet.com.my/cdn/shop/files/SRPJ37K1h.png?v=1684221312&width=720']::text[], 'https://www.jomashop.com/seiko-5-sports-automatic-green-camouflage-dial-mens-watch-srpj37k1.html', 212.8, 300.99, 'Llévalo con hoodie gris, cargo verde oliva y sneakers blancas; perfume limpio y mineral.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-6abb16f437af', 'mp-60727c51909d', 'mp-1957de84ee3b']::text[], 'Las sneakers de malla y la hoodie refuerzan el carácter deportivo del reloj, ideal para fin de semana. Sauvage aporta un perfil aromático fresco, ambroxan y especiado, enérgico y reconocible.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b4deb6329f8d', 'jomashop', 'CZAT2447-01E', 'Citizen AR Eco-Drive Chronograph Black Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Cronógrafo negro de lectura clara y presencia técnica elegante.', 'https://citizenwatch.widen.net/content/bccbydowx9/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/bccbydowx9/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/s4zxuhzmq9/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/jl2qi3r3jm/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ar-ecodrive-chronograph-black-dial-mens-watch-at244701e.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ar-ecodrive-chronograph-black-dial-mens-watch-at244701e_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ar-ecodrive-chronograph-black-dial-mens-watch-at244701e_3.jpg']::text[], 'https://www.jomashop.com/citizen-ar-watch-at2447-01e.html', 212.8, 300.99, 'Combínalo con camisa azul, pantalón recto y derby negras; perfume amaderado discreto.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-ccd7e4d707b6', 'mp-4520d6ec87f1', 'mp-f6fcd13690f5']::text[], 'Las brogues y Grey Vetiver equilibran el cronógrafo con una sofisticación práctica para oficina. El look se siente limpio, urbano y pulido, con un perfume seco, vetiverado y muy profesional.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f6fcd13690f5', 'theoutnet', 'ton-46376663162995502', 'Fit 4 Miramar Denim Effect Print Cotton Blend Canvas Pants', 'Rag & Bone', 'clothing', 'men', 'Canvas con efecto denim, moderno y versátil para un look urbano refinado.', 'https://www.theoutnet.com/variants/images/46376663162995502/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162995502/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162995502/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162995502/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162995502/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162995502/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/rag-bone/pants/casual-pants/fit-4-miramar-denim-effect-print-cotton-blend-canvas-pants/46376663162995502', 213, 300.99, 'Combínalo con reloj de acero, camisa celeste, perfume amaderado suave y zapatillas blancas impecables.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-7795ae7c1d60', 'mp-28a4b97e6968', 'mp-9c175b220b04']::text[], 'Los loafers y el reloj Tsuyosa suavizan el denim técnico, creando una mezcla inteligente entre casual y oficina relajada. Elegant Vetiver aporta una frescura verde y sobria, ideal para diario.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c808cc69c0a3', 'jomashop', 'CZBM8180-03E', 'Citizen Strap Eco-Drive 180 Day-Date Men''s Watch', 'Citizen', 'watch', 'men', 'Reloj funcional y sobrio, pensado para acompañar con discreción.', 'https://citizenwatch.widen.net/content/gzoliud0hm/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/gzoliud0hm/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/rqeea2ndfy/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/menkjxay6b/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-strap-eco-drive-180-men_s-watch-bm8180-03e_5.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-strap-eco-drive-180-men_s-watch-bm8180-03e_2_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-strap-eco-drive-180-men_s-watch-bm8180-03e_3_2.jpg']::text[], 'https://www.jomashop.com/citizen-bm8180-03e.html', 214, 301.99, 'Úsalo con camisa blanca, pantalón chino beige y loafers marrón; perfume limpio y seco.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-7795ae7c1d60', 'mp-10e143d19f46', 'mp-33eb4986cc4c']::text[], 'Los loafers y la camisa estructuran un conjunto limpio y discreto, perfecto para oficina y reuniones. Eau Sauvage Parfum añade un cítrico clásico, seco y elegante, sin imponerse.', 'oficina', NULL, NULL, NULL) 