INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4a904bb98bd9', 'theoutnet', 'ton-1647597356932414', 'Studded High Rise Slim Leg Jeans', 'Balmain', 'clothing', 'women', 'Jeans slim con tachas finas y una actitud sofisticada.', 'https://www.theoutnet.com/variants/images/1647597356932414/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597356932414/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597356932414/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597356932414/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597356932414/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597356932414/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/jeans/skinny-leg-jeans/studded-high-rise-slim-leg-jeans/1647597356932414', 214, 301.99, 'Combínalos con reloj plateado, blazer negro y botines de cuero; perfume especiado suave.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-95ac9c8c22b8', 'mp-1e7075d60425', 'mp-c798e1926e9d']::text[], 'Para ti, el jean con apliques pide una noche pulida y segura. Los pumps estilizan, el perfume añade cuero suave y faceta floral oscura, y el reloj mantiene el conjunto refinado sin perder carácter.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0124525d9691', 'theoutnet', 'ton-46376663163097423', 'Frederick French Cotton Blend Terry Drawstring Shorts', 'Orlebar Brown', 'clothing', 'men', 'Short de terry con caída limpia, cómodo y pulido para climas cálidos.', 'https://www.theoutnet.com/variants/images/46376663163097423/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163097423/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097423/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097423/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097423/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097423/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/shorts/casual-shorts/frederick-french-cotton-blend-terry-drawstring-shorts/46376663163097423', 215, 303.99, 'Llévalo con reloj minimalista, camiseta blanca, perfume cítrico y mocasines de gamuza color taupe.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-69ef4764b1ae', 'mp-a3db4bdcd8a6', 'mp-6a32aace5e0a']::text[], 'Para ti, este look funciona en vacaciones o fines de semana junto al mar. Las espadrilles y el reloj azul mantienen el aire relajado, mientras el perfume aporta neroli y cítricos limpios, frescos y elegantes.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1fa42b862d9c', 'jomashop', 'SE-SRE004', 'Seiko 5 Sports White Dial Two-tone Ladies Watch', 'Seiko', 'watch', 'women', 'Seiko femenino de dos tonos con esfera blanca y encanto clásico.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-white-dial-twotone-ladies-watch-sre004k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-white-dial-twotone-ladies-watch-sre004k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-white-dial-twotone-ladies-watch-sre004k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-white-dial-twotone-ladies-watch-sre004k1_3.jpg', 'https://cliftonjewelersinc.com/wp-content/uploads/2023/09/SRE004_1.png', 'https://www.citywatches.co.za/wp-content/uploads/2023/09/SRE004K1-4.jpg', 'https://cdn11.bigcommerce.com/s-uzonwrhn18/images/stencil/2560w/products/17749/91296/SRE004__60839.1647534951.jpg?c=1', 'https://passthewatch.com/cdn/shop/files/SRE004K1_7d11bd9c-0702-4fee-aecc-485b79c95f6f_1800x1800.png?v=1710437338']::text[], 'https://www.jomashop.com/seiko-5-sports-white-dial-two-tone-ladies-watch-sre004k1.html', 217.55, 306.99, 'Acompáñalo con vestido camel, abrigo crema y flats en piel; perfume floral discreto.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-eccea3334d40', 'mp-95ac9c8c22b8', 'mp-6becc442eecf']::text[], 'Para ti, el reloj luce más con una falda midi o un vestido floral para oficina creativa o almuerzo elegante. El perfume suma un carácter floral limpio y moderno, sobrio pero femenino, ideal para diario.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-21ad3f055628', 'jomashop', 'SE-SNKP22', 'Seiko 5 Automatic White Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Seiko 5 con esfera blanca, sobrio y fiable para uso diario.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-mens-watch-snkp22j1_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-mens-watch-snkp22j1_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-mens-watch-snkp22j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-automatic-white-dial-mens-watch-snkp22j1_3.jpg', 'https://www.citywatches.co.za/wp-content/uploads/2025/05/SNKP22J1.jpg', 'https://watchzonebd.com/uploads/multiimage/SNKP22J1-1 (2)_6519cbcfce018.webp']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snkp22j1.html', 217.55, 306.99, 'Con camisa azul clara, blazer marino, perfume fresco y zapatos derby marrón oscuro para pulcritud discreta.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-10e143d19f46', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'Para ti, la combinación encaja con oficina y reuniones informales: camisa de algodón, loafers y un reloj limpio y clásico. El perfume aporta vetiver seco y pulcro, muy sobrio, perfecto para un día largo.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=E