INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-bfd2adc26426', 'jomashop', 'CZNJ0151-88Z', 'Citizen Tsuyosa Automatic Orange Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Esfera naranja vibrante con movimiento automático y estilo contemporáneo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-orange-dial-mens-watch-nj015188z.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-orange-dial-mens-watch-nj015188z.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-orange-dial-mens-watch-nj015188z_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-orange-dial-mens-watch-nj015188z_3.jpg', 'https://watchimperio.com/cdn/shop/files/NJ0151-88Z.png.thumb.png?v=1757157214&width=1445', 'https://i5.walmartimages.com/seo/Citizen-Tsuyosa-Automatic-Orange-Dial-Men-s-Watch-NJ0151-88Z_f53f20df-78f2-48be-8565-8298a3e1567a.45d814e0d0ef0b0aa02b9c8f4b505e73.jpeg', 'https://images.jamtangan.com/preset:sharp/resize:fit:462:492/dpr:1.5/width:462/height:492/resize:fit/plain/https://assets.jamtangan.com/images/product/citizen/NJ0151-88Z/1l.jpg', 'https://images.jamtangan.com/preset:sharp/resize:fit:462:492/dpr:1.5/width:462/height:492/resize:fit/plain/https://assets.jamtangan.com/images/product/citizen/NJ0151-88Z/DETAIL3.jpg']::text[], 'https://www.jomashop.com/citizen-tsuyosa-automatic-orange-dial-mens-watch-nj0151-88z.html', 217.55, 306.99, 'Combínalo con camiseta blanca, sobrecamisa denim y zapatillas grises; perfume cítrico fresco.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-68a041916a67', 'mp-6abb16f437af', 'mp-605a39d82c0f']::text[], 'Para ti, un estilo activo pero refinado se logra con camiseta premium, sneakers técnicas y un reloj vibrante. El perfume añade un carácter moderno, aromático y fresco, ideal para moverte con energía sin perder presencia.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
