INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1e4d84f905c4', 'theoutnet', 'ton-46376663163107925', 'Satin Twill Shirt', 'Jacquemus', 'clothing', 'men', 'Satén con brillo sutil y caída precisa para una silueta moderna.', 'https://www.theoutnet.com/variants/images/46376663163107925/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163107925/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107925/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107925/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107925/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107925/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jacquemus/tops/casual-shirts/satin-twill-shirt/46376663163107925', 221, 310.99, 'Con reloj fino, pantalón negro, perfume oriental sobrio y loafers de charol para una lectura nocturna limpia.', 'https://images.stockcake.com/public/e/f/1/ef1cb030-ed89-4a00-af5d-cf1485e9e655_large/elegant-men-s-fashion-stockcake.jpg', ARRAY['mp-23af6e30e1cc', 'mp-ac85563341af', 'mp-40dd2be6dd83']::text[], 'Para noche, la seda satinada pide un reloj pulido, mocasines finos y MYSLF Le Parfum: cálido, moderno y envolvente, perfecto para una cena o cóctel con presencia discreta.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, re