INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d4a1e770a01d', 'theoutnet', 'ton-46376663163024215', 'Mendes Hammered Cotton Blend Pants', 'Frescobol Carioca', 'clothing', 'men', 'Pantalón de textura artesanal, cómodo y refinado para días de sol.', 'https://www.theoutnet.com/variants/images/46376663163024215/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163024215/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163024215/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163024215/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163024215/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163024215/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/pants/casual-pants/mendes-hammered-cotton-blend-pants/46376663163024215', 222, 311.99, 'Combínalo con reloj dorado discreto, camisa de lino crudo, perfume fresco y sandalias de cuero minimalistas.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-a3db4bdcd8a6', 'mp-32f83814872c', 'mp-8d5bb353d59a']::text[], 'Para verano, estos pantalones quedan impecables con un reloj azul, espadrilles y Neroli Portofino: cítrico, luminoso y muy limpio, ideal para días cálidos y fines de semana elegantes.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_