INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-94d8574d8710', 'jomashop', 'SE-SNKN96J1', 'Seiko 5 Automatic Gold Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera dorada con presencia cálida, un reloj clásico de carácter japonés.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-gold-dial-men_s-watch-snkn96j1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-gold-dial-men_s-watch-snkn96j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-gold-dial-men_s-watch-snkn96j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-automatic-gold-dial-men_s-watch-snkn96j1_3.jpg', 'https://nicewatch.vn/wp-content/uploads/2020/11/Seiko-SNKN96J1-2.jpg']::text[], 'https://www.jomashop.com/seiko-seiko-5-watch-snkn96j1.html', 222.3, 312.99, 'Llévalo con traje azul marino, camisa blanca, perfume especiado suave y zapatos negros pulidos.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-7795ae7c1d60', 'mp-4520d6ec87f1', 'mp-10e143d19f46']::text[], 'Para oficina, el reloj dorado se equilibra con una camisa de algodón, mocasines y Grey Vetiver: un conjunto clásico, sereno y bien resuelto para verte impecable sin esfuerzo.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1f6d8f6ece9d', 'jomashop', 'CZNJ0151-53W', 'Citizen Tsuyosa Automatic Men''s Watch', 'Citizen', 'watch', 'men', 'Automático limpio y contemporáneo, con esfera blanca que aporta presencia discreta al día a día.', 'https://citizenwatch.widen.net/content/9by0yquzrd/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/9by0yquzrd/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/djcvtbbrhe/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/lvc9thcohq/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-mens-watch-nj015153w.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-mens-watch-nj015153w_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-mens-watch-nj015153w_3.jpg']::text[], 'https://www.jomashop.com/citizen-tsuyosa-automatic-mens-watch-nj0151-53w.html', 222.3, 312.99, 'Combínelo con traje azul marino, camisa blanca, zapatos café oscuro, reloj de piel lisa y perfume amaderado.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-6a03b9633ec5', 'mp-c680203f6394', 'mp-33eb4986cc4c']::text[], 'Para lujo silencioso, el Tsuyosa azul va perfecto con pantalón estructurado, mocasines y Eau Sauvage Parfum: fresco, elegante y contenido, ideal para oficina o una cena informal.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
