INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-21708b443c49', 'jomashop', 'Z-9S3YY', 'Giorgio Armani Men''s Acqua Di Gio Profondo Parfum 6.8 oz', 'Giorgio Armani', 'perfume', 'men', 'Acqua Di Gio Profondo, profundo y marino, con frescura elegante y moderna.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-profondo-parfum-6-8-oz-fragrances-3614273953672.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-profondo-parfum-6-8-oz-fragrances-3614273953672.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-profondo-parfum-68-oz-fragrances-3614273953672_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-mens-acqua-di-gio-profondo-parfum-68-oz-fragrances-3614273953672_7.jpg', 'https://compraperfumesoriginales.com/product-images/acqua-di-gio-profondo-3614273953672-9099.png']::text[], 'https://www.jomashop.com/giorgio-armani-mens-acqua-di-gio-profondo-parfum-6-8-oz-fragrances-3614273953672.html', 226.29, 316.99, 'Llévalo con reloj acero, polo azul tinta, pantalón blanco y mocasines claros para una estética limpia.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-a5ebb19a7751', 'mp-8299c3343a4d', 'mp-48e0815f97a3']::text[], 'Para un look de verano activo, este perfume acompaña shorts de lino, sandalias y un reloj de buceo; su salida acuática y limpia refuerza una vibra fresca, marina y elegante.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3db8316ceb81', 'jomashop', 'Z-UR8ND', 'Xerjoff Unisex V Soprano EDP Spray 3.4 oz', 'Xerjoff', 'perfume', 'unisex', 'Perfume intenso y refinado, con un carácter envolvente que deja una estela memorable.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-soprano-edp-spray-3-4-oz-fragrances-8033488157630.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-soprano-edp-spray-3-4-oz-fragrances-8033488157630.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-soprano-edp-spray-34-oz-fragrances-8033488157630_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-soprano-edp-spray-34-oz-fragrances-8033488157630_3.jpg', 'https://i5.walmartimages.com/seo/Xerjoff-Unisex-V-Soprano-EDP-Spray-3-4-oz-Fragrances-8033488157630_88a993fd-35dc-4061-96bc-e7d41cd93ff4.bd67a4ef0ddf48fda1750ed096d56af2.jpeg', 'https://cdn2.jomashop.com/media/catalog/product/x/e/xerjoff-unisex-soprano-edp-34-oz-tester-fragrances-t8033488157630.jpg', 'https://cdn.beymen.com/mnresize/596/830/productimages/0709001254_IMG_03_8033488157630.jpg']::text[], 'https://www.jomashop.com/xerjoff-unisex-soprano-edp-spray-3-4-oz-fragrances-8033488157630.html', 226.27, 316.99, 'Úselo con reloj metálico sobrio, sastrería negra, camisa de seda y zapatos de cuero pulido en tonos oscuros.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-c109304a8cd3']::text[], 'Para noche, este perfume brillante pide la camisa satinada, mocasines de terciopelo y un reloj retro: un conjunto elegante, sensual y sofisticado, ideal para cena o evento especial.', 'noche', ARRAY['mp-270a92a68fd4', 'mp-f9f99f3e6118', 'mp-c798e1926e9d']::text[], 'Para una noche elegante en Lima, este vestido limpio se realza con pumps delicados y un reloj madre perla. Soprano aporta flores cremosas, frutas y un velo ambarado; sofisticado, femenino y memorable.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3d7ec08426d5', 'jomashop', 'Z-NGUP6', 'Christian Dior Men''s Sauvage Parfum 6.8 oz (200 ml)', 'Dior', 'perfume', 'men', 'Sauvage Parfum, intenso y pulido, con madera y especias de gran presencia.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-mens-sauvage-parfum-6-8-oz-200-ml-3348901520065.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-mens-sauvage-parfum-6-8-oz-200-ml-3348901520065.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-mens-sauvage-parfum-68-oz-200-ml-3348901520065_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-mens-sauvage-parfum-68-oz-200-ml-3348901520065_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/h/christian-dior-mens-sauvage-parfum-68-oz-200-ml-3348901520065_7.jpg', 'https://compraperfumesoriginales.com/product-images/sauvage-classic-perfume-3348901520065.png', 'https://compraperfumesoriginales.com/product-images/sauvage-classic-perfume-3348901520065-9966.png']::text[], 'https://www.jomashop.com/christian-dior-mens-sauvage-parfum-edp-6-8-oz-fragrances-3348901520065.html', 226.58, 317.99, 'Acompáñalo con reloj oscuro, blazer marino, camisa negra y zapatos de cuero liso para una noche sobria.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-c680203f6394', 'mp-7dff9c9cea5a']::text[], 'Para hombre, un look de oficina pulcro y contemporáneo: camisa satinada, loafers de cuero y un reloj world-time. Sauvage Parfum suma bergamota, maderas y ámbar; limpio, seguro y muy refinado.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e0cbc7e720bd', 'theoutnet', 'ton-46376663163097295', 'Nicolas Cotton And Linen Blend t Shirt', 'Orlebar Brown', 'clothing', 'men', 'Camiseta de algodón y lino, esencial, limpia y muy fácil de estilizar.', 'https://www.theoutnet.com/variants/images/46376663163097295/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163097295/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097295/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097295/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097295/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097295/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/t-shirts/nicolas-cotton-and-linen-blend-t-shirt/46376663163097295', 227, 317.99, 'Con reloj plateado, pantalón piedra, perfume cítrico y zapatillas blancas para un lujo cotidiano discreto.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-337d48edab34', 'mp-94d8574d8710']::text[], 'Ideal para verano en Lima: t-shirt de lino y algodón, espadrilles ligeras y Acqua di Gio Parfum. El conjunto respira frescura, sobriedad y comodidad; perfecto para almuerzos, costa o fines de semana.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration