INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f828dda76d0c', 'theoutnet', 'ton-46376663163116870', 'Plus Pendleton Checked Button Detailed Wool Flannel Shirt', 'Maison Margiela', 'clothing', 'women', 'Camisa de franela con cuadros clásicos y caída suave, ideal para un estilo relajado y pulido.', 'https://www.theoutnet.com/variants/images/46376663163116870/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163116870/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163116870/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163116870/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163116870/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163116870/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/maison-margiela/tops/long-sleeved-tops/plus-pendleton-checked-button-detailed-wool-flannel-shirt/46376663163116870', 228, 319.99, 'Acompáñela con reloj automático discreto, jeans índigo, botas café y perfume amaderado suave.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-a817148e69da', 'mp-3c42564cbf4d', 'mp-6195e4aa6adf']::text[], 'Para mujer, la camisa de flanela gana estructura con sneakers limpias y un reloj discreto. Flying es etéreo y suave, con aire limpio; un look casual chic, perfecto para día y media estación.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd,