INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-015d339460d4', 'theoutnet', 'ton-46376663163107937', 'Ripstop Track Pants', 'Jacquemus', 'clothing', 'men', 'Track pants de ripstop con aire técnico, modernos y ligeros para movimiento urbano.', 'https://www.theoutnet.com/variants/images/46376663163107937/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163107937/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107937/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107937/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107937/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107937/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jacquemus/pants/casual-pants/ripstop-track-pants/46376663163107937', 228, 319.99, 'Combínalo con reloj deportivo limpio, camiseta blanca, perfume fresco y sneakers negras de líneas mínimas.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-e886cd56a6d2', 'mp-3240465564d7', 'mp-605a39d82c0f']::text[], 'Para hombre, el track pant funciona mejor con sneakers técnicas y reloj deportivo. Luna Rossa Carbon es fresco, aromático y ligeramente mineral; ideal para ciudad, viaje o un sábado activo con estilo.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-820eb27c1392', 'jomashop', 'CZBN0151-09L', 'Citizen Promaster Professional Diver 200 Meters Eco-Drive Men''s Watch', 'Citizen', 'watch', 'men', 'Diver solar de líneas limpias y aire náutico, hecho para una presencia funcional y sobria.', 'https://citizenwatch.widen.net/content/1wzelrcvs4/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/1wzelrcvs4/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/1rwthhisdu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/fuhwxxufki/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iv1z6lnskv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-professional-diver-200-meters-ecodrive-mens-watch-bn015109l_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-professional-diver-200-meters-ecodrive-mens-watch-bn015109l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-professional-diver-200-meters-ecodrive-mens-watch-bn015109l_3.jpg']::text[], 'https://www.jomashop.com/citizen-watch-bn0151-09l.html', 229, 320.99, 'Llévelo con polo blanco, pantalón chino beige, mocasines o sneakers limpias y perfume marino fresco.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-e886cd56a6d2', 'mp-cf2b71c1d9e8', 'mp-015d339460d4']::text[], 'Para hombre, este diver se acompaña con sneakers versátiles y un carácter náutico sobrio. Mefisto aporta cítricos, iris y almizcle: fresco, elegante y perfecto para fin de semana, playa o escapada urbana.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6f20cf2d2571', 'theoutnet', 'ton-1647597325114780', 'Greer Habotai Wide Leg Pants', 'Ralph Lauren', 'clothing', 'women', 'Pantalón de pierna ancha con caída fluida, elegante y versátil para vestir con ligereza.', 'https://www.theoutnet.com/variants/images/1647597325114780/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597325114780/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597325114780/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597325114780/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597325114780/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597325114780/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ralph-lauren-collection/pants/wide-leg-pants/greer-habotai-wide-leg-pants/1647597325114780', 229, 320.99, 'Combínelo con reloj delgado, blusa o camisa crema, sandalias de cuero y perfume floral limpio.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-023029369bbc', 'mp-217a0ab70ad2', 'mp-6becc442eecf']::text[], 'Para mujer, el pantalón amplio se eleva con slippers de líneas suaves y reloj madre perla. My Way aporta flores blancas y calidez cremosa; un conjunto elegante, ligero y muy favorecedor para oficina o almuerzo.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3f6a0c894592', 'theoutnet', 'ton-46376663163024222', 'Mid Length Swim Shorts', 'Frescobol Carioca', 'clothing', 'men', 'Swim shorts de largo medio, prácticos y limpios para días de agua y sol.', 'https://www.theoutnet.com/variants/images/46376663163024222/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163024222/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163024222/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163024222/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163024222/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163024222/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/swimwear-beachwear/swim-shorts/mid-length-swim-shorts/46376663163024222', 229, 320.99, 'Úsalos con reloj resistente, camisa de lino abierta, perfume acuático y sandalias de cuero en tono arena.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-162803429493', 'mp-5744d9813fec', 'mp-337d48edab34']::text[], 'Para hombre, el swim short se ve impecable con sandalias de cuero, reloj azul y Acqua di Gio Parfum. Fresco, acuático y limpio; perfecto para playa, piscina o un verano relajado con buen gusto.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3ab14ad06920', 'theoutnet', 'ton-46376663163024224', 'Mid Length Swim Shorts', 'Frescobol Carioca', 'clothing', 'men', 'Swim shorts de largo medio, funcionales y versátiles para un verano elegante.', 'https://www.theoutnet.com/variants/images/46376663163024224/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163024224/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163024224/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163024224/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163024224/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163024224/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/swimwear-beachwear/swim-shorts/mid-length-swim-shorts/46376663163024224', 229, 320.99, 'Combínalos con reloj minimalista, polo blanco, perfume marino y alpargatas o sliders de cuero.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-e518f29b87d4', 'mp-5744d9813fec', 'mp-0de6cc427e14']::text[], 'Para playa o resort, las sneakers ligeras suman pulso urbano sin perder frescura. El reloj diver refuerza el aire náutico y Acqua di Gio aporta un perfil acuático y limpio, ideal para clima cálido y planes informales.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3afaba491a7d', 'jomashop', 'CZBN0150-28E', 'Citizen Promaster Diver 200 Meters Eco-Drive Black Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Diver en negro de presencia firme, equilibrado entre rendimiento marino y sobriedad contemporánea.', 'https://citizenwatch.widen.net/content/t0dosari4z/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/t0dosari4z/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/zxajovf2ka/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/xtclx2z708/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iv1z6lnskv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-diver-200-meters-ecodrive-black-dial-mens-watch-bn015028e.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-diver-200-meters-ecodrive-black-dial-mens-watch-bn015028e_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-diver-200-meters-ecodrive-black-dial-mens-watch-bn015028e_3.jpg']::text[], 'https://www.jomashop.com/citizen-watch-bn0150-28e.html', 230, 321.99, 'Use reloj de acero, camiseta gris, chaqueta utilitaria, pantalón oscuro y perfume acuático sobrio.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-8ff77782c120', 'mp-e886cd56a6d2', 'mp-605a39d82c0f']::text[], 'Un conjunto técnico y sobrio para escapadas de mar o piscina. El short chino equilibra el reloj de buceo; las sneakers limpias mantienen el look depurado. Luna Rossa Carbon añade frescor aromático con toque moderno y mineral.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b6a8a4e51c1a', 'jomashop', 'Z-YWAFV', 'Yves Saint Laurent Unisex Feuille De Violette Cuir Oud 2023 EDP Spray 4.2 oz', 'Yves Saint Laurent', 'perfume', 'unisex', 'Una composición oscura y sofisticada, con matices de cuero y oud de gran carácter.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-unisex-feuille-de-violette-cuir-oud-2023-edp-spray-42-oz-fragrances-3614273893626.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-unisex-feuille-de-violette-cuir-oud-2023-edp-spray-42-oz-fragrances-3614273893626.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/y/v/yves-saint-laurent-unisex-feuille-de-violette-cuir-oud-2023-edp-spray-fragrances-3614273893626.jpg?width=546&height=546', 'https://cdn11.bigcommerce.com/s-y76gmm/images/stencil/1280x1280/products/135544/309325/3614273893626__81695.1738780652.JPG?c=2', 'https://skinsociety.me/cdn/shop/files/3614273893626-1_1024x.jpg?v=1699878856']::text[], 'https://www.jomashop.com/yves-saint-laurent-unisex-feuille-de-violette-cuir-oud-2023-edp-spray-fragrances-3614273893626.html', 229.99, 321.99, 'Funciona con reloj negro o acero, abrigo estructurado, camisa oscura y zapatos de cuero liso.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-98496652d515']::text[], 'Para hombre, la camisa satinada, loafers de terciopelo y reloj dorado sostienen un look de noche impecable. Feuille de Violette Cuir Oud es profundo, ahumado y cuero suave; ideal para cena formal.', 'noche', ARRAY['mp-270a92a68fd4', 'mp-f9f99f3e6118', 'mp-a88c1eb55d5a']::text[], 'Para mujer, el vestido de punto con pumps y reloj madre perla crea una silueta sofisticada. Feuille de Violette Cuir Oud aporta cuero, violeta y oud; intenso, elegante y perfecto para una noche especial.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
