nspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-68ba04d02194', 'theoutnet', 'ton-46376663162935002', 'Printed Mid Length Swim Shorts', 'Off-White', 'clothing', 'men', 'Bañador de largo medio con estampado gráfico, de espíritu moderno y discreto.', 'https://www.theoutnet.com/variants/images/46376663162935002/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162935002/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162935002/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162935002/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162935002/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162935002/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/swimwear-beachwear/swim-shorts/printed-mid-length-swim-shorts/46376663162935002', 230, 321.99, 'Combínalo con polo blanco, reloj acero mate y sandalias de cuero en tonos arena.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-a3db4bdcd8a6', 'mp-21708b443c49']::text[], 'La propuesta es pulida y costeña: espadrilles, reloj azul y un perfume marino-cítrico. Los shorts gráficos ganan sofisticación sin perder actitud vacacional, perfecto para almuerzo frente al mar o un día de yate.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8ff77782c120', 'theoutnet', 'ton-46376663163100358', 'Incotex Linen And Cotton Blend Chino Shorts', 'Slowear', 'clothing', 'men', 'Short chino en mezcla de lino y algodón, limpio y fácil de llevar.', 'https://www.theoutnet.com/variants/images/46376663163100358/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163100358/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100358/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100358/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100358/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100358/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/slowear/shorts/casual-shorts/incotex-linen-and-cotton-blend-chino-shorts/46376663163100358', 230, 321.99, 'Llévalo con camisa celeste, reloj de cuero café y mocasines o loafers beige.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-21ad3f055628', 'mp-cf2b71c1d9e8']::text[], 'Los chinos cortos mantienen el tono relajado pero impecable, con espadrilles y un reloj blanco que aportan claridad visual. Mefisto completa con cítricos elegantes y un aire limpio, ideal para verano urbano o viaje.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_