INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-792737be6247', 'theoutnet', 'ton-1647597325094108', 'Pleated Cotton And Wool Blend Twill Tapered Pants', 'Ralph Lauren', 'clothing', 'women', 'Pantalón sastrero con pliegues definidos, ideal para una silueta pulida y moderna.', 'https://www.theoutnet.com/variants/images/1647597325094108/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597325094108/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597325094108/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597325094108/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597325094108/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597325094108/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ralph-lauren-collection/pants/tapered-pants/pleated-cotton-and-wool-blend-twill-tapered-pants/1647597325094108', 231, 322.99, 'Combínelo con reloj clásico, blazer azul tinta, camisa celeste y mocasines de cuero chocolate.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-2208bf601ddb', 'mp-8e3bd4eb7fe9', 'mp-57625857aaaa']::text[], 'El pantalón estructurado se eleva con loafers pulidos, reloj PRX y Libre Intense, de floral ambarado y presencia contenida. Perfecto para oficina en invierno con una lectura femenina y sofisticada.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ad8b0ead46b8', 'theoutnet', 'ton-46376663163103657', 'Striped Cotton Terry Polo Shirt', 'Orlebar Brown', 'clothing', 'men', 'Polo de terry con rayas sutiles, fresco y relajado con aire náutico.', 'https://www.theoutnet.com/variants/images/46376663163103657/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163103657/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103657/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103657/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103657/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103657/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/polo-shirts/striped-cotton-terry-polo-shirt/46376663163103657', 231, 322.99, 'Úsalo con short blanco, reloj de acero pulido y alpargatas o sneakers crema.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-69ef4764b1ae', 'mp-bf84158ff309', 'mp-8d5bb353d59a']::text[], 'El polo rayado se siente náutico y refinado junto a espadrilles y un reloj azul de presencia discreta. Neroli Portofino añade cítricos brillantes y almizcle suave, perfecto para brunch, terraza o escapada costera.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7dff9c9cea5a', 'jomashop', 'CZBU2020-02A', 'Citizen Calendrier Eco-Drive World Time Men''s Watch', 'Citizen', 'watch', 'men', 'Reloj con hora mundial y estética refinada, pensado para un ritmo internacional y elegante.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-calendrier-eco-drive-white-dial-men_s-watch-bu2020-02a.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-calendrier-eco-drive-white-dial-men_s-watch-bu2020-02a.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-calendrier-eco-drive-white-dial-men_s-watch-bu2020-02a_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-calendrier-eco-drive-white-dial-men_s-watch-bu2020-02a_3.jpg', 'https://i5.walmartimages.com/seo/Citizen-Men-s-Eco-Drive-Calendrier-World-Time-Watch-BU2020-02A_171e287e-1482-4f87-9a13-25f853f36ef8.1675ea4d68a2169e7796e0a81976dc19.jpeg']::text[], 'https://www.jomashop.com/citizen-watch-bu2020-02a.html', 231.8, 323.99, 'Acompáñelo con traje gris, camisa blanca, zapatos negros y perfume cítrico amaderado de perfil limpio.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-14b559e3d9cb', 'mp-c680203f6394', 'mp-4520d6ec87f1']::text[], 'Un conjunto de oficina sobrio y moderno: pantalón texturizado, loafers con carácter y un reloj world-time muy funcional. Grey Vetiver subraya la elegancia seca y profesional, ideal para jornadas largas y reuniones discretas.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a3faa93da4bf', 'jomashop', 'Y-151565', 'Tom Ford Unisex Oud Wood EDP Spray 3.4 oz Private Blend', 'Tom Ford', 'perfume', 'unisex', 'Oud suave y maderas secas en una firma elegante, profunda y envolvente.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-oud-wood-edp-spray-34-oz-fragrances-888066024099.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-oud-wood-edp-spray-34-oz-fragrances-888066024099.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-oud-wood-edp-spray-34-oz-fragrances-888066024099_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-oud-wood-edp-spray-34-oz-fragrances-888066024099_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-oud-wood-edp-spray-34-oz-fragrances-888066024099_4.jpg']::text[], 'https://www.jomashop.com/tom-ford-unisex-oud-wood-edp-spray-3-4-oz-fragrances-888066024099.html', 232.74, 324.99, 'Con reloj oscuro, abrigo de lana y cuero negro o azul marino, crea una presencia sobria y sofisticada.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-bdcc5c48a475', 'mp-3c75f66f94e0', 'mp-49e760656023']::text[], 'Para hombre, el sweater de lana, loafers de terciopelo y reloj negro-dorado forman un conjunto invernal y distinguido. Oud Wood es cálido, especiado y amaderado; ideal para cena, ciudad fría o noche elegante.', 'invierno', ARRAY['mp-33c53e7b9d78', 'mp-f9f99f3e6118', 'mp-69e7777fc13e']::text[], 'Para mujer, el vestido de punto con pumps y reloj negro refinado construye un look de invierno pulido. Oud Wood suma maderas suaves, cardamomo y ámbar; envolvente, elegante y muy actual para noche.', 'invierno') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
