INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-14b559e3d9cb', 'theoutnet', 'ton-46376663163023729', 'Oscar Herringbone Lyocell Linen And Cotton Blend Pants', 'Frescobol Carioca', 'clothing', 'men', 'Pantalón de caída suave en mezcla ligera, elegante sin esfuerzo.', 'https://www.theoutnet.com/variants/images/46376663163023729/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163023729/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023729/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023729/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023729/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023729/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/pants/casual-pants/oscar-herringbone-lyocell-linen-and-cotton-blend-pants/46376663163023729', 234, 326.99, 'Llévalo con camisa de lino, reloj delgado y mocasines marrón oscuro o coñac.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-7795ae7c1d60', 'mp-69df0685227c', 'mp-9c175b220b04']::text[], 'El pantalón herringbone funciona con loafers y un reloj de acero azul para una oficina relajada pero correcta. Elegant Vetiver acompaña con vetiver seco y elegante, perfecto para días cálidos y reuniones informales.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2f62ed525bad', 'theoutnet', 'ton-46376663163097222', 'Trevone Cotton Blend Terry Jacquard Shorts', 'Orlebar Brown', 'clothing', 'men', 'Short de terry con jacquard sutil, texturizado y contemporáneo.', 'https://www.theoutnet.com/variants/images/46376663163097222/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163097222/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097222/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097222/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097222/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097222/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/shorts/casual-shorts/trevone-cotton-blend-terry-jacquard-shorts/46376663163097222', 234, 326.99, 'Acompáñalo con polo marfil, reloj de acero cepillado y sandalias café o blancas.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-e305c6bba67b', 'mp-6bad761b5fb0', 'mp-6a32aace5e0a']::text[], 'La textura jacquard pide piezas frescas y bien acabadas: sandalias de piel, reloj gris sobrio y un perfume cítrico-aromático. Neroli Sauvage aporta brillo limpio, ideal para vacaciones, club de playa o almuerzo casual.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-291f66e5c21d', 'theoutnet', 'ton-46376663163023697', 'Horacio Cotton Pique Polo Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Polo piqué de línea limpia, versátil y sobrio para el verano.', 'https://www.theoutnet.com/variants/images/46376663163023697/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163023697/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023697/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023697/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023697/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023697/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/polo-shirts/horacio-cotton-pique-polo-shirt/46376663163023697', 234, 326.99, 'Combínalo con pantalón beige, reloj de cuero azul marino y loafers en gamuza.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-69ef4764b1ae', 'mp-a3db4bdcd8a6', 'mp-cedc1b107150']::text[], 'El polo piqué se eleva con espadrilles y un reloj azul de líneas limpias, creando una imagen fresca y refinada. Fiero añade cítricos verdes y especias suaves, perfecto para tarde de verano o viaje.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_no