INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-64d9b66191ee', 'theoutnet', 'ton-46376663163023728', 'Mid Length Swim Shorts', 'Frescobol Carioca', 'clothing', 'men', 'Bañador de largo medio con acabado refinado y aire costero.', 'https://www.theoutnet.com/variants/images/46376663163023728/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163023728/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023728/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023728/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023728/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023728/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/swimwear-beachwear/swim-shorts/mid-length-swim-shorts/46376663163023728', 234, 326.99, 'Úsalo con camisa de lino abierta, reloj deportivo fino y sandalias negras.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-21ad3f055628', 'mp-21708b443c49']::text[], 'Swim shorts, espadrilles y un reloj blanco componen un look de resort muy pulido. Profondo suma notas marinas y ambaradas, ideal para piscina, barco o un día cálido con elegancia silenciosa.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b84cb6b64c16', 'jomashop', 'CZEO2028-06L', 'Citizen Promaster Blue Dial Watch', 'Citizen', 'watch', 'unisex', 'Reloj deportivo de esfera azul, con presencia firme y espíritu náutico.', 'https://citizenwatch.widen.net/content/z4iphgjlnb/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/z4iphgjlnb/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/zmg5kjllhm/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/fu7vviw4iy/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iv1z6lnskv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-blue-dial-watch-eo202806l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-blue-dial-watch-eo202806l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-blue-dial-watch-eo202806l_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-blue-dial-watch-eo2028-06l.html', 235, 327.99, 'Llévelo con polo azul, jogger oscuro, zapatillas blancas y perfume fresco con notas marinas.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-a9c08c82f70a', 'mp-e518f29b87d4', 'mp-21708b443c49']::text[], 'Para hombre, el reloj azul encaja con swim shorts limpios, sneakers ligeras y un perfume acuático. Acqua di Gio Profondo es fresco, marino y limpio; ideal para verano, deporte suave o fin de semana.', 'deportivo', ARRAY['mp-f9bea38717c0', 'mp-a817148e69da', 'mp-6becc442eecf']::text[], 'Para mujer, la falda denim, sneakers pulidas y un perfume floral crean un look casual con carácter. My Way es luminoso y femenino; perfecto para día, viaje o planes relajados con un toque chic.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7ebeb632a92e', 'theoutnet', 'ton-46376663162894481', 'Antonio Linen Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Camisa de lino ligera, impecable y naturalmente fresca.', 'https://www.theoutnet.com/variants/images/46376663162894481/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162894481/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162894481/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162894481/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162894481/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162894481/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/casual-shirts/antonio-linen-shirt/46376663162894481', 235, 327.99, 'Llévala con pantalón crudo, reloj de cuero claro y mocasines o sandalias de piel.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-a3db4bdcd8a6', 'mp-8d5bb353d59a']::text[], 'Lino, espadrilles y un reloj azul componen un conjunto fresco y discreto. El perfume suma un cítrico marino, luminoso y elegante. Funciona muy bien para almuerzos, terraza o escapadas de verano.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-bc5ca8f9ef41', 'theoutnet', 'ton-46376663162894482', 'Antonio Linen Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Camisa de lino ligera, impecable y naturalmente fresca.', 'https://www.theoutnet.com/variants/images/46376663162894482/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162894482/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162894482/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162894482/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162894482/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162894482/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/casual-shirts/antonio-linen-shirt/46376663162894482', 235, 327.99, 'Llévala con pantalón crudo, reloj de cuero claro y mocasines o sandalias de piel.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-a3db4bdcd8a6', 'mp-8d5bb353d59a']::text[], 'Lino, espadrilles y un reloj azul crean una propuesta fresca y sobria. El perfume añade un acorde cítrico-marino, pulido y refinado. Perfecto para almuerzos, viaje o fines de semana de verano.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_c