INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4d33f51092b8', 'theoutnet', 'ton-46376663163103661', 'Ebro Striped Cotton Blend Terry Polo Shirt', 'Orlebar Brown', 'clothing', 'men', 'Polo de terry con rayas finas, relajado y pulcro.', 'https://www.theoutnet.com/variants/images/46376663163103661/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163103661/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103661/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103661/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103661/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103661/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/polo-shirts/ebro-striped-cotton-blend-terry-polo-shirt/46376663163103661', 236, 328.99, 'Combínalo con short arena, reloj de acero y sneakers blancas de perfil bajo.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-a3db4bdcd8a6', 'mp-8d5bb353d59a']::text[], 'El polo terry y las espadrilles mantienen el gesto relajado, mientras el reloj azul aporta orden visual. El perfume, cítrico y marino, remata un conjunto ideal para vacaciones, brunch o tarde cálida.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-99f35246fee1', 'jomashop', 'CZNJ0151-53Z', 'Citizen Tsuyosa Automatic Orange Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Automático naranja de aire vibrante, con un giro moderno y seguro de sí mismo.', 'https://citizenwatch.widen.net/content/zz13mn4b8u/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/zz13mn4b8u/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/djcvtbbrhe/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/zvmjkiq8al/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-orange-dial-mens-watch-nj015153z.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-orange-dial-mens-watch-nj015153z_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-orange-dial-mens-watch-nj015153z_3.jpg']::text[], 'https://www.jomashop.com/citizen-tsuyosa-automatic-orange-dial-mens-watch-nj0151-53z.html', 236.55, 329.99, 'Equilíbrelo con camisa blanca, denim oscuro, sneakers minimalistas y perfume amaderado ligero.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-291f66e5c21d', 'mp-1b60c92c78b6', 'mp-605a39d82c0f']::text[], 'El polo en pique y las sneakers equilibran el naranja del dial con una base limpia y urbana. El perfume, fresco y ambarado, acompaña sin imponerse. Muy bueno para diario, almuerzo o after office informal.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8b07465dff40', 'jomashop', 'CZBN0199-53X', 'Citizen Promaster Marine Eco-Drive Green Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Diver verde de espíritu marino, con acabados sobrios y vocación aventurera.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-marine-ecodrive-green-dial-mens-watch-bn019953x.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-marine-ecodrive-green-dial-mens-watch-bn019953x.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-marine-ecodrive-green-dial-mens-watch-bn019953x_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-marine-ecodrive-green-dial-mens-watch-bn019953x_3.jpg', 'https://i5.walmartimages.com/seo/Citizen-Promaster-Marine-Eco-Drive-Green-Dial-Men-s-Watch-BN0199-53X_8c6568ee-16e4-4c2d-893e-148338e5c328.eaa26fa29312533621650001f2dcbe0b.jpeg', 'https://watchzonebd.com/uploads/product/main171506140943270BN0199-53X.webp', 'https://i5.walmartimages.com/seo/Citizen-Promaster-Marine-Eco-Drive-Green-Dial-Men-s-Watch-BN0199-53X_fc2bd420-5c5c-4c1e-93a7-2660f93011d9.4624448eb023a68af2fdedff59ce80f0.jpeg', 'https://watchzonebd.com/uploads/product/BN0199-53X-3_6639c2a190372.webp']::text[], 'https://www.jomashop.com/citizen-promaster-marine-eco-drive-green-dial-mens-watch-bn0199-53x.html', 236.55, 329.99, 'Combínelo con camiseta blanca, pantalón de lona beige, botas náuticas y perfume fresco herbal.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-291f66e5c21d', 'mp-e886cd56a6d2', 'mp-21708b443c49']::text[], 'El polo pique y las sneakers de piel suavizan la energía del reloj de buceo. El perfume aporta frescura acuática y limpia, con aire elegante. Conjunto ideal para ciudad, paseo activo o fin de semana.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f9188621be33', 'jomashop', 'CZCA4213-18L', 'Citizen Avion Chronograph Eco-Drive Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Cronógrafo azul de estilo aeronáutico, preciso y con una elegancia funcional.', 'https://citizenwatch.widen.net/content/rokpchl8y0/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/rokpchl8y0/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/48ihzgz6xx/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/5sj8kjg6sy/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-avion-chronograph-ecodrive-blue-dial-mens-watch-ca421318l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-avion-chronograph-ecodrive-blue-dial-mens-watch-ca421318l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-avion-chronograph-ecodrive-blue-dial-mens-watch-ca421318l_3.jpg']::text[], 'https://www.jomashop.com/citizen-avion-watch-ca4213-18l.html', 236.55, 329.99, 'Úselo con camisa celeste, blazer azul, pantalón gris y loafers; perfume limpio de fondo amaderado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-90e204c4c1b2', 'mp-7795ae7c1d60', 'mp-e5b8eeedce5f']::text[], 'La camisa y los chinos afinan el cronógrafo azul con una lectura pulida y actual. Los loafers elevan el conjunto, mientras el perfume suma frescura especiada. Funciona muy bien para oficina y reuniones.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1f0254abf485', 'jomashop', 'TIST1204173605100', 'Tissot Seastar 1000 Chronograph Quartz Black Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Cronógrafo de buceo con presencia intensa, pensado para un estilo técnico y contundente.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-chronograph-quartz-black-dial-mens-watch-t1204173605100.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-chronograph-quartz-black-dial-mens-watch-t1204173605100.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-chronograph-quartz-black-dial-mens-watch-t1204173605100_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-chronograph-quartz-black-dial-mens-watch-t1204173605100_3.jpg', 'https://cdn11.bigcommerce.com/s-msby3f18ji/images/stencil/1280x1280/products/11572/25486/T1204173605100__29496.1666626710.jpg?c=1&imbypass=on']::text[], 'https://www.jomashop.com/tissot-seastar-1000-chronograph-quartz-black-dial-mens-watch-t1204173605100.html', 236.55, 329.99, 'Combínelo con chaqueta negra, polo oscuro, pantalón recto y perfume especiado de carácter seco.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-015d339460d4', 'mp-ab3a6a32e967', 'mp-3d7ec08426d5']::text[], 'El negro del reloj pide contraste limpio: el pantalón técnico y las sneakers mantienen la silueta moderna. El perfume, intenso y amaderado, da salida nocturna. Ideal para cena informal o plan after-dark.', 'noche', NULL, NULL, NULL) 