INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6f0d137af367', 'jomashop', 'CZEO2020-08E', 'Citizen Promaster Black Dial Ladies Watch', 'Citizen', 'watch', 'women', 'Diver femenino en negro, sobrio y versátil, con un carácter activo y limpio.', 'https://citizenwatch.widen.net/content/zj0mz63r6o/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/zj0mz63r6o/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/kxmdiaw09a/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/yd75063aks/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iv1z6lnskv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-black-dial-ladies-watch-eo202008e.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-black-dial-ladies-watch-eo202008e_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-black-dial-ladies-watch-eo202008e_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-black-dial-ladies-watch-eo2020-08e.html', 237, 330.99, 'Llévelo con top blanco, pantalón recto, zapatillas negras y perfume fresco acuático.', 'https://seekpretty.com/wp-content/uploads/2025/01/a-photo-of-a-monochrome-athleisure-set-t_UaYuWzRiRNqS_psTbzznVQ_2N3x2NedSsmd-SqFY7F8Cw.png', ARRAY['mp-8b1d23d08a7c', 'mp-771e0dce9f5f', 'mp-8cf3908f3eee']::text[], 'El negro del reloj pide contrastes limpios: pantalón fluido, ballet flats y Flora Gorgeous Gardenia, floral blanco y luminoso. Un look elegante de día, femenino y sobrio, muy favorable para oficina.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c66712cbebcf', 'jomashop', 'Z-L5MA9', 'Gucci Unisex Heart Of Leo EDP 3.4 oz', 'Gucci', 'perfume', 'unisex', 'Fragancia cálida y envolvente, con presencia refinada para la noche.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-heart-of-leo-edp-34-oz-fragrances-3616305169495.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-heart-of-leo-edp-34-oz-fragrances-3616305169495.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-heart-of-leo-edp-34-oz-fragrances-3616305169495_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-unisex-heart-of-leo-edp-34-oz-fragrances-3616305169495_7.jpg']::text[], 'https://www.jomashop.com/gucci-unisex-heart-of-leo-edp-3-4-oz-fragrances-3616305169495.html', 237.12, 330.99, 'Llévala con blazer negro, reloj oscuro y zapatos de cuero pulido en tono grafito.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-1e4d84f905c4', 'mp-ac85563341af', 'mp-572e6daacaab']::text[], 'Para una noche elegante, esta camisa satinada, los loafers de ante con detalle tejido y el Seiko dorado crean un equilibrio refinado y sutil. El Heart Of Leo aporta un velo ambarado y sensual, ideal para destacar sin excesos.', 'noche', ARRAY['mp-270a92a68fd4', 'mp-d0246a15c10d', 'mp-69e7777fc13e']::text[], 'Para una noche elegante, el vestido de punto, los pumps de cuero y el reloj negro con presencia pulida forman un conjunto sofisticado. El Heart Of Leo suma un carácter ambarado y seductor, perfecto para una cena o evento.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-16b67b85f8be', 'jomashop', 'SE-SRPK13K1', 'Seiko 5 Sports Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Ícono deportivo de líneas equilibradas, con esfera negra y carácter atemporal.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-srpk13k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-srpk13k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-srpk13k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-srpk13k1_3.jpg', 'https://cdnstatic.creationwatches.com/products/product-images/l/SRPK13K1_LRG.webp', 'https://www.strapseeker.com/cdn/shop/products/seikoseiko-5-sports-srpk13k1-srpk13-srpk13k-24-jewels-automatic-mens-watch-457395.jpg?v=1695454574&width=1080']::text[], 'https://www.jomashop.com/seiko-5-sports-automatic-black-dial-mens-watch-srpk13k1.html', 239, 332.99, 'Combínelo con camiseta premium, denim crudo, chaqueta de lana ligera y perfume amaderado discreto.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-7ebeb632a92e', 'mp-e886cd56a6d2', 'mp-2dc2d5978672']::text[], 'La camisa de lino y las sneakers de piel equilibran el negro del reloj con un aire relajado y pulcro. El perfume es fresco, clásico y nítido. Perfecto para diario, almuerzo o viaje corto.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-782e7cde9ac1', 'theoutnet', 'ton-46376663163051706', 'Shell Midi Skirt', 'Maison Margiela', 'clothing', 'women', 'Falda midi de silueta suave y estética limpia, fácil de llevar con discreta sofisticación.', 'https://www.theoutnet.com/variants/images/46376663163051706/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163051706/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163051706/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163051706/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163051706/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163051706/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/maison-margiela/skirts/midi-skirts/shell-midi-skirt/46376663163051706', 239, 332.99, 'Acompáñela con reloj delgado, blusa de seda, sandalias minimalistas y perfume floral limpio.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-08cb860e5a5a', 'mp-c798e1926e9d', 'mp-9d3a106a46fc']::text[], 'La falda estructurada gana serenidad con loafers de cuero, PRX perla y Silver Mountain Water, fresco y cristalino. Un conjunto de lujo silencioso, perfecto para oficina o almuerzo sofisticado.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ef6b916a5f31', 'theoutnet', 'ton-46376663163091346', 'Roberto Printed Silk Satin Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Camisa satinada con estampado expresivo, sofisticada y de impacto.', 'https://www.theoutnet.com/variants/images/46376663163091346/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163091346/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091346/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091346/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091346/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091346/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/casual-shirts/roberto-printed-silk-satin-shirt/46376663163091346', 239, 332.99, 'Combínala con pantalón negro, reloj dorado discreto y loafers de charol o cuero liso.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-3c75f66f94e0', 'mp-c109304a8cd3', 'mp-2e495b310fd2']::text[], 'La camisa satinada pide acabados ricos: terciopelo en los loafers y un reloj azul refuerzan el lujo discreto. El perfume, dulce-especiado y nocturno, acompaña una cena, gala o cóctel con presencia.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2bca30ea642c', 'theoutnet', 'ton-1647597306802602', 'Belted Crinkled Patent Leather Mini Skirt', 'Balmain', 'clothing', 'women', 'Mini falda de acabado brillante y cintura marcada, pensada para una entrada segura.', 'https://www.theoutnet.com/variants/images/1647597306802602/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597306802602/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306802602/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306802602/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306802602/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306802602/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/skirts/mini-skirts/belted-crinkled-patent-leather-mini-skirt/1647597306802602', 240, 333.99, 'Combínela con reloj joya, top negro, sandalias finas y perfume floral oscuro de presencia marcada.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-95ac9c8c22b8', 'mp-c798e1926e9d', 'mp-1e7075d60425']::text[], 'El mini skirt patentado gana fuerza con pumps afilados y un reloj de madreperla. El perfume, floral y sofisticado, aporta feminidad sin exceso. Ideal para cena, evento o noche elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-810c735a0488', 'jomashop', 'CZBM7103-51L', 'Citizen Corso Eco-Drive Diamond Blue Dial Watch', 'Citizen', 'watch', 'unisex', 'Reloj refinado con diamantes sutiles y esfera azul, elegante sin excesos.', 'https://citizenwatch.widen.net/content/glswaewy6c/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/glswaewy6c/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/yvw6vih2bc/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/9g73ty7dal/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-corso-diamond-blue-dial-watch-bm7103-51l--.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-corso-diamond-blue-dial-watch-bm7103-51l--_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-corso-diamond-blue-dial-watch-bm7103-51l--_3.jpg']::text[], 'https://www.jomashop.com/citizen-corso-watch-bm7103-51l.html', 241.3, 335.99, 'Use reloj metálico fino, blazer marino, camisa blanca, pantalón sastre y perfume limpio con vetiver.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-4f703db7d409', 'mp-c680203f6394', 'mp-4520d6ec87f1']::text[], 'Para oficina, el reloj azul funciona con camisa de lyocell, loafers de ante y un perfume limpio de vetiver. Un conjunto sobrio y preciso, con aire ejecutivo y moderno, perfecto para jornadas largas y reuniones discretas.', 'oficina', ARRAY['mp-e80799294eb5', 'mp-2208bf601ddb', 'mp-d3b04c599098']::text[], 'Para oficina, la camisa popelina, los loafers pulidos y el reloj de acero azul construyen una elegancia serena. Prada Infusion d’Iris añade un aroma limpio, empolvado y sofisticado, ideal para un día profesional.', 'oficina') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-040ca96a9ab7', 'theoutnet', 'ton-46376663163096950', 'Trevone Cotton Terry Drawstring Shorts', 'Orlebar Brown', 'clothing', 'men', 'Short de terry con cordón, cómodo y pulcro para días cálidos.', 'https://www.theoutnet.com/variants/images/46376663163096950/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096950/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096950/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096950/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096950/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096950/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/shorts/casual-shorts/trevone-cotton-terry-drawstring-shorts/46376663163096950', 241, 335.99, 'Combínalo con polo liso, reloj minimalista y sandalias de cuero en tonos beige.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-16b67b85f8be', 'mp-8d5bb353d59a', 'mp-32f83814872c']::text[], 'Los shorts de terry funcionan mejor con lino ligero y un reloj deportivo limpio. El perfume añade cítricos mediterráneos, frescos y refinados. Conjunto ideal para verano, playa o fin de semana relajado.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.