INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-402dd9c37b96', 'jomashop', 'CZBM7100-59H', 'Citizen Corso Eco-Drive Grey Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Reloj gris de líneas sobrias, fácil de integrar en un guardarropa pulido.', 'https://citizenwatch.widen.net/content/bjytcwfs9x/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/bjytcwfs9x/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/h0t5batada/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/tcidxtpp0c/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-corso-eco-drive-men_s-watch-bm7100-59h.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-corso-eco-drive-men_s-watch-bm7100-59h_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-corso-eco-drive-men_s-watch-bm7100-59h_3.jpg']::text[], 'https://www.jomashop.com/citizen-corso-watch-bm7100-59h.html', 242.25, 336.99, 'Combínelo con traje gris, camisa celeste, zapatos negros y perfume amaderado suave de trazo limpio.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4f703db7d409', 'mp-9b75c4948e46', 'mp-4520d6ec87f1']::text[], 'Para oficina, el reloj gris armoniza con camisa clara, pantalón de lino y loafers de ante. Grey Vetiver refuerza la sobriedad con un perfil seco, elegante y muy masculino, perfecto para reuniones y días de trabajo.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
