INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a76f1eb8cc75', 'jomashop', 'Z-R9RCB', 'Dolce & Gabbana Velvet Black Patchouli Eau de Parfum 5.0 oz/150 ml', 'Dolce & Gabbana', 'perfume', 'unisex', 'Perfume oscuro y aterciopelado, con un fondo profundo y seductor.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/o/dolce-gabbana-velvet-black-patchouli-eau-de-parfum-50-oz150-ml-3423222002503.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/o/dolce-gabbana-velvet-black-patchouli-eau-de-parfum-50-oz150-ml-3423222002503.jpg', 'https://www.dolcegabbana.com/dw/image/v2/BKDB_PRD/on/demandware.static/-/Sites-15/default/dw76741eb2/images/zoom/VP002BVP000_9V000_2.jpg?sw=1480&sh=1888', 'https://www.lookfantastic.com/images?url=https://static.thcdn.com/productimg/original/12779581-1304860423939942.jpg&format=webp&auto=avif&width=985&height=985&fit=cover', 'https://www.parfum-outlet.ch/media/ec/e1/4f/1674041543/Dolce Gabbana Velvet Black Patchouli-min.png']::text[], 'https://www.jomashop.com/dolce-gabbana-velvet-black-patchouli-eau-de-parfum-5-0-oz-150-ml-3423222002503.html', 244.99, 339.99, 'Combínalo con abrigo negro, reloj de piel y zapatos de cuero liso en grafito.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-1e4d84f905c4', 'mp-474b2526c36a', 'mp-98496652d515']::text[], 'Para una noche de invierno, la camisa satinada, los loafers de terciopelo y el reloj dorado elevan el conjunto con lujo contenido. Velvet Black Patchouli aporta profundidad oscura, terrosa y envolvente, muy apropiada para cena formal.', 'invierno', ARRAY['mp-3968aa79d4f8', 'mp-0cf3b002ce9d', 'mp-69e7777fc13e']::text[], 'Para una noche de invierno, el mini dress drapeado, las botas Rockstud y el reloj negro crean un conjunto poderoso y refinado. Velvet Black Patchouli aporta una estela oscura, cálida y sofisticada, ideal para evento nocturno.', 'invierno') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ab17c0bfb64c', 'jomashop', 'SE-SRPK11K1', 'Seiko 5 Sports Automatic Orange Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Automático naranja de energía inmediata, ideal para destacar con espíritu deportivo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-orange-dial-mens-watch-srpk11k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-orange-dial-mens-watch-srpk11k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-orange-dial-mens-watch-srpk11k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-orange-dial-mens-watch-srpk11k1_3.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Sports-Automatic-Orange-Dial-Men-s-Watch-SRPK11K1_419be539-ff39-48fb-b768-ebdf5496abe5.306603edcb6d627ecc21b89a41aef791.jpeg?odnHeight=573&odnWidth=573&odnBg=FFFFFF', 'https://hochuanwatch.com/images/products/secondary/srpk11k1-1.png', 'https://cdnstatic.creationwatches.com/products/product-images/l/SRPK11K1_3_LRG.webp', 'https://www.skywatches.com.sg/cdn/shop/files/SRPK11K12.png?v=1686717020&width=1080']::text[], 'https://www.jomashop.com/seiko-5-sports-automatic-orange-dial-mens-watch-srpk11k1.html', 245, 340.99, 'Combínelo con camiseta blanca, bomber oscura, denim y zapatillas; perfume cítrico fresco y limpio.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-3f6a0c894592', 'mp-6abb16f437af', 'mp-605a39d82c0f']::text[], 'Para un día deportivo, el reloj naranja se integra con swim shorts, sneakers técnicas y una fragancia dinámica. Luna Rossa Carbon aporta frescura mineral y limpia, perfecta para playa, paseo o actividad casual.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c1386c461b8d', 'theoutnet', 'ton-46376663163088829', 'Mendes Striped Lyocell Linen And Cotton Blend Pants', 'Frescobol Carioca', 'clothing', 'men', 'Pantalón de caída fluida con rayas discretas, fresco y distinguido.', 'https://www.theoutnet.com/variants/images/46376663163088829/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163088829/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163088829/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163088829/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163088829/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163088829/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/pants/casual-pants/mendes-striped-lyocell-linen-and-cotton-blend-pants/46376663163088829', 245, 340.99, 'Úsalo con camisa blanca, reloj de acero mate y mocasines beige o espadrilles.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-69ef4764b1ae', 'mp-bf84158ff309', 'mp-21708b443c49']::text[], 'Para verano, los pantalones rayados de lino, las espadrilles y el reloj azul construyen un look relajado y fino. Acqua di Gio Profondo añade un acorde marino y luminoso, ideal para un almuerzo al aire libre.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLU