INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a3db4bdcd8a6', 'jomashop', 'CZNJ0151-88X', 'Citizen Tsuyosa Automatic Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Automático azul de diseño limpio, versátil y actual, con presencia serena.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-blue-dial-mens-watch-nj015188x.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-blue-dial-mens-watch-nj015188x.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-blue-dial-mens-watch-nj015188x_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-blue-dial-mens-watch-nj015188x_3.jpg', 'https://www.reddeerwatches.com/media/catalog/product/cache/f20a3dad9a18e1857a6578422466bfb5/n/j/nj0151-88x_00.jpg']::text[], 'https://www.jomashop.com/citizen-automatic-blue-dial-mens-watch-nj0151-88x.html', 246.05, 341.99, 'Acompáñelo con camisa blanca, pantalón chino beige, mocasines marrones y perfume acuático amaderado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-82a5b81520e1', 'mp-e886cd56a6d2', 'mp-605a39d82c0f']::text[], 'Para un look casual y refinado, combina la esfera azul con la camisa de lino y unas sneakers de ante y cuero; queda limpio, actual y muy Lima. Si eliges este perfume, aporta un aire cítrico-amaderado, fresco y sobrio.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-82a5b81520e1', 'theoutnet', 'ton-46376663163091356', 'Antonio Linen Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Camisa de lino ligera, impecable y naturalmente fresca.', 'https://www.theoutnet.com/variants/images/46376663163091356/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163091356/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091356/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091356/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091356/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091356/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/casual-shirts/antonio-linen-shirt/46376663163091356', 246, 341.99, 'Llévala con pantalón crudo, reloj de cuero claro y mocasines o sandalias de piel.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-bf84158ff309', 'mp-32f83814872c', 'mp-337d48edab34']::text[], 'Para verano, esta camisa de lino funciona con espadrilles y un reloj sport azul: conjunto ligero, pulido y fácil de llevar de día. El perfume suma una frescura marina y elegante, ideal para calor y tardes al aire libre.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-dd380b537d97', 'theoutnet', 'ton-46376663163098861', 'Appliqued Rubber Slides', 'Givenchy', 'shoes', 'men', 'Sandalias de goma con líneas limpias, funcionales y contemporáneas.', 'https://www.theoutnet.com/variants/images/46376663163098861/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163098861/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098861/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098861/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098861/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098861/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/givenchy/sandals/flat-sandals/appliqued-rubber-slides/46376663163098861', 246, 341.99, 'Úsalas con short negro, camiseta blanca, reloj deportivo fino y gafas de acetato oscuro.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-82a5b81520e1', 'mp-8d5bb353d59a', 'mp-a3db4bdcd8a6']::text[], 'Con camisa de lino y pantalón ligero, estas slides elevan un look casual sin esfuerzo. Perfecto para un almuerzo de fin de semana o viaje corto. El perfume añade neroli brillante, limpio y distinguido, muy acorde a clima cálido.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.re