INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-fe57d43b0732', 'theoutnet', 'ton-46376663163098862', 'Appliqued Rubber Slides', 'Givenchy', 'shoes', 'men', 'Sandalias de goma con líneas limpias, funcionales y contemporáneas.', 'https://www.theoutnet.com/variants/images/46376663163098862/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163098862/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098862/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098862/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098862/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098862/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/givenchy/sandals/flat-sandals/appliqued-rubber-slides/46376663163098862', 246, 341.99, 'Úsalas con short negro, camiseta blanca, reloj deportivo fino y gafas de acetato oscuro.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-373e9b5e8f50', 'mp-a3db4bdcd8a6', 'mp-2dc2d5978672']::text[], 'Para un resultado silenciosamente lujoso, llévalas con lino suave y un reloj de acero azul; todo se ve relajado pero preciso. Ideal para fin de semana o resort. El perfume aporta cítricos clásicos, secos y muy limpios.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5099cd29d9cd', 'jomashop', 'Z-HZ4B8', 'Yves Saint Laurent Unisex Jumpsuit Vibrant Magnolia EDP Spray 4.2 oz', 'Yves Saint Laurent', 'perfume', 'unisex', 'Magnolia vibrante con aura limpia y femenina, de trazo contemporáneo y presencia discreta.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-unisex-jumpsuit-vibrant-magnolia-edp-spray-42-oz-fragrances-3614274184846.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-unisex-jumpsuit-vibrant-magnolia-edp-spray-42-oz-fragrances-3614274184846.jpg', 'https://perfumedubai.com/cdn/shop/files/3614274184846-2_16b21a77-0375-4791-91fb-7a64d6090f8a.jpg?v=1757583407', 'https://cdn.luxuryperfume.com.my/wp-content/uploads/2025/06/3614274184846_125ml_jumpsuit_edp_alt3.jpg', 'https://www.harmoniq.se/image/188057/3614274184846_7.jpg']::text[], 'https://www.jomashop.com/yves-saint-laurent-unisex-jumpsuit-vibrant-magnolia-edp-spray-4-2-oz-fragrances-3614274184846.html', 246.99, 342.99, 'Combínalo con reloj fino en oro claro, camisa cruda y mocasines nude para equilibrio sobrio.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-8c3966fd13a5', 'mp-ac85563341af', 'mp-23af6e30e1cc']::text[], 'Para ti, este perfume pide una camisa satinada, loafers pulidos y un reloj fino: una imagen elegante, moderna y discreta. Funciona muy bien para cena o evento nocturno. La fragancia es floral, cremosa y luminosa, con presencia sofisticada.', 'elegante', ARRAY['mp-d04ffafba9a6', 'mp-4f1a6a5f486b', 'mp-c798e1926e9d']::text[], 'Para ti, el perfume se acompaña mejor con falda midi de seda, flats de cuero y un reloj nacarado: femenino, pulido y sutil. Ideal para cena o una noche especial. La fragancia es floral, cremosa y muy elegante.', 'elegante') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
