INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8c3966fd13a5', 'theoutnet', 'ton-46376663163107969', 'Printed Mousseline Shirt', 'Jacquemus', 'clothing', 'men', 'Mousseline estampada con ligereza editorial, pensada para un impacto refinado y fresco.', 'https://www.theoutnet.com/variants/images/46376663163107969/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163107969/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107969/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107969/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107969/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107969/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jacquemus/tops/casual-shirts/printed-mousseline-shirt/46376663163107969', 248, 343.99, 'Úsala con reloj delgado, perfume floral suave y pantalón sastre beige con sandalias minimalistas.', 'https://images.stockcake.com/public/e/f/1/ef1cb030-ed89-4a00-af5d-cf1485e9e655_large/elegant-men-s-fashion-stockcake.jpg', ARRAY['mp-3c75f66f94e0', 'mp-cf2b71c1d9e8', 'mp-5744d9813fec']::text[], 'Para ti, la camisa estampada queda mejor con loafers de terciopelo y un perfume de perfil limpio y distinguido. Es un look ideal para cena de verano o cóctel. El resultado es sofisticado, fresco y con un punto artístico.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-49927423d2e5', 'theoutnet', 'ton-46376663163096487', 'Printed Woven Shirt', 'Sandro', 'clothing', 'men', 'Silueta tejida con estampado definido, sobria y con un gesto artístico.', 'https://www.theoutnet.com/variants/images/46376663163096487/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096487/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096487/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096487/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096487/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096487/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/sandro/tops/casual-shirts/printed-woven-shirt/46376663163096487', 248, 343.99, 'Acompáñala con reloj plateado, perfume amaderado y pantalón oscuro con derby de cuero.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-ccd7e4d707b6', 'mp-a3db4bdcd8a6', 'mp-2e495b310fd2']::text[], 'Para ti, combina el estampado con brogues clásicos y un reloj azul de acero: equilibrio entre carácter y corrección. Funciona para oficina creativa o cena. El perfume aporta una estela dulce-especiada, elegante y con presencia.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-162803429493', 'theoutnet', 'ton-46376663163158841', 'David Denim Sandals', 'MR P.', 'shoes', 'men', 'Sandalia en denim con carácter relajado y un acabado urbano muy actual.', 'https://www.theoutnet.com/variants/images/46376663163158841/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158841/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158841/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158841/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158841/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158841/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158841/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/mr-p/sandals/flat-sandals/david-denim-sandals/46376663163158841', 248, 343.99, 'Combínalas con reloj de acero, polo blanco y pantalón lino piedra para un aire limpio.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-f144bdfe9ff8', 'mp-bf84158ff309', 'mp-0de6cc427e14']::text[], 'Para un verano relajado, estas sandalias van perfectas con camisa de lino y shorts ligeros, más un reloj azul deportivo. El look es fresco y bien resuelto. El perfume suma una brisa marina y cítrica, limpia y moderna.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7dc0de26d463', 'theoutnet', 'ton-46376663163098867', 'Appliqued Rubber Slides', 'Givenchy', 'shoes', 'men', 'Slide en goma con detalle aplicado, simple y precisa para días cálidos.', 'https://www.theoutnet.com/variants/images/46376663163098867/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163098867/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098867/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098867/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098867/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163098867/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/givenchy/sandals/flat-sandals/appliqued-rubber-slides/46376663163098867', 248, 343.99, 'Llévalas con reloj minimalista, fragancia fresca y bermudas marfil con camisa de lino.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-373e9b5e8f50', 'mp-6bad761b5fb0', 'mp-60727c51909d']::text[], 'Con lino suave y un reloj de esfera gris, estas slides se sienten modernas y discretas. Ideal para paseo, brunch o escapada urbana. El perfume añade un frescor aromático y ambarado, limpio pero con buena fijación.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_