INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ccd7e4d707b6', 'theoutnet', 'ton-46376663163077923', 'Leather Brogues', 'Thom Browne', 'shoes', 'men', 'Brogues de cuero con estructura clásica, impecables para un guardarropa formal.', 'https://www.theoutnet.com/variants/images/46376663163077923/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163077923/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077923/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077923/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077923/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077923/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/flat-shoes/lace-ups/leather-brogues/46376663163077923', 248, 343.99, 'Con reloj de correa negra, perfume amaderado y traje gris carbón o pantalón navy.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-76e86cc39c9a', 'mp-23af6e30e1cc', 'mp-c98229ae5f30']::text[], 'Para ti, estos brogues piden pantalón sastre y un reloj clásico; el resultado es impecable para oficina o reunión formal. El perfume acompaña con un perfil refinado, amaderado y limpio, de presencia elegante y segura.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXC