INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-bf84158ff309', 'jomashop', 'SE-SRPK65K1', 'Seiko 5 Sports Special Edition Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera azul y espíritu deportivo, con presencia limpia para acompañar el día con discreción.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-special-edition-automatic-blue-dial-mens-watch-srpk65k1_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-special-edition-automatic-blue-dial-mens-watch-srpk65k1_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-special-edition-automatic-blue-dial-mens-watch-srpk65k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-special-edition-automatic-blue-dial-mens-watch-srpk65k1_3.jpg', 'https://media.klockgiganten.se/catalog/product/cache/074b491b7c680a360b2429f2a25e33dc/s/r/srpk65k1.jpg']::text[], 'https://www.jomashop.com/seiko-5-sports-special-edition-automatic-blue-dial-mens-watch-srpk65k1.html', 249, 344.99, 'Llévalo con polo blanco, denim oscuro, sneakers de cuero y perfume cítrico-amaderado para un look sobrio.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-82a5b81520e1', 'mp-e886cd56a6d2', 'mp-605a39d82c0f']::text[], 'Para ti, este Seiko azul encaja con camisa de lino y sneakers de ante: una lectura relajada pero cuidada. Ideal para fin de semana o viaje. El perfume aporta una frescura marina y elegante, muy versátil y luminosa.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-61e39424851a', 'theoutnet', 'ton-46376663163097357', 'Frederick French Cotton Blend Terry Drawstring Shorts', 'Orlebar Brown', 'clothing', 'men', 'Shorts de terry con ajuste limpio, perfectos para un descanso sofisticado.', 'https://www.theoutnet.com/variants/images/46376663163097357/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163097357/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097357/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097357/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097357/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097357/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/shorts/casual-shorts/frederick-french-cotton-blend-terry-drawstring-shorts/46376663163097357', 249, 344.99, 'Úsalos con reloj deportivo fino, perfume acuático y camiseta blanca con sneakers de cuero.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-162803429493', 'mp-0de6cc427e14', 'mp-5744d9813fec']::text[], 'Para ti, los shorts funcionan mejor con camisa de lino abierta, sandalias de cuero y un perfume fresco de aire marino. Es el uniforme perfecto para Lima en verano: limpio, cómodo y con lujo silencioso.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration