INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-cdb16616438b', 'jomashop', 'SE-SRPK87K1', 'Seiko 5 Sports SNXS Automatic Navy Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Navy dial con aire clásico, fácil de llevar y discretamente distinguido.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-snxs-automatic-navy-dial-mens-watch-srpk87k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-snxs-automatic-navy-dial-mens-watch-srpk87k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-snxs-automatic-navy-dial-mens-watch-srpk87k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-snxs-automatic-navy-dial-mens-watch-srpk87k1_3_1.jpg', 'https://www.zegarek.net/imageslib/produkty/duze/seiko-srpk87k1-zegarek-meski-sports-automat-210968-2.jpg', 'https://www.skywatches.com.sg/cdn/shop/files/SRPK87K11_3.png?v=1723171017&width=1200', 'https://www.skywatches.com.sg/cdn/shop/files/SRPK87K1.png?v=1723171205&width=1200', 'https://www.hodinky-365.cz/fotky/maxi/f244/seiko-5-sports-automatic-srpk87k1-snxs-series_251823_376112.jpg']::text[], 'https://www.jomashop.com/seiko-5-sports-snxs-automatic-navy-dial-mens-watch-srpk87k1.html', 251.75, 348.99, 'Combínalo con knit azul marino, pantalón gris, zapatillas blancas y perfume limpio amaderado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-82a5b81520e1', 'mp-e886cd56a6d2', 'mp-8d5bb353d59a']::text[], 'La camisa de lino y las sneakers Tod’s suavizan el azul del Seiko con refinamiento relajado. Tom Ford Neroli Portofino suma frescura cítrica y marina, ideal para un almuerzo elegante o tarde costera.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
