INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0e79c215b92a', 'jomashop', 'SE-SRPH33K1', 'Seiko 5 Sports Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera negra y perfil deportivo, una elección sobria para uso diario con estilo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-srph33k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-srph33k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-srph33k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-srph33k1_3.jpg', 'https://watchzonebd.com/uploads/multiimage/SRPH33K1-1 (3)_655c7177853e3.webp']::text[], 'https://www.jomashop.com/seiko-5-sports-automatic-black-dial-mens-watch-srph33k1.html', 254, 351.99, 'Llévalo con camiseta negra, overshirt beige, botas de cuero y perfume especiado ligero.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-9913fefbdf00', 'mp-1b60c92c78b6', 'mp-2dc2d5978672']::text[], 'El polo de lino y las Bally refinan el negro del Seiko con una elegancia contenida para diario. Eau Sauvage aporta un aire cítrico, clásico y pulcro, perfecto para oficina informal o cena temprana.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8d5bb353d59a', 'jomashop', 'Z-OBNSL', 'Tom Ford Neroli Portofino Eau de Parfum Spray 3.4 Oz Private Blend', 'Tom Ford', 'perfume', 'unisex', 'Neroli y cítricos mediterráneos: una estela fresca, limpia y refinada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-neroli-portofino-eau-de-parfum-spray-34-oz-private-blend-888066008457.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-neroli-portofino-eau-de-parfum-spray-34-oz-private-blend-888066008457.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-neroli-portofino-eau-de-parfum-spray-34-oz-private-blend-888066008457_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-neroli-portofino-eau-de-parfum-spray-34-oz-private-blend-888066008457_7.jpg', 'https://res.cloudinary.com/dp9dnliwc/image/upload/c_mfit,h_1200,w_1200/f_auto/q_auto/wmmedia/watch_images/large/888066008457_1622124471.jpg', 'https://www.parfuemerie-godel.de/media/95/c0/a8/1737552097/888066008457.jpg?ts=1737639581']::text[], 'https://www.jomashop.com/tom-ford-neroli-portofino-eau-de-parfum-spray-888066008457.html', 254.99, 352.99, 'Combínalo con reloj plateado, camisa de lino blanca, pantalón beige y mocasines claros para un porte relajado.', 'https://morningkoffee.com/wp-content/uploads/2025/05/Comfy-summer-outfit-Tote-bag-@bonheur-.linenclothing-linenoutfit-summerstyles-bonheurbag-birkenstocks-pinstripes-linenshirt-linenpants-totebag-canvasbag-casualoutfit-summerlooks.jpg', ARRAY['mp-82a5b81520e1', 'mp-32f83814872c', 'mp-914b0e1da729']::text[], 'Para el verano, este look respira frescura: la camisa de lino, las espadrilles y el reloj azul transmiten ligereza sofisticada. El perfume huele a cítricos mediterráneos, neroli limpio y brisa marina; perfecto para almuerzo casual o paseo costero.', 'verano', ARRAY['mp-eb14c8e1c046', 'mp-771e0dce9f5f', 'mp-cbf5fd94f2da']::text[], 'Para ti, el tank de punto, las flats y el reloj en verde suave crean un verano pulido y relajado. El perfume es cítrico, luminoso y aireado, con neroli fresco; ideal para día libre, viaje o almuerzo al sol.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4935327f2485', 'theoutnet', 'ton-46376663163103690', 'Sebastian Linen Jersey Polo Shirt', 'Orlebar Brown', 'clothing', 'men', 'Polo de lino jersey con tacto ligero y línea limpia.', 'https://www.theoutnet.com/variants/images/46376663163103690/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163103690/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103690/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103690/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103690/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103690/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/polo-shirts/sebastian-linen-jersey-polo-shirt/46376663163103690', 255, 352.99, 'Acompáñalo con reloj de acero, perfume marino y pantalón blanco o navy con loafers.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-162803429493', 'mp-056301398a15', 'mp-0de6cc427e14']::text[], 'Polo de lino, sandalias y un reloj negro crean un conjunto fresco y pulido para verano en la ciudad o escapada costera. Acqua di Gio Parfum refuerza la impresión con notas marinas, limpias y sobrias.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EX