INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-056301398a15', 'jomashop', 'SE-SRPD65K1', 'Seiko 5 Sports Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Negro total y estética robusta, un básico moderno con presencia contenida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-sports-automatic-black-dial-mens-watch-srpd65k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-sports-automatic-black-dial-mens-watch-srpd65k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-sports-automatic-black-dial-mens-watch-srpd65k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-5-sports-automatic-black-dial-mens-watch-srpd65k1_3.jpg', 'https://assets.gadgetandgear.com/upload/media/seiko-5-srpd65k1-sports-black-dial-automatic-mens-wrist-watch747.jpeg', 'https://assets.gadgetandgear.com/upload/media/seiko-5-srpd65k1-sports-black-dial-automatic-mens-wrist-watch-1636.jpeg', 'https://seikowatches.cdn.imgeng.in/s/files/1/0322/8424/6155/products/SRPD65K1_2.png?v=1586761235']::text[], 'https://www.jomashop.com/seiko-seiko-5-sports-automatic-black-dial-mens-watch-srpd65k1.html', 255.55, 353.99, 'Combínalo con denim índigo, camiseta blanca, zapatillas negras y perfume fresco amaderado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-82a5b81520e1', 'mp-1b60c92c78b6', 'mp-6a32aace5e0a']::text[], 'La camisa de lino y las Bally acompañan el Seiko con discreción contemporánea. Neroli Sauvage añade cítricos luminosos y un fondo elegante, ideal para un almuerzo de negocios o una tarde de verano.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6deb07156c23', 'jomashop', 'SE-SRPK99K1', 'Seiko 5 Sports SKX Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Inspirado en el SKX, con esfera negra y carácter deportivo de línea limpia.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-automatic-black-dial-mens-watch-srpk99k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-automatic-black-dial-mens-watch-srpk99k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-automatic-black-dial-mens-watch-srpk99k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-automatic-black-dial-mens-watch-srpk99k1_3.jpg', 'https://www.strapseeker.com/cdn/shop/files/sssgid.zone-1717657996-SRPK99K1__1.png?v=1733818428&width=1200', 'https://timeaccess-store.com/cdn/shop/files/SRPK99K1e.jpg?v=1723121755&width=960', 'https://www.strapseeker.com/cdn/shop/files/sssgid.zone-1717657995-SRPK99K1__2.png?v=1733818428&width=1200']::text[], 'https://www.jomashop.com/seiko-5-sports-skx-automatic-black-dial-mens-watch-srpk99k1.html', 255.55, 353.99, 'Úsalo con polo gris, cargo beige, sneakers sobrias y perfume marino para un look relajado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-c9d5f9473c8d', 'mp-e886cd56a6d2', 'mp-8d5bb353d59a']::text[], 'Los shorts de lino y las sneakers Tod’s mantienen el SKX en clave relajada pero cuidada. Neroli Portofino suma frescura mediterránea, limpia y brillante, ideal para un fin de semana o paseo al aire libre.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-914b0e1da729', 'jomashop', 'CZNJ0150-81L', 'Tsuyosa Automatic Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Azul brillante y brazalete pulido, un reloj contemporáneo con gesto elegante.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/s/tsuyosa-automatic-blue-dial-mens-watch-nj015081l.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/s/tsuyosa-automatic-blue-dial-mens-watch-nj015081l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/s/tsuyosa-automatic-blue-dial-mens-watch-nj015081l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/s/tsuyosa-automatic-blue-dial-mens-watch-nj015081l_3.jpg', 'https://chronospride.com.au/wp-content/uploads/2023/06/NJ0150-81L-4.png', 'https://cdnstatic.creationwatches.com/products/product-images/l/NJ0150-81L_LRG.webp', 'https://cdnstatic.creationwatches.com/products/product-images/l/NJ0150-81L_3_LRG.webp', 'https://watchzonebd.com/uploads/multiimage/NJ0150-81L-1 (4)_660287e28a0b8.webp']::text[], 'https://www.jomashop.com/citizen-automatic-blue-dial-mens-watch-nj0150-81l.html', 255.55, 353.99, 'Combínalo con camisa celeste, pantalón blanco, loafers claros y perfume acuático discreto.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-c1386c461b8d', 'mp-1b60c92c78b6', 'mp-605a39d82c0f']::text[], 'El pantalón texturizado y las Bally elevan el azul del Tsuyosa con sobriedad moderna. Luna Rossa Carbon aporta una estela aromática, fresca y ligeramente mineral, perfecta para oficina creativa o reunión casual.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-fb6574f56522', 'jomashop', 'CZNJ0150-81X', 'Tsuyosa Automatic Green Dial Watch', 'Citizen', 'watch', 'unisex', 'Verde intenso y acabado refinado, una pieza actual con personalidad serena.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-green-dial-watch-nj015081x.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-green-dial-watch-nj015081x.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-green-dial-watch-nj015081x_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-green-dial-watch-nj015081x_3.jpg', 'https://www.citywatches.co.za/wp-content/uploads/2023/08/NJ0150-81X_3.jpg', 'https://mzwatcheslk.com/cdn/shop/files/Citizen-Automatic-NJ0150-81X-5_1080x1080.webp?v=1686395408', 'https://watchzonebd.com/uploads/product/NJ0150-81X-1 (3)_6602874e8a658.webp', 'https://timeaccess-store.com/cdn/shop/files/NJ0150-81Xb.jpg?v=1697031658']::text[], 'https://www.jomashop.com/citizen-automatic-green-dial-watch-nj0150-81x.html', 255.55, 353.99, 'Llévalo con knit crema, pantalón oliva, mocasines marrones y perfume amaderado verde.', 'https://lifewithjazz.com/wp-content/uploads/2022/04/5-Smart-Casual-Outfits-Last-picture.jpg', ARRAY['mp-82a5b81520e1', 'mp-e886cd56a6d2', 'mp-605a39d82c0f']::text[], 'Para ti, la camisa de lino, las sneakers limpias y el reloj verde forman un casual sobrio y muy actual. El perfume aporta un perfil aromático fresco y amaderado, perfecto para trabajo relajado, brunch o salida de día.', 'casual', ARRAY['mp-eb14c8e1c046', 'mp-a817148e69da', 'mp-8d5bb353d59a']::text[], 'Para una mujer de estilo discreto, el tank de punto, las sneakers depuradas y el reloj verde construyen un look relajado pero fino. El perfume es cítrico y luminoso, ideal para día a día, viaje o media estación.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6819f676b738', 'jomashop', 'CZNJ0151-88L', 'Tsuyosa Automatic Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Azul profundo con caja pulida, una lectura limpia para estilo diario distinguido.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-blue-dial-mens-watch-nj015188l.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-blue-dial-mens-watch-nj015188l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-blue-dial-mens-watch-nj015188l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-blue-dial-mens-watch-nj015188l_3.jpg', 'https://watchzonebd.com/uploads/multiimage/NJ0151-88L-4_651d5a00d141d.webp', 'https://cdnstatic.creationwatches.com/products/product-images/l/NJ0151-88L_3_LRG.webp', 'https://cdnstatic.creationwatches.com/products/product-images/l/NJ0151-88L_LRG.webp']::text[], 'https://www.jomashop.com/citizen-automatic-blue-dial-mens-watch-nj0151-88l.html', 255.55, 353.99, 'Combínalo con camisa blanca, blazer gris, derby café y perfume cítrico amaderado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-9913fefbdf00', 'mp-1b60c92c78b6', 'mp-2dc2d5978672']::text[], 'Polo de lino y sneakers Bally acompañan el azul del Tsuyosa con equilibrio y ligereza. Eau Sauvage aporta cítricos nobles y una elegancia clásica, perfecta para un día de oficina relajada o brunch.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
