 reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-99e03e110973', 'theoutnet', 'ton-46376663163084108', 'Mid Length Striped Seersucker Swim Shorts', 'Thom Browne', 'clothing', 'men', 'Short de baño a rayas con proporción precisa y aire náutico refinado.', 'https://www.theoutnet.com/variants/images/46376663163084108/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163084108/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163084108/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163084108/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163084108/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163084108/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/swimwear-beachwear/swim-shorts/mid-length-striped-seersucker-swim-shorts/46376663163084108', 256, 353.99, 'Combínalo con reloj deportivo fino, perfume fresco y camisa de lino azul con slides.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-162803429493', 'mp-5744d9813fec', 'mp-0de6cc427e14']::text[], 'Las sandalias y el reloj de buceo refuerzan el carácter náutico de estos swim shorts para playa o piscina. Acqua di Gio Parfum aporta frescura marina, limpia y elegante, sin exceso.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1b60c92c78b6', 'theoutnet', 'ton-46376663163153942', 'Genk Striped Leather And Suede Sneakers', 'Bally', 'shoes', 'men', 'Sneakers de cuero y gamuza con rayas discretas, versátiles y bien resueltas.', 'https://www.theoutnet.com/variants/images/46376663163153942/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163153942/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153942/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153942/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153942/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153942/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/sneakers/fashion-sneakers/genk-striped-leather-and-suede-sneakers/46376663163153942', 256, 353.99, 'Úsalas con reloj plateado, perfume verde y denim oscuro con camisa blanca impecable.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-c1386c461b8d', 'mp-056301398a15', 'mp-2dc2d5978672']::text[], 'El pantalón de lino y el Seiko en negro dejan que las Bally luzcan con discreción moderna. Eau Sauvage completa con cítricos clásicos, ideal para oficina relajada o un almuerzo de temporada.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d3e6bc0a0b08', 'jomashop', 'SE-SRPL55K1', 'Seiko 5 Sports Automatic Blue Dial Watch', 'Seiko', 'watch', 'unisex', 'Azul limpio y silueta deportiva, un clásico fácil de integrar con elegancia.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-blue-dial-watch-srpl55k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-blue-dial-watch-srpl55k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-blue-dial-watch-srpl55k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-blue-dial-watch-srpl55k1_3.jpg', 'https://watches.uhrzeit.org/bilder/produkte/uhren/Seiko/SRPL55K1/raw3.jpg', 'https://www.citychain.com.sg/cdn/shop/files/seiko-5-sports-snxs-blue-srpl55k1-angle.jpg?v=1778331061&width=1080']::text[], 'https://www.jomashop.com/seiko-5-sports-automatic-blue-dial-watch-srpl55k1.html', 257.59, 355.99, 'Combínalo con camisa de lino, chino beige, loafers y perfume fresco amaderado para equilibrio discreto.', 'https://lifewithjazz.com/wp-content/uploads/2022/04/5-Smart-Casual-Outfits-Last-picture.jpg', ARRAY['mp-c1386c461b8d', 'mp-1b60c92c78b6', 'mp-2dc2d5978672']::text[], 'Para ti, el azul del reloj se complementa con tonos suaves y texturas ligeras; las sneakers ordenan el conjunto con un aire limpio. El perfume es clásico, cítrico y fresco, ideal para verano, oficina informal o fin de semana.', 'casual', ARRAY['mp-e80799294eb5', 'mp-a817148e69da', 'mp-8d5bb353d59a']::text[], 'Para ti, la camisa popelina, las sneakers sobrias y el reloj limpio crean un look actual y sin esfuerzo. El resultado es perfecto para oficina creativa o fin de semana; funciona especialmente bien en climas cálidos.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-58072ada40a0', 'jomashop', 'Z-C3LEU', 'Tom Ford Unisex Tuscan Leather EDP Spray 3.4 oz Private Blend', 'Tom Ford', 'perfume', 'women', 'Cuero cálido y profundo, con una estela intensa que deja una impresión refinada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-tuscan-leather-edp-spray-3-4-oz-private-blend-888066004459.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-tuscan-leather-edp-spray-3-4-oz-private-blend-888066004459.jpg', 'https://mediafiles.maxaroma.com/9cd29e92-4b8f-436f-ad1f-8e368b30dc1d/https://www.maxaroma.com/productimages/large/UP888066004459_1.jpg?ver=1758904860', 'https://cdn2.jomashop.com/media/catalog/product/cache/b3e31d40bbb1abcc90b26106659d5d3f/t/o/tom-ford-unisex-tuscan-leather-edp-spray-34-oz-fragrances-888066004459.jpg?width=800&height=800', 'https://www.alluringauras.com/wp-content/uploads/2024/11/888066004459-2.jpg']::text[], 'https://www.jomashop.com/tom-ford-unisex-tuscan-leather-edp-spray-3-4-oz-fragrances-888066004459.html', 258.39, 356.99, 'Combínalo con reloj de acero oscuro, blazer negro y zapatos de cuero liso para un conjunto sobrio y magnético.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-270a92a68fd4', 'mp-9fca20b50d99', 'mp-69e7777fc13e']::text[], 'El vestido de punto equilibra la intensidad del Tuscan Leather con una silueta pulida; los sandalias suenan sofisticadas para cena o cóctel. El reloj negro refuerza el aire nocturno, mientras el perfume aporta cuero, ámbar y un fondo cálido.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-206b9657d86c', 'jomashop', 'CZNJ0150-81E', 'Citizen Tsuyosa Automatic Black Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Esfera negra y brazalete pulido, sobriedad moderna para todos los días.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-black-dial-mens-watch-nj015081e.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-black-dial-mens-watch-nj015081e.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-black-dial-mens-watch-nj015081e_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-black-dial-mens-watch-nj015081e_3.jpg', 'https://chronospride.com.au/wp-content/uploads/2023/06/NJ0150-81E-3.png', 'https://chronospride.com.au/wp-content/uploads/2023/06/NJ0150-81E-4.png', 'https://watchzonebd.com/uploads/product/NJ0150-81E-2 (1)_66029d6951380.webp', 'https://www.gioiellerialucchese.it/27572/citizen-nj0150-81e-tsuyosa-automatic-watch.jpg']::text[], 'https://www.jomashop.com/citizen-automatic-black-dial-mens-watch-nj0150-81e.html', 259, 357.99, 'Llévalo con polo blanco, pantalón gris, zapatillas de cuero negro y perfume aromático limpio.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-82a5b81520e1', 'mp-e886cd56a6d2', 'mp-605a39d82c0f']::text[], 'Con camisa de lino, pantalón liviano y zapatillas de cuero, el Tsuyosa negro gana presencia limpia y contemporánea. Ideal para un almuerzo o fin de semana urbano; si añades perfume, Neroli Portofino aporta frescura cítrica y elegante.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-79e0646195cd', 'jomashop', 'CZNJ0150-56A', 'Citizen Tsuyosa Automatic White Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Esfera blanca y presencia luminosa, una pieza versátil con estética serena.', 'https://citizenwatch.widen.net/content/uojupvefzh/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/uojupvefzh/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/qe3nxl5dmt/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/dbr7hmllok/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-white-dial-mens-watch-nj015056a_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-white-dial-mens-watch-nj015056a_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-white-dial-mens-watch-nj015056a_3.jpg']::text[], 'https://www.jomashop.com/citizen-tsuyosa-automatic-white-dial-mens-watch-nj0150-56a.html', 259, 357.99, 'Combínalo con blazer azul, camiseta ecru, mocasines café y perfume cítrico suave.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-82a5b81520e1', 'mp-e886cd56a6d2', 'mp-605a39d82c0f']::text[], 'La esfera blanca se integra con lino, pantalón claro y sneakers refinados, logrando un look pulido pero relajado. Funciona muy bien en Lima de día; con Neroli Sauvage, el cierre olfativo es limpio, fresco y sofisticado.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6cee80b5082f', 'theoutnet', 'ton-46376663163107983', 'Floral Print Woven Shirt', 'Jacquemus', 'clothing', 'men', 'Camisa floral con trazo delicado, luminosa y con gesto contemporáneo.', 'https://www.theoutnet.com/variants/images/46376663163107983/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163107983/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107983/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107983/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107983/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107983/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jacquemus/tops/casual-shirts/floral-print-woven-shirt/46376663163107983', 259, 357.99, 'Acompáñala con reloj delgado, perfume floral limpio y pantalón beige con mocasines claros.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-b9b2b677d2ef', 'mp-c27ae7cfc8ab', 'mp-24e01ce26ae0']::text[], 'La camisa floral pide espadrilles y un reloj claro con aire vacacional, equilibrando el conjunto sin perder elegancia. Perfecto para una cena de verano o viaje costero; Dolce Amalfi suma un perfil cítrico-especiado, luminoso y amable.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5592a0a5cff7', 'theoutnet', 'ton-46376663163125603', 'Out of Office Textured Leather Sneakers', 'Off-White', 'shoes', 'men', 'Sneakers de cuero con textura y firma contenida, urbanas y precisas.', 'https://www.theoutnet.com/variants/images/46376663163125603/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163125603/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125603/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125603/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125603/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125603/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-textured-leather-sneakers/46376663163125603', 259, 357.99, 'Combínalas con reloj sobrio, perfume amaderado y pantalón negro recto con camiseta blanca.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-82a5b81520e1', 'mp-206b9657d86c', 'mp-605a39d82c0f']::text[], 'Las texturas neutras y el cuero blanco crean una base sobria que mantiene el sneaker protagonista. Ideal para ciudad y fin de semana; con Dior Sauvage, el perfume aporta frescura aromática, moderna y masculina.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e4ca126bdb77', 'theoutnet', 'ton-46376663163125601', 'Out of Office Leather Sneakers', 'Off-White', 'shoes', 'men', 'Sneakers de cuero limpias y actuales, con una lectura silenciosa del streetwear.', 'https://www.theoutnet.com/variants/images/46376663163125601/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163125601/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125601/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125601/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125601/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125601/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-leather-sneakers/46376663163125601', 259, 357.99, 'Llévalas con reloj de acero, perfume fresco y pantalón gris claro con sobrecamisa cruda.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-82a5b81520e1', 'mp-206b9657d86c', 'mp-605a39d82c0f']::text[], 'Camisa de lino, pantalón de caída ligera y sneakers limpios construyen un lujo discreto y versátil. Funciona para un brunch o reunión informal; Eau Sauvage añade un sello cítrico, clásico y muy pulcro.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4783988ec6c3', 'jomashop', 'SE-SRPK97K1', 'Seiko 5 Sports SKX Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Azul intenso y ADN SKX, un reloj deportivo con líneas definidas y sobrias.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-automatic-blue-dial-mens-watch-srpk97k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-automatic-blue-dial-mens-watch-srpk97k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-automatic-blue-dial-mens-watch-srpk97k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-automatic-blue-dial-mens-watch-srpk97k1_3.jpg', 'https://www.auswatches.com/media/catalog/product/cache/f20a3dad9a18e1857a6578422466bfb5/s/r/srpk97k1_00.jpg', 'https://timeaccess-store.com/cdn/shop/files/SRPK97K1r4.jpg?v=1723121132&width=1000']::text[], 'https://www.jomashop.com/seiko-5-sports-skx-automatic-blue-dial-mens-watch-srpk97k1.html', 260, 358.99, 'Úsalo con camiseta gris, jeans oscuros, sneakers blancas y perfume marino amaderado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-762ca64e80bd', 'mp-e886cd56a6d2', 'mp-605a39d82c0f']::text[], 'El azul del reloj conversa con el polo y el pantalón ligero, mientras las sneakers suavizan el conjunto. Ideal para un plan de día o paseo costero; Luna Rossa Carbon encaja con un carácter limpio, mineral y moderno.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c0078fd78066', 'jomashop', 'CZNJ0150-56Z', 'Citizen Tsuyosa Automatic Men''s Watch', 'Citizen', 'watch', 'men', 'Acabado dorado suave y esfera limpia, para un estilo clásico con presencia discreta.', 'https://citizenwatch.widen.net/content/poujpqmksw/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/poujpqmksw/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/vcsv9dkvun/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/ksnesbupgd/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-mens-watch-nj015056z.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-mens-watch-nj015056z_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-mens-watch-nj015056z_3.jpg']::text[], 'https://www.jomashop.com/citizen-tsuyosa-automatic-mens-watch-nj0150-56z.html', 260.3, 358.99, 'Combínalo con camisa azul claro, pantalón marino, loafers negros y perfume especiado ligero.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-82a5b81520e1', 'mp-e886cd56a6d2', 'mp-605a39d82c0f']::text[], 'La caja dorada del Tsuyosa se realza con lino natural, pantalón claro y zapatillas sobrias. Muy acertado para almuerzo elegante o after office; Neroli Portofino aporta brillo cítrico, elegante y mediterráneo.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4d86b13e4f03', 'jomashop', 'CZNJ0150-56X', 'Citizen Tsuyosa Automatic Men''s Watch', 'Citizen', 'watch', 'men', 'Brazalete tono champagne y diseño atemporal, una pieza sutilmente distinguida.', 'https://citizenwatch.widen.net/content/c155b5cxmk/webp/TSUYOSA.webp?u=41zuoe&width=1600&height=2000&quality=80&crop=false&keep=c&color=FFFFFF00', ARRAY['https://citizenwatch.widen.net/content/c155b5cxmk/webp/TSUYOSA.webp?u=41zuoe&width=1600&height=2000&quality=80&crop=false&keep=c&color=FFFFFF00', 'https://citizenwatch.widen.net/content/f4rwdrug66/webp/TSUYOSA.webp?u=41zuoe&width=1600&height=2000&quality=80&crop=false&keep=c&color=FFFFFF00', 'https://citizenwatch.widen.net/content/vcsv9dkvun/webp/TSUYOSA.webp?u=41zuoe&width=1600&height=2000&quality=80&crop=false&keep=c&color=FFFFFF00', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp/TSUYOSA.webp?u=41zuoe&width=1600&height=2000&quality=80&crop=false&keep=c&color=FFFFFF00', 'https://citizenwatch.widen.net/content/lbzgtopwjw/webp/TSUYOSA.webp?u=41zuoe&width=1600&height=2000&quality=80&crop=false&keep=c&color=FFFFFF00', 'https://citizenwatch.widen.net/content/6ajoaq7hlg/webp/TSUYOSA.webp?u=41zuoe&width=1600&height=2000&quality=80&crop=false&keep=c&color=FFFFFF00', 'https://citizenwatch.widen.net/content/nlbdtixmyx/webp/TSUYOSA.webp?u=41zuoe&width=1600&height=2000&quality=80&crop=false&keep=c&color=FFFFFF00']::text[], 'https://www.jomashop.com/citizen-tsuyosa-automatic-mens-watch-nj0150-56x.html', 260.3, 358.99, 'Llévalo con suéter crema, pantalón carbón, zapatos de cuero y perfume amaderado suave.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-82a5b81520e1', 'mp-e886cd56a6d2', 'mp-605a39d82c0f']::text[], 'El tono salmón del reloj se equilibra con lino neutro y sneakers de cuero, logrando un efecto fresco y refinado. Perfecto para día a día con intención; Neroli Sauvage suma salida cítrica, limpia y sofisticada.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c3ffd1b66ff9', 'theoutnet', 'ton-46376663163125608', 'Out of Office Leather Sneakers', 'Off-White', 'shoes', 'men', 'Sneakers de cuero de líneas limpias, pensadas para un uso urbano y elegante.', 'https://www.theoutnet.com/variants/images/46376663163125608/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163125608/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125608/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125608/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125608/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125608/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-leather-sneakers/46376663163125608', 260, 358.99, 'Combínalas con reloj minimalista, perfume cítrico y denim oscuro con jersey beige fino.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-82a5b81520e1', 'mp-4783988ec6c3', 'mp-605a39d82c0f']::text[], 'Las sneakers blancas funcionan mejor con lino, pantalón liviano y siluetas limpias, elevando un casual impecable. Ideal para oficina relajada o viaje; Eau Sauvage refuerza el conjunto con frescura clásica, nítida y elegante.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLU