INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e518f29b87d4', 'theoutnet', 'ton-46376663163159132', 'Air Pegasus 2k5 Mesh Sneakers', 'Nike', 'shoes', 'men', 'Sneakers de malla con perfil ágil y lectura moderna para ritmo diario.', 'https://www.theoutnet.com/variants/images/46376663163159132/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163159132/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159132/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159132/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159132/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159132/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159132/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/air-pegasus-2k5-mesh-sneakers/46376663163159132', 262, 360.99, 'Llévalas con reloj deportivo, perfume fresco y joggers negros o denim recto con hoodie limpio.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-3240465564d7', 'mp-c3c82fdede97']::text[], 'Las Pegasus encajan con jersey técnico, reloj sporty y una fragancia dinámica para un total look activo. Perfecto para ciudad y movimiento; Sauvage EDP aporta frescura intensa, especiada y enérgica.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_