INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-db3e96bd55d9', 'jomashop', 'COS-CLWES25', 'Creed Ladies Creed Love In White EDP Spray 2.5 oz', 'Creed', 'perfume', 'women', 'Un floral luminoso con faceta limpia y delicada, de presencia femenina y serena.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-ladies-creed-love-in-white-edp-spray-2-5-oz-fragrances-3508441104617_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-ladies-creed-love-in-white-edp-spray-2-5-oz-fragrances-3508441104617_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-ladies-creed-love-in-white-edp-spray-25-oz-fragrances-3508441104617_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-ladies-creed-love-in-white-edp-spray-25-oz-fragrances-3508441104617_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-ladies-creed-love-in-white-edp-spray-25-oz-fragrances-3508441104617_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-ladies-creed-love-in-white-edp-spray-25-oz-fragrances-3508441104617_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/9d6243d99187096e972f05545e39058c/c/r/creed-ladies-creed-love-in-white-edp-spray-25-oz-fragrances-3508441104617.jpg', 'https://facescr.vtexassets.com/arquivos/ids/175696/3508441104617_2.JPG.jpg?v=637998191417770000']::text[], 'https://www.jomashop.com/creed-clwes25.html', 262.99, 362.99, 'Acompáñalo con reloj delgado, vestido marfil, tacones nude y accesorios en tonos perla.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-3968aa79d4f8', 'mp-95ac9c8c22b8', 'mp-c798e1926e9d']::text[], 'El mini dress de Tom Ford y los pumps crean una línea femenina y luminosa, perfecta para un evento elegante. El PRX en madreperla aporta brillo sutil; Love In White acompaña con flores blancas, frescas y pulidas.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4f0005c3f8c7', 'theoutnet', 'ton-46376663163023762', 'Mid Length Printed Swim Shorts', 'Frescobol Carioca', 'clothing', 'men', 'Bañador estampado de largo medio, relajado y pulido, ideal para escapadas junto al mar.', 'https://www.theoutnet.com/variants/images/46376663163023762/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163023762/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023762/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023762/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023762/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023762/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/swimwear-beachwear/swim-shorts/mid-length-printed-swim-shorts/46376663163023762', 263, 362.99, 'Combínalo con reloj de acero, perfume cítrico y camisa blanca de lino, más sandalias de cuero tostado.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-162803429493', 'mp-5744d9813fec', 'mp-0de6cc427e14']::text[], 'El swim short pide sandalias discretas y un reloj de perfil acuático para un conjunto coherente de playa. Ideal para piscina o club de verano; Acqua di Gio Parfum suma frescura marina, limpia y luminosa.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-cea25765c0c4', 'theoutnet', 'ton-46376663163096280', 'Floral Print Woven Shirt', 'Onia', 'clothing', 'men', 'Camisa tejida con estampado floral, fresca y expresiva, pensada para días luminosos con carácter.', 'https://www.theoutnet.com/variants/images/46376663163096280/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096280/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096280/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096280/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096280/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096280/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/tops/casual-shirts/floral-print-woven-shirt/46376663163096280', 263, 362.99, 'Llévala con reloj delgado, perfume acuático y pantalón crudo; completa con mocasines o alpargatas de piel.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-162803429493', 'mp-5744d9813fec', 'mp-37af76f7012d']::text[], 'La camisa floral se apoya mejor en sandalias sobrias y reloj con guiño náutico, logrando frescura sin exceso. Perfecto para escapadas o almuerzo junto al mar; The Last Day Of Summer aporta un carácter verde y tranquilo.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-09471a395abf', 'theoutnet', 'ton-46376663163096282', 'Printed Woven Shirt', 'Onia', 'clothing', 'men', 'Camisa tejida estampada, ligera y contemporánea, aporta presencia discreta a looks de clima cálido.', 'https://www.theoutnet.com/variants/images/46376663163096282/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096282/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096282/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096282/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096282/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096282/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/tops/casual-shirts/printed-woven-shirt/46376663163096282', 263, 362.99, 'Úsala con reloj minimalista, perfume amaderado suave y chinos beige; suma zapatillas de cuero blanco.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-371303f8ebbb', 'mp-4783988ec6c3', 'mp-0de6cc427e14']::text[], 'Para un día de verano, elige espadrilles de ante, reloj azul y Acqua di Gio: una combinación fresca, pulida y relajada. La camisa estampada gana equilibrio con tonos marinos y un perfume cítrico-marino, limpio y luminoso.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-270a92a68fd4', 'theoutnet', 'ton-46376663162965166', 'Knitted Midi Dress', 'Tom Ford', 'clothing', 'women', 'Vestido midi de punto, sobrio y envolvente, con una silueta refinada para ocasiones especiales.', 'https://www.theoutnet.com/variants/images/46376663162965166/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162965166/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162965166/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162965166/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162965166/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162965166/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/dresses/midi-dresses/knitted-midi-dress/46376663162965166', 264, 363.99, 'Acompáñalo con reloj joya discreto, perfume ámbar y sandalias negras finas, en tonos carbón o marfil.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-95ac9c8c22b8', 'mp-c798e1926e9d', 'mp-57625857aaaa']::text[], 'El vestido de punto pide un zapato fino y un reloj limpio para oficina o cena sobria en invierno. Libre Intense suma un perfil cálido, floral y ambarado, acorde a una presencia femenina y precisa.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2208bf601ddb', 'theoutnet', 'ton-46376663162871435', 'Embossed Glossed Leather Loafers', 'Ferragamo', 'shoes', 'women', 'Loafers de cuero brillante y textura marcada, sobrios y perfectos para un vestir pulcro.', 'https://www.theoutnet.com/variants/images/46376663162871435/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162871435/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162871435/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162871435/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162871435/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162871435/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/flat-shoes/loafers/embossed-glossed-leather-loafers/46376663162871435', 264, 363.99, 'Úsalos con traje gris, reloj clásico, camisa blanca y perfume cítrico amaderado para un look ejecutivo.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-754d371ec329', 'mp-c798e1926e9d', 'mp-db3e96bd55d9']::text[], 'El pantalón amplio y el PRX de madreperla refuerzan la elegancia discreta del mocasín, ideal para oficina. Love In White añade un halo floral limpio y refinado, perfecto para un conjunto de lujo silencioso.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9a8a8745a068', 'theoutnet', 'ton-46376663163096284', 'French Cotton Blend Terry Hoodie', 'Onia', 'clothing', 'men', 'Hoodie de felpa mezclada, suave y limpio, eleva el descanso con una línea relajada.', 'https://www.theoutnet.com/variants/images/46376663163096284/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096284/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096284/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096284/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096284/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096284/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/tops/hoodies-zip-throughs/french-cotton-blend-terry-hoodie/46376663163096284', 264, 363.99, 'Con reloj deportivo fino, perfume maderoso y joggers taupe; remata con zapatillas blancas impecables.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-1b60c92c78b6', 'mp-4d86b13e4f03', 'mp-aa752fde5755']::text[], 'Para invierno, este hoodie va mejor con sneakers sobrias, reloj de acero y Dior Homme Intense: un conjunto urbano y refinado. La fragancia aporta iris, cacao y maderas suaves, ideal para un look casual con presencia.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7e23b3ff7cda', 'theoutnet', 'ton-46376663163023765', 'Mid Length Printed Swim Shorts', 'Frescobol Carioca', 'clothing', 'men', 'Bañador estampado de largo medio, versátil y fresco, para un estilo de playa bien resuelto.', 'https://www.theoutnet.com/variants/images/46376663163023765/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163023765/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023765/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023765/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023765/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023765/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/swimwear-beachwear/swim-shorts/mid-length-printed-swim-shorts/46376663163023765', 264, 363.99, 'Combínalo con reloj náutico, perfume cítrico y camisa de lino celeste; añade sandalias beige.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-162803429493', 'mp-5744d9813fec', 'mp-8d5bb353d59a']::text[], 'Para playa o piscina, las sandalias ligeras, el reloj de buceo y Neroli Portofino crean un look impecable. La fragancia es cítrica, aromática y solar; acompaña con naturalidad los swim shorts estampados sin perder elegancia.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-177361511fc4', 'theoutnet', 'ton-46376663163137919', 'Out of Office Leather Sneakers', 'Off-White', 'shoes', 'men', 'Zapatillas de cuero con diseño limpio, modernas y discretas, fáciles de integrar a diario.', 'https://www.theoutnet.com/variants/images/46376663163137919/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163137919/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163137919/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163137919/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163137919/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163137919/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-leather-sneakers/46376663163137919', 264, 363.99, 'Úsalas con reloj de brazalete, perfume limpio y pantalón recto gris; arriba, polo blanco o camisa azul.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-655fabea4d8c', 'mp-28a4b97e6968', 'mp-605a39d82c0f']::text[], 'Para un look de lujo silencioso, combina las sneakers con camisa de lino, reloj de acero y Luna Rossa Carbon. El resultado es limpio y moderno; perfecto para una salida casual con aire sofisticado y fresco.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e95f260e6b61', 'jomashop', 'CZBN0191-55L', 'Citizen Promaster Diver 200 Meters Eco-Drive Blue Dial Steel Men''s Watch', 'Citizen', 'watch', 'men', 'Buzo de buceo con esfera azul, robustez clara para un uso activo y refinado.', 'https://citizenwatch.widen.net/content/yph940eeal/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/yph940eeal/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/faeig5qpl9/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/aidemkcqbw/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iv1z6lnskv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-diver-200-meters-ecodrive-blue-dial-steel-mens-watch-bn019155l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-diver-200-meters-ecodrive-blue-dial-steel-mens-watch-bn019155l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-diver-200-meters-ecodrive-blue-dial-steel-mens-watch-bn019155l_3.jpg']::text[], 'https://www.jomashop.com/citizen-watch-bn0191-55l.html', 265.05, 364.99, 'Combínalo con polo técnico blanco, pantalón chino gris, zapatillas marinas y perfume acuático limpio.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-1957de84ee3b', 'mp-6abb16f437af', 'mp-21708b443c49']::text[], 'Para un estilo deportivo premium, el hoodie ligero, las sneakers técnicas y Acqua di Gio Profondo encajan perfecto. La fragancia es acuática, mineral y fresca; ideal para fines de semana activos y un perfil discreto.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
