INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-10655f81e9b0', 'theoutnet', 'ton-46376663163023768', 'Mid Length Printed Swim Shorts', 'Frescobol Carioca', 'clothing', 'men', 'Bañador estampado de largo medio, ligero y refinado, suma color sin perder sobriedad.', 'https://www.theoutnet.com/variants/images/46376663163023768/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163023768/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023768/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023768/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023768/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163023768/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/swimwear-beachwear/swim-shorts/mid-length-printed-swim-shorts/46376663163023768', 265, 364.99, 'Llévalo con reloj náutico, perfume marino y polo blanco; termina con sandalias de cuero miel.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-28a4b97e6968', 'mp-0de6cc427e14', 'mp-162803429493']::text[], 'Para playa o fin de semana, los swim shorts, el reloj blanco de acero y Acqua di Gio Parfum forman un look fresco y pulido. La fragancia aporta carácter marino y limpio, ideal para verano con discreta elegancia.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-61afdf9a070e', 'jomashop', 'Z-3WRB4', 'Xerjoff Unisex V Accento Overdose EDP Spray 3.4 oz', 'Xerjoff', 'perfume', 'unisex', 'Un perfume vibrante y envolvente, con salida luminosa y fondo sofisticado.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-accento-overdose-edp-spray-3-4-oz-fragrances-8033488159016.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-accento-overdose-edp-spray-3-4-oz-fragrances-8033488159016.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-v-accento-overdose-edp-spray-34-oz-fragrances-8033488159016_2.jpg', 'https://i5.walmartimages.com/seo/Xerjoff-Unisex-V-Accento-Overdose-EDP-Spray-3-4-oz-Fragrances-8033488159016_c6555ba0-cd8c-4fca-935a-669a255b7dae.81ca5e9344ee9ddfae5231a4f8bb6e93.jpeg', 'https://www.maxaroma.com/productimages/large/UP8033488159016_2.jpg?ver=1727147088', 'https://cdn.notinoimg.com/social/xerjoff/8033488159016_01-o/accento-overdose___220713.jpg', 'https://cdn.notinoimg.com/detail_main_mq/xerjoff/8033488159016_01-o/accento-overdose___220713.jpg']::text[], 'https://www.jomashop.com/xerjoff-sospiro-accento-overdose-eau-de-parfum-spray-3-4-oz-8033488159016.html', 265.7, 365.99, 'Llévalo con reloj de acero, blazer azul noche, camisa marfil y zapatos negros de piel pulida.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-76e86cc39c9a', 'mp-a1a9c18f6ebe', 'mp-23af6e30e1cc']::text[], 'Para una noche elegante, acompaña el perfume con pantalón de paño, mocasines de piel y Presage azul. La mezcla es sofisticada y cálida; el perfume proyecta fruta madura, oud suave y un aura lujosa.', 'noche', ARRAY['mp-270a92a68fd4', 'mp-95ac9c8c22b8', 'mp-a88c1eb55d5a']::text[], 'Para una noche elegante, el vestido de punto, los pumps y el PRX nácar crean una imagen refinada y femenina. La fragancia es intensa, frutal-ambarada y seductora; perfecta para cena, evento o cocktail.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-95ac9c8c22b8', 'theoutnet', 'ton-46376663163045874', 'Angelina Cutout Buckle Detailed Leather Pumps', 'Tom Ford', 'shoes', 'women', 'Pumps de cuero con calado y hebilla, aportan un acento sofisticado y seguro.', 'https://www.theoutnet.com/variants/images/46376663163045874/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163045874/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163045874/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163045874/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163045874/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163045874/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/pumps/high-heel-pumps/angelina-cutout-buckle-detailed-leather-pumps/46376663163045874', 267, 367.99, 'Acompáñalos con reloj fino, perfume floral intenso y vestido negro; prefiera joyería mínima y tonos nude.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-3968aa79d4f8', 'mp-c798e1926e9d', 'mp-501275d9ea5c']::text[], 'El mini dress de Tom Ford y el PRX de madreperla equilibran brillo y sobriedad para una noche elegante. Wild Leather aporta cuero, especias y un fondo cálido, perfecto para acompañar el aire sensual del zapato.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ea636a1de366', 'theoutnet', 'ton-46376663163091276', 'Angelo Linen Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Camisa de lino, fresca y natural, aporta elegancia relajada con un aire atemporal.', 'https://www.theoutnet.com/variants/images/46376663163091276/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163091276/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091276/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091276/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091276/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091276/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/casual-shirts/angelo-linen-shirt/46376663163091276', 267, 367.99, 'Con reloj de piel, perfume cítrico y pantalón de algodón arena; suma mocasines o alpargatas.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-69ef4764b1ae', 'mp-48e0815f97a3', 'mp-9d3a106a46fc']::text[], 'Para verano, el lino, las espadrilles y Silver Mountain Water logran un lujo silencioso muy limpio. La fragancia es fresca, verde y ligeramente almizclada; ideal para clima cálido, almuerzos frente al mar o escapadas.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a3c07033dec1', 'theoutnet', 'ton-46376663163111947', 'Horton Jacquard Knit Silk And Cotton Blend Polo Shirt', 'Orlebar Brown', 'clothing', 'men', 'Polo de seda y algodón, con textura sutil y presencia marina, ideal para días pulidos.', 'https://www.theoutnet.com/variants/images/46376663163111947/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163111947/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111947/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111947/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111947/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111947/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/polo-shirts/horton-jacquard-knit-silk-and-cotton-blend-polo-shirt/46376663163111947', 268, 368.99, 'Combínalo con reloj fino, perfume fresco y pantalón blanco; añade mocasines de gamuza en azul marino.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-3c75f66f94e0', 'mp-23af6e30e1cc', 'mp-9d3a106a46fc']::text[], 'Para un verano elegante, el polo de seda pide mocasines de terciopelo, Presage azul y Silver Mountain Water. El conjunto es sofisticado sin esfuerzo; ideal para cena o evento diurno con un toque fresco y pulcro.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-de9b3bac8274', 'theoutnet', 'ton-46376663163074845', 'Printed Crepe Shirt', 'Sandro', 'clothing', 'men', 'Camisa crepé estampada, ligera y expresiva, suma un gesto refinado al vestuario diario.', 'https://www.theoutnet.com/variants/images/46376663163074845/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163074845/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074845/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074845/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074845/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074845/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/sandro/tops/casual-shirts/printed-crepe-shirt/46376663163074845', 268, 368.99, 'Llévala con reloj minimalista, perfume amaderado y pantalón sastre beige; completa con loafers de cuero.', 'https://images.stockcake.com/public/e/f/1/ef1cb030-ed89-4a00-af5d-cf1485e9e655_large/elegant-men-s-fashion-stockcake.jpg', ARRAY['mp-3c75f66f94e0', 'mp-69df0685227c', 'mp-337d48edab34']::text[], 'Para un plan elegante-casual, la camisa estampada funciona con mocasines, PRX azul y Acqua di Gio Parfum. Equilibras textura y brillo con un perfume marino y amaderado, perfecto para cena o after office.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-28a4b97e6968', 'jomashop', 'CZNJ0150-81A', 'Citizen Tsuyosa Automatic White Dial Stainless Steel Men''s Watch', 'Citizen', 'watch', 'men', 'Esfera blanca y caja de acero en un diseño limpio, versátil y atemporal.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-white-dial-stainless-steel-mens-watch-nj015081a.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-white-dial-stainless-steel-mens-watch-nj015081a.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-white-dial-stainless-steel-mens-watch-nj015081a_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-white-dial-stainless-steel-mens-watch-nj015081a_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-white-dial-stainless-steel-mens-watch-nj015081a_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/fc2ff48f80400416c47c36b80c0a3202/o/p/open-box-citizen-tsuyosa-automatic-white-dial-stainless-steel-mens-watch-nj015081a_4.jpg?width=546&height=546', 'https://assets.jamtangan.com/images/product/citizen/NJ0150-81A/1l_800x800.jpg']::text[], 'https://www.jomashop.com/citizen-automatic-white-dial-stainless-steel-mens-watch-nj0150-81a.html', 269, 369.99, 'Úsalo con camisa celeste, chino gris, mocasines café y un perfume amaderado suave.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-6a03b9633ec5', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'Para oficina, el reloj Tsuyosa combina con pantalón de lana ligera, mocasines y Grey Vetiver. El resultado es sobrio y moderno; ideal para trabajo diario, con una fragancia seca, elegante y muy limpia.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-53c9144c0d39', 'jomashop', 'CZNJ0150-56L', 'Citizen Tsuyosa Automatic Men''s Watch', 'Citizen', 'watch', 'men', 'Un azul profundo y pulido que aporta carácter sereno a cualquier día.', 'https://citizenwatch.widen.net/content/thxpu5c2rt/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/thxpu5c2rt/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/vcsv9dkvun/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/qhr0rjdfs1/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-mens-watch-nj015056l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-mens-watch-nj015056l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-mens-watch-nj015056l_3.jpg']::text[], 'https://www.jomashop.com/citizen-tsuyosa-automatic-mens-watch-nj0150-56l.html', 269, 369.99, 'Combínalo con camisa blanca, blazer arena, pantalón oscuro y sneakers de cuero blanco.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-6e4425667ee2', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'Para una jornada de oficina o un almuerzo sobrio: camisa Oxford impecable, loafers pulidos y Grey Vetiver, de perfil limpio y seco, realzan el azul del reloj con discreta elegancia.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9afb99c96150', 'theoutnet', 'ton-46376663163096290', 'Printed Woven Shirt', 'Onia', 'clothing', 'men', 'Camisa tejida estampada, fresca y vibrante, aporta textura y movimiento a conjuntos relajados.', 'https://www.theoutnet.com/variants/images/46376663163096290/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096290/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096290/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096290/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096290/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096290/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/tops/casual-shirts/printed-woven-shirt/46376663163096290', 269, 369.99, 'Úsala con reloj de acero, perfume cítrico y shorts de lino; remata con zapatillas blancas o sandalias.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-162803429493', 'mp-28a4b97e6968', 'mp-8d5bb353d59a']::text[], 'Para un día de verano, la camisa estampada funciona con sandalias limpias y un reloj ligero; Neroli Portofino aporta cítricos y neroli, fresco y luminoso, ideal para un look relajado pero refinado.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6abb16f437af', 'theoutnet', 'ton-46376663163158860', 'M1000 Embroidered Leather And Mesh Sneakers', 'New Balance', 'shoes', 'men', 'Zapatillas de cuero y malla, dinámicas y limpias, equilibran comodidad con diseño urbano.', 'https://www.theoutnet.com/variants/images/46376663163158860/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158860/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158860/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158860/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158860/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158860/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158860/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/new-balance/sneakers/fashion-sneakers/m1000-embroidered-leather-and-mesh-sneakers/46376663163158860', 269, 369.99, 'Combínalas con reloj deportivo, perfume fresco y pantalón técnico; arriba, camiseta blanca y chaqueta ligera.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-1957de84ee3b', 'mp-3240465564d7', 'mp-605a39d82c0f']::text[], 'Para un fin de semana activo, el hoodie técnico, el reloj deportivo y Luna Rossa Carbon construyen un conjunto urbano y dinámico; su aroma fresco-ambarado acompaña con energía y pulcritud.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3240465564d7', 'jomashop', 'SE-SRPK67K1', 'Seiko 5 Sports Special Edition Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Automático Seiko 5 Sports de estética negra, robusta y contemporánea.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-special-edition-automatic-black-dial-mens-watch-srpk67k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-special-edition-automatic-black-dial-mens-watch-srpk67k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-special-edition-automatic-black-dial-mens-watch-srpk67k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-special-edition-automatic-black-dial-mens-watch-srpk67k1_3.jpg']::text[], 'https://www.jomashop.com/seiko-5-sports-special-edition-automatic-black-dial-mens-watch-srpk67k1.html', 270, 370.99, 'Llévalo con camiseta gris, sobrecamisa verde oliva, denim recto y perfume especiado limpio.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-762ca64e80bd', 'mp-177361511fc4', 'mp-60727c51909d']::text[], 'Para un look casual con intención, el polo estructurado y las sneakers limpias equilibran el negro del reloj. Sauvage suma un toque aromático y fresco, perfecto para día o tarde sin perder presencia.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f9c5b6ab761a', 'jomashop', 'SE-SRPK91K1', 'Seiko 5 Sports SNXS Automatic Ivory Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera marfil y proporciones clásicas para un porte sobrio y fácil de llevar.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-snxs-automatic-ivory-dial-mens-watch-srpk91k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-snxs-automatic-ivory-dial-mens-watch-srpk91k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-snxs-automatic-ivory-dial-mens-watch-srpk91k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-snxs-automatic-ivory-dial-mens-watch-srpk91k1_3.jpg', 'https://www.strapseeker.com/cdn/shop/files/SRPK91K1_3.png?v=1733818256&width=1200', 'https://www.skywatches.com.sg/cdn/shop/files/SRPK91K1_2.png?v=1723111686&width=1200', 'https://i5.walmartimages.com/seo/Seiko-5-Sports-SNXS-Automatic-Ivory-Dial-Men-s-Watch-SRPK91K1_4aba76c2-f23b-4b6b-90c1-9cb379845cbc.6e9e5a1ea4c66647c28d6a03a7aa8884.jpeg', 'https://www.strapseeker.com/cdn/shop/files/SRPK91K1_4.png?v=1733818256&width=1200']::text[], 'https://www.jomashop.com/seiko-5-sports-snxs-automatic-ivory-dial-mens-watch-srpk91k1.html', 269.8, 370.99, 'Combínalo con camisa azul claro, pantalón sastre beige, loafers marrón y perfume de té.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-4af1908c0185', 'mp-7795ae7c1d60', 'mp-9c175b220b04']::text[], 'Para oficina, combina la camisa de lino con un pantalón impecable y loafers sobrios; el reloj ivory aporta calidez. Elegant Vetiver añade vetiver refinado y limpio, ideal para una imagen segura y discreta.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b85e68c56026', 'jomashop', 'CZNJ0154-80H', 'Tsuyosa Automatic Black Dial Two-Tone Men''s Watch', 'Citizen', 'watch', 'men', 'Contraste bicolor y esfera negra para una elegancia moderna y contenida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-black-dial-twotone-mens-watch-nj015480h.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-black-dial-twotone-mens-watch-nj015480h.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-black-dial-twotone-mens-watch-nj015480h_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-automatic-black-dial-twotone-mens-watch-nj015480h_3.jpg', 'https://timeaccess-store.com/cdn/shop/files/NJ0154-80Hb.jpg?v=1734007743&width=1080']::text[], 'https://www.jomashop.com/citizen-automatic-black-dial-two-tone-mens-watch-nj0154-80h.html', 269.8, 370.99, 'Combínalo con blazer gris, camisa blanca, pantalón negro y mocasines de cuero liso.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-2ad272892924', 'mp-c680203f6394', 'mp-1fee958584dc']::text[], 'Para oficina, la camisa de lino fino, los tassel loafers y el reloj two-tone crean un porte pulido y actual. MYSLF aporta un carácter amaderado y luminoso, moderno sin exceso.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3bd9c6e35a19', 'jomashop', 'Z-38UBM', 'Gucci Vanilla Firenze EDP Spray 3.4 oz', 'Gucci', 'perfume', 'unisex', 'Vainilla con matiz florentino, cálida y envolvente, deja una estela sofisticada y serena.', 'https://media.gucci.com/style/DarkGray_Center_0_0_1200x1200/1733212812/801718_99999_0099_001_100_0000_Light-the-alchemists-garden-vanilla-firenze-100ml-eau-de-parfum.jpg', ARRAY['https://media.gucci.com/style/DarkGray_Center_0_0_1200x1200/1733212812/801718_99999_0099_001_100_0000_Light-the-alchemists-garden-vanilla-firenze-100ml-eau-de-parfum.jpg', 'https://media.gucci.com/style/DarkGray_Center_0_0_1200x1200/1733212813/801718_99999_0099_002_100_0000_Light-the-alchemists-garden-vanilla-firenze-100ml-eau-de-parfum.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/u/gucci-vanilla-firenze-edp-spray-34-oz-fragrances-3616305261823.jpg']::text[], 'https://www.jomashop.com/gucci-vanilla-firenze-edp-spray-3-4-oz-fragrances-3616305261823.html', 269.99, 370.99, 'Úsalo con reloj de vestir, blazer negro y zapatos de cuero; elige tonos crema, tabaco o burdeos.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-ef6b916a5f31', 'mp-f3cd717d3b87', 'mp-49e760656023']::text[], 'Para una noche elegante, la camisa de seda, los loafers ornamentados y el reloj dorado elevan la calidez de Vanilla Firenze. Su rastro avainillado y sensual acompaña con sofisticación y carácter.', 'noche', ARRAY['mp-3968aa79d4f8', 'mp-95ac9c8c22b8', 'mp-69e7777fc13e']::text[], 'Para una noche elegante, el vestido drapeado, los pumps y el reloj negro componen un conjunto sofisticado y femenino. Vanilla Firenze aporta vainilla cálida y envolvente, perfecta para una salida especial.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-49dfa8f3681d', 'theoutnet', 'ton-46376663163051851', 'Cutout High Rise Wide Leg Jeans', 'Maison Margiela', 'clothing', 'women', 'Jean de silueta amplia y cortes sutiles, moderno sin perder refinamiento.', 'https://www.theoutnet.com/variants/images/46376663163051851/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163051851/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163051851/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163051851/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163051851/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163051851/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/maison-margiela/jeans/wide-leg-jeans/cutout-high-rise-wide-leg-jeans/46376663163051851', 270, 370.99, 'Llévalo con reloj de acero fino, top negro, blazer estructurado y flats o loafers minimalistas.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-771e0dce9f5f', 'mp-031aa53c410f', 'mp-2dc2d5978672']::text[], 'Para oficina o un almuerzo formal, los jeans rectos, las ballet flats y el reloj verde logran un balance limpio y moderno. Añade Royal Oud para un fondo amaderado, seco y distinguido.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-90e204c4c1b2', 'theoutnet', 'ton-46376663163096316', 'Cotton Blend Twill Chinos', 'Onia', 'clothing', 'men', 'Chinos de twill, pulidos y versátiles, construyen una base limpia para el día a día.', 'https://www.theoutnet.com/variants/images/46376663163096316/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096316/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096316/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096316/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096316/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096316/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/pants/casual-pants/cotton-blend-twill-chinos/46376663163096316', 270, 370.99, 'Combínalos con reloj de acero, perfume amaderado y camisa azul; completa con loafers marrones.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-53c9144c0d39', 'mp-7795ae7c1d60', 'mp-e5b8eeedce5f']::text[], 'Para oficina, los chinos, los loafers y el reloj azul trazan una silueta clásica y precisa. Homme Intense suma iris y cacao sobrios, aportando profundidad elegante sin perder versatilidad.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUD