INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a261034b30b2', 'theoutnet', 'ton-46376663163096293', 'Striped Cotton Oxford Shirt', 'Onia', 'clothing', 'men', 'Camisa oxford a rayas, clásica y precisa, aporta orden visual con un gesto relajado.', 'https://www.theoutnet.com/variants/images/46376663163096293/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096293/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096293/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096293/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096293/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096293/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/tops/formal-shirts/striped-cotton-oxford-shirt/46376663163096293', 270, 370.99, 'Llévala con reloj sobrio, perfume limpio y pantalón gris; suma mocasines o zapatillas de cuero blanco.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-53c9144c0d39', 'mp-7795ae7c1d60', 'mp-e5b8eeedce5f']::text[], 'Para oficina, la camisa rayada, los loafers y el Tsuyosa azul construyen una presencia clara y refinada. Homme Intense aporta iris y cacao, con un aire elegante perfecto para el día.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=