INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-68a041916a67', 'theoutnet', 'ton-1647597331446243', 'Logo Appliqued Cotton Jersey t Shirt', 'Fear of God Essentials', 'clothing', 'men', 'Camiseta de algodón con logo aplicado, cómoda y limpia, para un estilo urbano esencial.', 'https://www.theoutnet.com/variants/images/1647597331446243/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597331446243/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597331446243/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597331446243/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597331446243/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597331446243/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/fear-of-god-essentials/tops/t-shirts/logo-appliqued-cotton-jersey-t-shirt/1647597331446243', 270, 370.99, 'Combínala con reloj minimalista, perfume fresco y joggers oscuros; completa con zapatillas blancas y bomber.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-6abb16f437af', 'mp-3240465564d7', 'mp-605a39d82c0f']::text[], 'Para un estilo deportivo y urbano, la camiseta, las sneakers y el reloj Seiko mantienen el conjunto limpio y actual. Luna Rossa Carbon añade frescura aromática con un fondo amaderado, moderno y enérgico.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-771e0dce9f5f', 'theoutnet', 'ton-46376663163066699', 'Varina Bow Detailed Leather Ballet Flats', 'Ferragamo', 'shoes', 'women', 'Ballerinas de cuero con lazo, femeninas y pulidas para un gesto clásico.', 'https://www.theoutnet.com/variants/images/46376663163066699/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163066699/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163066699/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163066699/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163066699/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163066699/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/flat-shoes/ballet-flats/varina-bow-detailed-leather-ballet-flats/46376663163066699', 272, 373.99, 'Combínalas con reloj fino, camisa de seda, falda midi o pantalón sastre y perfume floral suave.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-381d102f4ffc', 'mp-c798e1926e9d', 'mp-d2572817bc32']::text[], 'Para oficina o una comida elegante, los ballet flats, el sweater de cashmere y el PRX nácar componen una estética pulida y serena. Libre Le Parfum añade florales cálidos y sofisticados.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.