INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c680203f6394', 'theoutnet', 'ton-46376663163049712', 'Andrea Tasseled Suede Loafers', 'Santoni', 'shoes', 'men', 'Mocasines de gamuza con borlas, elegantes y discretos, elevan el vestir con naturalidad.', 'https://www.theoutnet.com/variants/images/46376663163049712/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163049712/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163049712/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163049712/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163049712/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163049712/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/santoni/flat-shoes/loafers/andrea-tasseled-suede-loafers/46376663163049712', 273, 374.99, 'Con reloj clásico, perfume amaderado y pantalón de lana azul; arriba, camisa blanca y blazer.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4af1908c0185', 'mp-69df0685227c', 'mp-4520d6ec87f1']::text[], 'Tu look de oficina queda impecable con lino pulido, el PRX azul y Grey Vetiver: seco, limpio y refinado. Ideal para días de reunión, con una presencia discreta y muy bien resuelta.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-69df0685227c', 'jomashop', 'TIST1374101604100', 'Tissot PRX Quartz Blue Dial Men''s Watch', 'Tissot', 'watch', 'men', 'El PRX azul une líneas depuradas y aire retro en clave contemporánea.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf10366bd/product-pictures/1035559f-8895-4f8b-a45c-fd0489773882_T137-410-16-041-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf10366bd/product-pictures/1035559f-8895-4f8b-a45c-fd0489773882_T137-410-16-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf10366bd/product-pictures/1035559f-8895-4f8b-a45c-fd0489773882_T137-410-16-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw077772f0/product-pictures/4afdbc7f-bdb1-406b-872e-e355a39c9e7f_T137_410_16_041_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwd80cdad0/product-pictures/03c75d38-eb01-440e-a474-0f6992464692_T137_410_16_041_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw7d75db73/product-pictures/2817b624-739c-44ff-addb-097d7fc9f9ed_T137_410_16_041_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwaca63858/product-pictures/4d400110-f3e6-4d50-80ba-ad4776193b44_T137_410_16_041_00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-tclassic-quartz-blue-dial-mens-watch-t1374101604100-t1374101604100.jpg']::text[], 'https://www.jomashop.com/tissot-t-classic-quartz-blue-dial-mens-watch-t137-410-16-041-00.html', 273.6, 375.99, 'Combínalo con traje gris medio, camisa blanca, derby negras y perfume limpio de vetiver.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-6e4425667ee2', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'La PRX azul queda impecable con oxford y mocasines de cuero, logrando un porte sobrio y pulido para oficina o cena afterwork. Grey Vetiver aporta frescura seca y elegante, sin imponerse.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c5905b2bbce9', 'theoutnet', 'ton-46376663163096549', 'Incotex Tapered Linen And Cotton Blend Pants', 'Slowear', 'clothing', 'men', 'Pantalón de lino y algodón, ligero y pulido, perfecto para una silueta relajada.', 'https://www.theoutnet.com/variants/images/46376663163096549/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163096549/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096549/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096549/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096549/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163096549/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/slowear/pants/casual-pants/incotex-tapered-linen-and-cotton-blend-pants/46376663163096549', 274, 375.99, 'Combínalo con reloj de acero, perfume cítrico y camisa de popelina; completa con loafers o mocasines.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4a5a48eeb043', 'mp-c680203f6394', 'mp-21708b443c49']::text[], 'El lino de estos pantalones pide una textura limpia y relajada: Tsuyosa, loafers de ante y una fragancia marina refinada. Ideal para verano en Lima, con aire ejecutivo pero ligero.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-badad2e695c8', 'jomashop', 'SE-SRPL59K1', 'Seiko 5 Sports Automatic Gold Dial Watch', 'Seiko', 'watch', 'unisex', 'Un dorado equilibrado que aporta luz y carácter a un clásico deportivo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-gold-dial-watch-srpl59k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-gold-dial-watch-srpl59k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-gold-dial-watch-srpl59k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-gold-dial-watch-srpl59k1_3.jpg', 'https://hochuanwatch.com/images/products/srpl59k1.jpg', 'https://hochuanwatch.com/images/products/secondary/srpl59k1-2.jpg', 'https://cdn.shopify.com/s/files/1/0550/6593/5925/files/Seiko_SRPL59K1-1.jpg?v=1763364970&width=1000']::text[], 'https://www.jomashop.com/seiko-5-sports-automatic-gold-dial-watch-srpl59k1.html', 274.55, 376.99, 'Llévalo con polo crema, pantalón azul marino, mocasines marrón y fragancia amaderada suave.', 'https://lifewithjazz.com/wp-content/uploads/2022/04/5-Smart-Casual-Outfits-Last-picture.jpg', ARRAY['mp-4af1908c0185', 'mp-c680203f6394', 'mp-4520d6ec87f1']::text[], 'Con camisa de lino, mocasines de ante y Grey Vetiver logras un casual sobrio y sofisticado. Perfecto para after office o brunch, con aire limpio, elegante y sin esfuerzo.', 'casual', ARRAY['mp-e80799294eb5', 'mp-08cb860e5a5a', 'mp-8498b52f4f24']::text[], 'Para oficina o almuerzo ejecutivo, la camisa estructurada, los loafers y un perfume suave crean un conjunto pulido. El acorde floral del aroma aporta feminidad discreta y elegante.', 'oficina') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6a32aace5e0a', 'jomashop', 'COS-CNSES33', 'Creed Neroli Sauvage / Creed EDP Spray 3.3 oz (100 ml) (u)', 'Creed', 'perfume', 'unisex', 'Neroli luminoso con frescura limpia, ideal para una presencia natural y refinada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-neroli-sauvage-creed-edp-spray-33-oz-100-ml-u-3508441001046.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-neroli-sauvage-creed-edp-spray-33-oz-100-ml-u-3508441001046.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-neroli-sauvage-creed-edp-spray-33-oz-100-ml-u-3508441001046_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-neroli-sauvage-creed-edp-spray-33-oz-100-ml-u-3508441001046_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-neroli-sauvage-creed-edp-spray-33-oz-100-ml-u-3508441001046_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/o/p/open-box-creed-neroli-sauvage-creed-edp-spray-33-oz-100-ml-u-3508441001046.jpg', 'https://images.stockmann.com/products/c52bf8f7414540a1a3ed200f3d1a89f82cb19b91/550x734/3508441001046_3.jpg']::text[], 'https://www.jomashop.com/creed-perfume-cnses33.html', 274.99, 376.99, 'Combínalo con reloj de acero, camisa de lino blanca, pantalón arena y loafers claros.', 'https://morningkoffee.com/wp-content/uploads/2025/05/Comfy-summer-outfit-Tote-bag-@bonheur-.linenclothing-linenoutfit-summerstyles-bonheurbag-birkenstocks-pinstripes-linenshirt-linenpants-totebag-canvasbag-casualoutfit-summerlooks.jpg', ARRAY['mp-655fabea4d8c', 'mp-32f83814872c', 'mp-69df0685227c']::text[], 'Para un día cálido y relajado, el lino, las espadrilles y el reloj azul acompañan muy bien este perfume: cítrico, nerolado y fresco, con un refinamiento limpio y mediterráneo.', 'verano', ARRAY['mp-e80799294eb5', 'mp-771e0dce9f5f', 'mp-cbf5fd94f2da']::text[], 'Para ti, una camisa blanca, ballet flats y un PRX ligero equilibran el neroli con un aire limpio y elegante. Ideal para verano, con frescura luminosa y muy silenciosa.', 'verano') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-501275d9ea5c', 'jomashop', 'Z-2FX1M', 'Yves Saint Laurent Unisex Wild Leather EDP Spray 4.2 oz', 'Yves Saint Laurent', 'perfume', 'women', 'Ámbar con cuero, profundo y sofisticado, deja una impresión intensa y contenida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-unisex-wild-leather-edp-spray-42-oz-fragrances-3614273312325.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-unisex-wild-leather-edp-spray-42-oz-fragrances-3614273312325.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-unisex-wild-leather-edp-spray-42-oz-fragrances-3614273312325_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/y/v/yves-saint-laurent-unisex-wild-leather-edp-spray-42-oz-fragrances-3614273312325_7.jpg']::text[], 'https://www.jomashop.com/yves-saint-laurent-unisex-wild-leather-edp-spray-fragrances-3614273312325.html', 274.99, 376.99, 'Llévalo con reloj oscuro, blazer de lana y zapatos negros; suma camisa marfil y tonos grafito.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-381d102f4ffc', 'mp-95ac9c8c22b8', 'mp-c798e1926e9d']::text[], 'Wild Leather dialoga con el cashmere recortado y pumps afilados, creando una silueta nocturna y segura. El reloj en nácar añade luz; el perfume es cuero cálido, especiado y sensual.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLU