nto con una estela seca y elegante.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-762ca64e80bd', 'theoutnet', 'ton-46376663163091179', 'Horacio Cotton Pique Polo Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Polo de piqué limpio y atemporal, con porte relajado y refinado.', 'https://www.theoutnet.com/variants/images/46376663163091179/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163091179/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091179/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091179/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091179/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091179/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/polo-shirts/horacio-cotton-pique-polo-shirt/46376663163091179', 276, 378.99, 'Llévalo con reloj de acero, perfume cítrico y pantalón de lino beige con mocasines café.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-69df0685227c', 'mp-32f83814872c', 'mp-6a32aace5e0a']::text[], 'Polo, PRX azul y espadrilles construyen un lujo discreto, ligero y muy veraniego. Neroli Sauvage aporta cítricos transparentes y sofisticados, ideal para días cálidos, viajes o un almuerzo informal.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f597bbe6ab0b', 'theoutnet', 'ton-1071994537819831', 'Ruffled Silk Georgette Mini Skirt', 'Balmain', 'clothing', 'women', 'Mini falda de seda con volumen definido y movimiento sofisticado.', 'https://www.theoutnet.com/variants/images/1071994537819831/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1071994537819831/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1071994537819831/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1071994537819831/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1071994537819831/E/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/skirts/mini-skirts/ruffled-silk-georgette-mini-skirt/1071994537819831', 277, 379.99, 'Combínala con reloj delicado, top satinado negro, tacones finos y perfume floral oscuro.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-d0246a15c10d', 'mp-3c1803aec5d1', 'mp-907d601e36bb']::text[], 'La falda cobra dramatismo con pumps de líneas limpias y un PRX negro con brillo discreto. Royal Princess Oud añade una presencia floral-amaderada, perfecta para una noche elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCL