INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a961d6904ead', 'theoutnet', 'ton-46376663163116854', 'High Rise Straight Leg Jeans', 'Maison Margiela', 'clothing', 'women', 'Jean recto de caída limpia, esencial para un guardarropa sobrio y moderno.', 'https://www.theoutnet.com/variants/images/46376663163116854/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163116854/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163116854/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163116854/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163116854/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163116854/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/maison-margiela/jeans/straight-leg-jeans/high-rise-straight-leg-jeans/46376663163116854', 277, 379.99, 'Llévalo con reloj de acero, camisa oxford blanca, blazer camel y mocasines o sneakers blancas.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-771e0dce9f5f', 'mp-cbf5fd94f2da', 'mp-6a32aace5e0a']::text[], 'El jean recto se vuelve pulido con ballerinas, PRX verde y una fragancia cítrica refinada. Un look de oficina moderna, cómoda y silenciosamente lujosa, también perfecto para viernes casual.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3c75f66f94e0', 'theoutnet', 'ton-46376663163154581', 'Tasseled Leather Trimmed Velvet Loafers', 'Tom Ford', 'shoes', 'men', 'Mocasín de terciopelo con ribete pulido, pensado para noches discretamente sofisticadas.', 'https://www.theoutnet.com/variants/images/46376663163154581/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163154581/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154581/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154581/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154581/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154581/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/flat-shoes/loafers/tasseled-leather-trimmed-velvet-loafers/46376663163154581', 277, 379.99, 'Combínalos con reloj delgado, perfume amaderado y traje negro o pantalón de lana gris.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-76e86cc39c9a', 'mp-23af6e30e1cc', 'mp-c904c1c531f7']::text[], 'Los loafers de terciopelo piden pantalón de grain de poudre y un reloj de presencia clásica. Cuir Sublime Oud aporta cuero noble y profundidad, ideal para noche formal o cena privada.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8b8b764da74e', 'theoutnet', 'ton-46376663163097820', 'Angelina Embellished Croc Effect Leather Sandals', 'Tom Ford', 'shoes', 'women', 'Sandalia de cuero con efecto cocodrilo, sobria y precisa para lucir de noche.', 'https://www.theoutnet.com/variants/images/46376663163097820/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163097820/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097820/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097820/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097820/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163097820/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/sandals/high-heel-sandals/angelina-embellished-croc-effect-leather-sandals/46376663163097820', 278, 380.99, 'Úsalas con reloj negro, perfume intenso y vestido satinado en tonos neutros o joya.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-f597bbe6ab0b', 'mp-3c1803aec5d1', 'mp-907d601e36bb']::text[], 'Las sandalias brillan con la falda Balmain y un PRX negro, creando un conjunto sofisticado y preciso. Royal Princess Oud suma un acorde opulento, floral-amaderado, perfecto para cóctel o gala.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration