INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3968aa79d4f8', 'theoutnet', 'ton-46376663163093753', 'Embellished Draped Jersey Mini Dress', 'Tom Ford', 'clothing', 'women', 'Minivestido drapeado con brillo sutil, para una presencia definida y moderna.', 'https://www.theoutnet.com/variants/images/46376663163093753/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163093753/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093753/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093753/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093753/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093753/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/dresses/mini-dresses/embellished-draped-jersey-mini-dress/46376663163093753', 278, 380.99, 'Acompáñalo con reloj fino, perfume floral oscuro y sandalias negras o nude de tacón.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-d0246a15c10d', 'mp-69e7777fc13e', 'mp-58072ada40a0']::text[], 'El vestido drapeado se equilibra con pumps pulidos, reloj negro y un cuero texturizado que refuerza el magnetismo nocturno. Tuscan Leather aporta profundidad cálida y sensual, ideal para una salida elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EX