INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e06d80fb575c', 'theoutnet', 'ton-46376663162991723', 'Ring Embellished Ribbed Cotton Blend Mini Dress', 'Tom Ford', 'clothing', 'women', 'Minivestido acanalado con detalle metálico, pulido y seguro para destacar con discreción.', 'https://www.theoutnet.com/variants/images/46376663162991723/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162991723/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162991723/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162991723/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162991723/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162991723/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/dresses/mini-dresses/ring-embellished-ribbed-cotton-blend-mini-dress/46376663162991723', 279, 381.99, 'Llévalo con reloj minimalista, perfume almizclado y botines negros o sandalias metálicas sobrias.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-95ac9c8c22b8', 'mp-3c1803aec5d1', 'mp-58072ada40a0']::text[], 'El vestido ribeteado pide una línea depurada: pumps de Tom Ford, reloj con diamantes y un perfume de cuero intenso. Tuscan Leather realza la noche con carácter, lujo y sensualidad.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiratio