INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-eb14c8e1c046', 'theoutnet', 'ton-1647597354272048', 'Knitted Tank', 'Ferragamo', 'clothing', 'women', 'Tank tejido de línea precisa, perfecto para una base pulida y discreta.', 'https://www.theoutnet.com/variants/images/1647597354272048/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597354272048/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597354272048/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597354272048/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597354272048/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597354272048/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597354272048/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/tops/sleeveless-tops/knitted-tank/1647597354272048', 279, 381.99, 'Combínalo con reloj fino, pantalón sastre, cardigan ligero y sandalias de cuero o loafers.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-771e0dce9f5f', 'mp-f67e672616b5', 'mp-6a32aace5e0a']::text[], 'El tank tejido se ordena con bailarinas, PRX azul y una estela cítrica limpia. Con pantalón sastre o denim oscuro, resulta ideal para oficina creativa y días templados.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c6a7c760b5d3', 'jomashop', 'CZNJ0152-51X', 'Citizen Tsuyosa Automatic Green Green Sunray Dial Watch', 'Citizen', 'watch', 'unisex', 'Verde sunray con brillo sutil, fresco y distintivo sin estridencias.', 'https://citizenwatch.widen.net/content/1pkrr1jwmf/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/1pkrr1jwmf/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iqknqohsul/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/xnx9djhstz/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-green-dial-watch-nj015251x_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-green-dial-watch-nj015251x_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-green-dial-watch-nj015251x_3.jpg']::text[], 'https://www.jomashop.com/citizen-tsuyosa-automatic-green-dial-mens-watch-nj0152-51x.html', 279.3, 382.99, 'Combínalo con camisa blanca, pantalón beige, zapatillas de cuero y perfume herbáceo limpio.', 'https://lifewithjazz.com/wp-content/uploads/2022/04/5-Smart-Casual-Outfits-Last-picture.jpg', ARRAY['mp-4af1908c0185', 'mp-7795ae7c1d60', 'mp-1fee958584dc']::text[], 'El verde del reloj conversa bien con una camisa de lino, mocasines y MYSLF, que aporta un carácter amaderado, limpio y moderno. Perfecto para oficina con un toque actual y discreto.', 'oficina', ARRAY['mp-eb14c8e1c046', 'mp-771e0dce9f5f', 'mp-8498b52f4f24']::text[], 'Para oficina o cena temprana, el tank de punto, los flats y la nota floral-luminosa del perfume crean una combinación serena. El reloj verde añade frescura contemporánea sin perder sobriedad.', 'oficina') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-aaadd7c31bbe', 'jomashop', 'CZBN0167-50H', 'Citizen Promaster Dive Eco-Drive Grey Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Reloj de buceo gris con presencia firme y lectura muy clara.', 'https://citizenwatch.widen.net/content/obgeq9erzf/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/obgeq9erzf/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/0peky1090q/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/dyoajs0uav/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/23uiq6jwgh/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-ecodrive-grey-dial-mens-watch-bn016750h.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-ecodrive-grey-dial-mens-watch-bn016750h_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-ecodrive-grey-dial-mens-watch-bn016750h_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-dive-eco-drive-grey-dial-mens-watch-bn0167-50h.html', 279.3, 382.99, 'Úsalo con polo azul acero, bermuda blanca, sneakers náuticas y perfume acuático seco.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-48065a020111', 'mp-32f83814872c', 'mp-a7bc1a9fc8da']::text[], 'Para escapada de playa o piscina, los swim shorts, espadrilles y Acqua di Giò Profondo forman un look funcional y pulido. El perfume es acuático, mineral y fresco, ideal para calor intenso.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c798e1926e9d', 'jomashop', 'TIST1370101111100', 'Tissot PRX Quartz White Mother of Pearl Dial Ladies Watch', 'Tissot', 'watch', 'women', 'Perla blanca y caja fina para una elegancia luminosa y precisa.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb2bf15dd/product-pictures/1db26820-5e45-432b-9589-efcee5753118_T137-010-11-111-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb2bf15dd/product-pictures/1db26820-5e45-432b-9589-efcee5753118_T137-010-11-111-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb2bf15dd/product-pictures/1db26820-5e45-432b-9589-efcee5753118_T137-010-11-111-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1ec0792f/product-pictures/60862381-4e49-441c-89b4-febdb672bfb3_T137-010-11-111-00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw45279174/product-pictures/aa6dc745-8a19-448c-91c5-f5fc33184750_T137-010-11-111-00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw744f8930/product-pictures/58985e62-9893-41fe-95f7-0334d7c151a1_T137-010-11-111-00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw690b78c5/product-pictures/d6983f83-a5b9-4d81-9f9c-6c39737b43c9_T137-010-11-111-00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-white-mother-of-pearl-dial-ladies-watch-t1370101111100_1.jpg']::text[], 'https://www.jomashop.com/tissot-prx-quartz-white-mother-of-pearl-dial-ladies-watch-t1370101111100.html', 280.25, 383.99, 'Combínalo con reloj delicado, blazer crema, vestido midi o sastre claro y flats nude.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-86d959f332e4', 'mp-d0246a15c10d', 'mp-81d52947c289']::text[], 'Para una reunión importante o cena formal, el pantalón sastrero, los pumps y Dama Bianca elevan el conjunto. El perfume es suave, limpio y empolvado, con una elegancia muy femenina.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-907d601e36bb', 'jomashop', 'Y-A5FVB', 'Creed Ladies Creed Royal Princess Oud EDP Spray 2.5 oz', 'Creed', 'perfume', 'women', 'Oud real con matiz femenino, profundo y suntuoso sin exceso.', 'https://creedboutique.com/cdn/shop/files/1500x1500_Royal-Princess-Oud_75ml.jpg?v=1740695961&width=1600', ARRAY['https://creedboutique.com/cdn/shop/files/1500x1500_Royal-Princess-Oud_75ml.jpg?v=1740695961&width=1600', 'https://creedboutique.com/cdn/shop/files/1500x1500_RPO-Notes_1.jpg?v=1764095747&width=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-ladies-creed-royal-princess-oud-edp-spray-25-oz-fragrances-871854102642.jpg']::text[], 'https://www.jomashop.com/creed-ladies-creed-royal-princess-oud-edp-spray-2-5-oz-fragrances-871854102642.html', 279.99, 383.99, 'Llévalo con reloj dorado discreto, vestido negro, sandalias altas y joyería mínima pulida.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-e06d80fb575c', 'mp-d0246a15c10d', 'mp-c798e1926e9d']::text[], 'Para una noche especial, el mini dress, los pumps y el PRX de nácar aportan brillo contenido. Royal Princess Oud es opulento, amaderado y floral, perfecto para una presencia sofisticada.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_no