INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0c7130472c08', 'jomashop', 'Y-130287', 'Giorgio Armani Unisex Rouge Malachite EDP Spray 3.4 oz', 'Giorgio Armani', 'perfume', 'unisex', 'Fragancia envolvente y sensual, con carácter profundo y presencia distinguida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-unisex-rouge-malachite-edp-spray-3-4-oz-fragrances-3614271063717.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-unisex-rouge-malachite-edp-spray-3-4-oz-fragrances-3614271063717.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-unisex-rouge-malachite-edp-spray-34-oz-fragrances-3614271063717_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-unisex-rouge-malachite-edp-spray-34-oz-fragrances-3614271063717_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-unisex-rouge-malachite-edp-spray-34-oz-fragrances-3614271063717_7.jpg', 'https://masilaparfum.com/wp-content/uploads/2023/03/3614271063717_1_1652447272239-1.jpeg', 'https://sasobg.com/wp-content/uploads/2023/04/3614271063717.jpg', 'https://cdn.beymen.com/productimages/0709001254_IMG_01_3614271063717.jpg']::text[], 'https://www.jomashop.com/giorgio-armani-unisex-rouge-malachite-edp-spray-3-4-oz-fragrances-3614271063717.html', 279.99, 383.99, 'Combínala con reloj dorado, vestido negro o sastre azul noche y tacones de cuero.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-ef6b916a5f31', 'mp-3c75f66f94e0', 'mp-23af6e30e1cc']::text[], 'Para cena de invierno, la camisa satinada, los loafers de terciopelo y el Presage azul crean un conjunto refinado. Rouge Malachite se siente floral-cremoso y cálido, con una estela intensa y elegante.', 'noche', ARRAY['mp-381d102f4ffc', 'mp-d0246a15c10d', 'mp-c798e1926e9d']::text[], 'Para una cena de invierno, el sweater de cashmere, los pumps y el PRX de nácar equilibran textura y brillo. Rouge Malachite aporta un floral cremoso, opulento y muy sensual.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-655fabea4d8c', 'theoutnet', 'ton-46376663163091183', 'Angelo Linen Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Camisa de lino ligera y limpia, pensada para un porte fresco y elevado.', 'https://www.theoutnet.com/variants/images/46376663163091183/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163091183/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091183/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091183/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091183/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091183/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/casual-shirts/angelo-linen-shirt/46376663163091183', 281, 384.99, 'Úsala con reloj de cuero claro, perfume cítrico y pantalón crema con mocasines marrón miel.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4a5a48eeb043', 'mp-32f83814872c', 'mp-6a32aace5e0a']::text[], 'Para un fin de semana en la costa, tu camisa de lino funciona mejor con el Tsuyosa negro, espadrilles y Neroli Sauvage. El perfume es cítrico, verde y limpio, muy fresco.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6e02774d371b', 'theoutnet', 'ton-46376663163009606', 'Moneta Patent Leather Sandals', 'Balmain', 'shoes', 'women', 'Sandalia de patente con línea firme, ideal para un gesto nocturno refinado.', 'https://www.theoutnet.com/variants/images/46376663163009606/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163009606/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163009606/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163009606/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163009606/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163009606/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/sandals/high-heel-sandals/moneta-patent-leather-sandals/46376663163009606', 282, 385.99, 'Combínalas con reloj brillante, perfume especiado y vestido midi negro o pantalón sastre.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-e06d80fb575c', 'mp-a88c1eb55d5a', 'mp-4c1e18349ce0']::text[], 'Para una noche elegante, este vestido mini realza las sandalias con líneas limpias y brillo sutil. El PRX madreperla aporta refinamiento discreto, y el perfume floral-cremoso suma un halo femenino, sofisticado y luminoso sin recargar.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5fc9d7d58615', 'theoutnet', 'ton-1647597286405306', 'Embroidered Embellished High Rise Slim Leg Jeans', 'Balmain', 'clothing', 'women', 'Jean con bordado y relieve, pensado para una presencia pulida y singular.', 'https://www.theoutnet.com/variants/images/1647597286405306/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597286405306/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597286405306/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597286405306/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597286405306/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597286405306/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/jeans/skinny-leg-jeans/embroidered-embellished-high-rise-slim-leg-jeans/1647597286405306', 282, 385.99, 'Combínalo con reloj esbelto, top negro, blazer estructurado, tacones puntuales y perfume oriental limpio.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-d0246a15c10d', 'mp-a88c1eb55d5a', 'mp-cb004bfbf1f3']::text[], 'Con pumps limpios, un PRX de madreperla y un perfume ámbar-floral, tus jeans bordados se leen pulidos y actuales. Ideal para una cena o coctel donde quieras destacar con discreción y elegancia.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-08082218eb07', 'theoutnet', 'ton-1647597331446260', 'Oversized Logo Appliqued Cotton Jersey t Shirt', 'Fear of God Essentials', 'clothing', 'men', 'T-shirt oversize con logo, de presencia relajada y urbana.', 'https://www.theoutnet.com/variants/images/1647597331446260/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597331446260/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597331446260/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597331446260/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597331446260/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597331446260/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/fear-of-god-essentials/tops/t-shirts/oversized-logo-appliqued-cotton-jersey-t-shirt/1647597331446260', 282, 385.99, 'Combínala con reloj deportivo, perfume limpio y denim recto con zapatillas blancas.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-6abb16f437af', 'mp-4a5a48eeb043', 'mp-0de6cc427e14']::text[], 'Para un fin de semana relajado, las sneakers equilibran el logo con aire urbano, el reloj aporta carácter limpio y el perfume acuático refuerza una impresión fresca, masculina y muy fácil de llevar.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a88c1eb55d5a', 'jomashop', 'TIST1370102111100', 'Tissot PRX Quartz White Mother of Pearl Dial Ladies Watch', 'Tissot', 'watch', 'women', 'Madre perla blanca y acabado fino para una feminidad serena.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwcaddf7a1/product-pictures/1ff19c55-7820-45e4-8261-e3fc044a2843_T137-010-21-111-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwcaddf7a1/product-pictures/1ff19c55-7820-45e4-8261-e3fc044a2843_T137-010-21-111-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwcaddf7a1/product-pictures/1ff19c55-7820-45e4-8261-e3fc044a2843_T137-010-21-111-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw65741b57/product-pictures/9e323d81-f59e-4f7a-92a8-25be86ccd0a0_T137-010-21-111-00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw88335a4a/product-pictures/8bfaaca6-489b-4cea-b9cd-159ccf191c28_T137-010-21-111-00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf933f846/product-pictures/06982187-9ebb-4c86-a0bd-742e07d1b9f3_T137-010-21-111-00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw18941e04/product-pictures/2e5af74a-8300-4e64-8a61-19a2c1da8459_T137-010-21-111-00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-white-mother-of-pearl-dial-ladies-watch-t1370102111100.jpg']::text[], 'https://www.jomashop.com/tissot-prx-quartz-white-mother-of-pearl-dial-ladies-watch-t1370102111100.html', 283.1, 386.99, 'Úsalo con reloj delicado, blouse marfil, falda lápiz o traje claro y tacones nude.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-381d102f4ffc', 'mp-2208bf601ddb', 'mp-d3b04c599098']::text[], 'Para oficina o reuniones, el sweater de cashmere, los loafers pulidos y el reloj madreperla crean un conjunto sobrio y refinado. El perfume limpio y empolvado acompaña con elegancia, sin imponerse.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9fca20b50d99', 'theoutnet', 'ton-46376663163009608', 'Ruby Suede Sandals', 'Balmain', 'shoes', 'women', 'Sandalia de gamuza con acabado aterciopelado, sutil y sofisticada.', 'https://www.theoutnet.com/variants/images/46376663163009608/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163009608/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163009608/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163009608/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163009608/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163009608/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/sandals/high-heel-sandals/ruby-suede-sandals/46376663163009608', 283, 386.99, 'Llévalas con reloj delgado, perfume amaderado y vestido fluido o pantalón negro pulido.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-3968aa79d4f8', 'mp-69e7777fc13e', 'mp-db3e96bd55d9']::text[], 'Para una noche especial, el vestido drapeado acompaña el brillo de las sandalias con equilibrio perfecto. El reloj negro aporta contraste elegante y el perfume floral-almizclado deja una estela romántica y sofisticada.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUD