INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-381d102f4ffc', 'theoutnet', 'ton-46376663163100372', 'Cutout Cashmere Blend Sweater', 'Ferragamo', 'clothing', 'women', 'Suave cashmere blend con cortes precisos y presencia serena, ideal para un guardarropa atemporal.', 'https://www.theoutnet.com/variants/images/46376663163100372/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163100372/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100372/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100372/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100372/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100372/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/knitwear/crew-neck-sweaters/cutout-cashmere-blend-sweater/46376663163100372', 284, 388.99, 'Con reloj de acero pulido, perfume amaderado y pantalón sastrero en gris, camel o negro, logra una armonía discreta.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-2ca59b3d8894', 'mp-69e7777fc13e', 'mp-58072ada40a0']::text[], 'Para invierno, las botas altas dan solidez al cashmere y el reloj negro suma sobriedad moderna. El perfume amaderado y cuero suave envuelve el look con calidez, discreción y lujo silencioso.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-56d450cf9722', 'theoutnet', 'ton-46376663162973008', 'Sebastian Linen Jersey Polo Shirt', 'Orlebar Brown', 'clothing', 'men', 'Polo de jersey en lino, liviano y pulcro, para días cálidos con estilo.', 'https://www.theoutnet.com/variants/images/46376663162973008/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162973008/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162973008/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162973008/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162973008/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162973008/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/tops/polo-shirts/sebastian-linen-jersey-polo-shirt/46376663162973008', 284, 388.99, 'Combínalo con reloj de acero, perfume fresco y chinos arena con loafers o sneakers blancas.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-32f83814872c', 'mp-4a5a48eeb043', 'mp-8d5bb353d59a']::text[], 'Para verano, las espadrilles mantienen el look fresco y relajado, mientras el reloj negro da estructura. El perfume cítrico-aromático aporta limpieza y energía, ideal para un almuerzo frente al mar o un viaje.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6a03b9633ec5', 'theoutnet', 'ton-46376663163091431', 'Columbo Cotton Blend Twill Pants', 'Frescobol Carioca', 'clothing', 'men', 'Pantalón de twill con caída limpia, versátil y sereno para el día a día.', 'https://www.theoutnet.com/variants/images/46376663163091431/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163091431/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091431/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091431/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091431/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091431/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/pants/casual-pants/columbo-cotton-blend-twill-pants/46376663163091431', 285, 389.99, 'Úsalo con reloj clásico, perfume discreto y camisa blanca o polo azul con mocasines.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-c680203f6394', 'mp-4520d6ec87f1', 'mp-e0ac20e6c3ac']::text[], 'Para oficina, los loafers y el reloj plateado equilibran la caída impecable del pantalón. El perfume vetiver refuerza una imagen pulcra, seria y contemporánea, perfecta para reuniones o un día de trabajo elegante.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2cd9c7e43f89', 'theoutnet', 'ton-46376663163018748', 'Striped Ribbed Cotton And Linen Blend Polo Shirt', 'Alex Mill', 'clothing', 'men', 'Polo de rayas finas con textura suave, relajado y bien resuelto.', 'https://www.theoutnet.com/variants/images/46376663163018748/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163018748/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163018748/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163018748/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163018748/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163018748/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/alex-mill/tops/polo-shirts/striped-ribbed-cotton-and-linen-blend-polo-shirt/46376663163018748', 285, 389.99, 'Acompáñalo con reloj de cuero, perfume cítrico y pantalón claro con sneakers de lona.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-34ed970dbc5d', 'mp-8d5bb353d59a']::text[], 'Las espadrilles equilibran la textura del polo y refuerzan un aire fresco y relajado. El reloj añade limpieza deportiva, y el Neroli Portofino aporta un cítrico, salino y luminoso ideal para una salida de día en verano.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-46a3f9eb4ee5', 'theoutnet', 'ton-46376663163088183', 'Floral Print Linen Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Camisa de lino con floral discreto, fresca y con carácter artístico.', 'https://www.theoutnet.com/variants/images/46376663163088183/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163088183/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163088183/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163088183/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163088183/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163088183/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/casual-shirts/floral-print-linen-shirt/46376663163088183', 285, 389.99, 'Llévala con reloj en tono plata, perfume verde y short crema o pantalón blanco con sandalias.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-69ef4764b1ae', 'mp-69df0685227c', 'mp-6a32aace5e0a']::text[], 'Las espadrilles de lona mantienen el look pulido sin esfuerzo, mientras el PRX suma discreción contemporánea. El Neroli Sauvage aporta un frescor cítrico y aromático perfecto para almuerzo estival o paseo costero.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7e287cc01611', 'theoutnet', 'ton-46376663163088184', 'Printed Linen Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Camisa de lino estampado, ligera y refinada, ideal para un look relajado.', 'https://www.theoutnet.com/variants/images/46376663163088184/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163088184/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163088184/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163088184/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163088184/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163088184/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/casual-shirts/printed-linen-shirt/46376663163088184', 285, 389.99, 'Combínala con reloj de cuero tostado, perfume acuático y bermudas beige con loafers suaves.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-32f83814872c', 'mp-4a5a48eeb043', 'mp-6a32aace5e0a']::text[], 'Las espadrilles suavizan el print y conservan una elegancia relajada. El Tsuyosa negro aporta contraste sobrio, y Neroli Sauvage suma un perfil cítrico limpio, ideal para una tarde de verano junto al mar.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7795ae7c1d60', 'theoutnet', 'ton-46376663163152909', 'Sadei Leather Loafers', 'Bally', 'shoes', 'men', 'Mocasín de cuero, sobrio y versátil, con una línea clásica muy pulida.', 'https://www.theoutnet.com/variants/images/46376663163152909/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163152909/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163152909/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163152909/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163152909/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163152909/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/flat-shoes/loafers/sadei-leather-loafers/46376663163152909', 285, 389.99, 'Úsalos con reloj de acero, perfume amaderado y pantalón de lana o denim oscuro.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-6e4425667ee2', 'mp-69df0685227c', 'mp-4520d6ec87f1']::text[], 'La camisa Oxford y el PRX construyen una imagen refinada y serena, perfecta para oficina o reunión. Grey Vetiver acompaña con un carácter seco, limpio y elegante, muy acorde al lujo silencioso.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d0246a15c10d', 'theoutnet', 'ton-46376663163053883', 'Four Stitches Leather Pumps', 'Maison Margiela', 'shoes', 'women', 'Salón de cuero con firma sutil y silueta limpia, pensado para elevar conjuntos sobrios.', 'https://www.theoutnet.com/variants/images/46376663163053883/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163053883/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163053883/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163053883/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163053883/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163053883/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/maison-margiela/pumps/mid-heel-pumps/four-stitches-leather-pumps/46376663163053883', 286, 390.99, 'Llévalos con reloj fino, perfume de cuero o ámbar y vestido negro, satén o sastrería oscura para un efecto pulido.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-cf73e236b136', 'mp-c798e1926e9d', 'mp-cb004bfbf1f3']::text[], 'Con este vestido mini de líneas suaves, los pumps aportan elegancia arquitectónica. El reloj en madreperla equilibra brillo discreto y el perfume añade un acorde floral-amaderado, ideal para una noche formal o cóctel.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-48065a020111', 'theoutnet', 'ton-46376663162959572', 'Bulldog Mid Length Printed Swim Shorts', 'Orlebar Brown', 'clothing', 'men', 'Short de baño estampado, cómodo y ligero, pensado para días de sol.', 'https://www.theoutnet.com/variants/images/46376663162959572/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162959572/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162959572/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162959572/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162959572/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162959572/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/swimwear-beachwear/swim-shorts/bulldog-mid-length-printed-swim-shorts/46376663162959572', 287, 391.99, 'Llévalo con reloj resistente al agua, perfume fresco y polo blanco con sandalias o alpargatas.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-5aaf8537baea', 'mp-ec3bfabe27c1', 'mp-0e1d44d63a68']::text[], 'Las sneakers mantienen energía y comodidad para playa o piscina. El Seiko amarillo suma un acento dinámico, y Acqua di Gio Absolu aporta frescura acuática con matiz aromático, ideal para días cálidos y activos.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ddfa6c5d3020', 'theoutnet', 'ton-46376663163159058', 'Air Max Sndr Rubber Trimmed Scuba Sneakers', 'Nike', 'shoes', 'men', 'Zapatilla técnica con volumen moderno, ágil y contemporánea.', 'https://www.theoutnet.com/variants/images/46376663163159058/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163159058/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159058/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159058/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159058/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159058/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/air-max-sndr-rubber-trimmed-scuba-sneakers/46376663163159058', 287, 391.99, 'Combínalas con reloj deportivo, perfume limpio y jogger negro o pantalón cargo con hoodie minimalista.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-1957de84ee3b', 'mp-605a39d82c0f', 'mp-c27ae7cfc8ab']::text[], 'El hoodie y las Nike Field General equilibran el short con un lenguaje urbano y funcional. Luna Rossa Carbon encaja por su frescor limpio, mineral y ligeramente amaderado, perfecto para un look casual de verano.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0215049a5848', 'theoutnet', 'ton-46376663163077389', 'Distressed Embellished Mid Rise Straight Leg Jeans', 'Versace', 'clothing', 'women', 'Jean recto con acabado vivido y brillo ornamental, para un carácter audaz y sofisticado.', 'https://www.theoutnet.com/variants/images/46376663163077389/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163077389/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077389/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077389/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077389/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077389/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077389/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/jeans/straight-leg-jeans/distressed-embellished-mid-rise-straight-leg-jeans/46376663163077389', 288, 393.99, 'Acompáñalo con reloj metálico, perfume especiado y blazer negro, camisa blanca o tacones minimalistas en tonos neutros.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-d0246a15c10d', 'mp-a88c1eb55d5a', 'mp-db3e96bd55d9']::text[], 'El jean embellishment pide un contraste pulido: pumps depurados, reloj de madreperla y un perfume limpio-floral. Funciona muy bien para una cena elegante con aire relajado y sofisticado.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-cf73e236b136', 'theoutnet', 'ton-9057334114097413', 'Oversized Cable Knit Wool And Cotton Blend Mini Dress', 'Maison Margiela', 'clothing', 'women', 'Mini dress de punto con volumen envolvente, de textura rica y encanto relajado.', 'https://www.theoutnet.com/variants/images/9057334114097413/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/9057334114097413/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/9057334114097413/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/9057334114097413/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/9057334114097413/E/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/maison-margiela/dresses/mini-dresses/oversized-cable-knit-wool-and-cotton-blend-mini-dress/9057334114097413', 288, 393.99, 'Combínalo con reloj sobrio, perfume amaderado y botas altas o mocasines, en lana, negro o marfil.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-d0246a15c10d', 'mp-69e7777fc13e', 'mp-907d601e36bb']::text[], 'La textura de punto se vuelve refinada con pumps clásicos y un reloj de estética atemporal. El perfume, fresco y luminoso, suaviza el conjunto; perfecto para oficina creativa o una cena de entretiempo.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, 