INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-dbd26aa3d211', 'theoutnet', 'ton-46376663163110710', 'Mid Length Printed Swim Shorts', 'Off-White', 'clothing', 'men', 'Short de baño gráfico con actitud urbana, ligero y expresivo.', 'https://www.theoutnet.com/variants/images/46376663163110710/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163110710/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163110710/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163110710/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163110710/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163110710/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/swimwear-beachwear/swim-shorts/mid-length-printed-swim-shorts/46376663163110710', 288, 393.99, 'Acompáñalo con reloj acuático, perfume cítrico y camiseta lisa con slides negras.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-5aaf8537baea', 'mp-aaadd7c31bbe', 'mp-21708b443c49']::text[], 'Las Pegasus y el Promaster dividen bien entre playa y ciudad, sin perder ligereza. Acqua di Gio Profondo aporta un frescor marino, transparente y elegante, ideal para vacaciones o fines de semana soleados.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c27ae7cfc8ab', 'jomashop', 'CZNY0168-64A', 'Citizen Promaster Automatic White Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Reloj automático de perfil limpio y esfera clara, listo para un uso activo con discreción.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-automatic-white-dial-mens-watch-ny016864a.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-automatic-white-dial-mens-watch-ny016864a.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-automatic-white-dial-mens-watch-ny016864a_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-automatic-white-dial-mens-watch-ny016864a_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-automatic-white-dial-mens-watch-ny016864a_5.jpg', 'https://i5.walmartimages.com/seo/Citizen-Promaster-Automatic-White-Dial-Men-s-Watch-NY0168-64A_557c3c00-e2ca-40fb-9168-f7c0a74b90a5.31ec9f51f954be96d357bc3222abde00.jpeg', 'https://www.citywatches.co.za/wp-content/uploads/2024/11/NY0168-64A_3.jpg', 'https://i5.walmartimages.com/seo/Citizen-Promaster-Automatic-White-Dial-Men-s-Watch-NY0168-64A_8895b1dd-5cf4-46cd-9b0b-aa4eef7a47b0.5164e652259e20ed97f6d02169ec8b54.jpeg']::text[], 'https://www.jomashop.com/citizen-promaster-automatic-white-dial-mens-watch-ny0168-64a.html', 289, 394.99, 'Úsalo con reloj solo, perfume fresco y polo, denim oscuro o chaqueta técnica para un look limpio y funcional.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-48065a020111', 'mp-ddfa6c5d3020', 'mp-21708b443c49']::text[], 'El reloj funciona perfecto con swim shorts y sneakers ligeras, en un registro deportivo y pulido. Profondo añade un perfil acuático, limpio y sofisticado, muy adecuado para playa, yate o escapada de verano.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9acf63398655', 'jomashop', 'Z-M73BM', 'Valentino Unisex L''innocence de L''air EDP Spray 3.4 oz', 'Valentino', 'perfume', 'unisex', 'Perfume aireado y delicado, con una estela luminosa y femenina.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-unisex-linnocence-de-lair-edp-spray-34-oz-fragrances-3614274198645.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/v/a/valentino-unisex-linnocence-de-lair-edp-spray-34-oz-fragrances-3614274198645.jpg', 'https://cms.brnstc.de/product_images/1122x1536_retina/cpro/media/images/product/26/1/3614274198645_0_1769754668926.jpg', 'https://cms.brnstc.de/product_images/680x930_retina/cpro/media/images/product/26/1/3614274198645_0_1769754668926.jpg']::text[], 'https://www.jomashop.com/valentino-unisex-linnocence-de-lair-edp-spray-3-4-oz-fragrances-3614274198645.html', 288.99, 394.99, 'Combínalo con reloj fino, vestido marfil o abrigo camel y tacones de cuero nude.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-76e86cc39c9a', 'mp-3c75f66f94e0', 'mp-23af6e30e1cc']::text[], 'Para noche e invierno, los pantalones de lana y los loafers de terciopelo acompañan la profundidad del perfume con mucha presencia. El reloj azul completa un conjunto clásico, refinado y con carácter.', 'noche', ARRAY['mp-0cf3b002ce9d', 'mp-a88c1eb55d5a', 'mp-d65a17879766']::text[], 'Para noche e invierno, el mini dress estructurado junto a las botas de combate de cuero crea contraste elegante y potente. El reloj madreperla suaviza el conjunto; el perfume cálido y especiado aporta una estela envolvente.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d65a17879766', 'theoutnet', 'ton-665933301267822', 'Cropped Fringed Metallic Tweed Straight Leg Pants', 'Balmain', 'clothing', 'women', 'Tweed metálico con flecos y corte preciso, pensado para destacar con sofisticación moderna.', 'https://www.theoutnet.com/variants/images/665933301267822/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/665933301267822/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/665933301267822/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/665933301267822/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/665933301267822/E/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/pants/straight-leg-pants/cropped-fringed-metallic-tweed-straight-leg-pants/665933301267822', 289, 394.99, 'Llévalo con reloj joya, perfume floral intenso y top negro, sandalias finas o blazer estructurado en tono marfil.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-08cb860e5a5a', 'mp-a88c1eb55d5a', 'mp-db3e96bd55d9']::text[], 'El tweed metálico cobra sobriedad con loafers de cuero y un reloj en madreperla. El perfume, floral y luminoso, aporta pulcritud; ideal para oficina con agenda de cóctel o lunch formal.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_n