INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b790003b93bf', 'theoutnet', 'ton-46376663163107934', 'Giardino Cotton Canvas Cargo Shorts', 'Jacquemus', 'clothing', 'men', 'Short cargo de lona, funcional y limpio, con espíritu relajado.', 'https://www.theoutnet.com/variants/images/46376663163107934/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163107934/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107934/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107934/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107934/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163107934/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jacquemus/shorts/casual-shorts/giardino-cotton-canvas-cargo-shorts/46376663163107934', 289, 394.99, 'Úsalo con reloj utilitario, perfume fresco y camisa de lino o polo crudo con sneakers blancas.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-e0ac20e6c3ac', 'mp-37af76f7012d']::text[], 'Las espadrilles afinan el cargo short sin restarle frescura. El Tsuyosa verde introduce un acento moderno y discreto, y The Last Day Of Summer aporta un tono verde-floral suave, ideal para un plan urbano de día.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a02fdec76331', 'theoutnet', 'ton-46376663163064355', 'Embellished High Rise Straight Leg Jeans', 'Versace', 'clothing', 'women', 'Jean de tiro alto con brillo ornamental, para una presencia llamativa y refinada.', 'https://www.theoutnet.com/variants/images/46376663163064355/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163064355/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163064355/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163064355/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163064355/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163064355/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/jeans/straight-leg-jeans/embellished-high-rise-straight-leg-jeans/46376663163064355', 290, 395.99, 'Suma reloj metálico, perfume oriental y top negro, blazer sastrero o stilettos en cuero liso.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-d0246a15c10d', 'mp-69e7777fc13e', 'mp-907d601e36bb']::text[], 'El denim bordado se eleva con pumps refinados y un reloj negro de presencia discreta. El perfume, oud floral y elegante, remata un look de noche con lujo silencioso y actitud segura.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f63eb8828e5a', 'theoutnet', 'ton-46376663163070143', 'French Cotton Terry Hoodie', 'Onia', 'clothing', 'men', 'Hoodie de terry francés, suave y fácil, con aire deportivo pulido.', 'https://www.theoutnet.com/variants/images/46376663163070143/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163070143/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163070143/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163070143/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163070143/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163070143/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/tops/hoodies-zip-throughs/french-cotton-terry-hoodie/46376663163070143', 290, 395.99, 'Llévalo con reloj deportivo, perfume limpio y jogger gris o denim con zapatillas blancas.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-e518f29b87d4', 'mp-171458574e87', 'mp-605a39d82c0f']::text[], 'Las sneakers livianas equilibran el hoodie con un aire deportivo limpio. El Seiko negro añade solidez urbana, y Luna Rossa Carbon suma un carácter fresco, ambarado y moderno, ideal para invierno casual.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EX