INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5aaf8537baea', 'theoutnet', 'ton-1647597357868479', 'Air Pegasus 2k5 Leather And Mesh Sneakers', 'Nike', 'shoes', 'men', 'Zapatilla de perfil retro, ligera y versátil, con presencia urbana.', 'https://www.theoutnet.com/variants/images/1647597357868479/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597357868479/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597357868479/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597357868479/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597357868479/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597357868479/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/air-pegasus-2k5-leather-and-mesh-sneakers/1647597357868479', 290, 395.99, 'Combínalas con reloj deportivo, perfume cítrico y pantalón recto o short técnico con camiseta blanca.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-f63eb8828e5a', 'mp-c27ae7cfc8ab', 'mp-605a39d82c0f']::text[], 'El hoodie y el Promaster crean un conjunto atlético, cómodo y bien resuelto. Luna Rossa Carbon aporta frescura limpia con fondo aromático y ligeramente mineral, perfecto para uso diario y clima fresco.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ec3bfabe27c1', 'jomashop', 'SE-SRPL87K1', 'Seiko 5 Sports Automatic Yellow Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera amarilla vibrante y espíritu deportivo, para un estilo activo con carácter.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-yellow-dial-mens-watch-srpl87k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-yellow-dial-mens-watch-srpl87k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-yellow-dial-mens-watch-srpl87k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-yellow-dial-mens-watch-srpl87k1_3.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Sports-Automatic-Yellow-Dial-Men-s-Watch-SRPL87K1_faa43c82-a13d-434d-9b63-754d1bc9216c.7ade446ddcb1a29a9560153a607ec963.jpeg', 'https://www.skywatches.com.sg/cdn/shop/files/Seiko5SportsSRPL87K1AutomaticWatch.png?v=1746436084&width=1200', 'https://www.auswatches.com/media/catalog/product/cache/f20a3dad9a18e1857a6578422466bfb5/s/r/srpl87k1_00.jpg']::text[], 'https://www.jomashop.com/seiko-5-sports-automatic-yellow-dial-mens-watch-srpl87k1.html', 290.99, 396.99, 'Combínalo con zapatillas técnicas, camiseta blanca y perfume cítrico; deja que el reloj aporte el acento.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-f63eb8828e5a', 'mp-ab3a6a32e967', 'mp-2ecaf353c55e']::text[], 'El hoodie y las sneakers sostienen el carácter sport del reloj amarillo. Gentleman Society Sport añade una frescura aromática, moderna y limpia, ideal para entrenamiento ligero, ciudad o fin de semana activo.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e0ac20e6c3ac', 'jomashop', 'CZNK5010-51X', 'Citizen Tsuyosa Automatic Green Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Esfera verde con estética limpia y energía contenida, para un gusto actual y sereno.', 'https://citizenwatch.widen.net/content/6q8sjtsvo4/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/6q8sjtsvo4/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/a5m7criwvr/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/cnecrs4lzv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-salmon-dial-mens-watch-nk501051x.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-salmon-dial-mens-watch-nk501051x_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-tsuyosa-automatic-salmon-dial-mens-watch-nk501051x_3.jpg']::text[], 'https://www.jomashop.com/citizen-tsuyosa-automatic-salmon-dial-mens-watch-nk5010-51x.html', 293.55, 399.99, 'Combínalo con camisa azul claro, pantalón beige y perfume fresco; suma mocasines marrón oscuro para equilibrio.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-6e4425667ee2', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'La Oxford y los loafers Bally elevan el Tsuyosa sin rigidez, con elegancia serena. Grey Vetiver refuerza el conjunto con un vetiver limpio, seco y profesional, perfecto para oficina o almuerzo de negocios.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7ea9b28f9a34', 'jomashop', 'CZBU2021-51L', 'Citizen Calendrier Eco-Drive World Time Dark Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Calendario mundial en azul profundo, sobrio y funcional, con presencia internacional.', 'https://citizenwatch.widen.net/content/yceoioovzf/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/yceoioovzf/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/s8kjsso3mn/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/18x0goweee/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/hezi7vpbpu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-calendrier-ecodrive-world-time-dark-blue-dial-mens-watch-bu202151l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-calendrier-ecodrive-world-time-dark-blue-dial-mens-watch-bu202151l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-calendrier-ecodrive-world-time-dark-blue-dial-mens-watch-bu202151l_3.jpg']::text[], 'https://www.jomashop.com/citizen-watch-bu2021-51l.html', 293.55, 399.99, 'Úsalo con traje azul marino, perfume amaderado limpio y zapatos negros; una correa lisa remata el conjunto.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4af1908c0185', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'La camisa de Officine Générale y los loafers Bally construyen un look pulcro y contemporáneo. Grey Vetiver acompaña con sobriedad fresca, ideal para trabajo, reuniones y una estética de lujo silencioso.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-69e7777fc13e', 'jomashop', 'TIST41118353', 'Tissot Le Locle Automatic Black Dial Ladies Watch', 'Tissot', 'watch', 'women', 'Reloj clásico de esfera negra y proporciones delicadas, con encanto formal permanente.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-le-locle-automatic-ladies-watch-t41.1.183.53.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-le-locle-automatic-ladies-watch-t41.1.183.53.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-le-locle-automatic-ladies-watch-t41.1.183.53_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-le-locle-automatic-ladies-watch-t41.1.183.53_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-le-locle-automatic-ladies-watch-t41.1.183.53_4.jpg', 'https://prestigetimepiececenter.com/cdn/shop/products/T41118353.jpg?v=1633445889', 'https://i.ibb.co/RDdMpkF/tissot-le-locle-black-dial-automatic-lady-watch-t41118353-1566473939-afd7b35d-progressive.jpg', 'https://prestigetimepiececenter.com/cdn/shop/products/t41118353b.jpg?v=1633445892']::text[], 'https://www.jomashop.com/tissot-le-loche-t41-1-183-53.html', 293.55, 399.99, 'Llévalo con blusa de seda, blazer entallado y perfume floral limpio; completa con tacones nude o negros.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-6f20cf2d2571', 'mp-2a81e6864b82', 'mp-db3e96bd55d9']::text[], 'El reloj de aire clásico se integra con pantalón amplio y pumps de ante para una silueta muy pulida. El perfume, floral y luminoso, es ideal para oficina y clima templado.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f34b7b9ce8bf', 'jomashop', 'Z-FJBLA', 'Tom Ford Unisex Tobacco Vanille EDP Spray 3.4 oz', 'Tom Ford', 'perfume', 'unisex', 'Tabaco y vainilla en una estela cálida, oscura y envolvente.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-tobacco-vanille-edp-spray-34-oz-fragrances-888066004503.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-tobacco-vanille-edp-spray-34-oz-fragrances-888066004503.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-tobacco-vanille-edp-spray-34-oz-fragrances-888066004503_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-tobacco-vanille-edp-spray-34-oz-fragrances-888066004503_3.jpg', 'https://parisgallery.ae/cdn/shop/products/888066004503.jpg?v=1643095455&width=2400']::text[], 'https://www.jomashop.com/tom-ford-unisex-tobacco-vanille-edp-spray-3-4-oz-fragrances-888066004503.html', 293.54, 399.99, 'Úsalo con abrigo camel, camisa negra, pantalón de lana y reloj de acero con cuero marrón.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-bdcc5c48a475', 'mp-d92a8189d8f4', 'mp-c109304a8cd3']::text[], 'Para una noche de invierno, el sweater de lana y los boots de ante equilibran la calidez del tabaco y vainilla. El reloj de buceo añade contraste moderno a un look masculino, oscuro y sofisticado.', 'invierno', ARRAY['mp-cf73e236b136', 'mp-8f0d9702a286', 'mp-cbf5fd94f2da']::text[], 'Para noche e invierno, el mini dress de punto y las botas altas crean una silueta envolvente. El reloj en verde suave aporta delicadeza, mientras el perfume de tabaco y vainilla deja una estela cálida y sensual.', 'invierno') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6e4425667ee2', 'theoutnet', 'ton-46376663163094985', 'Cotton Oxford Shirt', 'Onia', 'clothing', 'men', 'Camisa Oxford de algodón, nítida y esencial, para un estilo impecable.', 'https://www.theoutnet.com/variants/images/46376663163094985/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163094985/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094985/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094985/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094985/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094985/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/tops/casual-shirts/cotton-oxford-shirt/46376663163094985', 294, 400.99, 'Úsala con reloj clásico, perfume limpio y pantalón de vestir azul marino con loafers marrón.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-6e78cd2c0e9e', 'mp-aef4c954ee47', 'mp-4520d6ec87f1']::text[], 'Para oficina, la camisa Oxford, los penny loafers y el PRX negro construyen una imagen limpia y precisa. El vetiver refuerza el aire profesional, fresco y sobrio, ideal para Lima todo el año.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ac85563341af', 'theoutnet', 'ton-46376663163085646', 'Braided Leather Trimmed Suede Loafers', 'Gianvito Rossi', 'shoes', 'men', 'Mocasines de gamuza con borde trenzado, discretos y pulidos para una elegancia serena.', 'https://www.theoutnet.com/variants/images/46376663163085646/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163085646/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163085646/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163085646/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163085646/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163085646/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/gianvito-rossi/flat-shoes/loafers/braided-leather-trimmed-suede-loafers/46376663163085646', 294, 400.99, 'Con reloj de acero, perfume amaderado, pantalón de lana gris y camisa blanca impecable.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-76e86cc39c9a', 'mp-a7fbae0e4ca7', 'mp-cf2b71c1d9e8']::text[], 'Con pantalón de lana, reloj fino y un perfume amaderado-luminoso, estos loafers quedan impecables para oficina o cena discreta. El conjunto transmite calma, precisión y una elegancia masculina muy actual.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ab3a6a32e967', 'theoutnet', 'ton-46376663163158221', 'Field General 82 Mesh And Leather Sneakers', 'Nike', 'shoes', 'men', 'Sneakers de malla y cuero con aire retro, ligeros y versátiles para el día a día.', 'https://www.theoutnet.com/variants/images/46376663163158221/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158221/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158221/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158221/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158221/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158221/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/field-general-82-mesh-and-leather-sneakers/46376663163158221', 294, 400.99, 'Con reloj deportivo fino, perfume fresco, polo beige y pantalón chino azul marino.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-34ed970dbc5d', 'mp-68a041916a67', 'mp-605a39d82c0f']::text[], 'Para ti, un look limpio y activo: la camiseta con las Nike Field General y el Seiko 5 Sport equilibran energía y precisión. Ideal para fin de semana o viaje; Luna Rossa Carbon suma frescura especiada, moderna y segura.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-34ed970dbc5d', 'jomashop', 'SE-SRPK09K1', 'Seiko 5 Sports Automatic Silver Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Acero pulido y esfera sobria para un ritmo diario con espíritu deportivo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-silver-dial-mens-watch-srpk09k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-silver-dial-mens-watch-srpk09k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-silver-dial-mens-watch-srpk09k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-silver-dial-mens-watch-srpk09k1_3.jpg', 'https://i5.walmartimages.com/seo/Seiko-5-Sports-Automatic-Silver-Dial-Men-s-Watch-SRPK09K1_b2c34e20-d525-46f0-8611-060b4dffe795.70e6302eef60ed069b480649494095dd.jpeg?odnHeight=640&odnWidth=640&odnBg=FFFFFF', 'https://cdnstatic.creationwatches.com/products/product-images/l/SRPK09K1_3_LRG.webp', 'https://www.skywatches.com.sg/cdn/shop/products/sssgid.zone-1693982086-SRPK09K1__2.png?v=1693983003&width=1100']::text[], 'https://www.jomashop.com/seiko-5-sports-automatic-silver-dial-mens-watch-srpk09k1.html', 295, 401.99, 'Combínalo con polo, denim oscuro y zapatillas blancas o mocasines; el perfume cítrico mantiene la frescura.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-94e22572660d', 'mp-ab3a6a32e967', 'mp-605a39d82c0f']::text[], 'Para ti, el reloj gana presencia con joggers técnicos y unas Nike Field General. Funciona muy bien en fin de semana o escapadas urbanas; Luna Rossa Carbon aporta un carácter limpio, aromático y ligeramente amaderado.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
