, 'mp-474b2526c36a', 'mp-1f0254abf485']::text[], 'Para ti, el mini dress con botas y el PRX negro marcan una silueta poderosa y nocturna. Royal Princess Oud suma un oud elegante, cálido y especiado, ideal para invierno, cóctel o cena de impacto.', 'noche', ARRAY['mp-a02fdec76331', 'mp-0cf3b002ce9d', 'mp-69e7777fc13e']::text[], 'Una selección equilibrada por estilo, ocasión, nivel de precio y género para completar el conjunto.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
