=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0cb42bb2/product-pictures/56d0080b-e6d1-4ae3-8cc4-936a361c2ba9_T137_210_11_091_00.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-quartz-light-green-dial-ladies-watch-t1372101109100.html', 299.25, 406.99, 'Combínalo con blusa blanca, pantalón recto y mocasines; añade perfume fresco para un lujo cotidiano muy pulido.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-754d371ec329', 'mp-08cb860e5a5a', 'mp-db3e96bd55d9']::text[], 'La esfera verde suave armoniza con pantalón crema, loafers pulidos y un perfume luminoso. Es un look de oficina elegante, ideal para Lima todo el año; Love in White refuerza su frescura floral y pulida.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
