INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0949465cf5b3', 'theoutnet', 'ton-1647597306802788', 'Pleated Denim Mini Skirt', 'Balmain', 'clothing', 'women', 'Minifalda denim con pliegues definidos, de espíritu joven y acabado pulcro.', 'https://www.theoutnet.com/variants/images/1647597306802788/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597306802788/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306802788/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306802788/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306802788/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306802788/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/skirts/mini-skirts/pleated-denim-mini-skirt/1647597306802788', 302, 410.99, 'Úsala con reloj metálico, perfume limpio y camisa de popelina o botines; el denim oscuro equilibra el look.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-d0246a15c10d', 'mp-cbf5fd94f2da', 'mp-db3e96bd55d9']::text[], 'La mini falda denim se eleva con pumps minimalistas, un PRX verde claro y Love in White. Funciona en clima templado de verano o entretiempo; el perfume aporta un halo floral, limpio y muy femenino.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-59cfe62fcbe3', 'theoutnet', 'ton-46376663163158236', 'Field General 82 sp Mesh And Leather Sneakers', 'Nike', 'shoes', 'men', 'Sneakers de malla y cuero con silueta retro, funcionales y actuales.', 'https://www.theoutnet.com/variants/images/46376663163158236/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158236/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158236/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158236/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158236/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158236/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158236/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/field-general-82-sp-mesh-and-leather-sneakers/46376663163158236', 302, 410.99, 'Con reloj deportivo, perfume limpio, jeans rectos y camiseta gris claro.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-68a041916a67', 'mp-171458574e87', 'mp-605a39d82c0f']::text[], 'Las sneakers ganan equilibrio con la camiseta limpia, el Seiko deportivo y una fragancia amaderada-aromática. Ideal para un fin de semana urbano en Lima, con energía relajada y pulcritud contemporánea.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-171458574e87', 'jomashop', 'SE-SSK025K1', 'Seiko 5 Sports Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Automático negro con función GMT, robusto y versátil para el día a día.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-ssk025k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-ssk025k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-ssk025k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-ssk025k1_3.jpg']::text[], 'https://www.jomashop.com/seiko-5-sports-automatic-black-dial-mens-watch-ssk025k1.html', 303.05, 411.99, 'Combínalo con camiseta premium, jogger estructurado y sneakers negras; un perfume cítrico-amaderado lo mantiene equilibrado.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-59cfe62fcbe3', 'mp-605a39d82c0f']::text[], 'El reloj pide una base casual impecable: camiseta esencial, sneakers versátiles y un perfume fresco, especiado y masculino. Funciona perfecto para días activos o salidas informales con aire moderno.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-db86cdd766da', 'jomashop', 'COS-CSFES25', 'Creed Spring Flower by Creed EDP Spray 2.5 oz (w) (75 ml)', 'Creed', 'perfume', 'unisex', 'Fragancia floral luminosa, femenina y delicada, con un aire de jardín elegante.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-spring-flower-by-creed-edp-spray-2-5-oz-w-75-ml-3508441104563_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-spring-flower-by-creed-edp-spray-2-5-oz-w-75-ml-3508441104563_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-spring-flower-by-creed-edp-spray-25-oz-w-75-ml-3508441104563_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-spring-flower-by-creed-edp-spray-25-oz-w-75-ml-3508441104563_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-spring-flower-by-creed-edp-spray-25-oz-w-75-ml-3508441104563_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-spring-flower-by-creed-edp-spray-25-oz-w-75-ml-3508441104563_7.jpg', 'https://res.cloudinary.com/dp9dnliwc/image/upload/c_mfit,h_1200,w_1200/f_auto/q_auto/wmmedia/extra-images/large/3508441104563_6926163ad5d266.04882656.jpg']::text[], 'https://www.jomashop.com/creed-csfes25.html', 302.8, 411.99, 'Con reloj fino, vestido blanco, sandalias nude y joyería mínima en oro.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-76e86cc39c9a', 'mp-e5ebd0bc8e1d', 'mp-aaadd7c31bbe']::text[], 'Con este vestido, las ballerinas y el PRX de nácar, el perfume luce femenino y refinado. Perfecto para verano, cóctel o cena; Spring Flower aporta un bouquet floral limpio, luminoso y elegante, sin exceso.', 'elegante', ARRAY['mp-86d959f332e4', 'mp-d0246a15c10d', 'mp-481160552c8a']::text[], 'Una selección equilibrada por estilo, ocasión, nivel de precio y género para completar el conjunto.', 'lujo-silencioso') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2ad272892924', 'theoutnet', 'ton-46376663163074788', 'Cotton And Linen Blend Shirt', 'Sandro', 'clothing', 'men', 'Camisa de algodón y lino con caída limpia, sobria y versátil.', 'https://www.theoutnet.com/variants/images/46376663163074788/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163074788/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074788/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074788/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074788/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074788/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/sandro/tops/casual-shirts/cotton-and-linen-blend-shirt/46376663163074788', 303, 411.99, 'Con reloj de acero, perfume fresco, pantalón marino y mocasines marrones.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-7795ae7c1d60', 'mp-aef4c954ee47', 'mp-4520d6ec87f1']::text[], 'La camisa de lino se afina con loafers, PRX negro y vetiver elegante. Un conjunto sobrio para oficina o almuerzo ejecutivo, especialmente en clima cálido: limpio, refinado y sin exceso.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-31086b2d67a6', 'theoutnet', 'ton-46376663163125550', 'Out of Office Leather Sneakers', 'Off-White', 'shoes', 'men', 'Sneakers de cuero con carácter limpio, fáciles de combinar y discretamente sofisticados.', 'https://www.theoutnet.com/variants/images/46376663163125550/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163125550/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125550/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125550/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125550/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125550/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-leather-sneakers/46376663163125550', 303, 411.99, 'Con reloj de acero, perfume amaderado suave, pantalón sastre beige y camisa oxford.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-2ad272892924', 'mp-aef4c954ee47', 'mp-337d48edab34']::text[], 'Las sneakers elevan su perfil con camisa de lino, PRX negro y un perfume acuático limpio. El resultado es relajado pero pulido, ideal para cenas informales o viernes de oficina.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_