INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-031aa53c410f', 'jomashop', 'TIST1372101108100', 'Tissot PRX Quartz Green Dial Unisex Watch', 'Tissot', 'watch', 'unisex', 'PRX verde unisex con diseño limpio y temperamento contemporáneo, fácil de llevar.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwbe92c1c4/product-pictures/7d3461dd-2c02-44fe-8b56-1b2853b39637_T137-210-11-081-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwbe92c1c4/product-pictures/7d3461dd-2c02-44fe-8b56-1b2853b39637_T137-210-11-081-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwbe92c1c4/product-pictures/7d3461dd-2c02-44fe-8b56-1b2853b39637_T137-210-11-081-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw97e1a887/product-pictures/e5b77c91-2c46-495c-a139-a0c229f29794_T137_210_11_081_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1dcd3295/product-pictures/9d149ecf-49f0-4fbf-9714-64d4ff232471_T137_210_11_081_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwc736ef73/product-pictures/8877c08d-a498-45ec-b967-a597fe8eb838_T137_210_11_081_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw55381c39/product-pictures/8b4e16b3-2a7d-47c8-94f9-8f2c81922c2c_T137_210_11_081_00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-green-dial-unisex-watch-t1372101108100.jpg']::text[], 'https://www.jomashop.com/tissot-prx-quartz-green-dial-unisex-watch-t1372101108100.html', 303.53, 412.99, 'Con camisa blanca, pantalón sastre beige y mocasines, más perfume fresco, logra un lujo silencioso cotidiano.', 'https://lifewithjazz.com/wp-content/uploads/2022/04/5-Smart-Casual-Outfits-Last-picture.jpg', ARRAY['mp-2ad272892924', 'mp-7795ae7c1d60', 'mp-2dc2d5978672']::text[], 'La camisa estructurada, las ballerinas y el PRX verde crean un look de oficina muy limpio y femenino. Elle aporta brillo floral-almizclado, fresco y seguro; ideal para trabajo, reuniones y una transición amable a la tarde.', 'oficina', ARRAY['mp-c63686b7891d', 'mp-771e0dce9f5f', 'mp-2dc2d5978672']::text[], 'Una selección equilibrada por estilo, ocasión, nivel de precio y género para completar el conjunto.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-564a32ef0fa0', 'jomashop', 'TIST1374101142100', 'Tissot PRX Quartz Red Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Esfera roja con líneas limpias: una PRX moderna que aporta carácter sin perder sobriedad.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw5fc30e95/product-pictures/51a33ec8-1154-4527-ae43-dd129850416c_T137-410-11-421-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw5fc30e95/product-pictures/51a33ec8-1154-4527-ae43-dd129850416c_T137-410-11-421-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw5fc30e95/product-pictures/51a33ec8-1154-4527-ae43-dd129850416c_T137-410-11-421-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw6fcebf93/product-pictures/cc7b830e-d5bf-418a-8e5b-989e6658072c_T137-410-11-421-00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw2e3e482d/product-pictures/89ca7017-2cbb-4efb-9ac4-57435858a554_T137-410-11-421-00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw3db287f4/product-pictures/37ea169e-59c8-4b34-a74b-61ab1525c083_T137-410-11-421-00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw13bc2b85/product-pictures/86c9ea83-5567-4c17-8b8c-c02eb841348d_T137-410-11-421-00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-red-dial-mens-watch-t1374101142100.jpg']::text[], 'https://www.jomashop.com/tissot-prx-quartz-red-dial-mens-watch-t1374101142100.html', 303.53, 412.99, 'Llévalo con camisa blanca, blazer azul marino, pantalón gris y derby negro; perfume amaderado discreto.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-2ad272892924', 'mp-a1a9c18f6ebe', 'mp-9c175b220b04']::text[], 'El dial rojo aporta carácter a una camisa de lino, loafers sobrios y vetiver elegante. Conjunto de lujo silencioso para oficina creativa o cenas tempranas, con contraste refinado y moderno.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-76e86cc39c9a', 'theoutnet', 'ton-1647597350852210', 'Grain de Poudre Pants', 'Thom Browne', 'clothing', 'men', 'Pantalón de lana con caída impecable, preciso y muy pulido.', 'https://www.theoutnet.com/variants/images/1647597350852210/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597350852210/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597350852210/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597350852210/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597350852210/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597350852210/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/pants/tailored-pants/grain-de-poudre-pants/1647597350852210', 304, 412.99, 'Con reloj clásico, perfume seco, camisa celeste y mocasines negros de cuero.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-55daa2a79111', 'mp-a7fbae0e4ca7', 'mp-72eecd3685e7']::text[], 'El pantalón de lana pide penny loafers y un reloj de línea impecable. El perfume tabacoso y elegante refuerza una imagen ejecutiva de alto nivel, ideal para oficina y reuniones formales.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
