note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-fbc3b40db622', 'jomashop', 'Y-129884', 'Giorgio Armani - Prive Vert Malachite Eau De Parfum Spray 100ml / 3.4oz', 'Giorgio Armani', 'perfume', 'unisex', 'Ámbar verde con matiz exótico, intenso y pulido para una estela distinguida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-prive-vert-malachite-eau-de-parfum-spray-100ml-34oz-3614271063700.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-prive-vert-malachite-eau-de-parfum-spray-100ml-34oz-3614271063700.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-prive-vert-malachite-eau-de-parfum-spray-100ml-34oz-3614271063700_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-prive-vert-malachite-eau-de-parfum-spray-100ml-34oz-3614271063700_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/g/i/giorgio-armani-prive-vert-malachite-eau-de-parfum-spray-100ml-34oz-3614271063700_7.jpg', 'https://www.cdiscount.com/pdt2/7/0/0/1/550x550/auc3614271063700/rw/giorgio-armani-prive-vert-malachite-eau-de-parfum.jpg']::text[], 'https://www.jomashop.com/giorgio-armani-prive-vert-malachite-eau-de-parfum-spray-100ml-3-4oz-3614271063700.html', 304.99, 413.99, 'Con reloj oscuro, traje negro, camisa de seda y zapatos oxford brillantes.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-1e4d84f905c4', 'mp-3c75f66f94e0', 'mp-23af6e30e1cc']::text[], 'Este vestido, los pumps y el PRX con diamantes forman un look de noche impecable y sofisticado. Vert Malachite acompaña con flores verdes, cremosidad y profundidad, ideal para cena, gala o cóctel con presencia.', 'noche', ARRAY['mp-5fc9d7d58615', 'mp-d0246a15c10d', 'mp-481160552c8a']::text[], 'Una selección equilibrada por estilo, ocasión, nivel de precio y género para completar el conjunto.', 'lujo-silencioso') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e0d60717ea9e', 'jomashop', 'SE-SRPL83K1', 'Seiko 5 Sports SKX Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Azul profundo y espíritu retro: un Seiko versátil con presencia relajada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-automatic-blue-dial-mens-watch-srpl83k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-automatic-blue-dial-mens-watch-srpl83k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-automatic-blue-dial-mens-watch-srpl83k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-automatic-blue-dial-mens-watch-srpl83k1_3.jpg', 'https://www.reddeerwatches.com/media/catalog/product/cache/f20a3dad9a18e1857a6578422466bfb5/s/r/srpl83k1_00.jpg', 'https://www.strapseeker.com/cdn/shop/files/Seiko5SportsAutomaticBlueDialSteelSRPL83K1SRPL83SRPL83.png?v=1746430244&width=1200']::text[], 'https://www.jomashop.com/seiko-5-sports-skx-automatic-blue-dial-mens-watch-srpl83k1.html', 305, 414.99, 'Combínalo con polo marino, chaqueta ligera, denim oscuro y zapatillas blancas; perfume cítrico limpio.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-66518207ba70', 'mp-59cfe62fcbe3', 'mp-8d5bb353d59a']::text[], 'El Seiko azul encaja con camisa de lino, sneakers retro y un neroli fresco y luminoso. Un look casual con aire costero, ideal para fines de semana o almuerzos al aire libre.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-396173c2b3e2', 'theoutnet', 'ton-46376663163093779', 'Stretch Knit Mini Dress', 'Tom Ford', 'clothing', 'women', 'Mini dress de punto stretch, ceñido y sofisticado con una silueta precisa.', 'https://www.theoutnet.com/variants/images/46376663163093779/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163093779/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093779/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093779/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093779/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163093779/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/dresses/mini-dresses/stretch-knit-mini-dress/46376663163093779', 305, 414.99, 'Con reloj joya, perfume floral oscuro, sandalias negras y abrigo largo estructurado.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-2a81e6864b82', 'mp-da98d2ee7fd3', 'mp-58072ada40a0']::text[], 'El mini dress se potencia con pumps clásicos, PRX nácar y un cuero sensual, limpio y sofisticado. Conjunto pensado para noche, elegante y preciso, con presencia femenina y segura.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c63686b7891d', 'theoutnet', 'ton-46376663162908087', 'Alpaca Cotton And Wool Blend Vest', 'Maison Margiela', 'clothing', 'women', 'Mezcla de alpaca, algodón y lana: un chaleco sobrio con textura noble.', 'https://www.theoutnet.com/variants/images/46376663162908087/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162908087/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162908087/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162908087/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162908087/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162908087/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/maison-margiela/knitwear/v-neck-sweaters/alpaca-cotton-and-wool-blend-vest/46376663162908087', 305, 414.99, 'Úsalo sobre camisa cruda, pantalón sastre cacao y loafers; añade reloj metálico y perfume amaderado suave.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-771e0dce9f5f', 'mp-f67e672616b5', 'mp-6a32aace5e0a']::text[], 'El chaleco se afina con ballet flats, PRX verde suave y neroli fresco. Una fórmula de lujo silencioso para oficina o jornadas creativas, pulcra, ligera y muy actual.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUD