INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-329e187dadcb', 'jomashop', 'TIST1374101701100', 'Tissot PRX Quartz White Dial Men''s Watch', 'Tissot', 'watch', 'men', 'PRX de esfera blanca y correa textil: limpia, ligera y naturalmente pulida.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb63f94c4/product-pictures/8d561e42-6aa9-475d-b746-3ac14f35a7dd_T137-410-17-011-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb63f94c4/product-pictures/8d561e42-6aa9-475d-b746-3ac14f35a7dd_T137-410-17-011-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb63f94c4/product-pictures/8d561e42-6aa9-475d-b746-3ac14f35a7dd_T137-410-17-011-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw5da5f833/product-pictures/a9ebd580-9d2c-45c1-879b-6caa9a1a631d_T137_410_17_011_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw7b762cd7/product-pictures/b3f559d0-7798-454c-9d9e-057e570a9891_T137_410_17_011_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw2922ca7c/product-pictures/b0444de9-a4c8-4eee-bbe6-66793d84fefc_T137_410_17_011_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwd4d29525/product-pictures/f5e7f9ae-b2d1-49c8-89b8-67351060dc21_T137_410_17_011_00_Superluminova.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwa318e393/product-pictures/cc98771d-ffc7-4fa8-8649-b9c91c477b92_T137_410_17_011_00.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-quartz-white-dial-mens-watch-t137-410-17-011-00.html', 306, 415.99, 'Lúcelo con camisa celeste, chino beige, mocasines café y perfume cítrico amaderado de corte fresco.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4af1908c0185', 'mp-a1a9c18f6ebe', 'mp-4520d6ec87f1']::text[], 'El blanco del PRX combina con camisa ligera, loafers de pebbled leather y vetiver seco. Un conjunto limpio y sofisticado para oficina o almuerzos ejecutivos, con estética de lujo silencioso.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5bd09782904d', 'theoutnet', 'ton-46376663163103781', 'Afador Cotton Terry Drawstring Shorts', 'Orlebar Brown', 'clothing', 'men', 'Bermudas de felpa con caída suave, cómodas y relajadas para clima cálido.', 'https://www.theoutnet.com/variants/images/46376663163103781/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163103781/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103781/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103781/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103781/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163103781/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/orlebar-brown/shorts/casual-shorts/afador-cotton-terry-drawstring-shorts/46376663163103781', 306, 415.99, 'Con reloj deportivo fino, perfume acuático, polo claro y sneakers blancos.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-59cfe62fcbe3', 'mp-c27ae7cfc8ab', 'mp-0e1d44d63a68']::text[], 'Los shorts de terry funcionan mejor con sneakers ligeras, reloj deportivo y un perfil acuático fresco. Perfecto para verano y fines de semana en Lima, cómodo, limpio y con aire náutico.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXC