&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwdd0d233b/product-pictures/7e41bde9-42ae-4deb-9cbd-3cbb97254db1_T137-410-11-031-00_AMB_3.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-quartz-silver-dial-mens-watch-t137-410-11-031-00.html', 307.8, 417.99, 'Combínala con blazer gris, camisa blanca, pantalón azul noche y derbies negros; perfume limpio almizclado.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4af1908c0185', 'mp-7795ae7c1d60', 'mp-4520d6ec87f1']::text[], 'La camisa de lino, los loafers y el PRX plateado construyen un estilo de oficina relajado y preciso. Grey Vetiver suma un aire limpio, seco y elegante, ideal para jornadas largas, reuniones y clima cálido.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-481160552c8a', 'jomashop', 'TIST1372101103100', 'Tissot PRX Quartz Silver Dial Ladies Watch', 'Tissot', 'watch', 'women', 'Esfera nacarada y acero pulido: una PRX femenina, luminosa y serena.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw25729185/product-pictures/88373bf5-79c4-46b1-92c8-8d63251c61ca_T137-210-11-031-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw25729185/product-pictures/88373bf5-79c4-46b1-92c8-8d63251c61ca_T137-210-11-031-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw25729185/product-pictures/88373bf5-79c4-46b1-92c8-8d63251c61ca_T137-210-11-031-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw9b881fdf/product-pictures/4976e0c6-a9c6-47de-801e-624e6e8de354_T137_210_11_031_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw55b20f68/product-pictures/34791abe-60c9-4881-9f28-42997511e9a4_T137_210_11_031_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1567f999/product-pictures/5d45049f-afb7-493b-a8f0-462d46242946_T137_210_11_031_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0d0b0151/product-pictures/c30c103b-a1e7-40b5-9194-f9cbf7d24a53_T137_210_11_031_00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-quartz-silver-dial-ladies-watch-t1372101103100.jpg']::text[], 'https://www.jomashop.com/tissot-quartz-silver-dial-ladies-watch-t1372101103100.html', 307.8, 417.99, 'Acompáñala con blazer marfil, blusa de seda, pantalón recto negro y tacones nude; perfume floral sutil.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-e80799294eb5', 'mp-771e0dce9f5f', 'mp-d2572817bc32']::text[], 'Para ti, la camisa Ferragamo, las ballerinas y el PRX de acero crean una oficina impecable y femenina. Libre Le Parfum aporta lavanda cálida, flores blancas y un fondo ambarado, elegante para el día.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e80799294eb5', 'theoutnet', 'ton-46376663163159527', 'Topstitched Poplin Shirt', 'Ferragamo', 'clothing', 'women', 'Camisa de popelina con costuras visibles: estructura precisa y elegancia sobria.', 'https://www.theoutnet.com/variants/images/46376663163159527/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163159527/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159527/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159527/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159527/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159527/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/tops/long-sleeved-tops/topstitched-poplin-shirt/46376663163159527', 308, 417.99, 'Combínala con sastre azul tinta, reloj de acero, loafers negros y perfume fresco amaderado.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-a817148e69da', 'mp-031aa53c410f', 'mp-6a32aace5e0a']::text[], 'Con sneakers limpios y el PRX verde, la camisa se vuelve casual pero muy pulida, perfecta para oficina relajada o fin de semana. Neroli Sauvage añade cítricos brillantes, neroli y frescura refinada, sin invadir.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-50b447eced89', 'jomashop', 'SE-SRPK18', 'Seiko 5 Sports Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera negra y estética robusta: un Seiko clásico para el ritmo diario.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-srpk18.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-srpk18.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-srpk18_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-automatic-black-dial-mens-watch-srpk18_2.jpg', 'https://cdn11.bigcommerce.com/s-uzonwrhn18/images/stencil/1920w/products/18495/97835/SRPK18-03__72302.1690725497.jpg?c=1', 'https://s.turbifycdn.com/aah/4-watches/seiko-5-sports-srpk18-gold-tone-black-dial-automatic-watch-8.jpg', 'https://cdn11.bigcommerce.com/s-uzonwrhn18/images/stencil/2560w/products/18495/97832/SRPK18-04__05952.1690725497.jpg?c=1', 'https://cdn11.bigcommerce.com/s-uzonwrhn18/images/stencil/1920w/products/18495/97831/SRPK18-05__73612.1690725496.jpg?c=1']::text[], 'https://www.jomashop.com/seiko-seiko-5-sports-black-dial-mens-watch-srpk18.html', 309, 418.99, 'Llévalo con overshirt verde oliva, jean oscuro, botas o sneakers negras y perfume especiado limpio.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-054458c53a21', 'mp-0ee7e4469602', 'mp-605a39d82c0f']::text[], 'Las cargo, las sneakers y Luna Rossa Carbon equilibran el reloj deportivo con un look urbano y moderno. Ideal para ciudad o escapada casual; el perfume huele a lavanda, ambroxan y cítricos, limpio y enérgico.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-87146dc3b3db', 'jomashop', 'Z-QHBEH', 'Xerjoff Unisex Oud Stars Alexandria II EDP Spray 3.4 oz (100 ml)', 'Xerjoff', 'perfume', 'unisex', 'Ámbar, oud y especias: una composición intensa con presencia envolvente.', 'https://www.xerjoff.com/cdn/shop/files/gallery-xerjoff-alexandriaII-still.jpg?v=1749809880&width=1946', ARRAY['https://www.xerjoff.com/cdn/shop/files/gallery-xerjoff-alexandriaII-still.jpg?v=1749809880&width=1946', 'https://www.xerjoff.com/cdn/shop/files/gallery-xerjoff-alexandriaII-eau-de-parfum-100ml.png?v=1749810026&width=1946', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-unisex-oud-stars-alexandria-ii-edp-spray-34-oz-100-ml-8033488154967_1.jpg', 'https://mediahub.debenhams.us/m8033488154967_clear_xl.jpeg']::text[], 'https://www.jomashop.com/xerjoff-unisex-alexandria-ii-edp-spray-3-4-oz-fragrances-8033488154967.html', 308.74, 418.99, 'Úsalo con reloj dorado discreto, sastrería negra, cuero liso y tonos tabaco para una elegancia sobria.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-76e86cc39c9a', 'mp-3c75f66f94e0', 'mp-23af6e30e1cc']::text[], 'Para invierno y noche, este conjunto es impecable: el pantalón estructurado, los loafers de terciopelo y el Presage azul acompañan la profundidad del oud. La fragancia es rica, ambarada y resinosa, muy distinguida.', 'noche', ARRAY['mp-c234a66a0da9', 'mp-2a81e6864b82', 'mp-da98d2ee7fd3']::text[], 'Para una noche de invierno, este vestido midi con tacón clásico y reloj nacarado crea un conjunto pulido y femenino. Alexandria II aporta un aura ambarada, cremosa y especiada, ideal para una presencia elegante y memorable.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c2320d374c5f', 'theoutnet', 'ton-46376663163087952', 'Two Tone Linen Pants', 'Thom Browne', 'clothing', 'men', 'Pantalón de lino en dos tonos, sobrio y ligero con lenguaje sartorial.', 'https://www.theoutnet.com/variants/images/46376663163087952/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163087952/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163087952/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163087952/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163087952/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163087952/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/pants/casual-pants/two-tone-linen-pants/46376663163087952', 309, 418.99, 'Con reloj de acero, perfume fresco, camisa celeste y loafers de gamuza.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-55daa2a79111', 'mp-a7fbae0e4ca7', 'mp-cf2b71c1d9e8']::text[], 'Para oficina o reuniones formales, estos pantalones de lino funcionan con lo mejor de la sastrería discreta: mocasines con herencia, reloj champagne y un perfume refinado, amaderado y limpio. El resultado es sobrio, preciso y muy sofisticado.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-bf84af4d7df2', 'theoutnet', 'ton-46376663163158245', 'Dunk Low Retro se Suede Trimmed Leather Sneakers', 'Nike', 'shoes', 'men', 'Sneakers de cuero con paneles en gamuza, limpios y actuales para uso diario.', 'https://www.theoutnet.com/variants/images/46376663163158245/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158245/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158245/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158245/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158245/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158245/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158245/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/dunk-low-retro-se-suede-trimmed-leather-sneakers/46376663163158245', 309, 418.99, 'Con reloj de acero, perfume limpio, pantalón recto oscuro y camisa oxford blanca.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-4cccaaa0dc5d', 'mp-337d48edab34', 'mp-de9b3bac8274']::text[], 'Para un look casual con intención elegante, combina estas zapatillas con un reloj deportivo y una fragancia fresca, acuática y versátil. Es un conjunto ideal para ciudad de día, con equilibrio entre comodidad, energía y buen gusto.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6fc2da343618', 'theoutnet', 'ton-46376663163061019', 'Embellished Twisted Satin Jersey Dress', 'Versace', 'clothing', 'women', 'Satinado, brillo y drapeado definido: un vestido Versace para destacar con control.', 'https://www.theoutnet.com/variants/images/46376663163061019/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163061019/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061019/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061019/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061019/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163061019/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/dresses/knee-length-dresses/embellished-twisted-satin-jersey-dress/46376663163061019', 310, 420.99, 'Acompáñalo con reloj joya, perfume floral ambarado, sandalias finas negras y bolso rígido pequeño.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-85d352b48778', 'mp-3c1803aec5d1', 'mp-58072ada40a0']::text[], 'Para una noche especial, el vestido gana fuerza con pumps pulidos, reloj de detalle brillante y un perfume intenso de cuero y ámbar. Todo se siente refinado, sensual y perfectamente alineado con una ocasión elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-86d959f332e4', 'theoutnet', 'ton-1647597331468273', 'Satin Trimmed Wool Tapered Pants', 'Balmain', 'clothing', 'women', 'Pantalón de lana con ribetes satinados: sastrería precisa y carácter pulido.', 'https://www.theoutnet.com/variants/images/1647597331468273/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597331468273/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597331468273/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597331468273/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597331468273/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597331468273/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/pants/tapered-pants/satin-trimmed-wool-tapered-pants/1647597331468273', 310, 420.99, 'Combínalo con camisa blanca, reloj de acero, loafers negros y perfume amaderado elegante para un efecto limpio.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-08cb860e5a5a', 'mp-69e7777fc13e', 'mp-d2572817bc32']::text[], 'Para oficina o almuerzos ejecutivos, estos pantalones con loafers impecables y reloj clásico construyen una silueta serena y costosa. Libre Le Parfum añade un carácter floral-ambarado, sofisticado y seguro, sin perder delicadeza.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-22a9a0aaf882', 'theoutnet', 'ton-46376663163091430', 'Orlando Merino Wool Polo Sweater', 'Frescobol Carioca', 'clothing', 'men', 'Polo de lana merina con línea limpia y tacto refinado, pensado para vestir con discreción.', 'https://www.theoutnet.com/variants/images/46376663163091430/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163091430/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091430/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091430/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091430/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091430/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/knitwear/v-neck-sweaters/orlando-merino-wool-polo-sweater/46376663163091430', 310, 420.99, 'Combínalo con reloj de acero, perfume amaderado y pantalón de lana gris con mocasines café.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-9e04bde41b3e', 'mp-23af6e30e1cc', 'mp-cf2b71c1d9e8']::text[], 'Para un verano refinado, este polo de lana merino se eleva con loafers de líneas limpias, reloj azul profundo y un perfume fresco, cítrico y aromático. El conjunto transmite calma, distinción y una elegancia muy discreta.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6bd73f01e783', 'theoutnet', 'ton-46376663163159213', 'Oversized Logo Appliqued Cotton Jersey t Shirt', 'Fear of God Essentials', 'clothing', 'men', 'Camiseta amplia con logo aplicado, de espíritu urbano y relajado para el día a día.', 'https://www.theoutnet.com/variants/images/46376663163159213/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163159213/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159213/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159213/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159213/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159213/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/fear-of-god-essentials/tops/t-shirts/oversized-logo-appliqued-cotton-jersey-t-shirt/46376663163159213', 310, 420.99, 'Llévala con reloj deportivo, perfume fresco y jeans rectos con sneakers blancas minimalistas.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-0ee7e4469602', 'mp-50b447eced89', 'mp-1fee958584dc']::text[], 'Para un look casual de fin de semana, la camiseta oversized funciona muy bien con sneakers de perfil limpio, reloj deportivo y un perfume moderno, limpio y ligeramente amaderado. El resultado es relajado, actual y con aire urbano.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_n