INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-cf22458d26f2', 'theoutnet', 'ton-46376663163158247', 'ld 1000 Leather And Suede Trimmed Mesh Sneakers', 'Nike', 'shoes', 'men', 'Sneakers de malla con cuero y gamuza, ligeras y versátiles para un ritmo activo.', 'https://www.theoutnet.com/variants/images/46376663163158247/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158247/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158247/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158247/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158247/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158247/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/ld-1000-leather-and-suede-trimmed-mesh-sneakers/46376663163158247', 310, 420.99, 'Úsalas con reloj de caucho, perfume cítrico y joggers o denim oscuro con polo blanco.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-68a041916a67', 'mp-713ecb018a20', 'mp-60727c51909d']::text[], 'Para un verano activo, estas sneakers van perfecto con una tee limpia, reloj técnico y un perfume fresco, cítrico y enérgico. El conjunto se ve cómodo y pulido, ideal para moverte con estilo sin perder ligereza.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDE