INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0ee7e4469602', 'theoutnet', 'ton-46376663163125560', 'Out of Office Leather Sneakers', 'Off-White', 'shoes', 'men', 'Sneakers blancas de cuero con detalles discretos, de perfil limpio y contemporáneo.', 'https://www.theoutnet.com/variants/images/46376663163125560/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163125560/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125560/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125560/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125560/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125560/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-leather-sneakers/46376663163125560', 310, 420.99, 'Combínalas con reloj de acero, perfume limpio y pantalón sastre relajado con camisa azul clara.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4af1908c0185', 'mp-96bbb6af0c45', 'mp-8d5bb353d59a']::text[], 'Para un look casual de lujo silencioso, estas sneakers se equilibran con una camisa de lino y un reloj sobrio. Neroli Portofino aporta un carácter cítrico y mediterráneo, limpio y elegante, ideal para días cálidos en la ciudad.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d4537831ba4a', 'theoutnet', 'ton-1647597346222113', 'Rio Mid Length Swim Shorts', 'Frescobol Carioca', 'clothing', 'men', 'Bermudas de baño con porte mediterráneo, pensadas para una presencia pulida junto al mar.', 'https://www.theoutnet.com/variants/images/1647597346222113/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597346222113/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597346222113/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597346222113/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597346222113/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597346222113/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/swimwear-beachwear/swim-shorts/rio-mid-length-swim-shorts/1647597346222113', 311, 421.99, 'Llévalas con reloj resistente al agua, perfume acuático y camisa de lino abierta con sandalias de cuero.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-371303f8ebbb', 'mp-5744d9813fec', 'mp-0de6cc427e14']::text[], 'Para verano y escapadas junto al mar, este short de baño combina muy bien con espadrilles de perfil relajado, un reloj resistente y un perfume acuático fresco. El conjunto es ligero, pulido y claramente vacacional.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2b3e1685b705', 'theoutnet', 'ton-46376663163094670', 'Striped Linen Shirt', 'Onia', 'clothing', 'men', 'Camisa de lino rayado, fresca y sobria, con caída natural para días cálidos.', 'https://www.theoutnet.com/variants/images/46376663163094670/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163094670/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094670/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094670/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094670/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094670/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/tops/casual-shirts/striped-linen-shirt/46376663163094670', 311, 421.99, 'Acompáñala con reloj delgado, perfume cítrico y pantalón beige con mocasines o espadrilles.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-8299c3343a4d', 'mp-6a32aace5e0a', 'mp-aaadd7c31bbe']::text[], 'Para verano o un almuerzo frente al mar, esta camisa de lino se ve impecable con sandalias depuradas y una fragancia fresca, cítrica y natural. El resultado es silencioso, sofisticado y muy fácil de llevar.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-668e464a818f', 'theoutnet', 'ton-46376663163125565', 'Out of Office Mesh And Suede Sneakers', 'Off-White', 'shoes', 'men', 'Sneakers de malla, gamuza y cuero, con construcción limpia y aire urbano refinado.', 'https://www.theoutnet.com/variants/images/46376663163125565/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163125565/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125565/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125565/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125565/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125565/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-mesh-and-suede-sneakers/46376663163125565', 311, 421.99, 'Combínalas con reloj de acero, perfume fresco y pantalón recto oscuro con camiseta blanca premium.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-2ad272892924', 'mp-96bbb6af0c45', 'mp-6195e4aa6adf']::text[], 'Para un look casual refinado, estas sneakers armonizan con una camisa de lino y un reloj limpio. Flying tiene un perfil etéreo y fresco, ideal para acompañar días urbanos sin perder ligereza ni presencia.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXC