=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwd75c1547/product-pictures/b5b1b8f1-25de-4423-93d3-3efe3f57442f_T137-410-11-091-00_Head.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-t-classic-quartz-green-dial-mens-watch-t1374101109100.html', 312.08, 422.99, 'Úsalo con blazer azul oscuro, camisa marfil, pantalón gris y derbies marrón oscuro; perfume verde seco.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4af1908c0185', 'mp-7795ae7c1d60', 'mp-9c175b220b04']::text[], 'Para oficina o un día de ciudad, este reloj verde se luce con camisa de lino, loafers sobrios y un perfume vetiver elegante. El conjunto comunica seguridad discreta, modernidad y una pulcritud muy Maison Privée.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
