, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-713ecb018a20', 'jomashop', 'CZCA0820-50X', 'Citizen Promaster Dive Chronograph Eco-Drive Green Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Cronógrafo de buceo en verde: funcionalidad firme con presencia aventurera.', 'https://citizenwatch.widen.net/content/ibrkcraipe/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/ibrkcraipe/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/tgmmxxgbni/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/doytyn8thk/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iv1z6lnskv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-chronograph-ecodrive-green-dial-mens-watch-ca082050x.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-chronograph-ecodrive-green-dial-mens-watch-ca082050x_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-chronograph-ecodrive-green-dial-mens-watch-ca082050x_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-dive-chronograph-eco-drive-green-dial-mens-watch-ca0820-50x.html', 312.55, 423.99, 'Combínalo con polo técnico, chaqueta navy, cargo limpio y botas o sneakers oscuras; perfume acuático fresco.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-4af1908c0185', 'mp-3e5cc9d1ae64', 'mp-21708b443c49']::text[], 'Para un look deportivo pulido, combina la camiseta técnica del reloj con camisa de lino y sneakers en tono neutro. Ideal para fin de semana o viaje; el verde del dial se acompaña de un perfume fresco y marino, limpio y elegante.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-da98d2ee7fd3', 'jomashop', 'TIST1372101111100', 'Tissot PRX Quartz White Mother of Pearl Dial Ladies Watch', 'Tissot', 'watch', 'women', 'Nácar blanco y líneas finas: una PRX femenina, luminosa y discreta.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw266f6655/product-pictures/21c9d8dc-848f-4d9b-b76a-9481961cbd96_T137-210-11-111-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw266f6655/product-pictures/21c9d8dc-848f-4d9b-b76a-9481961cbd96_T137-210-11-111-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw266f6655/product-pictures/21c9d8dc-848f-4d9b-b76a-9481961cbd96_T137-210-11-111-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw5fc04c4d/product-pictures/f35cdc8e-e7ca-44ce-9c42-4b5ffbc9e601_T137_210_11_111_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw3e037bc6/product-pictures/48a65aeb-7517-49cf-96b8-90e827ff4c17_T137_210_11_111_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1de777a0/product-pictures/d8188cdd-3eb4-4530-91a0-1d5ca73a53b4_T137_210_11_111_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw8e9f4d67/product-pictures/a0041740-3d6f-4e21-8410-c2c7b1e6344c_T137_210_11_111_00.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1332e1cd/product-pictures/d2b2769b-5151-4bdb-8fb5-21202fdd3c1a_T137-210-11-111-00_Head.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-t-classic-automatic-ladies-watch-t1372101111100.html', 312.55, 423.99, 'Llévala con traje crema, blusa de seda, tacones nude y perfume floral suave para un look pulido.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-e80799294eb5', 'mp-08cb860e5a5a', 'mp-d3b04c599098']::text[], 'Para ti, este reloj luce impecable con camisa blanca, pantalón de tiro alto y loafers refinados. Es un conjunto de oficina con presencia discreta; la madreperla y el perfume aportan un aura floral, pulida y moderna.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
