reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6c95a52dff4c', 'theoutnet', 'ton-1647597358594712', 'Wrap Effect Button Embellished Wool Shorts', 'Balmain', 'clothing', 'women', 'Short de lana con botones joya: sastrería breve, refinada y moderna.', 'https://www.theoutnet.com/variants/images/1647597358594712/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597358594712/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597358594712/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597358594712/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597358594712/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597358594712/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/shorts/shorts/wrap-effect-button-embellished-wool-shorts/1647597358594712', 314, 425.99, 'Combínalo con blazer estructurado, camisa negra, tacones altos y reloj delgado en metal pulido.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-da98d2ee7fd3', 'mp-85d352b48778', 'mp-907d601e36bb']::text[], 'Para la oficina, estas shorts estructuradas se equilibran con una camisa pulida, reloj sobrio y pumps clásicos. El resultado es elegante y actual, perfecto para Lima; el perfume recomendado deja un rastro floral con carácter.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2a81e6864b82', 'theoutnet', 'ton-963761145488', 'Romy 100 Suede Pumps', 'Jimmy Choo', 'shoes', 'women', 'Silueta puntiaguda y gamuza suave: un pump icónico para estilizar con discreción.', 'https://www.theoutnet.com/variants/images/963761145488/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/963761145488/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/963761145488/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/963761145488/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/963761145488/E/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/pumps/high-heel-pumps/romy-100-suede-pumps/963761145488', 315, 426.99, 'Úsalos con vestido negro, reloj fino, perfume floral almizclado y accesorios en plata cepillada.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-c234a66a0da9', 'mp-3c1803aec5d1', 'mp-907d601e36bb']::text[], 'Para una noche especial, los pumps acompañan un midi dress con línea limpia y el reloj negro añade contraste sofisticado. El conjunto se siente refinado y seguro; el perfume aporta notas opulentas, cálidas y seductoras.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1ff7db1a40fb', 'theoutnet', 'ton-46376663162925289', 'Sulfer Gradient Degrade Linen Shirt', 'The Elder Statesman', 'clothing', 'men', 'Camisa de lino con degradado suave, ligera y artística, para una elegancia relajada.', 'https://www.theoutnet.com/variants/images/46376663162925289/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162925289/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162925289/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162925289/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162925289/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162925289/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/the-elder-statesman/tops/casual-shirts/sulfer-gradient-degrade-linen-shirt/46376663162925289', 315, 426.99, 'Combínala con reloj minimalista, perfume almizclado y pantalón de lino crudo con sandalias o mocasines.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-96f2d714483c', 'mp-6a32aace5e0a', 'mp-8299c3343a4d']::text[], 'Para verano, esta camisa degradé funciona con pantalón ligero, reloj azul y un perfume cítrico-blanco, luminoso y fresco. El look respira lujo silencioso; ideal para almuerzo junto al mar o una escapada de fin de semana.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-96f2d714483c', 'jomashop', 'TIST1374101104100', 'Tissot PRX Quartz Blue Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Azul profundo y brazalete integrado: una PRX limpia, versátil y siempre vigente.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw9b840963/product-pictures/739cc440-025b-42e8-a5f9-ae33b31479b2_T137-410-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw9b840963/product-pictures/739cc440-025b-42e8-a5f9-ae33b31479b2_T137-410-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw9b840963/product-pictures/739cc440-025b-42e8-a5f9-ae33b31479b2_T137-410-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe6ea7884/product-pictures/aa3020dc-8637-4ca7-b3f6-1213e695b805_T137_410_11_041_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw033319c5/product-pictures/ee92f93d-54d5-4a12-a1e8-c81c704b64b5_T137_410_11_041_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0dc9db8b/product-pictures/067e822a-1417-4f52-b948-1ea18906360e_T137_410_11_041_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw7539ad33/product-pictures/41484908-b33c-4911-bb0c-eb2cb1db21e5_T137-410-11-041-00_DETAIL-1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw4c8320f4/product-pictures/ea125a33-ba02-45f9-9ba3-a7c18ff47af5_T137_410_11_041_00_DETAIL-2.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-t-classic-quartz-blue-dial-mens-watch-t137-410-11-041-00.html', 316.35, 427.99, 'Combínalo con camisa blanca, pantalón arena, blazer gris y loafers marrón oscuro; perfume cítrico amaderado.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-2ad272892924', 'mp-7795ae7c1d60', 'mp-2dc2d5978672']::text[], 'Para oficina o after office, combina muy bien con camisa de lino y pantalón recto, rematado por loafers sobrios. El reloj azul aporta orden y modernidad; si sumas perfume, busca un vetiver limpio y elegante.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e440da9a2652', 'theoutnet', 'ton-1647597329732919', 'Antonio Linen Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Camisa de lino pulido, fresca y limpia, con presencia natural y atemporal.', 'https://www.theoutnet.com/variants/images/1647597329732919/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597329732919/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597329732919/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597329732919/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597329732919/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597329732919/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/casual-shirts/antonio-linen-shirt/1647597329732919', 317, 428.99, 'Acompáñala con reloj de acero, perfume cítrico y pantalón blanco roto con loafers de gamuza.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-2025bfd28159', 'mp-9d3a106a46fc', 'mp-8299c3343a4d']::text[], 'Para ti, esta camisa de lino pide un pantalón claro, un reloj verde discreto y un perfume fresco, mineral y refinado. Es un look de verano sereno, ideal para terraza, brunch o una cena informal junto al mar.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5803e4cb3355', 'theoutnet', 'ton-46376663163159223', 'Logo Appliqued Cotton Jersey t Shirt', 'Fear of God Essentials', 'clothing', 'men', 'Camiseta de algodón con logo aplicado, sencilla y actual, para uso diario con intención.', 'https://www.theoutnet.com/variants/images/46376663163159223/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163159223/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159223/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159223/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159223/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159223/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/fear-of-god-essentials/tops/t-shirts/logo-appliqued-cotton-jersey-t-shirt/46376663163159223', 317, 428.99, 'Llévala con reloj deportivo, perfume fresco y jeans rectos con sneakers blancas o grises.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-0ee7e4469602', 'mp-50b447eced89', 'mp-1fee958584dc']::text[], 'Para un look casual limpio, tus sneakers y el reloj sport balancean la camiseta con aire contemporáneo. Ideal para ciudad y fin de semana; el perfume suma frescura aromática y moderna, sin perder sofisticación.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e2ce438d4d61', 'theoutnet', 'ton-46376663163153326', 'Craxon Suede Loafers', 'Bally', 'shoes', 'men', 'Mocasines de ante con perfil clásico, sobrios y cómodos para una elegancia cotidiana.', 'https://www.theoutnet.com/variants/images/46376663163153326/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163153326/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153326/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153326/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153326/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153326/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/flat-shoes/loafers/craxon-suede-loafers/46376663163153326', 317, 428.99, 'Combínalos con reloj de acero, perfume amaderado y pantalón chino azul marino con camisa oxford.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4af1908c0185', 'mp-96bbb6af0c45', 'mp-6a32aace5e0a']::text[], 'Para ti, los loafers brillan con camisa de lino y un reloj de acero sobrio. Es un conjunto de lujo silencioso, perfecto para un almuerzo o reunión relajada; el perfume aporta cítricos nobles y frescura elegante.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4fb37f46f4bc', 'jomashop', 'Z-BZ57A', 'Tom Ford Oud Voyager EDP Spray 3.4 oz', 'Tom Ford', 'perfume', 'unisex', 'Oud profundo con matiz viajero, envolvente y sofisticado para noches frías.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-oud-voyager-edp-spray-34-oz-fragrances-888066174817.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-oud-voyager-edp-spray-34-oz-fragrances-888066174817.jpg', 'https://sdcdn.io/tf/tf_sku_T2HB01_3000x3000_1.jpeg?height=1400px&width=1400px', 'https://www.perfumestars.com/wp-content/uploads/2025/07/3456765334567890-.jpg']::text[], 'https://www.jomashop.com/tom-ford-oud-voyager-edp-spray-3-4-oz-fragrances-888066174817.html', 318.24, 430.99, 'Llévalo con abrigo oscuro, camisa negra y zapatos de cuero; reloj sobrio, pulido.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-f468012c6135', 'mp-3c75f66f94e0', 'mp-67717b2d9765']::text[], 'Para invierno, el oud se acompaña de bomber cálido, loafers de terciopelo y reloj con acento cobre. El resultado es nocturno y elegante; el perfume añade madera oscura, ámbar y especias envolventes.', 'invierno', ARRAY['mp-fdbb96df3a72', 'mp-0cf3b002ce9d', 'mp-da98d2ee7fd3']::text[], 'Para ti, el oud queda impecable con un midi dress drapeado, botines y reloj de madreperla. Es un look nocturno y sofisticado para invierno; el perfume aporta maderas oscuras, ámbar y un fondo seductor.', 'invierno') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9b75c4948e46', 'theoutnet', 'ton-46376663163153327', 'Cronus Suede Penny Loafers', 'Bally', 'shoes', 'men', 'Mocasines penny de ante, discretos y versátiles, con acabado clásico y pulido.', 'https://www.theoutnet.com/variants/images/46376663163153327/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163153327/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153327/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153327/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153327/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153327/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/flat-shoes/loafers/cronus-suede-penny-loafers/46376663163153327', 318, 430.99, 'Úsalos con reloj fino, perfume seco y traje gris o pantalón de vestir azul con camisa blanca.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-76e86cc39c9a', 'mp-96bbb6af0c45', 'mp-4520d6ec87f1']::text[], 'Sastrería relajada y sobria: el pantalón de lana limpia la silueta, el PRX añade precisión moderna y Grey Vetiver acompaña con un aire seco, elegante y refinado. Perfecto para oficina y reuniones formales.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-52a94ae2e3ab', 'theoutnet', 'ton-46376663163125571', 'Out of Office Canvas Sneakers', 'Off-White', 'shoes', 'men', 'Sneakers de lona con líneas limpias, ligeras y urbanas, para un estilo desenfadado.', 'https://www.theoutnet.com/variants/images/46376663163125571/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163125571/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125571/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125571/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125571/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125571/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-canvas-sneakers/46376663163125571', 318, 430.99, 'Combínalas con reloj de acero, perfume fresco y pantalón chino beige con camiseta blanca impecable.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-4af1908c0185', 'mp-50b447eced89', 'mp-8d5bb353d59a']::text[], 'Look casual de lujo silencioso, ideal para ciudad y viaje. La camisa de lino equilibra las sneakers, el reloj aporta carácter deportivo y Neroli Portofino suma frescura cítrica, limpia y luminosa.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7795b8bac3e3', 'jomashop', 'CZNY0151-59X', 'Citizen Promaster Dive Automatic Green Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Automático de buceo en verde: robustez precisa con aire deportivo refinado.', 'https://citizenwatch.widen.net/content/ewibamsbmy/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/ewibamsbmy/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/9xodknhazm/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/u1n82uxm7l/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iv1z6lnskv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-automatic-green-dial-mens-watch-ny015159x.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-automatic-green-dial-mens-watch-ny015159x_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-automatic-green-dial-mens-watch-ny015159x_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-dive-automatic-green-dial-mens-watch-ny0151-59x.html', 319, 431.99, 'Llévalo con camiseta blanca, sobrecamisa caqui, denim crudo y sneakers negras; perfume marino fresco.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-cdb07dd36a6d', 'mp-6a32aace5e0a', 'mp-a2717c731232']::text[], 'Con polo suave, PRX azul y Neroli Sauvage, el conjunto mantiene una energía activa pero pulida. Funciona muy bien en fines de semana o salidas diurnas; el perfume es fresco, cítrico y marino.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2f4bf32f62e5', 'theoutnet', 'ton-46376663162953157', 'Driss Distressed Straight Leg Jeans', 'Ralph Lauren', 'clothing', 'women', 'Denim recto con desgaste sutil: una pieza relajada de aire auténtico y limpio.', 'https://www.theoutnet.com/variants/images/46376663162953157/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162953157/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162953157/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162953157/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162953157/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162953157/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ralph-lauren-collection/jeans/straight-leg-jeans/driss-distressed-straight-leg-jeans/46376663162953157', 319, 431.99, 'Combínalo con camiseta blanca, reloj de acero, botas café y perfume amaderado ligero para equilibrio.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-4f1a6a5f486b', 'mp-cbf5fd94f2da', 'mp-6195e4aa6adf']::text[], 'Jeans con ballet flats crean una elegancia relajada y muy actual. El reloj pequeño aporta luz, y Flying suma un velo limpio, aireado y ligeramente almizclado. Ideal para un día casual en primavera o verano.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-88720fc6ecaa', 'theoutnet', 'ton-46376663163094684', 'Linen Polo Shirt', 'Sandro', 'clothing', 'men', 'Polo de lino con estructura ligera, sobrio y fresco para climas cálidos.', 'https://www.theoutnet.com/variants/images/46376663163094684/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163094684/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094684/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094684/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094684/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094684/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/sandro/tops/polo-shirts/linen-polo-shirt/46376663163094684', 319, 431.99, 'Acompáñalo con reloj delgado, perfume cítrico y bermudas sastre o pantalón claro con loafers.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-7795b8bac3e3', 'mp-6a32aace5e0a', 'mp-8299c3343a4d']::text[], 'Lino sobre lino, con reloj deportivo fino, construye un verano elegante y sin esfuerzo. El conjunto respira frescura; Neroli Sauvage añade un carácter cítrico, verde y nítido, perfecto para días cálidos.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_not