INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-371303f8ebbb', 'theoutnet', 'ton-46376663162923561', 'Rodolfo Suede Espadrilles', 'Frescobol Carioca', 'shoes', 'men', 'Espadrilles de ante, relajadas y refinadas, con un aire mediterráneo muy actual.', 'https://www.theoutnet.com/variants/images/46376663162923561/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162923561/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162923561/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162923561/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162923561/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162923561/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/espadrilles/flat-espadrilles/rodolfo-suede-espadrilles/46376663162923561', 319, 431.99, 'Llévalas con reloj de tela o acero, perfume acuático y pantalón de lino con camisa abierta.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-5bd09782904d', 'mp-c27ae7cfc8ab', 'mp-37af76f7012d']::text[], 'Espadrilles, shorts de terry y reloj acuático forman un look costero impecable. The Last Day of Summer refuerza el ambiente con una salida luminosa, suave y ligeramente melancólica. Ideal para escapadas de verano.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7aea194cd648', 'theoutnet', 'ton-46376663163125579', 'Out of Office Suede Sneakers', 'Off-White', 'shoes', 'men', 'Sneakers de ante con silueta limpia, sobria y fácil de integrar en el guardarropa.', 'https://www.theoutnet.com/variants/images/46376663163125579/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163125579/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125579/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125579/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125579/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125579/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-suede-sneakers/46376663163125579', 319, 431.99, 'Combínalas con reloj de acero, perfume amaderado y denim oscuro con camiseta premium o overshirt.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-4af1908c0185', 'mp-9570409433ac', 'mp-60727c51909d']::text[], 'Sneakers de gamuza con camisa de lino y PRX verde crean un casual refinado y contemporáneo. Sauvage aporta frescura especiada y limpia, ideal para día a día urbano con un toque de presencia.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids