INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ba76e243cd56', 'jomashop', 'OB-TIST1202101104100', 'Open Box - Tissot Seastar 1000 Quartz Blue Dial Ladies Watch', 'Tissot', 'watch', 'women', 'Seastar azul con perfil femenino: un diver limpio para días activos y luminosos.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1591242d/product-pictures/28c2842d-418c-4deb-878f-a8d5d1eb2280_T120-210-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1591242d/product-pictures/28c2842d-418c-4deb-878f-a8d5d1eb2280_T120-210-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1591242d/product-pictures/28c2842d-418c-4deb-878f-a8d5d1eb2280_T120-210-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwd11246e0/product-pictures/16297220-8f89-47d5-9f53-f0fac2790ad8_T120_210_11_041_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw8c0c47fe/product-pictures/478808b4-8a42-47ed-81d4-6bfd7f436df3_T120_210_11_041_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf15b7202/product-pictures/f58e56fe-50bb-446a-8cf0-29214b2906de_T120_210_11_041_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1a84a409/product-pictures/3beb4e0c-4db2-4e62-892c-8f3eedb97cff_T120_210_11_041_00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/o/p/open-box-tissot-seastar-1000-quartz-blue-dial-ladies-watch-t1202101104100-t1202101104100.jpg']::text[], 'https://www.jomashop.com/open-box-tissot-seastar-1000-quartz-blue-dial-ladies-watch-t1202101104100.html', 320.76, 433.99, 'Acompáñalo con traje de baño negro, camisa lino blanca, sandalias claras y perfume acuático fresco.', 'https://seekpretty.com/wp-content/uploads/2025/01/a-photo-of-a-monochrome-athleisure-set-t_UaYuWzRiRNqS_psTbzznVQ_2N3x2NedSsmd-SqFY7F8Cw.png', ARRAY['mp-eccea3334d40', 'mp-ca5e6334e29b', 'mp-13b71b592183']::text[], 'El reloj náutico pide un vestido fluido y sandalias pulidas para un verano elegante. Acqua Fiorentina acompaña con un carácter frutal-floral, ligero y sofisticado, perfecto para días de sol y paseo.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b818decf23a8', 'jomashop', 'Z-PPX78', 'Dolce and Gabbana Unisex Velvet Desert Oud EDP Spray 3.4 oz', 'Dolce & Gabbana', 'perfume', 'unisex', 'Oud denso y velado, con carácter elegante para noches de presencia serena.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/o/dolce-and-gabbana-unisex-velvet-desert-oud-edp-spray-34-oz-fragrances-8054754400038.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/o/dolce-and-gabbana-unisex-velvet-desert-oud-edp-spray-34-oz-fragrances-8054754400038.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/d/o/dolce-and-gabbana-unisex-velvet-desert-oud-edp-spray-34-oz-fragrances-8054754400038_7.jpg', 'https://abeyan.ae/wp-content/uploads/2024/10/8054754400038_ed576273-f2a2-4ab4-8c2d-98272dd23765_720x@2x.webp']::text[], 'https://www.jomashop.com/dolce-and-gabbana-unisex-velvet-desert-oud-edp-spray-3-4-oz-fragrances-8054754400038.html', 323.64, 436.99, 'Llévalo con reloj de cuero oscuro, sastrería negra y zapatos de piel lisos para una impronta contenida.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-5055150f299f', 'mp-3c75f66f94e0', 'mp-96f2d714483c']::text[], 'Para una noche discreta, combina el oud con pantalón de lino, loafers de terciopelo y reloj azul limpio. La propuesta es serena y lujosa; el perfume huele a cuero suave, maderas secas y resina.', 'noche', ARRAY['mp-c234a66a0da9', 'mp-85d352b48778', 'mp-3c1803aec5d1']::text[], 'Para una noche elegante, este perfume luce con un midi dress fluido, pumps de punta y reloj negro con brillo sutil. El conjunto es sofisticado y envolvente; la fragancia aporta cuero suave, resinas y maderas profundas.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5055150f299f', 'theoutnet', 'ton-2499567819708622', 'Linen Pants', 'Dunhill', 'clothing', 'men', 'Pantalón de lino con caída limpia, ligero y refinado para vestir con naturalidad.', 'https://www.theoutnet.com/variants/images/2499567819708622/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/2499567819708622/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/2499567819708622/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/2499567819708622/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/2499567819708622/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/dunhill/pants/tailored-pants/linen-pants/2499567819708622', 323, 436.99, 'Combínalo con reloj fino, perfume amaderado y camisa blanca con mocasines o loafers de ante.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-9b75c4948e46', 'mp-4520d6ec87f1', 'mp-2025bfd28159']::text[], 'Pantalón de lino, loafers de gamuza y Grey Vetiver forman una fórmula de oficina muy pulida. La propuesta es ligera, clásica y silenciosa; ideal para Lima, donde el lino aporta frescura sin perder formalidad.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note