, 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-light-green-dial-mens-watch-t1374101109101-t1374101109101_1.jpg']::text[], 'https://www.jomashop.com/tissot-prx-quartz-light-green-dial-mens-watch-t137-410-11-091-01.html', 325, 438.99, 'Llévala con blazer beige, camisa blanca, pantalón azul marino y loafers marrón claro; perfume limpio herbal.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4af1908c0185', 'mp-7795ae7c1d60', 'mp-1fee958584dc']::text[], 'Camisa de algodón y lino, loafers sobrios y el PRX verde crean una oficina relajada pero impecable. MYSLF suma un carácter limpio, amaderado y contemporáneo, perfecto para un estilo discreto y actual.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
