om/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-381d102f4ffc', 'mp-d0246a15c10d', 'mp-da98d2ee7fd3']::text[], 'El cashmere suaviza la estela frutal y luminosa del perfume; los pumps y el reloj de madreperla elevan el conjunto con discreción. Ideal para una cena formal o una reunión de día con presencia refinada.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
