INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e0f43d5efa1e', 'theoutnet', 'ton-46376663163125586', 'Out of Office Distressed Leather Sneakers', 'Off-White', 'shoes', 'men', 'Sneakers de cuero con acabado desgastado, de aire urbano y discreta sofisticación.', 'https://www.theoutnet.com/variants/images/46376663163125586/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163125586/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125586/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125586/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125586/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125586/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-distressed-leather-sneakers/46376663163125586', 326, 439.99, 'Combínalas con reloj metálico, perfume amaderado y jeans oscuros con camiseta blanca o chaqueta ligera.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-4af1908c0185', 'mp-67717b2d9765', 'mp-8d5bb353d59a']::text[], 'La camisa de lino y el reloj en tono cobre acompañan el carácter gastado del sneaker sin perder pulcritud. Neroli Portofino aporta frescura cítrica y limpia, ideal para un look relajado de ciudad o escapada.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-efcd734d1b84', 'theoutnet', 'ton-46376663163153331', 'Cronus Pebbled Leather Penny Loafers', 'Bally', 'shoes', 'men', 'Mocasín pebbled de líneas limpias y presencia sobria, ideal para vestir con discreción refinada.', 'https://www.theoutnet.com/variants/images/46376663163153331/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163153331/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153331/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153331/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153331/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153331/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/flat-shoes/loafers/cronus-pebbled-leather-penny-loafers/46376663163153331', 327, 441.99, 'Combínalo con reloj de acero, perfume amaderado, blazer azul marino y pantalón de lana gris, más cinturón negro.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-6e4425667ee2', 'mp-96bbb6af0c45', 'mp-3d7ec08426d5']::text[], 'La camisa Oxford y el reloj de acero pulen el penny loafer con sobriedad moderna. Sauvage Parfum añade una firma amaderada y elegante, perfecta para oficina o reuniones donde conviene verse impecable sin estridencias.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_not