INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9bb6e6613fdc', 'theoutnet', 'ton-46376663163125589', 'Out of Office Leather Sneakers', 'Off-White', 'shoes', 'men', 'Sneaker de cuero con perfil pulido y acento urbano, fácil de integrar con piezas serenas.', 'https://www.theoutnet.com/variants/images/46376663163125589/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163125589/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125589/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125589/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125589/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125589/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-leather-sneakers/46376663163125589', 327, 441.99, 'Llévalo con reloj deportivo fino, perfume cítrico limpio, camisa blanca y denim oscuro, o pantalón beige y suela clara.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-cdb07dd36a6d', 'mp-7795b8bac3e3', 'mp-6195e4aa6adf']::text[], 'El polo de punto y el reloj verde sostienen un aire relajado, pero muy cuidado. Replica Flying aporta ligereza aérea y limpia, ideal para brunch, ciudad o fines de semana con clima templado.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXC