INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b3356dd10948', 'jomashop', 'TIST1372101104100', 'Tissot PRX Quartz Blue Dial Unisex Watch', 'Tissot', 'watch', 'unisex', 'Icono versátil con esfera azul, líneas limpias y pulso contemporáneo.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw85cbf290/product-pictures/137cb52c-5d13-4d79-a9ce-53d32356fd77_T137-210-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw85cbf290/product-pictures/137cb52c-5d13-4d79-a9ce-53d32356fd77_T137-210-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw85cbf290/product-pictures/137cb52c-5d13-4d79-a9ce-53d32356fd77_T137-210-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw3ec232e0/product-pictures/270b27ae-8662-4f44-bf5a-97cb52c7972c_T137_210_11_041_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe7374edd/product-pictures/d1855580-414a-41d7-a4a7-437a707df536_T137_210_11_041_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw7154f3bf/product-pictures/f647ca1c-2e91-454f-98b4-178cb5107aa5_T137_210_11_041_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw89b1e551/product-pictures/22b52bef-445d-4bf4-b4ae-4f279c0bb544_T137-210-11-041-00_AMB_1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw29775724/product-pictures/b6913de4-313f-4046-b596-1631c0651cb1_T137_210_11_041_00.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-automatic-blue-dial-mens-watch-t1372101104100.html', 328.5, 442.99, 'Combínalo con traje gris, camisa blanca, zapatillas blancas o loafers y perfume fresco amaderado.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-4af1908c0185', 'mp-42bc749064f5', 'mp-2dc2d5978672']::text[], 'Para oficina, combina la camisa de lino, el pantalón limpio y los loafers de suede con una elegancia discreta. El PRX azul suma precisión contemporánea; si eliges perfume, Grey Vetiver aporta frescura seca y refinada.', 'oficina', ARRAY['mp-e80799294eb5', 'mp-771e0dce9f5f', 'mp-2dc2d5978672']::text[], 'La camisa popelina, el jean recto y los ballet flats crean una silueta pulida y serena, ideal para un día de oficina con estilo. El PRX azul remata con sobriedad moderna.', 'lujo-silencioso') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
