reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4f1a6a5f486b', 'theoutnet', 'ton-46376663163025684', 'Four Stitches Leather Ballet Flats', 'Maison Margiela', 'shoes', 'women', 'Bailarina minimalista en cuero, con detalle discreto y silueta atemporal.', 'https://www.theoutnet.com/variants/images/46376663163025684/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163025684/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163025684/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163025684/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163025684/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163025684/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/maison-margiela/flat-shoes/ballet-flats/four-stitches-leather-ballet-flats/46376663163025684', 328, 442.99, 'Úsala con reloj fino, pantalón sastre crema y perfume almizclado; añade bolso estructurado negro.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-754d371ec329', 'mp-217a0ab70ad2', 'mp-8cf3908f3eee']::text[], 'Las flats aportan ligereza al pantalón ancho y al reloj nacarado, logrando un casual pulido de día. Funciona para almuerzo o fin de semana; Flora Gorgeous Gardenia añade un floral cremoso, amable y luminoso.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
