INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0be86622eeee', 'jomashop', 'CZNY0156-04E', 'Citizen Promaster Dive Automatic Black Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Diver robusto de estética técnica, listo para uso activo y diario.', 'https://citizenwatch.widen.net/content/o6fgzwwhre/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/o6fgzwwhre/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/5d3abtgg2f/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/8majfxvrfn/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iv1z6lnskv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-automatic-black-dial-mens-watch-ny015604e.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-automatic-black-dial-mens-watch-ny015604e_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-automatic-black-dial-mens-watch-ny015604e_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-dive-automatic-black-dial-mens-watch-ny0156-04e.html', 329, 443.99, 'Lúcelo con polo oscuro, jeans rectos y zapatillas negras; suma perfume acuático o cítrico.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-1e2e2d2f0407', 'mp-9bb6e6613fdc', 'mp-60727c51909d']::text[], 'El polo de punto, las sneakers de lujo y la diver negra crean un conjunto técnico pero pulido. Sauvage aporta frescura especiada y limpia, ideal para actividades activas, viajes o fin de semana urbano.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-16f3ed6cc5fe', 'theoutnet', 'ton-1647597339110224', 'Tan go Patent Leather Platform Sandals', 'Valentino', 'shoes', 'women', 'Sandalia platform en patent tan con acabado brillante y silueta marcada, de efecto sofisticado.', 'https://www.theoutnet.com/variants/images/1647597339110224/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597339110224/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597339110224/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597339110224/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597339110224/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597339110224/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/valentino-garavani/sandals/high-heel-sandals/tan-go-patent-leather-platform-sandals/1647597339110224', 329, 443.99, 'Úsala con reloj fino, perfume floral intenso, vestido satinado marfil o negro y clutch rígido discreto.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-6fc2da343618', 'mp-3c1803aec5d1', 'mp-cb004bfbf1f3']::text[], 'Las plataformas en charol dan altura y dramatismo al vestido satinado, con un brillo muy de gala. Ideal para cena o fiesta; Donna Born In Roma Intense suma un perfil floral-ámbar, envolvente y elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
