INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f4ebd9b401e2', 'jomashop', 'SE-SSK036K1', 'Seiko 5 Sports SKX GMT Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'GMT sport con acento negro, funcional y urbano de fuerte presencia.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-gmt-automatic-black-dial-mens-watch-ssk036.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-gmt-automatic-black-dial-mens-watch-ssk036.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-gmt-automatic-black-dial-mens-watch-ssk036_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-skx-gmt-automatic-black-dial-mens-watch-ssk036_3.jpg', 'https://chronospride.com.au/wp-content/uploads/2024/12/Seiko-5-Sports-SSK036K1-2.jpg', 'https://watchzonebd.com/uploads/multiimage/SSK036K1-2_868.webp', 'https://images.jamtangan.com/preset:sharp/resize:fit:462:492/dpr:1.5/width:462/height:492/resize:fit/plain/https://assets.jamtangan.com/images/product/seiko/SSK036K1/DETAIL4.jpg', 'https://watchzonebd.com/uploads/multiimage/SSK036K1-3_149.webp']::text[], 'https://www.jomashop.com/seiko-5-sports-skx-gmt-automatic-black-dial-mens-watch-ssk036.html', 331.55, 446.99, 'Va bien con chaqueta utilitaria, denim oscuro y sneakers; añade perfume especiado fresco.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-2ad272892924', 'mp-b8ccf211d00d', 'mp-6a32aace5e0a']::text[], 'La camisa de lino, las sneakers limpias y el GMT crean un look viajero, sobrio y actual. Neroli Sauvage suma cítricos refinados y transparencia, ideal para ciudad, aeropuerto o escapadas de verano.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e7d342bb482f', 'jomashop', 'TIST1202102105100', 'Tissot Seastar 1000 Quartz Black Dial Unisex Watch', 'Tissot', 'watch', 'unisex', 'Seastar negro de líneas limpias, pensado para ritmo activo con estilo.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0e12cbac/product-pictures/d86b890e-c6c0-4db4-99dc-2588f58eb871_T120-210-21-051-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0e12cbac/product-pictures/d86b890e-c6c0-4db4-99dc-2588f58eb871_T120-210-21-051-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0e12cbac/product-pictures/d86b890e-c6c0-4db4-99dc-2588f58eb871_T120-210-21-051-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw6c4aa2e4/product-pictures/95b02e6a-79cf-4c30-833b-cf4eb3196a6e_T120_210_21_051_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwec88c6f6/product-pictures/38b4c397-0610-42d9-863d-9692cf405876_T120_210_21_051_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw354618b6/product-pictures/c6b6320a-6b59-4b7e-bf40-28cdf9c2d706_T120_210_21_051_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw5adb9760/product-pictures/2b3efa91-9b9b-4419-a04e-174eadfbea8a_T120_210_21_051_00_DETAIL-1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1812a27d/product-pictures/421393c0-78ad-42a2-96e2-7ed48bd5c723_T120_210_21_051_00_DETAIL-2.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-seastar-1000-quartz-black-dial-unisex-watch-t1202102105100.html', 332.5, 447.99, 'Acompáñalo con camisa oxford azul, chinos beige y zapatillas blancas; perfume marino discreto.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-1e2e2d2f0407', 'mp-938b95f56103', 'mp-605a39d82c0f']::text[], 'Para verano o escapada náutica, el polo texturizado, el pantalón de lino y los driving shoes mantienen el look fresco y preciso. El Seastar aporta espíritu deportivo; con perfume, Acqua di Gio Profondo luce acuático y limpio.', 'deportivo', ARRAY['mp-cf73e236b136', 'mp-a817148e69da', 'mp-60727c51909d']::text[], 'El vestido de punto, el jean recto y las sneakers equilibran comodidad y presencia para un fin de semana urbano. El Seastar añade carácter activo; con perfume, Flying es ligero, etéreo y elegante.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-923c7612ec2e', 'theoutnet', 'ton-46376663162849410', 'Checked Cotton Blend Tweed Mini Skirt', 'Thom Browne', 'clothing', 'women', 'Minifalda tweed con patrón clásico, precisa y femenina, perfecta para un guardarropa pulido.', 'https://www.theoutnet.com/variants/images/46376663162849410/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162849410/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162849410/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162849410/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162849410/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162849410/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/skirts/mini-skirts/checked-cotton-blend-tweed-mini-skirt/46376663162849410', 332, 447.99, 'Combínala con reloj metálico, perfume floral seco, blazer oscuro, camisa blanca y mocasines o botines negros.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-a817148e69da', 'mp-f67e672616b5', 'mp-db3e96bd55d9']::text[], 'La mini skirt gana ligereza con sneakers limpios y el PRX azul, creando un lujo relajado para días cálidos. Perfecto para verano; Love In White aporta un floral blanco, aireado y luminoso.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c234a66a0da9', 'theoutnet', 'ton-46376663163100308', 'Satin Paneled Crepe Midi Dress', 'Ferragamo', 'clothing', 'women', 'Midi satinado con paneles de crepe, caída pulida y porte sofisticado.', 'https://www.theoutnet.com/variants/images/46376663163100308/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163100308/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100308/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100308/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100308/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163100308/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/dresses/midi-dresses/satin-paneled-crepe-midi-dress/46376663163100308', 332, 447.99, 'Llévalo con reloj joya, stilettos negros y perfume floral almizclado para una presencia refinada.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-2a81e6864b82', 'mp-3c1803aec5d1', 'mp-907d601e36bb']::text[], 'El corte satinado del vestido pide sandalias delicadas y un reloj con brillo sutil para una presencia muy refinada. Ideal para noche; Royal Princess Oud deja un floral-ambarado, sofisticado y persistente.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-094f5b78d0d6', 'theoutnet', 'ton-46376663163094939', 'Linen Shorts', 'Sandro', 'clothing', 'men', 'Short de lino ligero con caída natural, pensado para días cálidos y estilo sereno.', 'https://www.theoutnet.com/variants/images/46376663163094939/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163094939/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094939/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094939/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094939/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163094939/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/sandro/shorts/casual-shorts/linen-shorts/46376663163094939', 332, 447.99, 'Úsalo con reloj de correa textil, perfume fresco, camisa de lino blanca y sandalias de cuero en tonos arena.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-371303f8ebbb', 'mp-5744d9813fec', 'mp-37af76f7012d']::text[], 'Las espadrilles y el reloj de buceo claro mantienen el conjunto ligero y mediterráneo. The Last Day Of Summer acompaña con frescura suave y melancólica, ideal para vacaciones, tardes cálidas y planes junto al mar.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b8ccf211d00d', 'theoutnet', 'ton-46376663163125598', 'Out of Office Leather Sneakers', 'Off-White', 'shoes', 'men', 'Sneaker de cuero con estética limpia y urbana, versátil para un andar contemporáneo.', 'https://www.theoutnet.com/variants/images/46376663163125598/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163125598/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125598/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125598/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125598/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125598/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-leather-sneakers/46376663163125598', 333, 448.99, 'Combínalo con reloj minimalista, perfume limpio, tee blanca, pantalón recto gris y abrigo corto camel.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-2ad272892924', 'mp-96f2d714483c', 'mp-8d5bb353d59a']::text[], 'La camisa de lino y el PRX azul suavizan la silueta del sneaker con un lujo silencioso muy limpio. Neroli Portofino aporta cítricos elegantes y luminosos, perfecto para ciudad, brunch o viajes de clima cálido.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-32a8755a0973', 'theoutnet', 'ton-46376663163125594', 'Out of Office Suede And Leather Sneakers', 'Off-White', 'shoes', 'men', 'Sneaker de gamuza y cuero con textura sutil, equilibrado para un estilo actual y discreto.', 'https://www.theoutnet.com/variants/images/46376663163125594/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163125594/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125594/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125594/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125594/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163125594/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/sneakers/fashion-sneakers/out-of-office-suede-and-leather-sneakers/46376663163125594', 333, 448.99, 'Llévalo con reloj de acero cepillado, perfume amaderado suave, sobrecamisa beige y denim índigo, o jogger negro.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-2ad272892924', 'mp-2025bfd28159', 'mp-605a39d82c0f']::text[], 'La camisa de lino, el pantalón twill y el PRX verde forman un conjunto relajado pero muy cuidado, perfecto para ciudad y brunch. Con estas sneakers, el aire es limpio; Neroli Sauvage o Prada Carbon resultan frescos y modernos.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-30e2d6000d0a', 'theoutnet', 'ton-46376663163084099', 'Long Length Striped Seersucker Swim Shorts', 'Thom Browne', 'clothing', 'men', 'Short de baño a rayas con aire náutico y silueta alargada, ideal para escapadas cálidas.', 'https://www.theoutnet.com/variants/images/46376663163084099/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163084099/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163084099/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163084099/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163084099/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163084099/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/swimwear-beachwear/swim-shorts/long-length-striped-seersucker-swim-shorts/46376663163084099', 336, 452.99, 'Acompáñalo con reloj resistente al agua, perfume marino, polo blanco y sandalias de cuero o alpargatas.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-5e3a9020fb17', 'mp-371303f8ebbb', 'mp-337d48edab34']::text[], 'Para playa o piscina, las swim shorts se ven mejor con un polo ligero, un reloj sumergible y espadrilles suaves. El conjunto es refinado y veraniego; Acqua di Gio Parfum aporta frescura marina y elegante.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EX