INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b9b2b677d2ef', 'theoutnet', 'ton-46376663163049655', 'Cesare Leather Espadrille Sandals', 'Gianvito Rossi', 'shoes', 'men', 'Sandalia espadrille de cuero, ligera y pulida, perfecta para un verano refinado.', 'https://www.theoutnet.com/variants/images/46376663163049655/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163049655/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163049655/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163049655/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163049655/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163049655/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/gianvito-rossi/sandals/flat-sandals/cesare-leather-espadrille-sandals/46376663163049655', 336, 452.99, 'Combínala con reloj de correa marrón, perfume cítrico, pantalón de lino crudo y camisa celeste o guayabera.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-3f1bb37bec2f', 'mp-23af6e30e1cc', 'mp-cf2b71c1d9e8']::text[], 'Las espadrilles de cuero ganan presencia con la camisa satinada y el short de lino, ideal para una cena de verano. El Presage azul eleva el tono; Mefisto o Dolce Amalfi aportan cítricos luminosos y limpios.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8a7681647f1e', 'theoutnet', 'ton-46376663163160079', 'Wool Blend Midi Skirt', 'Versace', 'clothing', 'women', 'Falda midi de lana con estampado sobrio, estructura y movimiento elegante.', 'https://www.theoutnet.com/variants/images/46376663163160079/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163160079/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160079/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160079/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160079/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160079/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/skirts/midi-skirts/wool-blend-midi-skirt/46376663163160079', 337, 453.99, 'Úsala con reloj de acero, blusa marfil, botas de cuero y perfume amaderado discreto.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-4f1a6a5f486b', 'mp-a164c517d625', 'mp-fa38caa36f41']::text[], 'La falda de lana se equilibra con flats depuradas y un reloj nacarado, manteniendo una elegancia cálida y profesional. Perfecto para invierno y oficina; Cuir Zerzura Intense aporta un cuero suave, elegante y envolvente.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-42bc749064f5', 'theoutnet', 'ton-46376663163153340', 'Craxon Suede Loafers', 'Bally', 'shoes', 'men', 'Mocasín de gamuza con acabado suave y presencia discreta, pensado para vestir con aplomo.', 'https://www.theoutnet.com/variants/images/46376663163153340/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163153340/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153340/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153340/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153340/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153340/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/flat-shoes/loafers/craxon-suede-loafers/46376663163153340', 338, 454.99, 'Úsalo con reloj sobrio, perfume de cedro, pantalón de vestir beige y camisa azul clara o suéter fino.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4af1908c0185', 'mp-96bbb6af0c45', 'mp-2dc2d5978672']::text[], 'Los loafers Craxon funcionan con camisa de lino, pantalón estructurado y el PRX plateado para una oficina relajada y precisa. El resultado es sobrio, silencioso y actual; Grey Vetiver acompaña con frescura seca.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-33f9e1a509fc', 'theoutnet', 'ton-46376663163160338', 'Dunk Low Retro Prm Suede And Mesh Trimmed Leather Sneakers', 'Nike', 'shoes', 'men', 'Sneaker retro de gamuza y malla, con energía urbana y trazo clásico.', 'https://www.theoutnet.com/variants/images/46376663163160338/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163160338/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160338/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160338/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160338/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160338/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160338/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/dunk-low-retro-prm-suede-and-mesh-trimmed-leather-sneakers/46376663163160338', 338, 454.99, 'Combínalo con reloj deportivo, perfume fresco, hoodie gris y jean recto, o pantalón técnico negro.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-68a041916a67', 'mp-f4ebd9b401e2', 'mp-2ecaf353c55e']::text[], 'Las Dunk Low encajan con el tee de algodón, el pantalón shell y el GMT negro para un look urbano de fin de semana. Es cómodo y limpio; Gentleman Society Sport o Luna Rossa Carbon aportan energía fresca.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-26710a02bc8b', 'jomashop', 'SE-SSK005K1', 'Seiko 5 Sports GMT Automatic Orange Dial Men''s Watch', 'Seiko', 'watch', 'men', 'GMT naranja con energía marcada, diseñado para destacar con dinamismo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-gmt-automatic-orange-dial-mens-watch-ssk005k1_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-gmt-automatic-orange-dial-mens-watch-ssk005k1_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-gmt-automatic-orange-dial-mens-watch-ssk005k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-gmt-automatic-orange-dial-mens-watch-ssk005k1_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-5-sports-gmt-automatic-orange-dial-mens-watch-ssk005k1_4.jpg', 'https://www.ioomobile.com/assets/images/seiko-ssk005k1-men-watch-02.jpg', 'https://www.watch.rs/wp-content/uploads/2022/11/SSK005K1.jpg']::text[], 'https://www.jomashop.com/seiko-5-sports-orange-dial-mens-watch-ssk005k1.html', 339, 455.99, 'Combínalo con bomber negra, jeans rectos y sneakers grises; perfume cítrico especiado.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-33f9e1a509fc', 'mp-2ecaf353c55e']::text[], 'El tee minimalista, el short de baño y las Dunk Low crean un look casual con guiño deportivo, ideal para paseo o viaje. El GMT naranja añade carácter; Acqua di Gio Profondo o Sauvage refuerzan frescura intensa.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
