=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-quartz-blue-dial-ladies-watch-t1202101104100-t1202101104100.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-1000-quartz-blue-dial-ladies-watch-t1202101104100.html', 338.58, 455.99, 'Llévalo con top blanco, blazer navy y loafers o tenis; perfume acuático fresco.', 'https://seekpretty.com/wp-content/uploads/2025/01/a-photo-of-a-monochrome-athleisure-set-t_UaYuWzRiRNqS_psTbzznVQ_2N3x2NedSsmd-SqFY7F8Cw.png', ARRAY['mp-754d371ec329', 'mp-08cb860e5a5a', 'mp-db3e96bd55d9']::text[], 'Los pantalones fluidos y los loafers mantienen una línea refinada, perfecta para oficina o un almuerzo de trabajo. Love In White acompaña con un aire floral, limpio y luminoso, muy chic.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
