INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3c1803aec5d1', 'jomashop', 'TIST1370101105600', 'Tissot PRX Quartz Diamond Black Dial Ladies Watch', 'Tissot', 'watch', 'women', 'PRX negro con diamantes sutiles, sobrio y preciso con brillo contenido.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb70fbe27/product-pictures/a4c037b8-d2a3-437d-a5a0-59c145c198ed_T137-010-11-056-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb70fbe27/product-pictures/a4c037b8-d2a3-437d-a5a0-59c145c198ed_T137-010-11-056-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb70fbe27/product-pictures/a4c037b8-d2a3-437d-a5a0-59c145c198ed_T137-010-11-056-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw910f7a5c/product-pictures/47017efd-7cbc-4e8d-978e-af86ce7360f2_T137-010-11-056-00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwcbda18e9/product-pictures/cffa9ef3-da7c-499f-b795-c0cd0fffcb3c_T137-010-11-056-00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw22370700/product-pictures/29835e87-5e37-4300-9192-dbd3ce83e000_T137-010-11-056-00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwad7a9432/product-pictures/bffea098-8a8d-417a-b9f8-04145563287f_T137-010-11-056-00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-diamond-black-dial-ladies-watch-t1370101105600.jpg']::text[], 'https://www.jomashop.com/tissot-prx-quartz-diamond-black-dial-ladies-watch-t1370101105600.html', 342, 459.99, 'Va con traje grafito, blusa crema y mocasines finos; perfume floral amaderado discreto.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-4309d7661011', 'mp-85d352b48778', 'mp-c0c58bfbda63']::text[], 'El blazer define un tailleur pulido, los pumps afilan la silueta y el reloj añade brillo contenido. Perfecto para oficina o cena sobria; Aventus for Her suma un halo frutal, elegante y limpio.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
