INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5d1aa18d7a30', 'theoutnet', 'ton-46376663163160452', 'Dunk Low qs Leather Sneakers', 'Nike', 'shoes', 'men', 'Sneaker retro de cuero con perfil limpio, versátil para un estilo urbano sin esfuerzo.', 'https://www.theoutnet.com/variants/images/46376663163160452/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163160452/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160452/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160452/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160452/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160452/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160452/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/dunk-low-qs-leather-sneakers/46376663163160452', 342, 459.99, 'Combínalo con reloj deportivo sobrio, perfume cítrico, camiseta blanca y pantalón cargo oscuro o jean recto.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-f63eb8828e5a', 'mp-0be86622eeee', 'mp-2ecaf353c55e']::text[], 'Las Dunk Low van perfectas con hoodie, joggers y un Promaster negro para un fin de semana activo o viaje. El look es relajado y actual; Gentleman Society Sport o Dior Sauvage aportan una estela fresca y enérgica.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_p