INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b32bbf7d64ab', 'theoutnet', 'ton-38063312417960442', 'Flared Cutout Tinsel Dress', 'Maison Margiela', 'clothing', 'women', 'Vestido con cutouts y brillo sutil, moderno y de impacto refinado.', 'https://www.theoutnet.com/variants/images/38063312417960442/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/38063312417960442/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/38063312417960442/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/38063312417960442/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/38063312417960442/E/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/mm6-maison-margiela/dresses/knee-length-dresses/flared-cutout-tinsel-dress/38063312417960442', 343, 460.99, 'Llévalo con reloj minimal, sandalias negras y perfume almizclado; añade abrigo largo estructurado.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-2208bf601ddb', 'mp-a74b23068c3b', 'mp-db86cdd766da']::text[], 'Las loafers equilibran el dramatismo del vestido con una nota refinada, mientras el PRX champagne suma luz discreta. Para noche o evento, Spring Flower aporta un floral fresco y elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids