INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d3f49d1e29fa', 'theoutnet', 'ton-1647597289402833', 'Printed Straight Leg Satin Pants', 'Versace', 'clothing', 'women', 'Pantalón satinado con estampado audaz, fluido y marcado por Versace.', 'https://www.theoutnet.com/variants/images/1647597289402833/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597289402833/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597289402833/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597289402833/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597289402833/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597289402833/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/pants/straight-leg-pants/printed-straight-leg-satin-pants/1647597289402833', 344, 462.99, 'Combínalo con reloj delgado, top negro y tacones nude; perfume oriental suave.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-e53c27f9978d', 'mp-a74b23068c3b', 'mp-cb004bfbf1f3']::text[], 'Los pumps alargan la silueta satinada y el PRX champagne refuerza el brillo sofisticado del conjunto. Ideal para cena o cóctel; Donna Born In Roma Intense añade un floral ambarado, envolvente.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, r