INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-77088a2b1b8f', 'theoutnet', 'ton-46376663163158290', 'Zoom%C2%A0vomero%C2%A05 Leather And Rubber Trimmed Mesh Sneakers', 'Nike', 'shoes', 'men', 'Sneaker ligero de malla y cuero, pensado para movimiento con una imagen limpia.', 'https://www.theoutnet.com/variants/images/46376663163158290/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158290/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158290/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158290/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158290/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158290/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158290/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/zoom%C2%A0vomero%C2%A05-leather-and-rubber-trimmed-mesh-sneakers/46376663163158290', 344, 462.99, 'Combínalo con reloj de entrenamiento elegante, perfume acuático, jogger negro y casaca técnica gris o blanca.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-26710a02bc8b', 'mp-605a39d82c0f']::text[], 'Para un look casual limpio, combina con t-shirt neutra, GMT deportivo y un perfume fresco-amaderado. Ideal para fines de semana o city breaks en Lima: cómodo, moderno y sin exceso, con una presencia sobria y refinada.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0360cc330109', 'theoutnet', 'ton-46376663163158292', 'Dunk Low Prm Suede And Leather Sneakers', 'Nike', 'shoes', 'men', 'Sneaker de gamuza y cuero con aire retro, fácil de llevar y de presencia actual.', 'https://www.theoutnet.com/variants/images/46376663163158292/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158292/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158292/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158292/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158292/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158292/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158292/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/dunk-low-prm-suede-and-leather-sneakers/46376663163158292', 344, 462.99, 'Llévalo con reloj deportivo fino, perfume verde, camiseta blanca y bomber azul marino o pantalón recto caqui.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-68a041916a67', 'mp-f78b3cb527bd', 'mp-0e1d44d63a68']::text[], 'La base en algodón, el reloj de buceo y un perfume acuático elegante equilibran tus Dunk con un aire relajado. Perfecto para días de ciudad o brunch; el aroma aporta limpieza marina y sofisticación discreta.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDE