INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2abd9b8ccfe5', 'theoutnet', 'ton-46376663163158297', 'Field General 82 sp Suede Trimmed Perforated Leather Sneakers', 'Nike', 'shoes', 'men', 'Sneaker perforado con gamuza y cuero, de espíritu atlético y acabado sobrio.', 'https://www.theoutnet.com/variants/images/46376663163158297/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158297/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158297/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158297/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158297/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158297/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158297/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/field-general-82-sp-suede-trimmed-perforated-leather-sneakers/46376663163158297', 345, 463.99, 'Úsalo con reloj deportivo limpio, perfume herbal, sudadera gris y pantalón recto oscuro, o short técnico.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-f63eb8828e5a', 'mp-204891a8b1dd', 'mp-60727c51909d']::text[], 'Con hoodie técnico, reloj de buceo y un clásico fresco, tus sneakers ganan intención urbana. Es un look ideal para un fin de semana activo o escapada costera; el perfume suma energía limpia y reconocible.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8bffb015f36e', 'jomashop', 'TIST1202102205101', 'Tissot Seastar Quartz Black Dial Watch', 'Tissot', 'watch', 'unisex', 'Reloj deportivo negro, funcional y sobrio, listo para el día activo.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1608d3f3/product-pictures/75b134ab-b45b-48b9-a185-8873d6c83d28_T120-210-22-051-01_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1608d3f3/product-pictures/75b134ab-b45b-48b9-a185-8873d6c83d28_T120-210-22-051-01_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1608d3f3/product-pictures/75b134ab-b45b-48b9-a185-8873d6c83d28_T120-210-22-051-01_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe1231682/product-pictures/f0a03f84-94b5-407a-b15e-b176629de49a_T120_210_22_051_01_B1-psd.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw01893b6b/product-pictures/4dc0effb-8358-4a7c-bf61-4ed52bc5feb1_T120-210-22-051-01.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-quartz-black-dial-watch-t1202102205101_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-quartz-black-dial-watch-t1202102205101_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-quartz-black-dial-watch-t1202102205101_3.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-quartz-black-dial-watch-t1202102205101.html', 346.75, 465.99, 'Combínalo con polo gris, jeans oscuros y zapatillas negras; perfume acuático limpio.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-1e2e2d2f0407', 'mp-6a32aace5e0a', 'mp-a2717c731232']::text[], 'Polo de punto, lino y espadrilles crean un conjunto veraniego de lujo discreto, perfecto para almuerzos junto al mar o una tarde en la ciudad. El perfume aporta neroli fresco, limpio y sofisticado, sin imponerse.', 'lujo-silencioso', ARRAY['mp-cf73e236b136', 'mp-a817148e69da', 'mp-6195e4aa6adf']::text[], 'Un vestido de punto suave, sneakers pulidos y un perfume limpio y etéreo logran un look relajado pero refinado. Ideal para viajes o fines de semana; funciona con un estilo minimalista y contemporáneo.', 'lujo-silencioso') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
