eco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-44c11d07801c', 'theoutnet', 'ton-46376663163160461', 'Dunk Low Leather And Suede Sneakers', 'Nike', 'shoes', 'men', 'Sneaker de cuero y gamuza con estética clásica, pensado para sumar textura sin exceso.', 'https://www.theoutnet.com/variants/images/46376663163160461/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163160461/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160461/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160461/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160461/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160461/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163160461/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/dunk-low-leather-and-suede-sneakers/46376663163160461', 349, 468.99, 'Combínalo con reloj de acero mate, perfume fresco amaderado, polo blanco y pantalón chino oliva o azul tinta.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-68a041916a67', 'mp-f78b3cb527bd', 'mp-0e1d44d63a68']::text[], 'La t-shirt esencial, el reloj azul y un perfume acuático dan equilibrio a tus Dunk: casual, fresco y bien resuelto. Perfecto para la ciudad o un almuerzo informal; el aroma es marino, limpio y elegante.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4704759f9794', 'jomashop', 'COS-CAVMES33B', 'Creed Aventus / Creed EDP Spray 3.3 oz (100 ml) (m)', 'Creed', 'perfume', 'unisex', 'Aroma masculino emblemático, vibrante y pulido con carácter seguro.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-aventus-creed-edp-spray-33-oz-100-ml-m-3508441001114.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-aventus-creed-edp-spray-33-oz-100-ml-m-3508441001114.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-aventus-creed-edp-spray-33-oz-100-ml-m-3508441001114_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-aventus-creed-edp-spray-33-oz-100-ml-m-3508441001114_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-aventus-creed-edp-spray-33-oz-100-ml-m-3508441001114_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/c/r/creed-mens-creed-aventus-edp-spray-33-oz-tester-fragrances-t3508441001114.jpg']::text[], 'https://www.jomashop.com/creed-fragrances-cavmes33b-3-3oz.html', 349.99, 469.99, 'Úsalo con reloj de acero, camisa blanca, saco azul marino y loafers de cuero liso.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-22a9a0aaf882', 'mp-9e04bde41b3e', 'mp-23af6e30e1cc']::text[], 'Polo de merino, loafers de piel y un reloj de vestir elevan Aventus con una estética sobria y precisa. Ideal para cena o reunión formal; el perfume aporta presencia frutal-amaderada, pulida y muy distinguida.', 'elegante', ARRAY['mp-d04ffafba9a6', 'mp-4f1a6a5f486b', 'mp-a164c517d625']::text[], 'La falda de seda, las bailarinas y el reloj nacarado crean un conjunto refinado y atemporal. Perfecto para una cena o evento especial; Aventus suma un carácter fresco, elegante y ligeramente ahumado.', 'elegante') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4e2c83702fa6', 'theoutnet', 'ton-1647597284054718', 'Patent Leather Sandals', 'Saint Laurent', 'shoes', 'women', 'Sandalias en cuero charol, finas y luminosas para una noche precisa.', 'https://www.theoutnet.com/variants/images/1647597284054718/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597284054718/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597284054718/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597284054718/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597284054718/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597284054718/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/saint-laurent/sandals/high-heel-sandals/patent-leather-sandals/1647597284054718', 350, 469.99, 'Acompáñalas con reloj delicado, vestido negro o pantalón sastre y perfume floral ambarado.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-c234a66a0da9', 'mp-a74b23068c3b', 'mp-907d601e36bb']::text[], 'El vestido midi y el reloj champagne equilibran el brillo del patent leather con una elegancia serena. Ideal para cena o cóctel; Royal Princess Oud aporta un aura floral-ambarada, distinguida.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b998ad5fe8cc', 'theoutnet', 'ton-1647597359506885', 'Marsai 90 Crystal Embellished Satin Sandals', 'Jimmy Choo', 'shoes', 'women', 'Satinado luminoso con cristales, para una presencia refinada y memorable.', 'https://www.theoutnet.com/variants/images/1647597359506885/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597359506885/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597359506885/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597359506885/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597359506885/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597359506885/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/sandals/high-heel-sandals/marsai-90-crystal-embellished-satin-sandals/1647597359506885', 350, 469.99, 'Llévalo con vestido negro fluido, reloj fino de acero y perfume floral ambarado en tonos marfil.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-b32bbf7d64ab', 'mp-3c1803aec5d1', 'mp-58072ada40a0']::text[], 'El vestido con brillo, el reloj con diamantes y el perfume de cuero suave construyen una imagen nocturna muy sofisticada. Ideal para cocktail o gala; las piezas equilibran dramatismo y elegancia con mucha seguridad.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a2bd187331bf', 'theoutnet', 'ton-46376663163111188', 'Lyocell Linen And Cotton Drawstring Shorts', 'Officine Générale', 'clothing', 'men', 'Short de lyocell, lino y algodón con caída limpia y aire relajado.', 'https://www.theoutnet.com/variants/images/46376663163111188/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163111188/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111188/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111188/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111188/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163111188/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/officine-generale/shorts/casual-shorts/lyocell-linen-and-cotton-drawstring-shorts/46376663163111188', 351, 470.99, 'Con polo crudo, sandalias de cuero y reloj fino en acero; perfume cítrico, limpio y seco.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-2025bfd28159', 'mp-8d5bb353d59a']::text[], 'Las bermudas de lino, las espadrilles y un reloj verde suave forman un look veraniego impecable. Perfecto para Lima en temporada cálida o escapadas costeras; el perfume añade neroli fresco, luminoso y muy pulcro.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLU