INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b5ecf7c2292f', 'theoutnet', 'ton-46376663163070129', 'French Cotton Terry Drawstring Shorts', 'Onia', 'clothing', 'men', 'Short de terry francés con tacto suave y silueta cómoda.', 'https://www.theoutnet.com/variants/images/46376663163070129/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163070129/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163070129/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163070129/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163070129/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163070129/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/onia/shorts/casual-shorts/french-cotton-terry-drawstring-shorts/46376663163070129', 351, 470.99, 'Llévalo con camiseta blanca, loafers de ante y reloj minimalista; perfume acuático y discreto.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-69ef4764b1ae', 'mp-96f2d714483c', 'mp-cf2b71c1d9e8']::text[], 'Espadrilles, reloj azul y un perfume cítrico-aromático elevan tus shorts con una elegancia relajada. Ideal para verano y viaje; la combinación se siente fresca, mediterránea y cuidada, sin perder naturalidad.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e53c27f9978d', 'theoutnet', 'ton-46376663162969082', 'Padlock Embellished Leather Platform Pumps', 'Tom Ford', 'shoes', 'women', 'Salón de cuero con plataforma y detalle metálico de presencia marcada.', 'https://www.theoutnet.com/variants/images/46376663162969082/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162969082/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162969082/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162969082/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162969082/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162969082/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/pumps/high-heel-pumps/padlock-embellished-leather-platform-pumps/46376663162969082', 352, 471.99, 'Con vestido negro fluido, clutch satinado, reloj joya y perfume ambarado para un gesto nocturno.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-a6caa1d21f46', 'mp-3c1803aec5d1', 'mp-58072ada40a0']::text[], 'El vestido midi, el reloj con diamantes y los pumps de satén crean un look de noche impecable. Ideal para cocktail o cena formal; el perfume de cuero suave aporta un final sofisticado y envolvente.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d04ffafba9a6', 'theoutnet', 'ton-1647597294988333', 'Pleated Silk Mesh Midi Skirt', 'Ferragamo', 'clothing', 'women', 'Plisado etéreo que aporta movimiento sereno y distinción contemporánea.', 'https://www.theoutnet.com/variants/images/1647597294988333/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597294988333/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597294988333/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597294988333/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597294988333/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597294988333/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/skirts/midi-skirts/pleated-silk-mesh-midi-skirt/1647597294988333', 352, 471.99, 'Combínala con blusa de seda crema, reloj delgado dorado y sandalias nude para un perfil pulido.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-771e0dce9f5f', 'mp-69e7777fc13e', 'mp-d2572817bc32']::text[], 'La falda de seda pide líneas limpias: bailarinas clásicas, reloj de perfil fino y un perfume elegante de lirio y vainilla. Perfecto para una cena íntima o evento de tarde; todo se siente sereno y valioso.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b2dbfc6f7e6e', 'theoutnet', 'ton-46376663163048712', 'Darian Textured Leather Oxford Shoes', 'Santoni', 'shoes', 'men', 'Oxford de cuero texturado con línea precisa y carácter refinado.', 'https://www.theoutnet.com/variants/images/46376663163048712/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163048712/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163048712/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163048712/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163048712/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163048712/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/santoni/flat-shoes/lace-ups/darian-textured-leather-oxford-shoes/46376663163048712', 352, 471.99, 'Combínalo con traje azul marino, reloj de vestir y perfume amaderado suave para una presencia sobria.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4af1908c0185', 'mp-96bbb6af0c45', 'mp-d3b04c599098']::text[], 'Para oficina, combina con una camisa de lino y algodón, pantalón de paño fino y un PRX sobrio. El resultado es pulido, discreto y contemporáneo; perfecto para reuniones formales. Si añades fragancia, elige una fresca y elegante, de vetiver limpio.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7dcf2d01e00e', 'jomashop', 'TISTT1202101101100', 'Tissot Seastar Quartz White Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Esfera blanca y carácter marino en una lectura limpia y versátil.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwbe9a3c7c/product-pictures/6f675766-9950-4831-8f8d-fe391099d13c_T120-210-11-011-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwbe9a3c7c/product-pictures/6f675766-9950-4831-8f8d-fe391099d13c_T120-210-11-011-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwbe9a3c7c/product-pictures/6f675766-9950-4831-8f8d-fe391099d13c_T120-210-11-011-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw37c078a7/product-pictures/0b1520c1-9480-4c42-a44a-ec8171632803_T120-210-11-011-00_SET.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw71a54e8c/product-pictures/4ccd772e-1447-4f8e-b343-e67a5e5b1f04_T120_210_11_011_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw4f05c067/product-pictures/65057f34-f078-4c3f-8c5c-689dd7e90a36_T120_210_11_011_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw107d1669/product-pictures/309e109d-10bf-49fe-b676-9fdb639200d6_T120_210_11_011_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1e36f10c/product-pictures/f8dd3a0d-cae7-4b64-accd-b2c4088cf1b1_T120_210_11_011_00.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-seastar1k-unisex-ss-br-wh-rb-sv-ind-white-dial-mens-watch-t120-210-110-11-00.html', 352.26, 472.99, 'Úsalo con camisa celeste, pantalón chino gris, zapatillas de cuero blanco y fragancia fresca acuática.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-5055150f299f', 'mp-44c11d07801c', 'mp-4520d6ec87f1']::text[], 'Con pantalón de lino, sneakers limpias y Grey Vetiver, tu Seastar queda equilibrado entre ciudad y actividad. Es un look versátil, deportivo sin perder orden, ideal para jornada activa o viaje corto. El perfume aporta un carácter seco, verde y refinado.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d983e562e79b', 'jomashop', 'TIST1204101104100', 'Tissot Seastar Quartz Blue Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Azul profundo y líneas nítidas para un estilo sobrio con aire náutico.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf85bb05a/product-pictures/ee73034b-3afd-41bb-808f-e3c995bf863a_T120-410-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf85bb05a/product-pictures/ee73034b-3afd-41bb-808f-e3c995bf863a_T120-410-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf85bb05a/product-pictures/ee73034b-3afd-41bb-808f-e3c995bf863a_T120-410-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwbcf75e4a/product-pictures/bd6c4a4e-97fa-4aad-aa89-26e552880bc3_T120_410_11_041_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw377c77fb/product-pictures/1952270d-fc27-4296-807f-2b674e9c719f_T120_410_11_041_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0a20abe1/product-pictures/01a7c88a-0015-489a-8120-bbb46bc121ef_T120_410_11_041_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0c5c7962/product-pictures/b031de85-dea7-4747-b96b-322df5dc4b42_T120_410_11_041_00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-quartz-blue-dial-mens-watch-t1204101104100-t1204101104100.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-quartz-blue-dial-mens-watch-t120-410-11-041-00.html', 352.26, 472.99, 'Combínalo con blazer azul marino, polo blanco, mocasines café y perfume cítrico limpio.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-c2320d374c5f', 'mp-55daa2a79111', 'mp-c3c82fdede97']::text[], 'El pantalón de lino, los loafers y Sauvage EDP acompañan bien al Seastar azul con aire profesional. Es un conjunto limpio y moderno para oficina o almuerzo de negocios. La fragancia suma frescura especiada y una presencia nítida.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-23bae4195fef', 'theoutnet', 'ton-46376663163149849', 'Wavy Velvet Wedge Sandals', 'Tom Ford', 'shoes', 'women', 'Sandalia de terciopelo con cuña y acabado escultórico de aire sofisticado.', 'https://www.theoutnet.com/variants/images/46376663163149849/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163149849/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163149849/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163149849/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163149849/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163149849/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/sandals/high-heel-sandals/wavy-velvet-wedge-sandals/46376663163149849', 353, 473.99, 'Con vestido midi negro, joyas discretas, reloj delgado y perfume floral oscuro para un look sereno.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-e15d8fec91e1', 'mp-a74b23068c3b', 'mp-907d601e36bb']::text[], 'Para noche, el vestido de devoré, los slingbacks satinados y un PRX en champagne crean una silueta sofisticada y muy femenina. Ideal para cena, cóctel o evento. La pieza principal dialoga con brillo suave y textura sensual, sin exceso.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9e5ae8bfe5b3', 'jomashop', 'Y-143426', 'Tom Ford Unisex Lost Cherry EDP Spray 3.4 oz Private Blend', 'Tom Ford', 'perfume', 'unisex', 'Lost Cherry abre con cereza oscura y acorde sensual, de estela envolvente.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-lost-cherry-edp-spray-34-oz-private-blend-888066098878.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-lost-cherry-edp-spray-34-oz-private-blend-888066098878.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/o/tom-ford-unisex-lost-cherry-edp-spray-34-oz-private-blend-888066098878_2.jpg', 'https://perfumeonline.pk/cdn/shop/files/888066098878_1024x1024.jpg?v=1726640157']::text[], 'https://www.jomashop.com/tom-ford-unisex-lost-cherry-edp-spray-3-4-oz-fragrances-888066098878.html', 354.99, 475.99, 'Llévalo con reloj fino, vestido satinado borgoña y sandalias negras; joyería dorada y terciopelo.', 'https://storage.googleapis.com/windsor-cms/media/2023/10/8c9595cf-what-to-wear-to-a-black-tie-16-dresses-hero-1.jpg', ARRAY['mp-a3c07033dec1', 'mp-3c75f66f94e0', 'mp-a7fbae0e4ca7']::text[], 'Lost Cherry pide un look de noche con polo de seda, loafers de terciopelo y PRX dorado. El conjunto es sensual y refinado, perfecto para una cena o bar elegante. El perfume añade un carácter gourmand, oscuro y cálido.', 'noche', ARRAY['mp-e15d8fec91e1', 'mp-f941866c6dcf', 'mp-a74b23068c3b']::text[], 'El devoré de Valentino, los slingbacks satinados y el PRX champagne acompañan Lost Cherry con elegancia nocturna. Es un look ideal para cena, gala o coctel. El perfume aporta un acorde gourmand de cereza, almendra y fondo aterciopelado.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-32f83814872c', 'theoutnet', 'ton-46376663162894613', 'Helio Leather And Suede Espadrilles', 'Frescobol Carioca', 'shoes', 'men', 'Espadrille de cuero y ante con espíritu relajado y pulcro.', 'https://www.theoutnet.com/variants/images/46376663162894613/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162894613/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162894613/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162894613/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162894613/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162894613/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/espadrilles/flat-espadrilles/helio-leather-and-suede-espadrilles/46376663162894613', 355, 475.99, 'Úsalo con lino arena, polo blanco, reloj en acero y perfume cítrico amaderado, muy limpio.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-1e2e2d2f0407', 'mp-8d5bb353d59a', 'mp-f4ebd9b401e2']::text[], 'Con polo waffle, espadrilles y Neroli Portofino, tu look respira verano y lujo relajado. Es perfecto para Lima costera, almuerzo informal o paseo de fin de semana. La fragancia es cítrica, luminosa y limpia, con aire mediterráneo.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1e2e2d2f0407', 'theoutnet', 'ton-46376663163091382', 'Horacio Waffle Knit Cotton Polo Shirt', 'Frescobol Carioca', 'clothing', 'men', 'Polo de algodón waffle con textura sutil y porte relajado.', 'https://www.theoutnet.com/variants/images/46376663163091382/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163091382/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091382/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091382/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091382/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091382/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/tops/polo-shirts/horacio-waffle-knit-cotton-polo-shirt/46376663163091382', 357, 478.99, 'Con pantalón de lino claro, mocasines de gamuza, reloj clásico y perfume verde suave.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-2025bfd28159', 'mp-6a32aace5e0a']::text[], 'El polo waffle se equilibra con lino, espadrilles y un PRX de esfera verde clara. Es un conjunto fresco, pulido y muy veraniego, ideal para brunch o escapada costera. Mantiene naturalidad sin perder intención.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_i