INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-744571d7ee01', 'theoutnet', 'ton-46376663163070134', 'Affonso Tapered Linen Pants', 'Frescobol Carioca', 'clothing', 'men', 'Pantalón de lino tapered con caída ligera y silueta precisa.', 'https://www.theoutnet.com/variants/images/46376663163070134/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163070134/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163070134/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163070134/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163070134/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163070134/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/pants/casual-pants/affonso-tapered-linen-pants/46376663163070134', 357, 478.99, 'Con camisa celeste, espadrilles de ante, reloj de correa marrón y perfume cítrico seco.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-32f83814872c', 'mp-2025bfd28159', 'mp-8d5bb353d59a']::text[], 'Lino y espadrilles afinan un look fresco y sobrio para Lima en verano. El PRX verde suma modernidad discreta; Neroli Portofino aporta una salida cítrica, limpia y marina, perfecta para un almuerzo costero o una escapada de día.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, re