INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e305c6bba67b', 'theoutnet', 'ton-46376663163045162', 'Radial Webbing And Leather Sandals', 'Dunhill', 'shoes', 'men', 'Sandalia de cuero y webbing con diseño funcional y limpio.', 'https://www.theoutnet.com/variants/images/46376663163045162/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163045162/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163045162/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163045162/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163045162/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163045162/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/dunhill/sandals/flat-sandals/radial-webbing-and-leather-sandals/46376663163045162', 358, 479.99, 'Con bermudas beige, camisa de lino y reloj deportivo fino; perfume marino, fresco y discreto.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-66518207ba70', 'mp-96f2d714483c', 'mp-21708b443c49']::text[], 'Las sandalias ganan presencia con la camisa de lino y el PRX azul, logrando un conjunto relajado pero pulido. Acqua di Gio Profondo añade un perfil acuático y elegante, ideal para un brunch junto al mar o una tarde cálida.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=E