INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2e8c1042a551', 'jomashop', 'CZJY8149-05E', 'Citizen Promaster Skyhawk A-T Chronograph Black Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Cronógrafo aeronáutico de estética técnica, preciso y decidido.', 'https://citizenwatch.widen.net/content/a3uzsgzjm4/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/a3uzsgzjm4/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/cdgysjrsps/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/q1vff6rv45/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/odeapwy2up/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-chronograph-black-dial-mens-watch-jy814905e_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-chronograph-black-dial-mens-watch-jy814905e_2_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-chronograph-black-dial-mens-watch-jy814905e_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-skyhawk-a-t-perpetual-alarm-world-time-chronograph-gmt-analog-digital-black-dial-mens-watch-jy8149-05e.html', 360.05, 481.99, 'Va bien con chaqueta bomber azul tinta, jeans rectos oscuros, botas de cuero y perfume especiado limpio.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-f60964fd1e13', 'mp-b2dbfc6f7e6e', 'mp-3d7ec08426d5']::text[], 'El tono técnico del Skyhawk se equilibra con el pantalón de textura ligera y unos Oxford Santoni. Sauvage Parfum añade especias limpias y fondo amaderado, perfecto para oficina con carácter o días de agenda intensa.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1e878742a0dc', 'jomashop', 'TIST1204103309100', 'Tissot Seastar 1000 Quartz Men''s Watch', 'Tissot', 'watch', 'men', 'Verde intenso y silueta resistente para un pulso moderno y seguro.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-quartz-mens-watch-t1204103309100.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-quartz-mens-watch-t1204103309100.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-quartz-mens-watch-t1204103309100_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-quartz-mens-watch-t1204103309100_3.jpg', 'https://assets.tissotwatches.com/transform/Extend/1a431e1b-ef46-4334-aa5c-4bcd9271cab5/T120-410-33-091-00_Shadow?io=transform:fit,width:800,height:800,gravity:center', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb010c3ee/product-pictures/dac04774-d687-42fe-8b85-848699c197fb_T120_410_33_091_00_WRIST.png']::text[], 'https://www.jomashop.com/tissot-seastar-quartz-mens-watch-t1204103309100.html', 360.05, 481.99, 'Combínalo con polo negro, chino oliva, zapatillas blancas sobrias y fragancia acuática con fondo amaderado.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-5055150f299f', 'mp-55daa2a79111', 'mp-4520d6ec87f1']::text[], 'Aunque deportivo, el Seastar funciona con pantalón de lana y loafers para una lectura urbana y sobria. Grey Vetiver refuerza la limpieza masculina con vetiver seco, ideal para oficina flexible o viernes de ciudad.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f913c9a65ba8', 'theoutnet', 'ton-46376663163158261', 'David Suede Sandals', 'MR P.', 'shoes', 'men', 'Sandalia de ante con líneas simples y comodidad discreta.', 'https://www.theoutnet.com/variants/images/46376663163158261/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158261/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158261/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158261/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158261/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158261/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/mr-p/sandals/flat-sandals/david-suede-sandals/46376663163158261', 360, 481.99, 'Con pantalón de lino, camiseta blanca y reloj minimalista; perfume hespéride y limpio.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-744571d7ee01', 'mp-2025bfd28159', 'mp-cf2b71c1d9e8']::text[], 'Las sandalias de ante se ven más finas con lino fluido y el PRX verde, manteniendo naturalidad silenciosa. Mefisto aporta cítricos, iris y frescura elegante, ideal para un verano limeño de día o una cena relajada.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a74b23068c3b', 'jomashop', 'TIST1370103302100', 'Tissot PRX 25 Quartz Champagne Dial Ladies Watch', 'Tissot', 'watch', 'women', 'Champagne delicado y formato compacto para una elegancia diaria impecable.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw376ad25b/product-pictures/d584e79b-31e8-45c3-adc5-4496b5487676_T137-010-33-021-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw376ad25b/product-pictures/d584e79b-31e8-45c3-adc5-4496b5487676_T137-010-33-021-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw376ad25b/product-pictures/d584e79b-31e8-45c3-adc5-4496b5487676_T137-010-33-021-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw51776692/product-pictures/b8e9877c-ae97-41f7-a3b6-27e5623fa73f_T137_010_33_021_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwae0a0cca/product-pictures/0e703b7c-939f-4260-8968-cdb7818bba3a_T137-010-33-021-00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw4ccb0104/product-pictures/256ec95d-7cc4-4e6e-9110-2bed64219d42_T137-010-33-021-00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw2cda8f34/product-pictures/18d3dd4d-836b-44ae-a1ca-34ce5bb51206_T137-010-33-021-00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-25-quartz-champagne-dial-ladies-watch-t1370103302100.jpg']::text[], 'https://www.jomashop.com/tissot-prx-25-quartz-champagne-dial-ladies-watch-t1370103302100.html', 361.35, 483.99, 'Llévalo con sastre beige, blusa crema, loafers nude y perfume floral suave de almizcle.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-52c3e350cbd1', 'mp-f0129b3dfc05', 'mp-b5f3689e32d6']::text[], 'El champagne del PRX dialoga con el pantalón Valentino y los pumps Saint Laurent, creando una silueta sofisticada y ejecutiva. Infusion de Rose suma rosa limpia y aire empolvado, perfecta para oficina y reuniones formales.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f60964fd1e13', 'theoutnet', 'ton-46376663163090350', 'Tapered Lyocell Linen And Cotton Blend Twill Pants', 'Sandro', 'clothing', 'men', 'Pantalón tapered en mezcla de lyocell, lino y algodón, pulido y liviano.', 'https://www.theoutnet.com/variants/images/46376663163090350/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163090350/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163090350/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163090350/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163090350/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/sandro/pants/tailored-pants/tapered-lyocell-linen-and-cotton-blend-twill-pants/46376663163090350', 363, 485.99, 'Con blazer sin estructura, mocasines marrón oscuro, reloj fino y perfume amaderado limpio.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-55daa2a79111', 'mp-96bbb6af0c45', 'mp-4520d6ec87f1']::text[], 'El pantalón Sandro se eleva con loafers de grosgrain y el PRX plateado, logrando sobriedad moderna. Grey Vetiver completa el conjunto con un vetiver seco y pulcro, ideal para oficina o citas de trabajo en Lima.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f78b3cb527bd', 'jomashop', 'CZNY0154-51L', 'Citizen Promaster Dive Automatic Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Azul vivo y espíritu oceánico para un uso activo con estilo.', 'https://citizenwatch.widen.net/content/y94wplzcm3/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/y94wplzcm3/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/kkqnj2mwsk/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/ojqipuj7ug/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iv1z6lnskv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-automatic-blue-dial-mens-watch-ny015451l_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-automatic-blue-dial-mens-watch-ny015451l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-dive-automatic-blue-dial-mens-watch-ny015451l_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-dive-automatic-blue-dial-mens-watch-ny0154-51l.html', 364, 486.99, 'Combínalo con camiseta técnica gris, jogger negro, sneakers blancas y perfume fresco marino.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-48065a020111', 'mp-2abd9b8ccfe5', 'mp-605a39d82c0f']::text[], 'El azul del diver y los swim shorts crean un look costero muy natural. Luna Rossa Carbon aporta frescura aromática y mineral, ideal para fin de semana, deporte ligero o almuerzo informal junto al mar.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a6caa1d21f46', 'theoutnet', 'ton-7789028784813517', 'Lace Paneled Pleated Studded Silk Crepe de Chine Midi Dress', 'Valentino', 'clothing', 'women', 'Encaje y tachuelas en una silueta sofisticada con carácter teatral.', 'https://www.theoutnet.com/variants/images/7789028784813517/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/7789028784813517/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/7789028784813517/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/7789028784813517/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/7789028784813517/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/7789028784813517/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/valentino-garavani/dresses/midi-dresses/lace-paneled-pleated-studded-silk-crepe-de-chine-midi-dress/7789028784813517', 369, 492.99, 'Compleméntalo con sandalias negras, reloj joya discreto y clutch satinado para un look de gala sobrio.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-f941866c6dcf', 'mp-a74b23068c3b', 'mp-db3e96bd55d9']::text[], 'El vestido pide una salida de noche: los slingbacks satinados estilizan y el PRX añade un brillo discreto. Love In White aporta blancura floral y elegante, con aire luminoso para cenas, cócteles o celebraciones.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-780b846a1c09', 'theoutnet', 'ton-1647597296161084', 'Gemma 40 Metallic Brocade Slingback Pumps', 'Jimmy Choo', 'shoes', 'women', 'Brocado metálico que ilumina el paso con refinamiento festivo.', 'https://www.theoutnet.com/variants/images/1647597296161084/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597296161084/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597296161084/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597296161084/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597296161084/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597296161084/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/pumps/mid-heel-pumps/gemma-40-metallic-brocade-slingback-pumps/1647597296161084', 369, 492.99, 'Llévalos con vestido negro midi, reloj delgado en oro y bolso pequeño satinado en tono champagne.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-a6caa1d21f46', 'mp-a74b23068c3b', 'mp-907d601e36bb']::text[], 'Los slingbacks metálicos funcionan mejor con el vestido de seda, de caída limpia y dramática. Royal Princess Oud aporta rosa, oud y maderas suaves, una estela refinada para noche, gala o evento especial.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLU