INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-23f89df132c9', 'jomashop', 'TIST1202102205100', 'Tissot Seastar Quartz Black Dial Unisex Watch', 'Tissot', 'watch', 'unisex', 'Negro integral y escala compacta para un uso práctico con presencia.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw915d875d/product-pictures/5ceefb3c-e50b-43e1-8bf5-90b8b27ffc37_T120-210-22-051-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw915d875d/product-pictures/5ceefb3c-e50b-43e1-8bf5-90b8b27ffc37_T120-210-22-051-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw915d875d/product-pictures/5ceefb3c-e50b-43e1-8bf5-90b8b27ffc37_T120-210-22-051-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwede9db3e/product-pictures/4a17304c-c29b-43af-ba54-c5c6b35105ff_T120_210_22_051_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb949139c/product-pictures/4880e810-d91e-4c10-a211-6e61d7c6662d_T120_210_22_051_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1f5b0e92/product-pictures/4e0441d1-a458-4b5a-82d4-08256c370735_T120_210_22_051_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw19d1be4c/product-pictures/0f53af85-1ba9-426d-8cca-abc37a79f76e_T120_210_22_051_00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-quartz-black-dial-unisex-watch-t1202102205100.jpg']::text[], 'https://www.jomashop.com/tissot-tissot-seastar-black-dial-unisex-watch-t1202102205100.html', 370.98, 495.99, 'Combínalo con camisa blanca, blazer azul marino, pantalón recto y zapatillas de cuero negro.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-f60964fd1e13', 'mp-b2dbfc6f7e6e', 'mp-4520d6ec87f1']::text[], 'Con pantalón de corte limpio, oxford de Santoni y Grey Vetiver, tu Seastar negro funciona perfecto en oficina. El look es serio, moderno y muy versátil para jornada laboral o reunión. La fragancia es seca, elegante y discretamente masculina.', 'oficina', ARRAY['mp-03f0eae878a1', 'mp-08cb860e5a5a', 'mp-8498b52f4f24']::text[], 'Para oficina, el pantalón de lana, los loafers Ferragamo y Elle de YSL crean un look firme y elegante. El Seastar negro suma precisión deportiva sin romper la sobriedad. La fragancia aporta un tono limpio, floral y pulido.', 'oficina') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a164c517d625', 'jomashop', 'TIST1202102211100', 'Tissot Seastar Quartz White Mother of Pearl Dial Watch', 'Tissot', 'watch', 'women', 'Nácar blanco y proporción fina para una elegancia suave y atemporal.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb12bd358/product-pictures/acd457e5-cdc0-468c-8802-6318f180ce28_T120-210-22-111-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb12bd358/product-pictures/acd457e5-cdc0-468c-8802-6318f180ce28_T120-210-22-111-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb12bd358/product-pictures/acd457e5-cdc0-468c-8802-6318f180ce28_T120-210-22-111-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw50e15a5b/product-pictures/0a19453f-e751-4b82-8eae-8c3e678138cd_T120_210_22_111_00_PROFIL-psd.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwcf2cf8b1/product-pictures/5b05abcc-c977-4c42-b43f-f9013d3d8d41_T120_210_22_111_00_B1-psd.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwc7e46da5/product-pictures/f4b1b4cb-443e-4f25-997d-1d1309f8504e_T120_210_22_111_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw3b22bb0d/product-pictures/d295d444-db8b-4a10-818f-c7d98b67d7a9_T120-210-22-111-00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-quartz-white-mother-of-pearl-dial-watch-t1202102211100.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-quartz-white-mother-of-pearl-dial-watch-t1202102211100.html', 370.98, 495.99, 'Úsalo con suéter de cashmere beige, falda midi marfil, mocasines nude y perfume limpio almizclado.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-d04ffafba9a6', 'mp-4f1a6a5f486b', 'mp-81d52947c289']::text[], 'La esfera nacarada se armoniza con la falda de seda y las ballet flats, creando un conjunto femenino y sereno. Dama Bianca suma vainilla cremosa, almizcle y flores blancas, perfecta para elegancia diurna o cena íntima.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-243f04615fce', 'theoutnet', 'ton-46376663163045174', 'Radial Suede Sandals', 'Dunhill', 'shoes', 'men', 'Sandalia de ante con silueta depurada y tacto noble.', 'https://www.theoutnet.com/variants/images/46376663163045174/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163045174/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163045174/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163045174/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163045174/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163045174/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/dunhill/sandals/flat-sandals/radial-suede-sandals/46376663163045174', 371, 495.99, 'Con camisa de lino azul, pantalón crema y reloj sencillo; perfume aromático fresco, nada estridente.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-744571d7ee01', 'mp-0be86622eeee', 'mp-8d5bb353d59a']::text[], 'Las sandalias de ante se integran con lino y un diver negro para un lujo relajado de verano. Neroli Portofino aporta cítricos brillantes y notas marinas, ideal para escapadas costeras o almuerzos al aire libre.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e15d8fec91e1', 'theoutnet', 'ton-34344356236749217', 'Ruffled Silk Blend Devore Velvet Dress', 'Valentino', 'clothing', 'women', 'Volantes y devoré en una lectura sensual, refinada y muy actual.', 'https://www.theoutnet.com/variants/images/34344356236749217/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/34344356236749217/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/34344356236749217/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/34344356236749217/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/34344356236749217/E/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/valentino-garavani/dresses/mini-dresses/ruffled-silk-blend-devore-velvet-dress/34344356236749217', 372, 496.99, 'Combínalo con sandalias negras minimalistas, reloj discreto en oro rosa y abrigo largo de lana negra.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-f941866c6dcf', 'mp-a74b23068c3b', 'mp-58072ada40a0']::text[], 'El vestido de Valentino luce mejor con slingbacks satinados, PRX champagne y Tuscan Leather. Es una propuesta de noche muy sofisticada, ideal para cena o evento especial. El perfume aporta cuero suave, incienso y un fondo cálido y envolvente.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a47f229935b7', 'theoutnet', 'ton-46376663163073932', 'Woven Pants', 'Acne Studios', 'clothing', 'men', 'Pantalón tejido con textura contemporánea y caída relajada.', 'https://www.theoutnet.com/variants/images/46376663163073932/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163073932/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163073932/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163073932/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163073932/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163073932/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/acne-studios/pants/tailored-pants/woven-pants/46376663163073932', 372, 496.99, 'Con camisa popelina, derby de cuero y reloj de acero; perfume seco, elegante y poco dulce.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-42bc749064f5', 'mp-96bbb6af0c45', 'mp-4520d6ec87f1']::text[], 'Con loafers de ante, PRX plateado y Grey Vetiver, este pantalón transmite lujo silencioso. Funciona en oficina creativa o cena relajada, con una estética limpia y muy actual. La fragancia es fresca, seca y refinada.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
