nspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-37d36772367a', 'jomashop', 'TIST1204101105100', 'Tissot Seastar Quartz Black Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Negro técnico y caja robusta para un estilo masculino firme y versátil.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0969eaf3/product-pictures/0113c782-4d5d-4596-9f2c-3fec9b7bb34f_T120-410-11-051-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0969eaf3/product-pictures/0113c782-4d5d-4596-9f2c-3fec9b7bb34f_T120-410-11-051-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0969eaf3/product-pictures/0113c782-4d5d-4596-9f2c-3fec9b7bb34f_T120-410-11-051-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwc7ec6a89/product-pictures/c24489f5-94cf-48c1-81cd-bdd8eae92b18_T120_410_11_051_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw2ea82ed6/product-pictures/68d3d486-8f91-44ce-b2e0-47cf2ac53ccc_T120_410_11_051_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwd0a5f8c4/product-pictures/637ba674-2f17-4374-a095-5af2bb1e8139_T120_410_11_051_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw9ace37a7/product-pictures/5109a76b-10b1-445f-8d12-867d2107c0d9_T120_410_11_051_00_DETAIL-1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1a64702b/product-pictures/1a7f58db-9fb2-4be5-8ae7-ac81107df5c0_T120_410_11_051_00_DETAIL-2.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-seastar-quartz-black-dial-mens-watch-t120-410-11-051-00.html', 375.25, 500.99, 'Úsalo con overshirt gris, pantalón cargo oscuro, sneakers negras y perfume de vetiver fresco.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-f60964fd1e13', 'mp-b2dbfc6f7e6e', 'mp-21708b443c49']::text[], 'Para un día de oficina con aire deportivo, estos pantalones limpios y mocasines refinados equilibran el reloj. Acqua di Gio Profondo aporta frescura marina y elegante, perfecta para Lima y para un look discreto, moderno y pulido.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-88356211960f', 'theoutnet', 'ton-46376663163101627', 'Long Length Striped Seersucker Swim Shorts', 'Thom Browne', 'clothing', 'men', 'Short de baño seersucker con rayas clásicas y largo elegante.', 'https://www.theoutnet.com/variants/images/46376663163101627/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163101627/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163101627/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163101627/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163101627/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163101627/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/swimwear-beachwear/swim-shorts/long-length-striped-seersucker-swim-shorts/46376663163101627', 375, 500.99, 'Con polo blanco, alpargatas, reloj resistente y perfume marino; después, camisa de lino beige.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-69ef4764b1ae', 'mp-5744d9813fec', 'mp-21708b443c49']::text[], 'Para ti, este conjunto respira verano: espadrilles, reloj de buceo y Acqua di Gio Profondo crean una lectura fresca, pulida y relajada. Ideal para playa, almuerzo costero o escapada de fin de semana, con una estela limpia y marina.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
