INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f0129b3dfc05', 'theoutnet', 'ton-46376663163165503', 'Anja Leather Pumps', 'Saint Laurent', 'shoes', 'women', 'Líneas limpias y acabado firme para una feminidad sobria y actual.', 'https://www.theoutnet.com/variants/images/46376663163165503/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163165503/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165503/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165503/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165503/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165503/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/saint-laurent/pumps/high-heel-pumps/anja-leather-pumps/46376663163165503', 377, 502.99, 'Combínalos con blazer crema, pantalón de pinzas, reloj oro claro y bolso estructurado en beige.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-4309d7661011', 'mp-da98d2ee7fd3', 'mp-b5f3689e32d6']::text[], 'Para oficina, el blazer entalla con precisión y las pumps estilizan sin exceso. El PRX de madreperla y Infusion de Rose completan un look luminoso, profesional y femenino, ideal para jornadas largas o reuniones importantes.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLU