INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3c2a0c191da5', 'jomashop', 'SE-SRPL05K1', 'Seiko Limited Edition 5 Sports Automatic Black Dial Watch', 'Seiko', 'watch', 'unisex', 'Automático robusto y estética deportiva para un pulso contemporáneo y confiable.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-limited-edition-5-sports-automatic-black-dial-watch-srpl05k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-limited-edition-5-sports-automatic-black-dial-watch-srpl05k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-limited-edition-5-sports-automatic-black-dial-watch-srpl05k1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-limited-edition-5-sports-automatic-black-dial-watch-srpl05k1_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-limited-edition-5-sports-automatic-black-dial-watch-srpl05k1_6.jpg', 'https://media.karousell.com/media/photos/products/2024/9/24/seiko_5_sports_srpl05_srpl05k1_1727147065_cb754136_progressive', 'https://media.karousell.com/media/photos/products/2024/9/24/seiko_5_sports_srpl05_srpl05k1_1727147065_65b32e75_progressive', 'https://cdnstatic.creationwatches.com/products/product-images/l/SRPL05K1_3_LRG.webp']::text[], 'https://www.jomashop.com/seiko-limited-edition-5-sports-automatic-black-dial-watch-srpl05k1.html', 379, 505.99, 'Llévalo con polo blanco, pantalón azul marino, sneakers de cuero y perfume fresco con maderas suaves.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-a47f229935b7', 'mp-b2dbfc6f7e6e', 'mp-e5b8eeedce5f']::text[], 'Para oficina, este pantalón de línea limpia y los oxford sobrios acompañan muy bien al reloj negro. Homme Intense añade un toque elegante, seco y ligeramente irisado, perfecto para verte impecable del escritorio a la cena.', 'oficina', ARRAY['mp-03f0eae878a1', 'mp-f0129b3dfc05', 'mp-8498b52f4f24']::text[], 'Para oficina, los pantalones de caída pulida y las pumps clásicas equilibran el reloj deportivo con elegancia. My Way aporta un floral limpio y moderno, ideal para un día de trabajo con presencia femenina y precisa.', 'oficina') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-57457d991c2d', 'jomashop', 'TIST1204103305100', 'Tissot Seastar 1000 Quartz Black Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Negro profundo y caja contundente para un estilo técnico con aplomo.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf51c151e/product-pictures/a85ddc5e-53ad-4d0f-9c85-4a43aec108fd_T120-410-33-051-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf51c151e/product-pictures/a85ddc5e-53ad-4d0f-9c85-4a43aec108fd_T120-410-33-051-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf51c151e/product-pictures/a85ddc5e-53ad-4d0f-9c85-4a43aec108fd_T120-410-33-051-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwdddb6473/product-pictures/9fbab168-1e6e-44a7-bbef-411fa8abccd0_T120_410_33_051_00_PROFIL-psd.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwcba7d0d2/product-pictures/f41cb624-2653-4298-bf20-af6d08829f6f_T120_410_33_051_00.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwc882426f/product-pictures/c531a847-5561-44db-9322-52d16bcc024d_T120_410_33_051_00-psd.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-quartz-black-dial-mens-watch-t1204103305100.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-quartz-black-dial-mens-watch-t1204103305100_2.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-1000-quartz-black-dial-mens-watch-t1204103305100.html', 379.05, 505.99, 'Combínalo con camiseta blanca, chaqueta ligera negra, denim oscuro y perfume amaderado limpio.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-8e340ce72afb', 'mp-5e2e71d7480e', 'mp-72eecd3685e7']::text[], 'Para ti, una camiseta esencial, zapatillas Nike y este Seastar crean un look deportivo y actual. Luna Rossa Carbon añade frescura aromática con faceta limpia y mineral, perfecto para fin de semana, caminatas o planes casuales.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-204891a8b1dd', 'jomashop', 'TIST1204103342100', 'Tissot Seastar 1000 Quartz Men''s Watch', 'Tissot', 'watch', 'men', 'Cronógrafo robusto con presencia náutica y acabado sobrio, ideal para un estilo activo y pulido.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-quartz-mens-watch-t1204103342100_2_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-quartz-mens-watch-t1204103342100_2_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-quartz-mens-watch-t1204103342100_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-quartz-mens-watch-t1204103342100_3.jpg', 'https://assets.tissotwatches.com/transform/Extend/0cd18b22-a637-4e7b-9d07-0c0a93262aa6/T120-410-33-421-00_Shadow?io=transform:fill,width:800,height:800,gravity:center']::text[], 'https://www.jomashop.com/tissot-seastar-1000-quartz-mens-watch-t1204103342100.html', 379.05, 505.99, 'Llévalo con polo blanco, pantalón azul marino y sneakers de cuero; añade perfume fresco acuático.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-f63eb8828e5a', 'mp-33f9e1a509fc', 'mp-60727c51909d']::text[], 'Para un look casual, el hoodie suave y las sneakers dan comodidad sin perder estilo. Sauvage aporta un perfil fresco, especiado y vibrante, ideal para tardes relajadas, viaje o brunch con actitud limpia y contemporánea.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0dcd0ed5dea8', 'theoutnet', 'ton-46376663163077208', 'One Shoulder Cutout Stretch Pique Midi Dress', 'Versace', 'clothing', 'women', 'Silhouette asimétrica y recortes precisos que dibujan una presencia moderna y segura para la noche.', 'https://www.theoutnet.com/variants/images/46376663163077208/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163077208/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077208/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077208/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077208/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077208/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/dresses/knee-length-dresses/one-shoulder-cutout-stretch-pique-midi-dress/46376663163077208', 379, 505.99, 'Combínalo con tacones negros, clutch rígido y reloj metálico fino; perfume ambarado, discreto.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-f941866c6dcf', 'mp-1e7075d60425', 'mp-a164c517d625']::text[], 'Para una noche elegante, el vestido con cutout se vuelve protagonista junto a las sandalias satinadas. Guilty Absolu aporta un carácter intenso, ambarado y sensual, ideal para cena, evento o celebración con presencia sofisticada.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-aca43f413514', 'theoutnet', 'ton-46376663163165506', 'Cassandra Patent Leather Sandals', 'Saint Laurent', 'shoes', 'women', 'Sandalia de charol con líneas limpias que eleva cualquier conjunto con brillo sofisticado.', 'https://www.theoutnet.com/variants/images/46376663163165506/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163165506/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165506/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165506/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165506/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165506/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/saint-laurent/sandals/flat-sandals/cassandra-patent-leather-sandals/46376663163165506', 379, 505.99, 'Úsalas con vestido negro satinado, reloj minimalista y aretes pequeños; perfume floral seco.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-a6caa1d21f46', 'mp-0c70d2a8c8be', 'mp-db3e96bd55d9']::text[], 'Para ti, este vestido midi y las sandalias patent mantienen una elegancia limpia y moderna. El reloj con diamantes suma luz sutil, y Love in White aporta un floral cremoso, perfecto para una cena refinada o cóctel.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b89a0d057c25', 'theoutnet', 'ton-46376663163165508', 'Joni Crystal Embellished Suede Flip Flops', 'Saint Laurent', 'shoes', 'women', 'Flip flops de gamuza con destellos sutiles para un lujo relajado y veraniego.', 'https://www.theoutnet.com/variants/images/46376663163165508/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163165508/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165508/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165508/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165508/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165508/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/saint-laurent/sandals/flat-sandals/joni-crystal-embellished-suede-flip-flops/46376663163165508', 380, 506.99, 'Combínalas con lino beige, reloj blanco limpio y camisa abierta; perfume cítrico ligero.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-d04ffafba9a6', 'mp-217a0ab70ad2', 'mp-8cf3908f3eee']::text[], 'La falda midi suaviza las sandalias con aire sofisticado; el reloj nácar añade brillo sutil. Flora Gorgeous Gardenia aporta un floral cremoso y femenino, perfecto para un almuerzo elegante o tarde de verano.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3770d038d351', 'theoutnet', 'ton-46376663163165509', 'Kiss 105 Neon Patent Leather Slingback Pumps', 'Saint Laurent', 'shoes', 'women', 'Tacón slingback en charol neón, audaz y escultural para destacar con intención.', 'https://www.theoutnet.com/variants/images/46376663163165509/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163165509/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165509/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165509/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165509/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165509/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/saint-laurent/pumps/high-heel-pumps/kiss-105-neon-patent-leather-slingback-pumps/46376663163165509', 380, 506.99, 'Acompáñalo con vestido negro, reloj delgado y bolso estructurado; perfume floral intenso, sofisticado.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-3c1803aec5d1', 'mp-cb004bfbf1f3', 'mp-fe3817a21904']::text[], 'El vestido midi de encaje y satén acompaña el acento neon con dramatismo pulido. El PRX negro suma contraste; Donna Born In Roma Intense aporta calidez floral-amaderada para una noche sofisticada.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUD