INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8e340ce72afb', 'theoutnet', 'ton-46376663163110383', 'Off Stamp Short Length Printed Swim Shorts', 'Off-White', 'clothing', 'men', 'Short de baño estampado con energía gráfica y acabado ligero.', 'https://www.theoutnet.com/variants/images/46376663163110383/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163110383/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163110383/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163110383/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163110383/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163110383/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/off-white%E2%84%A2/swimwear-beachwear/swim-shorts/off-stamp-short-length-printed-swim-shorts/46376663163110383', 382, 508.99, 'Con camiseta negra, sandalias simples, reloj deportivo y perfume cítrico-ámbar para un contraste limpio.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-69ef4764b1ae', 'mp-5744d9813fec', 'mp-a7bc1a9fc8da']::text[], 'Espadrilles, reloj de buceo y un perfume acuático dan un aire fresco y sofisticado para playa o club náutico. El conjunto mantiene la impronta urbana del short con una estela limpia, marina y elegante.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-08cb860e5a5a', 'theoutnet', 'ton-46376663163065492', 'Irina Leather Loafers', 'Ferragamo', 'shoes', 'women', 'Mocasín de líneas limpias y cuero liso, impecable para un guardarropa sobrio.', 'https://www.theoutnet.com/variants/images/46376663163065492/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163065492/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163065492/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163065492/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163065492/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163065492/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/flat-shoes/loafers/irina-leather-loafers/46376663163065492', 383, 510.99, 'Combínalos con traje gris, reloj de acero y camisa azul; perfume amaderado suave.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-4309d7661011', 'mp-a74b23068c3b', 'mp-db3e96bd55d9']::text[], 'El blazer estructurado convierte los loafers en un conjunto pulido y moderno. El reloj champán mantiene la línea impecable. Love In White aporta frescura almizclada y luminosa, perfecta para jornadas ejecutivas.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2ca59b3d8894', 'theoutnet', 'ton-46376663163066691', 'Torris 70 Leather Knee Boots', 'Ferragamo', 'shoes', 'women', 'Bota alta de cuero con perfil depurado, ideal para presencia elegante en frío.', 'https://www.theoutnet.com/variants/images/46376663163066691/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163066691/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163066691/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163066691/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163066691/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163066691/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/boots/tall-boots/torris-70-leather-knee-boots/46376663163066691', 383, 510.99, 'Usa con abrigo camel, vestido negro y reloj metálico; perfume especiado, discreto.', 'https://threadcurve.com/wp-content/uploads/2025/11/statement-coat-layered-winter-outfit.jpeg', ARRAY['mp-03f0eae878a1', 'mp-87c1eb6527f0', 'mp-8cf3908f3eee']::text[], 'Los pantalones sastre equilibran la bota alta con elegancia urbana. El reloj cristalino suma luz sin exceso. Gucci Flora Gorgeous Gardenia suaviza el conjunto con un floral blanco, ideal para invierno de ciudad.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=