INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5e2e71d7480e', 'theoutnet', 'ton-46376663163077029', 'Metallic Pebbled Leather Oxford Brogues', 'Thom Browne', 'shoes', 'men', 'Oxford brogue con brillo metálico y presencia contemporánea.', 'https://www.theoutnet.com/variants/images/46376663163077029/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163077029/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077029/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077029/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077029/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077029/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/flat-shoes/lace-ups/metallic-pebbled-leather-oxford-brogues/46376663163077029', 384, 511.99, 'Con traje negro, camisa blanca, reloj de vestir y perfume cuero-amaderado para una salida impecable.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-76e86cc39c9a', 'mp-a7fbae0e4ca7', 'mp-e5b8eeedce5f']::text[], 'El pantalón de lana afina la silueta, el PRX champagne suma pulso ejecutivo y el perfume aporta iris, cacao y maderas suaves. Ideal para oficina formal o cena de negocio con un gesto discreto y refinado.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_id