INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8e05e719dc6d', 'jomashop', 'TIST1372103302100', 'Tissot PRX Quartz Champagne Dial Unisex Watch', 'Tissot', 'watch', 'unisex', 'PRX de carátula champán y perfil integrado, clásico contemporáneo con encanto discreto.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwc19af558/product-pictures/43e281e1-1b22-48b6-8abf-94d79ab81e7d_T137-210-33-021-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwc19af558/product-pictures/43e281e1-1b22-48b6-8abf-94d79ab81e7d_T137-210-33-021-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwc19af558/product-pictures/43e281e1-1b22-48b6-8abf-94d79ab81e7d_T137-210-33-021-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw29b3dbc5/product-pictures/493047d8-0e2a-4482-b5ac-72f40ee9d3b1_T137_210_33_021_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw67af60ba/product-pictures/d2d2521d-a5b8-42ad-bb80-d9dc7c7ed965_T137_210_33_021_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwa1b77712/product-pictures/3350713d-dc54-4c94-9dff-2be8ef0c565f_T137_210_33_021_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw006ec6be/product-pictures/116f757e-f5a3-46de-a918-d9e851983695_T137_210_33_021_00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-champagne-dial-unisex-watch-t1372103302100.jpg']::text[], 'https://www.jomashop.com/tissot-prx-quartz-champagne-dial-unisex-watch-t1372103302100.html', 386.4, 514.99, 'Póntelo con camisa blanca, pantalón gris y mocasines; perfume limpio amaderado.', 'https://lifewithjazz.com/wp-content/uploads/2022/04/5-Smart-Casual-Outfits-Last-picture.jpg', ARRAY['mp-2ad272892924', 'mp-42bc749064f5', 'mp-1fee958584dc']::text[], 'Para oficina, la camisa de lino y los loafers equilibran el brillo champagne del PRX con naturalidad. Myslf suma un aroma limpio, amaderado y moderno, ideal para un día largo de trabajo con un cierre impecable.', 'oficina', ARRAY['mp-e80799294eb5', 'mp-a817148e69da', 'mp-6becc442eecf']::text[], 'Para oficina, la camisa estructurada y las sneakers pulidas suavizan el tono champagne del reloj. My Way aporta un floral luminoso y femenino, perfecto para un look versátil, fresco y elegante de lunes a viernes.', 'oficina') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-60a8cf75a8f6', 'theoutnet', 'ton-46376663163165012', 'Wedmer Suede Derby Shoes', 'Bally', 'shoes', 'men', 'Derby de ante con línea versátil y refinamiento natural.', 'https://www.theoutnet.com/variants/images/46376663163165012/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163165012/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165012/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165012/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165012/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165012/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/flat-shoes/lace-ups/wedmer-suede-derby-shoes/46376663163165012', 387, 515.99, 'Con pantalón de lana gris, camisa azul y reloj clásico; perfume vetiver, sobrio y seco.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-f60964fd1e13', 'mp-96bbb6af0c45', 'mp-4520d6ec87f1']::text[], 'Pantalón limpio, PRX plateado y Grey Vetiver construyen una elegancia sobria, ideal para oficina o almuerzo ejecutivo. El ante del zapato suaviza el conjunto y mantiene una presencia discreta, moderna y muy cuidada.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-54cf222e00eb', 'theoutnet', 'ton-1647597355248084', 'Basil 95 Ruched Leather Sandals', 'Jimmy Choo', 'shoes', 'women', 'Sandalia recogida en cuero con volumen suave, pensada para pasos elegantes y femeninos.', 'https://www.theoutnet.com/variants/images/1647597355248084/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597355248084/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597355248084/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597355248084/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597355248084/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597355248084/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/sandals/high-heel-sandals/basil-95-ruched-leather-sandals/1647597355248084', 388, 516.99, 'Combínalas con vestido midi satinado, reloj fino y clutch negro; perfume floral almizclado.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-a6caa1d21f46', 'mp-a74b23068c3b', 'mp-907d601e36bb']::text[], 'El midi de Valentino eleva las sandalias con un equilibrio muy chic. El PRX champán aporta brillo discreto. Royal Princess Oud suma un perfume floral amaderado, ideal para cóctel o cena.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids,