INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1677b7e6dd07', 'theoutnet', 'ton-46376663163165016', 'Scardino Leather Monk Strap Shoes', 'Bally', 'shoes', 'men', 'Monk strap de cuero con doble hebilla y porte distinguido.', 'https://www.theoutnet.com/variants/images/46376663163165016/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163165016/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165016/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165016/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165016/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165016/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/flat-shoes/lace-ups/scardino-leather-monk-strap-shoes/46376663163165016', 389, 517.99, 'Con traje azul petróleo, reloj pulido y perfume amaderado especiado; suma una corbata borgoña discreta.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-76e86cc39c9a', 'mp-38b9fcac4c9b', 'mp-cf2b71c1d9e8']::text[], 'El pantalón de corte impecable, el Le Locle y Mefisto —cítrico, aromático y limpio— refuerzan la formalidad sin rigidez. Una propuesta precisa para oficina importante o cena elegante, con acabado silencioso y distinguido.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EX