sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-quartz-champagne-dial-mens-watch-t1374103302100-t1374103302100.jpg']::text[], 'https://www.jomashop.com/tissot-prx-quartz-champagne-dial-mens-watch-t137-410-33-021-00.html', 391.92, 521.99, 'Combínalo con blazer azul, pantalón chino beige y derbies; perfume cítrico amaderado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-6a03b9633ec5', 'mp-60a8cf75a8f6', 'mp-337d48edab34']::text[], 'Los chinos equilibran el brillo del PRX, mientras los derbies en ante conservan sobriedad. Acqua di Gio Parfum aporta frescura mineral y elegante, ideal para oficina y después del trabajo en clima cálido.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
