co_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-74999c4382c8', 'jomashop', 'CZJY8147-01X', 'Citizen Promaster Skyhawk A-T Chronograph Green Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Cronógrafo aviador en verde, técnico y preciso, con mirada contemporánea y funcional.', 'https://citizenwatch.widen.net/content/kozevk0izq/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/kozevk0izq/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/mjixskrlro/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/dh7ziutogj/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/odeapwy2up/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-chronograph-green-dial-mens-watch-jy814701x.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-chronograph-green-dial-mens-watch-jy814701x_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-chronograph-green-dial-mens-watch-jy814701x_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-skyhawk-a-t-perpetual-alarm-world-time-chronograph-gmt-analog-digital-green-dial-mens-watch-jy8147-01x.html', 392.64, 522.99, 'Úsalo con camisa celeste, pantalón caqui y botas pulidas; perfume verde amaderado.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-f60964fd1e13', 'mp-94a0cc171f7c', 'mp-4520d6ec87f1']::text[], 'El pantalón técnico, los monk strap y Grey Vetiver crean un contraste sofisticado para viaje o jornada activa. El reloj refuerza el aire funcional; el perfume suma limpieza seca y moderna, sin perder presencia.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f702139c249a', 'theoutnet', 'ton-46376663163165514', 'Amber Leather Sandals', 'Saint Laurent', 'shoes', 'women', 'Sandalia de cuero con líneas puras que aporta elegancia serena a cualquier noche.', 'https://www.theoutnet.com/variants/images/46376663163165514/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163165514/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165514/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165514/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165514/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165514/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/saint-laurent/sandals/high-heel-sandals/amber-leather-sandals/46376663163165514', 393, 522.99, 'Combínalas con vestido negro, reloj delgado y abrigo largo; perfume ambarado suave.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-a6caa1d21f46', 'mp-bed33a85d2ac', 'mp-cb004bfbf1f3']::text[], 'El vestido midi aporta delicadeza a las sandalias con una silueta muy refinada. El Presage plateado suma brillo sereno. Donna Born In Roma Intense añade un floral ambarado, ideal para cena o gala.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note