INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-19acfd6024df', 'theoutnet', 'ton-46376663163165515', 'Eva Glossed Leather Mules', 'Saint Laurent', 'shoes', 'women', 'Mule glossed de silueta depurada, pulido brillo para un cierre sofisticado.', 'https://www.theoutnet.com/variants/images/46376663163165515/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163165515/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165515/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165515/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165515/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165515/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/saint-laurent/sandals/high-heel-sandals/eva-glossed-leather-mules/46376663163165515', 393, 522.99, 'Llévalas con falda midi, top de seda y reloj minimalista; perfume chipre ligero.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-c9910bcebeda', 'mp-87c1eb6527f0', 'mp-81d52947c289']::text[], 'Las mules dialogan con un mini dress floral y un reloj de madreperla para un look femenino y pulido. Ideal para cena o cóctel; el perfume aporta flores blancas suaves y una estela refinada.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCL