INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3d4c7aa7421d', 'theoutnet', 'ton-46376663162995310', 'Amara 85 Embellished Suede Mules', 'Jimmy Choo', 'shoes', 'women', 'Mule de gamuza con pedrería sutil, luminoso sin perder refinamiento.', 'https://www.theoutnet.com/variants/images/46376663162995310/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162995310/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162995310/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162995310/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162995310/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162995310/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/sandals/high-heel-sandals/amara-85-embellished-suede-mules/46376663162995310', 395, 525.99, 'Combínalas con pantalón palazzo negro, reloj plateado y top satinado; perfume floral oriental.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-93b4025350f4', 'mp-217a0ab70ad2', 'mp-864d2667cf0c']::text[], 'El blazer equilibra las mules con presencia nocturna y estructura fina. Funciona muy bien para cena o evento; el perfume suma un acorde floral aterciopelado, discreto pero sofisticado.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_no