tz-black-dial-mens-watch-t1204102205101_3.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-quartz-black-dial-mens-watch-t1204102205101.html', 397.44, 528.99, 'Úsalo con polo gris, jeans oscuros y sneakers blancas; perfume marino limpio.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-a157c4e48ec5', 'mp-605a39d82c0f']::text[], 'La camiseta minimalista, las Dunk Low y Luna Rossa Carbon forman un conjunto urbano y fresco para fin de semana o mar. El aroma es limpio, mineral y ligeramente aromático, ideal para un look relajado.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
