INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-30fb2e1c8bbc', 'theoutnet', 'ton-46376663162866857', 'Iman Suede Pumps', 'Ferragamo', 'shoes', 'women', 'Salón de gamuza con punta afilada, sobrio y femenino para jornadas pulidas.', 'https://www.theoutnet.com/variants/images/46376663162866857/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162866857/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162866857/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162866857/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162866857/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162866857/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/pumps/mid-heel-pumps/iman-suede-pumps/46376663162866857', 400, 531.99, 'Combínalo con pantalón sastre, blazer crema y reloj delgado; perfume almizclado discreto.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-035e4ccec884', 'mp-fe01b217f6d8', 'mp-cb004bfbf1f3']::text[], 'Los pumps de ante elevan el vestido midi con un aire más refinado y nocturno. Ideal para cena o evento formal; el perfume suma vainilla, flores y una estela seductora.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDE