INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-041722d35a9a', 'jomashop', 'CZJY8078-01L', 'Citizen Promaster Skyhawk A-T Perpetual Alarm Chronograph Men''s Watch', 'Citizen', 'watch', 'men', 'Cronógrafo aeronáutico con funciones avanzadas y presencia técnica, pensado para quienes van un paso adelante.', 'https://citizenwatch.widen.net/content/9m8mgrwkqb/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/9m8mgrwkqb/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/5ylofssj31/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/sccvwrzn6q/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/odeapwy2up/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-perpetual-alarm-chronograph-mens-watch-jy807801l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-perpetual-alarm-chronograph-mens-watch-jy807801l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-perpetual-alarm-chronograph-mens-watch-jy807801l_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-skyhawk-a-t-perpetual-alarm-chronograph-mens-watch-jy8078-01l.html', 402.24, 533.99, 'Llévalo con chaqueta verde oliva, camisa blanca y botas; perfume cítrico amaderado.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-ba531dfcfaae', 'mp-dffd0d484e72', 'mp-c3c82fdede97']::text[], 'El traje de lino suaviza la fuerza del chronograph, mientras los loafers de ante equilibran funcionalidad y elegancia. Sauvage EDP aporta frescura amaderada, ideal para viajes, oficina dinámica o un día largo.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
