INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-226b5ebf8d26', 'theoutnet', 'ton-1647597341958088', 'Condora 100 Spiked Leather Pumps', 'Christian Louboutin', 'shoes', 'women', 'Salones de cuero con tachuelas, de presencia precisa y espíritu audaz.', 'https://www.theoutnet.com/variants/images/1647597341958088/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597341958088/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597341958088/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597341958088/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597341958088/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597341958088/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/christian-louboutin/pumps/high-heel-pumps/condora-100-spiked-leather-pumps/1647597341958088', 407, 539.99, 'Combínalas con reloj fino, perfume amaderado y traje negro o vestido midi satinado.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-035e4ccec884', 'mp-16b4caef84fd', 'mp-58072ada40a0']::text[], 'Para una noche poderosa, este vestido con encaje y las pumps spiked crean impacto inmediato. El reloj azul profundo aporta contraste precioso, y Tuscan Leather refuerza el conjunto con cuero seco, ámbar y carácter sofisticado.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3f54661aa9f5', 'theoutnet', 'ton-46376663163091510', 'Rodolfo Suede Espadrilles', 'Frescobol Carioca', 'shoes', 'men', 'Espadrilles de gamuza con aire relajado y refinado, ideales para días cálidos con naturalidad.', 'https://www.theoutnet.com/variants/images/46376663163091510/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163091510/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091510/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091510/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091510/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091510/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/espadrilles/flat-espadrilles/rodolfo-suede-espadrilles/46376663163091510', 407, 539.99, 'Combínalas con reloj minimalista de acero, perfume cítrico y lino arena con pantalón blanco y camisa azul claro.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-744571d7ee01', 'mp-f4ebd9b401e2', 'mp-8d5bb353d59a']::text[], 'Lino claro, GMT y Neroli Portofino —cítrico, luminoso y limpio— acompañan con naturalidad estas espadrilles. Un look impecable para vacaciones, terraza o fin de semana cálido, con lujo relajado y sin esfuerzo.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f448663b0f97', 'theoutnet', 'ton-46376663163091511', 'Rodolfo Suede Espadrilles', 'Frescobol Carioca', 'shoes', 'men', 'Espadrilles de gamuza de líneas limpias, pensadas para un estilo fresco y discreto.', 'https://www.theoutnet.com/variants/images/46376663163091511/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163091511/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091511/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091511/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091511/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163091511/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/frescobol-carioca/espadrilles/flat-espadrilles/rodolfo-suede-espadrilles/46376663163091511', 407, 539.99, 'Llévalas con reloj delgado, fragancia marina y prendas de lino crudo con bermudas o pantalón beige.', 'https://thefashiontag.com/wp-content/uploads/2023/06/linen-shirts-for-men-outfits-1-5-1030x1030.jpg', ARRAY['mp-a2bd187331bf', 'mp-1fcb548dde4f', 'mp-21708b443c49']::text[], 'Los shorts de mezcla liviana, el Promaster verde y Profondo refuerzan la frescura marina del espadrille. Ideal para viaje o costa, con un perfume acuático y moderno que mantiene el conjunto pulcro y veraniego.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiratio