c8d158f7_T120-852-11-051-00_DETAIL-1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwcedac0dd/product-pictures/164bc29e-8a93-44ad-b1f5-a49e26aa38eb_T120-852-11-051-00_DETAIL-2.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-seastar-1000-quartz-gmt-black-dial-mens-watch-t120-852-11-051-00.html', 408, 541.99, 'Llévalo con polo azul marino, sneakers negras y perfume cítrico limpio; suma chaqueta técnica sobria.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-f468012c6135', 'mp-3f54661aa9f5', 'mp-60727c51909d']::text[], 'El bomber técnico, las espadrilles y Sauvage crean una mezcla deportiva-lujosa muy actual. Funciona para escapadas costeras o navegación, con aire robusto pero limpio; el GMT suma carácter funcional y presencia silenciosa.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6bae240f837d', 'theoutnet', 'ton-1647597333165773', 'Polka Dot Duchesse Satin Flared Pants', 'Balmain', 'clothing', 'women', 'Pantalón de satén duchesse con lunares, fluido y teatral, ideal para una silueta refinada.', 'https://www.theoutnet.com/variants/images/1647597333165773/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597333165773/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597333165773/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597333165773/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597333165773/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597333165773/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/pants/flared-pants/polka-dot-duchesse-satin-flared-pants/1647597333165773', 408, 541.99, 'Combínalo con reloj discreto, perfume floral intenso y blusa satinada; completa con tacones negros.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-19acfd6024df', 'mp-a74b23068c3b', 'mp-db3e96bd55d9']::text[], 'Para una noche elegante en Lima, estas mules pulen la silueta con discreción; el PRX en champagne suma brillo sutil y Creed Love In White aporta un floral limpio y luminoso, perfecto para un look sofisticado, moderno y femenino.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8fb5d61c332e', 'theoutnet', 'ton-34344356236612391', 'Hart 95 Suede Ankle Boots', 'Jimmy Choo', 'shoes', 'women', 'Botines de ante con tacón alto, de línea depurada y acabado sensual para elevar cualquier conjunto.', 'https://www.theoutnet.com/variants/images/34344356236612391/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/34344356236612391/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/34344356236612391/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/34344356236612391/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/34344356236612391/E/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/boots/ankle-boots/hart-95-suede-ankle-boots/34344356236612391', 408, 541.99, 'Úsalos con reloj delgado, perfume vainilla suave y abrigo camel; acompaña con pantalón negro recto.', 'https://threadcurve.com/wp-content/uploads/2025/11/statement-coat-layered-winter-outfit.jpeg', ARRAY['mp-381d102f4ffc', 'mp-a74b23068c3b', 'mp-87146dc3b3db']::text[], 'Para ti: el suéter de cachemira suaviza las botas y la falda midi equilibra la silueta con elegancia. Ideal para una cena de invierno o una salida refinada. El oud aporta una estela cálida, profunda y sofisticada.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
