INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-dffd0d484e72', 'theoutnet', 'ton-46376663163165031', 'Belfast Suede Penny Loafers', 'Bally', 'shoes', 'men', 'Mocasín de gamuza con silueta clásica, sobria y versátil para vestir con distinción.', 'https://www.theoutnet.com/variants/images/46376663163165031/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163165031/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165031/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165031/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165031/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163165031/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/flat-shoes/loafers/belfast-suede-penny-loafers/46376663163165031', 411, 544.99, 'Úsalos con reloj de brazalete fino, perfume amaderado y sastre azul marino con camisa blanca.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-2ad272892924', 'mp-38b9fcac4c9b', 'mp-d3b04c599098']::text[], 'Para ti: la camisa de lino y el pantalón de lana crean un conjunto sobrio que acompaña muy bien los loafers. Ideal para oficina o reuniones. El reloj añade precisión clásica y presencia serena.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note