INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4d4c7a52c4f5', 'theoutnet', 'ton-46376663163153290', 'Windsor Pebbled Leather Penny Loafers', 'Bally', 'shoes', 'men', 'Mocasín de cuero granulado con presencia serena, perfecto para jornadas formales sin rigidez.', 'https://www.theoutnet.com/variants/images/46376663163153290/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163153290/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153290/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153290/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153290/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153290/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/flat-shoes/loafers/windsor-pebbled-leather-penny-loafers/46376663163153290', 412, 545.99, 'Combínalos con reloj de acero mate, perfume almizclado y traje gris con camisa celeste.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-2ad272892924', 'mp-96f2d714483c', 'mp-d3b04c599098']::text[], 'Para ti: la camisa de lino y el pantalón entallado mantienen una línea limpia que realza el carácter de los loafers. Perfecto para oficina o almuerzos formales. El reloj azul suma distinción contenida.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image