INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-6e78cd2c0e9e', 'theoutnet', 'ton-46376663163153298', 'Slator Leather Penny Loafers', 'Bally', 'shoes', 'men', 'Mocasín de cuero pulido con línea atemporal, hecho para un guardarropa pulcro y fácil.', 'https://www.theoutnet.com/variants/images/46376663163153298/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163153298/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153298/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153298/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153298/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153298/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/flat-shoes/loafers/slator-leather-penny-loafers/46376663163153298', 415, 549.99, 'Combínalos con reloj clásico, perfume de cuero suave y pantalón de lana con polo fino o camisa Oxford.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4af1908c0185', 'mp-aef4c954ee47', 'mp-ae99e2aca74c']::text[], 'Para ti: la camisa de algodón y el pantalón recto crean un conjunto limpio que hace muy versátiles estos loafers. Ideal para oficina relajada o viernes formal. El perfume es vetiver elegante, seco y sobrio.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EX