_T120_417_17_051_03.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/o/p/open-box-tissot-seastar-1000-chronograph-quartz-black-dial-mens-watch-t120-417-17-051-03-t1204171705103.jpg']::text[], 'https://www.jomashop.com/open-box-tissot-seastar-1000-chronograph-quartz-black-dial-mens-watch-t120-417-17-051-03.html', 415.35, 550.99, 'Combínalo con reloj no necesario; mejor polo técnico, sneaker gris y perfume acuático o amaderado limpio.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-1e2e2d2f0407', 'mp-605a39d82c0f', 'mp-a2717c731232']::text[], 'Para ti: el polo técnico y el pantalón ligero acompañan muy bien al reloj de buceo. Ideal para un estilo activo con acabado limpio. El perfume es fresco, aromático y moderno, con energía marina.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7e218d2cc34e', 'jomashop', 'TIST41118335', 'Tissot Le Locle Double Happiness Lady Automatic Laides Watch', 'Tissot', 'watch', 'unisex', 'Reloj automático femenino con estética clásica y pulida, de encanto sereno y atemporal.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-le-locle-double-happiness-lady-automatic-grey-dial-stainless-steel-laides-watch-t41.1.183.35.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-le-locle-double-happiness-lady-automatic-grey-dial-stainless-steel-laides-watch-t41.1.183.35.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-le-locle-double-happiness-lady-automatic-grey-dial-stainless-steel-laides-watch-t41.1.183.35_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-le-locle-double-happiness-lady-automatic-grey-dial-stainless-steel-laides-watch-t41.1.183.35_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-le-locle-double-happiness-lady-automatic-grey-dial-stainless-steel-laides-watch-t41.1.183.35_4.jpg', 'https://thewatchobserver.ouest-france.fr/wp-content/uploads/2020/09/331x331_T41118335.jpg', 'https://cdn.vuahanghieu.com/unsafe/0x0/left/top/smart/filters:quality(90)/https://admin.vuahanghieu.com/upload/news/content/2024/01/dong-ho-nu-tissot-le-locle-double-happiness-lady-automatic-ladies-t41-1-183-35-t41118335-mau-bac5-jpg-1704356785-04012024152625.jpg', 'https://cdn.vuahanghieu.com/unsafe/0x0/left/top/smart/filters:quality(90)/https://admin.vuahanghieu.com/upload/news/content/2024/01/dong-ho-nu-tissot-le-locle-double-happiness-lady-automatic-ladies-t41-1-183-35-t41118335-mau-bac8-jpg-1704356770-04012024152610.jpg']::text[], 'https://www.jomashop.com/tissot-watch-t41-1-183-35.html', 417.6, 552.99, 'Combínalo con vestido midi marfil, perfume floral suave y joyería mínima; añade salones nude o mocasines.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-22a9a0aaf882', 'mp-f72ed8b412b3', 'mp-ef0283228ea3']::text[], 'Para ti: el cashmere y los pumps de líneas finas acompañan el reloj con una feminidad sobria. Ideal para oficina o un almuerzo elegante. El perfume es floral y luminoso, delicado sin perder carácter.', 'elegante', ARRAY['mp-86d959f332e4', 'mp-4f1a6a5f486b', 'mp-81d52947c289']::text[], 'Para un día de oficina refinada, este pantalón fluye con el reloj clásico y las bailarinas; Dama Bianca añade una estela almizclada, avainillada y etérea, muy pulida y serena, ideal para transmitir elegancia sin esfuerzo.', 'lujo-silencioso') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-cd8ff58dbf50', 'theoutnet', 'ton-1647597342619553', 'Distressed Cotton Cardigan', 'Maison Margiela', 'clothing', 'women', 'Cardigan de algodón con acabado desgastado, relajado y texturizado, para un lujo informal.', 'https://www.theoutnet.com/variants/images/1647597342619553/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597342619553/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597342619553/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597342619553/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597342619553/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597342619553/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/maison-margiela/knitwear/cardigans-zip-throughs/distressed-cotton-cardigan/1647597342619553', 417, 552.99, 'Llévalo con reloj sencillo, perfume amaderado ligero y pantalón sastre beige; completa con loafers o botas.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-c3eaa0c6b09e', 'mp-f67e672616b5', 'mp-8d5bb353d59a']::text[], 'Para ti: las sneakers equilibran la textura del cardigan y el reloj mantiene el conjunto moderno. Perfecto para un fin de semana relajado. El perfume es fresco, cítrico y limpio, con aire mediterráneo.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-52c3e350cbd1', 'theoutnet', 'ton-1647597317643709', 'Crepe Flared Pants', 'Valentino', 'clothing', 'women', 'Pantalón acampanado de crepé, de caída nítida y silueta favorecedora, con presencia refinada.', 'https://www.theoutnet.com/variants/images/1647597317643709/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597317643709/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597317643709/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597317643709/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597317643709/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/valentino-garavani/pants/flared-pants/crepe-flared-pants/1647597317643709', 418, 553.99, 'Combínalo con reloj clásico, perfume limpio y blazer estructurado; remata con camisa blanca y mocasines negros.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-30fb2e1c8bbc', 'mp-3c1803aec5d1', 'mp-c0c58bfbda63']::text[], 'Para ti: los pantalones flared se ven impecables con pumps y un reloj fino; el resultado es sofisticado y profesional. Ideal para oficina o reuniones importantes. El perfume es oud floral, elegante y persistente.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f72ed8b412b3', 'theoutnet', 'ton-46376663163077056', 'Tweed Penny Loafers', 'Thom Browne', 'shoes', 'men', 'Mocasín de tweed con textura rica y sobria, ideal para un vestir clásico con matiz.', 'https://www.theoutnet.com/variants/images/46376663163077056/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163077056/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077056/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077056/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077056/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163077056/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/flat-shoes/loafers/tweed-penny-loafers/46376663163077056', 418, 553.99, 'Úsalos con reloj de piel, perfume amaderado y blazer de lana con pantalón gris y camisa crema.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-76e86cc39c9a', 'mp-38b9fcac4c9b', 'mp-cf2b71c1d9e8']::text[], 'Penny loafers con pantalón de lana, reloj Le Locle y Mefisto crean un look impecable y sereno para oficina o reuniones formales. La mezcla de texturas eleva el conjunto sin perder discreción.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLU