INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-01c65ac8aa0b', 'jomashop', 'CZBN5058-07E', 'Citizen Promaster Altichron Lefty Black Dial Men''s Sports Watch', 'Citizen', 'watch', 'men', 'Reloj deportivo con brújula y perfil técnico, pensado para exteriores con estilo contenido.', 'https://citizenwatch.widen.net/content/kohcimnvan/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/kohcimnvan/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/0lsvjmgg9m/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/swezqvt42v/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/odeapwy2up/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-altichron-black-dial-mens-sports-watch-bn505807e.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-altichron-black-dial-mens-sports-watch-bn505807e_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-altichron-black-dial-mens-sports-watch-bn505807e_3.jpg']::text[], 'https://www.jomashop.com/citizen-watch-bn5058-07e.html', 419, 554.99, 'Úsalo con chaqueta impermeable, perfume fresco y botas trekking negras; añade pantalón cargo oscuro.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-16dc129ea1db', 'mp-d989491a5eb9', 'mp-60727c51909d']::text[], 'El reloj de aventura se equilibra con overshirt técnico, sneakers refinadas y Sauvage, de salida fresca y energética. Un conjunto limpio, actual y funcional para ciudad activa o fin de semana.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
