INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-035e4ccec884', 'theoutnet', 'ton-46376663162839117', 'Embellished Guipure Lace Paneled Satin Midi Dress', 'Versace', 'clothing', 'women', 'Vestido midi de encaje y satén, luminoso y preciso, con un aire de gala contemporánea.', 'https://www.theoutnet.com/variants/images/46376663162839117/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162839117/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162839117/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162839117/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162839117/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162839117/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/dresses/midi-dresses/embellished-guipure-lace-paneled-satin-midi-dress/46376663162839117', 421, 557.99, 'Acompáñalo con reloj joya, perfume floral opulento y clutch negro; termina con sandalias finas y abrigo corto.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-927acd750758', 'mp-3c1803aec5d1', 'mp-6a517157564d']::text[], 'El vestido gana fuerza con pumps de plataforma, reloj joya y Aventus for Her, frutal-amaderado. Un conjunto sofisticado para cena o evento nocturno, con brillo contenido y presencia segura.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b4a17f12eb64', 'theoutnet', 'ton-46376663162995808', 'Blake 85 Leather Wedge Knee Boots', 'Jimmy Choo', 'shoes', 'women', 'Botas altas de cuero con cuña, estilizadas y firmes, para sumar altura con elegancia.', 'https://www.theoutnet.com/variants/images/46376663162995808/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162995808/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162995808/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162995808/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162995808/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162995808/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/boots/tall-boots/blake-85-leather-wedge-knee-boots/46376663162995808', 422, 558.99, 'Llévalas con reloj sobrio, perfume especiado suave y abrigo largo; combina con vestido negro o falda midi.', 'https://threadcurve.com/wp-content/uploads/2025/11/statement-coat-layered-winter-outfit.jpeg', ARRAY['mp-3cd959786f5c', 'mp-bed33a85d2ac', 'mp-aada2edf1de8']::text[], 'Las botas altas funcionan con un vestido estructurado, reloj de esfera plateada y Royal Princess Oud, opulento y aterciopelado. Perfecto para invierno elegante, cena o evento de tarde-noche.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5fffd96abc7f', 'theoutnet', 'ton-1647597341958098', 'Athina 100 Patent Leather Trimmed Crystal Embellished Striped Satin Sandals', 'Christian Louboutin', 'shoes', 'women', 'Sandalias satinadas con cristal, delicadas y luminosas para una noche impecable.', 'https://www.theoutnet.com/variants/images/1647597341958098/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597341958098/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597341958098/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597341958098/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597341958098/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597341958098/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/christian-louboutin/sandals/high-heel-sandals/athina-100-patent-leather-trimmed-crystal-embellished-striped-satin-sandals/1647597341958098', 422, 558.99, 'Úsalas con reloj joya, perfume floral suave y vestido fluido en marfil o negro.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-035e4ccec884', 'mp-bed33a85d2ac', 'mp-58072ada40a0']::text[], 'Para una noche de verano, el vestido de seda y estas sandalias cristalinas crean una línea sensual y ligera; el Presage de esfera plateada aporta refinamiento, y Tuscan Leather añade un carácter cuero-amaderado, intenso y envolvente.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
