inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-927acd750758', 'theoutnet', 'ton-46376663163149340', 'Padlock Leather Platform Pumps', 'Tom Ford', 'shoes', 'women', 'Tacón plataforma con cuero pulido y silueta marcada, hecho para destacar con intención.', 'https://www.theoutnet.com/variants/images/46376663163149340/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163149340/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163149340/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163149340/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163149340/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163149340/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/pumps/high-heel-pumps/padlock-leather-platform-pumps/46376663163149340', 424, 560.99, 'Acompáñalos con reloj joya, perfume intenso y vestido negro o sastre satinado en tonos vino.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-035e4ccec884', 'mp-3c1803aec5d1', 'mp-6a517157564d']::text[], 'Las plataformas toman protagonismo junto al vestido de encaje, reloj joya y Aventus for Her. El resultado es nocturno, sensual y pulido, perfecto para cóctel o celebración elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_