INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-459598ac4804', 'theoutnet', 'ton-1071994537597054', 'Pleated Brocade Mini Skirt', 'Balmain', 'clothing', 'women', 'Minifalda de brocado con plisado definido, rica en textura y con brillo contenido.', 'https://www.theoutnet.com/variants/images/1071994537597054/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1071994537597054/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1071994537597054/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1071994537597054/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1071994537597054/E/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/skirts/mini-skirts/pleated-brocade-mini-skirt/1071994537597054', 424, 560.99, 'Acompáñala con reloj pequeño, perfume oriental suave y top satinado; añade tacones negros y abrigo corto.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-fd532cd27e6e', 'mp-fe01b217f6d8', 'mp-1e7075d60425']::text[], 'La mini brocada cobra carácter con mules de patente, reloj brillante y Guilty Absolu, intenso y envolvente. Un look de noche con acento festivo, sofisticado y femenino.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-70ebe553f139', 'jomashop', 'COS-CROES33', 'Creed Royal Oud / Creed EDP Spray 3.3 oz (100 ml) (u)', 'Creed', 'perfume', 'unisex', 'Oud refinado con madera seca y fondo cálido, de presencia elegante y persistente.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-royal-oud-creed-edp-spray-33-oz-100-ml-u-3508441001121.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-royal-oud-creed-edp-spray-33-oz-100-ml-u-3508441001121.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-royal-oud-creed-edp-spray-33-oz-100-ml-u-3508441001121_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-royal-oud-creed-edp-spray-33-oz-100-ml-u-3508441001121_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/o/p/open-box-creed-royal-oud-creed-edp-spray-33-oz-100-ml-u-3508441001121.jpg?width=546&height=546', 'https://cdn2.jomashop.com/media/catalog/product/cache/0ee3019724ce73007b606b54ba535a23/c/r/creed-unisex-creed-royal-oud-edp-33-oz-tester-fragrances-t3508441001121.jpg?width=546&height=546', 'https://cdn.paris-avenues.com/image/cache/catalog/Product2/3508441001121-Creed-Royal-Oud-Edp-100-Ml-2-1000x1000w.jpg', 'https://disabellas.hn/images/items/3508441001121.jpg']::text[], 'https://www.jomashop.com/creed-fragrances-croes33-3-3oz.html', 424.99, 561.99, 'Úsalo con reloj clásico, camisa blanca y traje azul marino; acompaña con cuero negro y tonos camel.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-4af1908c0185', 'mp-6e78cd2c0e9e', 'mp-23af6e30e1cc']::text[], 'Para ti, una camisa de lino-cotón, pantalón sobrio y loafers pulidos crean una presencia discreta y refinada. Ideal para oficina o almuerzos ejecutivos; Royal Oud aporta madera seca, incienso suave y un fondo noble.', 'oficina', ARRAY['mp-e80799294eb5', 'mp-08cb860e5a5a', 'mp-904838f23367']::text[], 'Para ti, la camisa impecable, el pantalón estructurado y los loafers logran un look pulcro y sereno. Perfecto para oficina o reuniones; Royal Oud deja una estela amaderada, seca y sofisticada.', 'oficina') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-47ecabca6adc', 'jomashop', 'SE-SRPL61J1', 'Seiko Presage Automatic Light Blue Dial Watch', 'Seiko', 'watch', 'unisex', 'Reloj automático de esfera azul clara, sereno y luminoso, con elegancia diaria.', 'https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2025/04/28/21/26/SRPL61J1/SRPL61J1.png', ARRAY['https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2025/04/28/21/26/SRPL61J1/SRPL61J1.png', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-automatic-light-blue-dial-watch-srpl61j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-automatic-light-blue-dial-watch-srpl61j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-automatic-light-blue-dial-watch-srpl61j1_3.jpg', 'https://seikoboutique.com.sg/wp-content/uploads/2025/05/SRPL61J1-1000x1000.png', 'https://www.seikowatches.com/uk-en/-/media/Images/Product--Image/All/Seiko/2025/04/28/21/26/SRPL61J1/SRPL61J1_ima_2_2025.png?mh=1200&mw=1200', 'https://www.seikowatches.com/nz-en/-/media/Images/Product--Image/All/Seiko/2025/04/28/21/26/SRPL61J1/SRPL61J1_ima_1_2025.png?mh=1200&mw=1200']::text[], 'https://www.jomashop.com/seiko-presage-automatic-light-blue-dial-watch-srpl61j1.html', 425, 562.99, 'Combínalo con camisa celeste, blazer gris y perfume acuático limpio; completa con pantalón de lana y loafers.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-4af1908c0185', 'mp-94a0cc171f7c', 'mp-3d7ec08426d5']::text[], 'Para ti, la camisa clara, el pantalón de caída limpia y los monk straps equilibran sobriedad y presencia. Ideal para oficina; el reloj azul añade frescura elegante, sin exceso, con un aire muy contemporáneo.', 'oficina', ARRAY['mp-e49d2abf765f', 'mp-08cb860e5a5a', 'mp-70ebe553f139']::text[], 'Para ti, el blazer de lana, el pantalón texturizado y los loafers construyen una silueta pulida y segura. Perfecto para oficina; el reloj azul suma luz y modernidad, sin perder discreción.', 'oficina') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5974d3fa2bbe', 'theoutnet', 'ton-46376663163009036', 'Cam Suede Platform Sandals', 'Balmain', 'shoes', 'women', 'Sandalias de plataforma en gamuza, sensuales y limpias, para una entrada segura.', 'https://www.theoutnet.com/variants/images/46376663163009036/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163009036/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163009036/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163009036/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163009036/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163009036/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/sandals/high-heel-sandals/cam-suede-platform-sandals/46376663163009036', 425, 562.99, 'Combínalas con reloj metálico fino, perfume floral cálido y vestido fluido o sastre claro en beige.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-035e4ccec884', 'mp-a74b23068c3b', 'mp-6a517157564d']::text[], 'Las sandalias elevan el vestido de encaje con un aire de gala estival; el reloj champagne suma brillo discreto y Aventus for Her añade frescura frutal-amaderada. Ideal para noche de verano.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-cc23be33120b', 'theoutnet', 'ton-46376663163148366', 'Dover Color Block Leather And Suede Sneakers', 'Paul Smith', 'shoes', 'men', 'Zapatillas de cuero y gamuza con bloques de color, equilibradas y contemporáneas.', 'https://www.theoutnet.com/variants/images/46376663163148366/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163148366/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148366/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148366/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148366/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148366/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/paul-smith/sneakers/fashion-sneakers/dover-color-block-leather-and-suede-sneakers/46376663163148366', 425, 562.99, 'Llévalas con reloj minimalista, perfume fresco y pantalón recto con camiseta premium o sobrecamisa neutra.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-16dc129ea1db', 'mp-1ca1ac0a3d89', 'mp-605a39d82c0f']::text[], 'Sneakers con overshirt de lino, polo waffle y Seastar azul crean un casual refinado. Funciona para viaje, almuerzo o ciudad, con equilibrio entre comodidad, textura y un toque náutico.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.