INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3e841bb339fb', 'jomashop', 'TIST1208522205100', 'Tissot Seastar 1000 Quartz GMT Black Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Reloj GMT de dos tonos con diseño robusto, preparado para viaje y uso activo.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf8433270/product-pictures/212f7c68-7add-4b70-96fd-f152d3dcc78f_T120-852-22-051-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf8433270/product-pictures/212f7c68-7add-4b70-96fd-f152d3dcc78f_T120-852-22-051-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf8433270/product-pictures/212f7c68-7add-4b70-96fd-f152d3dcc78f_T120-852-22-051-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw2c031919/product-pictures/b2af07a1-1ef3-4c52-b568-331c4de3c422_T120-852-22-051-00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw2559fd84/product-pictures/a21007cb-d576-4d4f-8ffe-377cdbf09f19_T120-852-22-051-00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwfe1d73a6/product-pictures/a343f60a-bb08-40ca-a237-25c4ebdaa933_T120-852-22-051-00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw8c668b4d/product-pictures/794ea5f7-0404-422f-a407-0cb41d56afcb_T120-852-22-051-00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-quartz-gmt-black-dial-mens-watch-t1208522205100-t1208522205100.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-1000-quartz-gmt-black-dial-mens-watch-t1208522205100.html', 426, 563.99, 'Combínalo con polo técnico, perfume fresco y chaqueta ligera; completa con jeans oscuros y zapatillas negras.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-a47f229935b7', 'mp-6e78cd2c0e9e', 'mp-21708b443c49']::text[], 'El Seastar GMT acompaña pantalón limpio, loafers deportivos y Acqua Di Gio Profondo, acuático y mineral. Conjunto versátil para días activos, viajes o fines de semana con elegancia relajada.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-fd532cd27e6e', 'theoutnet', 'ton-46376663163152658', 'Barret Embellished Patent Leather Mules', 'Versace', 'shoes', 'women', 'Mules de charol con brillo controlado, pensadas para una silueta audaz y elegante.', 'https://www.theoutnet.com/variants/images/46376663163152658/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163152658/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163152658/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163152658/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163152658/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163152658/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/sandals/mid-heel-sandals/barret-embellished-patent-leather-mules/46376663163152658', 427, 564.99, 'Combínalos con reloj pulido, perfume opulento y vestido negro o sastrería satinada en tonos profundos.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-035e4ccec884', 'mp-fe01b217f6d8', 'mp-58072ada40a0']::text[], 'Los mules patentados se integran con el vestido de satén y encaje, reloj brillante y Tuscan Leather, cálido y especiado. Un look de noche sofisticado, con carácter y sensualidad controlada.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, r