INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d2bb59cdfa69', 'jomashop', 'CZJY8035-04E', 'Citizen Promaster Navihawk A-T Eco Drive Black Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Reloj aeronáutico con dial negro y energía funcional, preciso y listo para ritmo dinámico.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-navihawk-a-t-eco-drive-black-dial-mens-watch-jy8035-04e.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-navihawk-a-t-eco-drive-black-dial-mens-watch-jy8035-04e.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-navihawk-a-t-eco-drive-black-dial-mens-watch-jy8035-04e_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-navihawk-a-t-eco-drive-black-dial-mens-watch-jy8035-04e_3.jpg']::text[], 'https://www.jomashop.com/citizen-watch-jy8035-04e.html', 431.04, 569.99, 'Combínalo con chaqueta técnica, perfume cítrico y pantalón cargo oscuro; completa con botas o sneakers negras.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-cc23be33120b', 'mp-60727c51909d', 'mp-015d339460d4']::text[], 'Para ti, el polo de punto, las sneakers color block y Sauvage forman un look activo pero cuidado. Funciona para fin de semana o viaje; el perfume es fresco, aromático y vibrante, con aire marino.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1ca1ac0a3d89', 'jomashop', 'TIST1204171704100', 'Tissot Seastar 1000 Chronograph Blue Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Cronógrafo Seastar en azul profundo, con presencia marina y líneas precisas para uso diario refinado.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw4696d429/product-pictures/560259c8-0395-451b-9033-d8062e7f1950_T120-417-17-041-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw4696d429/product-pictures/560259c8-0395-451b-9033-d8062e7f1950_T120-417-17-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw4696d429/product-pictures/560259c8-0395-451b-9033-d8062e7f1950_T120-417-17-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw65421b89/product-pictures/4f6c838d-8a59-40da-b653-57d74cf1dc3e_T120_417_17_041_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw075cf385/product-pictures/087c6259-f715-44fe-a180-783528449c67_T120_417_17_041_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw5766803e/product-pictures/9909adfd-89ef-42c8-9e0d-57a631033e8e_T120_417_17_041_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw3a113f2c/product-pictures/361878a8-6c77-4d8e-9d07-603dce140ac4_T120-417-17-041-00_AMB_1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwaf961eea/product-pictures/0e1d82b2-b524-4533-934e-cc4591f40160_T120_417_17_041_00.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-watch-t120-417-17-041-00.html', 432, 570.99, 'Llévalo con camisa blanca, pantalón marino y mocasines de cuero; perfume acuático, reloj acero azul complementario.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-1e2e2d2f0407', 'mp-6e78cd2c0e9e', 'mp-605a39d82c0f']::text[], 'Para ti, el polo waffle, el pantalón de lino y los loafers equilibran comodidad y estilo limpio. Ideal para casual urbano; el Seastar suma carácter deportivo, mientras el conjunto mantiene un lujo silencioso.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f915c06f7309', 'jomashop', 'TIST1204101701100', 'Tissot Seastar 1000 Wilson WNBA Quartz White Dial Unisex Watch', 'Tissot', 'watch', 'unisex', 'Seastar blanco y versátil, con estética limpia unisex y espíritu náutico contemporáneo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-wilson-wnba-quartz-white-dial-unisex-watch-t1204101701100.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-wilson-wnba-quartz-white-dial-unisex-watch-t1204101701100.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-wilson-wnba-quartz-white-dial-unisex-watch-t1204101701100_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-wilson-wnba-quartz-white-dial-unisex-watch-t1204101701100_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-wilson-wnba-quartz-white-dial-unisex-watch-t1204101701100_6.jpg', 'https://media.1815.io/yourwatchhub/i/width=2048&height=2048/2024/04/tissot-seastart-1000-wilson-wnba-quartz-ref-T120-410-17-011-00-white-strap.jpg', 'https://cdn11.bigcommerce.com/s-28d61/products/15417/images/151530/tissot-watches-tissot-seastar-wilson-wnba-quartz-40mm-unisex-watch-t120.410.17.011.00__31511.1735673614.1280.1280.jpg?c=2', 'https://media.1815.io/yourwatchhub/i/width=1080&height=1080/2024/04/tissot-seastart-1000-wilson-wnba-quartz-ref-T120-410-17-011-00-side.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-1000-wilson-wnba-quartz-white-dial-unisex-watch-t1204101701100.html', 432, 570.99, 'Combínalo con polo crudo, denim oscuro y zapatillas minimalistas; perfume fresco, tonos arena y acero pulido.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-1e2e2d2f0407', 'mp-a2717c731232', 'mp-605a39d82c0f']::text[], 'Para ti, el polo texturizado, el pantalón relajado y las sneakers crean un conjunto ágil y moderno. Perfecto para fin de semana o viaje; el reloj blanco refuerza el aire sport con elegancia limpia.', 'deportivo', ARRAY['mp-cf73e236b136', 'mp-a817148e69da', 'mp-60727c51909d']::text[], 'Para ti, el vestido de punto con jeans y sneakers equilibra comodidad y actitud moderna. Ideal para casual de día; el reloj blanco aporta frescura y un gesto deportivo, discreto y actual.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1214c6cfd09f', 'jomashop', 'TIST1202171106100', 'Tissot Seastar 1000 Chronograph Quartz Watch', 'Tissot', 'watch', 'unisex', 'Seastar negro de carácter técnico, pensado para un estilo firme y discreto.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw7d0cc3be/product-pictures/ee79c60c-4bdb-400d-ae6f-edb89cbafdc9_T120-217-11-061-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw7d0cc3be/product-pictures/ee79c60c-4bdb-400d-ae6f-edb89cbafdc9_T120-217-11-061-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw7d0cc3be/product-pictures/ee79c60c-4bdb-400d-ae6f-edb89cbafdc9_T120-217-11-061-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw4b97f956/product-pictures/ab17698d-d07e-41e7-a658-786febfb961e_T120-217-11-061-00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwda1f7e7d/product-pictures/0ee574c8-5229-4f34-a5c5-640c3a3de326_T120-217-11-061-00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1f369b42/product-pictures/66eb33ce-ba06-438f-89c7-c6cd1e19ccf2_T120-217-11-061-00_DETAIL-1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw5964d133/product-pictures/6da1e325-a217-4438-adc4-ea9a773d10f6_T120-217-11-061-00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-chronograph-quartz-watch-t1202171106100.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-1000-chronograph-quartz-watch-t1202171106100.html', 432, 570.99, 'Úsalo con camiseta negra, sobrecamisa gris y sneakers de piel; perfume amaderado, acentos grafito y acero.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-1e2e2d2f0407', 'mp-6e78cd2c0e9e', 'mp-605a39d82c0f']::text[], 'Para ti, el polo waffle, el pantalón ligero y los loafers crean un look relajado, limpio y muy versátil. Perfecto para fin de semana; el reloj aporta un acento náutico sin perder elegancia.', 'casual', ARRAY['mp-cf73e236b136', 'mp-63e949f58a3a', 'mp-60727c51909d']::text[], 'Para ti, el mini vestido de punto, los jeans y los mules crean un contraste chic y cómodo. Ideal para día libre; el reloj añade energía deportiva con un acabado refinado.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c64b5faa244b', 'theoutnet', 'ton-46376663163085653', 'Torris Embellished Leather Knee Boots', 'Ferragamo', 'shoes', 'women', 'Botas altas en cuero con ornamento preciso, pensadas para destacar con elegancia.', 'https://www.theoutnet.com/variants/images/46376663163085653/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163085653/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163085653/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163085653/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163085653/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163085653/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/boots/tall-boots/torris-embellished-leather-knee-boots/46376663163085653', 434, 573.99, 'Lúcelas con reloj joya, vestido negro estructurado y abrigo largo; perfume ámbar, tonos chocolate y oro viejo.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-035e4ccec884', 'mp-bed33a85d2ac', 'mp-1e7075d60425']::text[], 'Para ti, el vestido de encaje, el reloj de esfera clara y el perfume convierten los boots en un acento potente y elegante. Ideal para noche; la fragancia es dulce-floral, cálida y sofisticada.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image,