INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1fcb548dde4f', 'jomashop', 'CZBJ8055-04X', 'Citizen Promaster Green Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Promaster verde con aire aventurero y presencia robusta para días activos.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-green-dial-mens-watch-bj805504x_1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-green-dial-mens-watch-bj805504x_1.jpg', 'https://shop.repairtjc.com/cdn/shop/files/BJ8055-04X_0fade701-a6f4-4275-af05-81ca996b20e4.jpg?v=1737135529', 'https://starbuy.com.au/cdn/shop/files/citizen-promaster-48mm-bj8055-04x-6954057.jpg?v=1758585125&width=1280', 'https://cdn.watchcharts.com/listings/4ff36f96-0855-4267-bf88-b22e2580346e.png?d=600x600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-green-dial-mens-watch-bj805504x_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-green-dial-mens-watch-bj805504x_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-green-dial-mens-watch-bj805504x_4.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-green-dial-mens-watch-bj8055-04x.html', 435.84, 575.99, 'Combínalo con chaqueta técnica, pantalón beige y botas urbanas; perfume verde fresco, detalles oliva y acero.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-1e2e2d2f0407', 'mp-cc23be33120b', 'mp-6a32aace5e0a']::text[], 'Para ti, el polo de punto, las sneakers limpias y Neroli Sauvage construyen un look fresco y distinguido. Perfecto para fin de semana o clima cálido; el perfume es cítrico, verde y luminoso.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-abdb0743cd4b', 'theoutnet', 'ton-46376663163149352', 'Padlock Velvet Platform Pumps', 'Tom Ford', 'shoes', 'women', 'Tacones de terciopelo con presencia dramática, perfectos para vestir con sofisticación nocturna.', 'https://www.theoutnet.com/variants/images/46376663163149352/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163149352/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163149352/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163149352/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163149352/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163149352/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/pumps/high-heel-pumps/padlock-velvet-platform-pumps/46376663163149352', 436, 575.99, 'Acompáñalos con reloj joya discreto, perfume especiado y vestido oscuro o traje de velour.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-035e4ccec884', 'mp-87a3ff47cf1a', 'mp-b2bac3c4aeeb']::text[], 'Un vestido de satén con encaje y un reloj joya elevan estos pumps de terciopelo para una gala o cóctel nocturno. Royal Princess Oud aporta un halo opulento, amaderado y resinous, muy acorde al dramatismo elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-eaf715c73fbf', 'jomashop', 'TIST1202173706100', 'Tissot Seastar Chronograph Quartz Grey Gradient Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Cronógrafo gris degradado con perfil técnico y equilibrio sobrio.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb89bd4ff/product-pictures/32194017-2709-4f38-a89d-fb6af19b9392_T120-217-37-061-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb89bd4ff/product-pictures/32194017-2709-4f38-a89d-fb6af19b9392_T120-217-37-061-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb89bd4ff/product-pictures/32194017-2709-4f38-a89d-fb6af19b9392_T120-217-37-061-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw03037977/product-pictures/5dbd8890-44e1-4d16-ae94-7f424b1616d7_T120-217-37-061-00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw3eb257a9/product-pictures/712081e1-a1a6-41ea-a984-09abe00a46ce_T120-217-37-061-00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw7a6e7ca9/product-pictures/98e80354-51b7-4a65-b098-bfa14cf0e8cb_T120-217-37-061-00_DETAIL-1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw95015500/product-pictures/b8481008-463e-4c0b-b642-f71e600de56d_T120-217-37-061-00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-chronograph-quartz-grey-gradient-dial-mens-watch-t1202173706100.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-chronograph-quartz-grey-gradient-dial-mens-watch-t1202173706100.html', 438, 578.99, 'Combínalo con camisa celeste, pantalón carbón y zapatillas blancas; perfume cítrico, acero mate y líneas limpias.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-f60964fd1e13', 'mp-cc23be33120b', 'mp-21708b443c49']::text[], 'Para ti, el pantalón ligero, las sneakers y Acqua di Giò Profondo acompañan el reloj con un aire técnico y pulcro. Ideal para día activo; el perfume es marino, fresco y elegante, muy versátil.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
