ds, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e6400fa67091', 'theoutnet', 'ton-46376663163085074', 'Cayla Leather Sandals', 'Ferragamo', 'shoes', 'women', 'Sandalias de cuero con silueta limpia y gracia natural para días cálidos.', 'https://www.theoutnet.com/variants/images/46376663163085074/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163085074/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163085074/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163085074/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163085074/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163085074/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/sandals/mid-heel-sandals/cayla-leather-sandals/46376663163085074', 438, 578.99, 'Combínalas con reloj delgado, vestido lino color crema y bolso trenzado; perfume floral fresco y tonos arena.', 'https://www.styleatacertainage.com/wp-content/uploads/2025/06/Quince-Linen-Picks.png', ARRAY['mp-6fb5e0292d27', 'mp-0c70d2a8c8be', 'mp-907d601e36bb']::text[], 'El vestido asimétrico y el reloj nácar equilibran el brillo de estas sandalias para una cena o evento nocturno. Royal Princess Oud aporta un perfume opulento, ambarado y ligeramente ahumado.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_id