INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a2717c731232', 'theoutnet', 'ton-46376663163162512', 'ld 1000 Leather And Brushed Suede Trimmed Mesh Sneakers', 'Nike', 'shoes', 'men', 'Sneakers de inspiración retro con mezcla textil, cómodas y versátiles para el día.', 'https://www.theoutnet.com/variants/images/46376663163162512/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163162512/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163162512/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163162512/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163162512/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163162512/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/nike/sneakers/fashion-sneakers/ld-1000-leather-and-brushed-suede-trimmed-mesh-sneakers/46376663163162512', 439, 579.99, 'Úsalas con reloj deportivo limpio, perfume cítrico y jogger sobrio o denim oscuro con camiseta blanca.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-f60964fd1e13', 'mp-21708b443c49', 'mp-eaf715c73fbf']::text[], 'Para un look casual con aire pulido, el pantalón claro y el polo texturizado equilibran tus sneakers; Acqua di Giò Profondo refuerza la frescura marina y limpia, ideal para ciudad, viajes o fines de semana con estilo.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-23af6e30e1cc', 'jomashop', 'SE-SRPL07J1', 'Seiko Presage Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Presage azul con carátula serena y detalle japonés de gran sobriedad.', 'https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2024/04/16/21/17/SRPL07J1/SRPL07J1.png', ARRAY['https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2024/04/16/21/17/SRPL07J1/SRPL07J1.png', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-automatic-blue-dial-mens-watch-srpl07j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-automatic-blue-dial-mens-watch-srpl07j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-automatic-blue-dial-mens-watch-srpl07j1_3.jpg', 'https://www.watchportal.com.ph/cdn/shop/files/seiko-presage-srpl07j1-automatic-watch-watchportal-ph-3.jpg?v=1717726021&width=994', 'https://timeaccess-store.com/cdn/shop/files/SRPL07J1fw.webp?v=1723194647&width=1000']::text[], 'https://www.jomashop.com/seiko-presage-automatic-blue-dial-mens-watch-srpl07j1.html', 440.06, 580.99, 'Úsalo con traje azul tinta, camisa blanca y derbies marrón oscuro; perfume amaderado limpio.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-2ad272892924', 'mp-94a0cc171f7c', 'mp-cf2b71c1d9e8']::text[], 'Para oficina y reuniones, la camisa de lino y los monk strap sostienen la elegancia del Presage azul; Mefisto suma una frescura cítrica y limpia, sofisticada pero discreta, perfecta para un entorno profesional en Lima.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-904838f23367', 'jomashop', 'SE-SRPL63J1', 'Seiko Presage Automatic Ladies Light Green Dial Watch', 'Seiko', 'watch', 'women', 'Presage en verde claro, delicado y luminoso, con elegancia japonesa.', 'https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2025/04/28/21/28/SRPL63J1/SRPL63J1.png', ARRAY['https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2025/04/28/21/28/SRPL63J1/SRPL63J1.png', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-automatic-ladies-light-green-dial-watch-srpl63j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-automatic-ladies-light-green-dial-watch-srpl63j1_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-automatic-ladies-light-green-dial-watch-srpl63j1_2.jpg', 'https://www.seikowatches.com/au-en/-/media/Images/Product--Image/All/Seiko/2025/04/28/21/28/SRPL63J1/SRPL63J1.png?mh=1200&mw=1200', 'https://www.seikowatches.com/be-fr/-/media/Images/Product--Image/All/Seiko/2025/04/28/21/28/SRPL63J1/SRPL63J1_ima_2_2025.png?mh=1200&mw=1200', 'https://www.seikowatches.com/ph-en/-/media/Images/Product--Image/All/Seiko/2025/04/28/21/28/SRPL63J1/SRPL63J1_ima_3_2025.png?mh=1200&mw=1200']::text[], 'https://www.jomashop.com/seiko-presage-automatic-ladies-light-green-dial-watch-srpl63j1.html', 440, 580.99, 'Acompáñalo con reloj fino, blusa marfil y falda lápiz beige; perfume floral verde y accesorios dorados.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-52c3e350cbd1', 'mp-08cb860e5a5a', 'mp-db3e96bd55d9']::text[], 'El reloj verde luce impecable con pantalón crema y loafers; es un conjunto sereno para oficina en clima cálido. Love In White aporta un perfil floral limpio, elegante y luminoso.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-42a3fdb1f99b', 'jomashop', 'CZJY8084-09H', 'Citizen Promaster Skyhawk A-T Perpetual Alarm World Time Chronograph Men''s Watch', 'Citizen', 'watch', 'men', 'Skyhawk funcional y preciso, con lectura aérea y carácter contemporáneo.', 'https://citizenwatch.widen.net/content/dsxazebu5h/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/dsxazebu5h/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/f4defpicqd/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/izorouwp85/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/odeapwy2up/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-perpetual-alarm-world-time-chronograph-mens-watch-jy808409h_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-perpetual-alarm-world-time-chronograph-mens-watch-jy808409h_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-perpetual-alarm-world-time-chronograph-mens-watch-jy808409h_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-skyhawk-a-t-perpetual-alarm-world-time-chronograph-mens-watch-jy8084-09h.html', 440.64, 581.99, 'Combínalo con chaqueta técnica, pantalón cargo oscuro y botas utilitarias; perfume fresco, gris y azul acero.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-44c11d07801c', 'mp-60727c51909d']::text[], 'Para un día activo con estilo, el tee minimalista y las Dunk Low acompañan tu reloj técnico; Sauvage aporta una salida aromática fresca y especiada, enérgica y masculina, ideal para ritmo urbano o escapadas de fin de semana.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
