&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-chronograph-quartz-black-dial-mens-watch-t1204171705103-t1204171705103.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-1000-chronograph-quartz-black-dial-mens-watch-t120-417-17-051-03.html', 443.04, 584.99, 'Llévalo con polo negro, jean índigo y sneakers de cuero; perfume especiado suave, tonos carbón y plata.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-a47f229935b7', 'mp-cc23be33120b', 'mp-8d5bb353d59a']::text[], 'Para un casual refinado, el pantalón estructurado y las sneakers de Paul Smith equilibran la fuerza del Seastar; Neroli Portofino aporta un cítrico limpio y luminoso, perfecto para clima templado y una presencia relajada pero precisa.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
