INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c0f035a50894', 'theoutnet', 'ton-1647597301343184', 'Herringbone Cotton Tweed Tapered Pants', 'Maison Margiela', 'clothing', 'women', 'Pantalón herringbone de corte afinado, sobrio y muy bien resuelto.', 'https://www.theoutnet.com/variants/images/1647597301343184/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597301343184/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597301343184/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597301343184/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597301343184/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597301343184/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/maison-margiela/pants/tapered-pants/herringbone-cotton-tweed-tapered-pants/1647597301343184', 445, 586.99, 'Llévalo con reloj clásico, camisa celeste y loafers negros; perfume amaderado limpio, gris y camel.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-c984312e403f', 'mp-904838f23367', 'mp-13b71b592183']::text[], 'El pantalón herringbone se ve más ligero con pumps nude y un reloj verde suave, ideal para oficina en verano. Acqua Fiorentina aporta un floral afrutado, delicado y luminoso.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspi