INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4bff8a06f8bc', 'theoutnet', 'ton-46376663163015303', 'Cass 95 Embossed Leather And Pvc Pumps', 'Jimmy Choo', 'shoes', 'women', 'Pumps Jimmy Choo con brillo transparente y contraste contemporáneo.', 'https://www.theoutnet.com/variants/images/46376663163015303/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163015303/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015303/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015303/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015303/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015303/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/pumps/high-heel-pumps/cass-95-embossed-leather-and-pvc-pumps/46376663163015303', 446, 587.99, 'Acompáñalos con reloj joya, vestido midi negro y clutch satinado; perfume ámbar suave, plata y negro.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-6fb5e0292d27', 'mp-fe01b217f6d8', 'mp-fa38caa36f41']::text[], 'El midi dress estructurado y el reloj con diamantes realzan la geometría de estos pumps para una cena formal. Cuir Zerzura aporta un cuero refinado, especiado y muy elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, rec