INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0cf3b002ce9d', 'theoutnet', 'ton-1647597335086163', 'Rockstud Leather Ankle Boots', 'Valentino', 'shoes', 'women', 'Botines con tachuelas icónicas y carácter firme, para un estilo decidido y pulido.', 'https://www.theoutnet.com/variants/images/1647597335086163/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597335086163/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597335086163/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597335086163/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597335086163/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597335086163/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/valentino-garavani/boots/ankle-boots/rockstud-leather-ankle-boots/1647597335086163', 449, 591.99, 'Llévalos con reloj oscuro, perfume cuero-especiado y abrigo negro con denim crudo o sastre entallado.', 'https://threadcurve.com/wp-content/uploads/2025/11/statement-coat-layered-winter-outfit.jpeg', ARRAY['mp-c0f8dd83b8a6', 'mp-87c1eb6527f0', 'mp-81d52947c289']::text[], 'Los botines Rockstud elevan el mini dress con brillo moderno y la delicadeza del reloj mantiene el balance refinado. Ideal para cena o salida nocturna; Dama Bianca aporta un halo limpio, almizclado y cremoso, muy elegante.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=E