c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-ef6b916a5f31', 'mp-94a0cc171f7c', 'mp-a7fbae0e4ca7']::text[], 'Para una noche de impacto, la camisa satinada y los loafers de monograma acompañan el perfume con precisión; el PRX champagne suma brillo sobrio, mientras el aroma es amaderado, almizclado y cremosa-vainilla, muy seductor.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
