INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-169aade8e57a', 'theoutnet', 'ton-46376663163153901', 'Darsyl Suede Sneakers', 'Bally', 'shoes', 'men', 'Sneakers de gamuza con silueta limpia, cómodas y fáciles de integrar con estilo.', 'https://www.theoutnet.com/variants/images/46376663163153901/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163153901/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153901/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153901/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153901/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153901/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/sneakers/fashion-sneakers/darsyl-suede-sneakers/46376663163153901', 457, 601.99, 'Úsalas con reloj minimalista, perfume fresco y pantalón recto con sudadera premium o camisa ligera.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-f60964fd1e13', 'mp-6a32aace5e0a', 'mp-2767053fa91f']::text[], 'Pantalón fluido, polo texturizado y un perfume cítrico-nerolí elevan las sneakers sin esfuerzo; ideal para verano urbano, con una elegancia discreta y muy cuidada.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note,