2.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw680c1c1c/product-pictures/21c0659e-6cd6-4839-8751-a7399a204223_T120-417-11-091-01_AMB_3.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-seastar-chronograph-quartz-green-dial-mens-watch-t120-417-11-091-01.html', 460.08, 605.99, 'Combínalo con camiseta blanca, chaqueta navy, pantalón chino gris y sneakers sobrios.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-94e22572660d', 'mp-21708b443c49', 'mp-169aade8e57a']::text[], 'Track pants, polo de punto y un perfume marino-intenso acompañan su tono verde; conjunto ligero para clima cálido o escapadas, con energía deportiva y refinada.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
