INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-fe01b217f6d8', 'jomashop', 'SE-SRE009J1', 'Seiko Presage Cocktail Automatic Diamond White Dial Ladies Watch', 'Seiko', 'watch', 'women', 'Reloj femenino con esfera nacarada y destellos sutiles de diamante.', 'https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2022/12/14/11/47/SRE009J1/SRE009J1.png', ARRAY['https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2022/12/14/11/47/SRE009J1/SRE009J1.png', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-cocktail-automatic-diamond-white-dial-ladies-watch-sre009j1_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-cocktail-automatic-diamond-white-dial-ladies-watch-sre009j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-cocktail-automatic-diamond-white-dial-ladies-watch-sre009j1_3.jpg', 'https://www.zetamarket.com/wp-content/uploads/2023/08/SRE009J1.jpg', 'https://www.watchportal.com.ph/cdn/shop/files/seiko-sre009j1-presage-cocktail-time-skydiving-automatic-watch-for-women-watchportal-ph-2.jpg?v=1706061976&width=1000']::text[], 'https://www.jomashop.com/seiko-presage-cocktail-automatic-diamond-white-dial-ladies-watch-sre009j1.html', 465, 611.99, 'Combínalo con blusa marfil, falda plisada y perfume floral suave; zapatos nude.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-eccea3334d40', 'mp-63e949f58a3a', 'mp-6becc442eecf']::text[], 'Vestido midi fluido, mules pulidos y un perfume floral limpio acompañan el reloj con delicadeza; una propuesta elegante para oficina creativa o almuerzo especial.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-635288165406', 'jomashop', 'Z-R7E96', 'Xerjoff V Purple Accento by Xerjoff Eau de Parfum Spray 3.4 oz', 'Xerjoff', 'perfume', 'unisex', 'Perfume de estela envolvente, frutal y luminosa con carácter sofisticado.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-purple-accento-by-xerjoff-eau-de-parfum-spray-34-oz-8033488156404.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/x/e/xerjoff-purple-accento-by-xerjoff-eau-de-parfum-spray-34-oz-8033488156404.jpg', 'https://cdn.notinoimg.com/detail_main_hq/xerjoff/8033488156404_02-o/purple-accento___240530.jpg', 'https://cdn.notinoimg.com/detail_main_mq/xerjoff/8033488156404_01-o/xerjoff-purple-accento-eau-de-parfum-unisex___240530.jpg', 'https://www.bluesalon.com/cdn/shop/products/ucm3p3nz.wi5_IMG_01_8033488156404.jpg?v=1655885156', 'https://cdn.notinoimg.com/social/xerjoff/8033488156404_01-o/xerjoff-purple-accento-eau-de-parfum-unisex___240530.jpg']::text[], 'https://www.jomashop.com/xerjoff-purple-accento-by-xerjoff-eau-de-parfum-spray-3-4-oz-8033488156404.html', 465, 611.99, 'Llévalo con vestido negro, reloj de oro rosa y tacones finos en terciopelo.', 'https://i.pinimg.com/564x/3e/9b/44/3e9b44c4645f54291038976ad084b4b7.jpg', ARRAY['mp-a3c07033dec1', 'mp-f3cd717d3b87', 'mp-1f0254abf485']::text[], 'Para una noche elegante, el polo de mezcla silk-cotton y los loafers de velour sostienen el carácter del perfume; el Seastar 1000 aporta contraste deportivo, mientras la fragancia vibra entre frutas, especias y maderas oscuras.', 'noche', ARRAY['mp-422280d9eeaa', 'mp-60d70092570a', 'mp-76d7d1376454']::text[], 'Para una noche elegante, el vestido de terciopelo abraza la silueta y los pumps elevan el conjunto; el PRX ice blue añade luz refinada, mientras el perfume se siente frutal, floral y ambarado, sofisticado y muy femenino.', 'noche') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d989491a5eb9', 'theoutnet', 'ton-46376663163153913', 'Darnell Suede Trimmed Stretch Knit Sneakers', 'Bally', 'shoes', 'men', 'Sneakers de punto con gamuza, ligeras y versátiles para un ritmo urbano pulcro.', 'https://www.theoutnet.com/variants/images/46376663163153913/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163153913/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153913/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153913/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153913/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153913/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/sneakers/fashion-sneakers/darnell-suede-trimmed-stretch-knit-sneakers/46376663163153913', 465, 611.99, 'Combínalas con reloj deportivo sobrio, perfume limpio y pantalón tapered con polo o sobrecamisa neutra.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-a47f229935b7', 'mp-4a3f893e3d09', 'mp-6a32aace5e0a']::text[], 'Pantalón estructurado, reloj deportivo y un perfume cítrico-nervioso equilibran las sneakers con lujo discreto; ideal para ciudad, viajes o fines de semana de clima templado.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
