sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-chronograph-quartz-blue-dial-mens-watch-t1204171104103-t1204171104103.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-chronograph-quartz-blue-dial-mens-watch-t120-417-11-041-03.html', 466.56, 613.99, 'Acompáñalo con camisa Oxford, denim oscuro, zapatillas blancas y chaqueta ligera.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-94e22572660d', 'mp-169aade8e57a', 'mp-0e1d44d63a68']::text[], 'Jogger técnico, sneakers de suede y un perfume marino limpio refuerzan la energía del cronógrafo; perfecto para escapadas o días activos, con un toque muy actual.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7dd70e1e976e', 'jomashop', 'TIST1202173704100', 'Tissot Seastar Chronograph Quartz Turquoise Dial Watch', 'Tissot', 'watch', 'unisex', 'Reloj turquesa con presencia fresca y perfil deportivo muy actual.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwcabcce40/product-pictures/7cdff26a-84dc-4817-93e3-e557e752b9bc_T120-217-37-041-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwcabcce40/product-pictures/7cdff26a-84dc-4817-93e3-e557e752b9bc_T120-217-37-041-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://cdn11.bigcommerce.com/s-28d61/images/stencil/1280x1280/products/16483/173686/tissot-watches-tissot-seastar-1000-quartz-chronograph-38mm-turquoise-dial-mens-watch-t120.217.37.041.00__92760.1763098649.jpg?c=2', 'https://images.firstclasswatches.co.uk/87zvZTdzHwIxpSix_ZnFW8nr9gdIw1oedzZN-xfGDFE/rs:fit:0:1000/bg:fffcfa/bG9jYWw6Ly8vaW1hZ2VzL3Byb2R1Y3RzL3Byb2R1Y3QxNzIwODAtMzgxMl9jcm9wcGVkLnBuZw.jpg', 'https://content.thewosgroup.com/productimage/17361878/17361878_3.jpg?impolicy=zoom', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwcabcce40/product-pictures/7cdff26a-84dc-4817-93e3-e557e752b9bc_T120-217-37-041-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe2f8fd82/product-pictures/eb8f7923-ab3b-4011-b5ad-26d4ebe27c80_T120-217-37-041-00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwa6c340c0/product-pictures/2fa44879-c074-4de6-8729-42f5fdd22e07_T120-217-37-041-00_B1.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-seastar-chronograph-quartz-turquoise-dial-watch-t1202173704100.html', 468, 615.99, 'Combínalo con polo gris, bermudas de sarga, sneakers blancas y perfume acuático.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-f63eb8828e5a', 'mp-2abd9b8ccfe5', 'mp-c3c82fdede97']::text[], 'Para un look deportivo con pulso urbano, el hoodie técnico y las sneakers sostienen tu Seastar turquesa; Sauvage EDP aporta una frescura especiada y amaderada, energizante, ideal para salidas activas y clima cálido.', 'deportivo', ARRAY['mp-e80799294eb5', 'mp-c3eaa0c6b09e', 'mp-8498b52f4f24']::text[], 'Para un casual chic, la camisa popelín y las sneakers mixtas acompañan el reloj turquesa con modernidad; Elle suma flores suaves y maderas limpias, perfecta para un día relajado con aire fresco y femenino.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
