o_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a873dd2e9058', 'jomashop', 'CZBN2038-01L', 'Citizen Promaster Eco-Drive Blue Dial Pepsi Bezel Men''s Watch', 'Citizen', 'watch', 'men', 'Reloj de buceo con energía técnica y contraste azul muy limpio.', 'https://citizenwatch.widen.net/content/stfawtzzh8/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/stfawtzzh8/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/vlwgpmzpvk/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/cnwtofjnmp/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/odeapwy2up/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-ecodrive-blue-dial-pepsi-bezel-mens-watch-bn203801l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-ecodrive-blue-dial-pepsi-bezel-mens-watch-bn203801l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-ecodrive-blue-dial-pepsi-bezel-mens-watch-bn203801l_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-blue-dial-mens-watch-bn2038-01l.html', 469.44, 616.99, 'Combínalo con camiseta piqué, pantalón caqui, sneakers marinas y fragancia cítrica.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-44c11d07801c', 'mp-60727c51909d']::text[], 'Para hombre, un conjunto limpio y activo: camiseta esencial, sneakers de perfil urbano y Sauvage para un aura fresca, especiada y masculina. Ideal para fin de semana, viajes cortos o un look relajado con carácter.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3028d7208724', 'jomashop', 'TIST1204171105100', 'Tissot Seastar 1000 Chronograph Quartz Men''s Watch', 'Tissot', 'watch', 'men', 'Cronógrafo de buceo con caja sólida y carácter deportivo sobrio.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe13ff87d/product-pictures/bd22167b-1fb9-4fca-80de-5c715c11ab28_T120-417-11-051-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe13ff87d/product-pictures/bd22167b-1fb9-4fca-80de-5c715c11ab28_T120-417-11-051-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://mzwatcheslk.com/cdn/shop/products/watch-chronograph-man-tissot-t-sport-t1204171105100_415580_1080x1080.jpg?v=1660668511', 'https://cdn.clothbase.com/uploads/3005006d-ab1f-4d7d-a4a2-efa2c8665658/cbqezbohspudcjof7f2j.jpg', 'https://shop.joieriarovira.com/9443-thickbox_default/tissot-seastar-1000-quartz-chronograph-watch-black-dial-t1204171105100.jpg', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe13ff87d/product-pictures/bd22167b-1fb9-4fca-80de-5c715c11ab28_T120-417-11-051-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwc112023f/product-pictures/54d789ca-0bc9-48a3-88eb-c574f5ad1b7f_T120_417_11_051_00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-chronograph-quartz-mens-watch-t1204171105100.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-1000-watch-t1204171105100.html', 469.68, 617.99, 'Llévalo con hoodie gris, jogger estructurado, zapatillas blancas y perfume fresco.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-44c11d07801c', 'mp-0e1d44d63a68']::text[], 'Para hombre, funciona con camiseta sobria, sneakers versátiles y Acqua di Gio Absolu, acuático y ambarado. Perfecto para días de sol, paseo junto al mar o una salida casual con aire pulido.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a43199cd2a85', 'theoutnet', 'ton-46376663162966978', 'Suede Platform Sandals', 'Jimmy Choo', 'shoes', 'women', 'Sandalias de gamuza con plataforma, altas y equilibradas con elegancia.', 'https://www.theoutnet.com/variants/images/46376663162966978/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162966978/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162966978/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162966978/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162966978/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162966978/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/espadrilles/high-heel-espadrilles/suede-platform-sandals/46376663162966978', 470, 617.99, 'Acompáñalas con vestido midi satinado, reloj fino y clutch negro mate.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-422280d9eeaa', 'mp-16b4caef84fd', 'mp-1e7075d60425']::text[], 'Para mujer, este trío es impecable: vestido de terciopelo, reloj joya y Guilty Absolu, un perfume cálido y envolvente. Ideal para una cena de noche o evento elegante en temporada fresca.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-57c4262c9e6b', 'theoutnet', 'ton-46376663163153923', 'Rebby Canvas Trimmed Leather Sneakers', 'Bally', 'shoes', 'men', 'Sneakers de lona y cuero con perfil limpio, pensadas para uso diario con discreción.', 'https://www.theoutnet.com/variants/images/46376663163153923/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163153923/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153923/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153923/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153923/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163153923/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/sneakers/fashion-sneakers/rebby-canvas-trimmed-leather-sneakers/46376663163153923', 472, 619.99, 'Úsalas con reloj minimalista, perfume fresco y pantalón chino beige con camisa blanca o knit fino.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-1e2e2d2f0407', 'mp-60727c51909d', 'mp-4a3f893e3d09']::text[], 'Para hombre, polo texturizado, sneakers refinadas y Sauvage construyen una presencia discreta pero segura. Un look de lujo silencioso para almuerzos, reuniones informales o días de ciudad con temperatura suave.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXC