 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-100-chronograph-quartz-mens-watch-t1202172206100.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-100-chronograph-quartz-mens-watch-t1202172206100.html', 473.04, 621.99, 'Úsalo con camisa denim, pantalón beige, sneakers de cuero y perfume acuático.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-a2717c731232', 'mp-2ecaf353c55e']::text[], 'Para hombre, camiseta limpia, sneakers ligeras y Gentleman Society Sport: fresca, aromática y moderna. Es un conjunto ideal para viaje, paseo o un fin de semana activo con estética impecable.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
