INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-82fef2150d87', 'jomashop', 'SE-SRPE99', 'Seiko Prospex Automatic Blue Dial Pepsi Bezel Men''s Watch', 'Seiko', 'watch', 'men', 'Reloj de buceo con bisel pepsi y carácter clásico muy versátil.', 'https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2022/02/20/02/28/SRPE99K1/SRPE99K1.png', ARRAY['https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2022/02/20/02/28/SRPE99K1/SRPE99K1.png', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-automatic-blue-dial-mens-watch-srpe99k1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-automatic-blue-dial-mens-watch-srpe99k1_2.jpg', 'https://i5.walmartimages.com/seo/Seiko-Prospex-Automatic-Blue-Dial-Pepsi-Bezel-Men-s-Watch-SRPE99K1_e17c194e-907e-4acc-8d17-39b0e04c2ddc.bc1e44e63e86bf2dfcaca28dd6699a5c.jpeg']::text[], 'https://www.jomashop.com/seiko-prospex-automatic-blue-dial-mens-watch-srpe99k1.html', 474.99, 623.99, 'Combínalo con camisa blanca, pantalón azul oscuro, loafers o sneakers y perfume marino.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-44c11d07801c', 'mp-21708b443c49']::text[], 'Para hombre, camiseta esencial, Dunk Low y Profondo Parfum crean una imagen fresca, marina y contemporánea. Muy adecuado para fines de semana, clima cálido o una salida casual con sello refinado.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-16b4caef84fd', 'jomashop', 'SE-SRE007J1', 'Seiko Presage Automatic Diamond Blue Dial Ladies Watch', 'Seiko', 'watch', 'women', 'Reloj femenino azul con diamantes, luminoso y de encanto sereno.', 'https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2022/12/14/11/47/SRE007J1/SRE007J1.png', ARRAY['https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2022/12/14/11/47/SRE007J1/SRE007J1.png', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-automatic-diamond-blue-dial-ladies-watch-sre007j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-automatic-diamond-blue-dial-ladies-watch-sre007j1_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-presage-automatic-diamond-blue-dial-ladies-watch-sre007j1_3.jpg', 'https://www.citywatches.co.za/wp-content/uploads/2023/08/SRE007J1_2.jpg', 'https://media.karousell.com/media/photos/products/2024/9/24/seiko_presage_sre007_sre007j1__1727146267_2a125fee_progressive']::text[], 'https://www.jomashop.com/seiko-presage-automatic-diamond-blue-dial-ladies-watch-sre007j1.html', 474.99, 623.99, 'Llévalo con traje sastre beige, blusa de seda y tacones nude; perfume floral.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-eccea3334d40', 'mp-ca5e6334e29b', 'mp-6becc442eecf']::text[], 'Para mujer, el vestido floral, las sandalias y My Way Parfum logran una elegancia luminosa. Ideal para oficina creativa, almuerzo especial o primavera; el perfume es floral, suave y pulcro.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-422280d9eeaa', 'theoutnet', 'ton-22305376260456626', 'Pleated Velvet Turtleneck Midi Dress', 'Valentino', 'clothing', 'women', 'Vestido midi de terciopelo plisado, envolvente y de presencia impecable.', 'https://www.theoutnet.com/variants/images/22305376260456626/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/22305376260456626/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/22305376260456626/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/22305376260456626/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/22305376260456626/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/22305376260456626/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/22305376260456626/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/valentino-garavani/dresses/midi-dresses/pleated-velvet-turtleneck-midi-dress/22305376260456626', 476, 624.99, 'Acompáñalo con reloj fino, pendientes discretos y pumps negros de punta.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-60d70092570a', 'mp-16b4caef84fd', 'mp-db3e96bd55d9']::text[], 'Para mujer, este vestido de terciopelo pide pumps brillantes, reloj sutil y Love In White, floral, limpio y sofisticado. Un look perfecto para cena formal o gala en temporada fría.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d92a8189d8f4', 'theoutnet', 'ton-46376663163052013', 'Buckled Suede Boots', 'Tod''s', 'shoes', 'men', 'Botas de ante con hebilla, sobrias y masculinas, para un gesto atemporal con presencia.', 'https://www.theoutnet.com/variants/images/46376663163052013/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163052013/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163052013/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163052013/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163052013/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163052013/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tod-s/boots/lace-up-boots/buckled-suede-boots/46376663163052013', 477, 626.99, 'Con abrigo de lana camel, reloj de cuero negro y perfume amaderado; pantalón recto y botines pulidos.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-03dd349adfdf', 'mp-38b9fcac4c9b', 'mp-2869630c1217']::text[], 'Para hombre, las botas de gamuza encajan con una chaqueta de textura rica, reloj clásico y Soul of The Forest, amaderado y terroso. Ideal para invierno, oficina relajada o cenas discretas.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=