INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-60d70092570a', 'theoutnet', 'ton-46376663163014829', 'Romy 100 Glittered Woven Pumps', 'Jimmy Choo', 'shoes', 'women', 'Pumps brillantes de trama fina, elegantes y listos para impactar.', 'https://www.theoutnet.com/variants/images/46376663163014829/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163014829/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163014829/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163014829/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163014829/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163014829/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/pumps/high-heel-pumps/romy-100-glittered-woven-pumps/46376663163014829', 478, 627.99, 'Úsalos con vestido negro, reloj joya y clutch satinado; perfume floral ambarado.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-422280d9eeaa', 'mp-16b4caef84fd', 'mp-1e7075d60425']::text[], 'Para mujer, los pumps glitter y el vestido de terciopelo forman un conjunto de noche impecable; el reloj aporta brillo sutil y Guilty Absolu suma calidez floral-amaderada. Perfecto para una cena elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EX