INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4a3f893e3d09', 'jomashop', 'CZJY8148-08L', 'Citizen Promaster Skyhawk A-T Chronograph Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Cronógrafo aviador de presencia técnica y azul profundo, pensado para acompañar jornadas exigentes con precisión.', 'https://citizenwatch.widen.net/content/inmxnspe6o/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/inmxnspe6o/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://luxtime.pl/imageslib/produkty/duze/citizen-jy8148-08l-140189-1.jpg', 'https://i5.walmartimages.com/seo/Citizen-Promaster-Skyhawk-A-T-Chronograph-Blue-Dial-Men-s-Watch-JY8148-08L_7863940a-b793-4e3e-b3b8-00aae2b2d92a.097e921a2e0b1b66f354ef2c81a7030e.jpeg', 'https://www.demus-zegarki.pl/pol_pl_Citizen-Promaster-Skyhawk-A-T-Radio-Controlled-JY8148-08L-Zegarek-Meski-Edycja-specjalna-75653_3.jpg', 'https://citizenwatch.widen.net/content/tfcdm4hrzl/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/uh2v5dumbd/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/odeapwy2up/webp?width=1600&height=2000&quality=85&crop=false&keep=c']::text[], 'https://www.jomashop.com/citizen-promaster-skyhawk-a-t-perpetual-alarm-world-time-chronograph-gmt-analog-digital-blue-dial-mens-watch-jy8148-08l.html', 479, 628.99, 'Llévalo con camisa Oxford celeste, pantalón de lana gris, sneakers blancas limpias y perfume marino fresco.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-f60964fd1e13', 'mp-57c4262c9e6b', 'mp-6a32aace5e0a']::text[], 'Para hombre, pantalón de caída limpia, sneakers finas y Neroli Sauvage, cítrico y verde, equilibran el carácter técnico del reloj. Funciona para oficina casual o viajes con elegancia relajada.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
