INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a703bf8acd46', 'theoutnet', 'ton-46376663163157207', 'Cece 80 Leather Over The Knee Boots', 'Jimmy Choo', 'shoes', 'women', 'Botas altas de cuero con línea limpia, firmes y sofisticadas para estilizar la silueta.', 'https://www.theoutnet.com/variants/images/46376663163157207/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163157207/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163157207/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163157207/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163157207/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163157207/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/boots/over-the-knee-boots/cece-80-leather-over-the-knee-boots/46376663163157207', 502, 656.99, 'Combínalas con reloj metálico, abrigo largo negro, vestido midi de lana y perfume cuero-amaderado.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-da29446cb448', 'mp-f4871962fdc0', 'mp-3ca07bcbe159']::text[], 'El vestido shirt midi y las botas over the knee crean un contraste femenino y decidido, perfecto para entretiempo. El reloj nacarado suaviza el conjunto; La Tosca añade un floral envolvente y clásico.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-05af2cf383b4', 'theoutnet', 'ton-46376663163015354', 'Maryanne 100 Leather Pumps', 'Jimmy Choo', 'shoes', 'women', 'Pumps de cuero con tacón alto y perfil pulido, ideales para alargar con elegancia.', 'https://www.theoutnet.com/variants/images/46376663163015354/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163015354/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015354/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015354/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015354/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015354/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/pumps/high-heel-pumps/maryanne-100-leather-pumps/46376663163015354', 508, 664.99, 'Úsalos con reloj delgado, vestido sastre o falda lápiz y perfume floral ambarado.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-422280d9eeaa', 'mp-76d7d1376454', 'mp-907d601e36bb']::text[], 'El vestido de silueta limpia y el reloj de acero frío componen un lujo contenido y moderno. Royal Princess Oud aporta profundidad amaderada y almizclada, ideal para una noche elegante con presencia impecable.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-040d8d2dd56f', 'theoutnet', 'ton-46376663163082609', 'Cotton Blend Tweed Mini Dress', 'Thom Browne', 'clothing', 'women', 'Mini vestido en tweed, compacto y gráfico, con textura distinguida y aire contemporáneo.', 'https://www.theoutnet.com/variants/images/46376663163082609/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163082609/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163082609/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163082609/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163082609/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163082609/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/dresses/mini-dresses/cotton-blend-tweed-mini-dress/46376663163082609', 509, 665.99, 'Con medias opacas, reloj pequeño de acero y perfume floral oscuro; salones negros y abrigo recto.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-b72fefe9a8c0', 'mp-16b4caef84fd', 'mp-b2bac3c4aeeb']::text[], 'El tweed mini gana ligereza con sandalias de tiras y un reloj azul sutilmente brillante. El conjunto funciona muy bien en verano nocturno; Velvet Sublime aporta un carácter cálido, floral y refinado.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-87a3ff47cf1a', 'jomashop', 'TIST41118333', 'Tissot Le Locle Automatic Silver Dial Ladies Watch', 'Tissot', 'watch', 'women', 'Reloj automático de líneas clásicas y esfera plateada, sereno y preciso para el diario refinado.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-ladies-le-locle-watch-t41.1.183.33.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-ladies-le-locle-watch-t41.1.183.33.jpg', 'https://www.jared.com/productimages/processed/V-311680209_0_800.jpg?pristine=true', 'https://m.media-amazon.com/images/I/516TEJV0xoL._AC_SL1500_.jpg', 'https://mzwatcheslk.com/cdn/shop/files/tissot-le-locle-automatic-small-lady-2530-t41118333_1080x1080.jpg?v=1714130386', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-ladies-le-locle-watch-t41.1.183.33_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-ladies-le-locle-watch-t41.1.183.33_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-ladies-le-locle-watch-t41.1.183.33_4.jpg']::text[], 'https://www.jomashop.com/tissot-le-locle-t41-1-183-33.html', 511.2, 668.99, 'Combínalo con blazer camel, blusa de seda marfil, pantalón recto y perfume almizclado limpio.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-52c3e350cbd1', 'mp-08cb860e5a5a', 'mp-db3e96bd55d9']::text[], 'Los pantalones rectos o el tailoring sobrio acompañan con naturalidad la elegancia clásica del Le Locle. Los loafers mantienen discreción de oficina y Love in White suma un floral limpio, luminoso y profesional.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d6d4d019ec8e', 'theoutnet', 'ton-1647597306802572', 'Button Embellished Jacquard Knit Mini Dress', 'Balmain', 'clothing', 'women', 'Mini vestido jacquard con botones joya, estructurado y brillante con discreción moderna.', 'https://www.theoutnet.com/variants/images/1647597306802572/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597306802572/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306802572/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306802572/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306802572/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306802572/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/dresses/mini-dresses/button-embellished-jacquard-knit-mini-dress/1647597306802572', 514, 671.99, 'Acompáñalo con reloj fino, perfume floral ambarado y stilettos negros o sandalias doradas.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-05af2cf383b4', 'mp-87a3ff47cf1a', 'mp-cb004bfbf1f3']::text[], 'La textura jacquard del vestido pide pumps pulidos y un reloj clásico para un efecto de noche sofisticada. Donna Born In Roma Intense aporta vainilla, flores oscuras y carácter sensual sin perder elegancia.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-03dbb9e1183f', 'theoutnet', 'ton-46376663162839345', 'Stretch Georgette Bodysuit', 'Versace', 'clothing', 'women', 'Bodysuit de georgette con ajuste preciso y caída ligera, ideal para una imagen pulida.', 'https://www.theoutnet.com/variants/images/46376663162839345/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162839345/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162839345/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162839345/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162839345/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162839345/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/tops/bodysuits/stretch-georgette-bodysuit/46376663162839345', 518, 676.99, 'Llévalo con reloj minimalista, perfume cítrico-almizclado y pantalón negro sastre o tacones finos.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-08cb860e5a5a', 'mp-c0c58bfbda63', 'mp-87a3ff47cf1a']::text[], 'El bodysuit queda impecable con pantalón sastre y loafers, logrando una oficina moderna y discreta. Aventus for Her añade frescura afrutada y almizclada, elegante y segura, sin sobrecargar el conjunto.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.re