INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a3b7700027eb', 'theoutnet', 'ton-1647597296168866', 'Pleated Floral Print Silk Blend Twill Midi Shirt Dress', 'Valentino', 'clothing', 'women', 'Vestido camisa midi con flores, fluido y luminoso, de elegancia serena y femenina.', 'https://www.theoutnet.com/variants/images/1647597296168866/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597296168866/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597296168866/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597296168866/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597296168866/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597296168866/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/valentino-garavani/dresses/midi-dresses/pleated-floral-print-silk-blend-twill-midi-shirt-dress/1647597296168866', 519, 677.99, 'Con sandalias nude, reloj delgado y perfume floral ligero; agrega bolso estructurado en tono crema.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-50846d387b41', 'mp-76d7d1376454', 'mp-ccf304630040']::text[], 'El print floral y la caída midi se realzan con pumps arquitectónicos y un reloj de tono frío y contemporáneo. Si Intense aporta un floral ambarado, sobrio y femenino, perfecto para oficina con cena posterior.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note