INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b61ad42c6006', 'theoutnet', 'ton-11452292646388093', 'Satin Platform Pumps', 'Tom Ford', 'shoes', 'women', 'Salones de satén sobre plataforma, dramáticos y pulidos, para una silueta alta y precisa.', 'https://www.theoutnet.com/variants/images/11452292646388093/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/11452292646388093/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/11452292646388093/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/11452292646388093/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/11452292646388093/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/11452292646388093/E/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/pumps/high-heel-pumps/satin-platform-pumps/11452292646388093', 519, 677.99, 'Con vestido negro satinado, reloj joya discreto y perfume de vainilla seca; labios borgoña opcionales.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-99683d23a567', 'mp-3e1b992662c2', 'mp-907d601e36bb']::text[], 'Las satin platform pumps piden un mini vestido de impacto y un reloj de presencia elevada. Royal Princess Oud añade una estela opulenta, amaderada y ligeramente especiada, ideal para una noche de gala.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.rec