INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d8e8c8ce1c69', 'theoutnet', 'ton-46376663162974136', 'Trezze 30 Leather Slingback Sandals', 'Ferragamo', 'shoes', 'women', 'Sandalias slingback de cuero con tacón bajo, ligeras y refinadas para días cálidos.', 'https://www.theoutnet.com/variants/images/46376663162974136/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162974136/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162974136/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162974136/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162974136/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162974136/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/sandals/mid-heel-sandals/trezze-30-leather-slingback-sandals/46376663162974136', 520, 679.99, 'Combínalas con reloj delgado, vestido de lino crema, bolso estructurado y perfume floral fresco.', 'https://www.styleatacertainage.com/wp-content/uploads/2025/06/Quince-Linen-Picks.png', ARRAY['mp-4ff4da1e8d0c', 'mp-16b4caef84fd', 'mp-fa38caa36f41']::text[], 'Las slingback sandalias equilibran la feminidad del vestido floral con un acabado más pulido. El reloj azul aporta distinción nocturna; Cuir Zerzura Intense suma cuero suave, notas oscuras y elegancia contemporánea.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXC