INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3db0b4f31f71', 'jomashop', 'TIST0064071103300', 'Tissot Le Locle Powermatic 80 Automatic Men''s Watch', 'Tissot', 'watch', 'men', 'Reloj automático clásico con esfera blanca, equilibrado y sobrio para una presencia impecable.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1af9d0f4/product-pictures/8c99426a-3edc-4e15-ae24-ef8e49f73757_T006-407-11-033-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1af9d0f4/product-pictures/8c99426a-3edc-4e15-ae24-ef8e49f73757_T006-407-11-033-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1af9d0f4/product-pictures/8c99426a-3edc-4e15-ae24-ef8e49f73757_T006-407-11-033-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwee5facf8/product-pictures/d3942ac8-5742-448d-8535-8cf2d29d98ca_T006-407-11-033-00_Profil.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw01015f9e/product-pictures/1d5e8306-d206-4c97-b1e8-cb0d1dda09ad_T006_407_11_033_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb65fc906/product-pictures/4f1b5ed3-9c82-4164-b96a-723d255966e2_T006_407_11_033_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe621cc1e/product-pictures/8e56bc56-66fc-441d-9dc6-bf1a0d7564fb_T006-407-11-033-00_DETAIL-1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw99efc112/product-pictures/3fe1621d-f515-4a4d-89dd-e9d9bc5b25be_T006_407_11_033_00.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-watch-t0064071103300.html', 520.8, 680.99, 'Úsalo con traje gris medio, camisa blanca, derby negros y perfume amaderado limpio.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-03dd349adfdf', 'mp-eef693d6878c', 'mp-3d7ec08426d5']::text[], 'Para una jornada formal, este reloj se acompaña de una chaqueta estructurada, pantalón limpio y loafers clásicos. El resultado es sobrio y preciso, ideal para oficina o reuniones donde quieres proyectar elegancia discreta sin esfuerzo.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b6171d2cf074', 'jomashop', 'CZJV1006-51L', 'Citizen Promaster Analog-Digital Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Reloj analógico-digital con presencia técnica y azul profundo, pensado para ritmo activo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-analogdigital-blue-dial-mens-watch-jv100651l.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-analogdigital-blue-dial-mens-watch-jv100651l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-analogdigital-blue-dial-mens-watch-jv100651l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-analogdigital-blue-dial-mens-watch-jv100651l_3.jpg', 'https://www.auswatches.com/media/catalog/product/cache/f20a3dad9a18e1857a6578422466bfb5/j/v/jv1006-51l_00.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-analog-digital-blue-dial-mens-watch-jv1006-51l.html', 522.24, 681.99, 'Combínalo con chaqueta ligera, polo blanco, jogger oscuro o zapatillas running y perfume fresco acuático.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-44c11d07801c', 'mp-2ecaf353c55e']::text[], 'Con camiseta técnica, joggers y zapatillas, tu Promaster queda perfecto para un fin de semana activo. El look es cómodo y moderno; si eliges un perfume, busca uno fresco y acuático, de salida limpia y energética.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b72fefe9a8c0', 'theoutnet', 'ton-1647597335215128', 'Rockstud Alcove Smooth And Patent Leather Pumps', 'Valentino', 'shoes', 'women', 'Pumps con Rockstud, entre brillo y carácter, para una elegancia firme y moderna.', 'https://www.theoutnet.com/variants/images/1647597335215128/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597335215128/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597335215128/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597335215128/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597335215128/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597335215128/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/valentino-garavani/pumps/high-heel-pumps/rockstud-alcove-smooth-and-patent-leather-pumps/1647597335215128', 523, 682.99, 'Con traje negro entallado, reloj de acero y perfume amaderado; bolso rígido y líneas limpias.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-ebf760a142ec', 'mp-76d7d1376454', 'mp-cb004bfbf1f3']::text[], 'Los Rockstud pumps aportan filo refinado al mini dress y al reloj contemporáneo. Donna Born In Roma Intense deja una estela de vainilla, jazmín y maderas suaves, ideal para una noche elegante.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
