INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-eb9db9aaf311', 'jomashop', 'CZJY8125-54L', 'Citizen Promaster Skyhawk A-T Chronograph GMT Eco-Drive Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Cronógrafo GMT de estética azul intensa, práctico y pulido para moverse con soltura.', 'https://citizenwatch.widen.net/content/ag7ov33ss2/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/ag7ov33ss2/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/pmyt9nnprd/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/25fr86sbvh/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/qxfshfcycj/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-chronograph-gmt-ecodrive-blue-dial-mens-watch-jy812554l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-chronograph-gmt-ecodrive-blue-dial-mens-watch-jy812554l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-skyhawk-at-chronograph-gmt-ecodrive-blue-dial-mens-watch-jy812554l_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-skyhawk-a-t-chronograph-gmt-eco-drive-blue-dial-mens-watch-jy8125-54l.html', 527.04, 687.99, 'Combínalo con blazer casual, camisa blanca, pantalón chino gris y sneakers de cuero blanco.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-16dc129ea1db', 'mp-58f47135b97a', 'mp-605a39d82c0f']::text[], 'La sobrecamisa de lino, el pantalón relajado y los driving shoes equilibran muy bien tu Skyhawk. Es un conjunto casual con aire refinado, ideal para viaje o almuerzo de verano; el reloj aporta carácter deportivo sin perder sobriedad.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a163815499e7', 'theoutnet', 'ton-46376663163063219', 'One Shoulder Cutout Floral Print Stretch Jersey Dress', 'Versace', 'clothing', 'women', 'Diseño asimétrico con recorte floral, vibrante y sensual, pensado para destacar con presencia.', 'https://www.theoutnet.com/variants/images/46376663163063219/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163063219/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163063219/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163063219/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163063219/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163063219/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/dresses/knee-length-dresses/one-shoulder-cutout-floral-print-stretch-jersey-dress/46376663163063219', 532, 693.99, 'Combínalo con sandalias negras, reloj delgado de acero y perfume ambarado limpio para un efecto pulido.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-50846d387b41', 'mp-76d7d1376454', 'mp-db86cdd766da']::text[], 'Los pumps afinan la silueta del vestido sin restarle calma; el reloj azul suma luz sutil. El perfume aporta un floral limpio y elegante, perfecto para una velada refinada o evento de verano.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-50846d387b41', 'theoutnet', 'ton-46376663162872737', 'Anser Leather Pumps', 'Ferragamo', 'shoes', 'women', 'Salón de cuero con línea limpia y porte clásico, impecable para elevar cualquier conjunto.', 'https://www.theoutnet.com/variants/images/46376663162872737/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162872737/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162872737/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162872737/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162872737/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162872737/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/pumps/high-heel-pumps/anser-leather-pumps/46376663162872737', 534, 696.99, 'Llévalos con traje sastre gris, reloj de acero y perfume amaderado discreto para un look preciso.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-6ffcafde6997', 'mp-9b05bcfb7742', 'mp-b2bac3c4aeeb']::text[], 'El vestido off shoulder realza la línea del pump con un resultado elegante y muy femenino. El reloj mantiene el lujo contenido y el Oud aporta un perfil opulento, ideal para cena de noche.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCL