INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8c5d849c574c', 'jomashop', 'SE-SRPE33K1', 'Seiko Prospex Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Reloj Prospex de esfera azul, robusto y preciso, listo para acompañar días activos.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-automatic-blue-dial-mens-watch-srpe33k1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-automatic-blue-dial-mens-watch-srpe33k1.jpg', 'https://saicreationswatches.com/cdn/shop/files/srpe33k1_3.jpg?v=1714397006&width=1445', 'https://p1.liveauctioneers.com/6801/326528/175798140_1_x.jpg?height=512&quality=70&version=1713381253', 'https://down-my.img.susercontent.com/file/my-11134207-7rasl-m23c9p860fcob6', 'https://images-cdn.ubuy.co.in/685e65387fe027a07b02c337-seiko-prospex-blue-men-s-watch.jpg', 'https://m.media-amazon.com/images/I/71FcHK5iqPL._AC_SL1500_.jpg']::text[], 'https://www.jomashop.com/seiko-prospex-automatic-blue-dial-mens-watch-srpe33k1.html', 535.99, 698.99, 'Úsalo con polo técnico, pantalón oscuro y zapatillas blancas; perfume acuático para un perfil sobrio.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-44c11d07801c', 'mp-2ecaf353c55e']::text[], 'Tu Seiko luce mejor con una camiseta limpia, joggers y sneakers de líneas suaves. Es un look relajado para ciudad o escapadas de fin de semana, con energía deportiva y un acabado pulido.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-58f47135b97a', 'theoutnet', 'ton-1647597338596851', 'Gommino Calf Hair Driving Shoes', 'Tod''s', 'shoes', 'men', 'Driving shoes en pelo de becerro, suaves y sofisticados, para un andar relajado y distinguido.', 'https://www.theoutnet.com/variants/images/1647597338596851/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597338596851/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597338596851/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597338596851/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597338596851/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597338596851/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tod-s/flat-shoes/loafers/gommino-calf-hair-driving-shoes/1647597338596851', 538, 701.99, 'Con pantalón blanco, reloj de cuero chocolate y perfume fougère; polo azul marino y blazer ligero.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-1e2e2d2f0407', 'mp-529fb48cd3f0', 'mp-605a39d82c0f']::text[], 'Los driving shoes piden polo de punto, pantalón de lino y un reloj PRX para una silueta impecable. Es un look de lujo silencioso, perfecto para almuerzos o tardes de verano; si sumas perfume, elige uno cítrico y elegante.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED