INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5d0569476f27', 'theoutnet', 'ton-46376663163148371', 'Murano Suede Penny Loafers', 'Paul Smith', 'shoes', 'men', 'Loafers de ante con penny strap, clásicos y versátiles, de elegancia contenida.', 'https://www.theoutnet.com/variants/images/46376663163148371/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163148371/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148371/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148371/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148371/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148371/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/paul-smith/flat-shoes/loafers/murano-suede-penny-loafers/46376663163148371', 539, 702.99, 'Con pantalón de pinzas, reloj de acero y perfume de cedro; camisa celeste y abrigo camel.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-2ad272892924', 'mp-550ff261eb4e', 'mp-1fee958584dc']::text[], 'Estos loafers funcionan muy bien con camisa de lino, pantalón de corte fino y un reloj oscuro. El conjunto es sobrio y actual, ideal para oficina creativa o cena informal; transmite pulcritud sin rigidez.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco