INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e9c19d3ac984', 'jomashop', 'CZEG7000-01A', 'Citizen Ambiluna Eco-Drive Titanium Opaque Watch', 'Citizen', 'watch', 'unisex', 'Titanio mate y lectura limpia, un reloj ligero de presencia discreta y moderna.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ambiluna-ecodrive-titanium-opaque-watch-eg700001a.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ambiluna-ecodrive-titanium-opaque-watch-eg700001a.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ambiluna-ecodrive-titanium-opaque-watch-eg700001a_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ambiluna-ecodrive-titanium-opaque-watch-eg700001a_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ambiluna-ecodrive-titanium-opaque-watch-eg700001a_4.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-ambiluna-ecodrive-titanium-opaque-watch-eg700001a_6.jpg', 'https://i5.walmartimages.com/seo/Citizen-Ambiluna-Eco-Drive-Titanium-Opaque-Watch-EG7000-01A_04a681c9-6bab-4bb9-be8b-75e35f61eb2f.a47b59cdfe9604a67bf8949b06a12502.jpeg', 'https://donghotantan.vn/images/products/2016/11/11/large/dong-ho-citizen-eg7000-01a-.jpg']::text[], 'https://www.jomashop.com/citizen-watch-eg7000-01a.html', 541.44, 705.99, 'Combínalo con camisa blanca, blazer azul marino y mocasines; perfume cítrico amaderado, sin exceso.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-03dd349adfdf', 'mp-f72ed8b412b3', 'mp-814b8aba6cec']::text[], 'Tu Ambiluna se ve impecable con blazer ligero, pantalón de lana y loafers. Es una propuesta elegante y silenciosa, perfecta para oficina o una cena formal; el perfume ideal sería amaderado, seco y muy pulcro.', 'elegante', ARRAY['mp-381d102f4ffc', 'mp-d0246a15c10d', 'mp-c0c58bfbda63']::text[], 'Tu Ambiluna se combina con un sweater de cashmere, pantalón entallado y pumps para un resultado pulcro y sofisticado. Es ideal para oficina o cena elegante; el perfume sugerido debe ser floral-amaderado, delicado y envolvente.', 'elegante') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-0d7c339f012c', 'jomashop', 'TIST1372071109100', 'Tissot PRX Automatic Green Dial Unisex Watch', 'Tissot', 'watch', 'unisex', 'PRX verde de líneas precisas, contemporáneo y refinado, con un acento muy actual.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw7ed9e90f/product-pictures/a2c83d75-5920-46ae-9357-748382f43010_T137-207-11-091-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw7ed9e90f/product-pictures/a2c83d75-5920-46ae-9357-748382f43010_T137-207-11-091-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw7ed9e90f/product-pictures/a2c83d75-5920-46ae-9357-748382f43010_T137-207-11-091-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw4d8186e5/product-pictures/83a510ee-8333-4bdb-ad51-6a11803970a3_T137_207_11_091_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw594f541e/product-pictures/14d9e25f-95df-42bd-8da6-f3b9ecb101a2_T137_207_11_091_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwfeb6704d/product-pictures/b2f53bfc-c166-40a7-ae38-b8ef4223581f_T137_207_11_091_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw80b97d2f/product-pictures/a8f0b5dc-c2b9-4eb8-94e6-fa2eacf8b4f3_T137-207-11-091-00_DETAIL-1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe1522bc6/product-pictures/83b48873-f9e5-4284-8fcf-ce251319f5a6_T137_207_11_091_00_DETAIL-2.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-automatic-green-dial-unisex-watch-t1372071109100.html', 541.87, 706.99, 'Combínalo con sastre beige, camisa celeste y loafers; perfume verde amaderado para coherencia discreta.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-03dd349adfdf', 'mp-6e78cd2c0e9e', 'mp-3d7ec08426d5']::text[], 'El PRX verde queda muy bien con blazer de textura, pantalón limpio y loafers. Es un look de oficina con personalidad serena, perfecto para reuniones o un almuerzo ejecutivo; si añades perfume, mejor uno vetiver, seco y refinado.', 'oficina', ARRAY['mp-93b4025350f4', 'mp-08cb860e5a5a', 'mp-70ebe553f139']::text[], 'Tu PRX verde cobra fuerza con blazer de lana, pantalón sastre y loafers. Es un conjunto de oficina elegante y contemporáneo, ideal para días de trabajo; el perfume recomendado debe ser limpio, amaderado y discreto.', 'oficina') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8f52e7b9935a', 'jomashop', 'TIST0064071105300', 'Tissot Le Locle Powermatic 80 Automatic Men''s', 'Tissot', 'watch', 'men', 'Le Locle clásico, de esfera sobria y elegancia atemporal para el día formal.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw62fe4508/product-pictures/709538f1-d0c0-4294-abd0-c689cbdf708f_T006-407-11-053-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw62fe4508/product-pictures/709538f1-d0c0-4294-abd0-c689cbdf708f_T006-407-11-053-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw62fe4508/product-pictures/709538f1-d0c0-4294-abd0-c689cbdf708f_T006-407-11-053-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe9dd602a/product-pictures/f060b7ff-55e3-4545-887b-348ab8093505_T006-407-11-053-00_Profil.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwed0b0533/product-pictures/9f6814d2-46bf-4c09-9a36-5971fbbe8ff3_T006_407_11_053_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf971b7e8/product-pictures/195c4fa9-75ed-44f9-98e3-2da7723ab1b7_T006_407_11_053_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw61801b33/product-pictures/73d56419-3f44-4f80-8148-dfaf30125d49_T006_407_11_053_00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-le-locle-powermatic-80-automatic-black-dial-mens-t006.407.11.053.00.jpg']::text[], 'https://www.jomashop.com/tissot-watch-t006-407-11-053-00.html', 541.87, 706.99, 'Llévalo con traje azul oscuro, Oxford negros y perfume de vetiver; el conjunto respira autoridad serena.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-03dd349adfdf', 'mp-eef693d6878c', 'mp-3d7ec08426d5']::text[], 'El Le Locle encaja perfecto con blazer estructurado, pantalón de corte recto y loafers clásicos. Es un look de oficina impecable y atemporal, ideal para reuniones o una cena formal; si eliges perfume, que sea vetiver y elegante.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3002aadaf38c', 'theoutnet', 'ton-1647597339852949', 'Chiffon Paneled Draped Jersey Midi Dress', 'Versace', 'clothing', 'women', 'Vestido midi en gasa y jersey, fluido y sensual, con caída impecable.', 'https://www.theoutnet.com/variants/images/1647597339852949/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597339852949/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597339852949/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597339852949/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597339852949/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597339852949/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/dresses/midi-dresses/chiffon-paneled-draped-jersey-midi-dress/1647597339852949', 542, 706.99, 'Compleméntalo con sandalias finas, reloj pequeño en oro y perfume floral blanco para suavidad nocturna.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-50846d387b41', 'mp-9b05bcfb7742', 'mp-db3e96bd55d9']::text[], 'Los pumps equilibran el drapeado del vestido y lo vuelven más pulido. El reloj añade pureza visual y el perfume, floral y luminoso, es ideal para un almuerzo elegante o tarde de verano.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-18efa6b1f165', 'theoutnet', 'ton-1647597344368176', 'Jayla 85 Suede Knee Boots', 'Jimmy Choo', 'shoes', 'women', 'Bota alta en ante con tacón esbelto, femenina y precisa para climas fríos.', 'https://www.theoutnet.com/variants/images/1647597344368176/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597344368176/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597344368176/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597344368176/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597344368176/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597344368176/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/boots/tall-boots/jayla-85-suede-knee-boots/1647597344368176', 543, 707.99, 'Úsalas con abrigo largo camel, bolso estructurado y reloj metálico; perfume amaderado cálido completa el look.', 'https://threadcurve.com/wp-content/uploads/2025/11/statement-coat-layered-winter-outfit.jpeg', ARRAY['mp-dcde323f0351', 'mp-b92296fdc3b1', 'mp-81d52947c289']::text[], 'Las botas de ante funcionan muy bien con un abrigo de lana y un reloj compacto; el resultado es chic y urbano. El perfume aporta un carácter floral cremoso, perfecto para otoño o invierno.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-99683d23a567', 'theoutnet', 'ton-1647597349885828', 'Button Embellished Frayed Cotton Blend Tweed Mini Dress', 'Balmain', 'clothing', 'women', 'Mini vestido de tweed, con botones joya y borde desflecado, muy chic y contemporáneo.', 'https://www.theoutnet.com/variants/images/1647597349885828/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597349885828/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597349885828/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597349885828/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597349885828/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597349885828/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597349885828/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/balmain/dresses/mini-dresses/button-embellished-frayed-cotton-blend-tweed-mini-dress/1647597349885828', 544, 708.99, 'Con salones negros, reloj pequeño de oro y perfume chipre; añade abrigo largo estructurado.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-a4f5e06e83d2', 'mp-76d7d1376454', 'mp-cb004bfbf1f3']::text[], 'Las sandalias mantienen el look ligero y lujoso, dejando que el vestido sea protagonista. El reloj aporta destello frío y el perfume, dulce-especiado, completa un conjunto ideal para noche de verano o evento.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f4281ad4c519', 'theoutnet', 'ton-46376663163074973', 'Embellished Leather Platform Pumps', 'Tom Ford', 'shoes', 'women', 'Salones de plataforma con adornos, impactantes y pulidos, para una silueta poderosa.', 'https://www.theoutnet.com/variants/images/46376663163074973/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163074973/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074973/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074973/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074973/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074973/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/pumps/high-heel-pumps/embellished-leather-platform-pumps/46376663163074973', 545, 710.99, 'Con vestido negro columna, reloj joya discreto y perfume ámbar; clutch metálico y abrigo liso.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-79b23834fd03', 'mp-87a3ff47cf1a', 'mp-ccf304630040']::text[], 'El vestido midi brillante acompaña la teatralidad del zapato sin exceso. El reloj suma equilibrio clásico y el perfume, elegante y envolvente, resulta perfecto para cóctel, gala o cena especial.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a4f5e06e83d2', 'theoutnet', 'ton-1647597325259415', 'Roman Stud Leather Sandals', 'Valentino', 'shoes', 'women', 'Sandalias de cuero con studs romanos, firmes y luminosas, para una elegancia con actitud.', 'https://www.theoutnet.com/variants/images/1647597325259415/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597325259415/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597325259415/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597325259415/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597325259415/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597325259415/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/valentino-garavani/sandals/flat-sandals/roman-stud-leather-sandals/1647597325259415', 549, 714.99, 'Con vestido largo de seda, reloj delgado y perfume floral seco; bolso pequeño y tonos piedra.', 'https://www.styleatacertainage.com/wp-content/uploads/2025/06/Quince-Linen-Picks.png', ARRAY['mp-826b38279ee9', 'mp-3e1b992662c2', 'mp-ccf304630040']::text[], 'Las sandalias con studs aportan fuerza moderna a un vestido sofisticado. El reloj champagne añade elegancia y el perfume, femenino e intenso, termina un look ideal para noche, eventos o cenas de verano.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-847068464113', 'jomashop', 'TIST1372071104100', 'Tissot PRX Automatic 35mm Blue Dial Unisex Watch', 'Tissot', 'watch', 'unisex', 'PRX compacto en azul, equilibrado y versátil, con una elegancia limpia de uso diario.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw45f1dd0a/product-pictures/c40959ea-db66-4297-b91b-63cb686c1cf5_T137-207-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw45f1dd0a/product-pictures/c40959ea-db66-4297-b91b-63cb686c1cf5_T137-207-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw45f1dd0a/product-pictures/c40959ea-db66-4297-b91b-63cb686c1cf5_T137-207-11-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe95c2664/product-pictures/e48536cc-5de5-4908-a57b-144226133da7_T137_207_11_041_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0784bee7/product-pictures/253b7f44-dcc9-4aed-b0a8-f6fec4959875_T137_207_11_041_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw5a66a59d/product-pictures/4a298b14-0f32-4818-9ac8-8d03db82383b_T137_207_11_041_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw340a5212/product-pictures/4192fd78-dd96-4a45-a7db-8a743a83d50c_T137_207_11_041_00.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw34846eee/product-pictures/fc6b81e0-17b6-4223-8f14-68a51214acf9_T137-207-11-041-00_Head.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-automatic-blue-dial-unisex-watch-t1372071104100.html', 549.5, 715.99, 'Va con knit navy, pantalón recto y loafers; perfume cítrico amaderado para un efecto pulcro.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-16dc129ea1db', 'mp-58f47135b97a', 'mp-605a39d82c0f']::text[], 'Tu PRX azul de 35 mm luce mejor con sobrecamisa ligera, pantalón relajado y driving shoes. Es un look casual con mucha clase, ideal para verano, brunch o viaje; el perfume perfecto sería cítrico y fresco.', 'casual', ARRAY['mp-cd8ff58dbf50', 'mp-c3eaa0c6b09e', 'mp-6a32aace5e0a']::text[], 'Tu PRX azul de 35 mm se equilibra con un cardigan texturizado, vestido de punto y sneakers esculturales. Es un look casual pero sofisticado, ideal para día a día; un perfume floral fresco completaría el conjunto con suavidad.', 'casual') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d72bcb1e088f', 'theoutnet', 'ton-1647597341947404', 'Apostropha 80 Crystal Embellished Mesh Pumps', 'Christian Louboutin', 'shoes', 'women', 'Salones de malla con cristales, etéreos y precisos para una presencia refinada.', 'https://www.theoutnet.com/variants/images/1647597341947404/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597341947404/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597341947404/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597341947404/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597341947404/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597341947404/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/christian-louboutin/pumps/mid-heel-pumps/apostropha-80-crystal-embellished-mesh-pumps/1647597341947404', 550, 716.99, 'Combínalos con reloj pulido, perfume blanco y vestido estructurado en tonos humo o plata.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-99683d23a567', 'mp-76d7d1376454', 'mp-b2bac3c4aeeb']::text[], 'Una selección equilibrada por estilo, ocasión, nivel de precio y género para completar el conjunto.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_