INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-eef693d6878c', 'theoutnet', 'ton-46376663163075596', 'Leather Penny Loafers', 'Thom Browne', 'shoes', 'men', 'Mocasines de piel, precisos y limpios, con una lectura discreta del lujo masculino.', 'https://www.theoutnet.com/variants/images/46376663163075596/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163075596/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163075596/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163075596/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163075596/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163075596/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/thom-browne/flat-shoes/loafers/leather-penny-loafers/46376663163075596', 550, 716.99, 'Con pantalón de lana gris, reloj de acero y perfume vetiver; camisa blanca y abrigo navy.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-03dd349adfdf', 'mp-3db0b4f31f71', 'mp-4520d6ec87f1']::text[], 'La chaqueta estructurada, el reloj sobrio y el vetiver limpio elevan el penny loafer con precisión de oficina. Ideal para un look de trabajo refinado, discreto y perfectamente alineado con el lujo silencioso.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-72eecd3685e7', 'jomashop', 'Z-3HENB', 'Creed Men''s Creed Tabarome Millesime EDP Splash 8.4 oz', 'Creed', 'perfume', 'men', 'Aroma de tabaco y maderas, clásico y distinguido, con un aire de caballero moderno.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-mens-creed-tabarome-millesime-edp-splash-84-oz-fragrances-3123421250384.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-mens-creed-tabarome-millesime-edp-splash-84-oz-fragrances-3123421250384.jpg', 'https://nuestrasfragancias.com/wp-content/uploads/2024/08/Tabarome-Millesime-Eau-de-Parfum-100-ml-Hombre.webp', 'https://cdn.clothbase.com/uploads/27a4149d-a1ed-4882-8eb2-cbc93bf6736d/tabarome-millesime-eau-de-parfum-100-ml.jpg', 'https://cdn.clothbase.com/uploads/4afdbcac-9027-4204-839a-7cc64fd3b9d2/zqsddqdycxyujmrvaubz.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-mens-creed-tabarome-millesime-edp-splash-84-oz-fragrances-3123421250384_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/o/p/open-box-creed-mens-creed-tabarome-millesime-edp-splash-84-oz-fragrances-3123421250384.jpg']::text[], 'https://www.jomashop.com/creed-mens-creed-tabarome-millesime-edp-splash-8-4-oz-fragrances-3123421250384.html', 550.99, 717.99, 'Llévalo con traje azul, reloj de esfera limpia y zapatos Oxford; aporta profundidad sin imponerse.', 'https://images.stockcake.com/public/e/f/1/ef1cb030-ed89-4a00-af5d-cf1485e9e655_large/elegant-men-s-fashion-stockcake.jpg', ARRAY['mp-76e86cc39c9a', 'mp-4d4c7a52c4f5', 'mp-8f52e7b9935a']::text[], 'El pantalón de lana, los loafers pulidos y el Le Locle crean una sastrería clásica y distinguida. El Tabarome acompaña con tabaco suave, cítricos secos y madera, perfecto para oficina y reuniones formales.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c7f010c47ad7', 'theoutnet', 'ton-46376663163148383', 'Malfa Buckled Leather Sandals', 'Paul Smith', 'shoes', 'men', 'Sandalias de cuero con hebilla, limpias y sobrias, ideales para un verano relajado con carácter.', 'https://www.theoutnet.com/variants/images/46376663163148383/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163148383/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148383/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148383/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148383/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148383/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/paul-smith/sandals/flat-sandals/malfa-buckled-leather-sandals/46376663163148383', 552, 718.99, 'Úselas con reloj de acero, camisa de lino beige y pantalón claro; perfume cítrico y gafas carey.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-1e2e2d2f0407', 'mp-8d5bb353d59a', 'mp-529fb48cd3f0']::text[], 'Polo de punto, pantalón de lino y neroli fresco forman un conjunto relajado y sofisticado. Las sandalias encajan para verano, con una lectura limpia, mediterránea y muy de lujo silencioso.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_id