INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-474b2526c36a', 'theoutnet', 'ton-46376663163148389', 'Tasseled Velvet Loafers', 'Tom Ford', 'shoes', 'men', 'Mocasines de terciopelo con flecos, discretamente teatrales para una noche pulida.', 'https://www.theoutnet.com/variants/images/46376663163148389/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163148389/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148389/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148389/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148389/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163148389/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/flat-shoes/loafers/tasseled-velvet-loafers/46376663163148389', 554, 721.99, 'Combínelos con reloj negro, traje azul noche y perfume amaderado; funcionan mejor con lana y satén oscuro.', 'https://i.pinimg.com/736x/9c/c9/9e/9cc99e4d47d858740c6c2d87943c8511--dinner-jackets-wedding-tuxedos.jpg', ARRAY['mp-1e4d84f905c4', 'mp-981a93fef36b', 'mp-a7fbae0e4ca7']::text[], 'La camisa satinada, el punto merino y el terciopelo del zapato construyen una noche elegante y cálida. Scandal Absolu suma dulzor amaderado y sensual, ideal para invierno y cena formal.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EX