INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f285a5185544', 'theoutnet', 'ton-46376663163075262', 'Embellished Croc Effect Leather Platform Pumps', 'Tom Ford', 'shoes', 'women', 'Pumps de plataforma con efecto cocodrilo y brillo preciso, pensados para destacar con sofisticación.', 'https://www.theoutnet.com/variants/images/46376663163075262/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163075262/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163075262/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163075262/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163075262/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163075262/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/pumps/high-heel-pumps/embellished-croc-effect-leather-platform-pumps/46376663163075262', 557, 724.99, 'Llévelos con reloj joya, vestido negro estructurado y perfume ámbar; complete con aretes dorados discretos.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-79b23834fd03', 'mp-3e1b992662c2', 'mp-b2bac3c4aeeb']::text[], 'El vestido midi adornado y los pumps efecto cocodrilo crean una silueta poderosa y femenina. El reloj champagne aporta brillo discreto; perfecto para noche, con un perfume elegante y envolvente si se desea acompañar.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b2bac3c4aeeb', 'jomashop', 'Z-246YG', 'Creed Ladies Creed Royal Princess Oud EDP Splash 8.11 oz', 'Creed', 'perfume', 'women', 'Oud con rosa y especias, envolvente y majestuoso, perfecto para una firma personal refinada.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-ladies-creed-royal-princess-oud-edp-splash-811-oz-fragrances-3508440000569.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-ladies-creed-royal-princess-oud-edp-splash-811-oz-fragrances-3508440000569.jpg', 'https://www.dekantparfum.com.tr/idea/hs/04/myassets/products/072/creed-royal-princess-oud-edp.jpg?revision=1754548343', 'https://www.perfumenz.co.nz/cdn/shop/products/creed_royal_princess_oud_1024x1024.jpg?v=1496801149', 'https://missi.com.vn/wp-content/uploads/2026/04/Creed-Royal-Princess-Oud-EDP-01.jpg', 'https://myperfumeshop.com.au/cdn/shop/products/creed-royal-princess-oud-edp-perfume-cologne-612862.png?v=1693018747&width=1000', 'https://cdn.ecommercedns.uk/files/7/254947/6/49071016/tempimagejqtkal.jpg']::text[], 'https://www.jomashop.com/creed-ladies-creed-royal-princess-oud-edp-splash-8-11-oz-fragrances-3508440000569.html', 561.99, 730.99, 'Combínalo con vestido satinado, joyería discreta y sandalias delicadas; deja que el perfume marque la escena.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-79b23834fd03', 'mp-12add36cce18', 'mp-3e1b992662c2']::text[], 'El midi bordado y los pumps de tacón sostienen la opulencia del Oud Princess. El reloj champagne añade luz; la fragancia, floral-ambarada con oud noble, es ideal para una velada invernal.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
