INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-f82c020821e8', 'theoutnet', 'ton-1647597352325323', 'Tutti Rui Donna Perforated Suede Sneakers', 'Christian Louboutin', 'shoes', 'women', 'Zapatillas de ante perforado, sobrias y versátiles para un paso relajado.', 'https://www.theoutnet.com/variants/images/1647597352325323/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597352325323/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597352325323/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597352325323/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597352325323/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597352325323/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/christian-louboutin/sneakers/fashion-sneakers/tutti-rui-donna-perforated-suede-sneakers/1647597352325323', 564, 733.99, 'Llévalas con reloj minimalista, perfume limpio y prendas crudas, denim oscuro o lino beige.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-c5006cb8c599', 'mp-0011f169d584', 'mp-6a32aace5e0a']::text[], 'Una selección equilibrada por estilo, ocasión, nivel de precio y género para completar el conjunto.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco