INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2ed2085d4b66', 'theoutnet', 'ton-46376663163015317', 'Chike Leather And Ribbed Knit Hiking Boots', 'Jimmy Choo', 'shoes', 'women', 'Hiking boot en cuero y knit, funcional y sobria, con acabado urbano.', 'https://www.theoutnet.com/variants/images/46376663163015317/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163015317/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015317/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015317/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015317/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015317/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/boots/ankle-boots/chike-leather-and-ribbed-knit-hiking-boots/46376663163015317', 570, 740.99, 'Combínalas con denim negro, parka limpia y reloj de esfera oscura; perfume especiado suave añade carácter.', 'https://threadcurve.com/wp-content/uploads/2025/11/statement-coat-layered-winter-outfit.jpeg', ARRAY['mp-dcde323f0351', 'mp-f67e672616b5', 'mp-58072ada40a0']::text[], 'La versión en cuero funciona con abrigo de lana y reloj compacto para un invierno sofisticado. Tuscan Leather suma cuero ahumado y fondo ambarado, ideal para ciudad y climas fríos.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_im