0.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe89a92c3/product-pictures/6418a4c8-ef12-435e-8778-5e49438bb475_T137-407-11-091-00_Head.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-tissot-prx-automatic-green-dial-mens-watch-t1374071109100.html', 571.2, 742.99, 'Va con camisa de lino, pantalón crema y loafers; perfume verde amaderado completa un lujo silencioso.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-1e2e2d2f0407', 'mp-58f47135b97a', 'mp-605a39d82c0f']::text[], 'El verde del PRX dialoga con polo de punto, lino y driving shoes, en una clave relajada pero precisa. Muy apropiado para fines de semana, con frescura y lujo silencioso.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
