EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-e49d2abf765f', 'theoutnet', 'ton-46376663163117160', 'Wool Crepe Blazer', 'Maison Margiela', 'clothing', 'women', 'Blazer de lana crepé con caída sobria y elegancia arquitectónica.', 'https://www.theoutnet.com/variants/images/46376663163117160/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163117160/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163117160/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163117160/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163117160/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163117160/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/maison-margiela/jackets/blazers/wool-crepe-blazer/46376663163117160', 585, 759.99, 'Acompáñalo con reloj de acero pulido, perfume limpio y camisa marfil con pantalón gris y derbies.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-87a3ff47cf1a', 'mp-50846d387b41', 'mp-d3b04c599098']::text[], 'Tu blazer gana presencia con pumps clásicos y un reloj de línea fina: femenino, preciso y muy Maison Privée. Ideal para oficina o presentación. Infusion d’Iris aporta un iris limpio y aterciopelado.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
