'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw6933b6b3/product-pictures/5318765e-5077-4373-b1f0-a98265cc2b57_T137_407_21_031_00_DETAIL-2.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-t-classic-prx-powermatic-80-automatic-mens-watch-t137-407-21-031-00.html', 587.52, 762.99, 'Llévalo con perfume cítrico seco, camisa celeste y chino beige con loafers de ante.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4af1908c0185', 'mp-6e78cd2c0e9e', 'mp-2dc2d5978672']::text[], 'La PRX funciona con camisa de algodón-lino, pantalón fluido y loafers pulidos: discreción con carácter. Perfecto para oficina o almuerzo de negocios; Eau Sauvage deja un frescor cítrico y clásico.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
