=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwda1c8a04/product-pictures/e19c5b28-4251-497c-80ab-0d685562ea88_T137_407_11_351_01.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-powermatic-80-automatic-blue-dial-mens-watch-t1374071135101.html', 587.52, 762.99, 'Combínalo con perfume amaderado ligero, blazer azul marino y pantalón crema con mocasines marrones.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-2ad272892924', 'mp-54068fb7261c', 'mp-2dc2d5978672']::text[], 'Con camisa de lino, pantalón ligero y loafers de ante, tu PRX azul se ve sofisticada sin esfuerzo. Ideal para días largos en Lima; Myslf añade un acorde limpio, moderno y ligeramente ambarado.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-814b8aba6cec', 'jomashop', 'Z-C6ZY6', 'Creed Men''s Absolu Aventus EDP Spray 3.4 oz', 'Creed', 'perfume', 'men', 'Aventus en versión Absolu, vibrante y refinado con sello distintivo.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-mens-absolu-aventus-edp-spray-3-4-oz-fragrances-3508440004352.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-mens-absolu-aventus-edp-spray-3-4-oz-fragrances-3508440004352.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-mens-absolu-aventus-edp-spray-34-oz-fragrances-3508440004352_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-mens-absolu-aventus-edp-spray-34-oz-fragrances-3508440004352_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-mens-absolu-aventus-edp-spray-34-oz-fragrances-3508440004352_7.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-mens-absolu-aventus-edp-spray-34-oz-fragrances-3508440004352.jpg']::text[], 'https://www.jomashop.com/creed-mens-absolu-aventus-edp-spray-3-4-oz-fragrances-3508440004352.html', 588.05, 763.99, 'Úsalo con reloj de acero, traje azul oscuro y zapatos negros; añade camisa blanca impecable.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-0c0fab912d30', 'mp-94a0cc171f7c', 'mp-a7fbae0e4ca7']::text[], 'Absolu Aventus pide estructura: chaqueta de cashmere, pantalón impecable y monk straps. Es un conjunto de noche o cena formal, con un perfume afrutado-ahumado, potente y refinado.', 'elegante', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-31785b0725f8', 'theoutnet', 'ton-46376663163055669', 'Nik Leather Boots', 'Paul Smith', 'shoes', 'men', 'Botas de cuero Nik, sobrias y versátiles, con una silueta limpia para diario.', 'https://www.theoutnet.com/variants/images/46376663163055669/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163055669/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163055669/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163055669/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163055669/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163055669/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/paul-smith/boots/chelsea-boots/nik-leather-boots/46376663163055669', 588, 763.99, 'Llévelas con reloj de acero, blazer gris y lana oscura; perfume especiado y accesorios sin brillo excesivo.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-f468012c6135', 'mp-3d7ec08426d5', 'mp-c30d9d897570']::text[], 'Las botas brillan con bomber de corduroy, pantalón sobrio y silueta limpia: cálido, urbano y elegante. Perfecto para invierno y oficina creativa; Sauvage Parfum aporta especias, ambroxán y fondo amaderado.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-7dd6504e6feb', 'theoutnet', 'ton-1647597287645969', 'Neon Leather Mesh And Suede Hiking Boots', 'Alexander McQueen', 'shoes', 'women', 'Botas hiking en cuero, malla y gamuza con carácter urbano.', 'https://www.theoutnet.com/variants/images/1647597287645969/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597287645969/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597287645969/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597287645969/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597287645969/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597287645969/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/mcq-alexander-mcqueen/boots/ankle-boots/neon-leather-mesh-and-suede-hiking-boots/1647597287645969', 589, 764.99, 'Combínalas con reloj deportivo, perfume especiado y pantalón cargo oscuro con abrigo técnico negro.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-cf73e236b136', 'mp-6f0d137af367', 'mp-aa9cd49c4ded']::text[], 'Para ti, este conjunto equilibra abrigo y carácter: el vestido de punto aporta textura, el reloj suma precisión deportiva y el perfume de higo da un fondo fresco y elegante. Ideal para fines de semana fríos o una salida casual con estilo.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a45db5396207', 'jomashop', 'CZBN2029-01E', 'Citizen Promaster Aqualand Depth Meter Eco-Drive Men''s Watch', 'Citizen', 'watch', 'men', 'Promaster de inmersión con medidor de profundidad, técnico y confiable.', 'https://citizenwatch.widen.net/content/i9r3ddnueu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/i9r3ddnueu/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/iv1z6lnskv/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-aqualand-depth-meter-black-dial-mens-watch-bn202901e.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-aqualand-depth-meter-black-dial-mens-watch-bn202901e_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-aqualand-depth-meter-black-dial-mens-watch-bn202901e_3.jpg']::text[], 'https://www.jomashop.com/citizen-watch-bn2029-01e.html', 590.4, 765.99, 'Llévalo con perfume acuático, polo técnico y pantalón corto negro con zapatillas de alto agarre.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-44c11d07801c', 'mp-605a39d82c0f']::text[], 'Para ti, una combinación limpia y funcional: camiseta, sneakers y un perfume acuático-amaderado. Funciona perfecto para playa, paseo o viaje; el reloj acompaña con espíritu técnico y resistente, sin perder presencia.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-12add36cce18', 'theoutnet', 'ton-1647597355257129', 'Carla 70 Bow Detailed Patent Leather Pumps', 'Ferragamo', 'shoes', 'women', 'Slingback de charol con lazo, femenino y pulido para ocasiones especiales.', 'https://www.theoutnet.com/variants/images/1647597355257129/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597355257129/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597355257129/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597355257129/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597355257129/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597355257129/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/pumps/mid-heel-pumps/carla-70-bow-detailed-patent-leather-pumps/1647597355257129', 592, 767.99, 'Combínalas con perfume floral blanco, clutch negro y vestido satinado en tonos marfil o burdeos.', 'https://i.pinimg.com/736x/0e/f0/b8/0ef0b8d68a3710f2552bdd114aa5e043.jpg', ARRAY['mp-62b292ce9b64', 'mp-cb004bfbf1f3', 'mp-9b05bcfb7742']::text[], 'El vestido de línea pulida y los pumps de charol elevan el gesto nocturno con elegancia segura. Donna Born In Roma Intense suma un perfume floral-ambarado, sensual y moderno.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_not