://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw40ed8c7b/product-pictures/0e2ea75d-f09e-492c-896f-f00bbf0a9b5d_T137-207-11-111-00_Head.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-powermatic-80-automatic-chronometer-ladies-watch-t137-207-11-111-00.html', 594.24, 770.99, 'Acompáñalo con perfume limpio floral, blazer crema y pantalón recto gris con tacones nude.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-4309d7661011', 'mp-08cb860e5a5a', 'mp-db3e96bd55d9']::text[], 'El reloj PRX dialoga con el blazer estructurado y los loafers, logrando un conjunto pulcro para oficina y after office. Love In White añade una estela floral limpia y luminosa.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
