INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-505a7a8da7d4', 'theoutnet', 'ton-46376663163015337', 'Maceo Leather Over The Knee Boots', 'Jimmy Choo', 'shoes', 'women', 'Botas over the knee en cuero, sensuales y contundentes.', 'https://www.theoutnet.com/variants/images/46376663163015337/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163015337/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015337/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015337/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015337/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015337/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/boots/over-the-knee-boots/maceo-leather-over-the-knee-boots/46376663163015337', 594, 770.99, 'Combínalas con reloj pulido, perfume especiado y vestido negro corto o abrigo largo en lana.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-dcde323f0351', 'mp-21f8ec52e6da', 'mp-81d52947c289']::text[], 'Las botas altas se equilibran con el abrigo de lana y un reloj sutil para un look casual sofisticado de invierno. Dama Bianca añade un velo almizclado-vainilla, suave y elegante.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c54c681189c8', 'theoutnet', 'ton-1647597359516012', 'Drive 60 Metallic Cracked Leather Wedge Sandals', 'Jimmy Choo', 'shoes', 'women', 'Sandalias metálicas con cuña y brillo moderno para destacar con medida.', 'https://www.theoutnet.com/variants/images/1647597359516012/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597359516012/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597359516012/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597359516012/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597359516012/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597359516012/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/espadrilles/mid-heel-espadrilles/drive-60-metallic-cracked-leather-wedge-sandals/1647597359516012', 595, 771.99, 'Úsalas con reloj fino, perfume oriental suave y vestido midi satinado en plata o negro.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-43caf9831f12', 'mp-3e1b992662c2', 'mp-907d601e36bb']::text[], 'Sandalias metálicas, satinados y reloj champagne forman un conjunto brillante pero contenido, ideal para cóctel o gala. Royal Princess Oud suma profundidad floral-amaderada con presencia distinguida.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
