=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw47914f2f/product-pictures/015b1cad-997c-4fec-9b81-5c224e184569_T137-407-11-041-00_AMB_1.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-t-classic-automatic-blue-dial-mens-watch-t137-407-11-041-00.html', 595.68, 772.99, 'Combínalo con perfume cítrico amaderado, camisa blanca y blazer gris con pantalón azul marino.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-2ad272892924', 'mp-6e78cd2c0e9e', 'mp-4520d6ec87f1']::text[], 'Para ti, el PRX luce impecable con camisa nítida, mocasines pulidos y vetiver sobrio. El conjunto transmite seguridad serena para oficina o almuerzos de negocio, con un acabado refinado y nada estridente.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ff959d454450', 'jomashop', 'TIST1204071704100', 'Tissot Seastar 1000 Automatic Blue Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Seastar azul con espíritu náutico y resistencia para días activos.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dweba5ba39/product-pictures/03ab9cd8-17bc-4a1e-9106-a7c437b30ac3_T120-407-17-041-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dweba5ba39/product-pictures/03ab9cd8-17bc-4a1e-9106-a7c437b30ac3_T120-407-17-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dweba5ba39/product-pictures/03ab9cd8-17bc-4a1e-9106-a7c437b30ac3_T120-407-17-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw070b6353/product-pictures/14d8f19d-6fdc-42ab-9d87-3d407f63cc29_T120-407-17-041-00_Profil.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe7ae37a5/product-pictures/e4e8500b-9ebc-45cb-a4ec-f26824b5bad9_T120_407_17_041_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw8b655731/product-pictures/a6156602-ebeb-4090-8ae3-ea20e1865320_T120_407_17_041_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw347fa3d9/product-pictures/7800cf88-aea6-452c-9514-8c078a577928_T120_407_17_041_00_DETAIL-1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw86f97f23/product-pictures/9633b13a-8337-40d2-ac16-0e134af64a91_T120_407_17_041_00_DETAIL-2.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-seastar-1000-watch-t1204071704100.html', 596.4, 773.99, 'Llévalo con perfume marino, polo técnico y bermudas beige con zapatillas blancas o náuticos.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-68a041916a67', 'mp-2abd9b8ccfe5', 'mp-60727c51909d']::text[], 'Para ti, este look se siente relajado pero cuidado: camiseta de algodón, sneakers versátiles y un perfume clásico, fresco y limpio. Es una fórmula ideal para ciudad, paseo de fin de semana o planes informales junto al mar.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-41a3121d7f90', 'theoutnet', 'ton-46376663163167004', 'Craxon Suede Loafers', 'Bally', 'shoes', 'men', 'Mocasines de ante, suaves y refinados, para un porte discreto de oficina.', 'https://www.theoutnet.com/variants/images/46376663163167004/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163167004/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163167004/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163167004/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163167004/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163167004/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/bally/flat-shoes/loafers/craxon-suede-loafers/46376663163167004', 598, 775.99, 'Combínelos con reloj clásico, camisa celeste y pantalón marino; perfume limpio y cinturón de cuero café.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-03dd349adfdf', 'mp-c30d9d897570', 'mp-9c175b220b04']::text[], 'Para ti, los loafers encuentran su mejor marco con la chaqueta de punto estructurada, el PRX y un vetiver elegante. El resultado es discreto y pulido, perfecto para oficina o cenas donde el detalle marca la diferencia.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-69b7dd1cdf49', 'jomashop', 'CZBN4065-07L', 'Citizen Promaster Altichron Eco-Drive Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Altichron azul con lectura aventurera y presencia técnica precisa.', 'https://citizenwatch.widen.net/content/vmzrm3xrzx/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/vmzrm3xrzx/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/mj5fsyp4lt/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/vi9q6hmasg/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/odeapwy2up/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-altichron-ecodrive-blue-dial-mens-watch-bn406507l_1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-altichron-ecodrive-blue-dial-mens-watch-bn406507l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-altichron-ecodrive-blue-dial-mens-watch-bn406507l_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-altichron-eco-drive-blue-dial-mens-watch-bn4065-07l.html', 599, 776.99, 'Combínalo con perfume verde aromático, chaqueta softshell y pantalón cargo oliva con botas trekking.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-f63eb8828e5a', 'mp-169aade8e57a', 'mp-21708b443c49']::text[], 'Para ti, una propuesta técnica y fresca: hoodie suave, sneakers de ante y un perfume marino intenso. Va muy bien para actividades al aire libre, viajes o fines de semana activos, con energía y limpieza visual.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
