INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a92e8d528d52', 'jomashop', 'Z-2MJDR', 'Creed Unisex Oud Zarian EDP Spray 3.4 oz', 'Creed', 'perfume', 'unisex', 'Oud profundo y envolvente, con presencia serena y un sello oriental refinado.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-unisex-oud-zarian-edp-spray-34-oz-fragrances-3508440004130.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-unisex-oud-zarian-edp-spray-34-oz-fragrances-3508440004130.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-unisex-oud-zarian-edp-spray-34-oz-fragrances-3508440004130_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-unisex-oud-zarian-edp-spray-34-oz-fragrances-3508440004130_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/r/creed-unisex-oud-zarian-edp-spray-34-oz-fragrances-3508440004130_7.jpg', 'https://rougeb2car.vtexassets.com/arquivos/ids/248500/3508440004130_2.jpg?v=638981374095870000']::text[], 'https://www.jomashop.com/creed-unisex-oud-zarian-edp-spray-3-4-oz-fragrances-3508440004130.html', 606.24, 785.99, 'Con reloj de acero gris, abrigo camel y mocasines negros; añade lana, cuero liso y perfume ambarado.', 'https://thefemmena.com/wp-content/uploads/2024/04/quiet-luxury-outfit-ideas-anoukyve.jpeg', ARRAY['mp-0c0fab912d30', 'mp-31785b0725f8', 'mp-a7fbae0e4ca7']::text[], 'Para ti, el perfume se acompaña muy bien de un mini vestido de punto, botas altas y un reloj delicado. Funciona de noche o en invierno, con una silueta refinada y un aroma oud profundo, cálido y seductor.', 'elegante', ARRAY['mp-381d102f4ffc', 'mp-a9ffba2f285a', 'mp-904838f23367']::text[], 'Oud Zarian exige texturas ricas: cashmere, botas altas y un reloj elegante. Es un conjunto perfecto para noche de invierno, con aire opulento; el perfume resulta oscuro, resinoso y sofisticado.', 'invierno') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
