loafers y un perfume limpio, moderno y ligeramente amaderado. Es una combinación versátil para oficina o viajes, con aire técnico y elegancia contenida.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1b2509cb8018', 'theoutnet', 'ton-1647597335087454', 'Tan go Patent Leather Platform Sandals', 'Valentino', 'shoes', 'women', 'Sandalias de plataforma en charol, gráficas y pulidas, con presencia de noche.', 'https://www.theoutnet.com/variants/images/1647597335087454/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597335087454/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597335087454/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597335087454/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597335087454/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597335087454/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/valentino-garavani/sandals/high-heel-sandals/tan-go-patent-leather-platform-sandals/1647597335087454', 612, 792.99, 'Acompáñelas con reloj fino, vestido satinado negro y perfume ámbar; cierre con clutch rígido y labios neutros.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-43caf9831f12', 'mp-3e1b992662c2', 'mp-907d601e36bb']::text[], 'Las plataformas de charol encuentran equilibrio en satén fluido y un reloj de tono cálido. Conjunto perfecto para cena o evento formal; el perfume añade oud suave, cremoso y lujoso, de estela contenida.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9e8af89ce341', 'theoutnet', 'ton-1647597355286016', 'Farah Leather Boots', 'Ferragamo', 'shoes', 'women', 'Bota de cuero sobria, de línea limpia y tacto pulcro para diario elegante.', 'https://www.theoutnet.com/variants/images/1647597355286016/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597355286016/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597355286016/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597355286016/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597355286016/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597355286016/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/boots/ankle-boots/farah-leather-boots/1647597355286016', 612, 792.99, 'Con reloj de acero cepillado, abrigo de lana y pantalón sastre; perfume amaderado y zapatos negros.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-e49d2abf765f', 'mp-87c1eb6527f0', 'mp-81d52947c289']::text[], 'Las botas Ferragamo se suavizan con un blazer estructurado, reloj luminoso y un perfume de aura limpia. Ideal para otoño o fin de semana elegante; la fragancia es empolvada, almizclada y delicadamente floral.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2ef30783efc4', 'theoutnet', 'ton-46376663163158830', 'Tom Padded Suede Sandals', 'MR P.', 'shoes', 'men', 'Sandalias acolchadas de ante, relajadas y pulidas, perfectas para días cálidos.', 'https://www.theoutnet.com/variants/images/46376663163158830/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163158830/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158830/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158830/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158830/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158830/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163158830/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/mr-p/sandals/flat-sandals/tom-padded-suede-sandals/46376663163158830', 615, 796.99, 'Úselas con reloj deportivo sobrio, camisa de lino blanca y short beige; perfume fresco y tonos arena.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-16dc129ea1db', 'mp-8d5bb353d59a', 'mp-5e3a9020fb17']::text[], 'Para ti, estas sandalias van mejor con sobrecamisa de lino, pantalón ligero y un neroli fresco, cítrico y refinado. El conjunto es ideal para verano, almuerzos junto al mar o escapadas relajadas con un aire muy pulido.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d7d759721bdc', 'theoutnet', 'ton-46376663163015356', 'Maceo 85 Leather Over The Knee Boots', 'Jimmy Choo', 'shoes', 'women', 'Bota sobre la rodilla con líneas precisas que alarga y afina la silueta.', 'https://www.theoutnet.com/variants/images/46376663163015356/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163015356/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015356/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015356/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015356/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015356/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/boots/over-the-knee-boots/maceo-85-leather-over-the-knee-boots/46376663163015356', 617, 798.99, 'Con reloj delgado, vestido midi oscuro y abrigo estructurado; perfume cálido y accesorios mínimos.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-4309d7661011', 'mp-217a0ab70ad2', 'mp-8cf3908f3eee']::text[], 'Las botas over the knee ganan equilibrio con un blazer crepé y un reloj nacarado. Perfecto para un look casual elevado; el perfume aporta gardenia cremosa, femenina y pulida, ideal de día o tarde.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2f613086f7f8', 'jomashop', 'TIST1208073305100', 'Tissot Seastar 1000 Automatic Graded Grey-Black Dial Watch', 'Tissot', 'watch', 'unisex', 'Diver automático en gris humo, robusto y sobrio para ritmo urbano.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-automatic-graded-greyblack-dial-watch-t1208073305100.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-automatic-graded-greyblack-dial-watch-t1208073305100.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-automatic-graded-greyblack-dial-watch-t1208073305100_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-automatic-graded-greyblack-dial-watch-t1208073305100_3.jpg', 'https://www.guestandphilips.co.uk/images/shop/more/760x1176_386471_12ea4ee784de5449b094a427a13b9b42_1726678179T1208073305100.jpg', 'https://res.cloudinary.com/dp9dnliwc/image/upload/c_mfit,h_1200,w_1200/f_auto/q_auto/wmmedia/watch_images/large/t1208073305100_1731946593.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-1000-automatic-graded-grey-black-dial-watch-t1208073305100.html', 618.62, 800.99, 'Con reloj ya definido; camisa oxford, knit marino y zapatillas blancas o botas de cuero.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-015d339460d4', 'mp-d989491a5eb9', 'mp-605a39d82c0f']::text[], 'Para ti, este Seastar luce más refinado con trench arquitectónico, sneakers esculturales y un perfume suave, etéreo y contemporáneo. Es una propuesta ideal para entretiempo, con presencia limpia y un lujo muy discreto.', 'lujo-silencioso', ARRAY['mp-fc52850a61fd', 'mp-f82c020821e8', 'mp-6195e4aa6adf']::text[], 'Con parka técnica, sneakers y una fragancia ligera, el Seastar queda listo para escapadas y fines de semana. Ideal en clima fresco; Flying aporta un perfil aireado, limpio y etéreo.', 'deportivo') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9072e4537da0', 'jomashop', 'TIST1208072205101', 'Tissot Seastar 1000 Automatic Graded Grey-Black Dial Watch', 'Tissot', 'watch', 'unisex', 'Divers gris-negro de presencia contenida, ideal para un uso activo y elegante.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwd9abba2e/product-pictures/93130aca-712d-4d99-a37a-21646344312d_T120-807-22-051-01_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwd9abba2e/product-pictures/93130aca-712d-4d99-a37a-21646344312d_T120-807-22-051-01_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwd9abba2e/product-pictures/93130aca-712d-4d99-a37a-21646344312d_T120-807-22-051-01_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwaecc8b25/product-pictures/2ffca054-656c-4759-9819-2b70a6bfd127_T120-807-22-051-01_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb5dadc61/product-pictures/ecb6832c-6d32-49b7-be70-610d36d133d2_T120-807-22-051-01_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw43a36979/product-pictures/0cfc309f-93f5-42a9-84d9-e70a3cd6735a_T120-807-22-051-01_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwd3343425/product-pictures/3ce52a84-ad81-4c41-a705-d9de785b87aa_T120-807-22-051-01.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe085faa4/product-pictures/436d55c0-b1eb-4c62-a05e-60521931ee2b_T120-807-22-051-01_head.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-seastar-1000-automatic-graded-grey-black-dial-watch-t1208072205101.html', 618.62, 800.99, 'Con reloj ya definido; polo blanco, pantalón técnico oscuro y zapatillas de cuero o loafers.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-015d339460d4', 'mp-d989491a5eb9', 'mp-605a39d82c0f']::text[], 'Para ti, la mezcla de mini vestido de punto, sneakers de suela marcada y un clásico limpio crea un look actual y cómodo. Ideal para días frescos; el perfume aporta una frescura refinada, ligeramente cítrica y elegante.', 'casual', ARRAY['mp-c63686b7891d', 'mp-f82c020821e8', 'mp-8d5bb353d59a']::text[], 'La Seastar se equilibra con chaleco cálido, sneakers y una nota fresca de Neroli Portofino: cítrica, transparente y elegante. Perfecto para casual de día, viajes o verano junto al mar.', 'deportivo') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-abc135310ab3', 'theoutnet', 'ton-46376663163015358', 'Cierra 100 Suede Over The Knee Boots', 'Jimmy Choo', 'shoes', 'women', 'Ante sobre la rodilla con caída limpia y una silueta sensorial y precisa.', 'https://www.theoutnet.com/variants/images/46376663163015358/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163015358/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015358/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015358/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015358/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163015358/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/boots/over-the-knee-boots/cierra-100-suede-over-the-knee-boots/46376663163015358', 618, 800.99, 'Con reloj fino, vestido negro o chocolate y abrigo largo; perfume ámbar seco.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-e49d2abf765f', 'mp-87c1eb6527f0', 'mp-81d52947c289']::text[], 'Las botas de ante se equilibran con un blazer suave, reloj discreto y perfume limpio. Ideal para otoño en Lima o un almuerzo elegante; la fragancia es aterciopelada, empolvada y ligeramente floral.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_id