INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-08cea9481d14', 'jomashop', 'TIST1374071135100', 'Tissot PRX Powermatic 80 Automatic Ice Blue Dial Men''s Watch', 'Tissot', 'watch', 'men', 'PRX de hielo azul, moderno y equilibrado, con un brillo contenido.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe2f8f9e3/product-pictures/5f0c9cb0-604a-476e-8ba7-563133b91d5c_T137-407-11-351-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe2f8f9e3/product-pictures/5f0c9cb0-604a-476e-8ba7-563133b91d5c_T137-407-11-351-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe2f8f9e3/product-pictures/5f0c9cb0-604a-476e-8ba7-563133b91d5c_T137-407-11-351-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw16dd7389/product-pictures/420ed2bc-3fb5-4570-9734-c1f71dab41a2_T137_407_11_351_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw68894fd3/product-pictures/a25e6739-1a25-4827-b9ff-58da52ae42a4_T137_407_11_351_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw4b19a5d6/product-pictures/df9ac882-eb16-40b9-b0f2-5fe1910e5686_T137_407_11_351_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwc538fa47/product-pictures/59b8e7b1-d4cd-44a9-a34f-553129a984c5_T137_407_11_351_00.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw00813e66/product-pictures/0236ed75-16dd-458e-b78b-fcd9b4445e70_T137-407-11-351-00_Head.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-powermatic-80-automatic-ice-blue-dial-mens-watch-t137-407-11-351-00.html', 619.2, 801.99, 'Con camisa blanca, blazer gris y loafers de cuero; perfume fresco amaderado y reloj como centro.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-4af1908c0185', 'mp-6e78cd2c0e9e', 'mp-4520d6ec87f1']::text[], 'Para un look impecable de oficina o cena discreta, combina el reloj con una camisa de lino suave, mocasines de cuero y Grey Vetiver: limpio, seco y elegante, con una presencia sobria que realza el dial ice blue sin competir con él.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-826b38279ee9', 'theoutnet', 'ton-46376663163074567', 'Metallic Open Knit Maxi Dress', 'Tom Ford', 'clothing', 'women', 'Vestido maxi de punto metálico, fluido y luminoso, pensado para una entrada memorable.', 'https://www.theoutnet.com/variants/images/46376663163074567/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163074567/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074567/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074567/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074567/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163074567/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/tom-ford/dresses/maxi-dresses/metallic-open-knit-maxi-dress/46376663163074567', 623, 806.99, 'Llévelo con reloj joya, sandalias negras y perfume oriental; añada clutch minimalista y pendientes finos.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-1b2509cb8018', 'mp-3e1b992662c2', 'mp-907d601e36bb']::text[], 'El tejido abierto del vestido pide sandalias fuertes, un reloj champagne y un perfume de raíz noble. Perfecto para noche y clima templado; la fragancia aporta oud cremoso, elegante y muy femenino.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-43caf9831f12', 'theoutnet', 'ton-46376663163079535', 'Embellished Draped Satin Dress', 'Versace', 'clothing', 'women', 'Satinado drapeado con brillo medido, pensado para destacar con sofisticación.', 'https://www.theoutnet.com/variants/images/46376663163079535/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163079535/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079535/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079535/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079535/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079535/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/dresses/knee-length-dresses/embellished-draped-satin-dress/46376663163079535', 623, 806.99, 'Con reloj joya o minimalista, sandalias negras y clutch; perfume floral intenso y abrigo negro.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-2149c170339c', 'mp-3e1b992662c2', 'mp-c0c58bfbda63']::text[], 'El satén drapeado luce mejor con pumps joya y un reloj de esfera cálida. Ideal para gala o cóctel; el perfume suma frutas maduras, flores blancas y un fondo aterciopelado, muy sofisticado.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-38d330ee3c81', 'jomashop', 'TIST1208071109100', 'Tissot Seastar 1000 Automatic Unisex Watch', 'Tissot', 'watch', 'unisex', 'Automático unisex de espíritu marino, sobrio y versátil para todos los días.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwede95d9e/product-pictures/aab7efde-3a92-49ff-8937-e90a317512e9_T120-807-11-091-00_Shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwede95d9e/product-pictures/aab7efde-3a92-49ff-8937-e90a317512e9_T120-807-11-091-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwede95d9e/product-pictures/aab7efde-3a92-49ff-8937-e90a317512e9_T120-807-11-091-00_Shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw18a93d48/product-pictures/a6caf9b6-7d52-4644-88d1-541ccf22d9a1_T120_807_11_091_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw5df81d72/product-pictures/037227cf-5810-492e-9882-22ccea46a6b2_T120-807-11-091-00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwec23d01c/product-pictures/e9900807-c62a-4866-a84c-b5b9d47fcbc2_T120_807_11_091_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwf6956957/product-pictures/98cb15d8-4aa9-4079-bbbc-18db3a43252e_T120-807-11-091-00_DETAIL-1-psd.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe8a6447a/product-pictures/adad98a3-d091-4986-b342-a839e01d249f_T120_807_11_091_00.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-t-sport-automatic-unisex-watch-t1208071109100.html', 625, 808.99, 'Con reloj ya definido; polo crema, pantalón azul marino y sneakers blancas o mocasines.', 'https://lifewithjazz.com/wp-content/uploads/2021/02/howtostyleathleisureoutfits.jpg', ARRAY['mp-015d339460d4', 'mp-d989491a5eb9', 'mp-605a39d82c0f']::text[], 'Para un look casual pulido, suma la gabardina con sneakers limpios y Replica Flying: fresco, mineral y moderno. El conjunto aporta ligereza y carácter, ideal para días templados en Lima sin dejar de verse cuidado.', 'casual', ARRAY['mp-c63686b7891d', 'mp-765403f77c4f', 'mp-6a32aace5e0a']::text[], 'Para tu Seastar unisex, el chaleco suave y las sneakers de shell dan una lectura contemporánea y cómoda. Ideal para verano activo; Neroli Sauvage huele cítrico, luminoso y limpio.', 'deportivo') ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3033ac5579ed', 'theoutnet', 'ton-46376663163159953', 'Embellished Floral Print Chainmail Mini Dress', 'Versace', 'clothing', 'women', 'Minivestido de malla con flores, audaz y escultórico para una noche marcada.', 'https://www.theoutnet.com/variants/images/46376663163159953/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163159953/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159953/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159953/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159953/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163159953/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/dresses/mini-dresses/embellished-floral-print-chainmail-mini-dress/46376663163159953', 629, 813.99, 'Con reloj pequeño en metal, sandalias finas y clutch negro; perfume floral ambarado y abrigo liso.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-2149c170339c', 'mp-3e1b992662c2', 'mp-b2bac3c4aeeb']::text[], 'La mini dress pide tacón joya, reloj champán y un perfume de corte regio. Ideal para noche de verano o evento formal; la fragancia es ambarada, floral y con un oud delicado y envolvente.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, rec