INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ad4eb6159840', 'theoutnet', 'ton-46376663163156893', 'Katissima 45 Embellished Patent Leather Point Toe Pumps', 'Christian Louboutin', 'shoes', 'women', 'Salones de punta fina con brillo sutil, perfectos para elevar el día.', 'https://www.theoutnet.com/variants/images/46376663163156893/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163156893/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163156893/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163156893/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163156893/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163156893/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/christian-louboutin/pumps/mid-heel-pumps/katissima-45-embellished-patent-leather-point-toe-pumps/46376663163156893', 629, 813.99, 'Llévalos con reloj clásico, perfume floral seco y sastre gris, camel o azul marino.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-4309d7661011', 'mp-3e1b992662c2', 'mp-d3b04c599098']::text[], 'Con blazer estructurado y reloj PRX champagne, tus pumps elevan cualquier día de oficina. Es un conjunto pulido y seguro; Infusion de Rose añade un rosa limpio, delicado y elegante.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.sty