INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-15a9c8590930', 'theoutnet', 'ton-1647597359172609', 'Alva 120 Glittered Metallic Leather Platform Sandals', 'Jimmy Choo', 'shoes', 'women', 'Sandalia plataforma con brillo metálico, hecha para elevar la noche con seguridad.', 'https://www.theoutnet.com/variants/images/1647597359172609/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597359172609/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597359172609/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597359172609/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597359172609/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597359172609/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/sandals/high-heel-sandals/alva-120-glittered-metallic-leather-platform-sandals/1647597359172609', 635, 821.99, 'Con reloj fino, vestido negro o plata y clutch rígido; perfume intenso y líneas depuradas.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-62b292ce9b64', 'mp-3e1b992662c2', 'mp-58072ada40a0']::text[], 'Un vestido de un solo hombro y un perfume de cuero cálido elevan estas sandalias a una noche de gala. El reloj champagne aporta brillo refinado sin competir, logrando un conjunto potente, femenino y sofisticado.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_