g_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ca76d9740f44', 'jomashop', 'CZNB6026-56L', 'Citizen Promaster Marine Automatic Blue Dial Men''s Watch', 'Citizen', 'watch', 'men', 'Cronógrafo marino azul, preciso y funcional con una estética contenida.', 'https://citizenwatch.widen.net/content/lyir02ai5j/webp?width=1600&height=2000&quality=85&crop=false&keep=c', ARRAY['https://citizenwatch.widen.net/content/lyir02ai5j/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/oudo5k8p83/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/sh48oydlgt/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://citizenwatch.widen.net/content/ouli0ui9j8/webp?width=1600&height=2000&quality=85&crop=false&keep=c', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-marine-automatic-blue-dial-mens-watch-nb602656l.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-marine-automatic-blue-dial-mens-watch-nb602656l_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/c/i/citizen-promaster-marine-automatic-blue-dial-mens-watch-nb602656l_3.jpg']::text[], 'https://www.jomashop.com/citizen-promaster-marine-automatic-blue-dial-mens-watch-nb6026-56l.html', 639, 825.99, 'Con reloj ya definido; polo blanco, pantalón beige y náuticos o zapatillas marino y gris.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-a47f229935b7', 'mp-d989491a5eb9', 'mp-60727c51909d']::text[], 'Pants técnicos y sneakers sobrios acompañan naturalmente este Promaster de espíritu acuático. Sauvage aporta energía limpia, aromática y fresca, perfecta para fin de semana, viajes o clima cálido con un aire deportivo refinado.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b07456fe8471', 'theoutnet', 'ton-1647597347231760', 'Metallic Leather Sandals', 'Ferragamo', 'shoes', 'women', 'Sandalia metálica de cuero, luminosa y limpia para días y noches cálidas.', 'https://www.theoutnet.com/variants/images/1647597347231760/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597347231760/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597347231760/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597347231760/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597347231760/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597347231760/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/sandals/high-heel-sandals/metallic-leather-sandals/1647597347231760', 640, 827.99, 'Con reloj pulido, vestido blanco o lino arena y bolso estructurado; perfume cítrico y joyería mínima.', 'https://www.styleatacertainage.com/wp-content/uploads/2025/06/Quince-Linen-Picks.png', ARRAY['mp-a3b7700027eb', 'mp-9b05bcfb7742', 'mp-aa9cd49c4ded']::text[], 'El vestido floral mantiene el look ligero y femenino, mientras las sandalias metálicas suman elegancia sin peso. El reloj plateado y la fragancia de higo refuerzan un verano chic, luminoso y relajado.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-29a793dca8a1', 'theoutnet', 'ton-46376663163154994', 'Etana 50 Crystal Embellished Satin Mules', 'Jimmy Choo', 'shoes', 'women', 'Mule de satén con cristal, delicado y escultural para un perfil sofisticado.', 'https://www.theoutnet.com/variants/images/46376663163154994/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163154994/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154994/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154994/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154994/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163154994/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/sandals/mid-heel-sandals/etana-50-crystal-embellished-satin-mules/46376663163154994', 641, 828.99, 'Con reloj delgado, slip dress negro y abrigo de lana; perfume floral oscuro y metal pulido.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-8775c04c75ac', 'mp-76d7d1376454', 'mp-b2bac3c4aeeb']::text[], 'El satén cristalizado pide un vestido de textura rica y brillo contenido. El reloj ice blue aporta contraste fresco y el oud real añade profundidad floral-amaderada, perfecto para una noche formal y muy pulida.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d878d30bedee', 'jomashop', 'SE-SSC965', 'Seiko Prospex Chronograph Quartz Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Cronógrafo azul de aire náutico, práctico y limpio para una rutina con estilo.', 'https://www.seikowatches.com/global-en/-/media/Images/GlobalEn/Seiko/Home/products/prospex/product_detail/SPEEDTIMER_260202/SSC965P1_01_1x1.jpg?mh=630&mw=1120&hash=2ECFFDA99B48221B3D447422FEE39171', ARRAY['https://www.seikowatches.com/global-en/-/media/Images/GlobalEn/Seiko/Home/products/prospex/product_detail/SPEEDTIMER_260202/SSC965P1_01_1x1.jpg?mh=630&mw=1120&hash=2ECFFDA99B48221B3D447422FEE39171', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-chronograph-quartz-blue-dial-mens-watch-ssc965.jpg', 'https://www.watchpro.com/cloud/2026/02/04/OaeZauXa-SSC965_Seikoboutique.co_.uk_640-1-1024x1024.jpg', 'https://www.juweliervandam.nl/cdn/shop/files/SSC965P1_ima_1_2025.png?v=1770216308&width=2400', 'https://www.seikowatches.com/pt-pt/-/media/Images/Portugal/Seiko/Home/products/prospex/seiko-prospex-speedtimer-ssc965p1-ogp.jpg']::text[], 'https://www.jomashop.com/seiko-prospex-chronograph-quartz-blue-dial-mens-watch-ssc965.html', 649.99, 839.99, 'Con reloj ya definido; camisa celeste, denim oscuro y sneakers blancas o mocasines de gamuza.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-16dc129ea1db', 'mp-d989491a5eb9', 'mp-605a39d82c0f']::text[], 'La cronografía azul combina con overshirt y sneakers de aire limpio, creando un conjunto versátil y masculino. Luna Rossa Carbon aporta una frescura mineral y moderna, ideal para uso diario con estética deportiva sofisticada.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-50ab1087ee6f', 'theoutnet', 'ton-46376663162857791', 'Toile Iconographe Jacquard Slides', 'Valentino', 'shoes', 'women', 'Slides con jacquard Toile Iconographe, limpias y distintivas, para un verano refinado.', 'https://www.theoutnet.com/variants/images/46376663162857791/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663162857791/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162857791/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162857791/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162857791/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663162857791/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/valentino-garavani/sandals/flat-sandals/toile-iconographe-jacquard-slides/46376663162857791', 652, 841.99, 'Úselas con reloj de cuero claro, camisa de lino y pantalón crema; perfume cítrico y bolso tejido.', 'https://www.styleatacertainage.com/wp-content/uploads/2025/06/Quince-Linen-Picks.png', ARRAY['mp-eccea3334d40', 'mp-0011f169d584', 'mp-6a32aace5e0a']::text[], 'Las slides encajan con un vestido midi ligero y una estética vacacional elegante. El Seastar añade un guiño náutico y Neroli Sauvage aporta cítricos limpios y solares, ideal para verano en ciudad o escapada.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-82b04d22028d', 'theoutnet', 'ton-46376663163079558', 'Belted Floral Print Silk Blend Georgette Midi Dress', 'Versace', 'clothing', 'women', 'Midi de georgette floral con cinturón, fluido y femenino con movimiento.', 'https://www.theoutnet.com/variants/images/46376663163079558/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163079558/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079558/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079558/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079558/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079558/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/dresses/knee-length-dresses/belted-floral-print-silk-blend-georgette-midi-dress/46376663163079558', 652, 841.99, 'Con reloj fino, sandalias nude y bolso de rafia; perfume fresco floral y blazer marfil.', 'https://www.styleatacertainage.com/wp-content/uploads/2025/06/Quince-Linen-Picks.png', ARRAY['mp-b07456fe8471', 'mp-3e1b992662c2', 'mp-8cf3908f3eee']::text[], 'El vestido floral y las sandalias metálicas construyen un look femenino, fresco y pulido para almuerzo o cóctel de día. El reloj champagne y gardenia suave completan una elegancia luminosa y muy estival.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
