o_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-410606d42af9', 'jomashop', 'TIST1374073304100', 'Tissot PRX Automatic Blue Dial Men''s Watch', 'Tissot', 'watch', 'men', 'PRX automático azul, equilibrado y moderno, con presencia sobria y segura.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw890c700c/product-pictures/daab9283-862f-4732-abd0-fa955e11d7bd_T137-407-33-041-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw890c700c/product-pictures/daab9283-862f-4732-abd0-fa955e11d7bd_T137-407-33-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw890c700c/product-pictures/daab9283-862f-4732-abd0-fa955e11d7bd_T137-407-33-041-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwcf715b95/product-pictures/b33cc289-d828-45f2-a1ac-1a12e7b09fac_T137-407-33-041-00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwab9a8382/product-pictures/84417eec-2423-45d5-94ba-fb50b687fb86_T137-407-33-041-00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw54fb1a47/product-pictures/850ca710-858d-4e32-897f-ec26a43d054a_T137-407-33-041-00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw8422075e/product-pictures/a604a736-340e-47c5-8a4a-beaa613637a0_T137-407-33-041-00.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw0ffdd24d/product-pictures/722474f0-e144-411b-9690-f41639f01378_T137-407-33-041-00_HEAD.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-automatic-blue-dial-mens-watch-t1374073304100.html', 656.64, 847.99, 'Con camisa blanca, traje gris o denim oscuro y loafers; perfume fresco amaderado y reloj protagonista.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-4af1908c0185', 'mp-7795ae7c1d60', 'mp-ae99e2aca74c']::text[], 'Camisa de lino, loafers sobrios y el azul del PRX crean un código impecable, ligero y urbano. Gentleman Reserve Privée suma un acorde amaderado y cálido, perfecto para oficina y after office.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d45616b11308', 'theoutnet', 'ton-46376663163066713', 'Klem Pebbled Leather Ankle Boots', 'Ferragamo', 'shoes', 'women', 'Botín de cuero granulado, pulcro y resistente, con elegancia diaria.', 'https://www.theoutnet.com/variants/images/46376663163066713/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163066713/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163066713/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163066713/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163066713/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163066713/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/ferragamo/boots/ankle-boots/klem-pebbled-leather-ankle-boots/46376663163066713', 661, 853.99, 'Con reloj de acero, pantalón de lana y abrigo camel; perfume amaderado y prendas en negro o gris.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-e49d2abf765f', 'mp-87a3ff47cf1a', 'mp-70ebe553f139']::text[], 'Las líneas depuradas del abrigo y el tacón cerrado refuerzan un look de invierno elegante y contenido. Le Locle aporta clasicismo, mientras Royal Oud añade profundidad resinosa y noble, ideal para oficina sofisticada.', 'invierno', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c5006cb8c599', 'theoutnet', 'ton-1647597306532755', 'Tulle Paneled Cotton Gabardine Trench Coat', 'Maison Margiela', 'clothing', 'women', 'Trench con paneles de tul, ligero y preciso, entre arquitectura y movimiento.', 'https://www.theoutnet.com/variants/images/1647597306532755/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597306532755/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306532755/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306532755/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306532755/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597306532755/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/maison-margiela/coats/raincoats-trench-coats/tulle-paneled-cotton-gabardine-trench-coat/1647597306532755', 663, 855.99, 'Con reloj minimalista, pantalón sastre y mocasines; perfume limpio y tonos arena, blanco y negro.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-d45616b11308', 'mp-b3356dd10948', 'mp-6a32aace5e0a']::text[], 'El trench de gabardina se ve moderno con botas pulidas y un PRX azul de presencia discreta. Neroli Sauvage aporta frescura limpia y elegante, perfecta para entretiempo, oficina relajada o salidas urbanas.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-62b292ce9b64', 'theoutnet', 'ton-46376663163062248', 'One Shoulder Silk Cady Dress', 'Versace', 'clothing', 'women', 'Silk cady de un hombro, fluido y preciso para una elegancia nocturna.', 'https://www.theoutnet.com/variants/images/46376663163062248/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163062248/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163062248/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163062248/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163062248/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163062248/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/dresses/knee-length-dresses/one-shoulder-silk-cady-dress/46376663163062248', 664, 856.99, 'Con reloj fino, tacones negros y clutch pequeño; perfume floral ámbar y abrigo estructurado.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-29a793dca8a1', 'mp-3e1b992662c2', 'mp-58072ada40a0']::text[], 'La silueta de un hombro único pide mules joya y un reloj champagne para una lectura glamorosa y precisa. Tuscan Leather suma cuero oscuro y sensual, ideal para una noche formal.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_