_021_00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-powermatic-80-automatic-champagne-dial-ladies-watch-t1372073302100.jpg']::text[], 'https://www.jomashop.com/tissot-prx-powermatic-80-automatic-champagne-dial-ladies-watch-t1372073302100.html', 665.76, 858.99, 'Llévelo con traje beige o camel, mocasines de cuero y perfume floral ambarado para un look pulido.', 'https://www.chicstylecollective.com/wp-content/uploads/2025/02/Belted-Bags-Trend.jpg', ARRAY['mp-e49d2abf765f', 'mp-50846d387b41', 'mp-d3b04c599098']::text[], 'El tono champagne del reloj armoniza con sastrería suave y pumps de líneas clásicas. Infusion diris aporta limpieza floral-almizclada, perfecta para oficina, reuniones y una elegancia serena durante todo el día.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
