00.png?sm=fit&sw=1600&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-prx-powermatic-80-automatic-champagne-dial-mens-watch-t1374073302100_1.jpg']::text[], 'https://www.jomashop.com/tissot-prx-powermatic-80-automatic-champagne-dial-mens-watch-t1374073302100.html', 665.76, 858.99, 'Combínelo con camisa blanca, pantalón gris y zapatos negros; sume perfume amaderado limpio.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-149ae652798d', 'mp-f72ed8b412b3', 'mp-d3b04c599098']::text[], 'El tono champagne del reloj armoniza con el lino claro y los loafers pulidos para una oficina refinada. Grey Vetiver aporta frescura seca y elegante, ideal para Lima y jornadas de clima templado.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
