00&sh=1600', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/t/i/tissot-seastar-1000-automatic-black-dial-mens-watch-t1204071105100-t1204071105100_1.jpg']::text[], 'https://www.jomashop.com/tissot-seastar-1000-watch-t1204071105100.html', 666, 859.99, 'Úselo con polo técnico, pantalón azul marino y zapatillas de cuero; perfume fresco marino.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-ccc0141b2ec0', 'mp-d989491a5eb9', 'mp-21708b443c49']::text[], 'La caja negra del Seastar encaja con el field jacket y sneakers limpios en un registro activo, pero sobrio. Acqua di Giò Profondo suma un perfil marino, fresco y moderno, perfecto para un día dinámico.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
