da0b339dbe7c4b0b03f372ea5c01/t/i/tissot-tsport-automatic-mens-watch-t1204071109101-t1204071109101_2.jpg']::text[], 'https://www.jomashop.com/tissot-t-sport-automatic-mens-watch-t120-407-11-091-01.html', 666, 859.99, 'Combínelo con chaqueta ligera, denim oscuro y botas náuticas; perfume acuático y limpio.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-16dc129ea1db', 'mp-169aade8e57a', 'mp-605a39d82c0f']::text[], 'El azul del Seastar conversa con la overshirt relajada y las sneakers de ante para un look casual pulcro. Luna Rossa Carbon añade una estela aromática fresca, mineral y contemporánea, ideal para diario.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-08c76522cb78', 'theoutnet', 'ton-46376663163079450', 'Double Breasted Cutout Grain de Poudre Wool Blend Mini Dress', 'Versace', 'clothing', 'women', 'Sastrería marcada y aberturas precisas; una mini de presencia fuerte y femenina.', 'https://www.theoutnet.com/variants/images/46376663163079450/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163079450/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079450/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079450/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079450/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079450/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/dresses/mini-dresses/double-breasted-cutout-grain-de-poudre-wool-blend-mini-dress/46376663163079450', 666, 859.99, 'Llévela con reloj fino, sandalias negras y perfume chipre; complete con clutch estructurado.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-4218e693c0f4', 'mp-3e1b992662c2', 'mp-58072ada40a0']::text[], 'La silueta estructurada del vestido pide pumps de brillo limpio y un reloj fino, manteniendo una elegancia rotunda. Tuscan Leather refuerza la noche con un acorde oscuro, sensual y sofisticado.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4fa3e4a0eefb', 'jomashop', 'SE-SPB117J1', 'Seiko Prospex Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Un diver japonés de líneas limpias, pensado para aventura con discreción elegante.', 'https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2022/02/20/00/45/SPB117J1/SPB117J1.png', ARRAY['https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2022/02/20/00/45/SPB117J1/SPB117J1.png', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-automatic-black-dial-mens-watch-spb117j1.jpg', 'https://luxewatch.vn/wp-content/uploads/2023/05/Dong-Ho-Seiko-Automatic-Prospex-Alpinist-Black-Dial-SPB117J1-.7.jpg', 'https://timepiecestore.com.au/wp-content/uploads/2025/12/seiko_SPB117J1-768x768.jpg', 'https://luxewatch.vn/wp-content/uploads/2023/05/Dong-Ho-Seiko-Automatic-Prospex-Alpinist-Black-Dial-SPB117J1-.5.jpg']::text[], 'https://www.jomashop.com/seiko-prospex-automatic-black-dial-mens-watch-spb117j1.html', 669.99, 864.99, 'Combínelo con camiseta blanca, sobrecamisa oliva y botas safari; perfume verde y amaderado.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-ccc0141b2ec0', 'mp-d989491a5eb9', 'mp-60727c51909d']::text[], 'El Prospex se equilibra con el field jacket y unas sneakers técnicas para un lujo relajado y funcional. Sauvage aporta una frescura especiada y limpia, adecuada para fines de semana o viaje.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
