w=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw7ed59aba/product-pictures/94e351ad-c81e-4be2-8084-4d2fc9c9a975_T137_407_11_041_02_DETAIL-2.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-ufo-robot-grendizer-mens-watch-t137-407-11-041-02.html', 672, 866.99, 'Úselo con blazer azul tinta, camisa blanca y loafers; perfume seco amaderado, sin exceso.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-2ad272892924', 'mp-ae99e2aca74c', 'mp-6e78cd2c0e9e']::text[], 'El PRX Grendizer se suaviza con camisa oxford y pantalón fluido en tonos neutros, logrando un office look moderno. Gentleman Réserve Privée añade una firma amaderada, cálida y elegante.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-3d4cc7d184ba', 'jomashop', 'SE-SPB249J1', 'Seiko Prospex Land Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Esfera azul y construcción resistente para un estilo activo, preciso y sobrio.', 'https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2022/02/20/01/05/SPB249J1/SPB249J1.png', ARRAY['https://www.seikowatches.com/global-en/-/media/Images/Product--Image/All/Seiko/2022/02/20/01/05/SPB249J1/SPB249J1.png', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-land-automatic-blue-dial-mens-watch-spb249j1.jpg', 'https://cdn.shopify.com/s/files/1/0563/2131/0884/products/Prospex_SPB249J1_RGB_SQ-scaled.jpg?v=1641625033', 'https://static.zegarek.net/imageslib/produkty/duze/seiko-spb249j1-prospex-prospex-alpinist-deep-lake-159655-1.jpg']::text[], 'https://www.jomashop.com/seiko-prospex-land-automatic-blue-dial-mens-watch-spb249j1.html', 675, 870.99, 'Combínelo con parka ligera, pantalón cargo oscuro y botas trekking; perfume fresco especiado.', 'https://i.pinimg.com/736x/0f/73/be/0f73bec64253c0c4979af81f915fd53c--mens-sportswear-male-fashion.jpg?b=t', ARRAY['mp-16dc129ea1db', 'mp-d989491a5eb9', 'mp-21708b443c49']::text[], 'El reloj de aventura urbana funciona con la overshirt ligera y sneakers de ante, en un registro cómodo y premium. Acqua di Giò Profondo suma un frescor acuático, ideal para días activos.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_