INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ac006499312d', 'theoutnet', 'ton-1647597343995195', 'Naidoo 90 Mesh And Leather Ankle Boots', 'Jimmy Choo', 'shoes', 'women', 'Malla y cuero en equilibrio; una bota ligera, sensual y moderna.', 'https://www.theoutnet.com/variants/images/1647597343995195/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597343995195/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597343995195/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597343995195/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597343995195/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597343995195/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/jimmy-choo/boots/ankle-boots/naidoo-90-mesh-and-leather-ankle-boots/1647597343995195', 728, 935.99, 'Combínelas con vestido fluido, reloj minimalista y perfume floral almizclado; use negro, plata o crema.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-9a50ef419258', 'mp-21f8ec52e6da', 'mp-8cf3908f3eee']::text[], 'Las botas mesh se vuelven más ligeras con trench oversize y reloj con diamantes sutiles. Ideal para Lima en media estación; Flora Gorgeous Gardenia añade un floral limpio, luminoso y elegante.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_id