INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4f1c7b9fd789', 'theoutnet', 'ton-34344356237582835', 'Ruffled Embellished Tulle Dress', 'Valentino', 'clothing', 'women', 'Tulle etéreo y volantes precisos para una presencia romántica y escultural.', 'https://www.theoutnet.com/variants/images/34344356237582835/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/34344356237582835/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/34344356237582835/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/34344356237582835/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/34344356237582835/E/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/valentino-garavani/dresses/knee-length-dresses/ruffled-embellished-tulle-dress/34344356237582835', 733, 941.99, 'Acompáñelo con tacones satinados, reloj joya y perfume floral empolvado; mantenga joyería discreta.', 'https://mytrendboutique.com/wp-content/uploads/2024/12/0_0_640_N-2-229.webp', ARRAY['mp-4218e693c0f4', 'mp-3e1b992662c2', 'mp-6a517157564d']::text[], 'El tul ruflado pide pumps Rockstud y un PRX champagne para un acabado couture y equilibrado. Perfecto para gala o boda; Aventus for Her combina manzana, rosas y sándalo, brillante y majestuoso.', 'noche', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-ee45113482cf', 'theoutnet', 'ton-46376663163079443', 'Embellished Cotton Blend Tweed Jacket', 'Versace', 'clothing', 'women', 'Tweed con brillo contenido; una chaqueta pulida que eleva cualquier conjunto.', 'https://www.theoutnet.com/variants/images/46376663163079443/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/46376663163079443/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079443/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079443/Q/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079443/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079443/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/46376663163079443/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/versace/jackets/smart-jackets/embellished-cotton-blend-tweed-jacket/46376663163079443', 733, 941.99, 'Combínela con reloj clásico, pantalón sastre y loafers; perfume chypre limpio en tonos beige o marino.', 'https://i.pinimg.com/474x/73/33/c8/7333c84fbb67f02ab7952632f09e6933--womens-business-clothes-business-outfits-women.jpg', ARRAY['mp-87a3ff47cf1a', 'mp-ccf304630040', 'mp-4218e693c0f4']::text[], 'El tweed intervenido funciona con mocasines limpios y reloj clásico, manteniendo autoridad sin dureza. Para oficina con estilo, Si Intense ofrece grosella negra, rosa y vainilla, elegante y envolvente.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
