=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-9a50ef419258', 'theoutnet', 'ton-17957409490769375', 'Double Breasted Padded Cotton Trench Coat', 'Maison Margiela', 'clothing', 'women', 'Trench acolchado de líneas amplias, ideal para capas elegantes y funcionales.', 'https://www.theoutnet.com/variants/images/17957409490769375/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/17957409490769375/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/17957409490769375/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/17957409490769375/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/17957409490769375/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/17957409490769375/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/mm6-maison-margiela/coats/raincoats-trench-coats/double-breasted-padded-cotton-trench-coat/17957409490769375', 773, 991.99, 'Úselo con reloj de acero, pantalón sastre y botas negras; perfume amaderado limpio, discreto.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-c721206d4e0f', 'mp-9b05bcfb7742', 'mp-fa38caa36f41']::text[], 'Las botas de caña alta equilibran el volumen del trench con autoridad y limpieza visual. El PRX da precisión moderna; el perfume, cuero elegante y sofisticado, acompaña muy bien jornadas de oficina en invierno o reuniones formales.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-baece83184f0', 'theoutnet', 'ton-1647597349305466', 'Condora 55 Suede Mules', 'Christian Louboutin', 'shoes', 'women', 'Mules de ante, suaves y depuradas para un lujo discreto de diario.', 'https://www.theoutnet.com/variants/images/1647597349305466/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597349305466/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597349305466/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597349305466/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597349305466/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597349305466/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/christian-louboutin/sandals/mid-heel-sandals/condora-55-suede-mules/1647597349305466', 792, 1014.99, 'Combínalas con reloj minimalista, perfume fresco y pantalón amplio o vestido de lino.', 'https://chiquehomeliving.com/wp-content/uploads/2025/12/smart-casual-outfit-ideasIMG_1984-768x1365.jpg', ARRAY['mp-c5006cb8c599', 'mp-cbf5fd94f2da', 'mp-8d5bb353d59a']::text[], 'Para mujer: el mule de ante, el trench ligero y el PRX verde componen un lujo relajado y preciso. Ideal para entretiempo o viaje; el perfume es cítrico y marino, limpio, fresco y muy chic.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUD