INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4be7be8e7c0e', 'theoutnet', 'ton-1647597327064421', 'Brigissima 70 Leather And Suede Platform Espadrilles', 'Christian Louboutin', 'shoes', 'women', 'Espadrilles con plataforma, frescas y relajadas para sumar altura con naturalidad.', 'https://www.theoutnet.com/variants/images/1647597327064421/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597327064421/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597327064421/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597327064421/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597327064421/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597327064421/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/christian-louboutin/espadrilles/mid-heel-espadrilles/brigissima-70-leather-and-suede-platform-espadrilles/1647597327064421', 801, 1025.99, 'Úsalas con reloj de correa clara, perfume cítrico y vestido de algodón o pantalón blanco.', 'https://www.styleatacertainage.com/wp-content/uploads/2025/06/Quince-Linen-Picks.png', ARRAY['mp-a3b7700027eb', 'mp-0011f169d584', 'mp-aa9cd49c4ded']::text[], 'Para mujer: el vestido floral, el Seastar azul y Infusion de Figue dan un aire fresco y sofisticado. Perfecto para verano en Lima; el perfume es verde, frutal y ligeramente cremosa, muy natural.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_