INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-664c67bed252', 'theoutnet', 'ton-1647597327064427', 'Melides du Desert 85 Cotton Canvas Espadrille Wedge Sandals', 'Christian Louboutin', 'shoes', 'women', 'Sandalias de cuña con yute, ligeras y luminosas para escapadas estivales.', 'https://www.theoutnet.com/variants/images/1647597327064427/F/w1020_q80.jpg', ARRAY['https://www.theoutnet.com/variants/images/1647597327064427/F/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597327064427/R/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597327064427/D/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597327064427/E/w1020_q80.jpg', 'https://www.theoutnet.com/variants/images/1647597327064427/N/w1020_q80.jpg']::text[], 'https://www.theoutnet.com/en-us/shop/product/christian-louboutin/espadrilles/high-heel-espadrilles/melides-du-desert-85-cotton-canvas-espadrille-wedge-sandals/1647597327064427', 804, 1028.99, 'Combínalas con reloj dorado discreto, perfume floral fresco y lino beige, blanco o azul cielo.', 'https://www.styleatacertainage.com/wp-content/uploads/2025/06/Quince-Linen-Picks.png', ARRAY['mp-82b04d22028d', 'mp-16b4caef84fd', 'mp-aa9cd49c4ded']::text[], 'Una selección equilibrada por estilo, ocasión, nivel de precio y género para completar el conjunto.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco