it&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw2f75b8cd/product-pictures/d15ea6a1-dc27-442e-8396-a18f0990c3d2_T137-907-97-201-00_DETAIL-2.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-powermatic-80-automatic-mens-watch-t1379079720100.html', 806.4, 1030.99, 'Llévalo con camisa blanca, blazer azul marino, mocasines negros y perfume amaderado limpio.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-2ad272892924', 'mp-6e78cd2c0e9e', 'mp-4520d6ec87f1']::text[], 'El PRX en oro sutil se integra con camisa de lino y loafers para una oficina elegante sin excesos. Grey Vetiver aporta un carácter verde-amaderado, sobrio y muy pulido.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
