https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwebd7b384/product-pictures/03052c2a-34fa-474f-ad5a-e5f21d849a48_T120_607_11_041_00_DETAIL-2.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-seastar-automatic-mens-watch-t120-607-11-041-00.html', 905.25, 1129.99, 'Úsalo con polo blanco, chaqueta técnica azul, sneakers blancas y perfume cítrico seco.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-16dc129ea1db', 'mp-d989491a5eb9', 'mp-21708b443c49']::text[], 'Para un look sobrio de viaje o ciudad, combina overshirt de lino, sneakers técnicos y Acqua Di Gio Profondo: acuático, fresco y elegante. El conjunto acompaña la presencia robusta del reloj con un refinamiento relajado.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
