ps://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwe20628bc/product-pictures/f7418c70-762a-4786-b6de-78d1f6b41a74_T120-607-11-041-01_head.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-seastar-2000-automatic-mens-watch-t120-607-11-041-01.html', 979.2, 1203.99, 'Úsalo con knit azul oscuro, jeans crudos, zapatillas de cuero y perfume fresco amaderado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-f60964fd1e13', 'mp-57c4262c9e6b', 'mp-8d5bb353d59a']::text[], 'Para ti, este look funciona en ciudad o fin de semana: pantalón ligero, sneakers de cuero y Neroli Portofino, un cítrico mediterráneo, brillante y elegante. El resultado es moderno, limpio y muy fácil de llevar.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-2cdee511759b', 'jomashop', 'SE-SPB485', 'Seiko Prospex Luxe Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Negro profundo y construcción precisa para una presencia moderna y contenida.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-automatic-black-dial-mens-watch-spb485.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-automatic-black-dial-mens-watch-spb485.jpg', 'https://seikoluxe.com/wp-content/uploads/2024/09/SPB485_1-927x1536.png', 'https://www.righttime.com/seiko/prospex_luxury/spb485m.jpg', 'https://www.fratellowatches.com/cdn-cgi/image/anim=false/wp-content/uploads/2024/10/Seiko-SPB481J1-SPB483J1-SPB485J1-14.jpg', 'https://www.fratellowatches.com/cdn-cgi/image/anim=false/wp-content/uploads/2024/10/Seiko-SPB481J1-SPB483J1-SPB485J1-8a.jpg']::text[], 'https://www.jomashop.com/seiko-seiko-prospex-luxe-black-dial-mens-watch-spb485.html', 994.56, 1219.99, 'Combínalo con polo negro, sobrecamisa gris, botas de cuero y perfume vetiver limpio.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-f60964fd1e13', 'mp-6e78cd2c0e9e', 'mp-2ecaf353c55e']::text[], 'Para un estilo sobrio y refinado, el pantalón fluido y los loafers equilibran la fuerza del Prospex con elegancia discreta. Gentleman Society Sport suma un perfil fresco, amaderado y pulcro, ideal para oficina informal o viaje.', 'lujo-silencioso', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-b6b2fe4b7062', 'jomashop', 'SE-SPB379', 'Seiko Seiko Prospex Luxe Alpinist GMT Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Función GMT y carisma montañés para viajar con elegancia sobria.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-prospex-luxe-alpinist-gmt-automatic-black-dial-mens-watch-spb379.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-prospex-luxe-alpinist-gmt-automatic-black-dial-mens-watch-spb379.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-prospex-luxe-alpinist-gmt-automatic-black-dial-mens-watch-spb379_2.jpg', 'https://hemsleys.com/cdn/shop/files/SPB379J1.png?v=1695911311', 'https://cdn11.bigcommerce.com/s-f06f69/images/stencil/1280x1280/products/15684/65227/SPB379J1__82647.1693561209.png?c=2', 'https://www.watchwinders.pk/wp-content/uploads/2025/03/Seiko-Prospex-Alpinist-GMT-2023-SPB377-SPB379-Hands-On-Review-8.jpg']::text[], 'https://www.jomashop.com/seiko-seiko-prospex-luxe-alpinist-gmt-gmt-black-dial-mens-watch-spb379.html', 999.99, 1224.99, 'Llévalo con field jacket verde oliva, pantalón beige, botas de gamuza y perfume verde seco.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-ccc0141b2ec0', 'mp-cc23be33120b', 'mp-6a32aace5e0a']::text[], 'Para un look de escapada o ciudad relajada, la field jacket, las sneakers bicolor y Neroli Sauvage armonizan con el carácter aventurero del reloj. El perfume es cítrico, verde y luminoso, muy limpio y sofisticado.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-a54cd0be060e', 'jomashop', 'SE-SPB377', 'Seiko Prospex Luxe Alpinist GMT Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Azul profundo y función GMT para una lectura elegante en movimiento.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-alpinist-gmt-automatic-blue-dial-mens-watch-spb377.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-alpinist-gmt-automatic-blue-dial-mens-watch-spb377.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-alpinist-gmt-automatic-blue-dial-mens-watch-spb377_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-alpinist-gmt-automatic-blue-dial-mens-watch-spb377_3.jpg', 'https://seikoluxe.com/wp-content/uploads/2024/05/SPB377_1-768x1335.png']::text[], 'https://www.jomashop.com/seiko-seiko-prospex-luxe-alpinist-gmt-gmt-blue-dial-mens-watch-spb377.html', 1025, 1249.99, 'Combínalo con blazer de lino azul, camisa blanca, mocasines marrón oscuro y perfume cítrico amaderado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-a47f229935b7', 'mp-58f47135b97a', 'mp-605a39d82c0f']::text[], 'Para un fin de semana activo, el pantalón texturizado, los driving shoes y Luna Rossa Carbon acompañan bien el espíritu outdoor del Alpinist. El perfume es aromático, mineral y fresco, con un toque moderno y enérgico.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-dd16ceafb4e6', 'jomashop', 'SE-SPB483', 'Seiko Prospex Luxe Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Azul luminoso y construcción precisa para un estilo relajado y distinguido.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-automatic-blue-dial-mens-watch-spb483.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-automatic-blue-dial-mens-watch-spb483.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-automatic-blue-dial-mens-watch-spb483_3.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-automatic-blue-dial-mens-watch-spb483_2.jpg', 'https://seikoluxe.com/wp-content/uploads/2024/09/SPB483_1-927x1536.png', 'https://images.jamtangan.com/preset:sharp/resize:fit:462:492/dpr:1.5/width:462/height:492/resize:fit/plain/https://assets.jamtangan.com/images/product/seiko/SPB483J1/DETAIL95.jpg', 'https://chronospride.com.au/wp-content/uploads/2024/12/SPB483J1-Seiko-1.jpg']::text[], 'https://www.jomashop.com/seiko-seiko-prospex-luxe-blue-dial-mens-watch-spb483.html', 1036, 1260.99, 'Úsalo con camiseta blanca, chaqueta beige, pantalón azul marino y perfume acuático ambarado.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-16dc129ea1db', 'mp-169aade8e57a', 'mp-8d5bb353d59a']::text[], 'Para un look casual elevado, el overshirt ligero y las sneakers de ante refuerzan el tono aventurero del reloj. Neroli Portofino aporta frescura cítrica y limpia, ideal para clima templado o escapadas de fin de semana.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-5840178ede7b', 'jomashop', 'SE-SPB433', 'Seiko Prospex Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Negro sobrio y arquitectura funcional para un uso versátil y actual.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-automatic-black-dial-mens-watch-spb433.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-automatic-black-dial-mens-watch-spb433.jpg', 'https://media.karousell.com/media/photos/products/2024/10/17/seiko_prospex_spb433_spb433j1__1729134164_674a620e_progressive', 'https://media.karousell.com/media/photos/products/2024/10/17/seiko_prospex_spb433_spb433j1__1729134164_fef7c958_progressive']::text[], 'https://www.jomashop.com/seiko-prospex-automatic-black-dial-mens-watch-spb433.html', 1150, 1374.99, 'Combínalo con suéter gris, jeans índigo, zapatillas negras y perfume seco de cedro.', 'https://myquickurl.com/cheerlives.com/43-cheerlives_gleamnest_20241122082932.webp', ARRAY['mp-f468012c6135', 'mp-57c4262c9e6b', 'mp-60727c51909d']::text[], 'Para ti, este conjunto es ideal en viaje o fin de semana: bomber de corduroy, sneakers y Sauvage EDT. La fragancia es aromática, especiada y limpia, con energía suficiente para acompañar el carácter del Prospex.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-4cccaaa0dc5d', 'jomashop', 'TIST1374271101100', 'Tissot PRX Chronograph Automatic White Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Cronógrafo de líneas claras que aporta un acento pulcro y moderno.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw79af40c4/product-pictures/ee366fd4-7d3b-4cc8-8d59-07b9892ab1a5_T137-427-11-011-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw79af40c4/product-pictures/ee366fd4-7d3b-4cc8-8d59-07b9892ab1a5_T137-427-11-011-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw79af40c4/product-pictures/ee366fd4-7d3b-4cc8-8d59-07b9892ab1a5_T137-427-11-011-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwade7cbe7/product-pictures/8b33c303-f10d-49c3-a765-14d650b98d8b_T137-427-11-011-00_Profil.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw956c18aa/product-pictures/653ddd30-92e4-4e28-87fd-d7970341a488_T137-427-11-011-00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw84340767/product-pictures/cba8b290-ad8d-474e-8d63-f2ff1645cdfd_T137-427-11-011-00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwba18a7ca/product-pictures/cdfa4987-56a0-4657-afe9-40b3fe0691ad_T137-427-11-011-00_DETAIL-1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwb7a3b091/product-pictures/59c9fb6c-a955-400f-bf84-9946fd09642f_T137-427-11-011-00_DETAIL-2.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-chronograph-automatic-white-dial-mens-watch-t1374271101100.html', 1456.35, 1680.99, 'Llévalo con traje azul tinta, camisa blanca, Oxford negros y perfume limpio de iris.', 'https://thevou.com/wp-content/uploads/2024/07/Business-Formal-Attire-Men.jpg', ARRAY['mp-4af1908c0185', 'mp-6e78cd2c0e9e', 'mp-c98229ae5f30']::text[], 'Para oficina o almuerzo formal, la camisa de lino, los loafers y L’Homme de Prada construyen una imagen precisa y elegante. El perfume es limpio, irisado y refinado, perfecto para acompañar el cronógrafo sin exceso.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-d6a4499af722', 'jomashop', 'TISTT9314074129100', 'Tissot PRX Automatic Brown Dial Men''s Watch', 'Tissot', 'watch', 'men', 'Esfera marrón y perfil clásico con una calidez discreta y refinada.', 'https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwebc37a31/product-pictures/73041096-8408-4321-9a60-4dd96b949fd1_T931-407-41-291-00_shadow.png?sm=fit&sw=1600&sh=1600', ARRAY['https://www.tissotwatches.com/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwebc37a31/product-pictures/73041096-8408-4321-9a60-4dd96b949fd1_T931-407-41-291-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwebc37a31/product-pictures/73041096-8408-4321-9a60-4dd96b949fd1_T931-407-41-291-00_shadow.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw1c9185ca/product-pictures/72b916d8-fca9-41f1-b56b-95092ed63646_T931_407_41_291_00_PROFIL.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dwcec3221e/product-pictures/0be393dd-7b93-46f0-a96d-fcb6d3afe0e9_T931_407_41_291_00_B1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw21497bc8/product-pictures/5cb38699-a43f-4465-96e4-654a381ba4e1_T931_407_41_291_00_WRIST.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw77244d90/product-pictures/e0171f42-aa34-492b-86dd-3574deb180a0_T931-407-41-291-00_DETAIL-1.png?sm=fit&sw=1600&sh=1600', 'https://www.tissotwatches.com/dw/image/v2/BKKD_PRD/on/demandware.static/-/Sites-Tissot-Catalogue/default/dw70046435/product-pictures/1478daf9-a188-492e-bdae-77c69ce6e957_T931_407_41_291_00_DETAIL-2.png?sm=fit&sw=1600&sh=1600']::text[], 'https://www.jomashop.com/tissot-prx-automatic-brown-dial-mens-watch-t931-407-41-291-00.html', 1775, 1999.99, 'Combínalo con blazer camel, camisa crema, zapatos café y perfume amaderado suave.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-4af1908c0185', 'mp-7795ae7c1d60', 'mp-2dc2d5978672']::text[], 'Para ti, la camisa de lino y algodón con el pantalón tapered y los loafers de cuero crean un conjunto limpio y sereno, ideal para oficina o una cena discreta. El PRX brown aporta calidez y sofisticación sin esfuerzo.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-8fc3cbe0af5b', 'jomashop', 'SE-SLA061J1', 'Seiko Prospex Luxe Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Negro técnico y presencia contundente para un estilo sobrio y robusto.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-automatic-black-dial-mens-watch-sla061j1.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-automatic-black-dial-mens-watch-sla061j1.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-automatic-black-dial-mens-watch-sla061j1_2.jpg', 'https://www.thewatchcompany.com/media/catalog/product/cache/2e643380bf6acdbc360c33153b32ea2f/S/e/Seiko-SLA061J1.jpg', 'https://jetsostore.com/cdn/shop/files/seiko-sla061j1-men-watch-09_1600x.jpg?v=1718853403', 'https://www.seikowatches.com/au-en/-/media/Images/Product--Image/All/Seiko/2022/02/19/23/12/SLA061J1/SLA061J1.png?mh=1200&mw=1200']::text[], 'https://www.jomashop.com/seiko-seiko-prospex-luxe-black-dial-mens-watch-sla061j1.html', 2764.5, 2989.99, 'Úsalo con parka negra, pantalón técnico gris, botas oscuras y perfume de incienso seco.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-ccc0141b2ec0', 'mp-cc23be33120b', 'mp-605a39d82c0f']::text[], 'Para ti, la field jacket, el pantalón ligero y las sneakers en cuero y ante equilibran técnica y refinamiento, perfectos para viaje o fin de semana activo. El Prospex luce contemporáneo y el perfume, si lo sumas, debe sentirse fresco y dinámico.', 'deportivo', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-48e0815f97a3', 'jomashop', 'SE-SLA053', 'Seiko Prospex Luxe Marinemaster Automatic Blue Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Azul marino y vocación oceánica en una pieza de fuerte presencia.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-marinemaster-automatic-blue-dial-mens-watch-sla053.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-marinemaster-automatic-blue-dial-mens-watch-sla053.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-marinemaster-automatic-blue-dial-mens-watch-sla053_2.jpg', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-luxe-marinemaster-automatic-blue-dial-mens-watch-sla053_3.jpg', 'https://preview.redd.it/wts-seiko-marinemaster-sla053-prospex-full-set-v0-q5ulumvrgo091.jpg?auto=webp&s=03b545f38d15be8a934d7779c9c1799cae1d424e']::text[], 'https://www.jomashop.com/seiko-seiko-prospex-luxe-marinemaster-blue-dial-mens-watch-sla053.html', 3181, 3405.99, 'Combínalo con camisa de lino blanca, pantalón arena, mocasines náuticos y perfume marino limpio.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-1e2e2d2f0407', 'mp-c7f010c47ad7', 'mp-21708b443c49']::text[], 'Para ti, el polo texturizado, el pantalón de lino y las sandalias de cuero componen un look fresco y pulido, ideal para verano junto al mar o un almuerzo elegante. El marino del reloj se realza con una presencia limpia y luminosa.', 'verano', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-c8c4b720370e', 'jomashop', 'SE-SNR053', 'Seiko Prospex LX Automatic Men''s Watch', 'Seiko', 'watch', 'men', 'Ingeniería visible y perfil contemporáneo para una elegancia funcional de alto nivel.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-lx-automatic-mens-watch-snr053.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-prospex-lx-automatic-mens-watch-snr053.jpg', 'https://diamondsoflondon.com/cdn/shop/files/SNR053_5.jpg?v=1736270716&width=1200', 'https://seikoluxe.com/wp-content/uploads/2024/05/SNR053_4.jpg']::text[], 'https://www.jomashop.com/seiko-seiko-prospex-lx-gmt-multi-color-dial-mens-watch-snr053.html', 5652, 5876.99, 'Llévalo con traje gris oscuro, camisa celeste, Derby negros y perfume amaderado mineral.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-8cf6c0c5bfe3', 'mp-4520d6ec87f1', 'mp-41a3121d7f90']::text[], 'Para ti, el blazer de lino, el pantalón ligero y Grey Vetiver forman una imagen impecable y sobria, perfecta para oficina o reuniones de alto nivel. El conjunto respira frescura, estructura y una elegancia muy silenciosa.', 'oficina', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EX