INSERT INTO products(id, source, source_id, name, brand, type, gender, description, image_url, images, source_url, base_price_usd, final_price_usd, styling_note, inspiration_image, reco_ids, reco_note, reco_context, reco_ids_w, reco_note_w, reco_context_w) VALUES ('mp-1ba033584c87', 'jomashop', 'SE-SNR035', 'Seiko Seiko Prospex Lx Line Automatic Black Dial Men''s Watch', 'Seiko', 'watch', 'men', 'Negro profundo y construcción audaz para una presencia técnica y discreta.', 'https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-prospex-lx-line-automatic-black-dial-mens-watch-snr035.jpg', ARRAY['https://cdn2.jomashop.com/media/catalog/product/cache/bb8fda0b339dbe7c4b0b03f372ea5c01/s/e/seiko-seiko-prospex-lx-line-automatic-black-dial-mens-watch-snr035.jpg', 'https://media.karousell.com/media/photos/products/2020/01/26/fsbnib_seiko_prospex_lx_gmt_spring_drive_black_leather_448mm_watch_snr035_snr035j_snr035j1_1580053182_0b482d6d.jpg', 'https://monochrome-watches.com/wp-content/uploads/2019/03/Baselworld-2019-Seiko-Prospex-LX-Line-Spring-Drive-SNR025-SNR027-SNR029-SNR031-SNR033-SNR035-4.jpg', 'https://timeandtidewatches.com/wp-content/uploads/2020/12/Seiko-Prospex-LX-SNR035J.jpg', 'https://www.exquisitetimepieces.com/blog/wp-content/uploads/2023/10/Seiko-Prospex-LX-SNR035-750x344.jpg']::text[], 'https://www.jomashop.com/seiko-seiko-prospex-lx-line-black-dial-mens-watch-snr035.html', 5652, 5876.99, 'Combínalo con chaqueta de lana grafito, polo negro, sneakers minimalistas y perfume vetiver seco.', 'https://www.thefashionisto.com/wp-content/uploads/2023/01/Hermes-Men-Fall-Winter-2023-Collection-Runway-040.jpg', ARRAY['mp-16dc129ea1db', 'mp-d989491a5eb9', 'mp-605a39d82c0f']::text[], 'Para ti, la overshirt, el pantalón amplio y las sneakers técnicas crean un casual refinado, ideal para ciudad o viaje. El reloj aporta presencia deportiva-lujosa; si añades perfume, busca un perfil fresco y limpio, sin exceso.', 'casual', NULL, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name=EXCLUDED.name, brand=EXCLUDED.brand, type=EXCLUDED.type, gender=EXCLUDED.gender, description=EXCLUDED.description, image_url=EXCLUDED.image_url, images=EXCLUDED.images, source_url=EXCLUDED.source_url, base_price_usd=EXCLUDED.base_price_usd, final_price_usd=EXCLUDED.final_price_usd, styling_note=EXCLUDED.styling_note, inspiration_image=EXCLUDED.inspiration_image, reco_ids=EXCLUDED.reco_ids, reco_note=EXCLUDED.reco_note, reco_context=EXCLUDED.reco_context, reco_ids_w=EXCLUDED.reco_ids_w, reco_note_w=EXCLUDED.reco_note_w, reco_context_w=EXCLUDED.reco_context_w;
